window.KJV1769_STRONG_BOOKS["Ps"] = {"osis":"Ps","book":"시편","verses":{"1:1":{"text":"Blessed is the man that walketh not in the counsel of the ungodly, nor standeth in the way of sinners, nor sitteth in the seat of the scornful.","words":[["H0835","Blessed",0,7],["H0376","is the man",8,18],["H1980","that walketh",19,31],["H6098","not in the counsel",32,50],["H7563","of the ungodly",51,65],["H5975","nor standeth",67,79],["H1870","in the way",80,90],["H2400","of sinners",91,101],["H3427","nor sitteth",103,114],["H4186","in the seat",115,126],["H3887","of the scornful",127,142]]},"1:2":{"text":"But his delight is in the law of the LORD; and in his law doth he meditate day and night.","words":[["H2656","But his delight",0,15],["H8451","is in the law",16,29],["H3068","of the LORD",30,41],["H8451","and in his law",43,57],["H1897","doth he meditate",58,74],["H3119","day",75,78],["H3915","and night",79,88]]},"1:3":{"text":"And he shall be like a tree planted by the rivers of water, that bringeth forth his fruit in his season; his leaf also shall not wither; and whatsoever he doeth shall prosper.","words":[["H6086","And he shall be like a tree",0,27],["H8362","planted",28,35],["H6388","by the rivers",36,49],["H4325","of water",50,58],["H5414","that bringeth forth",60,79],["H6529","his fruit",80,89],["H6256","in his season",90,103],["H5929","his leaf",105,113],["H5034","also shall not wither",114,135],["H6213","and whatsoever he doeth",137,160],["H6743","shall prosper",161,174]]},"1:4":{"text":"The ungodly are not so: but are like the chaff which the wind driveth away.","words":[["H7563","The ungodly",0,11],["H4671","are not so: but are like the chaff",12,46],["H7307","which the wind",47,61],["H5086","driveth away",62,74]]},"1:5":{"text":"Therefore the ungodly shall not stand in the judgment, nor sinners in the congregation of the righteous.","words":[["H7563","Therefore the ungodly",0,21],["H6965","shall not stand",22,37],["H4941","in the judgment",38,53],["H2400","nor sinners",55,66],["H5712","in the congregation",67,86],["H6662","of the righteous",87,103]]},"1:6":{"text":"For the LORD knoweth the way of the righteous: but the way of the ungodly shall perish.","words":[["H3068","For the LORD",0,12],["H3045","knoweth",13,20],["H1870","the way",21,28],["H6662","of the righteous",29,45],["H1870","but the way",47,58],["H7563","of the ungodly",59,73],["H0006","shall perish",74,86]]},"2:1":{"text":"Why do the heathen rage, and the people imagine a vain thing?","words":[["H1471","Why do the heathen",0,18],["H7283","rage",19,23],["H3816","and the people",25,39],["H1897","imagine",40,47],["H7385","a vain thing",48,60]]},"2:2":{"text":"The kings of the earth set themselves, and the rulers take counsel together, against the LORD, and against his anointed, saying,","words":[["H4428","The kings",0,9],["H0776","of the earth",10,22],["H3320","set",23,26],["H7336","themselves, and the rulers",27,53],["H3245","take counsel",54,66],["H3162","together",67,75],["H3068","against the LORD",77,93],["H4899","and against his anointed",95,119]]},"2:3":{"text":"Let us break their bands asunder, and cast away their cords from us.","words":[["H5423","Let us break",0,12],["H4147","their bands",13,24],["H5423","asunder",25,32],["H7993","and cast away",34,47],["H5688","their cords",48,59]]},"2:4":{"text":"He that sitteth in the heavens shall laugh: the Lord shall have them in derision.","words":[["H3427","He that sitteth",0,15],["H8064","in the heavens",16,30],["H7832","shall laugh",31,42],["H0136","the Lord",44,52],["H3932","shall have them in derision",53,80]]},"2:5":{"text":"Then shall he speak unto them in his wrath, and vex them in his sore displeasure.","words":[["H1696","Then shall he speak",0,19],["H0639","unto them in his wrath",20,42],["H0926","and vex",44,51],["H2740","them in his sore displeasure",52,80]]},"2:6":{"text":"Yet have I set my king upon my holy hill of Zion.","words":[["H5258","Yet have I set",0,14],["H4428","my king",15,22],["H6944","upon my holy",23,35],["H2022","hill",36,40],["H6726","of Zion",41,48]]},"2:7":{"text":"I will declare the decree: the LORD hath said unto me, Thou art my Son; this day have I begotten thee.","words":[["H5608","I will declare",0,14],["H2706","the decree",15,25],["H3068","the LORD",27,35],["H0559","hath said",36,45],["H1121","unto me, Thou art my Son",46,70],["H3117","this day",72,80],["H3205","have I begotten",81,96]]},"2:8":{"text":"Ask of me, and I shall give thee the heathen for thine inheritance, and the uttermost parts of the earth for thy possession.","words":[["H7592","Ask",0,3],["H5414","of me, and I shall give",4,27],["H1471","thee the heathen",28,44],["H5159","for thine inheritance",45,66],["H0657","and the uttermost parts",68,91],["H0776","of the earth",92,104],["H0272","for thy possession",105,123]]},"2:9":{"text":"Thou shalt break them with a rod of iron; thou shalt dash them in pieces like a potter's vessel.","words":[["H7489","Thou shalt break",0,16],["H7626","them with a rod",17,32],["H1270","of iron",33,40],["H5310","thou shalt dash them in pieces",42,72],["H3335","like a potter's",73,88],["H3627","vessel",89,95]]},"2:10":{"text":"Be wise now therefore, O ye kings: be instructed, ye judges of the earth.","words":[["H7919","Be wise",0,7],["H4428","now therefore, O ye kings",8,33],["H3256","be instructed",35,48],["H8199","ye judges",50,59],["H0776","of the earth",60,72]]},"2:11":{"text":"Serve the LORD with fear, and rejoice with trembling.","words":[["H5647","Serve",0,5],["H3068","the LORD",6,14],["H3374","with fear",15,24],["H1523","and rejoice",26,37],["H7461","with trembling",38,52]]},"2:12":{"text":"Kiss the Son, lest he be angry, and ye perish from the way, when his wrath is kindled but a little. Blessed are all they that put their trust in him.","words":[["H5401","Kiss",0,4],["H1248","the Son",5,12],["H0599","lest he be angry",14,30],["H0006","and ye perish",32,45],["H1870","from the way",46,58],["H0639","when his wrath",60,74],["H1197","is kindled",75,85],["H4592","but a little",86,98],["H0835","Blessed",100,107],["H2620","are all they that put their trust",108,141]]},"3:1":{"text":"A Psalm of David, when he fled from Absalom his son. LORD, how are they increased that trouble me! many are they that rise up against me.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H1272","when he fled",18,30],["H6440","from",31,35],["H0053","Absalom",36,43],["H1121","his son",44,51],["H3068","LORD",53,57],["H7231","how are they increased",59,81],["H6862","that trouble",82,94],["H7227","me! many",95,103],["H6965","are they that rise up",104,125]]},"3:2":{"text":"Many there be which say of my soul, There is no help for him in God. Selah.","words":[["H7227","Many",0,4],["H0559","there be which say",5,23],["H5315","of my soul",24,34],["H3444","There is no help",36,52],["H0430","for him in God",53,67],["H5542","Selah",69,74]]},"3:3":{"text":"But thou, O LORD, art a shield for me; my glory, and the lifter up of mine head.","words":[["H3068","But thou, O LORD",0,16],["H4043","art a shield",18,30],["H3519","for me; my glory",31,47],["H7311","and the lifter up",49,66],["H7218","of mine head",67,79]]},"3:4":{"text":"I cried unto the LORD with my voice, and he heard me out of his holy hill. Selah.","words":[["H7121","I cried",0,7],["H3068","unto the LORD",8,21],["H6963","with my voice",22,35],["H6030","and he heard",37,49],["H6944","me out of his holy",50,68],["H2022","hill",69,73],["H5542","Selah",75,80]]},"3:5":{"text":"I laid me down and slept; I awaked; for the LORD sustained me.","words":[["H7901","I laid me down",0,14],["H3462","and slept",15,24],["H6974","I awaked",26,34],["H3068","for the LORD",36,48],["H5564","sustained",49,58]]},"3:6":{"text":"I will not be afraid of ten thousands of people, that have set themselves against me round about.","words":[["H3372","I will not be afraid",0,20],["H7233","of ten thousands",21,37],["H5971","of people",38,47],["H7896","that have set",49,62],["H5439","themselves against me round about",63,96]]},"3:7":{"text":"Arise, O LORD; save me, O my God: for thou hast smitten all mine enemies upon the cheek bone; thou hast broken the teeth of the ungodly.","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H3467","save",15,19],["H0430","me, O my God",20,32],["H5221","for thou hast smitten",34,55],["H0341","all mine enemies",56,72],["H3895","upon the cheek bone",73,92],["H7665","thou hast broken",94,110],["H8127","the teeth",111,120],["H7563","of the ungodly",121,135]]},"3:8":{"text":"Salvation belongeth unto the LORD: thy blessing is upon thy people. Selah.","words":[["H3444","Salvation",0,9],["H3068","belongeth unto the LORD",10,33],["H1293","thy blessing",35,47],["H5971","is upon thy people",48,66],["H5542","Selah",68,73]]},"4:1":{"text":"To the chief Musician on Neginoth, A Psalm of David. Hear me when I call, O God of my righteousness: thou hast enlarged me when I was in distress; have mercy upon me, and hear my prayer.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H4210","A Psalm",35,42],["H1732","of David",43,51],["H6030","Hear",53,57],["H7121","me when I call",58,72],["H0430","O God",74,79],["H6664","of my righteousness",80,99],["H7337","thou hast enlarged",101,119],["H6862","me when I was in distress",120,145],["H2603","have mercy",147,157],["H8085","upon me, and hear",158,175],["H8605","my prayer",176,185]]},"4:2":{"text":"O ye sons of men, how long will ye turn my glory into shame? how long will ye love vanity, and seek after leasing? Selah.","words":[["H1121","O ye sons",0,9],["H0376","of men",10,16],["H5704","how long",18,26],["H3519","will ye turn my glory",27,48],["H3639","into shame",49,59],["H0157","how long will ye love",61,82],["H7385","vanity",83,89],["H1245","and seek",91,99],["H3577","after leasing",100,113],["H5542","Selah",115,120]]},"4:3":{"text":"But know that the LORD hath set apart him that is godly for himself: the LORD will hear when I call unto him.","words":[["H3045","But know",0,8],["H3068","that the LORD",9,22],["H6395","hath set apart",23,37],["H2623","him that is godly",38,55],["H3068","for himself: the LORD",56,77],["H8085","will hear",78,87],["H7121","when I call",88,99]]},"4:4":{"text":"Stand in awe, and sin not: commune with your own heart upon your bed, and be still. Selah.","words":[["H7264","Stand in awe",0,12],["H2398","and sin",14,21],["H0559","not: commune",22,34],["H3824","with your own heart",35,54],["H4904","upon your bed",55,68],["H1826","and be still",70,82],["H5542","Selah",84,89]]},"4:5":{"text":"Offer the sacrifices of righteousness, and put your trust in the LORD.","words":[["H2076","Offer",0,5],["H2077","the sacrifices",6,20],["H6664","of righteousness",21,37],["H0982","and put your trust",39,57],["H3068","in the LORD",58,69]]},"4:6":{"text":"There be many that say, Who will shew us any good? LORD, lift thou up the light of thy countenance upon us.","words":[["H7227","There be many",0,13],["H0559","that say",14,22],["H7200","Who will shew",24,37],["H2896","us any good",38,49],["H3068","LORD",51,55],["H5375","lift thou up",57,69],["H0216","the light",70,79],["H6440","of thy countenance",80,98]]},"4:7":{"text":"Thou hast put gladness in my heart, more than in the time that their corn and their wine increased.","words":[["H5414","Thou hast put",0,13],["H8057","gladness",14,22],["H3820","in my heart",23,34],["H6256","more than in the time",36,57],["H1715","that their corn",58,73],["H8492","and their wine",74,88],["H7231","increased",89,98]]},"4:8":{"text":"I will both lay me down in peace, and sleep: for thou, LORD, only makest me dwell in safety.","words":[["H3162","I will both",0,11],["H7901","lay me down",12,23],["H7965","in peace",24,32],["H3462","and sleep",34,43],["H3068","for thou, LORD",45,59],["H0910","only",61,65],["H3427","makest me dwell",66,81],["H0983","in safety",82,91]]},"5:1":{"text":"To the chief Musician upon Nehiloth, A Psalm of David. Give ear to my words, O LORD, consider my meditation.","words":[["H5329","To the chief Musician",0,21],["H5155","upon Nehiloth",22,35],["H4210","A Psalm",37,44],["H1732","of David",45,53],["H0238","Give ear",55,63],["H0561","to my words",64,75],["H3068","O LORD",77,83],["H0995","consider",85,93],["H1901","my meditation",94,107]]},"5:2":{"text":"Hearken unto the voice of my cry, my King, and my God: for unto thee will I pray.","words":[["H7181","Hearken",0,7],["H6963","unto the voice",8,22],["H7773","of my cry",23,32],["H4428","my King",34,41],["H0430","and my God",43,53],["H6419","for unto thee will I pray",55,80]]},"5:3":{"text":"My voice shalt thou hear in the morning, O LORD; in the morning will I direct my prayer unto thee, and will look up.","words":[["H6963","My voice",0,8],["H8085","shalt thou hear",9,24],["H1242","in the morning",25,39],["H3068","O LORD",41,47],["H1242","in the morning",49,63],["H6186","will I direct",64,77],["H6822","my prayer unto thee, and will look up",78,115]]},"5:4":{"text":"For thou art not a God that hath pleasure in wickedness: neither shall evil dwell with thee.","words":[["H0410","For thou art not a God",0,22],["H2655","that hath pleasure",23,41],["H7562","in wickedness",42,55],["H7451","neither shall evil",57,75],["H1481","dwell",76,81]]},"5:5":{"text":"The foolish shall not stand in thy sight: thou hatest all workers of iniquity.","words":[["H1984","The foolish",0,11],["H3320","shall not stand",12,27],["H5869","in thy sight",28,40],["H8130","thou hatest",42,53],["H6466","all workers",54,65],["H0205","of iniquity",66,77]]},"5:6":{"text":"Thou shalt destroy them that speak leasing: the LORD will abhor the bloody and deceitful man.","words":[["H0006","Thou shalt destroy",0,18],["H1696","them that speak",19,34],["H3577","leasing",35,42],["H3068","the LORD",44,52],["H8581","will abhor",53,63],["H1818","the bloody",64,74],["H4820","and deceitful",75,88],["H0376","man",89,92]]},"5:7":{"text":"But as for me, I will come into thy house in the multitude of thy mercy: and in thy fear will I worship toward thy holy temple.","words":[["H0935","But as for me, I will come",0,26],["H1004","into thy house",27,41],["H7230","in the multitude",42,58],["H2617","of thy mercy",59,71],["H3374","and in thy fear",73,88],["H7812","will I worship",89,103],["H6944","toward thy holy",104,119],["H1964","temple",120,126]]},"5:8":{"text":"Lead me, O LORD, in thy righteousness because of mine enemies; make thy way straight before my face.","words":[["H5148","Lead",0,4],["H3068","me, O LORD",5,15],["H6666","in thy righteousness",17,37],["H8324","because of mine enemies",38,61],["H1870","make thy way",63,75],["H3474","straight",76,84],["H6440","before my face",85,99]]},"5:9":{"text":"For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre; they flatter with their tongue.","words":[["H3559","For there is no faithfulness",0,28],["H6310","in their mouth",29,43],["H7130","their inward",45,57],["H1942","part is very wickedness",58,81],["H1627","their throat",83,95],["H6605","is an open",96,106],["H6913","sepulchre",107,116],["H2505","they flatter",118,130],["H3956","with their tongue",131,148]]},"5:10":{"text":"Destroy thou them, O God; let them fall by their own counsels; cast them out in the multitude of their transgressions; for they have rebelled against thee.","words":[["H0816","Destroy",0,7],["H0430","thou them, O God",8,24],["H5307","let them fall",26,39],["H4156","by their own counsels",40,61],["H5080","cast them out",63,76],["H7230","in the multitude",77,93],["H6588","of their transgressions",94,117],["H4784","for they have rebelled",119,141]]},"5:11":{"text":"But let all those that put their trust in thee rejoice: let them ever shout for joy, because thou defendest them: let them also that love thy name be joyful in thee.","words":[["H2620","But let all those that put their trust",0,38],["H8055","in thee rejoice",39,54],["H5769","let them ever",56,69],["H7442","shout for joy",70,83],["H5526","because thou defendest",85,107],["H0157","them: let them also that love",108,137],["H8034","thy name",138,146],["H5970","be joyful",147,156]]},"5:12":{"text":"For thou, LORD, wilt bless the righteous; with favour wilt thou compass him as with a shield.","words":[["H3068","For thou, LORD",0,14],["H1288","wilt bless",16,26],["H6662","the righteous",27,40],["H7522","with favour",42,53],["H5849","wilt thou compass",54,71],["H6793","him as with a shield",72,92]]},"6:1":{"text":"To the chief Musician on Neginoth upon Sheminith, A Psalm of David. O LORD, rebuke me not in thine anger, neither chasten me in thy hot displeasure.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H8067","upon Sheminith",34,48],["H4210","A Psalm",50,57],["H1732","of David",58,66],["H3068","O LORD",68,74],["H3198","rebuke",76,82],["H0639","me not in thine anger",83,104],["H3256","neither chasten",106,121],["H2534","me in thy hot displeasure",122,147]]},"6:2":{"text":"Have mercy upon me, O LORD; for I am weak: O LORD, heal me; for my bones are vexed.","words":[["H2603","Have mercy",0,10],["H3068","upon me, O LORD",11,26],["H0536","for I am weak",28,41],["H3068","O LORD",43,49],["H7495","heal",51,55],["H6106","me; for my bones",56,72],["H0926","are vexed",73,82]]},"6:3":{"text":"My soul is also sore vexed: but thou, O LORD, how long?","words":[["H5315","My soul",0,7],["H3966","is also sore",8,20],["H0926","vexed",21,26],["H3068","but thou, O LORD",28,44]]},"6:4":{"text":"Return, O LORD, deliver my soul: oh save me for thy mercies' sake.","words":[["H7725","Return",0,6],["H3068","O LORD",8,14],["H2502","deliver",16,23],["H5315","my soul",24,31],["H3467","oh save",33,40],["H2617","me for thy mercies'",41,60]]},"6:5":{"text":"For in death there is no remembrance of thee: in the grave who shall give thee thanks?","words":[["H4194","For in death",0,12],["H2143","there is no remembrance",13,36],["H7585","of thee: in the grave",37,58],["H3034","who shall give thee thanks",59,85]]},"6:6":{"text":"I am weary with my groaning; all the night make I my bed to swim; I water my couch with my tears.","words":[["H3021","I am weary",0,10],["H0585","with my groaning",11,27],["H3915","all the night",29,42],["H4296","make I my bed",43,56],["H7811","to swim",57,64],["H4529","I water",66,73],["H6210","my couch",74,82],["H1832","with my tears",83,96]]},"6:7":{"text":"Mine eye is consumed because of grief; it waxeth old because of all mine enemies.","words":[["H5869","Mine eye",0,8],["H6244","is consumed",9,20],["H3708","because of grief",21,37],["H6275","it waxeth old",39,52],["H6887","because of all mine enemies",53,80]]},"6:8":{"text":"Depart from me, all ye workers of iniquity; for the LORD hath heard the voice of my weeping.","words":[["H5493","Depart",0,6],["H6466","from me, all ye workers",7,30],["H0205","of iniquity",31,42],["H3068","for the LORD",44,56],["H8085","hath heard",57,67],["H6963","the voice",68,77],["H1065","of my weeping",78,91]]},"6:9":{"text":"The LORD hath heard my supplication; the LORD will receive my prayer.","words":[["H3068","The LORD",0,8],["H8085","hath heard",9,19],["H8467","my supplication",20,35],["H3068","the LORD",37,45],["H3947","will receive",46,58],["H8605","my prayer",59,68]]},"6:10":{"text":"Let all mine enemies be ashamed and sore vexed: let them return and be ashamed suddenly.","words":[["H0341","Let all mine enemies",0,20],["H0954","be ashamed",21,31],["H3966","and sore",32,40],["H0926","vexed",41,46],["H7725","let them return",48,63],["H0954","and be ashamed",64,78],["H7281","suddenly",79,87]]},"7:1":{"text":"Shiggaion of David, which he sang unto the LORD, concerning the words of Cush the Benjamite. O LORD my God, in thee do I put my trust: save me from all them that persecute me, and deliver me:","words":[["H7692","Shiggaion",0,9],["H1732","of David",10,18],["H7891","which he sang",20,33],["H3068","unto the LORD",34,47],["H1697","concerning the words",49,69],["H3568","of Cush",70,77],["H1121","the Benjamite",78,91],["H1145","the Benjamite",78,91],["H3068","O LORD",93,99],["H0430","my God",100,106],["H2620","in thee do I put my trust",108,133],["H3467","save",135,139],["H7291","me from all them that persecute",140,171],["H5337","me, and deliver",172,187]]},"7:2":{"text":"Lest he tear my soul like a lion, rending it in pieces, while there is none to deliver.","words":[["H2963","Lest he tear",0,12],["H5315","my soul",13,20],["H0738","like a lion",21,32],["H6561","rending it in pieces",34,54],["H5337","while there is none to deliver",56,86]]},"7:3":{"text":"O LORD my God, if I have done this; if there be iniquity in my hands;","words":[["H3068","O LORD",0,6],["H0430","my God",7,13],["H6213","if I have done",15,29],["H3426","this; if there be",30,47],["H5766","iniquity",48,56],["H3709","in my hands",57,68]]},"7:4":{"text":"If I have rewarded evil unto him that was at peace with me; (yea, I have delivered him that without cause is mine enemy:)","words":[["H1580","If I have rewarded",0,18],["H7451","evil",19,23],["H7999","unto him that was at peace",24,50],["H2502","with me; (yea, I have delivered",51,82],["H7387","him that without cause",83,105],["H6887","is mine enemy",106,119]]},"7:5":{"text":"Let the enemy persecute my soul, and take it; yea, let him tread down my life upon the earth, and lay mine honour in the dust. Selah.","words":[["H0341","Let the enemy",0,13],["H7291","persecute",14,23],["H5315","my soul",24,31],["H5381","and take",33,41],["H7429","it; yea, let him tread down",42,69],["H2416","my life",70,77],["H0776","upon the earth",78,92],["H7931","and lay",94,101],["H3519","mine honour",102,113],["H6083","in the dust",114,125],["H5542","Selah",127,132]]},"7:6":{"text":"Arise, O LORD, in thine anger, lift up thyself because of the rage of mine enemies: and awake for me to the judgment that thou hast commanded.","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H0639","in thine anger",15,29],["H5375","lift up",31,38],["H5678","thyself because of the rage",39,66],["H6887","of mine enemies",67,82],["H5782","and awake",84,93],["H4941","for me to the judgment",94,116],["H6680","that thou hast commanded",117,141]]},"7:7":{"text":"So shall the congregation of the people compass thee about: for their sakes therefore return thou on high.","words":[["H5712","So shall the congregation",0,25],["H3816","of the people",26,39],["H5437","compass thee about",40,58],["H7725","for their sakes therefore return",60,92],["H4791","thou on high",93,105]]},"7:8":{"text":"The LORD shall judge the people: judge me, O LORD, according to my righteousness, and according to mine integrity that is in me.","words":[["H3068","The LORD",0,8],["H1777","shall judge",9,20],["H5971","the people",21,31],["H8199","judge",33,38],["H3068","me, O LORD",39,49],["H6664","according to my righteousness",51,80],["H8537","and according to mine integrity",82,113]]},"7:9":{"text":"Oh let the wickedness of the wicked come to an end; but establish the just: for the righteous God trieth the hearts and reins.","words":[["H7451","Oh let the wickedness",0,21],["H7563","of the wicked",22,35],["H1584","come to an end",36,50],["H3559","but establish",52,65],["H6662","the just",66,74],["H6662","for the righteous",76,93],["H0430","God",94,97],["H0974","trieth",98,104],["H3826","the hearts",105,115],["H3629","and reins",116,125]]},"7:10":{"text":"My defence is of God, which saveth the upright in heart.","words":[["H4043","My defence",0,10],["H0430","is of God",11,20],["H3467","which saveth",22,34],["H3477","the upright",35,46],["H3820","in heart",47,55]]},"7:11":{"text":"God judgeth the righteous, and God is angry with the wicked every day.","words":[["H0430","God",0,3],["H8199","judgeth",4,11],["H6662","the righteous",12,25],["H0410","and God",27,34],["H2194","is angry",35,43],["H3117","with the wicked every day",44,69]]},"7:12":{"text":"If he turn not, he will whet his sword; he hath bent his bow, and made it ready.","words":[["H7725","If he turn",0,10],["H3913","not, he will whet",11,28],["H2719","his sword",29,38],["H1869","he hath bent",40,52],["H7198","his bow",53,60],["H3559","and made it ready",62,79]]},"7:13":{"text":"He hath also prepared for him the instruments of death; he ordaineth his arrows against the persecutors.","words":[["H3559","He hath also prepared",0,21],["H3627","for him the instruments",22,45],["H4194","of death",46,54],["H6466","he ordaineth",56,68],["H2671","his arrows",69,79],["H1814","against the persecutors",80,103]]},"7:14":{"text":"Behold, he travaileth with iniquity, and hath conceived mischief, and brought forth falsehood.","words":[["H2254","Behold, he travaileth",0,21],["H0205","with iniquity",22,35],["H2029","and hath conceived",37,55],["H5999","mischief",56,64],["H3205","and brought forth",66,83],["H8267","falsehood",84,93]]},"7:15":{"text":"He made a pit, and digged it, and is fallen into the ditch which he made.","words":[["H3738","He made",0,7],["H0953","a pit",8,13],["H2658","and digged",15,25],["H5307","it, and is fallen",26,43],["H7845","into the ditch",44,58],["H6466","which he made",59,72]]},"7:16":{"text":"His mischief shall return upon his own head, and his violent dealing shall come down upon his own pate.","words":[["H5999","His mischief",0,12],["H7725","shall return",13,25],["H7218","upon his own head",26,43],["H2555","and his violent",45,60],["H3381","dealing shall come down",61,84],["H6936","upon his own pate",85,102]]},"7:17":{"text":"I will praise the LORD according to his righteousness: and will sing praise to the name of the LORD most high.","words":[["H3034","I will praise",0,13],["H3068","the LORD",14,22],["H6664","according to his righteousness",23,53],["H2167","and will sing praise",55,75],["H8034","to the name",76,87],["H3068","of the LORD",88,99],["H5945","most high",100,109]]},"8:1":{"text":"To the chief Musician upon Gittith, A Psalm of David. O LORD our Lord, how excellent is thy name in all the earth! who hast set thy glory above the heavens.","words":[["H5329","To the chief Musician",0,21],["H1665","upon Gittith",22,34],["H4210","A Psalm",36,43],["H1732","of David",44,52],["H3068","O LORD",54,60],["H0113","our Lord",61,69],["H0117","how excellent",71,84],["H8034","is thy name",85,96],["H0776","in all the earth",97,113],["H5414","who hast set",115,127],["H1935","thy glory",128,137],["H8064","above the heavens",138,155]]},"8:2":{"text":"Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies, that thou mightest still the enemy and the avenger.","words":[["H6310","Out of the mouth",0,16],["H5768","of babes",17,25],["H3243","and sucklings",26,39],["H3245","hast thou ordained",40,58],["H5797","strength",59,67],["H6887","because of thine enemies",68,92],["H7673","that thou mightest still",94,118],["H0341","the enemy",119,128],["H5358","and the avenger",129,144]]},"8:3":{"text":"When I consider thy heavens, the work of thy fingers, the moon and the stars, which thou hast ordained;","words":[["H7200","When I consider",0,15],["H8064","thy heavens",16,27],["H4639","the work",29,37],["H0676","of thy fingers",38,52],["H3394","the moon",54,62],["H3556","and the stars",63,76],["H3559","which thou hast ordained",78,102]]},"8:4":{"text":"What is man, that thou art mindful of him? and the son of man, that thou visitest him?","words":[["H0582","What is man",0,11],["H2142","that thou art mindful",13,34],["H1121","of him? and the son",35,54],["H0120","of man",55,61],["H6485","that thou visitest",63,81]]},"8:5":{"text":"For thou hast made him a little lower than the angels, and hast crowned him with glory and honour.","words":[["H4592","For thou hast made him a little",0,31],["H2637","lower",32,37],["H0430","than the angels",38,53],["H5849","and hast crowned",55,71],["H3519","him with glory",72,86],["H1926","and honour",87,97]]},"8:6":{"text":"Thou madest him to have dominion over the works of thy hands; thou hast put all things under his feet:","words":[["H4910","Thou madest him to have dominion",0,32],["H4639","over the works",33,47],["H3027","of thy hands",48,60],["H7896","thou hast put",62,75],["H7272","all things under his feet",76,101]]},"8:7":{"text":"All sheep and oxen, yea, and the beasts of the field;","words":[["H6792","All sheep",0,9],["H0504","and oxen",10,18],["H0929","yea, and the beasts",20,39],["H7704","of the field",40,52]]},"8:8":{"text":"The fowl of the air, and the fish of the sea, and whatsoever passeth through the paths of the seas.","words":[["H6833","The fowl",0,8],["H8064","of the air",9,19],["H1709","and the fish",21,33],["H3220","of the sea",34,44],["H5674","and whatsoever passeth through",46,76],["H0734","the paths",77,86],["H3220","of the seas",87,98]]},"8:9":{"text":"O LORD our Lord, how excellent is thy name in all the earth!","words":[["H3068","O LORD",0,6],["H0113","our Lord",7,15],["H0117","how excellent",17,30],["H8034","is thy name",31,42],["H0776","in all the earth",43,59]]},"9:1":{"text":"To the chief Musician upon Muthlabben, A Psalm of David. I will praise thee, O LORD, with my whole heart; I will shew forth all thy marvellous works.","words":[["H5329","To the chief Musician",0,21],["H4192","upon Muthlabben",22,37],["H1121","upon Muthlabben",22,37],["H4210","A Psalm",39,46],["H1732","of David",47,55],["H3034","I will praise",57,70],["H3068","thee, O LORD",71,83],["H3820","with my whole heart",85,104],["H5608","I will shew forth",106,123],["H6381","all thy marvellous works",124,148]]},"9:2":{"text":"I will be glad and rejoice in thee: I will sing praise to thy name, O thou most High.","words":[["H8055","I will be glad",0,14],["H5970","and rejoice",15,26],["H2167","in thee: I will sing praise",27,54],["H8034","to thy name",55,66],["H5945","O thou most High",68,84]]},"9:3":{"text":"When mine enemies are turned back, they shall fall and perish at thy presence.","words":[["H0341","When mine enemies",0,17],["H7725","are turned",18,28],["H0268","back",29,33],["H3782","they shall fall",35,50],["H0006","and perish",51,61],["H6440","at thy presence",62,77]]},"9:4":{"text":"For thou hast maintained my right and my cause; thou satest in the throne judging right.","words":[["H6213","For thou hast maintained",0,24],["H4941","my right",25,33],["H1779","and my cause",34,46],["H3427","thou satest",48,59],["H3678","in the throne",60,73],["H8199","judging",74,81],["H6664","right",82,87]]},"9:5":{"text":"Thou hast rebuked the heathen, thou hast destroyed the wicked, thou hast put out their name for ever and ever.","words":[["H1605","Thou hast rebuked",0,17],["H1471","the heathen",18,29],["H0006","thou hast destroyed",31,50],["H7563","the wicked",51,61],["H4229","thou hast put out",63,80],["H8034","their name",81,91],["H5769","for ever",92,100],["H5703","and ever",101,109]]},"9:6":{"text":"O thou enemy, destructions are come to a perpetual end: and thou hast destroyed cities; their memorial is perished with them.","words":[["H0341","O thou enemy",0,12],["H2723","destructions",14,26],["H5331","are come to a perpetual",27,50],["H8552","end",51,54],["H5428","and thou hast destroyed",56,79],["H6145","cities",80,86],["H5892","cities",80,86],["H2143","their memorial",88,102],["H0006","is perished",103,114],["H1992","with them",115,124]]},"9:7":{"text":"But the LORD shall endure for ever: he hath prepared his throne for judgment.","words":[["H3068","But the LORD",0,12],["H3427","shall endure",13,25],["H5769","for ever",26,34],["H3559","he hath prepared",36,52],["H3678","his throne",53,63],["H4941","for judgment",64,76]]},"9:8":{"text":"And he shall judge the world in righteousness, he shall minister judgment to the people in uprightness.","words":[["H8199","And he shall judge",0,18],["H8398","the world",19,28],["H6664","in righteousness",29,45],["H1777","he shall minister judgment",47,73],["H3816","to the people",74,87],["H4339","in uprightness",88,102]]},"9:9":{"text":"The LORD also will be a refuge for the oppressed, a refuge in times of trouble.","words":[["H3068","The LORD",0,8],["H4869","also will be a refuge",9,30],["H1790","for the oppressed",31,48],["H4869","a refuge",50,58],["H6256","in times",59,67],["H6869","of trouble",68,78]]},"9:10":{"text":"And they that know thy name will put their trust in thee: for thou, LORD, hast not forsaken them that seek thee.","words":[["H3045","And they that know",0,18],["H8034","thy name",19,27],["H0982","will put their trust",28,48],["H3068","in thee: for thou, LORD",49,72],["H5800","hast not forsaken",74,91],["H1875","them that seek",92,106]]},"9:11":{"text":"Sing praises to the LORD, which dwelleth in Zion: declare among the people his doings.","words":[["H2167","Sing praises",0,12],["H3068","to the LORD",13,24],["H3427","which dwelleth",26,40],["H6726","in Zion",41,48],["H5046","declare",50,57],["H5971","among the people",58,74],["H5949","his doings",75,85]]},"9:12":{"text":"When he maketh inquisition for blood, he remembereth them: he forgetteth not the cry of the humble.","words":[["H1875","When he maketh inquisition",0,26],["H1818","for blood",27,36],["H2142","he remembereth",38,52],["H7911","them: he forgetteth",53,72],["H6818","not the cry",73,84],["H6035","of the humble",85,98],["H6041","of the humble",85,98]]},"9:13":{"text":"Have mercy upon me, O LORD; consider my trouble which I suffer of them that hate me, thou that liftest me up from the gates of death:","words":[["H2603","Have mercy",0,10],["H3068","upon me, O LORD",11,26],["H7200","consider",28,36],["H6040","my trouble",37,47],["H8130","which I suffer of them that hate",48,80],["H7311","me, thou that liftest me up",81,108],["H8179","from the gates",109,123],["H4194","of death",124,132]]},"9:14":{"text":"That I may shew forth all thy praise in the gates of the daughter of Zion: I will rejoice in thy salvation.","words":[["H5608","That I may shew forth",0,21],["H8416","all thy praise",22,36],["H8179","in the gates",37,49],["H1323","of the daughter",50,65],["H6726","of Zion",66,73],["H1523","I will rejoice",75,89],["H3444","in thy salvation",90,106]]},"9:15":{"text":"The heathen are sunk down in the pit that they made: in the net which they hid is their own foot taken.","words":[["H1471","The heathen",0,11],["H2883","are sunk down",12,25],["H7845","in the pit",26,36],["H6213","that they made",37,51],["H7568","in the net",53,63],["H2098","which",64,69],["H2934","they hid",70,78],["H7272","is their own foot",79,96],["H3920","taken",97,102]]},"9:16":{"text":"The LORD is known by the judgment which he executeth: the wicked is snared in the work of his own hands. Higgaion. Selah.","words":[["H3068","The LORD",0,8],["H3045","is known",9,17],["H4941","by the judgment",18,33],["H6213","which he executeth",34,52],["H7563","the wicked",54,64],["H5367","is snared",65,74],["H6467","in the work",75,86],["H3709","of his own hands",87,103],["H1902","Higgaion",105,113],["H5542","Selah",115,120]]},"9:17":{"text":"The wicked shall be turned into hell, and all the nations that forget God.","words":[["H7563","The wicked",0,10],["H7725","shall be turned",11,26],["H7585","into hell",27,36],["H1471","and all the nations",38,57],["H7913","that forget",58,69],["H0430","God",70,73]]},"9:18":{"text":"For the needy shall not alway be forgotten: the expectation of the poor shall not perish for ever.","words":[["H0034","For the needy",0,13],["H5331","shall not alway",14,29],["H7911","be forgotten",30,42],["H8615","the expectation",44,59],["H6041","of the poor",60,71],["H6035","of the poor",60,71],["H0006","shall not perish",72,88],["H5703","for ever",89,97]]},"9:19":{"text":"Arise, O LORD; let not man prevail: let the heathen be judged in thy sight.","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H0582","let not man",15,26],["H5810","prevail",27,34],["H1471","let the heathen",36,51],["H8199","be judged",52,61],["H6440","in thy sight",62,74]]},"9:20":{"text":"Put them in fear, O LORD: that the nations may know themselves to be but men. Selah.","words":[["H7896","Put",0,3],["H4172","them in fear",4,16],["H4172","them in fear",4,16],["H3068","O LORD",18,24],["H1471","that the nations",26,42],["H3045","may know",43,51],["H0582","themselves to be but men",52,76],["H5542","Selah",78,83]]},"10:1":{"text":"Why standest thou afar off, O LORD? why hidest thou thyself in times of trouble?","words":[["H5975","Why standest",0,12],["H7350","thou afar off",13,26],["H3068","O LORD",28,34],["H5956","why hidest",36,46],["H6256","thou thyself in times",47,68],["H6869","of trouble",69,79]]},"10:2":{"text":"The wicked in his pride doth persecute the poor: let them be taken in the devices that they have imagined.","words":[["H7563","The wicked",0,10],["H1346","in his pride",11,23],["H1814","doth persecute",24,38],["H6041","the poor",39,47],["H8610","let them be taken",49,66],["H4209","in the devices",67,81],["H2098","that",82,86],["H2803","they have imagined",87,105]]},"10:3":{"text":"For the wicked boasteth of his heart's desire, and blesseth the covetous, whom the LORD abhorreth.","words":[["H7563","For the wicked",0,14],["H1984","boasteth",15,23],["H5315","of his heart's",24,38],["H8378","desire",39,45],["H1288","and blesseth",47,59],["H1214","the covetous",60,72],["H3068","whom the LORD",74,87],["H5006","abhorreth",88,97]]},"10:4":{"text":"The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts.","words":[["H7563","The wicked",0,10],["H1363","through the pride",12,29],["H0639","of his countenance",30,48],["H1875","will not seek",50,63],["H0430","after God: God",64,78],["H4209","is not in all his thoughts",79,105]]},"10:5":{"text":"His ways are always grievous; thy judgments are far above out of his sight: as for all his enemies, he puffeth at them.","words":[["H1870","His ways",0,8],["H6256","are always",9,19],["H2342","grievous",20,28],["H4941","thy judgments",30,43],["H4791","are far above",44,57],["H6887","out of his sight: as for all his enemies",58,98],["H6315","he puffeth",100,110]]},"10:6":{"text":"He hath said in his heart, I shall not be moved: for I shall never be in adversity.","words":[["H0559","He hath said",0,12],["H3820","in his heart",13,25],["H4131","I shall not be moved",27,47],["H1755","for I shall never",49,66],["H1755","for I shall never",49,66],["H7451","be in adversity",67,82]]},"10:7":{"text":"His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity.","words":[["H6310","His mouth",0,9],["H4390","is full",10,17],["H0423","of cursing",18,28],["H4820","and deceit",29,39],["H8496","and fraud",40,49],["H3956","under his tongue",51,67],["H5999","is mischief",68,79],["H0205","and vanity",80,90]]},"10:8":{"text":"He sitteth in the lurking places of the villages: in the secret places doth he murder the innocent: his eyes are privily set against the poor.","words":[["H3427","He sitteth",0,10],["H3993","in the lurking places",11,32],["H2691","of the villages",33,48],["H4565","in the secret places",50,70],["H2026","doth he murder",71,85],["H5355","the innocent",86,98],["H5869","his eyes",100,108],["H6845","are privily set",109,124],["H2489","against the poor",125,141]]},"10:9":{"text":"He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor: he doth catch the poor, when he draweth him into his net.","words":[["H0693","He lieth in wait",0,16],["H4565","secretly",17,25],["H0738","as a lion",26,35],["H5520","in his den",36,46],["H0693","he lieth in wait",48,64],["H2414","to catch",65,73],["H6041","the poor",74,82],["H2414","he doth catch",84,97],["H6041","the poor",98,106],["H4900","when he draweth",108,123],["H7568","him into his net",124,140]]},"10:10":{"text":"He croucheth, and humbleth himself, that the poor may fall by his strong ones.","words":[["H1794","He croucheth",0,12],["H7817","and humbleth",14,26],["H2426","himself, that the poor",27,49],["H2489","himself, that the poor",27,49],["H2489","himself, that the poor",27,49],["H5307","may fall",50,58],["H6099","by his strong ones",59,77]]},"10:11":{"text":"He hath said in his heart, God hath forgotten: he hideth his face; he will never see it.","words":[["H0559","He hath said",0,12],["H3820","in his heart",13,25],["H0410","God",27,30],["H7911","hath forgotten",31,45],["H5641","he hideth",47,56],["H6440","his face",57,65],["H5331","he will never",67,80],["H7200","see",81,84]]},"10:12":{"text":"Arise, O LORD; O God, lift up thine hand: forget not the humble.","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H0410","O God",15,20],["H5375","lift up",22,29],["H3027","thine hand",30,40],["H7911","forget",42,48],["H6035","not the humble",49,63],["H6041","not the humble",49,63]]},"10:13":{"text":"Wherefore doth the wicked contemn God? he hath said in his heart, Thou wilt not require it.","words":[["H7563","Wherefore doth the wicked",0,25],["H5006","contemn",26,33],["H0430","God",34,37],["H0559","he hath said",39,51],["H3820","in his heart",52,64],["H1875","Thou wilt not require",66,87]]},"10:14":{"text":"Thou hast seen it; for thou beholdest mischief and spite, to requite it with thy hand: the poor committeth himself unto thee; thou art the helper of the fatherless.","words":[["H7200","Thou hast seen",0,14],["H5027","it; for thou beholdest",15,37],["H5999","mischief",38,46],["H3708","and spite",47,56],["H5414","to requite",58,68],["H3027","it with thy hand",69,85],["H2489","the poor",87,95],["H5800","committeth",96,106],["H5826","himself unto thee; thou art the helper",107,145],["H3490","of the fatherless",146,163]]},"10:15":{"text":"Break thou the arm of the wicked and the evil man: seek out his wickedness till thou find none.","words":[["H7665","Break",0,5],["H2220","thou the arm",6,18],["H7563","of the wicked",19,32],["H7451","and the evil",33,45],["H1875","man: seek out",46,59],["H7562","his wickedness",60,74],["H4672","till thou find",75,89],["H1077","none",90,94]]},"10:16":{"text":"The LORD is King for ever and ever: the heathen are perished out of his land.","words":[["H3068","The LORD",0,8],["H4428","is King",9,16],["H5769","for ever",17,25],["H5703","and ever",26,34],["H1471","the heathen",36,47],["H0006","are perished",48,60],["H0776","out of his land",61,76]]},"10:17":{"text":"LORD, thou hast heard the desire of the humble: thou wilt prepare their heart, thou wilt cause thine ear to hear:","words":[["H3068","LORD",0,4],["H8085","thou hast heard",6,21],["H8378","the desire",22,32],["H6035","of the humble",33,46],["H3559","thou wilt prepare",48,65],["H3820","their heart",66,77],["H0241","thou wilt cause thine ear",79,104],["H7181","to hear",105,112]]},"10:18":{"text":"To judge the fatherless and the oppressed, that the man of the earth may no more oppress.","words":[["H8199","To judge",0,8],["H3490","the fatherless",9,23],["H1790","and the oppressed",24,41],["H0582","that the man",43,55],["H0776","of the earth",56,68],["H3254","may no more",69,80],["H6206","oppress",81,88]]},"11:1":{"text":"To the chief Musician, A Psalm of David. In the LORD put I my trust: how say ye to my soul, Flee as a bird to your mountain?","words":[["H5329","To the chief Musician",0,21],["H1732","A Psalm of David",23,39],["H3068","In the LORD",41,52],["H2620","put I my trust",53,67],["H0559","how say",69,76],["H5315","ye to my soul",77,90],["H5110","Flee",92,96],["H6833","as a bird",97,106],["H2022","to your mountain",107,123]]},"11:2":{"text":"For, lo, the wicked bend their bow, they make ready their arrow upon the string, that they may privily shoot at the upright in heart.","words":[["H7563","For, lo, the wicked",0,19],["H1869","bend",20,24],["H7198","their bow",25,34],["H3559","they make ready",36,51],["H2671","their arrow",52,63],["H3499","upon the string",64,79],["H0652","that they may privily",81,102],["H1119","that they may privily",81,102],["H3384","shoot",103,108],["H3477","at the upright",109,123],["H3820","in heart",124,132]]},"11:3":{"text":"If the foundations be destroyed, what can the righteous do?","words":[["H8356","If the foundations",0,18],["H2040","be destroyed",19,31],["H6662","what can the righteous",33,55],["H6466","do",56,58]]},"11:4":{"text":"The LORD is in his holy temple, the LORD'S throne is in heaven: his eyes behold, his eyelids try, the children of men.","words":[["H3068","The LORD",0,8],["H6944","is in his holy",9,23],["H1964","temple",24,30],["H3068","the LORD'S",32,42],["H3678","throne",43,49],["H8064","is in heaven",50,62],["H5869","his eyes",64,72],["H2372","behold",73,79],["H6079","his eyelids",81,92],["H0974","try",93,96],["H1121","the children",98,110],["H0120","of men",111,117]]},"11:5":{"text":"The LORD trieth the righteous: but the wicked and him that loveth violence his soul hateth.","words":[["H3068","The LORD",0,8],["H0974","trieth",9,15],["H6662","the righteous",16,29],["H7563","but the wicked",31,45],["H0157","and him that loveth",46,65],["H2555","violence",66,74],["H5315","his soul",75,83],["H8130","hateth",84,90]]},"11:6":{"text":"Upon the wicked he shall rain snares, fire and brimstone, and an horrible tempest: this shall be the portion of their cup.","words":[["H7563","Upon the wicked",0,15],["H4305","he shall rain",16,29],["H6341","snares",30,36],["H0784","fire",38,42],["H1614","and brimstone",43,56],["H2152","and an horrible",58,73],["H7307","tempest",74,81],["H4521","this shall be the portion",83,108],["H3563","of their cup",109,121]]},"11:7":{"text":"For the righteous LORD loveth righteousness; his countenance doth behold the upright.","words":[["H6662","For the righteous",0,17],["H3068","LORD",18,22],["H0157","loveth",23,29],["H6666","righteousness",30,43],["H6440","his countenance",45,60],["H2372","doth behold",61,72],["H3477","the upright",73,84]]},"12:1":{"text":"To the chief Musician upon Sheminith, A Psalm of David. Help, LORD; for the godly man ceaseth; for the faithful fail from among the children of men.","words":[["H5329","To the chief Musician",0,21],["H8067","upon Sheminith",22,36],["H4210","A Psalm",38,45],["H1732","of David",46,54],["H3467","Help",56,60],["H3068","LORD",62,66],["H2623","for the godly man",68,85],["H1584","ceaseth",86,93],["H0539","for the faithful",95,111],["H6461","fail",112,116],["H1121","from among the children",117,140],["H0120","of men",141,147]]},"12:2":{"text":"They speak vanity every one with his neighbour: with flattering lips and with a double heart do they speak.","words":[["H1696","They speak",0,10],["H7723","vanity",11,17],["H0376","every one",18,27],["H7453","with his neighbour",28,46],["H2513","with flattering",48,63],["H8193","lips",64,68],["H3820","and with a double",69,86],["H3820","heart",87,92],["H1696","do they speak",93,106]]},"12:3":{"text":"The LORD shall cut off all flattering lips, and the tongue that speaketh proud things:","words":[["H3068","The LORD",0,8],["H3772","shall cut off",9,22],["H2513","all flattering",23,37],["H8193","lips",38,42],["H3956","and the tongue",44,58],["H1696","that speaketh",59,72],["H1419","proud",73,78]]},"12:4":{"text":"Who have said, With our tongue will we prevail; our lips are our own: who is lord over us?","words":[["H0559","Who have said",0,13],["H3956","With our tongue",15,30],["H1396","will we prevail",31,46],["H8193","our lips",48,56],["H0113","are our own: who is lord",57,81]]},"12:5":{"text":"For the oppression of the poor, for the sighing of the needy, now will I arise, saith the LORD; I will set him in safety from him that puffeth at him.","words":[["H7701","For the oppression",0,18],["H6041","of the poor",19,30],["H0603","for the sighing",32,47],["H0034","of the needy",48,60],["H6965","now will I arise",62,78],["H0559","saith",80,85],["H3068","the LORD",86,94],["H7896","I will set",96,106],["H3468","him in safety",107,120],["H6315","from him that puffeth",121,142]]},"12:6":{"text":"The words of the LORD are pure words: as silver tried in a furnace of earth, purified seven times.","words":[["H0565","The words",0,9],["H3068","of the LORD",10,21],["H2889","are pure",22,30],["H0565","words",31,36],["H3701","as silver",38,47],["H6884","tried",48,53],["H5948","in a furnace",54,66],["H0776","of earth",67,75],["H2212","purified",77,85],["H7659","seven times",86,97]]},"12:7":{"text":"Thou shalt keep them, O LORD, thou shalt preserve them from this generation for ever.","words":[["H8104","Thou shalt keep",0,15],["H3068","them, O LORD",16,28],["H5341","thou shalt preserve",30,49],["H2098","them from this",50,64],["H1755","generation",65,75],["H5769","for ever",76,84]]},"12:8":{"text":"The wicked walk on every side, when the vilest men are exalted.","words":[["H7563","The wicked",0,10],["H1980","walk",11,15],["H5439","on every side",16,29],["H2149","when the vilest",31,46],["H1121","men",47,50],["H0120","men",47,50],["H7311","are exalted",51,62]]},"13:1":{"text":"To the chief Musician, A Psalm of David. How long wilt thou forget me, O LORD? for ever? how long wilt thou hide thy face from me?","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H7911","How long wilt thou forget",41,66],["H3068","me, O LORD",67,77],["H5331","for ever",79,87],["H5641","how long wilt thou hide",89,112],["H6440","thy face",113,121]]},"13:2":{"text":"How long shall I take counsel in my soul, having sorrow in my heart daily? how long shall mine enemy be exalted over me?","words":[["H7896","How long shall I take",0,21],["H6098","counsel",22,29],["H5315","in my soul",30,40],["H3015","having sorrow",42,55],["H3824","in my heart",56,67],["H3119","daily",68,73],["H0341","how long shall mine enemy",75,100],["H7311","be exalted",101,111]]},"13:3":{"text":"Consider and hear me, O LORD my God: lighten mine eyes, lest I sleep the sleep of death;","words":[["H5027","Consider",0,8],["H6030","and hear",9,17],["H3068","me, O LORD",18,28],["H0430","my God",29,35],["H0215","lighten",37,44],["H5869","mine eyes",45,54],["H3462","lest I sleep",56,68],["H4194","the sleep of death",69,87]]},"13:4":{"text":"Lest mine enemy say, I have prevailed against him; and those that trouble me rejoice when I am moved.","words":[["H0341","Lest mine enemy",0,15],["H0559","say",16,19],["H3201","I have prevailed",21,37],["H6862","against him; and those that trouble",38,73],["H1523","me rejoice",74,84],["H4131","when I am moved",85,100]]},"13:5":{"text":"But I have trusted in thy mercy; my heart shall rejoice in thy salvation.","words":[["H0982","But I have trusted",0,18],["H2617","in thy mercy",19,31],["H3820","my heart",33,41],["H1523","shall rejoice",42,55],["H3444","in thy salvation",56,72]]},"13:6":{"text":"I will sing unto the LORD, because he hath dealt bountifully with me.","words":[["H7891","I will sing",0,11],["H3068","unto the LORD",12,25],["H1580","because he hath dealt bountifully",27,60]]},"14:1":{"text":"To the chief Musician, A Psalm of David. The fool hath said in his heart, There is no God. They are corrupt, they have done abominable works, there is none that doeth good.","words":[["H5329","To the chief Musician",0,21],["H1732","A Psalm of David",23,39],["H5036","The fool",41,49],["H0559","hath said",50,59],["H3820","in his heart",60,72],["H0430","There is no God",74,89],["H7843","They are corrupt",91,107],["H8581","they have done abominable",109,134],["H5949","works",135,140],["H6213","there is none that doeth",142,166],["H2896","good",167,171]]},"14:2":{"text":"The LORD looked down from heaven upon the children of men, to see if there were any that did understand, and seek God.","words":[["H3068","The LORD",0,8],["H8259","looked down",9,20],["H8064","from heaven",21,32],["H1121","upon the children",33,50],["H0120","of men",51,57],["H7200","to see",59,65],["H3426","if there",66,74],["H7919","were any that did understand",75,103],["H1875","and seek",105,113],["H0430","God",114,117]]},"14:3":{"text":"They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one.","words":[["H5493","They are all gone aside",0,23],["H3162","they are all together",25,46],["H0444","become filthy",47,60],["H6213","there is none that doeth",62,86],["H2896","good",87,91],["H0259","no, not one",93,104]]},"14:4":{"text":"Have all the workers of iniquity no knowledge? who eat up my people as they eat bread, and call not upon the LORD.","words":[["H6466","Have all the workers",0,20],["H0205","of iniquity",21,32],["H3045","no knowledge",33,45],["H0398","who eat up",47,57],["H5971","my people",58,67],["H0398","as they eat",68,79],["H3899","bread",80,85],["H7121","and call",87,95],["H3068","not upon the LORD",96,113]]},"14:5":{"text":"There were they in great fear: for God is in the generation of the righteous.","words":[["H6343","There were they in great",0,24],["H6342","fear",25,29],["H0430","for God",31,38],["H1755","is in the generation",39,59],["H6662","of the righteous",60,76]]},"14:6":{"text":"Ye have shamed the counsel of the poor, because the LORD is his refuge.","words":[["H0954","Ye have shamed",0,14],["H6098","the counsel",15,26],["H6041","of the poor",27,38],["H3068","because the LORD",40,56],["H4268","is his refuge",57,70]]},"14:7":{"text":"Oh that the salvation of Israel were come out of Zion! when the LORD bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad.","words":[["H5414","Oh that",0,7],["H3444","the salvation",8,21],["H3478","of Israel",22,31],["H6726","were come out of Zion",32,53],["H3068","when the LORD",55,68],["H7725","bringeth back",69,82],["H7622","the captivity",83,96],["H5971","of his people",97,110],["H3290","Jacob",112,117],["H1523","shall rejoice",118,131],["H3478","and Israel",133,143],["H8055","shall be glad",144,157]]},"15:1":{"text":"A Psalm of David. LORD, who shall abide in thy tabernacle? who shall dwell in thy holy hill?","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H3068","LORD",18,22],["H1481","who shall abide",24,39],["H0168","in thy tabernacle",40,57],["H7931","who shall dwell",59,74],["H6944","in thy holy",75,86],["H2022","hill",87,91]]},"15:2":{"text":"He that walketh uprightly, and worketh righteousness, and speaketh the truth in his heart.","words":[["H1980","He that walketh",0,15],["H8549","uprightly",16,25],["H6466","and worketh",27,38],["H6664","righteousness",39,52],["H1696","and speaketh",54,66],["H0571","the truth",67,76],["H3824","in his heart",77,89]]},"15:3":{"text":"He that backbiteth not with his tongue, nor doeth evil to his neighbour, nor taketh up a reproach against his neighbour.","words":[["H7270","He that backbiteth",0,18],["H3956","not with his tongue",19,38],["H6213","nor doeth",40,49],["H7451","evil",50,54],["H7453","to his neighbour",55,71],["H5375","nor taketh up",73,86],["H2781","a reproach",87,97],["H7138","against his neighbour",98,119]]},"15:4":{"text":"In whose eyes a vile person is contemned; but he honoureth them that fear the LORD. He that sweareth to his own hurt, and changeth not.","words":[["H5869","In whose eyes",0,13],["H3988","a vile person",14,27],["H0959","is contemned",28,40],["H3513","but he honoureth",42,58],["H3373","them that fear",59,73],["H3068","the LORD",74,82],["H7650","He that sweareth",84,100],["H7489","to his own hurt",101,116],["H4171","and changeth",118,130]]},"15:5":{"text":"He that putteth not out his money to usury, nor taketh reward against the innocent. He that doeth these things shall never be moved.","words":[["H5414","He that putteth not out",0,23],["H3701","his money",24,33],["H5392","to usury",34,42],["H3947","nor taketh",44,54],["H7810","reward",55,61],["H5355","against the innocent",62,82],["H6213","He that doeth",84,97],["H5769","these things shall never",98,122],["H4131","be moved",123,131]]},"16:1":{"text":"Michtam of David. Preserve me, O God: for in thee do I put my trust.","words":[["H4387","Michtam",0,7],["H1732","of David",8,16],["H8104","Preserve",18,26],["H0410","me, O God",27,36],["H2620","for in thee do I put my trust",38,67]]},"16:2":{"text":"O my soul, thou hast said unto the LORD, Thou art my Lord: my goodness extendeth not to thee;","words":[["H0559","O my soul, thou hast said",0,25],["H3068","unto the LORD",26,39],["H0136","Thou art my Lord",41,57],["H2896","my goodness",59,70]]},"16:3":{"text":"But to the saints that are in the earth, and to the excellent, in whom is all my delight.","words":[["H6918","But to the saints",0,17],["H1992","that",18,22],["H0776","are in the earth",23,39],["H0117","and to the excellent",41,61],["H2656","in whom is all my delight",63,88]]},"16:4":{"text":"Their sorrows shall be multiplied that hasten after another god: their drink offerings of blood will I not offer, nor take up their names into my lips.","words":[["H6094","Their sorrows",0,13],["H7235","shall be multiplied",14,33],["H4116","that hasten",34,45],["H0312","after another",46,59],["H5262","god: their drink offerings",60,86],["H1818","of blood",87,95],["H5258","will I not offer",96,112],["H1077","nor",114,117],["H5375","take up",118,125],["H8034","their names",126,137],["H8193","into my lips",138,150]]},"16:5":{"text":"The LORD is the portion of mine inheritance and of my cup: thou maintainest my lot.","words":[["H3068","The LORD",0,8],["H4490","is the portion",9,23],["H2506","of mine inheritance",24,43],["H3563","and of my cup",44,57],["H8551","thou maintainest",59,75],["H1486","my lot",76,82]]},"16:6":{"text":"The lines are fallen unto me in pleasant places; yea, I have a goodly heritage.","words":[["H2256","The lines",0,9],["H5307","are fallen",10,20],["H5273","unto me in pleasant",21,40],["H8231","places; yea, I have a goodly",41,69],["H5159","heritage",70,78]]},"16:7":{"text":"I will bless the LORD, who hath given me counsel: my reins also instruct me in the night seasons.","words":[["H1288","I will bless",0,12],["H3068","the LORD",13,21],["H3289","who hath given me counsel",23,48],["H3629","my reins",50,58],["H3256","also instruct",59,72],["H3915","me in the night seasons",73,96]]},"16:8":{"text":"I have set the LORD always before me: because he is at my right hand, I shall not be moved.","words":[["H7737","I have set",0,10],["H3068","the LORD",11,19],["H8548","always",20,26],["H3225","before me: because he is at my right hand",27,68],["H4131","I shall not be moved",70,90]]},"16:9":{"text":"Therefore my heart is glad, and my glory rejoiceth: my flesh also shall rest in hope.","words":[["H3820","Therefore my heart",0,18],["H8055","is glad",19,26],["H3519","and my glory",28,40],["H1523","rejoiceth",41,50],["H1320","my flesh",52,60],["H7931","also shall rest",61,76],["H0983","in hope",77,84]]},"16:10":{"text":"For thou wilt not leave my soul in hell; neither wilt thou suffer thine Holy One to see corruption.","words":[["H5800","For thou wilt not leave",0,23],["H5315","my soul",24,31],["H7585","in hell",32,39],["H5414","neither wilt thou suffer",41,65],["H2623","thine Holy One",66,80],["H7200","to see",81,87],["H7845","corruption",88,98]]},"16:11":{"text":"Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore.","words":[["H3045","Thou wilt shew",0,14],["H0734","me the path",15,26],["H2416","of life",27,34],["H6440","in thy presence",36,51],["H7648","is fulness",52,62],["H8057","of joy",63,69],["H3225","at thy right hand",71,88],["H5273","there are pleasures",89,108],["H5331","for evermore",109,121]]},"17:1":{"text":"A Prayer of David. Hear the right, O LORD, attend unto my cry, give ear unto my prayer, that goeth not out of feigned lips.","words":[["H8605","A Prayer",0,8],["H1732","of David",9,17],["H8085","Hear",19,23],["H6664","the right",24,33],["H3068","O LORD",35,41],["H7181","attend",43,49],["H7440","unto my cry",50,61],["H0238","give ear",63,71],["H8605","unto my prayer",72,86],["H3808","that goeth not",88,102],["H4820","out of feigned",103,117],["H8193","lips",118,122]]},"17:2":{"text":"Let my sentence come forth from thy presence; let thine eyes behold the things that are equal.","words":[["H4941","Let my sentence",0,15],["H3318","come forth",16,26],["H6440","from thy presence",27,44],["H5869","let thine eyes",46,60],["H2372","behold",61,67],["H4339","the things that are equal",68,93]]},"17:3":{"text":"Thou hast proved mine heart; thou hast visited me in the night; thou hast tried me, and shalt find nothing; I am purposed that my mouth shall not transgress.","words":[["H0974","Thou hast proved",0,16],["H3820","mine heart",17,27],["H6485","thou hast visited",29,46],["H3915","me in the night",47,62],["H6884","thou hast tried",64,79],["H4672","me, and shalt find",80,98],["H2161","nothing; I am purposed",99,121],["H6310","that my mouth",122,135],["H5674","shall not transgress",136,156]]},"17:4":{"text":"Concerning the works of men, by the word of thy lips I have kept me from the paths of the destroyer.","words":[["H6468","Concerning the works",0,20],["H0120","of men",21,27],["H1697","by the word",29,40],["H8193","of thy lips",41,52],["H8104","I have kept",53,64],["H0734","me from the paths",65,82],["H6530","of the destroyer",83,99]]},"17:5":{"text":"Hold up my goings in thy paths, that my footsteps slip not.","words":[["H8551","Hold up",0,7],["H0838","my goings",8,17],["H4570","in thy paths",18,30],["H6471","that my footsteps",32,49],["H4131","slip",50,54]]},"17:6":{"text":"I have called upon thee, for thou wilt hear me, O God: incline thine ear unto me, and hear my speech.","words":[["H7121","I have called",0,13],["H6030","upon thee, for thou wilt hear",14,43],["H0410","me, O God",44,53],["H5186","incline",55,62],["H0241","thine ear",63,72],["H8085","unto me, and hear",73,90],["H0565","my speech",91,100]]},"17:7":{"text":"Shew thy marvellous lovingkindness, O thou that savest by thy right hand them which put their trust in thee from those that rise up against them.","words":[["H6395","Shew thy marvellous",0,19],["H2617","lovingkindness",20,34],["H3467","O thou that savest",36,54],["H3225","by thy right hand",55,72],["H2620","them which put their trust",73,99],["H6965","in thee from those that rise up",100,131]]},"17:8":{"text":"Keep me as the apple of the eye, hide me under the shadow of thy wings,","words":[["H8104","Keep",0,4],["H0380","me as the apple",5,20],["H1323","of the eye",21,31],["H5869","of the eye",21,31],["H5641","hide",33,37],["H6738","me under the shadow",38,57],["H3671","of thy wings",58,70]]},"17:9":{"text":"From the wicked that oppress me, from my deadly enemies, who compass me about.","words":[["H6440","From",0,4],["H7563","the wicked",5,15],["H2098","that",16,20],["H7703","oppress",21,28],["H5315","me, from my deadly",29,47],["H0341","enemies",48,55],["H5362","who compass me about",57,77]]},"17:10":{"text":"They are inclosed in their own fat: with their mouth they speak proudly.","words":[["H5462","They are inclosed",0,17],["H2459","in their own fat",18,34],["H6310","with their mouth",36,52],["H1696","they speak",53,63],["H1348","proudly",64,71]]},"17:11":{"text":"They have now compassed us in our steps: they have set their eyes bowing down to the earth;","words":[["H5437","They have now compassed",0,23],["H0838","us in our steps",24,39],["H7896","they have set",41,54],["H5869","their eyes",55,65],["H5186","bowing down",66,77],["H0776","to the earth",78,90]]},"17:12":{"text":"Like as a lion that is greedy of his prey, and as it were a young lion lurking in secret places.","words":[["H1825","Like",0,4],["H0738","as a lion",5,14],["H3700","that is greedy",15,29],["H2963","of his prey",30,41],["H3715","and as it were a young lion",43,70],["H3427","lurking",71,78],["H4565","in secret places",79,95]]},"17:13":{"text":"Arise, O LORD, disappoint him, cast him down: deliver my soul from the wicked, which is thy sword:","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H6923","disappoint",15,25],["H6440","him",26,29],["H3766","cast him down",31,44],["H6403","deliver",46,53],["H5315","my soul",54,61],["H7563","from the wicked",62,77],["H2719","which is thy sword",79,97]]},"17:14":{"text":"From men which are thy hand, O LORD, from men of the world, which have their portion in this life, and whose belly thou fillest with thy hid treasure: they are full of children, and leave the rest of their substance to their babes.","words":[["H4962","From men",0,8],["H3027","which are thy hand",9,27],["H3068","O LORD",29,35],["H4962","from men",37,45],["H2465","of the world",46,58],["H2506","which have their portion",60,84],["H2416","in this life",85,97],["H0990","and whose belly",99,114],["H4390","thou fillest",115,127],["H6840","with thy hid",128,140],["H7646","treasure: they are full",141,164],["H1121","of children",165,176],["H3240","and leave",178,187],["H3499","the rest",188,196],["H5768","of their substance to their babes",197,230]]},"17:15":{"text":"As for me, I will behold thy face in righteousness: I shall be satisfied, when I awake, with thy likeness.","words":[["H2372","As for me, I will behold",0,24],["H6440","thy face",25,33],["H6664","in righteousness",34,50],["H7646","I shall be satisfied",52,72],["H6974","when I awake",74,86],["H8544","with thy likeness",88,105]]},"18:1":{"text":"To the chief Musician, A Psalm of David, the servant of the LORD, who spake unto the LORD the words of this song in the day that the LORD delivered him from the hand of all his enemies, and from the hand of Saul: And he said, I will love thee, O LORD, my strength.","words":[["H5329","To the chief Musician",0,21],["H1732","A Psalm of David",23,39],["H5650","the servant",41,52],["H3068","of the LORD",53,64],["H1696","who spake",66,75],["H3068","unto the LORD",76,89],["H1697","the words",90,99],["H7892","of this song",100,112],["H3117","in the day",113,123],["H3068","that the LORD",124,137],["H5337","delivered",138,147],["H3709","him from the hand",148,165],["H0341","of all his enemies",166,184],["H3027","and from the hand",186,203],["H7586","of Saul",204,211],["H0559","And he said",213,224],["H7355","I will love",226,237],["H3068","thee, O LORD",238,250],["H2391","my strength",252,263]]},"18:2":{"text":"The LORD is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower.","words":[["H3068","The LORD",0,8],["H5553","is my rock",9,19],["H4686","and my fortress",21,36],["H6403","and my deliverer",38,54],["H0410","my God",56,62],["H6697","my strength",64,75],["H2620","in whom I will trust",77,97],["H4043","my buckler",99,109],["H7161","and the horn",111,123],["H3468","of my salvation",124,139],["H4869","and my high tower",141,158]]},"18:3":{"text":"I will call upon the LORD, who is worthy to be praised: so shall I be saved from mine enemies.","words":[["H7121","I will call",0,11],["H3068","upon the LORD",12,25],["H1984","who is worthy to be praised",27,54],["H3467","so shall I be saved",56,75],["H0341","from mine enemies",76,93]]},"18:4":{"text":"The sorrows of death compassed me, and the floods of ungodly men made me afraid.","words":[["H2256","The sorrows",0,11],["H4194","of death",12,20],["H0661","compassed",21,30],["H5158","me, and the floods",31,49],["H1100","of ungodly men",50,64],["H1204","made me afraid",65,79]]},"18:5":{"text":"The sorrows of hell compassed me about: the snares of death prevented me.","words":[["H2256","The sorrows",0,11],["H7585","of hell",12,19],["H5437","compassed me about",20,38],["H4170","the snares",40,50],["H4194","of death",51,59],["H6923","prevented",60,69]]},"18:6":{"text":"In my distress I called upon the LORD, and cried unto my God: he heard my voice out of his temple, and my cry came before him, even into his ears.","words":[["H6862","In my distress",0,14],["H7121","I called",15,23],["H3068","upon the LORD",24,37],["H7768","and cried",39,48],["H0430","unto my God",49,60],["H8085","he heard",62,70],["H6963","my voice",71,79],["H1964","out of his temple",80,97],["H7775","and my cry",99,109],["H0935","came",110,114],["H6440","before",115,121],["H0241","him, even into his ears",122,145]]},"18:7":{"text":"Then the earth shook and trembled; the foundations also of the hills moved and were shaken, because he was wroth.","words":[["H0776","Then the earth",0,14],["H1607","shook",15,20],["H7493","and trembled",21,33],["H4146","the foundations",35,50],["H2022","also of the hills",51,68],["H7264","moved",69,74],["H1607","and were shaken",75,90],["H2734","because he was wroth",92,112]]},"18:8":{"text":"There went up a smoke out of his nostrils, and fire out of his mouth devoured: coals were kindled by it.","words":[["H5927","There went up",0,13],["H6227","a smoke",14,21],["H0639","out of his nostrils",22,41],["H0784","and fire",43,51],["H6310","out of his mouth",52,68],["H0398","devoured",69,77],["H1513","coals",79,84],["H1197","were kindled",85,97]]},"18:9":{"text":"He bowed the heavens also, and came down: and darkness was under his feet.","words":[["H5186","He bowed",0,8],["H8064","the heavens",9,20],["H3381","also, and came down",21,40],["H6205","and darkness",42,54],["H7272","was under his feet",55,73]]},"18:10":{"text":"And he rode upon a cherub, and did fly: yea, he did fly upon the wings of the wind.","words":[["H7392","And he rode",0,11],["H3742","upon a cherub",12,25],["H5774","and did fly",27,38],["H1675","yea, he did fly",40,55],["H3671","upon the wings",56,70],["H7307","of the wind",71,82]]},"18:11":{"text":"He made darkness his secret place; his pavilion round about him were dark waters and thick clouds of the skies.","words":[["H7896","He made",0,7],["H2822","darkness",8,16],["H5643","his secret place",17,33],["H5521","his pavilion",35,47],["H5439","round about",48,59],["H2824","him were dark",60,73],["H4325","waters",74,80],["H5645","and thick clouds",81,97],["H7834","of the skies",98,110]]},"18:12":{"text":"At the brightness that was before him his thick clouds passed, hail stones and coals of fire.","words":[["H5051","At the brightness",0,17],["H5645","that was before him his thick clouds",18,54],["H5674","passed",55,61],["H1259","hail",63,67],["H1513","stones and coals",68,84],["H0784","of fire",85,92]]},"18:13":{"text":"The LORD also thundered in the heavens, and the Highest gave his voice; hail stones and coals of fire.","words":[["H3068","The LORD",0,8],["H7481","also thundered",9,23],["H8064","in the heavens",24,38],["H5945","and the Highest",40,55],["H5414","gave",56,60],["H6963","his voice",61,70],["H1259","hail",72,76],["H1513","stones and coals",77,93],["H0784","of fire",94,101]]},"18:14":{"text":"Yea, he sent out his arrows, and scattered them; and he shot out lightnings, and discomfited them.","words":[["H7971","Yea, he sent out",0,16],["H2671","his arrows",17,27],["H6327","and scattered",29,42],["H7232","them; and he shot out",43,64],["H1300","lightnings",65,75],["H2000","and discomfited",77,92]]},"18:15":{"text":"Then the channels of waters were seen, and the foundations of the world were discovered at thy rebuke, O LORD, at the blast of the breath of thy nostrils.","words":[["H0650","Then the channels",0,17],["H4325","of waters",18,27],["H7200","were seen",28,37],["H4146","and the foundations",39,58],["H8398","of the world",59,71],["H1540","were discovered",72,87],["H1606","at thy rebuke",88,101],["H3068","O LORD",103,109],["H5397","at the blast",111,123],["H7307","of the breath",124,137],["H0639","of thy nostrils",138,153]]},"18:16":{"text":"He sent from above, he took me, he drew me out of many waters.","words":[["H7971","He sent",0,7],["H4791","from above",8,18],["H3947","he took",20,27],["H4871","me, he drew",28,39],["H7227","me out of many",40,54],["H4325","waters",55,61]]},"18:17":{"text":"He delivered me from my strong enemy, and from them which hated me: for they were too strong for me.","words":[["H5337","He delivered",0,12],["H5794","me from my strong",13,30],["H0341","enemy",31,36],["H8130","and from them which hated",38,63],["H0553","me: for they were too strong",64,92]]},"18:18":{"text":"They prevented me in the day of my calamity: but the LORD was my stay.","words":[["H6923","They prevented",0,14],["H3117","me in the day",15,28],["H0343","of my calamity",29,43],["H3068","but the LORD",45,57],["H4937","was my stay",58,69]]},"18:19":{"text":"He brought me forth also into a large place; he delivered me, because he delighted in me.","words":[["H3318","He brought me forth",0,19],["H4800","also into a large place",20,43],["H2502","he delivered",45,57],["H2654","me, because he delighted",58,82]]},"18:20":{"text":"The LORD rewarded me according to my righteousness; according to the cleanness of my hands hath he recompensed me.","words":[["H3068","The LORD",0,8],["H1580","rewarded",9,17],["H6664","me according to my righteousness",18,50],["H1252","according to the cleanness",52,78],["H3027","of my hands",79,90],["H7725","hath he recompensed",91,110]]},"18:21":{"text":"For I have kept the ways of the LORD, and have not wickedly departed from my God.","words":[["H8104","For I have kept",0,15],["H1870","the ways",16,24],["H3068","of the LORD",25,36],["H7561","and have not wickedly departed",38,68],["H0430","from my God",69,80]]},"18:22":{"text":"For all his judgments were before me, and I did not put away his statutes from me.","words":[["H4941","For all his judgments",0,21],["H5493","were before me, and I did not put away",22,60],["H2708","his statutes",61,73]]},"18:23":{"text":"I was also upright before him, and I kept myself from mine iniquity.","words":[["H8549","I was also upright",0,18],["H8104","before him, and I kept",19,41],["H5771","myself from mine iniquity",42,67]]},"18:24":{"text":"Therefore hath the LORD recompensed me according to my righteousness, according to the cleanness of my hands in his eyesight.","words":[["H3068","Therefore hath the LORD",0,23],["H7725","recompensed",24,35],["H6664","me according to my righteousness",36,68],["H1252","according to the cleanness",70,96],["H3027","of my hands",97,108],["H5869","in his eyesight",109,124]]},"18:25":{"text":"With the merciful thou wilt shew thyself merciful; with an upright man thou wilt shew thyself upright;","words":[["H2623","With the merciful",0,17],["H2616","thou wilt shew thyself merciful",18,49],["H8549","with an upright",51,66],["H1399","man",67,70],["H8552","thou wilt shew thyself upright",71,101]]},"18:26":{"text":"With the pure thou wilt shew thyself pure; and with the froward thou wilt shew thyself froward.","words":[["H1305","With the pure",0,13],["H1305","thou wilt shew thyself pure",14,41],["H6141","and with the froward",43,63],["H6617","thou wilt shew thyself froward",64,94]]},"18:27":{"text":"For thou wilt save the afflicted people; but wilt bring down high looks.","words":[["H3467","For thou wilt save",0,18],["H6041","the afflicted",19,32],["H5971","people",33,39],["H8213","but wilt bring down",41,60],["H7311","high",61,65],["H5869","looks",66,71]]},"18:28":{"text":"For thou wilt light my candle: the LORD my God will enlighten my darkness.","words":[["H0215","For thou wilt light",0,19],["H5216","my candle",20,29],["H3068","the LORD",31,39],["H0430","my God",40,46],["H5050","will enlighten",47,61],["H2822","my darkness",62,73]]},"18:29":{"text":"For by thee I have run through a troop; and by my God have I leaped over a wall.","words":[["H7323","For by thee I have run through",0,30],["H1416","a troop",31,38],["H0430","and by my God",40,53],["H1801","have I leaped over",54,72],["H7791","a wall",73,79]]},"18:30":{"text":"As for God, his way is perfect: the word of the LORD is tried: he is a buckler to all those that trust in him.","words":[["H0410","As for God",0,10],["H1870","his way",12,19],["H8549","is perfect",20,30],["H0565","the word",32,40],["H3068","of the LORD",41,52],["H6884","is tried",53,61],["H4043","he is a buckler",63,78],["H2620","to all those that trust",79,102]]},"18:31":{"text":"For who is God save the LORD? or who is a rock save our God?","words":[["H0433","For who is God",0,14],["H1107","save",15,19],["H3068","the LORD",20,28],["H6697","or who is a rock",30,46],["H2108","save",47,51],["H0430","our God",52,59]]},"18:32":{"text":"It is God that girdeth me with strength, and maketh my way perfect.","words":[["H0410","It is God",0,9],["H0247","that girdeth",10,22],["H2428","me with strength",23,39],["H5414","and maketh",41,51],["H1870","my way",52,58],["H8549","perfect",59,66]]},"18:33":{"text":"He maketh my feet like hinds' feet, and setteth me upon my high places.","words":[["H7737","He maketh",0,9],["H7272","my feet",10,17],["H0355","like hinds'",18,29],["H5975","feet, and setteth",30,47],["H1116","me upon my high places",48,70]]},"18:34":{"text":"He teacheth my hands to war, so that a bow of steel is broken by mine arms.","words":[["H3925","He teacheth",0,11],["H3027","my hands",12,20],["H4421","to war",21,27],["H7198","so that a bow",29,42],["H5154","of steel",43,51],["H5181","is broken",52,61],["H2220","by mine arms",62,74]]},"18:35":{"text":"Thou hast also given me the shield of thy salvation: and thy right hand hath holden me up, and thy gentleness hath made me great.","words":[["H5414","Thou hast also given",0,20],["H4043","me the shield",21,34],["H3468","of thy salvation",35,51],["H3225","and thy right hand",53,71],["H5582","hath holden me up",72,89],["H6037","and thy gentleness",91,109],["H7235","hath made me great",110,128]]},"18:36":{"text":"Thou hast enlarged my steps under me, that my feet did not slip.","words":[["H7337","Thou hast enlarged",0,18],["H6806","my steps",19,27],["H7166","under me, that my feet",28,50],["H4571","did not slip",51,63]]},"18:37":{"text":"I have pursued mine enemies, and overtaken them: neither did I turn again till they were consumed.","words":[["H7291","I have pursued",0,14],["H0341","mine enemies",15,27],["H5381","and overtaken",29,42],["H7725","them: neither did I turn again",43,73],["H3615","till they were consumed",74,97]]},"18:38":{"text":"I have wounded them that they were not able to rise: they are fallen under my feet.","words":[["H4272","I have wounded",0,14],["H3201","them that they were not able",15,43],["H6965","to rise",44,51],["H5307","they are fallen",53,68],["H7272","under my feet",69,82]]},"18:39":{"text":"For thou hast girded me with strength unto the battle: thou hast subdued under me those that rose up against me.","words":[["H0247","For thou hast girded",0,20],["H2428","me with strength",21,37],["H4421","unto the battle",38,53],["H3766","thou hast subdued",55,72],["H6965","under me those that rose up",73,100]]},"18:40":{"text":"Thou hast also given me the necks of mine enemies; that I might destroy them that hate me.","words":[["H5414","Thou hast also given",0,20],["H6203","me the necks",21,33],["H0341","of mine enemies",34,49],["H6789","that I might destroy",51,71],["H8130","them that hate",72,86]]},"18:41":{"text":"They cried, but there was none to save them: even unto the LORD, but he answered them not.","words":[["H7768","They cried",0,10],["H3467","but there was none to save",12,38],["H3068","them: even unto the LORD",39,63],["H6030","but he answered",65,80]]},"18:42":{"text":"Then did I beat them small as the dust before the wind: I did cast them out as the dirt in the streets.","words":[["H7833","Then did I beat",0,15],["H6083","them small as the dust",16,38],["H6440","before",39,45],["H7307","the wind",46,54],["H7324","I did cast them out",56,75],["H2916","as the dirt",76,87],["H2351","in the streets",88,102]]},"18:43":{"text":"Thou hast delivered me from the strivings of the people; and thou hast made me the head of the heathen: a people whom I have not known shall serve me.","words":[["H6403","Thou hast delivered",0,19],["H7379","me from the strivings",20,41],["H5971","of the people",42,55],["H7760","and thou hast made",57,75],["H7218","me the head",76,87],["H1471","of the heathen",88,102],["H5971","a people",104,112],["H3045","whom I have not known",113,134],["H5647","shall serve",135,146]]},"18:44":{"text":"As soon as they hear of me, they shall obey me: the strangers shall submit themselves unto me.","words":[["H8088","As soon as they hear",0,20],["H0241","As soon as they hear",0,20],["H8085","of me, they shall obey",21,43],["H1121","me: the strangers",44,61],["H5236","me: the strangers",44,61],["H3584","shall submit",62,74]]},"18:45":{"text":"The strangers shall fade away, and be afraid out of their close places.","words":[["H1121","The strangers",0,13],["H5236","The strangers",0,13],["H5034","shall fade away",14,29],["H2727","and be afraid",31,44],["H4526","out of their close places",45,70]]},"18:46":{"text":"The LORD liveth; and blessed be my rock; and let the God of my salvation be exalted.","words":[["H3068","The LORD",0,8],["H2416","liveth",9,15],["H1288","and blessed",17,28],["H6697","be my rock",29,39],["H0430","and let the God",41,56],["H3468","of my salvation",57,72],["H7311","be exalted",73,83]]},"18:47":{"text":"It is God that avengeth me, and subdueth the people under me.","words":[["H0410","It is God",0,9],["H5414","that avengeth",10,23],["H5360","that avengeth",10,23],["H1696","me, and subdueth",24,40],["H5971","the people",41,51]]},"18:48":{"text":"He delivereth me from mine enemies: yea, thou liftest me up above those that rise up against me: thou hast delivered me from the violent man.","words":[["H6403","He delivereth",0,13],["H0341","me from mine enemies",14,34],["H7311","yea, thou liftest me up",36,59],["H6965","above those that rise up",60,84],["H5337","against me: thou hast delivered",85,116],["H2555","me from the violent",117,136],["H0376","man",137,140]]},"18:49":{"text":"Therefore will I give thanks unto thee, O LORD, among the heathen, and sing praises unto thy name.","words":[["H3034","Therefore will I give thanks",0,28],["H3068","unto thee, O LORD",29,46],["H1471","among the heathen",48,65],["H2167","and sing praises",67,83],["H8034","unto thy name",84,97]]},"18:50":{"text":"Great deliverance giveth he to his king; and sheweth mercy to his anointed, to David, and to his seed for evermore.","words":[["H1431","Great",0,5],["H3444","deliverance",6,17],["H4428","giveth he to his king",18,39],["H6213","and sheweth",41,52],["H2617","mercy",53,58],["H4899","to his anointed",59,74],["H1732","to David",76,84],["H2233","and to his seed",86,101],["H5704","for",102,105],["H5769","evermore",106,114]]},"19:1":{"text":"To the chief Musician, A Psalm of David. The heavens declare the glory of God; and the firmament sheweth his handywork.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H8064","The heavens",41,52],["H5608","declare",53,60],["H3519","the glory",61,70],["H0410","of God",71,77],["H7549","and the firmament",79,96],["H5046","sheweth his",97,108],["H4639","handywork",109,118],["H3027","handywork",109,118]]},"19:2":{"text":"Day unto day uttereth speech, and night unto night sheweth knowledge.","words":[["H3117","Day",0,3],["H3117","unto day",4,12],["H5042","uttereth",13,21],["H0562","speech",22,28],["H3915","and night",30,39],["H3915","unto night",40,50],["H2331","sheweth",51,58],["H1847","knowledge",59,68]]},"19:3":{"text":"There is no speech nor language, where their voice is not heard.","words":[["H0562","There is no speech",0,18],["H1697","nor language",19,31],["H6963","where their voice",33,50],["H8085","is not heard",51,63]]},"19:4":{"text":"Their line is gone out through all the earth, and their words to the end of the world. In them hath he set a tabernacle for the sun,","words":[["H6957","Their line",0,10],["H3318","is gone out",11,22],["H0776","through all the earth",23,44],["H4405","and their words",46,61],["H7097","to the end",62,72],["H8398","of the world",73,85],["H7760","In them hath he set",87,106],["H0168","a tabernacle",107,119],["H8121","for the sun",120,131]]},"19:5":{"text":"Which is as a bridegroom coming out of his chamber, and rejoiceth as a strong man to run a race.","words":[["H2860","Which is as a bridegroom",0,24],["H3318","coming out",25,35],["H2646","of his chamber",36,50],["H7797","and rejoiceth",52,65],["H1368","as a strong man",66,81],["H7323","to run",82,88],["H0734","a race",89,95]]},"19:6":{"text":"His going forth is from the end of the heaven, and his circuit unto the ends of it: and there is nothing hid from the heat thereof.","words":[["H4161","His going forth",0,15],["H7097","is from the end",16,31],["H8064","of the heaven",32,45],["H8622","and his circuit",47,62],["H7098","unto the ends",63,76],["H5641","of it: and there is nothing hid",77,108],["H2535","from the heat",109,122]]},"19:7":{"text":"The law of the LORD is perfect, converting the soul: the testimony of the LORD is sure, making wise the simple.","words":[["H8451","The law",0,7],["H3068","of the LORD",8,19],["H8549","is perfect",20,30],["H7725","converting",32,42],["H5315","the soul",43,51],["H5715","the testimony",53,66],["H3068","of the LORD",67,78],["H0539","is sure",79,86],["H2449","making wise",88,99],["H6612","the simple",100,110]]},"19:8":{"text":"The statutes of the LORD are right, rejoicing the heart: the commandment of the LORD is pure, enlightening the eyes.","words":[["H6490","The statutes",0,12],["H3068","of the LORD",13,24],["H3477","are right",25,34],["H8055","rejoicing",36,45],["H3820","the heart",46,55],["H4687","the commandment",57,72],["H3068","of the LORD",73,84],["H1249","is pure",85,92],["H0215","enlightening",94,106],["H5869","the eyes",107,115]]},"19:9":{"text":"The fear of the LORD is clean, enduring for ever: the judgments of the LORD are true and righteous altogether.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H2889","is clean",21,29],["H5975","enduring",31,39],["H5703","for ever",40,48],["H4941","the judgments",50,63],["H3068","of the LORD",64,75],["H0571","are true",76,84],["H6663","and righteous",85,98],["H3162","altogether",99,109]]},"19:10":{"text":"More to be desired are they than gold, yea, than much fine gold: sweeter also than honey and the honeycomb.","words":[["H2530","More to be desired",0,18],["H2091","are they than gold",19,37],["H7227","yea, than much",39,53],["H6337","fine gold",54,63],["H4966","sweeter",65,72],["H1706","also than honey",73,88],["H5317","and the honeycomb",89,106],["H6688","and the honeycomb",89,106]]},"19:11":{"text":"Moreover by them is thy servant warned: and in keeping of them there is great reward.","words":[["H5650","Moreover by them is thy servant",0,31],["H2094","warned",32,38],["H8104","and in keeping",40,54],["H7227","of them there is great",55,77],["H6118","reward",78,84]]},"19:12":{"text":"Who can understand his errors? cleanse thou me from secret faults.","words":[["H0995","Who can understand",0,18],["H7691","his errors",19,29],["H5352","cleanse",31,38],["H5641","thou me from secret",39,58]]},"19:13":{"text":"Keep back thy servant also from presumptuous sins; let them not have dominion over me: then shall I be upright, and I shall be innocent from the great transgression.","words":[["H2820","Keep back",0,9],["H5650","thy servant",10,21],["H2086","also from presumptuous",22,44],["H4910","sins; let them not have dominion",45,77],["H8552","over me: then shall I be upright",78,110],["H5352","and I shall be innocent",112,135],["H7227","from the great",136,150],["H6588","transgression",151,164]]},"19:14":{"text":"Let the words of my mouth, and the meditation of my heart, be acceptable in thy sight, O LORD, my strength, and my redeemer.","words":[["H0561","Let the words",0,13],["H6310","of my mouth",14,25],["H1902","and the meditation",27,45],["H3820","of my heart",46,57],["H7522","be acceptable",59,72],["H6440","in thy sight",73,85],["H3068","O LORD",87,93],["H6697","my strength",95,106],["H1350","and my redeemer",108,123]]},"20:1":{"text":"To the chief Musician, A Psalm of David. The LORD hear thee in the day of trouble; the name of the God of Jacob defend thee;","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H3068","The LORD",41,49],["H6030","hear",50,54],["H3117","thee in the day",55,70],["H6869","of trouble",71,81],["H8034","the name",83,91],["H0430","of the God",92,102],["H3290","of Jacob",103,111],["H7682","defend",112,118]]},"20:2":{"text":"Send thee help from the sanctuary, and strengthen thee out of Zion;","words":[["H7971","Send",0,4],["H5828","thee help",5,14],["H6944","from the sanctuary",15,33],["H5582","and strengthen",35,49],["H6726","thee out of Zion",50,66]]},"20:3":{"text":"Remember all thy offerings, and accept thy burnt sacrifice; Selah.","words":[["H2142","Remember",0,8],["H4503","all thy offerings",9,26],["H1878","and accept",28,38],["H5930","thy burnt sacrifice",39,58],["H5542","Selah",60,65]]},"20:4":{"text":"Grant thee according to thine own heart, and fulfil all thy counsel.","words":[["H5414","Grant",0,5],["H3824","thee according to thine own heart",6,39],["H4390","and fulfil",41,51],["H6098","all thy counsel",52,67]]},"20:5":{"text":"We will rejoice in thy salvation, and in the name of our God we will set up our banners: the LORD fulfil all thy petitions.","words":[["H7442","We will rejoice",0,15],["H3444","in thy salvation",16,32],["H8034","and in the name",34,49],["H0430","of our God",50,60],["H1713","we will set up our banners",61,87],["H3068","the LORD",89,97],["H4390","fulfil",98,104],["H4862","all thy petitions",105,122]]},"20:6":{"text":"Now know I that the LORD saveth his anointed; he will hear him from his holy heaven with the saving strength of his right hand.","words":[["H3045","Now know",0,8],["H3068","I that the LORD",9,24],["H3467","saveth",25,31],["H4899","his anointed",32,44],["H6030","he will hear",46,58],["H6944","him from his holy",59,76],["H8064","heaven",77,83],["H3468","with the saving",84,99],["H1369","strength",100,108],["H3225","of his right hand",109,126]]},"20:7":{"text":"Some trust in chariots, and some in horses: but we will remember the name of the LORD our God.","words":[["H7393","Some trust in chariots",0,22],["H5483","and some in horses",24,42],["H2142","but we will remember",44,64],["H8034","the name",65,73],["H3068","of the LORD",74,85],["H0430","our God",86,93]]},"20:8":{"text":"They are brought down and fallen: but we are risen, and stand upright.","words":[["H3766","They are brought down",0,21],["H5307","and fallen",22,32],["H6965","but we are risen",34,50],["H5749","and stand upright",52,69]]},"20:9":{"text":"Save, LORD: let the king hear us when we call.","words":[["H3467","Save",0,4],["H3068","LORD",6,10],["H4428","let the king",12,24],["H6030","hear",25,29],["H3117","us when",30,37],["H7121","we call",38,45]]},"21:1":{"text":"To the chief Musician, A Psalm of David. The king shall joy in thy strength, O LORD; and in thy salvation how greatly shall he rejoice!","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H4428","The king",41,49],["H8055","shall joy",50,59],["H5797","in thy strength",60,75],["H3068","O LORD",77,83],["H3444","and in thy salvation",85,105],["H3966","how greatly",106,117],["H1523","shall he rejoice",118,134]]},"21:2":{"text":"Thou hast given him his heart's desire, and hast not withholden the request of his lips. Selah.","words":[["H5414","Thou hast given",0,15],["H3820","him his heart's",16,31],["H8378","desire",32,38],["H4513","and hast not withholden",40,63],["H0782","the request",64,75],["H8193","of his lips",76,87],["H5542","Selah",89,94]]},"21:3":{"text":"For thou preventest him with the blessings of goodness: thou settest a crown of pure gold on his head.","words":[["H6923","For thou preventest",0,19],["H1293","him with the blessings",20,42],["H2896","of goodness",43,54],["H7896","thou settest",56,68],["H5850","a crown",69,76],["H6337","of pure gold",77,89],["H7218","on his head",90,101]]},"21:4":{"text":"He asked life of thee, and thou gavest it him, even length of days for ever and ever.","words":[["H7592","He asked",0,8],["H2416","life",9,13],["H5414","of thee, and thou gavest",14,38],["H0753","it him, even length",39,58],["H3117","of days",59,66],["H5769","for ever",67,75],["H5703","and ever",76,84]]},"21:5":{"text":"His glory is great in thy salvation: honour and majesty hast thou laid upon him.","words":[["H3519","His glory",0,9],["H1419","is great",10,18],["H3444","in thy salvation",19,35],["H1935","honour",37,43],["H1926","and majesty",44,55],["H7737","hast thou laid",56,70]]},"21:6":{"text":"For thou hast made him most blessed for ever: thou hast made him exceeding glad with thy countenance.","words":[["H7896","For thou hast made",0,18],["H1293","him most blessed",19,35],["H5703","for ever",36,44],["H2302","thou hast made",46,60],["H8057","him exceeding glad",61,79],["H6440","with thy countenance",80,100]]},"21:7":{"text":"For the king trusteth in the LORD, and through the mercy of the most High he shall not be moved.","words":[["H4428","For the king",0,12],["H0982","trusteth",13,21],["H3068","in the LORD",22,33],["H2617","and through the mercy",35,56],["H5945","of the most High",57,73],["H4131","he shall not be moved",74,95]]},"21:8":{"text":"Thine hand shall find out all thine enemies: thy right hand shall find out those that hate thee.","words":[["H3027","Thine hand",0,10],["H4672","shall find out",11,25],["H0341","all thine enemies",26,43],["H3225","thy right hand",45,59],["H4672","shall find out",60,74],["H8130","those that hate",75,90]]},"21:9":{"text":"Thou shalt make them as a fiery oven in the time of thine anger: the LORD shall swallow them up in his wrath, and the fire shall devour them.","words":[["H7896","Thou shalt make",0,15],["H0784","them as a fiery",16,31],["H8574","oven",32,36],["H6256","in the time",37,48],["H6440","of thine anger",49,63],["H3068","the LORD",65,73],["H1104","shall swallow them up",74,95],["H0639","in his wrath",96,108],["H0784","and the fire",110,122],["H0398","shall devour",123,135]]},"21:10":{"text":"Their fruit shalt thou destroy from the earth, and their seed from among the children of men.","words":[["H6529","Their fruit",0,11],["H0006","shalt thou destroy",12,30],["H0776","from the earth",31,45],["H2233","and their seed",47,61],["H1121","from among the children",62,85],["H0120","of men",86,92]]},"21:11":{"text":"For they intended evil against thee: they imagined a mischievous device, which they are not able to perform.","words":[["H5186","For they intended",0,17],["H7451","evil",18,22],["H2803","against thee: they imagined",23,50],["H4209","a mischievous device",51,71],["H3201","which they are not able",73,96]]},"21:12":{"text":"Therefore shalt thou make them turn their back, when thou shalt make ready thine arrows upon thy strings against the face of them.","words":[["H7896","Therefore shalt thou make",0,25],["H7926","them turn their back",26,46],["H3559","when thou shalt make ready",48,74],["H4340","thine arrows upon thy strings",75,104],["H6440","against the face",105,121]]},"21:13":{"text":"Be thou exalted, LORD, in thine own strength: so will we sing and praise thy power.","words":[["H7311","Be thou exalted",0,15],["H3068","LORD",17,21],["H5797","in thine own strength",23,44],["H7891","so will we sing",46,61],["H2167","and praise",62,72],["H1369","thy power",73,82]]},"22:1":{"text":"To the chief Musician upon Aijeleth Shahar, A Psalm of David. My God, my God, why hast thou forsaken me? why art thou so far from helping me, and from the words of my roaring?","words":[["H5329","To the chief Musician",0,21],["H0365","upon Aijeleth",22,35],["H7837","Shahar",36,42],["H4210","A Psalm",44,51],["H1732","of David",52,60],["H0410","My God",62,68],["H0410","my God",70,76],["H5800","why hast thou forsaken",78,100],["H7350","me? why art thou so far",101,124],["H3444","from helping",125,137],["H1697","me, and from the words",138,160],["H7581","of my roaring",161,174]]},"22:2":{"text":"O my God, I cry in the daytime, but thou hearest not; and in the night season, and am not silent.","words":[["H0430","O my God",0,8],["H7121","I cry",10,15],["H3119","in the daytime",16,30],["H6030","but thou hearest",32,48],["H3915","not; and in the night season",49,77],["H1747","and am not silent",79,96]]},"22:3":{"text":"But thou art holy, O thou that inhabitest the praises of Israel.","words":[["H6918","But thou art holy",0,17],["H3427","O thou that inhabitest",19,41],["H8416","the praises",42,53],["H3478","of Israel",54,63]]},"22:4":{"text":"Our fathers trusted in thee: they trusted, and thou didst deliver them.","words":[["H0001","Our fathers",0,11],["H0982","trusted",12,19],["H0982","in thee: they trusted",20,41],["H6403","and thou didst deliver",43,65]]},"22:5":{"text":"They cried unto thee, and were delivered: they trusted in thee, and were not confounded.","words":[["H2199","They cried",0,10],["H4422","unto thee, and were delivered",11,40],["H0982","they trusted",42,54],["H0954","in thee, and were not confounded",55,87]]},"22:6":{"text":"But I am a worm, and no man; a reproach of men, and despised of the people.","words":[["H8438","But I am a worm",0,15],["H0376","and no man",17,27],["H2781","a reproach",29,39],["H0120","of men",40,46],["H0959","and despised",48,60],["H5971","of the people",61,74]]},"22:7":{"text":"All they that see me laugh me to scorn: they shoot out the lip, they shake the head, saying,","words":[["H7200","All they that see",0,17],["H3932","me laugh me to scorn",18,38],["H6358","they shoot out",40,54],["H8193","the lip",55,62],["H5128","they shake",64,74],["H7218","the head",75,83]]},"22:8":{"text":"He trusted on the LORD that he would deliver him: let him deliver him, seeing he delighted in him.","words":[["H1556","He trusted",0,10],["H3068","on the LORD",11,22],["H6403","that he would deliver",23,44],["H5337","him: let him deliver",45,65],["H2654","him, seeing he delighted",66,90]]},"22:9":{"text":"But thou art he that took me out of the womb: thou didst make me hope when I was upon my mother's breasts.","words":[["H1518","But thou art he that took",0,25],["H0990","me out of the womb",26,44],["H0982","thou didst make me hope",46,69],["H0517","when I was upon my mother's",70,97],["H7699","breasts",98,105]]},"22:10":{"text":"I was cast upon thee from the womb: thou art my God from my mother's belly.","words":[["H7993","I was cast",0,10],["H7358","upon thee from the womb",11,34],["H0410","thou art my God",36,51],["H0517","from my mother's",52,68],["H0990","belly",69,74]]},"22:11":{"text":"Be not far from me; for trouble is near; for there is none to help.","words":[["H7368","Be not far",0,10],["H6869","from me; for trouble",11,31],["H7138","is near",32,39],["H5826","for there is none to help",41,66]]},"22:12":{"text":"Many bulls have compassed me: strong bulls of Bashan have beset me round.","words":[["H7227","Many",0,4],["H6499","bulls",5,10],["H5437","have compassed",11,25],["H0047","me: strong",26,36],["H1316","bulls of Bashan",37,52],["H3803","have beset me round",53,72]]},"22:13":{"text":"They gaped upon me with their mouths, as a ravening and a roaring lion.","words":[["H6475","They gaped",0,10],["H6310","upon me with their mouths",11,36],["H2963","as a ravening",38,51],["H7580","and a roaring",52,65],["H0738","lion",66,70]]},"22:14":{"text":"I am poured out like water, and all my bones are out of joint: my heart is like wax; it is melted in the midst of my bowels.","words":[["H8210","I am poured out",0,15],["H4325","like water",16,26],["H6106","and all my bones",28,44],["H6504","are out of joint",45,61],["H3820","my heart",63,71],["H1749","is like wax",72,83],["H4549","it is melted",85,97],["H8432","in the midst",98,110],["H4578","of my bowels",111,123]]},"22:15":{"text":"My strength is dried up like a potsherd; and my tongue cleaveth to my jaws; and thou hast brought me into the dust of death.","words":[["H3581","My strength",0,11],["H3001","is dried up",12,23],["H2789","like a potsherd",24,39],["H3956","and my tongue",41,54],["H1692","cleaveth",55,63],["H4455","to my jaws",64,74],["H8239","and thou hast brought",76,97],["H6083","me into the dust",98,114],["H4194","of death",115,123]]},"22:16":{"text":"For dogs have compassed me: the assembly of the wicked have inclosed me: they pierced my hands and my feet.","words":[["H3611","For dogs",0,8],["H5437","have compassed",9,23],["H5712","me: the assembly",24,40],["H7489","of the wicked",41,54],["H5362","have inclosed",55,68],["H3738","me: they pierced",69,85],["H0738","me: they pierced",69,85],["H3027","my hands",86,94],["H7272","and my feet",95,106]]},"22:17":{"text":"I may tell all my bones: they look and stare upon me.","words":[["H5608","I may tell",0,10],["H6106","all my bones",11,23],["H5027","they look",25,34],["H7200","and stare",35,44]]},"22:18":{"text":"They part my garments among them, and cast lots upon my vesture.","words":[["H2505","They part",0,9],["H0899","my garments",10,21],["H5307","among them, and cast",22,42],["H1486","lots",43,47],["H3830","upon my vesture",48,63]]},"22:19":{"text":"But be not thou far from me, O LORD: O my strength, haste thee to help me.","words":[["H7368","But be not thou far",0,19],["H3068","from me, O LORD",20,35],["H0360","O my strength",37,50],["H2363","haste",52,57],["H5833","thee to help",58,70]]},"22:20":{"text":"Deliver my soul from the sword; my darling from the power of the dog.","words":[["H5337","Deliver",0,7],["H5315","my soul",8,15],["H2719","from the sword",16,30],["H3173","my darling",32,42],["H3027","from the power",43,57],["H3611","of the dog",58,68]]},"22:21":{"text":"Save me from the lion's mouth: for thou hast heard me from the horns of the unicorns.","words":[["H3467","Save",0,4],["H0738","me from the lion's",5,23],["H6310","mouth",24,29],["H6030","for thou hast heard",31,50],["H7161","me from the horns",51,68],["H7214","of the unicorns",69,84]]},"22:22":{"text":"I will declare thy name unto my brethren: in the midst of the congregation will I praise thee.","words":[["H5608","I will declare",0,14],["H8034","thy name",15,23],["H0251","unto my brethren",24,40],["H8432","in the midst",42,54],["H6951","of the congregation",55,74],["H1984","will I praise",75,88]]},"22:23":{"text":"Ye that fear the LORD, praise him; all ye the seed of Jacob, glorify him; and fear him, all ye the seed of Israel.","words":[["H3373","Ye that fear",0,12],["H3068","the LORD",13,21],["H1984","praise",23,29],["H2233","him; all ye the seed",30,50],["H3290","of Jacob",51,59],["H3513","glorify",61,68],["H1481","him; and fear",69,82],["H2233","him, all ye the seed",83,103],["H3478","of Israel",104,113]]},"22:24":{"text":"For he hath not despised nor abhorred the affliction of the afflicted; neither hath he hid his face from him; but when he cried unto him, he heard.","words":[["H0959","For he hath not despised",0,24],["H8262","nor abhorred",25,37],["H6039","the affliction",38,52],["H6041","of the afflicted",53,69],["H5641","neither hath he hid",71,90],["H6440","his face",91,99],["H7768","from him; but when he cried",100,127],["H8085","unto him, he heard",128,146]]},"22:25":{"text":"My praise shall be of thee in the great congregation: I will pay my vows before them that fear him.","words":[["H8416","My praise",0,9],["H7227","shall be of thee in the great",10,39],["H6951","congregation",40,52],["H7999","I will pay",54,64],["H5088","my vows",65,72],["H3373","before them that fear",73,94]]},"22:26":{"text":"The meek shall eat and be satisfied: they shall praise the LORD that seek him: your heart shall live for ever.","words":[["H6035","The meek",0,8],["H0398","shall eat",9,18],["H7646","and be satisfied",19,35],["H1984","they shall praise",37,54],["H3068","the LORD",55,63],["H1875","that seek",64,73],["H3824","him: your heart",74,89],["H2421","shall live",90,100],["H5703","for ever",101,109]]},"22:27":{"text":"All the ends of the world shall remember and turn unto the LORD: and all the kindreds of the nations shall worship before thee.","words":[["H0657","All the ends",0,12],["H0776","of the world",13,25],["H2142","shall remember",26,40],["H7725","and turn",41,49],["H3068","unto the LORD",50,63],["H4940","and all the kindreds",65,85],["H1471","of the nations",86,100],["H7812","shall worship",101,114],["H6440","before",115,121]]},"22:28":{"text":"For the kingdom is the LORD'S: and he is the governor among the nations.","words":[["H4410","For the kingdom",0,15],["H3068","is the LORD'S",16,29],["H4910","and he is the governor",31,53],["H1471","among the nations",54,71]]},"22:29":{"text":"All they that be fat upon earth shall eat and worship: all they that go down to the dust shall bow before him: and none can keep alive his own soul.","words":[["H1879","All they that be fat",0,20],["H0776","upon earth",21,31],["H0398","shall eat",32,41],["H7812","and worship",42,53],["H3381","all they that go down",55,76],["H6083","to the dust",77,88],["H3766","shall bow",89,98],["H6440","before",99,105],["H2421","him: and none can keep alive",106,134],["H5315","his own soul",135,147]]},"22:30":{"text":"A seed shall serve him; it shall be accounted to the Lord for a generation.","words":[["H2233","A seed",0,6],["H5647","shall serve",7,18],["H5608","him; it shall be accounted",19,45],["H0136","to the Lord",46,57],["H1755","for a generation",58,74]]},"22:31":{"text":"They shall come, and shall declare his righteousness unto a people that shall be born, that he hath done this.","words":[["H0935","They shall come",0,15],["H5046","and shall declare",17,34],["H6666","his righteousness",35,52],["H5971","unto a people",53,66],["H3205","that shall be born",67,85],["H6213","that he hath done",87,104]]},"23:1":{"text":"A Psalm of David. The LORD is my shepherd; I shall not want.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H3068","The LORD",18,26],["H7462","is my shepherd",27,41],["H2637","I shall not want",43,59]]},"23:2":{"text":"He maketh me to lie down in green pastures: he leadeth me beside the still waters.","words":[["H7257","He maketh me to lie down",0,24],["H1877","in green",25,33],["H4999","pastures",34,42],["H5095","he leadeth",44,54],["H4496","me beside the still",55,74],["H4325","waters",75,81]]},"23:3":{"text":"He restoreth my soul: he leadeth me in the paths of righteousness for his name's sake.","words":[["H7725","He restoreth",0,12],["H5315","my soul",13,20],["H5148","he leadeth",22,32],["H4570","me in the paths",33,48],["H6664","of righteousness",49,65],["H8034","for his name's",66,80]]},"23:4":{"text":"Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod and thy staff they comfort me.","words":[["H3212","Yea, though I walk",0,18],["H1516","through the valley",19,37],["H6757","of the shadow of death",38,60],["H3372","I will fear",62,73],["H7451","no evil",74,81],["H7626","for thou art with me; thy rod",83,112],["H4938","and thy staff",113,126],["H5162","they comfort",127,139]]},"23:5":{"text":"Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over.","words":[["H6186","Thou preparest",0,14],["H7979","a table",15,22],["H6440","before",23,29],["H6887","me in the presence of mine enemies",30,64],["H1878","thou anointest",66,80],["H7218","my head",81,88],["H8081","with oil",89,97],["H3563","my cup",99,105],["H7310","runneth over",106,118]]},"23:6":{"text":"Surely goodness and mercy shall follow me all the days of my life: and I will dwell in the house of the LORD for ever.","words":[["H2896","Surely goodness",0,15],["H2617","and mercy",16,25],["H7291","shall follow",26,38],["H3117","me all the days",39,54],["H2416","of my life",55,65],["H3427","and I will dwell",67,83],["H1004","in the house",84,96],["H3068","of the LORD",97,108],["H0753","for ever",109,117],["H3117","for ever",109,117]]},"24:1":{"text":"A Psalm of David. The earth is the LORD'S, and the fulness thereof; the world, and they that dwell therein.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H0776","The earth",18,27],["H3068","is the LORD'S",28,41],["H4393","and the fulness",43,58],["H8398","thereof; the world",59,77],["H3427","and they that dwell",79,98]]},"24:2":{"text":"For he hath founded it upon the seas, and established it upon the floods.","words":[["H3245","For he hath founded",0,19],["H3220","it upon the seas",20,36],["H3559","and established",38,53],["H5104","it upon the floods",54,72]]},"24:3":{"text":"Who shall ascend into the hill of the LORD? or who shall stand in his holy place?","words":[["H5927","Who shall ascend",0,16],["H2022","into the hill",17,30],["H3068","of the LORD",31,42],["H6965","or who shall stand",44,62],["H6944","in his holy",63,74],["H4725","place",75,80]]},"24:4":{"text":"He that hath clean hands, and a pure heart; who hath not lifted up his soul unto vanity, nor sworn deceitfully.","words":[["H5355","He that hath clean",0,18],["H3709","hands",19,24],["H1249","and a pure",26,36],["H3824","heart",37,42],["H5375","who hath not lifted up",44,66],["H5315","his soul",67,75],["H7723","unto vanity",76,87],["H7650","nor sworn",89,98],["H4820","deceitfully",99,110]]},"24:5":{"text":"He shall receive the blessing from the LORD, and righteousness from the God of his salvation.","words":[["H5375","He shall receive",0,16],["H1293","the blessing",17,29],["H3068","from the LORD",30,43],["H6666","and righteousness",45,62],["H0430","from the God",63,75],["H3468","of his salvation",76,92]]},"24:6":{"text":"This is the generation of them that seek him, that seek thy face, O Jacob. Selah.","words":[["H1755","This is the generation",0,22],["H1875","of them that seek",23,40],["H1245","him, that seek",41,55],["H6440","thy face",56,64],["H3290","O Jacob",66,73],["H5542","Selah",75,80]]},"24:7":{"text":"Lift up your heads, O ye gates; and be ye lift up, ye everlasting doors; and the King of glory shall come in.","words":[["H5375","Lift up",0,7],["H7218","your heads",8,18],["H8179","O ye gates",20,30],["H5375","and be ye lift up",32,49],["H5769","ye everlasting",51,65],["H6607","doors",66,71],["H4428","and the King",73,85],["H3519","of glory",86,94],["H0935","shall come in",95,108]]},"24:8":{"text":"Who is this King of glory? The LORD strong and mighty, the LORD mighty in battle.","words":[["H4428","Who is this King",0,16],["H3519","of glory",17,25],["H3068","The LORD",27,35],["H5808","strong",36,42],["H1368","and mighty",43,53],["H3068","the LORD",55,63],["H1368","mighty",64,70],["H4421","in battle",71,80]]},"24:9":{"text":"Lift up your heads, O ye gates; even lift them up, ye everlasting doors; and the King of glory shall come in.","words":[["H5375","Lift up",0,7],["H7218","your heads",8,18],["H8179","O ye gates",20,30],["H5375","even lift them up",32,49],["H5769","ye everlasting",51,65],["H6607","doors",66,71],["H4428","and the King",73,85],["H3519","of glory",86,94],["H0935","shall come in",95,108]]},"24:10":{"text":"Who is this King of glory? The LORD of hosts, he is the King of glory. Selah.","words":[["H4428","Who is this King",0,16],["H3519","of glory",17,25],["H3068","The LORD",27,35],["H6635","of hosts",36,44],["H4428","he is the King",46,60],["H3519","of glory",61,69],["H5542","Selah",71,76]]},"25:1":{"text":"A Psalm of David. Unto thee, O LORD, do I lift up my soul.","words":[["H1732","A Psalm of David",0,16],["H3068","Unto thee, O LORD",18,35],["H5375","do I lift up",37,49],["H5315","my soul",50,57]]},"25:2":{"text":"O my God, I trust in thee: let me not be ashamed, let not mine enemies triumph over me.","words":[["H0430","O my God",0,8],["H0982","I trust",10,17],["H0954","in thee: let me not be ashamed",18,48],["H0341","let not mine enemies",50,70],["H5970","triumph",71,78]]},"25:3":{"text":"Yea, let none that wait on thee be ashamed: let them be ashamed which transgress without cause.","words":[["H6960","Yea, let none that wait",0,23],["H0954","on thee be ashamed",24,42],["H0954","let them be ashamed",44,63],["H0898","which transgress",64,80],["H7387","without cause",81,94]]},"25:4":{"text":"Shew me thy ways, O LORD; teach me thy paths.","words":[["H3045","Shew",0,4],["H1870","me thy ways",5,16],["H3068","O LORD",18,24],["H3925","teach",26,31],["H0734","me thy paths",32,44]]},"25:5":{"text":"Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day.","words":[["H1869","Lead",0,4],["H0571","me in thy truth",5,20],["H3925","and teach",22,31],["H0430","me: for thou art the God",32,56],["H3468","of my salvation",57,72],["H6960","on thee do I wait",74,91],["H3117","all the day",92,103]]},"25:6":{"text":"Remember, O LORD, thy tender mercies and thy lovingkindnesses; for they have been ever of old.","words":[["H2142","Remember",0,8],["H3068","O LORD",10,16],["H7356","thy tender mercies",18,36],["H2617","and thy lovingkindnesses",37,61],["H5769","for they have been ever of old",63,93]]},"25:7":{"text":"Remember not the sins of my youth, nor my transgressions: according to thy mercy remember thou me for thy goodness' sake, O LORD.","words":[["H2142","Remember",0,8],["H2403","not the sins",9,21],["H5271","of my youth",22,33],["H6588","nor my transgressions",35,56],["H2617","according to thy mercy",58,80],["H2142","remember",81,89],["H2898","thou me for thy goodness'",90,115],["H3068","sake, O LORD",116,128]]},"25:8":{"text":"Good and upright is the LORD: therefore will he teach sinners in the way.","words":[["H2896","Good",0,4],["H3477","and upright",5,16],["H3068","is the LORD",17,28],["H3384","therefore will he teach",30,53],["H2400","sinners",54,61],["H1870","in the way",62,72]]},"25:9":{"text":"The meek will he guide in judgment: and the meek will he teach his way.","words":[["H6035","The meek",0,8],["H1869","will he guide",9,22],["H4941","in judgment",23,34],["H6035","and the meek",36,48],["H3925","will he teach",49,62],["H1870","his way",63,70]]},"25:10":{"text":"All the paths of the LORD are mercy and truth unto such as keep his covenant and his testimonies.","words":[["H0734","All the paths",0,13],["H3068","of the LORD",14,25],["H2617","are mercy",26,35],["H0571","and truth",36,45],["H5341","unto such as keep",46,63],["H1285","his covenant",64,76],["H5713","and his testimonies",77,96]]},"25:11":{"text":"For thy name's sake, O LORD, pardon mine iniquity; for it is great.","words":[["H8034","For thy name's",0,14],["H3068","sake, O LORD",15,27],["H5545","pardon",29,35],["H5771","mine iniquity",36,49],["H7227","for it is great",51,66]]},"25:12":{"text":"What man is he that feareth the LORD? him shall he teach in the way that he shall choose.","words":[["H0376","What man",0,8],["H3373","is he that feareth",9,27],["H3068","the LORD",28,36],["H3384","him shall he teach",38,56],["H1870","in the way",57,67],["H0977","that he shall choose",68,88]]},"25:13":{"text":"His soul shall dwell at ease; and his seed shall inherit the earth.","words":[["H5315","His soul",0,8],["H3885","shall dwell",9,20],["H2896","at ease",21,28],["H2233","and his seed",30,42],["H3423","shall inherit",43,56],["H0776","the earth",57,66]]},"25:14":{"text":"The secret of the LORD is with them that fear him; and he will shew them his covenant.","words":[["H5475","The secret",0,10],["H3068","of the LORD",11,22],["H3373","is with them that fear",23,45],["H3045","him; and he will shew",46,67],["H1285","them his covenant",68,85]]},"25:15":{"text":"Mine eyes are ever toward the LORD; for he shall pluck my feet out of the net.","words":[["H5869","Mine eyes",0,9],["H8548","are ever",10,18],["H3068","toward the LORD",19,34],["H3318","for he shall pluck",36,54],["H7272","my feet",55,62],["H7568","out of the net",63,77]]},"25:16":{"text":"Turn thee unto me, and have mercy upon me; for I am desolate and afflicted.","words":[["H6437","Turn",0,4],["H2603","thee unto me, and have mercy",5,33],["H3173","upon me; for I am desolate",34,60],["H6041","and afflicted",61,74]]},"25:17":{"text":"The troubles of my heart are enlarged: O bring thou me out of my distresses.","words":[["H6869","The troubles",0,12],["H3824","of my heart",13,24],["H7337","are enlarged",25,37],["H3318","O bring thou me out",39,58],["H4691","of my distresses",59,75]]},"25:18":{"text":"Look upon mine affliction and my pain; and forgive all my sins.","words":[["H7200","Look",0,4],["H6040","upon mine affliction",5,25],["H5999","and my pain",26,37],["H5375","and forgive",39,50],["H2403","all my sins",51,62]]},"25:19":{"text":"Consider mine enemies; for they are many; and they hate me with cruel hatred.","words":[["H7200","Consider",0,8],["H0341","mine enemies",9,21],["H7231","for they are many",23,40],["H8130","and they hate",42,55],["H2555","me with cruel",56,69],["H8135","hatred",70,76]]},"25:20":{"text":"O keep my soul, and deliver me: let me not be ashamed; for I put my trust in thee.","words":[["H8104","O keep",0,6],["H5315","my soul",7,14],["H5337","and deliver",16,27],["H0954","me: let me not be ashamed",28,53],["H2620","for I put my trust",55,73]]},"25:21":{"text":"Let integrity and uprightness preserve me; for I wait on thee.","words":[["H8537","Let integrity",0,13],["H3476","and uprightness",14,29],["H5341","preserve",30,38],["H6960","me; for I wait",39,53]]},"25:22":{"text":"Redeem Israel, O God, out of all his troubles.","words":[["H6299","Redeem",0,6],["H3478","Israel",7,13],["H0430","O God",15,20],["H6869","out of all his troubles",22,45]]},"26:1":{"text":"A Psalm of David. Judge me, O LORD; for I have walked in mine integrity: I have trusted also in the LORD; therefore I shall not slide.","words":[["H1732","A Psalm of David",0,16],["H8199","Judge",18,23],["H3068","me, O LORD",24,34],["H1980","for I have walked",36,53],["H8537","in mine integrity",54,71],["H0982","I have trusted",73,87],["H3068","also in the LORD",88,104],["H4571","therefore I shall not slide",106,133]]},"26:2":{"text":"Examine me, O LORD, and prove me; try my reins and my heart.","words":[["H0974","Examine",0,7],["H3068","me, O LORD",8,18],["H5254","and prove",20,29],["H6884","me; try",30,37],["H3629","my reins",38,46],["H3820","and my heart",47,59]]},"26:3":{"text":"For thy lovingkindness is before mine eyes: and I have walked in thy truth.","words":[["H2617","For thy lovingkindness",0,22],["H5869","is before mine eyes",23,42],["H1980","and I have walked",44,61],["H0571","in thy truth",62,74]]},"26:4":{"text":"I have not sat with vain persons, neither will I go in with dissemblers.","words":[["H3427","I have not sat",0,14],["H7723","with vain",15,24],["H4962","persons",25,32],["H0935","neither will I go in",34,54],["H5956","with dissemblers",55,71]]},"26:5":{"text":"I have hated the congregation of evil doers; and will not sit with the wicked.","words":[["H8130","I have hated",0,12],["H6951","the congregation",13,29],["H7489","of evil doers",30,43],["H3427","and will not sit",45,61],["H7563","with the wicked",62,77]]},"26:6":{"text":"I will wash mine hands in innocency: so will I compass thine altar, O LORD:","words":[["H7364","I will wash",0,11],["H3709","mine hands",12,22],["H5356","in innocency",23,35],["H5437","so will I compass",37,54],["H4196","thine altar",55,66],["H3068","O LORD",68,74]]},"26:7":{"text":"That I may publish with the voice of thanksgiving, and tell of all thy wondrous works.","words":[["H8085","That I may publish",0,18],["H6963","with the voice",19,33],["H8426","of thanksgiving",34,49],["H5608","and tell",51,59],["H6381","of all thy wondrous works",60,85]]},"26:8":{"text":"LORD, I have loved the habitation of thy house, and the place where thine honour dwelleth.","words":[["H3068","LORD",0,4],["H0157","I have loved",6,18],["H4583","the habitation",19,33],["H1004","of thy house",34,46],["H4725","and the place",48,61],["H3519","where thine honour",62,80],["H4908","dwelleth",81,89]]},"26:9":{"text":"Gather not my soul with sinners, nor my life with bloody men:","words":[["H0622","Gather",0,6],["H5315","not my soul",7,18],["H2400","with sinners",19,31],["H2416","nor my life",33,44],["H1818","with bloody",45,56],["H0582","men",57,60]]},"26:10":{"text":"In whose hands is mischief, and their right hand is full of bribes.","words":[["H3027","In whose hands",0,14],["H2154","is mischief",15,26],["H3225","and their right hand",28,48],["H4390","is full",49,56],["H7810","of bribes",57,66]]},"26:11":{"text":"But as for me, I will walk in mine integrity: redeem me, and be merciful unto me.","words":[["H3212","But as for me, I will walk",0,26],["H8537","in mine integrity",27,44],["H6299","redeem",46,52],["H2603","me, and be merciful",53,72]]},"26:12":{"text":"My foot standeth in an even place: in the congregations will I bless the LORD.","words":[["H7272","My foot",0,7],["H5975","standeth",8,16],["H4334","in an even place",17,33],["H4721","in the congregations",35,55],["H1288","will I bless",56,68],["H3068","the LORD",69,77]]},"27:1":{"text":"A Psalm of David. The LORD is my light and my salvation; whom shall I fear? the LORD is the strength of my life; of whom shall I be afraid?","words":[["H1732","A Psalm of David",0,16],["H3068","The LORD",18,26],["H0216","is my light",27,38],["H3468","and my salvation",39,55],["H3372","whom shall I fear",57,74],["H3068","the LORD",76,84],["H4581","is the strength",85,100],["H2416","of my life",101,111],["H6342","of whom shall I be afraid",113,138]]},"27:2":{"text":"When the wicked, even mine enemies and my foes, came upon me to eat up my flesh, they stumbled and fell.","words":[["H7489","When the wicked",0,15],["H6862","even mine enemies",17,34],["H0341","and my foes",35,46],["H7126","came",48,52],["H0398","upon me to eat up",53,70],["H1320","my flesh",71,79],["H3782","they stumbled",81,94],["H5307","and fell",95,103]]},"27:3":{"text":"Though an host should encamp against me, my heart shall not fear: though war should rise against me, in this will I be confident.","words":[["H4264","Though an host",0,14],["H2583","should encamp",15,28],["H3820","against me, my heart",29,49],["H3372","shall not fear",50,64],["H4421","though war",66,76],["H6965","should rise",77,88],["H0982","against me, in this will I be confident",89,128]]},"27:4":{"text":"One thing have I desired of the LORD, that will I seek after; that I may dwell in the house of the LORD all the days of my life, to behold the beauty of the LORD, and to enquire in his temple.","words":[["H0259","One",0,3],["H7592","thing have I desired",4,24],["H3068","of the LORD",25,36],["H1245","that will I seek",38,54],["H3427","after; that I may dwell",55,78],["H1004","in the house",79,91],["H3068","of the LORD",92,103],["H3117","all the days",104,116],["H2416","of my life",117,127],["H2372","to behold",129,138],["H5278","the beauty",139,149],["H3068","of the LORD",150,161],["H1239","and to enquire",163,177],["H1964","in his temple",178,191]]},"27:5":{"text":"For in the time of trouble he shall hide me in his pavilion: in the secret of his tabernacle shall he hide me; he shall set me up upon a rock.","words":[["H3117","For in the time",0,15],["H7451","of trouble",16,26],["H6845","he shall hide",27,40],["H5520","me in his pavilion",41,59],["H5643","in the secret",61,74],["H0168","of his tabernacle",75,92],["H5641","shall he hide",93,106],["H7311","me; he shall set me up",107,129],["H6697","upon a rock",130,141]]},"27:6":{"text":"And now shall mine head be lifted up above mine enemies round about me: therefore will I offer in his tabernacle sacrifices of joy; I will sing, yea, I will sing praises unto the LORD.","words":[["H7218","And now shall mine head",0,23],["H7311","be lifted up",24,36],["H0341","above mine enemies",37,55],["H5439","round about",56,67],["H2076","me: therefore will I offer",68,94],["H0168","in his tabernacle",95,112],["H2077","sacrifices",113,123],["H8643","of joy",124,130],["H7891","I will sing",132,143],["H2167","yea, I will sing praises",145,169],["H3068","unto the LORD",170,183]]},"27:7":{"text":"Hear, O LORD, when I cry with my voice: have mercy also upon me, and answer me.","words":[["H8085","Hear",0,4],["H3068","O LORD",6,12],["H7121","when I cry",14,24],["H6963","with my voice",25,38],["H2603","have mercy",40,50],["H6030","also upon me, and answer",51,75]]},"27:8":{"text":"When thou saidst, Seek ye my face; my heart said unto thee, Thy face, LORD, will I seek.","words":[["H1245","When thou saidst, Seek",0,22],["H6440","ye my face",23,33],["H3820","my heart",35,43],["H0559","said",44,48],["H6440","unto thee, Thy face",49,68],["H3068","LORD",70,74],["H1245","will I seek",76,87]]},"27:9":{"text":"Hide not thy face far from me; put not thy servant away in anger: thou hast been my help; leave me not, neither forsake me, O God of my salvation.","words":[["H5641","Hide",0,4],["H6440","not thy face",5,17],["H5186","far from me; put",18,34],["H5650","not thy servant",35,50],["H5186","away",51,55],["H0639","in anger",56,64],["H5833","thou hast been my help",66,88],["H5203","leave",90,95],["H5800","me not, neither forsake",96,119],["H0430","me, O God",120,129],["H3468","of my salvation",130,145]]},"27:10":{"text":"When my father and my mother forsake me, then the LORD will take me up.","words":[["H0001","When my father",0,14],["H0517","and my mother",15,28],["H5800","forsake",29,36],["H3068","me, then the LORD",37,54],["H0622","will take me up",55,70]]},"27:11":{"text":"Teach me thy way, O LORD, and lead me in a plain path, because of mine enemies.","words":[["H3384","Teach",0,5],["H1870","me thy way",6,16],["H3068","O LORD",18,24],["H5148","and lead",26,34],["H4334","me in a plain",35,48],["H0734","path",49,53],["H8324","because of mine enemies",55,78]]},"27:12":{"text":"Deliver me not over unto the will of mine enemies: for false witnesses are risen up against me, and such as breathe out cruelty.","words":[["H5414","Deliver",0,7],["H5315","me not over unto the will",8,33],["H6862","of mine enemies",34,49],["H8267","for false",51,60],["H5707","witnesses",61,70],["H6965","are risen up",71,83],["H3307","against me, and such as breathe out",84,119],["H2555","cruelty",120,127]]},"27:13":{"text":"I had fainted, unless I had believed to see the goodness of the LORD in the land of the living.","words":[["H3884","I had fainted, unless",0,21],["H0539","I had believed",22,36],["H7200","to see",37,43],["H2898","the goodness",44,56],["H3068","of the LORD",57,68],["H0776","in the land",69,80],["H2416","of the living",81,94]]},"27:14":{"text":"Wait on the LORD: be of good courage, and he shall strengthen thine heart: wait, I say, on the LORD.","words":[["H6960","Wait",0,4],["H3068","on the LORD",5,16],["H2388","be of good courage",18,36],["H0553","and he shall strengthen",38,61],["H3820","thine heart",62,73],["H6960","wait",75,79],["H3068","I say, on the LORD",81,99]]},"28:1":{"text":"A Psalm of David. Unto thee will I cry, O LORD my rock; be not silent to me: lest, if thou be silent to me, I become like them that go down into the pit.","words":[["H1732","A Psalm of David",0,16],["H7121","Unto thee will I cry",18,38],["H3068","O LORD",40,46],["H6697","my rock",47,54],["H2814","be not silent",56,69],["H2790","to me: lest, if thou be silent",70,100],["H4911","to me, I become",101,116],["H3381","like them that go down",117,139],["H0953","into the pit",140,152]]},"28:2":{"text":"Hear the voice of my supplications, when I cry unto thee, when I lift up my hands toward thy holy oracle.","words":[["H8085","Hear",0,4],["H6963","the voice",5,14],["H8469","of my supplications",15,34],["H7768","when I cry",36,46],["H5375","unto thee, when I lift up",47,72],["H3027","my hands",73,81],["H6944","toward thy holy",82,97],["H1687","oracle",98,104]]},"28:3":{"text":"Draw me not away with the wicked, and with the workers of iniquity, which speak peace to their neighbours, but mischief is in their hearts.","words":[["H4900","Draw me not away",0,16],["H7563","with the wicked",17,32],["H6466","and with the workers",34,54],["H0205","of iniquity",55,66],["H1696","which speak",68,79],["H7965","peace",80,85],["H7453","to their neighbours",86,105],["H7451","but mischief",107,119],["H3824","is in their hearts",120,138]]},"28:4":{"text":"Give them according to their deeds, and according to the wickedness of their endeavours: give them after the work of their hands; render to them their desert.","words":[["H5414","Give",0,4],["H6467","them according to their deeds",5,34],["H7455","and according to the wickedness",36,67],["H4611","of their endeavours",68,87],["H5414","give",89,93],["H4639","them after the work",94,113],["H3027","of their hands",114,128],["H7725","render",130,136],["H1576","to them their desert",137,157]]},"28:5":{"text":"Because they regard not the works of the LORD, nor the operation of his hands, he shall destroy them, and not build them up.","words":[["H0995","Because they regard",0,19],["H6468","not the works",20,33],["H3068","of the LORD",34,45],["H4639","nor the operation",47,64],["H3027","of his hands",65,77],["H2040","he shall destroy",79,95],["H1129","them, and not build them up",96,123]]},"28:6":{"text":"Blessed be the LORD, because he hath heard the voice of my supplications.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H8085","because he hath heard",21,42],["H6963","the voice",43,52],["H8469","of my supplications",53,72]]},"28:7":{"text":"The LORD is my strength and my shield; my heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him.","words":[["H3068","The LORD",0,8],["H5797","is my strength",9,23],["H4043","and my shield",24,37],["H3820","my heart",39,47],["H0982","trusted",48,55],["H5826","in him, and I am helped",56,79],["H3820","therefore my heart",81,99],["H5937","greatly rejoiceth",100,117],["H7892","and with my song",119,135],["H3034","will I praise",136,149]]},"28:8":{"text":"The LORD is their strength, and he is the saving strength of his anointed.","words":[["H3068","The LORD",0,8],["H5797","is their strength",9,26],["H3444","and he is the saving",28,48],["H4581","strength",49,57],["H4899","of his anointed",58,73]]},"28:9":{"text":"Save thy people, and bless thine inheritance: feed them also, and lift them up for ever.","words":[["H3467","Save",0,4],["H5971","thy people",5,15],["H1288","and bless",17,26],["H5159","thine inheritance",27,44],["H7462","feed",46,50],["H5375","them also, and lift them up",51,78],["H5769","for ever",79,87]]},"29:1":{"text":"A Psalm of David. Give unto the LORD, O ye mighty, give unto the LORD glory and strength.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H3051","Give",18,22],["H3068","unto the LORD",23,36],["H1121","O ye mighty",38,49],["H0410","O ye mighty",38,49],["H3051","give",51,55],["H3068","unto the LORD",56,69],["H3519","glory",70,75],["H5797","and strength",76,88]]},"29:2":{"text":"Give unto the LORD the glory due unto his name; worship the LORD in the beauty of holiness.","words":[["H3051","Give",0,4],["H3068","unto the LORD",5,18],["H3519","the glory",19,28],["H8034","due unto his name",29,46],["H7812","worship",48,55],["H3068","the LORD",56,64],["H1927","in the beauty",65,78],["H6944","of holiness",79,90]]},"29:3":{"text":"The voice of the LORD is upon the waters: the God of glory thundereth: the LORD is upon many waters.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H4325","is upon the waters",22,40],["H0410","the God",42,49],["H3519","of glory",50,58],["H7481","thundereth",59,69],["H3068","the LORD",71,79],["H7227","is upon many",80,92],["H4325","waters",93,99]]},"29:4":{"text":"The voice of the LORD is powerful; the voice of the LORD is full of majesty.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H3581","is powerful",22,33],["H6963","the voice",35,44],["H3068","of the LORD",45,56],["H1926","is full of majesty",57,75]]},"29:5":{"text":"The voice of the LORD breaketh the cedars; yea, the LORD breaketh the cedars of Lebanon.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H7665","breaketh",22,30],["H0730","the cedars",31,41],["H3068","yea, the LORD",43,56],["H7665","breaketh",57,65],["H0730","the cedars",66,76],["H3844","of Lebanon",77,87]]},"29:6":{"text":"He maketh them also to skip like a calf; Lebanon and Sirion like a young unicorn.","words":[["H7540","He maketh them also to skip",0,27],["H5695","like a calf",28,39],["H3844","Lebanon",41,48],["H8303","and Sirion",49,59],["H1121","like a young",60,72],["H7214","unicorn",73,80]]},"29:7":{"text":"The voice of the LORD divideth the flames of fire.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H2672","divideth",22,30],["H3852","the flames",31,41],["H0784","of fire",42,49]]},"29:8":{"text":"The voice of the LORD shaketh the wilderness; the LORD shaketh the wilderness of Kadesh.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H2342","shaketh",22,29],["H4057","the wilderness",30,44],["H3068","the LORD",46,54],["H2342","shaketh",55,62],["H4057","the wilderness",63,77],["H6946","of Kadesh",78,87]]},"29:9":{"text":"The voice of the LORD maketh the hinds to calve, and discovereth the forests: and in his temple doth every one speak of his glory.","words":[["H6963","The voice",0,9],["H3068","of the LORD",10,21],["H0355","maketh the hinds",22,38],["H2342","to calve",39,47],["H2834","and discovereth",49,64],["H3295","the forests",65,76],["H1964","and in his temple",78,95],["H0559","doth every one speak",96,116],["H3519","of his glory",117,129]]},"29:10":{"text":"The LORD sitteth upon the flood; yea, the LORD sitteth King for ever.","words":[["H3068","The LORD",0,8],["H3427","sitteth",9,16],["H3999","upon the flood",17,31],["H3068","yea, the LORD",33,46],["H3427","sitteth",47,54],["H4428","King",55,59],["H5769","for ever",60,68]]},"29:11":{"text":"The LORD will give strength unto his people; the LORD will bless his people with peace.","words":[["H3068","The LORD",0,8],["H5414","will give",9,18],["H5797","strength",19,27],["H5971","unto his people",28,43],["H3068","the LORD",45,53],["H1288","will bless",54,64],["H5971","his people",65,75],["H7965","with peace",76,86]]},"30:1":{"text":"A Psalm and Song at the dedication of the house of David. I will extol thee, O LORD; for thou hast lifted me up, and hast not made my foes to rejoice over me.","words":[["H4210","A Psalm",0,7],["H7892","and Song",8,16],["H2598","at the dedication",17,34],["H1004","of the house",35,47],["H1732","of David",48,56],["H7311","I will extol",58,70],["H3068","thee, O LORD",71,83],["H1802","for thou hast lifted me up",85,111],["H0341","and hast not made my foes",113,138],["H8055","to rejoice",139,149]]},"30:2":{"text":"O LORD my God, I cried unto thee, and thou hast healed me.","words":[["H3068","O LORD",0,6],["H0430","my God",7,13],["H7768","I cried",15,22],["H7495","unto thee, and thou hast healed",23,54]]},"30:3":{"text":"O LORD, thou hast brought up my soul from the grave: thou hast kept me alive, that I should not go down to the pit.","words":[["H3068","O LORD",0,6],["H5927","thou hast brought up",8,28],["H5315","my soul",29,36],["H7585","from the grave",37,51],["H2421","thou hast kept me alive",53,76],["H3381","that I should not go down",78,103],["H3381","that I should not go down",78,103],["H0953","to the pit",104,114]]},"30:4":{"text":"Sing unto the LORD, O ye saints of his, and give thanks at the remembrance of his holiness.","words":[["H2167","Sing",0,4],["H3068","unto the LORD",5,18],["H2623","O ye saints",20,31],["H3034","of his, and give thanks",32,55],["H2143","at the remembrance",56,74],["H6944","of his holiness",75,90]]},"30:5":{"text":"For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning.","words":[["H0639","For his anger",0,13],["H7281","endureth but a moment",14,35],["H7522","in his favour",37,50],["H2416","is life",51,58],["H1065","weeping",60,67],["H3885","may endure",68,78],["H6153","for a night",79,90],["H7440","but joy",92,99],["H1242","cometh in the morning",100,121]]},"30:6":{"text":"And in my prosperity I said, I shall never be moved.","words":[["H7959","And in my prosperity",0,20],["H0559","I said",21,27],["H5769","I shall never",29,42],["H4131","be moved",43,51]]},"30:7":{"text":"LORD, by thy favour thou hast made my mountain to stand strong: thou didst hide thy face, and I was troubled.","words":[["H3068","LORD",0,4],["H7522","by thy favour",6,19],["H2042","thou hast made my mountain",20,46],["H5975","to stand",47,55],["H5797","strong",56,62],["H5641","thou didst hide",64,79],["H6440","thy face",80,88],["H0926","and I was troubled",90,108]]},"30:8":{"text":"I cried to thee, O LORD; and unto the LORD I made supplication.","words":[["H7121","I cried",0,7],["H3068","to thee, O LORD",8,23],["H3068","and unto the LORD",25,42],["H2603","I made supplication",43,62]]},"30:9":{"text":"What profit is there in my blood, when I go down to the pit? Shall the dust praise thee? shall it declare thy truth?","words":[["H1215","What profit",0,11],["H1818","is there in my blood",12,32],["H3381","when I go down",34,48],["H7845","to the pit",49,59],["H6083","Shall the dust",61,75],["H3034","praise",76,82],["H5046","thee? shall it declare",83,105],["H0571","thy truth",106,115]]},"30:10":{"text":"Hear, O LORD, and have mercy upon me: LORD, be thou my helper.","words":[["H8085","Hear",0,4],["H3068","O LORD",6,12],["H2603","and have mercy",14,28],["H3068","upon me: LORD",29,42],["H5826","be thou my helper",44,61]]},"30:11":{"text":"Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness;","words":[["H2015","Thou hast turned",0,16],["H4553","for me my mourning",17,35],["H4234","into dancing",36,48],["H6605","thou hast put off",50,67],["H8242","my sackcloth",68,80],["H0247","and girded",82,92],["H8057","me with gladness",93,109]]},"30:12":{"text":"To the end that my glory may sing praise to thee, and not be silent. O LORD my God, I will give thanks unto thee for ever.","words":[["H3519","To the end that my glory",0,24],["H2167","may sing",25,33],["H1826","praise to thee, and not be silent",34,67],["H3068","O LORD",69,75],["H0430","my God",76,82],["H3034","I will give thanks",84,102],["H5769","unto thee for ever",103,121]]},"31:1":{"text":"To the chief Musician, A Psalm of David. In thee, O LORD, do I put my trust; let me never be ashamed: deliver me in thy righteousness.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H3068","In thee, O LORD",41,56],["H2620","do I put my trust",58,75],["H0408","let me never",77,89],["H5769","let me never",77,89],["H0954","be ashamed",90,100],["H6403","deliver",102,109],["H6666","me in thy righteousness",110,133]]},"31:2":{"text":"Bow down thine ear to me; deliver me speedily: be thou my strong rock, for an house of defence to save me.","words":[["H5186","Bow down",0,8],["H0241","thine ear",9,18],["H5337","to me; deliver",19,33],["H4120","me speedily",34,45],["H4581","be thou my strong",47,64],["H6697","rock",65,69],["H1004","for an house",71,83],["H4686","of defence",84,94],["H3467","to save",95,102]]},"31:3":{"text":"For thou art my rock and my fortress; therefore for thy name's sake lead me, and guide me.","words":[["H5553","For thou art my rock",0,20],["H4686","and my fortress",21,36],["H8034","therefore for thy name's",38,62],["H5148","sake lead",63,72],["H5095","me, and guide",73,86]]},"31:4":{"text":"Pull me out of the net that they have laid privily for me: for thou art my strength.","words":[["H3318","Pull me out",0,11],["H7568","of the net",12,22],["H2098","that",23,27],["H2934","they have laid privily",28,50],["H4581","for me: for thou art my strength",51,83]]},"31:5":{"text":"Into thine hand I commit my spirit: thou hast redeemed me, O LORD God of truth.","words":[["H3027","Into thine hand",0,15],["H6485","I commit",16,24],["H7307","my spirit",25,34],["H6299","thou hast redeemed",36,54],["H3068","me, O LORD",55,65],["H0410","God",66,69],["H0571","of truth",70,78]]},"31:6":{"text":"I have hated them that regard lying vanities: but I trust in the LORD.","words":[["H8130","I have hated",0,12],["H8104","them that regard",13,29],["H7723","lying",30,35],["H1892","vanities",36,44],["H0982","but I trust",46,57],["H3068","in the LORD",58,69]]},"31:7":{"text":"I will be glad and rejoice in thy mercy: for thou hast considered my trouble; thou hast known my soul in adversities;","words":[["H1523","I will be glad",0,14],["H8055","and rejoice",15,26],["H2617","in thy mercy",27,39],["H7200","for thou hast considered",41,65],["H6040","my trouble",66,76],["H3045","thou hast known",78,93],["H5315","my soul",94,101],["H6869","in adversities",102,116]]},"31:8":{"text":"And hast not shut me up into the hand of the enemy: thou hast set my feet in a large room.","words":[["H5462","And hast not shut me up",0,23],["H3027","into the hand",24,37],["H0341","of the enemy",38,50],["H5975","thou hast set",52,65],["H7272","my feet",66,73],["H4800","in a large room",74,89]]},"31:9":{"text":"Have mercy upon me, O LORD, for I am in trouble: mine eye is consumed with grief, yea, my soul and my belly.","words":[["H2603","Have mercy",0,10],["H3068","upon me, O LORD",11,26],["H6887","for I am in trouble",28,47],["H5869","mine eye",49,57],["H6244","is consumed",58,69],["H3708","with grief",70,80],["H5315","yea, my soul",82,94],["H0990","and my belly",95,107]]},"31:10":{"text":"For my life is spent with grief, and my years with sighing: my strength faileth because of mine iniquity, and my bones are consumed.","words":[["H2416","For my life",0,11],["H3615","is spent",12,20],["H3015","with grief",21,31],["H8141","and my years",33,45],["H0585","with sighing",46,58],["H3581","my strength",60,71],["H3782","faileth",72,79],["H5771","because of mine iniquity",80,104],["H6106","and my bones",106,118],["H6244","are consumed",119,131]]},"31:11":{"text":"I was a reproach among all mine enemies, but especially among my neighbours, and a fear to mine acquaintance: they that did see me without fled from me.","words":[["H2781","I was a reproach",0,16],["H6887","among all mine enemies",17,39],["H3966","but especially",41,55],["H7934","among my neighbours",56,75],["H6343","and a fear",77,87],["H3045","to mine acquaintance",88,108],["H7200","they that did see",110,127],["H2351","me without",128,138],["H5074","fled",139,143]]},"31:12":{"text":"I am forgotten as a dead man out of mind: I am like a broken vessel.","words":[["H7911","I am forgotten",0,14],["H4191","as a dead man",15,28],["H3820","out of mind",29,40],["H0006","I am like a broken",42,60],["H3627","vessel",61,67]]},"31:13":{"text":"For I have heard the slander of many: fear was on every side: while they took counsel together against me, they devised to take away my life.","words":[["H8085","For I have heard",0,16],["H1681","the slander",17,28],["H7227","of many",29,36],["H4032","fear",38,42],["H5439","was on every side",43,60],["H3245","while they took counsel",62,85],["H3162","together",86,94],["H2161","against me, they devised",95,119],["H3947","to take away",120,132],["H5315","my life",133,140]]},"31:14":{"text":"But I trusted in thee, O LORD: I said, Thou art my God.","words":[["H0982","But I trusted",0,13],["H3068","in thee, O LORD",14,29],["H0559","I said",31,37],["H0430","Thou art my God",39,54]]},"31:15":{"text":"My times are in thy hand: deliver me from the hand of mine enemies, and from them that persecute me.","words":[["H6256","My times",0,8],["H3027","are in thy hand",9,24],["H5337","deliver",26,33],["H3027","me from the hand",34,50],["H0341","of mine enemies",51,66],["H7291","and from them that persecute",68,96]]},"31:16":{"text":"Make thy face to shine upon thy servant: save me for thy mercies' sake.","words":[["H6440","Make thy face",0,13],["H0215","to shine",14,22],["H5650","upon thy servant",23,39],["H3467","save",41,45],["H2617","me for thy mercies'",46,65]]},"31:17":{"text":"Let me not be ashamed, O LORD; for I have called upon thee: let the wicked be ashamed, and let them be silent in the grave.","words":[["H0954","Let me not be ashamed",0,21],["H3068","O LORD",23,29],["H7121","for I have called",31,48],["H7563","upon thee: let the wicked",49,74],["H0954","be ashamed",75,85],["H1826","and let them be silent",87,109],["H7585","in the grave",110,122]]},"31:18":{"text":"Let the lying lips be put to silence; which speak grievous things proudly and contemptuously against the righteous.","words":[["H8267","Let the lying",0,13],["H8193","lips",14,18],["H0481","be put to silence",19,36],["H1696","which speak",38,49],["H6277","grievous",50,58],["H1346","things proudly",59,73],["H0937","and contemptuously",74,92],["H6662","against the righteous",93,114]]},"31:19":{"text":"Oh how great is thy goodness, which thou hast laid up for them that fear thee; which thou hast wrought for them that trust in thee before the sons of men!","words":[["H7227","Oh how great",0,12],["H2898","is thy goodness",13,28],["H6845","which thou hast laid up",30,53],["H3373","for them that fear",54,72],["H6466","thee; which thou hast wrought",73,102],["H2620","for them that trust",103,122],["H1121","in thee before the sons",123,146],["H0120","of men",147,153]]},"31:20":{"text":"Thou shalt hide them in the secret of thy presence from the pride of man: thou shalt keep them secretly in a pavilion from the strife of tongues.","words":[["H5641","Thou shalt hide",0,15],["H5643","them in the secret",16,34],["H6440","of thy presence",35,50],["H7407","from the pride",51,65],["H0376","of man",66,72],["H6845","thou shalt keep them secretly",74,103],["H5521","in a pavilion",104,117],["H7379","from the strife",118,133],["H3956","of tongues",134,144]]},"31:21":{"text":"Blessed be the LORD: for he hath shewed me his marvellous kindness in a strong city.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H6381","for he hath shewed me his marvellous",21,57],["H2617","kindness",58,66],["H4692","in a strong",67,78],["H5892","city",79,83]]},"31:22":{"text":"For I said in my haste, I am cut off from before thine eyes: nevertheless thou heardest the voice of my supplications when I cried unto thee.","words":[["H0559","For I said",0,10],["H2648","in my haste",11,22],["H1629","I am cut off",24,36],["H5048","from before",37,48],["H5869","thine eyes",49,59],["H0403","nevertheless",61,73],["H8085","thou heardest",74,87],["H6963","the voice",88,97],["H8469","of my supplications",98,117],["H7768","when I cried",118,130]]},"31:23":{"text":"O love the LORD, all ye his saints: for the LORD preserveth the faithful, and plentifully rewardeth the proud doer.","words":[["H0157","O love",0,6],["H3068","the LORD",7,15],["H2623","all ye his saints",17,34],["H3068","for the LORD",36,48],["H5341","preserveth",49,59],["H0539","the faithful",60,72],["H3499","and plentifully",74,89],["H7999","rewardeth",90,99],["H1346","the proud",100,109],["H6213","doer",110,114]]},"31:24":{"text":"Be of good courage, and he shall strengthen your heart, all ye that hope in the LORD.","words":[["H2388","Be of good courage",0,18],["H0553","and he shall strengthen",20,43],["H3824","your heart",44,54],["H3176","all ye that hope",56,72],["H3068","in the LORD",73,84]]},"32:1":{"text":"A Psalm of David, Maschil. Blessed is he whose transgression is forgiven, whose sin is covered.","words":[["H1732","A Psalm of David",0,16],["H4905","Maschil",18,25],["H0835","Blessed",27,34],["H6588","is he whose transgression",35,60],["H5375","is forgiven",61,72],["H2401","whose sin",74,83],["H3680","is covered",84,94]]},"32:2":{"text":"Blessed is the man unto whom the LORD imputeth not iniquity, and in whose spirit there is no guile.","words":[["H0835","Blessed",0,7],["H0120","is the man",8,18],["H3068","unto whom the LORD",19,37],["H2803","imputeth",38,46],["H5771","not iniquity",47,59],["H7307","and in whose spirit",61,80],["H7423","there is no guile",81,98]]},"32:3":{"text":"When I kept silence, my bones waxed old through my roaring all the day long.","words":[["H2790","When I kept silence",0,19],["H6106","my bones",21,29],["H1086","waxed old",30,39],["H7581","through my roaring",40,58],["H3117","all the day",59,70]]},"32:4":{"text":"For day and night thy hand was heavy upon me: my moisture is turned into the drought of summer. Selah.","words":[["H3119","For day",0,7],["H3915","and night",8,17],["H3027","thy hand",18,26],["H3513","was heavy",27,36],["H3955","upon me: my moisture",37,57],["H2015","is turned",58,67],["H2725","into the drought",68,84],["H7019","of summer",85,94],["H5542","Selah",96,101]]},"32:5":{"text":"I acknowledged my sin unto thee, and mine iniquity have I not hid. I said, I will confess my transgressions unto the LORD; and thou forgavest the iniquity of my sin. Selah.","words":[["H3045","I acknowledged",0,14],["H2403","my sin",15,21],["H5771","unto thee, and mine iniquity",22,50],["H3680","have I not hid",51,65],["H0559","I said",67,73],["H3034","I will confess",75,89],["H6588","my transgressions",90,107],["H3068","unto the LORD",108,121],["H5375","and thou forgavest",123,141],["H5771","the iniquity",142,154],["H2403","of my sin",155,164],["H5542","Selah",166,171]]},"32:6":{"text":"For this shall every one that is godly pray unto thee in a time when thou mayest be found: surely in the floods of great waters they shall not come nigh unto him.","words":[["H2623","For this shall every one that is godly",0,38],["H6419","pray",39,43],["H6256","unto thee in a time",44,63],["H4672","when thou mayest be found",64,89],["H7858","surely in the floods",91,111],["H7227","of great",112,120],["H4325","waters",121,127],["H5060","they shall not come nigh",128,152]]},"32:7":{"text":"Thou art my hiding place; thou shalt preserve me from trouble; thou shalt compass me about with songs of deliverance. Selah.","words":[["H5643","Thou art my hiding place",0,24],["H5341","thou shalt preserve",26,45],["H6862","me from trouble",46,61],["H5437","thou shalt compass",63,81],["H7438","me about with songs",82,101],["H6405","of deliverance",102,116],["H5542","Selah",118,123]]},"32:8":{"text":"I will instruct thee and teach thee in the way which thou shalt go: I will guide thee with mine eye.","words":[["H7919","I will instruct",0,15],["H3384","thee and teach",16,30],["H1870","thee in the way",31,46],["H2098","which",47,52],["H3212","thou shalt go",53,66],["H3289","I will guide",68,80],["H5869","thee with mine eye",81,99]]},"32:9":{"text":"Be ye not as the horse, or as the mule, which have no understanding: whose mouth must be held in with bit and bridle, lest they come near unto thee.","words":[["H5483","Be ye not as the horse",0,22],["H6505","or as the mule",24,38],["H0995","which have no understanding",40,67],["H5716","whose mouth",69,80],["H1102","must be held",81,93],["H4964","in with bit",94,105],["H7448","and bridle",106,116],["H1077","lest",118,122],["H7126","they come near",123,137]]},"32:10":{"text":"Many sorrows shall be to the wicked: but he that trusteth in the LORD, mercy shall compass him about.","words":[["H7227","Many",0,4],["H4341","sorrows",5,12],["H7563","shall be to the wicked",13,35],["H0982","but he that trusteth",37,57],["H3068","in the LORD",58,69],["H2617","mercy",71,76],["H5437","shall compass",77,90]]},"32:11":{"text":"Be glad in the LORD, and rejoice, ye righteous: and shout for joy, all ye that are upright in heart.","words":[["H8055","Be glad",0,7],["H3068","in the LORD",8,19],["H1523","and rejoice",21,32],["H6662","ye righteous",34,46],["H7442","and shout",48,57],["H3477","for joy, all ye that are upright",58,90],["H3820","in heart",91,99]]},"33:1":{"text":"Rejoice in the LORD, O ye righteous: for praise is comely for the upright.","words":[["H7442","Rejoice",0,7],["H3068","in the LORD",8,19],["H6662","O ye righteous",21,35],["H8416","for praise",37,47],["H5000","is comely",48,57],["H3477","for the upright",58,73]]},"33:2":{"text":"Praise the LORD with harp: sing unto him with the psaltery and an instrument of ten strings.","words":[["H3034","Praise",0,6],["H3068","the LORD",7,15],["H3658","with harp",16,25],["H2167","sing",27,31],["H5035","unto him with the psaltery",32,58],["H6218","and an instrument of ten strings",59,91]]},"33:3":{"text":"Sing unto him a new song; play skilfully with a loud noise.","words":[["H7891","Sing",0,4],["H2319","unto him a new",5,19],["H7892","song",20,24],["H5059","play",26,30],["H3190","skilfully",31,40],["H8643","with a loud noise",41,58]]},"33:4":{"text":"For the word of the LORD is right; and all his works are done in truth.","words":[["H1697","For the word",0,12],["H3068","of the LORD",13,24],["H3477","is right",25,33],["H4639","and all his works",35,52],["H0530","are done in truth",53,70]]},"33:5":{"text":"He loveth righteousness and judgment: the earth is full of the goodness of the LORD.","words":[["H0157","He loveth",0,9],["H6666","righteousness",10,23],["H4941","and judgment",24,36],["H0776","the earth",38,47],["H4390","is full",48,55],["H2617","of the goodness",56,71],["H3068","of the LORD",72,83]]},"33:6":{"text":"By the word of the LORD were the heavens made; and all the host of them by the breath of his mouth.","words":[["H1697","By the word",0,11],["H3068","of the LORD",12,23],["H8064","were the heavens",24,40],["H6213","made",41,45],["H6635","and all the host",47,63],["H7307","of them by the breath",64,85],["H6310","of his mouth",86,98]]},"33:7":{"text":"He gathereth the waters of the sea together as an heap: he layeth up the depth in storehouses.","words":[["H3664","He gathereth",0,12],["H4325","the waters",13,23],["H3220","of the sea",24,34],["H5067","together as an heap",35,54],["H5414","he layeth up",56,68],["H8415","the depth",69,78],["H0214","in storehouses",79,93]]},"33:8":{"text":"Let all the earth fear the LORD: let all the inhabitants of the world stand in awe of him.","words":[["H0776","Let all the earth",0,17],["H3372","fear",18,22],["H3068","the LORD",23,31],["H3427","let all the inhabitants",33,56],["H8398","of the world",57,69],["H1481","stand in awe",70,82]]},"33:9":{"text":"For he spake, and it was done; he commanded, and it stood fast.","words":[["H0559","For he spake",0,12],["H6680","and it was done; he commanded",14,43],["H5975","and it stood fast",45,62]]},"33:10":{"text":"The LORD bringeth the counsel of the heathen to nought: he maketh the devices of the people of none effect.","words":[["H3068","The LORD",0,8],["H6331","bringeth",9,17],["H6098","the counsel",18,29],["H1471","of the heathen",30,44],["H6331","to nought",45,54],["H5106","he maketh",56,65],["H4284","the devices",66,77],["H5971","of the people",78,91],["H5106","of none effect",92,106]]},"33:11":{"text":"The counsel of the LORD standeth for ever, the thoughts of his heart to all generations.","words":[["H6098","The counsel",0,11],["H3068","of the LORD",12,23],["H5975","standeth",24,32],["H5769","for ever",33,41],["H4284","the thoughts",43,55],["H3820","of his heart",56,68],["H1755","to all",69,75],["H1755","generations",76,87]]},"33:12":{"text":"Blessed is the nation whose God is the LORD; and the people whom he hath chosen for his own inheritance.","words":[["H0835","Blessed",0,7],["H1471","is the nation",8,21],["H0430","whose God",22,31],["H3068","is the LORD",32,43],["H5971","and the people",45,59],["H0977","whom he hath chosen",60,79],["H5159","for his own inheritance",80,103]]},"33:13":{"text":"The LORD looketh from heaven; he beholdeth all the sons of men.","words":[["H3068","The LORD",0,8],["H5027","looketh",9,16],["H8064","from heaven",17,28],["H7200","he beholdeth",30,42],["H1121","all the sons",43,55],["H0120","of men",56,62]]},"33:14":{"text":"From the place of his habitation he looketh upon all the inhabitants of the earth.","words":[["H4349","From the place",0,14],["H3427","of his habitation",15,32],["H7688","he looketh",33,43],["H3427","upon all the inhabitants",44,68],["H0776","of the earth",69,81]]},"33:15":{"text":"He fashioneth their hearts alike; he considereth all their works.","words":[["H3335","He fashioneth",0,13],["H3820","their hearts",14,26],["H3162","alike",27,32],["H0995","he considereth",34,48],["H4639","all their works",49,64]]},"33:16":{"text":"There is no king saved by the multitude of an host: a mighty man is not delivered by much strength.","words":[["H4428","There is no king",0,16],["H3467","saved",17,22],["H7230","by the multitude",23,39],["H2428","of an host",40,50],["H1368","a mighty man",52,64],["H5337","is not delivered",65,81],["H7230","by much",82,89],["H3581","strength",90,98]]},"33:17":{"text":"An horse is a vain thing for safety: neither shall he deliver any by his great strength.","words":[["H5483","An horse",0,8],["H8267","is a vain thing",9,24],["H8668","for safety",25,35],["H4422","neither shall he deliver",37,61],["H7230","any by his great",62,78],["H2428","strength",79,87]]},"33:18":{"text":"Behold, the eye of the LORD is upon them that fear him, upon them that hope in his mercy;","words":[["H5869","Behold, the eye",0,15],["H3068","of the LORD",16,27],["H3373","is upon them that fear",28,50],["H3176","him, upon them that hope",51,75],["H2617","in his mercy",76,88]]},"33:19":{"text":"To deliver their soul from death, and to keep them alive in famine.","words":[["H5337","To deliver",0,10],["H5315","their soul",11,21],["H4194","from death",22,32],["H2421","and to keep them alive",34,56],["H7458","in famine",57,66]]},"33:20":{"text":"Our soul waiteth for the LORD: he is our help and our shield.","words":[["H5315","Our soul",0,8],["H2442","waiteth",9,16],["H3068","for the LORD",17,29],["H5828","he is our help",31,45],["H4043","and our shield",46,60]]},"33:21":{"text":"For our heart shall rejoice in him, because we have trusted in his holy name.","words":[["H3820","For our heart",0,13],["H8055","shall rejoice",14,27],["H0982","in him, because we have trusted",28,59],["H6944","in his holy",60,71],["H8034","name",72,76]]},"33:22":{"text":"Let thy mercy, O LORD, be upon us, according as we hope in thee.","words":[["H2617","Let thy mercy",0,13],["H3068","O LORD",15,21],["H3176","be upon us, according as we hope",23,55]]},"34:1":{"text":"A Psalm of David, when he changed his behaviour before Abimelech; who drove him away, and he departed. I will bless the LORD at all times: his praise shall continually be in my mouth.","words":[["H1732","A Psalm of David",0,16],["H8138","when he changed",18,33],["H2940","his behaviour",34,47],["H6440","before",48,54],["H0040","Abimelech",55,64],["H1644","who drove him away",66,84],["H3212","and he departed",86,101],["H1288","I will bless",103,115],["H3068","the LORD",116,124],["H6256","at all times",125,137],["H8416","his praise",139,149],["H8548","shall continually",150,167],["H6310","be in my mouth",168,182]]},"34:2":{"text":"My soul shall make her boast in the LORD: the humble shall hear thereof, and be glad.","words":[["H5315","My soul",0,7],["H1984","shall make her boast",8,28],["H3068","in the LORD",29,40],["H6035","the humble",42,52],["H8085","shall hear",53,63],["H8055","thereof, and be glad",64,84]]},"34:3":{"text":"O magnify the LORD with me, and let us exalt his name together.","words":[["H1431","O magnify",0,9],["H3068","the LORD",10,18],["H7311","with me, and let us exalt",19,44],["H8034","his name",45,53],["H3162","together",54,62]]},"34:4":{"text":"I sought the LORD, and he heard me, and delivered me from all my fears.","words":[["H1875","I sought",0,8],["H3068","the LORD",9,17],["H6030","and he heard",19,31],["H5337","me, and delivered",32,49],["H4035","me from all my fears",50,70]]},"34:5":{"text":"They looked unto him, and were lightened: and their faces were not ashamed.","words":[["H5027","They looked",0,11],["H5102","unto him, and were lightened",12,40],["H6440","and their faces",42,57],["H2659","were not ashamed",58,74]]},"34:6":{"text":"This poor man cried, and the LORD heard him, and saved him out of all his troubles.","words":[["H6041","This poor man",0,13],["H7121","cried",14,19],["H3068","and the LORD",21,33],["H8085","heard",34,39],["H3467","him, and saved",40,54],["H6869","him out of all his troubles",55,82]]},"34:7":{"text":"The angel of the LORD encampeth round about them that fear him, and delivereth them.","words":[["H4397","The angel",0,9],["H3068","of the LORD",10,21],["H2583","encampeth",22,31],["H5439","round about",32,43],["H3373","them that fear",44,58],["H2502","him, and delivereth",59,78]]},"34:8":{"text":"O taste and see that the LORD is good: blessed is the man that trusteth in him.","words":[["H2938","O taste",0,7],["H7200","and see",8,15],["H3068","that the LORD",16,29],["H2896","is good",30,37],["H0835","blessed",39,46],["H1397","is the man",47,57],["H2620","that trusteth",58,71]]},"34:9":{"text":"O fear the LORD, ye his saints: for there is no want to them that fear him.","words":[["H3372","O fear",0,6],["H3068","the LORD",7,15],["H6918","ye his saints",17,30],["H4270","for there is no want",32,52],["H3373","to them that fear",53,70]]},"34:10":{"text":"The young lions do lack, and suffer hunger: but they that seek the LORD shall not want any good thing.","words":[["H3715","The young lions",0,15],["H7326","do lack",16,23],["H7456","and suffer hunger",25,42],["H1875","but they that seek",44,62],["H3068","the LORD",63,71],["H2637","shall not want",72,86],["H2896","any good",87,95]]},"34:11":{"text":"Come, ye children, hearken unto me: I will teach you the fear of the LORD.","words":[["H3212","Come",0,4],["H1121","ye children",6,17],["H8085","hearken",19,26],["H3925","unto me: I will teach",27,48],["H3374","you the fear",49,61],["H3068","of the LORD",62,73]]},"34:12":{"text":"What man is he that desireth life, and loveth many days, that he may see good?","words":[["H0376","What man",0,8],["H2655","is he that desireth",9,28],["H2416","life",29,33],["H0157","and loveth",35,45],["H3117","many days",46,55],["H7200","that he may see",57,72],["H2896","good",73,77]]},"34:13":{"text":"Keep thy tongue from evil, and thy lips from speaking guile.","words":[["H5341","Keep",0,4],["H3956","thy tongue",5,15],["H7451","from evil",16,25],["H8193","and thy lips",27,39],["H1696","from speaking",40,53],["H4820","guile",54,59]]},"34:14":{"text":"Depart from evil, and do good; seek peace, and pursue it.","words":[["H5493","Depart",0,6],["H7451","from evil",7,16],["H6213","and do",18,24],["H2896","good",25,29],["H1245","seek",31,35],["H7965","peace",36,41],["H7291","and pursue",43,53]]},"34:15":{"text":"The eyes of the LORD are upon the righteous, and his ears are open unto their cry.","words":[["H5869","The eyes",0,8],["H3068","of the LORD",9,20],["H6662","are upon the righteous",21,43],["H0241","and his ears",45,57],["H7775","are open unto their cry",58,81]]},"34:16":{"text":"The face of the LORD is against them that do evil, to cut off the remembrance of them from the earth.","words":[["H6440","The face",0,8],["H3068","of the LORD",9,20],["H6213","is against them that do",21,44],["H7451","evil",45,49],["H3772","to cut off",51,61],["H2143","the remembrance",62,77],["H0776","of them from the earth",78,100]]},"34:17":{"text":"The righteous cry, and the LORD heareth, and delivereth them out of all their troubles.","words":[["H6817","The righteous cry",0,17],["H3068","and the LORD",19,31],["H8085","heareth",32,39],["H5337","and delivereth",41,55],["H6869","them out of all their troubles",56,86]]},"34:18":{"text":"The LORD is nigh unto them that are of a broken heart; and saveth such as be of a contrite spirit.","words":[["H3068","The LORD",0,8],["H7138","is nigh",9,16],["H7665","unto them that are of a broken",17,47],["H3820","heart",48,53],["H3467","and saveth",55,65],["H1793","such as be of a contrite",66,90],["H7307","spirit",91,97]]},"34:19":{"text":"Many are the afflictions of the righteous: but the LORD delivereth him out of them all.","words":[["H7227","Many",0,4],["H7451","are the afflictions",5,24],["H6662","of the righteous",25,41],["H3068","but the LORD",43,55],["H5337","delivereth",56,66]]},"34:20":{"text":"He keepeth all his bones: not one of them is broken.","words":[["H8104","He keepeth",0,10],["H6106","all his bones",11,24],["H0259","not one",26,33],["H2007","of them",34,41],["H7665","is broken",42,51]]},"34:21":{"text":"Evil shall slay the wicked: and they that hate the righteous shall be desolate.","words":[["H7451","Evil",0,4],["H4191","shall slay",5,15],["H7563","the wicked",16,26],["H8130","and they that hate",28,46],["H6662","the righteous",47,60],["H0816","shall be desolate",61,78]]},"34:22":{"text":"The LORD redeemeth the soul of his servants: and none of them that trust in him shall be desolate.","words":[["H3068","The LORD",0,8],["H6299","redeemeth",9,18],["H5315","the soul",19,27],["H5650","of his servants",28,43],["H2620","and none of them that trust",45,72],["H0816","in him shall be desolate",73,97]]},"35:1":{"text":"A Psalm of David. Plead my cause, O LORD, with them that strive with me: fight against them that fight against me.","words":[["H1732","A Psalm of David",0,16],["H7378","Plead",18,23],["H3068","my cause, O LORD",24,40],["H3401","with them that strive",42,63],["H3898","with me: fight",64,78],["H3898","against them that fight",79,102]]},"35:2":{"text":"Take hold of shield and buckler, and stand up for mine help.","words":[["H2388","Take hold",0,9],["H4043","of shield",10,19],["H6793","and buckler",20,31],["H6965","and stand up",33,45],["H5833","for mine help",46,59]]},"35:3":{"text":"Draw out also the spear, and stop the way against them that persecute me: say unto my soul, I am thy salvation.","words":[["H7324","Draw out",0,8],["H2595","also the spear",9,23],["H5462","and stop",25,33],["H7125","the way against",34,49],["H7291","them that persecute",50,69],["H0559","me: say",70,77],["H5315","unto my soul",78,90],["H3444","I am thy salvation",92,110]]},"35:4":{"text":"Let them be confounded and put to shame that seek after my soul: let them be turned back and brought to confusion that devise my hurt.","words":[["H0954","Let them be confounded",0,22],["H3637","and put to shame",23,39],["H1245","that seek",40,49],["H5315","after my soul",50,63],["H5472","let them be turned",65,83],["H0268","back",84,88],["H2659","and brought to confusion",89,113],["H2803","that devise",114,125],["H7451","my hurt",126,133]]},"35:5":{"text":"Let them be as chaff before the wind: and let the angel of the LORD chase them.","words":[["H4671","Let them be as chaff",0,20],["H6440","before",21,27],["H7307","the wind",28,36],["H4397","and let the angel",38,55],["H3068","of the LORD",56,67],["H1760","chase",68,73]]},"35:6":{"text":"Let their way be dark and slippery: and let the angel of the LORD persecute them.","words":[["H1870","Let their way",0,13],["H2822","be dark",14,21],["H2519","and slippery",22,34],["H4397","and let the angel",36,53],["H3068","of the LORD",54,65],["H7291","persecute",66,75]]},"35:7":{"text":"For without cause have they hid for me their net in a pit, which without cause they have digged for my soul.","words":[["H2600","For without cause",0,17],["H2934","have they hid",18,31],["H7568","for me their net",32,48],["H7845","in a pit",49,57],["H2600","which without cause",59,78],["H2658","they have digged",79,95],["H5315","for my soul",96,107]]},"35:8":{"text":"Let destruction come upon him at unawares; and let his net that he hath hid catch himself: into that very destruction let him fall.","words":[["H7722","Let destruction",0,15],["H0935","come",16,20],["H3045","upon him at unawares",21,41],["H3808","upon him at unawares",21,41],["H7568","and let his net",43,58],["H2934","that he hath hid",59,75],["H3920","catch",76,81],["H7722","himself: into that very destruction",82,117],["H5307","let him fall",118,130]]},"35:9":{"text":"And my soul shall be joyful in the LORD: it shall rejoice in his salvation.","words":[["H5315","And my soul",0,11],["H1523","shall be joyful",12,27],["H3068","in the LORD",28,39],["H7797","it shall rejoice",41,57],["H3444","in his salvation",58,74]]},"35:10":{"text":"All my bones shall say, LORD, who is like unto thee, which deliverest the poor from him that is too strong for him, yea, the poor and the needy from him that spoileth him?","words":[["H6106","All my bones",0,12],["H0559","shall say",13,22],["H3068","LORD",24,28],["H5337","who is like unto thee, which deliverest",30,69],["H6041","the poor",70,78],["H2389","from him that is too strong",79,106],["H6041","for him, yea, the poor",107,129],["H0034","and the needy",130,143],["H1497","from him that spoileth",144,166]]},"35:11":{"text":"False witnesses did rise up; they laid to my charge things that I knew not.","words":[["H2555","False",0,5],["H5707","witnesses",6,15],["H6965","did rise up",16,27],["H7592","they laid to my charge",29,51],["H3045","things that I knew",52,70]]},"35:12":{"text":"They rewarded me evil for good to the spoiling of my soul.","words":[["H7999","They rewarded",0,13],["H7451","me evil",14,21],["H2896","for good",22,30],["H7908","to the spoiling",31,46],["H5315","of my soul",47,57]]},"35:13":{"text":"But as for me, when they were sick, my clothing was sackcloth: I humbled my soul with fasting; and my prayer returned into mine own bosom.","words":[["H2470","But as for me, when they were sick",0,34],["H3830","my clothing",36,47],["H8242","was sackcloth",48,61],["H6031","I humbled",63,72],["H5315","my soul",73,80],["H6685","with fasting",81,93],["H8605","and my prayer",95,108],["H7725","returned",109,117],["H2436","into mine own bosom",118,137]]},"35:14":{"text":"I behaved myself as though he had been my friend or brother: I bowed down heavily, as one that mourneth for his mother.","words":[["H1980","I behaved",0,9],["H7453","myself as though he had been my friend",10,48],["H0251","or brother",49,59],["H7817","I bowed down",61,73],["H6937","heavily",74,81],["H0057","as one that mourneth",83,103],["H0517","for his mother",104,118]]},"35:15":{"text":"But in mine adversity they rejoiced, and gathered themselves together: yea, the abjects gathered themselves together against me, and I knew it not; they did tear me, and ceased not:","words":[["H6761","But in mine adversity",0,21],["H8055","they rejoiced",22,35],["H0622","and gathered themselves together",37,69],["H5222","yea, the abjects",71,87],["H0622","gathered themselves together",88,116],["H3045","against me, and I knew",117,139],["H7167","it not; they did tear",140,161],["H1826","me, and ceased",162,176]]},"35:16":{"text":"With hypocritical mockers in feasts, they gnashed upon me with their teeth.","words":[["H2611","With hypocritical",0,17],["H3934","mockers",18,25],["H4580","in feasts",26,35],["H2786","they gnashed",37,49],["H8127","upon me with their teeth",50,74]]},"35:17":{"text":"Lord, how long wilt thou look on? rescue my soul from their destructions, my darling from the lions.","words":[["H0136","Lord",0,4],["H7200","how long wilt thou look on",6,32],["H7725","rescue",34,40],["H5315","my soul",41,48],["H7722","from their destructions",49,72],["H3173","my darling",74,84],["H3715","from the lions",85,99]]},"35:18":{"text":"I will give thee thanks in the great congregation: I will praise thee among much people.","words":[["H3034","I will give thee thanks",0,23],["H7227","in the great",24,36],["H6951","congregation",37,49],["H1984","I will praise",51,64],["H6099","thee among much",65,80],["H5971","people",81,87]]},"35:19":{"text":"Let not them that are mine enemies wrongfully rejoice over me: neither let them wink with the eye that hate me without a cause.","words":[["H0341","Let not them that are mine enemies",0,34],["H8267","wrongfully",35,45],["H8055","rejoice",46,53],["H7169","over me: neither let them wink",54,84],["H5869","with the eye",85,97],["H8130","that hate",98,107],["H2600","me without a cause",108,126]]},"35:20":{"text":"For they speak not peace: but they devise deceitful matters against them that are quiet in the land.","words":[["H1696","For they speak",0,14],["H7965","not peace",15,24],["H2803","but they devise",26,41],["H4820","deceitful",42,51],["H1697","matters",52,59],["H7282","against them that are quiet",60,87],["H0776","in the land",88,99]]},"35:21":{"text":"Yea, they opened their mouth wide against me, and said, Aha, aha, our eye hath seen it.","words":[["H6310","Yea, they opened their mouth",0,28],["H7337","wide",29,33],["H0559","against me, and said",34,54],["H1889","Aha",56,59],["H1889","aha",61,64],["H5869","our eye",66,73],["H7200","hath seen",74,83]]},"35:22":{"text":"This thou hast seen, O LORD: keep not silence: O Lord, be not far from me.","words":[["H7200","This thou hast seen",0,19],["H3068","O LORD",21,27],["H2790","keep not silence",29,45],["H0136","O Lord",47,53],["H7368","be not far",55,65]]},"35:23":{"text":"Stir up thyself, and awake to my judgment, even unto my cause, my God and my Lord.","words":[["H5782","Stir up",0,7],["H6974","thyself, and awake",8,26],["H4941","to my judgment",27,41],["H7379","even unto my cause",43,61],["H0430","my God",63,69],["H0136","and my Lord",70,81]]},"35:24":{"text":"Judge me, O LORD my God, according to thy righteousness; and let them not rejoice over me.","words":[["H8199","Judge",0,5],["H3068","me, O LORD",6,16],["H0430","my God",17,23],["H6664","according to thy righteousness",25,55],["H8055","and let them not rejoice",57,81]]},"35:25":{"text":"Let them not say in their hearts, Ah, so would we have it: let them not say, We have swallowed him up.","words":[["H0559","Let them not say",0,16],["H3820","in their hearts",17,32],["H1889","Ah",34,36],["H5315","so would we have it",38,57],["H0559","let them not say",59,75],["H1104","We have swallowed him up",77,101]]},"35:26":{"text":"Let them be ashamed and brought to confusion together that rejoice at mine hurt: let them be clothed with shame and dishonour that magnify themselves against me.","words":[["H0954","Let them be ashamed",0,19],["H2659","and brought to confusion",20,44],["H3162","together",45,53],["H8056","that rejoice",54,66],["H7451","at mine hurt",67,79],["H3847","let them be clothed",81,100],["H1322","with shame",101,111],["H3639","and dishonour",112,125],["H1431","that magnify",126,138]]},"35:27":{"text":"Let them shout for joy, and be glad, that favour my righteous cause: yea, let them say continually, Let the LORD be magnified, which hath pleasure in the prosperity of his servant.","words":[["H7442","Let them shout for joy",0,22],["H8055","and be glad",24,35],["H2655","that favour",37,48],["H6664","my righteous cause",49,67],["H0559","yea, let them say",69,86],["H8548","continually",87,98],["H3068","Let the LORD",100,112],["H1431","be magnified",113,125],["H2655","which hath pleasure",127,146],["H7965","in the prosperity",147,164],["H5650","of his servant",165,179]]},"35:28":{"text":"And my tongue shall speak of thy righteousness and of thy praise all the day long.","words":[["H3956","And my tongue",0,13],["H1897","shall speak",14,25],["H6664","of thy righteousness",26,46],["H8416","and of thy praise",47,64],["H3117","all the day",65,76]]},"36:1":{"text":"To the chief Musician, A Psalm of David the servant of the LORD. The transgression of the wicked saith within my heart, that there is no fear of God before his eyes.","words":[["H5329","To the chief Musician",0,21],["H1732","A Psalm of David",23,39],["H5650","the servant",40,51],["H3068","of the LORD",52,63],["H6588","The transgression",65,82],["H7563","of the wicked",83,96],["H5002","saith",97,102],["H7130","within",103,109],["H3820","my heart",110,118],["H6343","that there is no fear",120,141],["H0430","of God",142,148],["H5869","before his eyes",149,164]]},"36:2":{"text":"For he flattereth himself in his own eyes, until his iniquity be found to be hateful.","words":[["H2505","For he flattereth",0,17],["H5869","himself in his own eyes",18,41],["H5771","until his iniquity",43,61],["H4672","be found",62,70],["H8130","to be hateful",71,84]]},"36:3":{"text":"The words of his mouth are iniquity and deceit: he hath left off to be wise, and to do good.","words":[["H1697","The words",0,9],["H6310","of his mouth",10,22],["H0205","are iniquity",23,35],["H4820","and deceit",36,46],["H2308","he hath left off",48,64],["H7919","to be wise",65,75],["H3190","and to do good",77,91]]},"36:4":{"text":"He deviseth mischief upon his bed; he setteth himself in a way that is not good; he abhorreth not evil.","words":[["H2803","He deviseth",0,11],["H0205","mischief",12,20],["H4904","upon his bed",21,33],["H3320","he setteth",35,45],["H1870","himself in a way",46,62],["H2896","that is not good",63,79],["H3988","he abhorreth",81,93],["H7451","not evil",94,102]]},"36:5":{"text":"Thy mercy, O LORD, is in the heavens; and thy faithfulness reacheth unto the clouds.","words":[["H2617","Thy mercy",0,9],["H3068","O LORD",11,17],["H8064","is in the heavens",19,36],["H0530","and thy faithfulness",38,58],["H7834","reacheth unto the clouds",59,83]]},"36:6":{"text":"Thy righteousness is like the great mountains; thy judgments are a great deep: O LORD, thou preservest man and beast.","words":[["H6666","Thy righteousness",0,17],["H0410","is like the great",18,35],["H2042","mountains",36,45],["H4941","thy judgments",47,60],["H7227","are a great",61,72],["H8415","deep",73,77],["H3068","O LORD",79,85],["H3467","thou preservest",87,102],["H0120","man",103,106],["H0929","and beast",107,116]]},"36:7":{"text":"How excellent is thy lovingkindness, O God! therefore the children of men put their trust under the shadow of thy wings.","words":[["H3368","How excellent",0,13],["H2617","is thy lovingkindness",14,35],["H0430","O God",37,42],["H1121","therefore the children",44,66],["H0120","of men",67,73],["H2620","put their trust",74,89],["H6738","under the shadow",90,106],["H3671","of thy wings",107,119]]},"36:8":{"text":"They shall be abundantly satisfied with the fatness of thy house; and thou shalt make them drink of the river of thy pleasures.","words":[["H7301","They shall be abundantly satisfied",0,34],["H1880","with the fatness",35,51],["H1004","of thy house",52,64],["H8248","and thou shalt make them drink",66,96],["H5158","of the river",97,109],["H5730","of thy pleasures",110,126]]},"36:9":{"text":"For with thee is the fountain of life: in thy light shall we see light.","words":[["H4726","For with thee is the fountain",0,29],["H2416","of life",30,37],["H0216","in thy light",39,51],["H7200","shall we see",52,64],["H0216","light",65,70]]},"36:10":{"text":"O continue thy lovingkindness unto them that know thee; and thy righteousness to the upright in heart.","words":[["H4900","O continue",0,10],["H2617","thy lovingkindness",11,29],["H3045","unto them that know",30,49],["H6666","thee; and thy righteousness",50,77],["H3477","to the upright",78,92],["H3820","in heart",93,101]]},"36:11":{"text":"Let not the foot of pride come against me, and let not the hand of the wicked remove me.","words":[["H7272","Let not the foot",0,16],["H1346","of pride",17,25],["H0935","come",26,30],["H3027","against me, and let not the hand",31,63],["H7563","of the wicked",64,77],["H5110","remove",78,84]]},"36:12":{"text":"There are the workers of iniquity fallen: they are cast down, and shall not be able to rise.","words":[["H6466","There are the workers",0,21],["H0205","of iniquity",22,33],["H5307","fallen",34,40],["H1760","they are cast down",42,60],["H3201","and shall not be able",62,83],["H6965","to rise",84,91]]},"37:1":{"text":"A Psalm of David. Fret not thyself because of evildoers, neither be thou envious against the workers of iniquity.","words":[["H1732","A Psalm of David",0,16],["H2734","Fret",18,22],["H7489","not thyself because of evildoers",23,55],["H7065","neither be thou envious",57,80],["H6213","against the workers",81,100],["H5766","of iniquity",101,112]]},"37:2":{"text":"For they shall soon be cut down like the grass, and wither as the green herb.","words":[["H4120","For they shall soon",0,19],["H5243","be cut down",20,31],["H2682","like the grass",32,46],["H5034","and wither",48,58],["H3418","as the green",59,71],["H1877","herb",72,76]]},"37:3":{"text":"Trust in the LORD, and do good; so shalt thou dwell in the land, and verily thou shalt be fed.","words":[["H0982","Trust",0,5],["H3068","in the LORD",6,17],["H6213","and do",19,25],["H2896","good",26,30],["H7931","so shalt thou dwell",32,51],["H0776","in the land",52,63],["H0530","and verily",65,75],["H7462","thou shalt be fed",76,93]]},"37:4":{"text":"Delight thyself also in the LORD; and he shall give thee the desires of thine heart.","words":[["H6026","Delight",0,7],["H3068","thyself also in the LORD",8,32],["H5414","and he shall give",34,51],["H4862","thee the desires",52,68],["H3820","of thine heart",69,83]]},"37:5":{"text":"Commit thy way unto the LORD; trust also in him; and he shall bring it to pass.","words":[["H1556","Commit",0,6],["H1870","thy way",7,14],["H3068","unto the LORD",15,28],["H0982","trust",30,35],["H6213","also in him; and he shall bring it to pass",36,78]]},"37:6":{"text":"And he shall bring forth thy righteousness as the light, and thy judgment as the noonday.","words":[["H3318","And he shall bring forth",0,24],["H6664","thy righteousness",25,42],["H0216","as the light",43,55],["H4941","and thy judgment",57,73],["H6672","as the noonday",74,88]]},"37:7":{"text":"Rest in the LORD, and wait patiently for him: fret not thyself because of him who prospereth in his way, because of the man who bringeth wicked devices to pass.","words":[["H1826","Rest",0,4],["H3068","in the LORD",5,16],["H2342","and wait patiently",18,36],["H2734","for him: fret",37,50],["H6743","not thyself because of him who prospereth",51,92],["H1870","in his way",93,103],["H0376","because of the man",105,123],["H6213","who bringeth",124,136],["H4209","wicked devices",137,151],["H6213","to pass",152,159]]},"37:8":{"text":"Cease from anger, and forsake wrath: fret not thyself in any wise to do evil.","words":[["H7503","Cease",0,5],["H0639","from anger",6,16],["H5800","and forsake",18,29],["H2534","wrath",30,35],["H2734","fret",37,41],["H0389","not thyself in any wise",42,65],["H7489","to do evil",66,76]]},"37:9":{"text":"For evildoers shall be cut off: but those that wait upon the LORD, they shall inherit the earth.","words":[["H7489","For evildoers",0,13],["H3772","shall be cut off",14,30],["H6960","but those that wait",32,51],["H3068","upon the LORD",52,65],["H3423","they shall inherit",67,85],["H0776","the earth",86,95]]},"37:10":{"text":"For yet a little while, and the wicked shall not be: yea, thou shalt diligently consider his place, and it shall not be.","words":[["H4592","For yet a little while",0,22],["H7563","and the wicked",24,38],["H0995","shall not be: yea, thou shalt diligently consider",39,88],["H4725","his place",89,98]]},"37:11":{"text":"But the meek shall inherit the earth; and shall delight themselves in the abundance of peace.","words":[["H6035","But the meek",0,12],["H3423","shall inherit",13,26],["H0776","the earth",27,36],["H6026","and shall delight",38,55],["H7230","themselves in the abundance",56,83],["H7965","of peace",84,92]]},"37:12":{"text":"The wicked plotteth against the just, and gnasheth upon him with his teeth.","words":[["H7563","The wicked",0,10],["H2161","plotteth",11,19],["H6662","against the just",20,36],["H2786","and gnasheth",38,50],["H8127","upon him with his teeth",51,74]]},"37:13":{"text":"The Lord shall laugh at him: for he seeth that his day is coming.","words":[["H0136","The Lord",0,8],["H7832","shall laugh",9,20],["H7200","at him: for he seeth",21,41],["H3117","that his day",42,54],["H0935","is coming",55,64]]},"37:14":{"text":"The wicked have drawn out the sword, and have bent their bow, to cast down the poor and needy, and to slay such as be of upright conversation.","words":[["H7563","The wicked",0,10],["H6605","have drawn out",11,25],["H2719","the sword",26,35],["H1869","and have bent",37,50],["H7198","their bow",51,60],["H5307","to cast down",62,74],["H6041","the poor",75,83],["H0034","and needy",84,93],["H2873","and to slay",95,106],["H3477","such as be of upright",107,128],["H1870","conversation",129,141]]},"37:15":{"text":"Their sword shall enter into their own heart, and their bows shall be broken.","words":[["H2719","Their sword",0,11],["H0935","shall enter",12,23],["H3820","into their own heart",24,44],["H7198","and their bows",46,60],["H7665","shall be broken",61,76]]},"37:16":{"text":"A little that a righteous man hath is better than the riches of many wicked.","words":[["H4592","A little",0,8],["H6662","that a righteous man",9,29],["H2896","hath is better",30,44],["H1995","than the riches",45,60],["H7227","of many",61,68],["H7563","wicked",69,75]]},"37:17":{"text":"For the arms of the wicked shall be broken: but the LORD upholdeth the righteous.","words":[["H2220","For the arms",0,12],["H7563","of the wicked",13,26],["H7665","shall be broken",27,42],["H3068","but the LORD",44,56],["H5564","upholdeth",57,66],["H6662","the righteous",67,80]]},"37:18":{"text":"The LORD knoweth the days of the upright: and their inheritance shall be for ever.","words":[["H3068","The LORD",0,8],["H3045","knoweth",9,16],["H3117","the days",17,25],["H8549","of the upright",26,40],["H5159","and their inheritance",42,63],["H5769","shall be for ever",64,81]]},"37:19":{"text":"They shall not be ashamed in the evil time: and in the days of famine they shall be satisfied.","words":[["H0954","They shall not be ashamed",0,25],["H7451","in the evil",26,37],["H6256","time",38,42],["H3117","and in the days",44,59],["H7459","of famine",60,69],["H7646","they shall be satisfied",70,93]]},"37:20":{"text":"But the wicked shall perish, and the enemies of the LORD shall be as the fat of lambs: they shall consume; into smoke shall they consume away.","words":[["H7563","But the wicked",0,14],["H0006","shall perish",15,27],["H0341","and the enemies",29,44],["H3068","of the LORD",45,56],["H3368","shall be as the fat",57,76],["H3733","of lambs",77,85],["H3615","they shall consume",87,105],["H6227","into smoke",107,117],["H3615","shall they consume away",118,141]]},"37:21":{"text":"The wicked borroweth, and payeth not again: but the righteous sheweth mercy, and giveth.","words":[["H7563","The wicked",0,10],["H3867","borroweth",11,20],["H7999","and payeth not again",22,42],["H6662","but the righteous",44,61],["H2603","sheweth mercy",62,75],["H5414","and giveth",77,87]]},"37:22":{"text":"For such as be blessed of him shall inherit the earth; and they that be cursed of him shall be cut off.","words":[["H1288","For such as be blessed",0,22],["H3423","of him shall inherit",23,43],["H0776","the earth",44,53],["H7043","and they that be cursed",55,78],["H3772","of him shall be cut off",79,102]]},"37:23":{"text":"The steps of a good man are ordered by the LORD: and he delighteth in his way.","words":[["H4703","The steps",0,9],["H1397","of a good man",10,23],["H3559","are ordered",24,35],["H3068","by the LORD",36,47],["H2654","and he delighteth",49,66],["H1870","in his way",67,77]]},"37:24":{"text":"Though he fall, he shall not be utterly cast down: for the LORD upholdeth him with his hand.","words":[["H5307","Though he fall",0,14],["H2904","he shall not be utterly cast down",16,49],["H3068","for the LORD",51,63],["H5564","upholdeth",64,73],["H3027","him with his hand",74,91]]},"37:25":{"text":"I have been young, and now am old; yet have I not seen the righteous forsaken, nor his seed begging bread.","words":[["H5288","I have been young",0,17],["H2204","and now am old",19,33],["H7200","yet have I not seen",35,54],["H6662","the righteous",55,68],["H5800","forsaken",69,77],["H2233","nor his seed",79,91],["H1245","begging",92,99],["H3899","bread",100,105]]},"37:26":{"text":"He is ever merciful, and lendeth; and his seed is blessed.","words":[["H3117","He is ever",0,10],["H2603","merciful",11,19],["H3867","and lendeth",21,32],["H2233","and his seed",34,46],["H1293","is blessed",47,57]]},"37:27":{"text":"Depart from evil, and do good; and dwell for evermore.","words":[["H5493","Depart",0,6],["H7451","from evil",7,16],["H6213","and do",18,24],["H2896","good",25,29],["H7931","and dwell",31,40],["H5769","for evermore",41,53]]},"37:28":{"text":"For the LORD loveth judgment, and forsaketh not his saints; they are preserved for ever: but the seed of the wicked shall be cut off.","words":[["H3068","For the LORD",0,12],["H0157","loveth",13,19],["H4941","judgment",20,28],["H5800","and forsaketh",30,43],["H2623","not his saints",44,58],["H8104","they are preserved",60,78],["H5769","for ever",79,87],["H2233","but the seed",89,101],["H7563","of the wicked",102,115],["H3772","shall be cut off",116,132]]},"37:29":{"text":"The righteous shall inherit the land, and dwell therein for ever.","words":[["H6662","The righteous",0,13],["H3423","shall inherit",14,27],["H0776","the land",28,36],["H7931","and dwell",38,47],["H5703","therein for ever",48,64]]},"37:30":{"text":"The mouth of the righteous speaketh wisdom, and his tongue talketh of judgment.","words":[["H6310","The mouth",0,9],["H6662","of the righteous",10,26],["H1897","speaketh",27,35],["H2451","wisdom",36,42],["H3956","and his tongue",44,58],["H1696","talketh",59,66],["H4941","of judgment",67,78]]},"37:31":{"text":"The law of his God is in his heart; none of his steps shall slide.","words":[["H8451","The law",0,7],["H0430","of his God",8,18],["H3820","is in his heart",19,34],["H0838","none of his steps",36,53],["H4571","shall slide",54,65]]},"37:32":{"text":"The wicked watcheth the righteous, and seeketh to slay him.","words":[["H7563","The wicked",0,10],["H6822","watcheth",11,19],["H6662","the righteous",20,33],["H1245","and seeketh",35,46],["H4191","to slay",47,54]]},"37:33":{"text":"The LORD will not leave him in his hand, nor condemn him when he is judged.","words":[["H3068","The LORD",0,8],["H5800","will not leave",9,23],["H3027","him in his hand",24,39],["H7561","nor condemn",41,52],["H8199","him when he is judged",53,74]]},"37:34":{"text":"Wait on the LORD, and keep his way, and he shall exalt thee to inherit the land: when the wicked are cut off, thou shalt see it.","words":[["H6960","Wait",0,4],["H3068","on the LORD",5,16],["H8104","and keep",18,26],["H1870","his way",27,34],["H7311","and he shall exalt",36,54],["H3423","thee to inherit",55,70],["H0776","the land",71,79],["H7563","when the wicked",81,96],["H3772","are cut off",97,108],["H7200","thou shalt see",110,124]]},"37:35":{"text":"I have seen the wicked in great power, and spreading himself like a green bay tree.","words":[["H7200","I have seen",0,11],["H7563","the wicked",12,22],["H6184","in great power",23,37],["H6168","and spreading",39,52],["H7488","himself like a green",53,73],["H0249","bay tree",74,82]]},"37:36":{"text":"Yet he passed away, and, lo, he was not: yea, I sought him, but he could not be found.","words":[["H5674","Yet he passed away",0,18],["H1245","and, lo, he was not: yea, I sought",20,54],["H4672","him, but he could not be found",55,85]]},"37:37":{"text":"Mark the perfect man, and behold the upright: for the end of that man is peace.","words":[["H8104","Mark",0,4],["H8535","the perfect",5,16],["H7200","man, and behold",17,32],["H3477","the upright",33,44],["H0319","for the end",46,57],["H0376","of that man",58,69],["H7965","is peace",70,78]]},"37:38":{"text":"But the transgressors shall be destroyed together: the end of the wicked shall be cut off.","words":[["H6586","But the transgressors",0,21],["H8045","shall be destroyed",22,40],["H3162","together",41,49],["H0319","the end",51,58],["H7563","of the wicked",59,72],["H3772","shall be cut off",73,89]]},"37:39":{"text":"But the salvation of the righteous is of the LORD: he is their strength in the time of trouble.","words":[["H8668","But the salvation",0,17],["H6662","of the righteous",18,34],["H3068","is of the LORD",35,49],["H4581","he is their strength",51,71],["H6256","in the time",72,83],["H6869","of trouble",84,94]]},"37:40":{"text":"And the LORD shall help them, and deliver them: he shall deliver them from the wicked, and save them, because they trust in him.","words":[["H3068","And the LORD",0,12],["H5826","shall help",13,23],["H6403","them, and deliver",24,41],["H6403","them: he shall deliver",42,64],["H7563","them from the wicked",65,85],["H3467","and save",87,95],["H2620","them, because they trust",96,120]]},"38:1":{"text":"A Psalm of David, to bring to remembrance. O LORD, rebuke me not in thy wrath: neither chasten me in thy hot displeasure.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H2142","to bring to remembrance",18,41],["H3068","O LORD",43,49],["H3198","rebuke",51,57],["H7110","me not in thy wrath",58,77],["H3256","neither chasten",79,94],["H2534","me in thy hot displeasure",95,120]]},"38:2":{"text":"For thine arrows stick fast in me, and thy hand presseth me sore.","words":[["H2671","For thine arrows",0,16],["H5181","stick fast",17,27],["H3027","in me, and thy hand",28,47],["H5181","presseth me sore",48,64]]},"38:3":{"text":"There is no soundness in my flesh because of thine anger; neither is there any rest in my bones because of my sin.","words":[["H4974","There is no soundness",0,21],["H1320","in my flesh",22,33],["H6440","because",34,41],["H2195","of thine anger",42,56],["H7965","neither is there any rest",58,83],["H6106","in my bones",84,95],["H6440","because",96,103],["H2403","of my sin",104,113]]},"38:4":{"text":"For mine iniquities are gone over mine head: as an heavy burden they are too heavy for me.","words":[["H5771","For mine iniquities",0,19],["H5674","are gone over",20,33],["H7218","mine head",34,43],["H3515","as an heavy",45,56],["H4853","burden",57,63],["H3513","they are too heavy",64,82]]},"38:5":{"text":"My wounds stink and are corrupt because of my foolishness.","words":[["H2250","My wounds",0,9],["H0887","stink",10,15],["H4743","and are corrupt",16,31],["H6440","because",32,39],["H0200","of my foolishness",40,57]]},"38:6":{"text":"I am troubled; I am bowed down greatly; I go mourning all the day long.","words":[["H5753","I am troubled",0,13],["H7817","I am bowed down",15,30],["H3966","greatly",31,38],["H1980","I go",40,44],["H6937","mourning",45,53],["H3117","all the day",54,65]]},"38:7":{"text":"For my loins are filled with a loathsome disease: and there is no soundness in my flesh.","words":[["H3689","For my loins",0,12],["H4390","are filled",13,23],["H7033","with a loathsome",24,40],["H4974","disease: and there is no soundness",41,75],["H1320","in my flesh",76,87]]},"38:8":{"text":"I am feeble and sore broken: I have roared by reason of the disquietness of my heart.","words":[["H6313","I am feeble",0,11],["H3966","and sore",12,20],["H1794","broken",21,27],["H7580","I have roared",29,42],["H5100","by reason of the disquietness",43,72],["H3820","of my heart",73,84]]},"38:9":{"text":"Lord, all my desire is before thee; and my groaning is not hid from thee.","words":[["H0136","Lord",0,4],["H8378","all my desire",6,19],["H0585","is before thee; and my groaning",20,51],["H5641","is not hid",52,62]]},"38:10":{"text":"My heart panteth, my strength faileth me: as for the light of mine eyes, it also is gone from me.","words":[["H3820","My heart",0,8],["H5503","panteth",9,16],["H3581","my strength",18,29],["H5800","faileth",30,37],["H0216","me: as for the light",38,58],["H5869","of mine eyes",59,71],["H1992","it",73,75],["H0369","also is gone",76,88]]},"38:11":{"text":"My lovers and my friends stand aloof from my sore; and my kinsmen stand afar off.","words":[["H0157","My lovers",0,9],["H7453","and my friends",10,24],["H5975","stand",25,30],["H5048","aloof from",31,41],["H5061","my sore",42,49],["H7138","and my kinsmen",51,65],["H5975","stand",66,71],["H7350","afar off",72,80]]},"38:12":{"text":"They also that seek after my life lay snares for me: and they that seek my hurt speak mischievous things, and imagine deceits all the day long.","words":[["H1245","They also that seek",0,19],["H5315","after my life",20,33],["H5367","lay snares",34,44],["H1875","for me: and they that seek",45,71],["H7451","my hurt",72,79],["H1696","speak",80,85],["H1942","mischievous things",86,104],["H1897","and imagine",106,117],["H4820","deceits",118,125],["H3117","all the day",126,137]]},"38:13":{"text":"But I, as a deaf man, heard not; and I was as a dumb man that openeth not his mouth.","words":[["H2795","But I, as a deaf",0,16],["H8085","man, heard",17,27],["H0483","not; and I was as a dumb man",28,56],["H6605","that openeth",57,69],["H6310","not his mouth",70,83]]},"38:14":{"text":"Thus I was as a man that heareth not, and in whose mouth are no reproofs.","words":[["H0376","Thus I was as a man",0,19],["H8085","that heareth",20,32],["H6310","not, and in whose mouth",33,56],["H8433","are no reproofs",57,72]]},"38:15":{"text":"For in thee, O LORD, do I hope: thou wilt hear, O Lord my God.","words":[["H3068","For in thee, O LORD",0,19],["H3176","do I hope",21,30],["H6030","thou wilt hear",32,46],["H0136","O Lord",48,54],["H0430","my God",55,61]]},"38:16":{"text":"For I said, Hear me, lest otherwise they should rejoice over me: when my foot slippeth, they magnify themselves against me.","words":[["H0559","For I said",0,10],["H8055","Hear me, lest otherwise they should rejoice",12,55],["H7272","over me: when my foot",56,77],["H4131","slippeth",78,86],["H1431","they magnify",88,100]]},"38:17":{"text":"For I am ready to halt, and my sorrow is continually before me.","words":[["H3559","For I am ready",0,14],["H6761","to halt",15,22],["H4341","and my sorrow",24,37],["H8548","is continually",38,52]]},"38:18":{"text":"For I will declare mine iniquity; I will be sorry for my sin.","words":[["H5046","For I will declare",0,18],["H5771","mine iniquity",19,32],["H1672","I will be sorry",34,49],["H2403","for my sin",50,60]]},"38:19":{"text":"But mine enemies are lively, and they are strong: and they that hate me wrongfully are multiplied.","words":[["H0341","But mine enemies",0,16],["H2416","are lively",17,27],["H6105","and they are strong",29,48],["H8130","and they that hate",50,68],["H8267","me wrongfully",69,82],["H7231","are multiplied",83,97]]},"38:20":{"text":"They also that render evil for good are mine adversaries; because I follow the thing that good is.","words":[["H7999","They also that render",0,21],["H7451","evil",22,26],["H2896","for good",27,35],["H7853","are mine adversaries",36,56],["H7291","because I follow",58,74],["H2896","the thing that good",75,94]]},"38:21":{"text":"Forsake me not, O LORD: O my God, be not far from me.","words":[["H5800","Forsake",0,7],["H3068","me not, O LORD",8,22],["H0430","O my God",24,32],["H7368","be not far",34,44]]},"38:22":{"text":"Make haste to help me, O Lord my salvation.","words":[["H2363","Make haste",0,10],["H5833","to help",11,18],["H0136","me, O Lord",19,29],["H8668","my salvation",30,42]]},"39:1":{"text":"To the chief Musician, even to Jeduthun, A Psalm of David. I said, I will take heed to my ways, that I sin not with my tongue: I will keep my mouth with a bridle, while the wicked is before me.","words":[["H5329","To the chief Musician",0,21],["H3038","even to Jeduthun",23,39],["H4210","A Psalm",41,48],["H1732","of David",49,57],["H0559","I said",59,65],["H8104","I will take heed",67,83],["H1870","to my ways",84,94],["H2398","that I sin",96,106],["H3956","not with my tongue",107,125],["H8104","I will keep",127,138],["H6310","my mouth",139,147],["H4269","with a bridle",148,161],["H7563","while the wicked",163,179]]},"39:2":{"text":"I was dumb with silence, I held my peace, even from good; and my sorrow was stirred.","words":[["H0481","I was dumb",0,10],["H1747","with silence",11,23],["H2814","I held my peace",25,40],["H2896","even from good",42,56],["H3511","and my sorrow",58,71],["H5916","was stirred",72,83]]},"39:3":{"text":"My heart was hot within me, while I was musing the fire burned: then spake I with my tongue,","words":[["H3820","My heart",0,8],["H2552","was hot",9,16],["H7130","within",17,23],["H1901","me, while I was musing",24,46],["H0784","the fire",47,55],["H1197","burned",56,62],["H0227","then",64,68],["H1696","spake",69,74],["H3956","I with my tongue",75,91]]},"39:4":{"text":"LORD, make me to know mine end, and the measure of my days, what it is; that I may know how frail I am.","words":[["H3068","LORD",0,4],["H3045","make me to know",6,21],["H7093","mine end",22,30],["H4060","and the measure",32,47],["H3117","of my days",48,58],["H3045","what it is; that I may know",60,87],["H2310","how frail",88,97]]},"39:5":{"text":"Behold, thou hast made my days as an handbreadth; and mine age is as nothing before thee: verily every man at his best state is altogether vanity. Selah.","words":[["H5414","Behold, thou hast made",0,22],["H3117","my days",23,30],["H2947","as an handbreadth",31,48],["H2465","and mine age",50,62],["H3605","is as nothing before thee: verily every",63,102],["H0120","man",103,106],["H5324","at his best state",107,124],["H3605","is altogether",125,138],["H1892","vanity",139,145],["H5542","Selah",147,152]]},"39:6":{"text":"Surely every man walketh in a vain shew: surely they are disquieted in vain: he heapeth up riches, and knoweth not who shall gather them.","words":[["H0376","Surely every man",0,16],["H1980","walketh",17,24],["H6754","in a vain shew",25,39],["H1993","surely they are disquieted",41,67],["H1892","in vain",68,75],["H6651","he heapeth up",77,90],["H3045","riches, and knoweth",91,110],["H0622","not who shall gather",111,131]]},"39:7":{"text":"And now, Lord, what wait I for? my hope is in thee.","words":[["H0136","And now, Lord",0,13],["H6960","what wait",15,24],["H8431","I for? my hope",25,39]]},"39:8":{"text":"Deliver me from all my transgressions: make me not the reproach of the foolish.","words":[["H5337","Deliver",0,7],["H6588","me from all my transgressions",8,37],["H7760","make",39,43],["H2781","me not the reproach",44,63],["H5036","of the foolish",64,78]]},"39:9":{"text":"I was dumb, I opened not my mouth; because thou didst it.","words":[["H0481","I was dumb",0,10],["H6605","I opened",12,20],["H6310","not my mouth",21,33],["H6213","because thou didst",35,53]]},"39:10":{"text":"Remove thy stroke away from me: I am consumed by the blow of thine hand.","words":[["H5493","Remove",0,6],["H5061","thy stroke",7,17],["H5493","away",18,22],["H3615","from me: I am consumed",23,45],["H8409","by the blow",46,57],["H3027","of thine hand",58,71]]},"39:11":{"text":"When thou with rebukes dost correct man for iniquity, thou makest his beauty to consume away like a moth: surely every man is vanity. Selah.","words":[["H8433","When thou with rebukes",0,22],["H3256","dost correct",23,35],["H0376","man",36,39],["H5771","for iniquity",40,52],["H2530","thou makest his beauty",54,76],["H4529","to consume away",77,92],["H6211","like a moth",93,104],["H0120","surely every man",106,122],["H1892","is vanity",123,132],["H5542","Selah",134,139]]},"39:12":{"text":"Hear my prayer, O LORD, and give ear unto my cry; hold not thy peace at my tears: for I am a stranger with thee, and a sojourner, as all my fathers were.","words":[["H8085","Hear",0,4],["H8605","my prayer",5,14],["H3068","O LORD",16,22],["H0238","and give ear",24,36],["H7775","unto my cry",37,48],["H2790","hold not thy peace",50,68],["H1832","at my tears",69,80],["H1616","for I am a stranger",82,101],["H8453","with thee, and a sojourner",102,128],["H0001","as all my fathers",130,147]]},"39:13":{"text":"O spare me, that I may recover strength, before I go hence, and be no more.","words":[["H8159","O spare",0,7],["H1082","me, that I may recover strength",8,39],["H3212","before I go hence",41,58]]},"40:1":{"text":"To the chief Musician, A Psalm of David. I waited patiently for the LORD; and he inclined unto me, and heard my cry.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H6960","I waited",41,49],["H6960","patiently",50,59],["H3068","for the LORD",60,72],["H5186","and he inclined",74,89],["H8085","unto me, and heard",90,108],["H7775","my cry",109,115]]},"40:2":{"text":"He brought me up also out of an horrible pit, out of the miry clay, and set my feet upon a rock, and established my goings.","words":[["H5927","He brought me up",0,16],["H7588","also out of an horrible",17,40],["H0953","pit",41,44],["H3121","out of the miry",46,61],["H2916","clay",62,66],["H6965","and set",68,75],["H7272","my feet",76,83],["H5553","upon a rock",84,95],["H3559","and established",97,112],["H0838","my goings",113,122]]},"40:3":{"text":"And he hath put a new song in my mouth, even praise unto our God: many shall see it, and fear, and shall trust in the LORD.","words":[["H5414","And he hath put",0,15],["H2319","a new",16,21],["H7892","song",22,26],["H6310","in my mouth",27,38],["H8416","even praise",40,51],["H0430","unto our God",52,64],["H7227","many",66,70],["H7200","shall see",71,80],["H3372","it, and fear",81,93],["H0982","and shall trust",95,110],["H3068","in the LORD",111,122]]},"40:4":{"text":"Blessed is that man that maketh the LORD his trust, and respecteth not the proud, nor such as turn aside to lies.","words":[["H0835","Blessed",0,7],["H1397","is that man",8,19],["H7760","that maketh",20,31],["H3068","the LORD",32,40],["H4009","his trust",41,50],["H6437","and respecteth",52,66],["H7295","not the proud",67,80],["H7750","nor such as turn aside",82,104],["H3577","to lies",105,112]]},"40:5":{"text":"Many, O LORD my God, are thy wonderful works which thou hast done, and thy thoughts which are to us-ward: they cannot be reckoned up in order unto thee: if I would declare and speak of them, they are more than can be numbered.","words":[["H7227","Many",0,4],["H3068","O LORD",6,12],["H0430","my God",13,19],["H6381","are thy wonderful",21,38],["H6213","works which thou hast done",39,65],["H4284","and thy thoughts",67,83],["H6186","which are to us-ward: they cannot be reckoned up in order",84,141],["H5046","unto thee: if I would declare",142,171],["H1696","and speak",172,181],["H6105","of them, they are more",182,204],["H5608","than can be numbered",205,225]]},"40:6":{"text":"Sacrifice and offering thou didst not desire; mine ears hast thou opened: burnt offering and sin offering hast thou not required.","words":[["H2077","Sacrifice",0,9],["H4503","and offering",10,22],["H2654","thou didst not desire",23,44],["H0241","mine ears",46,55],["H3738","hast thou opened",56,72],["H5930","burnt offering",74,88],["H2401","and sin offering",89,105],["H7592","hast thou not required",106,128]]},"40:7":{"text":"Then said I, Lo, I come: in the volume of the book it is written of me,","words":[["H0559","Then said",0,9],["H0935","I, Lo, I come",10,23],["H4039","in the volume",25,38],["H5612","of the book",39,50],["H3789","it is written",51,64]]},"40:8":{"text":"I delight to do thy will, O my God: yea, thy law is within my heart.","words":[["H2654","I delight",0,9],["H6213","to do",10,15],["H7522","thy will",16,24],["H0430","O my God",26,34],["H8451","yea, thy law",36,48],["H8432","is within",49,58],["H4578","my heart",59,67]]},"40:9":{"text":"I have preached righteousness in the great congregation: lo, I have not refrained my lips, O LORD, thou knowest.","words":[["H1319","I have preached",0,15],["H6664","righteousness",16,29],["H7227","in the great",30,42],["H6951","congregation",43,55],["H3607","lo, I have not refrained",57,81],["H8193","my lips",82,89],["H3068","O LORD",91,97],["H3045","thou knowest",99,111]]},"40:10":{"text":"I have not hid thy righteousness within my heart; I have declared thy faithfulness and thy salvation: I have not concealed thy lovingkindness and thy truth from the great congregation.","words":[["H3680","I have not hid",0,14],["H6666","thy righteousness",15,32],["H8432","within",33,39],["H3820","my heart",40,48],["H0559","I have declared",50,65],["H0530","thy faithfulness",66,82],["H8668","and thy salvation",83,100],["H3582","I have not concealed",102,122],["H2617","thy lovingkindness",123,141],["H0571","and thy truth",142,155],["H7227","from the great",156,170],["H6951","congregation",171,183]]},"40:11":{"text":"Withhold not thou thy tender mercies from me, O LORD: let thy lovingkindness and thy truth continually preserve me.","words":[["H3607","Withhold",0,8],["H7356","not thou thy tender mercies",9,36],["H3068","from me, O LORD",37,52],["H2617","let thy lovingkindness",54,76],["H0571","and thy truth",77,90],["H8548","continually",91,102],["H5341","preserve",103,111]]},"40:12":{"text":"For innumerable evils have compassed me about: mine iniquities have taken hold upon me, so that I am not able to look up; they are more than the hairs of mine head: therefore my heart faileth me.","words":[["H4557","For innumerable",0,15],["H7451","evils",16,21],["H0661","have compassed",22,36],["H5771","me about: mine iniquities",37,62],["H5381","have taken hold",63,78],["H3201","upon me, so that I am not able",79,109],["H7200","to look up",110,120],["H6105","they are more",122,135],["H8185","than the hairs",136,150],["H7218","of mine head",151,163],["H3820","therefore my heart",165,183],["H5800","faileth",184,191]]},"40:13":{"text":"Be pleased, O LORD, to deliver me: O LORD, make haste to help me.","words":[["H7521","Be pleased",0,10],["H3068","O LORD",12,18],["H5337","to deliver",20,30],["H3068","me: O LORD",31,41],["H2363","make haste",43,53],["H5833","to help",54,61]]},"40:14":{"text":"Let them be ashamed and confounded together that seek after my soul to destroy it; let them be driven backward and put to shame that wish me evil.","words":[["H0954","Let them be ashamed",0,19],["H2659","and confounded",20,34],["H3162","together",35,43],["H1245","that seek",44,53],["H5315","after my soul",54,67],["H5595","to destroy",68,78],["H5472","it; let them be driven",79,101],["H0268","backward",102,110],["H3637","and put to shame",111,127],["H2655","that wish",128,137],["H7451","me evil",138,145]]},"40:15":{"text":"Let them be desolate for a reward of their shame that say unto me, Aha, aha.","words":[["H8074","Let them be desolate",0,20],["H6118","for a reward",21,33],["H1322","of their shame",34,48],["H0559","that say",49,57],["H1889","unto me, Aha",58,70],["H1889","aha",72,75]]},"40:16":{"text":"Let all those that seek thee rejoice and be glad in thee: let such as love thy salvation say continually, The LORD be magnified.","words":[["H1245","Let all those that seek",0,23],["H7797","thee rejoice",24,36],["H8055","and be glad",37,48],["H0157","in thee: let such as love",49,74],["H8668","thy salvation",75,88],["H0559","say",89,92],["H8548","continually",93,104],["H3068","The LORD",106,114],["H1431","be magnified",115,127]]},"40:17":{"text":"But I am poor and needy; yet the Lord thinketh upon me: thou art my help and my deliverer; make no tarrying, O my God.","words":[["H6041","But I am poor",0,13],["H0034","and needy",14,23],["H0136","yet the Lord",25,37],["H2803","thinketh",38,46],["H5833","upon me: thou art my help",47,72],["H6403","and my deliverer",73,89],["H0309","make no tarrying",91,107],["H0430","O my God",109,117]]},"41:1":{"text":"To the chief Musician, A Psalm of David. Blessed is he that considereth the poor: the LORD will deliver him in time of trouble.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H0835","Blessed",41,48],["H7919","is he that considereth",49,71],["H1800","the poor",72,80],["H3068","the LORD",82,90],["H4422","will deliver",91,103],["H3117","him in time",104,115],["H7451","of trouble",116,126]]},"41:2":{"text":"The LORD will preserve him, and keep him alive; and he shall be blessed upon the earth: and thou wilt not deliver him unto the will of his enemies.","words":[["H3068","The LORD",0,8],["H8104","will preserve",9,22],["H2421","him, and keep him alive",23,46],["H0833","and he shall be blessed",48,71],["H0776","upon the earth",72,86],["H5414","and thou wilt not deliver",88,113],["H5315","him unto the will",114,131],["H0341","of his enemies",132,146]]},"41:3":{"text":"The LORD will strengthen him upon the bed of languishing: thou wilt make all his bed in his sickness.","words":[["H3068","The LORD",0,8],["H5582","will strengthen",9,24],["H6210","him upon the bed",25,41],["H1741","of languishing",42,56],["H2015","thou wilt make",58,72],["H4904","all his bed",73,84],["H2483","in his sickness",85,100]]},"41:4":{"text":"I said, LORD, be merciful unto me: heal my soul; for I have sinned against thee.","words":[["H0559","I said",0,6],["H3068","LORD",8,12],["H2603","be merciful",14,25],["H7495","unto me: heal",26,39],["H5315","my soul",40,47],["H2398","for I have sinned",49,66]]},"41:5":{"text":"Mine enemies speak evil of me, When shall he die, and his name perish?","words":[["H0341","Mine enemies",0,12],["H0559","speak",13,18],["H7451","evil",19,23],["H4191","of me, When shall he die",24,48],["H8034","and his name",50,62],["H0006","perish",63,69]]},"41:6":{"text":"And if he come to see me, he speaketh vanity: his heart gathereth iniquity to itself; when he goeth abroad, he telleth it.","words":[["H0935","And if he come",0,14],["H7200","to see",15,21],["H1696","me, he speaketh",22,37],["H7723","vanity",38,44],["H3820","his heart",46,55],["H6908","gathereth",56,65],["H0205","iniquity",66,74],["H3318","to itself; when he goeth",75,99],["H2351","abroad",100,106],["H1696","he telleth",108,118]]},"41:7":{"text":"All that hate me whisper together against me: against me do they devise my hurt.","words":[["H8130","All that hate",0,13],["H3907","me whisper",14,24],["H3162","together",25,33],["H2803","against me: against me do they devise",34,71],["H7451","my hurt",72,79]]},"41:8":{"text":"An evil disease, say they, cleaveth fast unto him: and now that he lieth he shall rise up no more.","words":[["H1100","An evil",0,7],["H1697","disease",8,15],["H3332","say they, cleaveth fast",17,40],["H7901","unto him: and now that he lieth",41,72],["H6965","he shall rise up",73,89],["H3254","no more",90,97]]},"41:9":{"text":"Yea, mine own familiar friend, in whom I trusted, which did eat of my bread, hath lifted up his heel against me.","words":[["H7965","Yea, mine own familiar",0,22],["H0376","friend",23,29],["H0982","in whom I trusted",31,48],["H0398","which did eat",50,63],["H3899","of my bread",64,75],["H1431","hath lifted up",77,91],["H6119","his heel",92,100]]},"41:10":{"text":"But thou, O LORD, be merciful unto me, and raise me up, that I may requite them.","words":[["H3068","But thou, O LORD",0,16],["H2603","be merciful",18,29],["H6965","unto me, and raise me up",30,54],["H7999","that I may requite",56,74]]},"41:11":{"text":"By this I know that thou favourest me, because mine enemy doth not triumph over me.","words":[["H3045","By this I know",0,14],["H2654","that thou favourest",15,34],["H0341","me, because mine enemy",35,57],["H7321","doth not triumph",58,74]]},"41:12":{"text":"And as for me, thou upholdest me in mine integrity, and settest me before thy face for ever.","words":[["H8551","And as for me, thou upholdest",0,29],["H8537","me in mine integrity",30,50],["H5324","and settest",52,63],["H6440","me before thy face",64,82],["H5769","for ever",83,91]]},"41:13":{"text":"Blessed be the LORD God of Israel from everlasting, and to everlasting. Amen, and Amen.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H0430","God",20,23],["H3478","of Israel",24,33],["H5769","from everlasting",34,50],["H5769","and to everlasting",52,70],["H0543","Amen",72,76],["H0543","and Amen",78,86]]},"42:1":{"text":"To the chief Musician, Maschil, for the sons of Korah. As the hart panteth after the water brooks, so panteth my soul after thee, O God.","words":[["H5329","To the chief Musician",0,21],["H4905","Maschil",23,30],["H1121","for the sons",32,44],["H7141","of Korah",45,53],["H0354","As the hart",55,66],["H6165","panteth",67,74],["H4325","after the water",75,90],["H0650","brooks",91,97],["H6165","so panteth",99,109],["H5315","my soul",110,117],["H0430","after thee, O God",118,135]]},"42:2":{"text":"My soul thirsteth for God, for the living God: when shall I come and appear before God?","words":[["H5315","My soul",0,7],["H6770","thirsteth",8,17],["H0430","for God",18,25],["H2416","for the living",27,41],["H0410","God",42,45],["H0935","when shall I come",47,64],["H7200","and appear",65,75],["H6440","before",76,82],["H0430","God",83,86]]},"42:3":{"text":"My tears have been my meat day and night, while they continually say unto me, Where is thy God?","words":[["H1832","My tears",0,8],["H3899","have been my meat",9,26],["H3119","day",27,30],["H3915","and night",31,40],["H3117","while they continually",42,64],["H0559","say",65,68],["H0430","unto me, Where is thy God",69,94]]},"42:4":{"text":"When I remember these things, I pour out my soul in me: for I had gone with the multitude, I went with them to the house of God, with the voice of joy and praise, with a multitude that kept holyday.","words":[["H2142","When I remember",0,15],["H8210","these things, I pour out",16,40],["H5315","my soul",41,48],["H5674","in me: for I had gone",49,70],["H5519","with the multitude",71,89],["H1718","I went",91,97],["H1004","with them to the house",98,120],["H0430","of God",121,127],["H6963","with the voice",129,143],["H7440","of joy",144,150],["H8426","and praise",151,161],["H1995","with a multitude",163,179],["H2287","that kept holyday",180,197]]},"42:5":{"text":"Why art thou cast down, O my soul? and why art thou disquieted in me? hope thou in God: for I shall yet praise him for the help of his countenance.","words":[["H7817","Why art thou cast down",0,22],["H5315","O my soul",24,33],["H1993","and why art thou disquieted",35,62],["H3176","in me? hope",63,74],["H0430","thou in God",75,86],["H3034","for I shall yet praise",88,110],["H3444","him for the help",111,127],["H6440","of his countenance",128,146]]},"42:6":{"text":"O my God, my soul is cast down within me: therefore will I remember thee from the land of Jordan, and of the Hermonites, from the hill Mizar.","words":[["H0430","O my God",0,8],["H5315","my soul",10,17],["H7817","is cast down",18,30],["H2142","within me: therefore will I remember",31,67],["H0776","thee from the land",68,86],["H3383","of Jordan",87,96],["H2769","and of the Hermonites",98,119],["H2022","from the hill",121,134],["H4706","Mizar",135,140]]},"42:7":{"text":"Deep calleth unto deep at the noise of thy waterspouts: all thy waves and thy billows are gone over me.","words":[["H8415","Deep",0,4],["H7121","calleth",5,12],["H8415","unto deep",13,22],["H6963","at the noise",23,35],["H6794","of thy waterspouts",36,54],["H4867","all thy waves",56,69],["H1530","and thy billows",70,85],["H5674","are gone",86,94]]},"42:8":{"text":"Yet the LORD will command his lovingkindness in the daytime, and in the night his song shall be with me, and my prayer unto the God of my life.","words":[["H3068","Yet the LORD",0,12],["H6680","will command",13,25],["H2617","his lovingkindness",26,44],["H3119","in the daytime",45,59],["H3915","and in the night",61,77],["H7892","his song",78,86],["H8605","shall be with me, and my prayer",87,118],["H0410","unto the God",119,131],["H2416","of my life",132,142]]},"42:9":{"text":"I will say unto God my rock, Why hast thou forgotten me? why go I mourning because of the oppression of the enemy?","words":[["H0559","I will say",0,10],["H0410","unto God",11,19],["H5553","my rock",20,27],["H7911","Why hast thou forgotten",29,52],["H3212","me? why go",53,63],["H6937","I mourning",64,74],["H3906","because of the oppression",75,100],["H0341","of the enemy",101,113]]},"42:10":{"text":"As with a sword in my bones, mine enemies reproach me; while they say daily unto me, Where is thy God?","words":[["H7524","As with a sword",0,15],["H6106","in my bones",16,27],["H6887","mine enemies",29,41],["H2778","reproach",42,50],["H0559","me; while they say",51,69],["H3117","daily",70,75],["H0430","unto me, Where is thy God",76,101]]},"42:11":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope thou in God: for I shall yet praise him, who is the health of my countenance, and my God.","words":[["H7817","Why art thou cast down",0,22],["H5315","O my soul",24,33],["H1993","and why art thou disquieted",35,62],["H3176","within me? hope",63,78],["H0430","thou in God",79,90],["H3034","for I shall yet praise",92,114],["H3444","him, who is the health",115,137],["H6440","of my countenance",138,155],["H0430","and my God",157,167]]},"43:1":{"text":"Judge me, O God, and plead my cause against an ungodly nation: O deliver me from the deceitful and unjust man.","words":[["H8199","Judge",0,5],["H0430","me, O God",6,15],["H7378","and plead",17,26],["H7379","my cause",27,35],["H3808","against an ungodly",36,54],["H2623","against an ungodly",36,54],["H1471","nation",55,61],["H6403","O deliver",63,72],["H4820","me from the deceitful",73,94],["H5766","and unjust",95,105],["H0376","man",106,109]]},"43:2":{"text":"For thou art the God of my strength: why dost thou cast me off? why go I mourning because of the oppression of the enemy?","words":[["H0430","For thou art the God",0,20],["H4581","of my strength",21,35],["H2186","why dost thou cast me off",37,62],["H1980","why go",64,70],["H6937","I mourning",71,81],["H3906","because of the oppression",82,107],["H0341","of the enemy",108,120]]},"43:3":{"text":"O send out thy light and thy truth: let them lead me; let them bring me unto thy holy hill, and to thy tabernacles.","words":[["H7971","O send out",0,10],["H0216","thy light",11,20],["H0571","and thy truth",21,34],["H5148","let them lead",36,49],["H0935","me; let them bring",50,68],["H6944","me unto thy holy",69,85],["H2022","hill",86,90],["H4908","and to thy tabernacles",92,114]]},"43:4":{"text":"Then will I go unto the altar of God, unto God my exceeding joy: yea, upon the harp will I praise thee, O God my God.","words":[["H0935","Then will I go",0,14],["H4196","unto the altar",15,29],["H0430","of God",30,36],["H0410","unto God",38,46],["H8057","my exceeding",47,59],["H1524","joy",60,63],["H3658","yea, upon the harp",65,83],["H3034","will I praise",84,97],["H0430","thee, O God",98,109],["H0430","my God",110,116]]},"43:5":{"text":"Why art thou cast down, O my soul? and why art thou disquieted within me? hope in God: for I shall yet praise him, who is the health of my countenance, and my God.","words":[["H7817","Why art thou cast down",0,22],["H5315","O my soul",24,33],["H1993","and why art thou disquieted",35,62],["H3176","within me? hope",63,78],["H0430","in God",79,85],["H3034","for I shall yet praise",87,109],["H3444","him, who is the health",110,132],["H6440","of my countenance",133,150],["H0430","and my God",152,162]]},"44:1":{"text":"To the chief Musician for the sons of Korah, Maschil. We have heard with our ears, O God, our fathers have told us, what work thou didst in their days, in the times of old.","words":[["H5329","To the chief Musician",0,21],["H1121","for the sons",22,34],["H7141","of Korah",35,43],["H4905","Maschil",45,52],["H8085","We have heard",54,67],["H0241","with our ears",68,81],["H0430","O God",83,88],["H0001","our fathers",90,101],["H5608","have told",102,111],["H6467","us, what work",112,125],["H6466","thou didst",126,136],["H3117","in their days",137,150],["H3117","in the times",152,164],["H6924","of old",165,171]]},"44:2":{"text":"How thou didst drive out the heathen with thy hand, and plantedst them; how thou didst afflict the people, and cast them out.","words":[["H3423","How thou didst drive out",0,24],["H1471","the heathen",25,36],["H3027","with thy hand",37,50],["H5193","and plantedst",52,65],["H7489","them; how thou didst afflict",66,94],["H3816","the people",95,105],["H7971","and cast them out",107,124]]},"44:3":{"text":"For they got not the land in possession by their own sword, neither did their own arm save them: but thy right hand, and thine arm, and the light of thy countenance, because thou hadst a favour unto them.","words":[["H3423","For they got",0,12],["H0776","not the land",13,25],["H3423","in possession",26,39],["H2719","by their own sword",40,58],["H2220","neither did their own arm",60,85],["H3467","save",86,90],["H3225","them: but thy right hand",91,115],["H2220","and thine arm",117,130],["H0216","and the light",132,145],["H6440","of thy countenance",146,164],["H7521","because thou hadst a favour",166,193]]},"44:4":{"text":"Thou art my King, O God: command deliverances for Jacob.","words":[["H4428","Thou art my King",0,16],["H0430","O God",18,23],["H6680","command",25,32],["H3444","deliverances",33,45],["H3290","for Jacob",46,55]]},"44:5":{"text":"Through thee will we push down our enemies: through thy name will we tread them under that rise up against us.","words":[["H5055","Through thee will we push down",0,30],["H6862","our enemies",31,42],["H8034","through thy name",44,60],["H0947","will we tread them under",61,85],["H6965","that rise up",86,98]]},"44:6":{"text":"For I will not trust in my bow, neither shall my sword save me.","words":[["H0982","For I will not trust",0,20],["H7198","in my bow",21,30],["H2719","neither shall my sword",32,54],["H3467","save",55,59]]},"44:7":{"text":"But thou hast saved us from our enemies, and hast put them to shame that hated us.","words":[["H3467","But thou hast saved",0,19],["H6862","us from our enemies",20,39],["H0954","and hast put them to shame",41,67],["H8130","that hated",68,78]]},"44:8":{"text":"In God we boast all the day long, and praise thy name for ever. Selah.","words":[["H0430","In God",0,6],["H1984","we boast",7,15],["H3117","all the day",16,27],["H3034","long, and praise",28,44],["H8034","thy name",45,53],["H5769","for ever",54,62],["H5542","Selah",64,69]]},"44:9":{"text":"But thou hast cast off, and put us to shame; and goest not forth with our armies.","words":[["H0637","But",0,3],["H2186","thou hast cast off",4,22],["H3637","and put us to shame",24,43],["H3318","and goest not forth",45,64],["H6635","with our armies",65,80]]},"44:10":{"text":"Thou makest us to turn back from the enemy: and they which hate us spoil for themselves.","words":[["H7725","Thou makest us to turn",0,22],["H0268","back",23,27],["H6862","from the enemy",28,42],["H8130","and they which hate",44,63],["H8154","us spoil",64,72]]},"44:11":{"text":"Thou hast given us like sheep appointed for meat; and hast scattered us among the heathen.","words":[["H5414","Thou hast given",0,15],["H6629","us like sheep",16,29],["H3978","appointed for meat",30,48],["H2219","and hast scattered",50,68],["H1471","us among the heathen",69,89]]},"44:12":{"text":"Thou sellest thy people for nought, and dost not increase thy wealth by their price.","words":[["H4376","Thou sellest",0,12],["H5971","thy people",13,23],["H1952","for nought",24,34],["H7235","and dost not increase",36,57],["H4242","thy wealth by their price",58,83]]},"44:13":{"text":"Thou makest us a reproach to our neighbours, a scorn and a derision to them that are round about us.","words":[["H7760","Thou makest",0,11],["H2781","us a reproach",12,25],["H7934","to our neighbours",26,43],["H3933","a scorn",45,52],["H7047","and a derision",53,67],["H5439","to them that are round about",68,96]]},"44:14":{"text":"Thou makest us a byword among the heathen, a shaking of the head among the people.","words":[["H7760","Thou makest",0,11],["H4912","us a byword",12,23],["H1471","among the heathen",24,41],["H4493","a shaking",43,52],["H7218","of the head",53,64],["H3816","among the people",65,81]]},"44:15":{"text":"My confusion is continually before me, and the shame of my face hath covered me,","words":[["H3639","My confusion",0,12],["H3117","is continually",13,27],["H1322","before me, and the shame",28,52],["H6440","of my face",53,63],["H3680","hath covered",64,76]]},"44:16":{"text":"For the voice of him that reproacheth and blasphemeth; by reason of the enemy and avenger.","words":[["H6963","For the voice",0,13],["H2778","of him that reproacheth",14,37],["H1442","and blasphemeth",38,53],["H6440","by reason",55,64],["H0341","of the enemy",65,77],["H5358","and avenger",78,89]]},"44:17":{"text":"All this is come upon us; yet have we not forgotten thee, neither have we dealt falsely in thy covenant.","words":[["H0935","All this is come",0,16],["H7911","upon us; yet have we not forgotten",17,51],["H8266","thee, neither have we dealt falsely",52,87],["H1285","in thy covenant",88,103]]},"44:18":{"text":"Our heart is not turned back, neither have our steps declined from thy way;","words":[["H3820","Our heart",0,9],["H5472","is not turned",10,23],["H0268","back",24,28],["H0838","neither have our steps",30,52],["H5186","declined",53,61],["H0734","from thy way",62,74]]},"44:19":{"text":"Though thou hast sore broken us in the place of dragons, and covered us with the shadow of death.","words":[["H1794","Though thou hast sore broken",0,28],["H4725","us in the place",29,44],["H8577","of dragons",45,55],["H3680","and covered",57,68],["H6757","us with the shadow of death",69,96]]},"44:20":{"text":"If we have forgotten the name of our God, or stretched out our hands to a strange god;","words":[["H7911","If we have forgotten",0,20],["H8034","the name",21,29],["H0430","of our God",30,40],["H6566","or stretched out",42,58],["H3709","our hands",59,68],["H2114","to a strange",69,81],["H0410","god",82,85]]},"44:21":{"text":"Shall not God search this out? for he knoweth the secrets of the heart.","words":[["H0430","Shall not God",0,13],["H2713","search this out",14,29],["H3045","for he knoweth",31,45],["H8587","the secrets",46,57],["H3820","of the heart",58,70]]},"44:22":{"text":"Yea, for thy sake are we killed all the day long; we are counted as sheep for the slaughter.","words":[["H2026","Yea, for thy sake are we killed",0,31],["H3117","all the day",32,43],["H2803","long; we are counted",44,64],["H6629","as sheep",65,73],["H2878","for the slaughter",74,91]]},"44:23":{"text":"Awake, why sleepest thou, O Lord? arise, cast us not off for ever.","words":[["H5782","Awake",0,5],["H3462","why sleepest",7,19],["H0136","thou, O Lord",20,32],["H6974","arise",34,39],["H2186","cast us not off",41,56],["H5331","for ever",57,65]]},"44:24":{"text":"Wherefore hidest thou thy face, and forgettest our affliction and our oppression?","words":[["H5641","Wherefore hidest",0,16],["H6440","thou thy face",17,30],["H7911","and forgettest",32,46],["H6040","our affliction",47,61],["H3906","and our oppression",62,80]]},"44:25":{"text":"For our soul is bowed down to the dust: our belly cleaveth unto the earth.","words":[["H5315","For our soul",0,12],["H7743","is bowed down",13,26],["H6083","to the dust",27,38],["H0990","our belly",40,49],["H1692","cleaveth",50,58],["H0776","unto the earth",59,73]]},"44:26":{"text":"Arise for our help, and redeem us for thy mercies' sake.","words":[["H6965","Arise",0,5],["H5833","for our help",6,18],["H6299","and redeem",20,30],["H2617","us for thy mercies'",31,50]]},"45:1":{"text":"To the chief Musician upon Shoshannim, for the sons of Korah, Maschil, A Song of loves. My heart is inditing a good matter: I speak of the things which I have made touching the king: my tongue is the pen of a ready writer.","words":[["H5329","To the chief Musician",0,21],["H7799","upon Shoshannim",22,37],["H1121","for the sons",39,51],["H7141","of Korah",52,60],["H4905","Maschil",62,69],["H7892","A Song",71,77],["H3039","of loves",78,86],["H3820","My heart",88,96],["H7370","is inditing",97,108],["H2896","a good",109,115],["H1697","matter",116,122],["H0559","I speak",124,131],["H4639","of the things which I have made",132,163],["H4428","touching the king",164,181],["H3956","my tongue",183,192],["H5842","is the pen",193,203],["H4106","of a ready",204,214],["H5608","writer",215,221]]},"45:2":{"text":"Thou art fairer than the children of men: grace is poured into thy lips: therefore God hath blessed thee for ever.","words":[["H3302","Thou art fairer",0,15],["H1121","than the children",16,33],["H0120","of men",34,40],["H2580","grace",42,47],["H3332","is poured",48,57],["H8193","into thy lips",58,71],["H0430","therefore God",73,86],["H1288","hath blessed",87,99],["H5769","thee for ever",100,113]]},"45:3":{"text":"Gird thy sword upon thy thigh, O most mighty, with thy glory and thy majesty.","words":[["H2296","Gird",0,4],["H2719","thy sword",5,14],["H3409","upon thy thigh",15,29],["H1368","O most mighty",31,44],["H1935","with thy glory",46,60],["H1926","and thy majesty",61,76]]},"45:4":{"text":"And in thy majesty ride prosperously because of truth and meekness and righteousness; and thy right hand shall teach thee terrible things.","words":[["H1926","And in thy majesty",0,18],["H7392","ride",19,23],["H6743","prosperously",24,36],["H1697","because",37,44],["H0571","of truth",45,53],["H6037","and meekness",54,66],["H6664","and righteousness",67,84],["H3225","and thy right hand",86,104],["H3384","shall teach",105,116],["H3372","thee terrible things",117,137]]},"45:5":{"text":"Thine arrows are sharp in the heart of the king's enemies; whereby the people fall under thee.","words":[["H2671","Thine arrows",0,12],["H8150","are sharp",13,22],["H3820","in the heart",23,35],["H4428","of the king's",36,49],["H0341","enemies",50,57],["H5971","whereby the people",59,77],["H5307","fall",78,82]]},"45:6":{"text":"Thy throne, O God, is for ever and ever: the sceptre of thy kingdom is a right sceptre.","words":[["H3678","Thy throne",0,10],["H0430","O God",12,17],["H5769","is for ever",19,30],["H5703","and ever",31,39],["H7626","the sceptre",41,52],["H4438","of thy kingdom",53,67],["H4334","is a right",68,78],["H7626","sceptre",79,86]]},"45:7":{"text":"Thou lovest righteousness, and hatest wickedness: therefore God, thy God, hath anointed thee with the oil of gladness above thy fellows.","words":[["H0157","Thou lovest",0,11],["H6664","righteousness",12,25],["H8130","and hatest",27,37],["H7562","wickedness",38,48],["H0430","therefore God",50,63],["H0430","thy God",65,72],["H4886","hath anointed",74,87],["H8081","thee with the oil",88,105],["H8342","of gladness",106,117],["H2270","above thy fellows",118,135]]},"45:8":{"text":"All thy garments smell of myrrh, and aloes, and cassia, out of the ivory palaces, whereby they have made thee glad.","words":[["H0899","All thy garments",0,16],["H4753","smell of myrrh",17,31],["H0174","and aloes",33,42],["H7102","and cassia",44,54],["H8127","out of the ivory",56,72],["H1964","palaces",73,80],["H4482","whereby",82,89],["H8055","they have made thee glad",90,114]]},"45:9":{"text":"Kings' daughters were among thy honourable women: upon thy right hand did stand the queen in gold of Ophir.","words":[["H4428","Kings'",0,6],["H1323","daughters",7,16],["H3368","were among thy honourable women",17,48],["H3225","upon thy right hand",50,69],["H5324","did stand",70,79],["H7694","the queen",80,89],["H3800","in gold",90,97],["H0211","of Ophir",98,106]]},"45:10":{"text":"Hearken, O daughter, and consider, and incline thine ear; forget also thine own people, and thy father's house;","words":[["H8085","Hearken",0,7],["H1323","O daughter",9,19],["H7200","and consider",21,33],["H5186","and incline",35,46],["H0241","thine ear",47,56],["H7911","forget",58,64],["H5971","also thine own people",65,86],["H0001","and thy father's",88,104],["H1004","house",105,110]]},"45:11":{"text":"So shall the king greatly desire thy beauty: for he is thy Lord; and worship thou him.","words":[["H4428","So shall the king",0,17],["H0183","greatly desire",18,32],["H3308","thy beauty",33,43],["H0113","for he is thy Lord",45,63],["H7812","and worship",65,76]]},"45:12":{"text":"And the daughter of Tyre shall be there with a gift; even the rich among the people shall intreat thy favour.","words":[["H1323","And the daughter",0,16],["H6865","of Tyre",17,24],["H4503","shall be there with a gift",25,51],["H6223","even the rich",53,66],["H5971","among the people",67,83],["H2470","shall intreat",84,97],["H6440","thy favour",98,108]]},"45:13":{"text":"The king's daughter is all glorious within: her clothing is of wrought gold.","words":[["H4428","The king's",0,10],["H1323","daughter",11,19],["H3520","is all glorious",20,35],["H6441","within",36,42],["H3830","her clothing",44,56],["H4865","is of wrought",57,70],["H2091","gold",71,75]]},"45:14":{"text":"She shall be brought unto the king in raiment of needlework: the virgins her companions that follow her shall be brought unto thee.","words":[["H2986","She shall be brought",0,20],["H4428","unto the king",21,34],["H7553","in raiment of needlework",35,59],["H1330","the virgins",61,72],["H7464","her companions",73,87],["H0310","that follow",88,99],["H0935","her shall be brought",100,120]]},"45:15":{"text":"With gladness and rejoicing shall they be brought: they shall enter into the king's palace.","words":[["H8057","With gladness",0,13],["H1524","and rejoicing",14,27],["H2986","shall they be brought",28,49],["H0935","they shall enter",51,67],["H4428","into the king's",68,83],["H1964","palace",84,90]]},"45:16":{"text":"Instead of thy fathers shall be thy children, whom thou mayest make princes in all the earth.","words":[["H0001","Instead of thy fathers",0,22],["H1121","shall be thy children",23,44],["H7896","whom thou mayest make",46,67],["H8269","princes",68,75],["H0776","in all the earth",76,92]]},"45:17":{"text":"I will make thy name to be remembered in all generations: therefore shall the people praise thee for ever and ever.","words":[["H8034","I will make thy name",0,20],["H2142","to be remembered",21,37],["H1755","in all",38,44],["H1755","generations",45,56],["H5971","therefore shall the people",58,84],["H3034","praise",85,91],["H5769","thee for ever",92,105],["H5703","and ever",106,114]]},"46:1":{"text":"To the chief Musician for the sons of Korah, A Song upon Alamoth. God is our refuge and strength, a very present help in trouble.","words":[["H5329","To the chief Musician",0,21],["H1121","for the sons",22,34],["H7141","of Korah",35,43],["H7892","A Song",45,51],["H5961","upon Alamoth",52,64],["H0430","God",66,69],["H4268","is our refuge",70,83],["H5797","and strength",84,96],["H3966","a very",98,104],["H4672","present",105,112],["H5833","help",113,117],["H6869","in trouble",118,128]]},"46:2":{"text":"Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea;","words":[["H3372","Therefore will not we fear",0,26],["H0776","though the earth",28,44],["H4171","be removed",45,55],["H2022","and though the mountains",57,81],["H4131","be carried",82,92],["H3820","into the midst",93,107],["H3220","of the sea",108,118]]},"46:3":{"text":"Though the waters thereof roar and be troubled, though the mountains shake with the swelling thereof. Selah.","words":[["H4325","Though the waters",0,17],["H1993","thereof roar",18,30],["H2560","and be troubled",31,46],["H2022","though the mountains",48,68],["H7493","shake",69,74],["H1346","with the swelling",75,92],["H5542","thereof. Selah",93,107]]},"46:4":{"text":"There is a river, the streams whereof shall make glad the city of God, the holy place of the tabernacles of the most High.","words":[["H5104","There is a river",0,16],["H6388","the streams",18,29],["H8055","whereof shall make glad",30,53],["H5892","the city",54,62],["H0430","of God",63,69],["H6918","the holy",71,79],["H4908","place of the tabernacles",80,104],["H5945","of the most High",105,121]]},"46:5":{"text":"God is in the midst of her; she shall not be moved: God shall help her, and that right early.","words":[["H0430","God",0,3],["H7130","is in the midst",4,19],["H4131","of her; she shall not be moved",20,50],["H0430","God",52,55],["H5826","shall help",56,66],["H6437","her, and that right",67,86],["H1242","early",87,92]]},"46:6":{"text":"The heathen raged, the kingdoms were moved: he uttered his voice, the earth melted.","words":[["H1471","The heathen",0,11],["H1993","raged",12,17],["H4467","the kingdoms",19,31],["H4131","were moved",32,42],["H5414","he uttered",44,54],["H6963","his voice",55,64],["H0776","the earth",66,75],["H4127","melted",76,82]]},"46:7":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah.","words":[["H3068","The LORD",0,8],["H6635","of hosts",9,17],["H0430","is with us; the God",18,37],["H3290","of Jacob",38,46],["H4869","is our refuge",47,60],["H5542","Selah",62,67]]},"46:8":{"text":"Come, behold the works of the LORD, what desolations he hath made in the earth.","words":[["H3212","Come",0,4],["H2372","behold",6,12],["H4659","the works",13,22],["H3068","of the LORD",23,34],["H8047","what desolations",36,52],["H7760","he hath made",53,65],["H0776","in the earth",66,78]]},"46:9":{"text":"He maketh wars to cease unto the end of the earth; he breaketh the bow, and cutteth the spear in sunder; he burneth the chariot in the fire.","words":[["H4421","He maketh wars",0,14],["H7673","to cease",15,23],["H7097","unto the end",24,36],["H0776","of the earth",37,49],["H7665","he breaketh",51,62],["H7198","the bow",63,70],["H7112","and cutteth",72,83],["H2595","the spear",84,93],["H7112","in sunder",94,103],["H8313","he burneth",105,115],["H5699","the chariot",116,127],["H0784","in the fire",128,139]]},"46:10":{"text":"Be still, and know that I am God: I will be exalted among the heathen, I will be exalted in the earth.","words":[["H7503","Be still",0,8],["H3045","and know",10,18],["H0430","that I am God",19,32],["H7311","I will be exalted",34,51],["H1471","among the heathen",52,69],["H7311","I will be exalted",71,88],["H0776","in the earth",89,101]]},"46:11":{"text":"The LORD of hosts is with us; the God of Jacob is our refuge. Selah.","words":[["H3068","The LORD",0,8],["H6635","of hosts",9,17],["H0430","is with us; the God",18,37],["H3290","of Jacob",38,46],["H4869","is our refuge",47,60],["H5542","Selah",62,67]]},"47:1":{"text":"To the chief Musician, A Psalm for the sons of Korah. O clap your hands, all ye people; shout unto God with the voice of triumph.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1121","for the sons",31,43],["H7141","of Korah",44,52],["H8628","O clap",54,60],["H3709","your hands",61,71],["H5971","all ye people",73,86],["H7321","shout",88,93],["H0430","unto God",94,102],["H6963","with the voice",103,117],["H7440","of triumph",118,128]]},"47:2":{"text":"For the LORD most high is terrible; he is a great King over all the earth.","words":[["H3068","For the LORD",0,12],["H5945","most high",13,22],["H3372","is terrible",23,34],["H1419","he is a great",36,49],["H4428","King",50,54],["H0776","over all the earth",55,73]]},"47:3":{"text":"He shall subdue the people under us, and the nations under our feet.","words":[["H1696","He shall subdue",0,15],["H5971","the people",16,26],["H3816","under us, and the nations",27,52],["H7272","under our feet",53,67]]},"47:4":{"text":"He shall choose our inheritance for us, the excellency of Jacob whom he loved. Selah.","words":[["H0977","He shall choose",0,15],["H5159","our inheritance",16,31],["H1347","for us, the excellency",32,54],["H3290","of Jacob",55,63],["H0157","whom he loved",64,77],["H5542","Selah",79,84]]},"47:5":{"text":"God is gone up with a shout, the LORD with the sound of a trumpet.","words":[["H0430","God",0,3],["H5927","is gone up",4,14],["H8643","with a shout",15,27],["H3068","the LORD",29,37],["H6963","with the sound",38,52],["H7782","of a trumpet",53,65]]},"47:6":{"text":"Sing praises to God, sing praises: sing praises unto our King, sing praises.","words":[["H2167","Sing praises",0,12],["H0430","to God",13,19],["H2167","sing praises",21,33],["H2167","sing praises",35,47],["H4428","unto our King",48,61],["H2167","sing praises",63,75]]},"47:7":{"text":"For God is the King of all the earth: sing ye praises with understanding.","words":[["H0430","For God",0,7],["H4428","is the King",8,19],["H0776","of all the earth",20,36],["H2167","sing ye praises",38,53],["H7919","with understanding",54,72]]},"47:8":{"text":"God reigneth over the heathen: God sitteth upon the throne of his holiness.","words":[["H0430","God",0,3],["H4427","reigneth",4,12],["H1471","over the heathen",13,29],["H0430","God",31,34],["H3427","sitteth",35,42],["H3678","upon the throne",43,58],["H6944","of his holiness",59,74]]},"47:9":{"text":"The princes of the people are gathered together, even the people of the God of Abraham: for the shields of the earth belong unto God: he is greatly exalted.","words":[["H5081","The princes",0,11],["H5971","of the people",12,25],["H0622","are gathered together",26,47],["H5971","even the people",49,64],["H0430","of the God",65,75],["H0085","of Abraham",76,86],["H4043","for the shields",88,103],["H0776","of the earth",104,116],["H0430","belong unto God",117,132],["H3966","he is greatly",134,147],["H5927","exalted",148,155]]},"48:1":{"text":"A Song and Psalm for the sons of Korah. Great is the LORD, and greatly to be praised in the city of our God, in the mountain of his holiness.","words":[["H7892","A Song",0,6],["H4210","and Psalm",7,16],["H1121","for the sons",17,29],["H7141","of Korah",30,38],["H1419","Great",40,45],["H3068","is the LORD",46,57],["H3966","and greatly",59,70],["H1984","to be praised",71,84],["H5892","in the city",85,96],["H0430","of our God",97,107],["H2022","in the mountain",109,124],["H6944","of his holiness",125,140]]},"48:2":{"text":"Beautiful for situation, the joy of the whole earth, is mount Zion, on the sides of the north, the city of the great King.","words":[["H3303","Beautiful",0,9],["H5131","for situation",10,23],["H4885","the joy",25,32],["H0776","of the whole earth",33,51],["H2022","is mount",53,61],["H6726","Zion",62,66],["H3411","on the sides",68,80],["H6828","of the north",81,93],["H7151","the city",95,103],["H7227","of the great",104,116],["H4428","King",117,121]]},"48:3":{"text":"God is known in her palaces for a refuge.","words":[["H0430","God",0,3],["H3045","is known",4,12],["H0759","in her palaces",13,27],["H4869","for a refuge",28,40]]},"48:4":{"text":"For, lo, the kings were assembled, they passed by together.","words":[["H4428","For, lo, the kings",0,18],["H3259","were assembled",19,33],["H5674","they passed by",35,49],["H3162","together",50,58]]},"48:5":{"text":"They saw it, and so they marvelled; they were troubled, and hasted away.","words":[["H7200","They saw",0,8],["H8539","it, and so they marvelled",9,34],["H0926","they were troubled",36,54],["H2648","and hasted away",56,71]]},"48:6":{"text":"Fear took hold upon them there, and pain, as of a woman in travail.","words":[["H7461","Fear",0,4],["H0270","took hold",5,14],["H2427","upon them there, and pain",15,40],["H3205","as of a woman in travail",42,66]]},"48:7":{"text":"Thou breakest the ships of Tarshish with an east wind.","words":[["H7665","Thou breakest",0,13],["H0591","the ships",14,23],["H8659","of Tarshish",24,35],["H6921","with an east",36,48],["H7307","wind",49,53]]},"48:8":{"text":"As we have heard, so have we seen in the city of the LORD of hosts, in the city of our God: God will establish it for ever. Selah.","words":[["H8085","As we have heard",0,16],["H7200","so have we seen",18,33],["H5892","in the city",34,45],["H3068","of the LORD",46,57],["H6635","of hosts",58,66],["H5892","in the city",68,79],["H0430","of our God",80,90],["H0430","God",92,95],["H3559","will establish",96,110],["H5704","it for",111,117],["H5769","ever",118,122],["H5542","Selah",124,129]]},"48:9":{"text":"We have thought of thy lovingkindness, O God, in the midst of thy temple.","words":[["H1819","We have thought",0,15],["H2617","of thy lovingkindness",16,37],["H0430","O God",39,44],["H7130","in the midst",46,58],["H1964","of thy temple",59,72]]},"48:10":{"text":"According to thy name, O God, so is thy praise unto the ends of the earth: thy right hand is full of righteousness.","words":[["H8034","According to thy name",0,21],["H0430","O God",23,28],["H8416","so is thy praise",30,46],["H7099","unto the ends",47,60],["H0776","of the earth",61,73],["H3225","thy right hand",75,89],["H4390","is full",90,97],["H6664","of righteousness",98,114]]},"48:11":{"text":"Let mount Zion rejoice, let the daughters of Judah be glad, because of thy judgments.","words":[["H2022","Let mount",0,9],["H6726","Zion",10,14],["H8055","rejoice",15,22],["H1323","let the daughters",24,41],["H3063","of Judah",42,50],["H1523","be glad",51,58],["H4941","because of thy judgments",60,84]]},"48:12":{"text":"Walk about Zion, and go round about her: tell the towers thereof.","words":[["H5437","Walk about",0,10],["H6726","Zion",11,15],["H5362","and go round about",17,35],["H5608","her: tell",36,45],["H4026","the towers",46,56]]},"48:13":{"text":"Mark ye well her bulwarks, consider her palaces; that ye may tell it to the generation following.","words":[["H7896","Mark",0,4],["H3820","ye well",5,12],["H2430","her bulwarks",13,25],["H6448","consider",27,35],["H0759","her palaces",36,47],["H5608","that ye may tell",49,65],["H1755","it to the generation",66,86],["H0314","following",87,96]]},"48:14":{"text":"For this God is our God for ever and ever: he will be our guide even unto death.","words":[["H0430","For this God",0,12],["H0430","is our God",13,23],["H5769","for ever",24,32],["H5703","and ever",33,41],["H5090","he will be our guide",43,63],["H4192","even unto death",64,79]]},"49:1":{"text":"To the chief Musician, A Psalm for the sons of Korah. Hear this, all ye people; give ear, all ye inhabitants of the world:","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1121","for the sons",31,43],["H7141","of Korah",44,52],["H8085","Hear",54,58],["H5971","this, all ye people",59,78],["H0238","give ear",80,88],["H3427","all ye inhabitants",90,108],["H2465","of the world",109,121]]},"49:2":{"text":"Both low and high, rich and poor, together.","words":[["H1121","Both low",0,8],["H0120","Both low",0,8],["H1121","and high",9,17],["H0376","and high",9,17],["H6223","rich",19,23],["H0034","and poor",24,32],["H3162","together",34,42]]},"49:3":{"text":"My mouth shall speak of wisdom; and the meditation of my heart shall be of understanding.","words":[["H6310","My mouth",0,8],["H1696","shall speak",9,20],["H2454","of wisdom",21,30],["H1900","and the meditation",32,50],["H3820","of my heart",51,62],["H8394","shall be of understanding",63,88]]},"49:4":{"text":"I will incline mine ear to a parable: I will open my dark saying upon the harp.","words":[["H5186","I will incline",0,14],["H0241","mine ear",15,23],["H4912","to a parable",24,36],["H6605","I will open",38,49],["H2420","my dark saying",50,64],["H3658","upon the harp",65,78]]},"49:5":{"text":"Wherefore should I fear in the days of evil, when the iniquity of my heels shall compass me about?","words":[["H3372","Wherefore should I fear",0,23],["H3117","in the days",24,35],["H7451","of evil",36,43],["H5771","when the iniquity",45,62],["H6120","of my heels",63,74],["H5437","shall compass",75,88]]},"49:6":{"text":"They that trust in their wealth, and boast themselves in the multitude of their riches;","words":[["H0982","They that trust",0,15],["H2428","in their wealth",16,31],["H1984","and boast",33,42],["H7230","themselves in the multitude",43,70],["H6239","of their riches",71,86]]},"49:7":{"text":"None of them can by any means redeem his brother, nor give to God a ransom for him:","words":[["H0376","None of them can",0,16],["H6299","by any means",17,29],["H6299","redeem",30,36],["H0251","his brother",37,48],["H5414","nor give",50,58],["H0430","to God",59,65],["H3724","a ransom",66,74]]},"49:8":{"text":"(For the redemption of their soul is precious, and it ceaseth for ever:)","words":[["H6306","(For the redemption",0,19],["H5315","of their soul",20,33],["H3365","is precious",34,45],["H2308","and it ceaseth",47,61],["H5769","for ever",62,70]]},"49:9":{"text":"That he should still live for ever, and not see corruption.","words":[["H2421","That he should still live",0,25],["H5331","for ever",26,34],["H7200","and not see",36,47],["H7845","corruption",48,58]]},"49:10":{"text":"For he seeth that wise men die, likewise the fool and the brutish person perish, and leave their wealth to others.","words":[["H7200","For he seeth",0,12],["H2450","that wise men",13,26],["H4191","die",27,30],["H3162","likewise",32,40],["H3684","the fool",41,49],["H1198","and the brutish person",50,72],["H0006","perish",73,79],["H5800","and leave",81,90],["H2428","their wealth",91,103],["H0312","to others",104,113]]},"49:11":{"text":"Their inward thought is, that their houses shall continue for ever, and their dwelling places to all generations; they call their lands after their own names.","words":[["H7130","Their inward",0,12],["H1004","thought is, that their houses",13,42],["H5769","shall continue for ever",43,66],["H4908","and their dwelling",68,86],["H1755","places to all",87,100],["H1755","generations",101,112],["H7121","they call",114,123],["H0127","their lands",124,135],["H8034","after their own names",136,157]]},"49:12":{"text":"Nevertheless man being in honour abideth not: he is like the beasts that perish.","words":[["H0120","Nevertheless man",0,16],["H3366","being in honour",17,32],["H3885","abideth",33,40],["H4911","not: he is like",41,56],["H0929","the beasts",57,67],["H1820","that perish",68,79]]},"49:13":{"text":"This their way is their folly: yet their posterity approve their sayings. Selah.","words":[["H1870","This their way",0,14],["H3689","is their folly",15,29],["H0310","yet their posterity",31,50],["H7521","approve",51,58],["H6310","their sayings",59,72],["H5542","Selah",74,79]]},"49:14":{"text":"Like sheep they are laid in the grave; death shall feed on them; and the upright shall have dominion over them in the morning; and their beauty shall consume in the grave from their dwelling.","words":[["H6629","Like sheep",0,10],["H8371","they are laid",11,24],["H7585","in the grave",25,37],["H4194","death",39,44],["H7462","shall feed",45,55],["H3477","on them; and the upright",56,80],["H7287","shall have dominion",81,100],["H1242","over them in the morning",101,125],["H6697","and their beauty",127,143],["H6736","and their beauty",127,143],["H1086","shall consume",144,157],["H7585","in the grave",158,170],["H2073","from their dwelling",171,190]]},"49:15":{"text":"But God will redeem my soul from the power of the grave: for he shall receive me. Selah.","words":[["H0430","But God",0,7],["H6299","will redeem",8,19],["H5315","my soul",20,27],["H3027","from the power",28,42],["H7585","of the grave",43,55],["H3947","for he shall receive",57,77],["H5542","me. Selah",78,87]]},"49:16":{"text":"Be not thou afraid when one is made rich, when the glory of his house is increased;","words":[["H3372","Be not thou afraid",0,18],["H0376","when one",19,27],["H6238","is made rich",28,40],["H3519","when the glory",42,56],["H1004","of his house",57,69],["H7235","is increased",70,82]]},"49:17":{"text":"For when he dieth he shall carry nothing away: his glory shall not descend after him.","words":[["H4194","For when he dieth",0,17],["H3947","he shall carry nothing away",18,45],["H3519","his glory",47,56],["H3381","shall not descend",57,74],["H0310","after",75,80]]},"49:18":{"text":"Though while he lived he blessed his soul: and men will praise thee, when thou doest well to thyself.","words":[["H2416","Though while he lived",0,21],["H1288","he blessed",22,32],["H5315","his soul",33,41],["H3034","and men will praise",43,62],["H3190","thee, when thou doest well",63,89]]},"49:19":{"text":"He shall go to the generation of his fathers; they shall never see light.","words":[["H0935","He shall go",0,11],["H1755","to the generation",12,29],["H0001","of his fathers",30,44],["H3808","they shall never",46,62],["H5331","they shall never",46,62],["H7200","see",63,66],["H0216","light",67,72]]},"49:20":{"text":"Man that is in honour, and understandeth not, is like the beasts that perish.","words":[["H0120","Man",0,3],["H3366","that is in honour",4,21],["H0995","and understandeth",23,40],["H4911","not, is like",41,53],["H0929","the beasts",54,64],["H1820","that perish",65,76]]},"50:1":{"text":"A Psalm of Asaph. The mighty God, even the LORD, hath spoken, and called the earth from the rising of the sun unto the going down thereof.","words":[["H4210","A Psalm",0,7],["H0623","of Asaph",8,16],["H0410","The mighty",18,28],["H0430","God",29,32],["H3068","even the LORD",34,47],["H1696","hath spoken",49,60],["H7121","and called",62,72],["H0776","the earth",73,82],["H4217","from the rising",83,98],["H8121","of the sun",99,109],["H3996","unto the going down",110,129]]},"50:2":{"text":"Out of Zion, the perfection of beauty, God hath shined.","words":[["H6726","Out of Zion",0,11],["H4359","the perfection",13,27],["H3308","of beauty",28,37],["H0430","God",39,42],["H3313","hath shined",43,54]]},"50:3":{"text":"Our God shall come, and shall not keep silence: a fire shall devour before him, and it shall be very tempestuous round about him.","words":[["H0430","Our God",0,7],["H0935","shall come",8,18],["H2790","and shall not keep silence",20,46],["H0784","a fire",48,54],["H0398","shall devour",55,67],["H6440","before",68,74],["H3966","him, and it shall be very",75,100],["H8175","tempestuous",101,112],["H5439","round about",113,124]]},"50:4":{"text":"He shall call to the heavens from above, and to the earth, that he may judge his people.","words":[["H7121","He shall call",0,13],["H8064","to the heavens",14,28],["H5920","from above",29,39],["H0776","and to the earth",41,57],["H1777","that he may judge",59,76],["H5971","his people",77,87]]},"50:5":{"text":"Gather my saints together unto me; those that have made a covenant with me by sacrifice.","words":[["H0622","Gather",0,6],["H2623","my saints",7,16],["H3772","together unto me; those that have made",17,55],["H1285","a covenant",56,66],["H2077","with me by sacrifice",67,87]]},"50:6":{"text":"And the heavens shall declare his righteousness: for God is judge himself. Selah.","words":[["H8064","And the heavens",0,15],["H5046","shall declare",16,29],["H6664","his righteousness",30,47],["H0430","for God",49,56],["H8199","is judge",57,65],["H5542","himself. Selah",66,80]]},"50:7":{"text":"Hear, O my people, and I will speak; O Israel, and I will testify against thee: I am God, even thy God.","words":[["H8085","Hear",0,4],["H5971","O my people",6,17],["H1696","and I will speak",19,35],["H3478","O Israel",37,45],["H5749","and I will testify",47,65],["H0430","against thee: I am God",66,88],["H0430","even thy God",90,102]]},"50:8":{"text":"I will not reprove thee for thy sacrifices or thy burnt offerings, to have been continually before me.","words":[["H3198","I will not reprove",0,18],["H2077","thee for thy sacrifices",19,42],["H5930","or thy burnt offerings",43,65],["H8548","to have been continually",67,91]]},"50:9":{"text":"I will take no bullock out of thy house, nor he goats out of thy folds.","words":[["H3947","I will take",0,11],["H6499","no bullock",12,22],["H1004","out of thy house",23,39],["H6260","nor he goats",41,53],["H4356","out of thy folds",54,70]]},"50:10":{"text":"For every beast of the forest is mine, and the cattle upon a thousand hills.","words":[["H2416","For every beast",0,15],["H3293","of the forest",16,29],["H0929","is mine, and the cattle",30,53],["H0505","upon a thousand",54,69],["H2042","hills",70,75]]},"50:11":{"text":"I know all the fowls of the mountains: and the wild beasts of the field are mine.","words":[["H3045","I know",0,6],["H5775","all the fowls",7,20],["H2022","of the mountains",21,37],["H2123","and the wild beasts",39,58],["H7704","of the field",59,71],["H5978","are mine",72,80]]},"50:12":{"text":"If I were hungry, I would not tell thee: for the world is mine, and the fulness thereof.","words":[["H7456","If I were hungry",0,16],["H0559","I would not tell",18,34],["H8398","thee: for the world",35,54],["H4393","is mine, and the fulness",55,79]]},"50:13":{"text":"Will I eat the flesh of bulls, or drink the blood of goats?","words":[["H0398","Will I eat",0,10],["H1320","the flesh",11,20],["H0047","of bulls",21,29],["H8354","or drink",31,39],["H1818","the blood",40,49],["H6260","of goats",50,58]]},"50:14":{"text":"Offer unto God thanksgiving; and pay thy vows unto the most High:","words":[["H2076","Offer",0,5],["H0430","unto God",6,14],["H8426","thanksgiving",15,27],["H7999","and pay",29,36],["H5088","thy vows",37,45],["H5945","unto the most High",46,64]]},"50:15":{"text":"And call upon me in the day of trouble: I will deliver thee, and thou shalt glorify me.","words":[["H7121","And call",0,8],["H3117","upon me in the day",9,27],["H6869","of trouble",28,38],["H2502","I will deliver",40,54],["H3513","thee, and thou shalt glorify",55,83]]},"50:16":{"text":"But unto the wicked God saith, What hast thou to do to declare my statutes, or that thou shouldest take my covenant in thy mouth?","words":[["H7563","But unto the wicked",0,19],["H0430","God",20,23],["H0559","saith",24,29],["H5608","What hast thou to do to declare",31,62],["H2706","my statutes",63,74],["H5375","or that thou shouldest take",76,103],["H1285","my covenant",104,115],["H6310","in thy mouth",116,128]]},"50:17":{"text":"Seeing thou hatest instruction, and castest my words behind thee.","words":[["H8130","Seeing thou hatest",0,18],["H4148","instruction",19,30],["H7993","and castest",32,43],["H1697","my words",44,52],["H0310","behind",53,59]]},"50:18":{"text":"When thou sawest a thief, then thou consentedst with him, and hast been partaker with adulterers.","words":[["H7200","When thou sawest",0,16],["H1590","a thief",17,24],["H7521","then thou consentedst",26,47],["H2506","with him, and hast been partaker",48,80],["H5003","with adulterers",81,96]]},"50:19":{"text":"Thou givest thy mouth to evil, and thy tongue frameth deceit.","words":[["H7971","Thou givest",0,11],["H6310","thy mouth",12,21],["H7451","to evil",22,29],["H3956","and thy tongue",31,45],["H6775","frameth",46,53],["H4820","deceit",54,60]]},"50:20":{"text":"Thou sittest and speakest against thy brother; thou slanderest thine own mother's son.","words":[["H3427","Thou sittest",0,12],["H1696","and speakest",13,25],["H0251","against thy brother",26,45],["H5414","thou",47,51],["H1848","slanderest",52,62],["H0517","thine own mother's",63,81],["H1121","son",82,85]]},"50:21":{"text":"These things hast thou done, and I kept silence; thou thoughtest that I was altogether such an one as thyself: but I will reprove thee, and set them in order before thine eyes.","words":[["H6213","These things hast thou done",0,27],["H2790","and I kept silence",29,47],["H1819","thou thoughtest",49,64],["H1961","that I was altogether",65,86],["H3198","such an one as thyself: but I will reprove",87,129],["H6186","thee, and set them in order",130,157],["H5869","before thine eyes",158,175]]},"50:22":{"text":"Now consider this, ye that forget God, lest I tear you in pieces, and there be none to deliver.","words":[["H0995","Now consider",0,12],["H7911","this, ye that forget",13,33],["H0433","God",34,37],["H2963","lest I tear you in pieces",39,64],["H5337","and there be none to deliver",66,94]]},"50:23":{"text":"Whoso offereth praise glorifieth me: and to him that ordereth his conversation aright will I shew the salvation of God.","words":[["H2076","Whoso offereth",0,14],["H8426","praise",15,21],["H3513","glorifieth",22,32],["H7760","me: and to him that ordereth",33,61],["H1870","his conversation",62,78],["H7200","aright will I shew",79,97],["H3468","the salvation",98,111],["H0430","of God",112,118]]},"51:1":{"text":"To the chief Musician, A Psalm of David, when Nathan the prophet came unto him, after he had gone in to Bathsheba. Have mercy upon me, O God, according to thy lovingkindness: according unto the multitude of thy tender mercies blot out my transgressions.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H5416","when Nathan",41,52],["H5030","the prophet",53,64],["H0935","came",65,69],["H0935","unto him, after he had gone in",70,100],["H1339","to Bathsheba",101,113],["H2603","Have mercy",115,125],["H0430","upon me, O God",126,140],["H2617","according to thy lovingkindness",142,173],["H7230","according unto the multitude",175,203],["H7356","of thy tender mercies",204,225],["H4229","blot out",226,234],["H6588","my transgressions",235,252]]},"51:2":{"text":"Wash me throughly from mine iniquity, and cleanse me from my sin.","words":[["H3526","Wash",0,4],["H7235","me throughly",5,17],["H5771","from mine iniquity",18,36],["H2891","and cleanse",38,49],["H2403","me from my sin",50,64]]},"51:3":{"text":"For I acknowledge my transgressions: and my sin is ever before me.","words":[["H3045","For I acknowledge",0,17],["H6588","my transgressions",18,35],["H2403","and my sin",37,47],["H8548","is ever",48,55]]},"51:4":{"text":"Against thee, thee only, have I sinned, and done this evil in thy sight: that thou mightest be justified when thou speakest, and be clear when thou judgest.","words":[["H2398","Against thee, thee only, have I sinned",0,38],["H6213","and done",40,48],["H7451","this evil",49,58],["H5869","in thy sight",59,71],["H6663","that thou mightest be justified",73,104],["H1696","when thou speakest",105,123],["H2135","and be clear",125,137],["H8199","when thou judgest",138,155]]},"51:5":{"text":"Behold, I was shapen in iniquity; and in sin did my mother conceive me.","words":[["H2342","Behold, I was shapen",0,20],["H5771","in iniquity",21,32],["H2399","and in sin",34,44],["H0517","did my mother",45,58],["H3179","conceive",59,67]]},"51:6":{"text":"Behold, thou desirest truth in the inward parts: and in the hidden part thou shalt make me to know wisdom.","words":[["H2654","Behold, thou desirest",0,21],["H0571","truth",22,27],["H2910","in the inward parts",28,47],["H5640","and in the hidden",49,66],["H3045","part thou shalt make me to know",67,98],["H2451","wisdom",99,105]]},"51:7":{"text":"Purge me with hyssop, and I shall be clean: wash me, and I shall be whiter than snow.","words":[["H2398","Purge",0,5],["H0231","me with hyssop",6,20],["H2891","and I shall be clean",22,42],["H3526","wash",44,48],["H3835","me, and I shall be whiter",49,74],["H7950","than snow",75,84]]},"51:8":{"text":"Make me to hear joy and gladness; that the bones which thou hast broken may rejoice.","words":[["H8085","Make me to hear",0,15],["H8342","joy",16,19],["H8057","and gladness",20,32],["H6106","that the bones",34,48],["H1794","which thou hast broken",49,71],["H1523","may rejoice",72,83]]},"51:9":{"text":"Hide thy face from my sins, and blot out all mine iniquities.","words":[["H5641","Hide",0,4],["H6440","thy face",5,13],["H2399","from my sins",14,26],["H4229","and blot out",28,40],["H5771","all mine iniquities",41,60]]},"51:10":{"text":"Create in me a clean heart, O God; and renew a right spirit within me.","words":[["H1254","Create",0,6],["H2889","in me a clean",7,20],["H3820","heart",21,26],["H0430","O God",28,33],["H2318","and renew",35,44],["H3559","a right",45,52],["H7307","spirit",53,59],["H7130","within",60,66]]},"51:11":{"text":"Cast me not away from thy presence; and take not thy holy spirit from me.","words":[["H7993","Cast me not away",0,16],["H6440","from thy presence",17,34],["H3947","and take",36,44],["H6944","not thy holy",45,57],["H7307","spirit",58,64]]},"51:12":{"text":"Restore unto me the joy of thy salvation; and uphold me with thy free spirit.","words":[["H7725","Restore",0,7],["H8342","unto me the joy",8,23],["H3468","of thy salvation",24,40],["H5564","and uphold",42,52],["H5081","me with thy free",53,69],["H7307","spirit",70,76]]},"51:13":{"text":"Then will I teach transgressors thy ways; and sinners shall be converted unto thee.","words":[["H3925","Then will I teach",0,17],["H6586","transgressors",18,31],["H1870","thy ways",32,40],["H2400","and sinners",42,53],["H7725","shall be converted",54,72]]},"51:14":{"text":"Deliver me from bloodguiltiness, O God, thou God of my salvation: and my tongue shall sing aloud of thy righteousness.","words":[["H5337","Deliver",0,7],["H1818","me from bloodguiltiness",8,31],["H0430","O God",33,38],["H0430","thou God",40,48],["H8668","of my salvation",49,64],["H3956","and my tongue",66,79],["H7442","shall sing aloud",80,96],["H6666","of thy righteousness",97,117]]},"51:15":{"text":"O Lord, open thou my lips; and my mouth shall shew forth thy praise.","words":[["H0136","O Lord",0,6],["H6605","open",8,12],["H8193","thou my lips",13,25],["H6310","and my mouth",27,39],["H5046","shall shew forth",40,56],["H8416","thy praise",57,67]]},"51:16":{"text":"For thou desirest not sacrifice; else would I give it: thou delightest not in burnt offering.","words":[["H2654","For thou desirest",0,17],["H2077","not sacrifice",18,31],["H5414","else would I give",33,50],["H7521","it: thou delightest",51,70],["H5930","not in burnt offering",71,92]]},"51:17":{"text":"The sacrifices of God are a broken spirit: a broken and a contrite heart, O God, thou wilt not despise.","words":[["H2077","The sacrifices",0,14],["H0430","of God",15,21],["H7665","are a broken",22,34],["H7307","spirit",35,41],["H7665","a broken",43,51],["H1794","and a contrite",52,66],["H3820","heart",67,72],["H0430","O God",74,79],["H0959","thou wilt not despise",81,102]]},"51:18":{"text":"Do good in thy good pleasure unto Zion: build thou the walls of Jerusalem.","words":[["H3190","Do good",0,7],["H7522","in thy good pleasure",8,28],["H6726","unto Zion",29,38],["H1129","build",40,45],["H2346","thou the walls",46,60],["H3389","of Jerusalem",61,73]]},"51:19":{"text":"Then shalt thou be pleased with the sacrifices of righteousness, with burnt offering and whole burnt offering: then shall they offer bullocks upon thine altar.","words":[["H2654","Then shalt thou be pleased",0,26],["H2077","with the sacrifices",27,46],["H6664","of righteousness",47,63],["H5930","with burnt offering",65,84],["H3632","and whole",85,94],["H5930","burnt offering",95,109],["H5927","then shall they offer",111,132],["H6499","bullocks",133,141],["H4196","upon thine altar",142,158]]},"52:1":{"text":"To the chief Musician, Maschil, A Psalm of David, when Doeg the Edomite came and told Saul, and said unto him, David is come to the house of Ahimelech. Why boastest thou thyself in mischief, O mighty man? the goodness of God endureth continually.","words":[["H5329","To the chief Musician",0,21],["H4905","Maschil",23,30],["H1732","A Psalm of David",32,48],["H1673","when Doeg",50,59],["H0130","the Edomite",60,71],["H0935","came",72,76],["H5046","and told",77,85],["H7586","Saul",86,90],["H0559","and said",92,100],["H1732","unto him, David",101,116],["H0935","is come",117,124],["H1004","to the house",125,137],["H0288","of Ahimelech",138,150],["H1984","Why boastest",152,164],["H7451","thou thyself in mischief",165,189],["H1368","O mighty",191,199],["H2617","man? the goodness",200,217],["H0410","of God",218,224],["H3117","endureth continually",225,245]]},"52:2":{"text":"Thy tongue deviseth mischiefs; like a sharp razor, working deceitfully.","words":[["H3956","Thy tongue",0,10],["H2803","deviseth",11,19],["H1942","mischiefs",20,29],["H3913","like a sharp",31,43],["H8593","razor",44,49],["H6213","working",51,58],["H7423","deceitfully",59,70]]},"52:3":{"text":"Thou lovest evil more than good; and lying rather than to speak righteousness. Selah.","words":[["H0157","Thou lovest",0,11],["H7451","evil",12,16],["H2896","more than good",17,31],["H8267","and lying",33,42],["H1696","rather than to speak",43,63],["H6664","righteousness",64,77],["H5542","Selah",79,84]]},"52:4":{"text":"Thou lovest all devouring words, O thou deceitful tongue.","words":[["H0157","Thou lovest",0,11],["H1105","all devouring",12,25],["H1697","words",26,31],["H4820","O thou deceitful",33,49],["H3956","tongue",50,56]]},"52:5":{"text":"God shall likewise destroy thee for ever, he shall take thee away, and pluck thee out of thy dwelling place, and root thee out of the land of the living. Selah.","words":[["H0410","God",0,3],["H5422","shall likewise destroy",4,26],["H5331","thee for ever",27,40],["H2846","he shall take thee away",42,65],["H5255","and pluck thee out",67,85],["H0168","of thy dwelling place",86,107],["H8327","and root thee out",109,126],["H0776","of the land",127,138],["H2416","of the living",139,152],["H5542","Selah",154,159]]},"52:6":{"text":"The righteous also shall see, and fear, and shall laugh at him:","words":[["H6662","The righteous",0,13],["H7200","also shall see",14,28],["H3372","and fear",30,38],["H7832","and shall laugh",40,55]]},"52:7":{"text":"Lo, this is the man that made not God his strength; but trusted in the abundance of his riches, and strengthened himself in his wickedness.","words":[["H1397","Lo, this is the man",0,19],["H7760","that made",20,29],["H0430","not God",30,37],["H4581","his strength",38,50],["H0982","but trusted",52,63],["H7230","in the abundance",64,80],["H6239","of his riches",81,94],["H5810","and strengthened",96,112],["H1942","himself in his wickedness",113,138]]},"52:8":{"text":"But I am like a green olive tree in the house of God: I trust in the mercy of God for ever and ever.","words":[["H7488","But I am like a green",0,21],["H2132","olive tree",22,32],["H1004","in the house",33,45],["H0430","of God",46,52],["H0982","I trust",54,61],["H2617","in the mercy",62,74],["H0430","of God",75,81],["H5769","for ever",82,90],["H5703","and ever",91,99]]},"52:9":{"text":"I will praise thee for ever, because thou hast done it: and I will wait on thy name; for it is good before thy saints.","words":[["H3034","I will praise",0,13],["H5769","thee for ever",14,27],["H6213","because thou hast done",29,51],["H6960","it: and I will wait",52,71],["H8034","on thy name",72,83],["H2896","for it is good",85,99],["H2623","before thy saints",100,117]]},"53:1":{"text":"To the chief Musician upon Mahalath, Maschil, A Psalm of David. The fool hath said in his heart, There is no God. Corrupt are they, and have done abominable iniquity: there is none that doeth good.","words":[["H5329","To the chief Musician",0,21],["H4257","upon Mahalath",22,35],["H4905","Maschil",37,44],["H1732","A Psalm of David",46,62],["H5036","The fool",64,72],["H0559","hath said",73,82],["H3820","in his heart",83,95],["H0430","There is no God",97,112],["H7843","Corrupt",114,121],["H8581","are they, and have done abominable",122,156],["H5766","iniquity",157,165],["H6213","there is none that doeth",167,191],["H2896","good",192,196]]},"53:2":{"text":"God looked down from heaven upon the children of men, to see if there were any that did understand, that did seek God.","words":[["H0430","God",0,3],["H8259","looked down",4,15],["H8064","from heaven",16,27],["H1121","upon the children",28,45],["H0120","of men",46,52],["H7200","to see",54,60],["H3426","if there were",61,74],["H7919","any that did understand",75,98],["H1875","that did seek",100,113],["H0430","God",114,117]]},"53:3":{"text":"Every one of them is gone back: they are altogether become filthy; there is none that doeth good, no, not one.","words":[["H5472","Every one of them is gone back",0,30],["H3162","they are altogether",32,51],["H0444","become filthy",52,65],["H6213","there is none that doeth",67,91],["H2896","good",92,96],["H0259","no, not one",98,109]]},"53:4":{"text":"Have the workers of iniquity no knowledge? who eat up my people as they eat bread: they have not called upon God.","words":[["H6466","Have the workers",0,16],["H0205","of iniquity",17,28],["H3045","no knowledge",29,41],["H0398","who eat up",43,53],["H5971","my people",54,63],["H0398","as they eat",64,75],["H3899","bread",76,81],["H7121","they have not called",83,103],["H0430","upon God",104,112]]},"53:5":{"text":"There were they in great fear, where no fear was: for God hath scattered the bones of him that encampeth against thee: thou hast put them to shame, because God hath despised them.","words":[["H6343","There were they in great",0,24],["H6342","fear",25,29],["H6343","where no fear",31,44],["H0430","was: for God",45,57],["H6340","hath scattered",58,72],["H6106","the bones",73,82],["H2583","of him that encampeth",83,104],["H0954","against thee: thou hast put them to shame",105,146],["H0430","because God",148,159],["H3988","hath despised",160,173]]},"53:6":{"text":"Oh that the salvation of Israel were come out of Zion! When God bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad.","words":[["H5414","Oh that",0,7],["H3444","the salvation",8,21],["H3478","of Israel",22,31],["H6726","were come out of Zion",32,53],["H0430","When God",55,63],["H7725","bringeth back",64,77],["H7622","the captivity",78,91],["H5971","of his people",92,105],["H3290","Jacob",107,112],["H1523","shall rejoice",113,126],["H3478","and Israel",128,138],["H8055","shall be glad",139,152]]},"54:1":{"text":"To the chief Musician on Neginoth, Maschil, A Psalm of David, when the Ziphims came and said to Saul, Doth not David hide himself with us? Save me, O God, by thy name, and judge me by thy strength.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H4905","Maschil",35,42],["H1732","A Psalm of David",44,60],["H2130","when the Ziphims",62,78],["H0935","came",79,83],["H0559","and said",84,92],["H7586","to Saul",93,100],["H1732","Doth not David",102,116],["H5641","hide",117,121],["H3467","himself with us? Save",122,143],["H0430","me, O God",144,153],["H8034","by thy name",155,166],["H1777","and judge",168,177],["H1369","me by thy strength",178,196]]},"54:2":{"text":"Hear my prayer, O God; give ear to the words of my mouth.","words":[["H8085","Hear",0,4],["H8605","my prayer",5,14],["H0430","O God",16,21],["H0238","give ear",23,31],["H0561","to the words",32,44],["H6310","of my mouth",45,56]]},"54:3":{"text":"For strangers are risen up against me, and oppressors seek after my soul: they have not set God before them. Selah.","words":[["H2114","For strangers",0,13],["H6965","are risen up",14,26],["H6184","against me, and oppressors",27,53],["H1245","seek",54,58],["H5315","after my soul",59,72],["H7760","they have not set",74,91],["H0430","God",92,95],["H5542","before them. Selah",96,114]]},"54:4":{"text":"Behold, God is mine helper: the Lord is with them that uphold my soul.","words":[["H0430","Behold, God",0,11],["H5826","is mine helper",12,26],["H0136","the Lord",28,36],["H5564","is with them that uphold",37,61],["H5315","my soul",62,69]]},"54:5":{"text":"He shall reward evil unto mine enemies: cut them off in thy truth.","words":[["H7725","He shall reward",0,15],["H7725","He shall reward",0,15],["H7451","evil",16,20],["H8324","unto mine enemies",21,38],["H6789","cut them off",40,52],["H0571","in thy truth",53,65]]},"54:6":{"text":"I will freely sacrifice unto thee: I will praise thy name, O LORD; for it is good.","words":[["H5071","I will freely",0,13],["H2076","sacrifice",14,23],["H3034","unto thee: I will praise",24,48],["H8034","thy name",49,57],["H3068","O LORD",59,65],["H2896","for it is good",67,81]]},"54:7":{"text":"For he hath delivered me out of all trouble: and mine eye hath seen his desire upon mine enemies.","words":[["H5337","For he hath delivered",0,21],["H6869","me out of all trouble",22,43],["H5869","and mine eye",45,57],["H7200","hath seen",58,67],["H0341","his desire upon mine enemies",68,96]]},"55:1":{"text":"To the chief Musician on Neginoth, Maschil, A Psalm of David. Give ear to my prayer, O God; and hide not thyself from my supplication.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H4905","Maschil",35,42],["H1732","A Psalm of David",44,60],["H0238","Give ear",62,70],["H8605","to my prayer",71,83],["H0430","O God",85,90],["H5956","and hide",92,100],["H8467","not thyself from my supplication",101,133]]},"55:2":{"text":"Attend unto me, and hear me: I mourn in my complaint, and make a noise;","words":[["H7181","Attend",0,6],["H6030","unto me, and hear",7,24],["H7300","me: I mourn",25,36],["H7879","in my complaint",37,52],["H1949","and make a noise",54,70]]},"55:3":{"text":"Because of the voice of the enemy, because of the oppression of the wicked: for they cast iniquity upon me, and in wrath they hate me.","words":[["H6963","Because of the voice",0,20],["H0341","of the enemy",21,33],["H6440","because",35,42],["H6125","of the oppression",43,60],["H7563","of the wicked",61,74],["H4131","for they cast",76,89],["H0205","iniquity",90,98],["H0639","upon me, and in wrath",99,120],["H7852","they hate",121,130]]},"55:4":{"text":"My heart is sore pained within me: and the terrors of death are fallen upon me.","words":[["H3820","My heart",0,8],["H2342","is sore pained",9,23],["H7130","within",24,30],["H0367","me: and the terrors",31,50],["H4194","of death",51,59],["H5307","are fallen",60,70]]},"55:5":{"text":"Fearfulness and trembling are come upon me, and horror hath overwhelmed me.","words":[["H3374","Fearfulness",0,11],["H7461","and trembling",12,25],["H0935","are come",26,34],["H6427","upon me, and horror",35,54],["H3680","hath overwhelmed",55,71]]},"55:6":{"text":"And I said, Oh that I had wings like a dove! for then would I fly away, and be at rest.","words":[["H0559","And I said",0,10],["H5414","Oh that",12,19],["H0083","I had wings",20,31],["H3123","like a dove",32,43],["H5774","for then would I fly away",45,70],["H7931","and be at rest",72,86]]},"55:7":{"text":"Lo, then would I wander far off, and remain in the wilderness. Selah.","words":[["H5074","Lo, then would I wander",0,23],["H7368","far off",24,31],["H3885","and remain",33,43],["H4057","in the wilderness",44,61],["H5542","Selah",63,68]]},"55:8":{"text":"I would hasten my escape from the windy storm and tempest.","words":[["H2363","I would hasten",0,14],["H4655","my escape",15,24],["H7307","from the windy",25,39],["H5584","storm",40,45],["H5591","and tempest",46,57]]},"55:9":{"text":"Destroy, O Lord, and divide their tongues: for I have seen violence and strife in the city.","words":[["H1104","Destroy",0,7],["H0136","O Lord",9,15],["H6385","and divide",17,27],["H3956","their tongues",28,41],["H7200","for I have seen",43,58],["H2555","violence",59,67],["H7379","and strife",68,78],["H5892","in the city",79,90]]},"55:10":{"text":"Day and night they go about it upon the walls thereof: mischief also and sorrow are in the midst of it.","words":[["H3119","Day",0,3],["H3915","and night",4,13],["H5437","they go about",14,27],["H2346","it upon the walls",28,45],["H0205","thereof: mischief",46,63],["H5999","also and sorrow",64,79],["H7130","are in the midst",80,96]]},"55:11":{"text":"Wickedness is in the midst thereof: deceit and guile depart not from her streets.","words":[["H1942","Wickedness",0,10],["H7130","is in the midst",11,26],["H8496","thereof: deceit",27,42],["H4820","and guile",43,52],["H4185","depart",53,59],["H7339","not from her streets",60,80]]},"55:12":{"text":"For it was not an enemy that reproached me; then I could have borne it: neither was it he that hated me that did magnify himself against me; then I would have hid myself from him:","words":[["H0341","For it was not an enemy",0,23],["H2778","that reproached",24,39],["H5375","me; then I could have borne",40,67],["H8130","it: neither was it he that hated",68,100],["H1431","me that did magnify",101,120],["H5641","himself against me; then I would have hid",121,162]]},"55:13":{"text":"But it was thou, a man mine equal, my guide, and mine acquaintance.","words":[["H0582","But it was thou, a man",0,22],["H6187","mine equal",23,33],["H0441","my guide",35,43],["H3045","and mine acquaintance",45,66]]},"55:14":{"text":"We took sweet counsel together, and walked unto the house of God in company.","words":[["H4985","We took sweet",0,13],["H5475","counsel",14,21],["H3162","together",22,30],["H1980","and walked",32,42],["H1004","unto the house",43,57],["H0430","of God",58,64],["H7285","in company",65,75]]},"55:15":{"text":"Let death seize upon them, and let them go down quick into hell: for wickedness is in their dwellings, and among them.","words":[["H4194","Let death",0,9],["H5377","seize",10,15],["H3451","seize",10,15],["H3381","upon them, and let them go down",16,47],["H2416","quick",48,53],["H7585","into hell",54,63],["H7451","for wickedness",65,79],["H4033","is in their dwellings",80,101],["H7130","and among",103,112]]},"55:16":{"text":"As for me, I will call upon God; and the LORD shall save me.","words":[["H7121","As for me, I will call",0,22],["H0430","upon God",23,31],["H3068","and the LORD",33,45],["H3467","shall save",46,56]]},"55:17":{"text":"Evening, and morning, and at noon, will I pray, and cry aloud: and he shall hear my voice.","words":[["H6153","Evening",0,7],["H1242","and morning",9,20],["H6672","and at noon",22,33],["H7878","will I pray",35,46],["H1993","and cry aloud",48,61],["H8085","and he shall hear",63,80],["H6963","my voice",81,89]]},"55:18":{"text":"He hath delivered my soul in peace from the battle that was against me: for there were many with me.","words":[["H6299","He hath delivered",0,17],["H5315","my soul",18,25],["H7965","in peace",26,34],["H7128","from the battle",35,50],["H7227","that was against me: for there were many",51,91]]},"55:19":{"text":"God shall hear, and afflict them, even he that abideth of old. Selah. Because they have no changes, therefore they fear not God.","words":[["H0410","God",0,3],["H8085","shall hear",4,14],["H6030","and afflict",16,27],["H3427","them, even he that abideth",28,54],["H6924","of old",55,61],["H5542","Selah",63,68],["H2487","Because they have no changes",70,98],["H3372","therefore they fear",100,119],["H0430","not God",120,127]]},"55:20":{"text":"He hath put forth his hands against such as be at peace with him: he hath broken his covenant.","words":[["H7971","He hath put forth",0,17],["H3027","his hands",18,27],["H7965","against such as be at peace",28,55],["H2490","with him: he hath broken",56,80],["H1285","his covenant",81,93]]},"55:21":{"text":"The words of his mouth were smoother than butter, but war was in his heart: his words were softer than oil, yet were they drawn swords.","words":[["H6310","The words of his mouth",0,22],["H2505","were smoother",23,36],["H4260","than butter",37,48],["H7128","but war",50,57],["H3820","was in his heart",58,74],["H1697","his words",76,85],["H7401","were softer",86,97],["H8081","than oil",98,106],["H6609","yet were they drawn swords",108,134]]},"55:22":{"text":"Cast thy burden upon the LORD, and he shall sustain thee: he shall never suffer the righteous to be moved.","words":[["H7993","Cast",0,4],["H3053","thy burden",5,15],["H3068","upon the LORD",16,29],["H3557","and he shall sustain",31,51],["H5769","thee: he shall never",52,72],["H5414","suffer",73,79],["H6662","the righteous",80,93],["H4131","to be moved",94,105]]},"55:23":{"text":"But thou, O God, shalt bring them down into the pit of destruction: bloody and deceitful men shall not live out half their days; but I will trust in thee.","words":[["H0430","But thou, O God",0,15],["H3381","shalt bring them down",17,38],["H0875","into the pit",39,51],["H7845","of destruction",52,66],["H1818","bloody",68,74],["H4820","and deceitful",75,88],["H0582","men",89,92],["H2673","shall not live out half",93,116],["H3117","their days",117,127],["H0982","but I will trust",129,145]]},"56:1":{"text":"To the chief Musician upon Jonathelemrechokim, Michtam of David, when the Philistines took him in Gath. Be merciful unto me, O God: for man would swallow me up; he fighting daily oppresseth me.","words":[["H5329","To the chief Musician",0,21],["H3128","upon Jonathelemrechokim",22,45],["H4387","Michtam",47,54],["H1732","of David",55,63],["H6430","when the Philistines",65,85],["H0270","took",86,90],["H1661","him in Gath",91,102],["H2603","Be merciful",104,115],["H0430","unto me, O God",116,130],["H0582","for man",132,139],["H7602","would swallow me up",140,159],["H3898","he fighting",161,172],["H3117","daily",173,178],["H3905","oppresseth",179,189]]},"56:2":{"text":"Mine enemies would daily swallow me up: for they be many that fight against me, O thou most High.","words":[["H8324","Mine enemies",0,12],["H3117","would daily",13,24],["H7602","swallow",25,32],["H7227","me up: for they be many",33,56],["H3898","that fight",57,67],["H4791","against me, O thou most High",68,96]]},"56:3":{"text":"What time I am afraid, I will trust in thee.","words":[["H3117","What time",0,9],["H3372","I am afraid",10,21],["H0982","I will trust",23,35]]},"56:4":{"text":"In God I will praise his word, in God I have put my trust; I will not fear what flesh can do unto me.","words":[["H0430","In God",0,6],["H1984","I will praise",7,20],["H1697","his word",21,29],["H0430","in God",31,37],["H0982","I have put my trust",38,57],["H3372","I will not fear",59,74],["H1320","what flesh",75,85],["H6213","can do",86,92]]},"56:5":{"text":"Every day they wrest my words: all their thoughts are against me for evil.","words":[["H3117","Every day",0,9],["H6087","they wrest",10,20],["H1697","my words",21,29],["H4284","all their thoughts",31,49],["H7451","are against me for evil",50,73]]},"56:6":{"text":"They gather themselves together, they hide themselves, they mark my steps, when they wait for my soul.","words":[["H1481","They gather themselves together",0,31],["H6845","they hide",33,42],["H6845","they hide",33,42],["H8104","themselves, they mark",43,64],["H6119","my steps",65,73],["H6960","when they wait",75,89],["H5315","for my soul",90,101]]},"56:7":{"text":"Shall they escape by iniquity? in thine anger cast down the people, O God.","words":[["H6405","Shall they escape",0,17],["H0205","by iniquity",18,29],["H0639","in thine anger",31,45],["H3381","cast down",46,55],["H5971","the people",56,66],["H0430","O God",68,73]]},"56:8":{"text":"Thou tellest my wanderings: put thou my tears into thy bottle: are they not in thy book?","words":[["H5608","Thou tellest",0,12],["H5112","my wanderings",13,26],["H7760","put",28,31],["H1832","thou my tears",32,45],["H4997","into thy bottle",46,61],["H5612","are they not in thy book",63,87]]},"56:9":{"text":"When I cry unto thee, then shall mine enemies turn back: this I know; for God is for me.","words":[["H3117","When",0,4],["H7121","I cry",5,10],["H0341","unto thee, then shall mine enemies",11,45],["H7725","turn",46,50],["H0268","back",51,55],["H3045","this I know",57,68],["H0430","for God",70,77]]},"56:10":{"text":"In God will I praise his word: in the LORD will I praise his word.","words":[["H0430","In God",0,6],["H1984","will I praise",7,20],["H1697","his word",21,29],["H3068","in the LORD",31,42],["H1984","will I praise",43,56],["H1697","his word",57,65]]},"56:11":{"text":"In God have I put my trust: I will not be afraid what man can do unto me.","words":[["H0430","In God",0,6],["H0982","have I put my trust",7,26],["H3372","I will not be afraid",28,48],["H0120","what man",49,57],["H6213","can do",58,64]]},"56:12":{"text":"Thy vows are upon me, O God: I will render praises unto thee.","words":[["H5088","Thy vows",0,8],["H0430","are upon me, O God",9,27],["H7999","I will render",29,42],["H8426","praises",43,50]]},"56:13":{"text":"For thou hast delivered my soul from death: wilt not thou deliver my feet from falling, that I may walk before God in the light of the living?","words":[["H5337","For thou hast delivered",0,23],["H5315","my soul",24,31],["H4194","from death",32,42],["H7272","wilt not thou deliver my feet",44,73],["H1762","from falling",74,86],["H1980","that I may walk",88,103],["H6440","before",104,110],["H0430","God",111,114],["H0216","in the light",115,127],["H2416","of the living",128,141]]},"57:1":{"text":"To the chief Musician, Altaschith, Michtam of David, when he fled from Saul in the cave. Be merciful unto me, O God, be merciful unto me: for my soul trusteth in thee: yea, in the shadow of thy wings will I make my refuge, until these calamities be overpast.","words":[["H5329","To the chief Musician",0,21],["H0516","Altaschith",23,33],["H4387","Michtam",35,42],["H1732","of David",43,51],["H1272","when he fled",53,65],["H6440","from",66,70],["H7586","Saul",71,75],["H4631","in the cave",76,87],["H2603","Be merciful",89,100],["H0430","unto me, O God",101,115],["H2603","be merciful",117,128],["H5315","unto me: for my soul",129,149],["H2620","trusteth",150,158],["H6738","in thee: yea, in the shadow",159,186],["H3671","of thy wings",187,199],["H2620","will I make my refuge",200,221],["H1942","until these calamities",223,245],["H5674","be overpast",246,257]]},"57:2":{"text":"I will cry unto God most high; unto God that performeth all things for me.","words":[["H7121","I will cry",0,10],["H0430","unto God",11,19],["H5945","most high",20,29],["H0410","unto God",31,39],["H1584","that performeth",40,55]]},"57:3":{"text":"He shall send from heaven, and save me from the reproach of him that would swallow me up. Selah. God shall send forth his mercy and his truth.","words":[["H7971","He shall send",0,13],["H8064","from heaven",14,25],["H3467","and save",27,35],["H2778","me from the reproach",36,56],["H7602","of him that would swallow me up",57,88],["H5542","Selah",90,95],["H0430","God",97,100],["H7971","shall send forth",101,117],["H2617","his mercy",118,127],["H0571","and his truth",128,141]]},"57:4":{"text":"My soul is among lions: and I lie even among them that are set on fire, even the sons of men, whose teeth are spears and arrows, and their tongue a sharp sword.","words":[["H5315","My soul",0,7],["H8432","is among",8,16],["H3833","lions",17,22],["H7901","and I lie",24,33],["H3857","even among them that are set on fire",34,70],["H1121","even the sons",72,85],["H0120","of men",86,92],["H8127","whose teeth",94,105],["H2595","are spears",106,116],["H2671","and arrows",117,127],["H3956","and their tongue",129,145],["H2299","a sharp",146,153],["H2719","sword",154,159]]},"57:5":{"text":"Be thou exalted, O God, above the heavens; let thy glory be above all the earth.","words":[["H7311","Be thou exalted",0,15],["H0430","O God",17,22],["H8064","above the heavens",24,41],["H3519","let thy glory",43,56],["H0776","be above all the earth",57,79]]},"57:6":{"text":"They have prepared a net for my steps; my soul is bowed down: they have digged a pit before me, into the midst whereof they are fallen themselves. Selah.","words":[["H3559","They have prepared",0,18],["H7568","a net",19,24],["H6471","for my steps",25,37],["H5315","my soul",39,46],["H3721","is bowed down",47,60],["H3738","they have digged",62,78],["H7882","a pit",79,84],["H6440","before",85,91],["H8432","me, into the midst",92,110],["H5307","whereof they are fallen",111,134],["H5542","themselves. Selah",135,152]]},"57:7":{"text":"My heart is fixed, O God, my heart is fixed: I will sing and give praise.","words":[["H3820","My heart",0,8],["H3559","is fixed",9,17],["H0430","O God",19,24],["H3820","my heart",26,34],["H3559","is fixed",35,43],["H7891","I will sing",45,56],["H2167","and give praise",57,72]]},"57:8":{"text":"Awake up, my glory; awake, psaltery and harp: I myself will awake early.","words":[["H5782","Awake up",0,8],["H3519","my glory",10,18],["H5782","awake",20,25],["H5035","psaltery",27,35],["H3658","and harp",36,44],["H5782","I myself will awake",46,65],["H7837","early",66,71]]},"57:9":{"text":"I will praise thee, O Lord, among the people: I will sing unto thee among the nations.","words":[["H3034","I will praise",0,13],["H0136","thee, O Lord",14,26],["H5971","among the people",28,44],["H2167","I will sing",46,57],["H3816","unto thee among the nations",58,85]]},"57:10":{"text":"For thy mercy is great unto the heavens, and thy truth unto the clouds.","words":[["H2617","For thy mercy",0,13],["H1419","is great",14,22],["H8064","unto the heavens",23,39],["H0571","and thy truth",41,54],["H7834","unto the clouds",55,70]]},"57:11":{"text":"Be thou exalted, O God, above the heavens: let thy glory be above all the earth.","words":[["H7311","Be thou exalted",0,15],["H0430","O God",17,22],["H8064","above the heavens",24,41],["H3519","let thy glory",43,56],["H0776","be above all the earth",57,79]]},"58:1":{"text":"To the chief Musician, Altaschith, Michtam of David. Do ye indeed speak righteousness, O congregation? do ye judge uprightly, O ye sons of men?","words":[["H5329","To the chief Musician",0,21],["H0516","Altaschith",23,33],["H4387","Michtam",35,42],["H1732","of David",43,51],["H0552","Do ye indeed",53,65],["H1696","speak",66,71],["H6664","righteousness",72,85],["H0482","O congregation",87,101],["H8199","do ye judge",103,114],["H4339","uprightly",115,124],["H1121","O ye sons",126,135],["H0120","of men",136,142]]},"58:2":{"text":"Yea, in heart ye work wickedness; ye weigh the violence of your hands in the earth.","words":[["H3820","Yea, in heart",0,13],["H6466","ye work",14,21],["H5766","wickedness",22,32],["H6424","ye weigh",34,42],["H2555","the violence",43,55],["H3027","of your hands",56,69],["H0776","in the earth",70,82]]},"58:3":{"text":"The wicked are estranged from the womb: they go astray as soon as they be born, speaking lies.","words":[["H7563","The wicked",0,10],["H2114","are estranged",11,24],["H7358","from the womb",25,38],["H8582","they go astray",40,54],["H0990","as soon as they be born",55,78],["H1696","speaking",80,88],["H3577","lies",89,93]]},"58:4":{"text":"Their poison is like the poison of a serpent: they are like the deaf adder that stoppeth her ear;","words":[["H2534","Their poison",0,12],["H1823","is like",13,20],["H2534","the poison",21,31],["H5175","of a serpent",32,44],["H2795","they are like the deaf",46,68],["H6620","adder",69,74],["H0331","that stoppeth",75,88],["H0241","her ear",89,96]]},"58:5":{"text":"Which will not hearken to the voice of charmers, charming never so wisely.","words":[["H8085","Which will not hearken",0,22],["H6963","to the voice",23,35],["H3907","of charmers",36,47],["H2266","charming",49,57],["H2267","charming",49,57],["H2449","never so wisely",58,73]]},"58:6":{"text":"Break their teeth, O God, in their mouth: break out the great teeth of the young lions, O LORD.","words":[["H2040","Break",0,5],["H8127","their teeth",6,17],["H0430","O God",19,24],["H6310","in their mouth",26,40],["H5422","break out",42,51],["H4459","the great teeth",52,67],["H3715","of the young lions",68,86],["H3068","O LORD",88,94]]},"58:7":{"text":"Let them melt away as waters which run continually: when he bendeth his bow to shoot his arrows, let them be as cut in pieces.","words":[["H3988","Let them melt away",0,18],["H4325","as waters",19,28],["H1980","which run continually",29,50],["H1869","when he bendeth",52,67],["H2671","his bow to shoot his arrows",68,95],["H4135","let them be as cut in pieces",97,125]]},"58:8":{"text":"As a snail which melteth, let every one of them pass away: like the untimely birth of a woman, that they may not see the sun.","words":[["H7642","As a snail",0,10],["H8557","which melteth",11,24],["H1980","let every one of them pass away",26,57],["H5309","like the untimely birth",59,82],["H0802","of a woman",83,93],["H2372","that they may not see",95,116],["H8121","the sun",117,124]]},"58:9":{"text":"Before your pots can feel the thorns, he shall take them away as with a whirlwind, both living, and in his wrath.","words":[["H5518","Before your pots",0,16],["H0995","can feel",17,25],["H0329","the thorns",26,36],["H8175","he shall take them away as with a whirlwind",38,81],["H2416","both living",83,94],["H2740","and in his wrath",96,112]]},"58:10":{"text":"The righteous shall rejoice when he seeth the vengeance: he shall wash his feet in the blood of the wicked.","words":[["H6662","The righteous",0,13],["H8055","shall rejoice",14,27],["H2372","when he seeth",28,41],["H5359","the vengeance",42,55],["H7364","he shall wash",57,70],["H6471","his feet",71,79],["H1818","in the blood",80,92],["H7563","of the wicked",93,106]]},"58:11":{"text":"So that a man shall say, Verily there is a reward for the righteous: verily he is a God that judgeth in the earth.","words":[["H0120","So that a man",0,13],["H0559","shall say",14,23],["H6529","Verily there is a reward",25,49],["H6662","for the righteous",50,67],["H3426","verily he is",69,81],["H0430","a God",82,87],["H8199","that judgeth",88,100],["H0776","in the earth",101,113]]},"59:1":{"text":"To the chief Musician, Altaschith, Michtam of David; when Saul sent, and they watched the house to kill him. Deliver me from mine enemies, O my God: defend me from them that rise up against me.","words":[["H5329","To the chief Musician",0,21],["H0516","Altaschith",23,33],["H4387","Michtam",35,42],["H1732","of David",43,51],["H7586","when Saul",53,62],["H7971","sent",63,67],["H8104","and they watched",69,85],["H1004","the house",86,95],["H4191","to kill him",96,107],["H5337","Deliver",109,116],["H0341","me from mine enemies",117,137],["H0430","O my God",139,147],["H7682","defend",149,155],["H6965","me from them that rise up",156,181]]},"59:2":{"text":"Deliver me from the workers of iniquity, and save me from bloody men.","words":[["H5337","Deliver",0,7],["H6466","me from the workers",8,27],["H0205","of iniquity",28,39],["H3467","and save",41,49],["H1818","me from bloody",50,64],["H0582","men",65,68]]},"59:3":{"text":"For, lo, they lie in wait for my soul: the mighty are gathered against me; not for my transgression, nor for my sin, O LORD.","words":[["H0693","For, lo, they lie in wait",0,25],["H5315","for my soul",26,37],["H5794","the mighty",39,49],["H1481","are gathered",50,62],["H6588","against me; not for my transgression",63,99],["H2403","nor for my sin",101,115],["H3068","O LORD",117,123]]},"59:4":{"text":"They run and prepare themselves without my fault: awake to help me, and behold.","words":[["H7323","They run",0,8],["H3559","and prepare",9,20],["H5771","themselves without my fault",21,48],["H5782","awake",50,55],["H7125","to help",56,63],["H7200","me, and behold",64,78]]},"59:5":{"text":"Thou therefore, O LORD God of hosts, the God of Israel, awake to visit all the heathen: be not merciful to any wicked transgressors. Selah.","words":[["H3068","Thou therefore, O LORD",0,22],["H0430","God",23,26],["H6635","of hosts",27,35],["H0430","the God",37,44],["H3478","of Israel",45,54],["H6974","awake",56,61],["H6485","to visit",62,70],["H1471","all the heathen",71,86],["H2603","be not merciful",88,103],["H0205","to any wicked",104,117],["H0898","transgressors",118,131],["H5542","Selah",133,138]]},"59:6":{"text":"They return at evening: they make a noise like a dog, and go round about the city.","words":[["H7725","They return",0,11],["H6153","at evening",12,22],["H1993","they make a noise",24,41],["H3611","like a dog",42,52],["H5437","and go round about",54,72],["H5892","the city",73,81]]},"59:7":{"text":"Behold, they belch out with their mouth: swords are in their lips: for who, say they, doth hear?","words":[["H5042","Behold, they belch out",0,22],["H6310","with their mouth",23,39],["H2719","swords",41,47],["H8193","are in their lips",48,65],["H8085","for who, say they, doth hear",67,95]]},"59:8":{"text":"But thou, O LORD, shalt laugh at them; thou shalt have all the heathen in derision.","words":[["H3068","But thou, O LORD",0,16],["H7832","shalt laugh",18,29],["H1471","at them; thou shalt have all the heathen",30,70],["H3932","in derision",71,82]]},"59:9":{"text":"Because of his strength will I wait upon thee: for God is my defence.","words":[["H5797","Because of his strength",0,23],["H8104","will I wait",24,35],["H0430","upon thee: for God",36,54],["H4869","is my defence",55,68]]},"59:10":{"text":"The God of my mercy shall prevent me: God shall let me see my desire upon mine enemies.","words":[["H0430","The God",0,7],["H2617","of my mercy",8,19],["H6923","shall prevent",20,33],["H0430","me: God",34,41],["H7200","shall let me see",42,58],["H8324","my desire upon mine enemies",59,86]]},"59:11":{"text":"Slay them not, lest my people forget: scatter them by thy power; and bring them down, O Lord our shield.","words":[["H2026","Slay",0,4],["H5971","them not, lest my people",5,29],["H7911","forget",30,36],["H5128","scatter",38,45],["H2428","them by thy power",46,63],["H3381","and bring them down",65,84],["H0136","O Lord",86,92],["H4043","our shield",93,103]]},"59:12":{"text":"For the sin of their mouth and the words of their lips let them even be taken in their pride: and for cursing and lying which they speak.","words":[["H2403","For the sin",0,11],["H6310","of their mouth",12,26],["H1697","and the words",27,40],["H8193","of their lips",41,54],["H3920","let them even be taken",55,77],["H1347","in their pride",78,92],["H0423","and for cursing",94,109],["H3585","and lying",110,119],["H5608","which they speak",120,136]]},"59:13":{"text":"Consume them in wrath, consume them, that they may not be: and let them know that God ruleth in Jacob unto the ends of the earth. Selah.","words":[["H3615","Consume",0,7],["H2534","them in wrath",8,21],["H3615","consume",23,30],["H3045","them, that they may not be: and let them know",31,76],["H0430","that God",77,85],["H4910","ruleth",86,92],["H3290","in Jacob",93,101],["H0657","unto the ends",102,115],["H0776","of the earth",116,128],["H5542","Selah",130,135]]},"59:14":{"text":"And at evening let them return; and let them make a noise like a dog, and go round about the city.","words":[["H6153","And at evening",0,14],["H7725","let them return",15,30],["H1993","and let them make a noise",32,57],["H3611","like a dog",58,68],["H5437","and go round about",70,88],["H5892","the city",89,97]]},"59:15":{"text":"Let them wander up and down for meat, and grudge if they be not satisfied.","words":[["H5128","Let them wander up and down",0,27],["H5128","Let them wander up and down",0,27],["H0398","for meat",28,36],["H3885","and grudge",38,48],["H7646","if they be not satisfied",49,73]]},"59:16":{"text":"But I will sing of thy power; yea, I will sing aloud of thy mercy in the morning: for thou hast been my defence and refuge in the day of my trouble.","words":[["H7891","But I will sing",0,15],["H5797","of thy power",16,28],["H7442","yea, I will sing aloud",30,52],["H2617","of thy mercy",53,65],["H1242","in the morning",66,80],["H4869","for thou hast been my defence",82,111],["H4498","and refuge",112,122],["H3117","in the day",123,133],["H6862","of my trouble",134,147]]},"59:17":{"text":"Unto thee, O my strength, will I sing: for God is my defence, and the God of my mercy.","words":[["H5797","Unto thee, O my strength",0,24],["H2167","will I sing",26,37],["H0430","for God",39,46],["H4869","is my defence",47,60],["H0430","and the God",62,73],["H2617","of my mercy",74,85]]},"60:1":{"text":"To the chief Musician upon Shushaneduth, Michtam of David, to teach; when he strove with Aramnaharaim and with Aramzobah, when Joab returned, and smote of Edom in the valley of salt twelve thousand. O God, thou hast cast us off, thou hast scattered us, thou hast been displeased; O turn thyself to us again.","words":[["H5329","To the chief Musician",0,21],["H7802","upon Shushaneduth",22,39],["H4387","Michtam",41,48],["H1732","of David",49,57],["H3925","to teach",59,67],["H5327","when he strove",69,83],["H0763","with Aramnaharaim",84,101],["H5104","with Aramnaharaim",84,101],["H0760","and with Aramzobah",102,120],["H3097","when Joab",122,131],["H7725","returned",132,140],["H5221","and smote",142,151],["H0123","of Edom",152,159],["H1516","in the valley",160,173],["H4417","of salt",174,181],["H8147","twelve",182,188],["H6240","twelve",182,188],["H0505","thousand",189,197],["H0430","O God",199,204],["H2186","thou hast cast us off",206,227],["H6555","thou hast scattered",229,248],["H0599","us, thou hast been displeased",249,278],["H7725","O turn thyself to us again",280,306]]},"60:2":{"text":"Thou hast made the earth to tremble; thou hast broken it: heal the breaches thereof; for it shaketh.","words":[["H0776","Thou hast made the earth",0,24],["H7493","to tremble",25,35],["H6480","thou hast broken",37,53],["H7495","it: heal",54,62],["H7667","the breaches",63,75],["H4131","thereof; for it shaketh",76,99]]},"60:3":{"text":"Thou hast shewed thy people hard things: thou hast made us to drink the wine of astonishment.","words":[["H7200","Thou hast shewed",0,16],["H5971","thy people",17,27],["H7186","hard things",28,39],["H8248","thou hast made us to drink",41,67],["H3196","the wine",68,76],["H8653","of astonishment",77,92]]},"60:4":{"text":"Thou hast given a banner to them that fear thee, that it may be displayed because of the truth. Selah.","words":[["H5414","Thou hast given",0,15],["H5251","a banner",16,24],["H3373","to them that fear",25,42],["H5127","thee, that it may be displayed",43,73],["H6440","because",74,81],["H7189","of the truth",82,94],["H5542","Selah",96,101]]},"60:5":{"text":"That thy beloved may be delivered; save with thy right hand, and hear me.","words":[["H3039","That thy beloved",0,16],["H2502","may be delivered",17,33],["H3467","save",35,39],["H3225","with thy right hand",40,59],["H6030","and hear",61,69]]},"60:6":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth.","words":[["H0430","God",0,3],["H1696","hath spoken",4,15],["H6944","in his holiness",16,31],["H5937","I will rejoice",33,47],["H2505","I will divide",49,62],["H7927","Shechem",63,70],["H4058","and mete out",72,84],["H6010","the valley",85,95],["H5523","of Succoth",96,106]]},"60:7":{"text":"Gilead is mine, and Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;","words":[["H1568","Gilead",0,6],["H4519","is mine, and Manasseh",7,28],["H0669","is mine; Ephraim",29,45],["H4581","also is the strength",46,66],["H7218","of mine head",67,79],["H3063","Judah",81,86],["H2710","is my lawgiver",87,101]]},"60:8":{"text":"Moab is my washpot; over Edom will I cast out my shoe: Philistia, triumph thou because of me.","words":[["H4124","Moab",0,4],["H5518","is my washpot",5,18],["H7366","is my washpot",5,18],["H0123","over Edom",20,29],["H7993","will I cast out",30,45],["H5275","my shoe",46,53],["H6429","Philistia",55,64],["H7321","triumph",66,73]]},"60:9":{"text":"Who will bring me into the strong city? who will lead me into Edom?","words":[["H2986","Who will bring",0,14],["H4692","me into the strong",15,33],["H5892","city",34,38],["H5148","who will lead",40,53],["H0123","me into Edom",54,66]]},"60:10":{"text":"Wilt not thou, O God, which hadst cast us off? and thou, O God, which didst not go out with our armies?","words":[["H0430","Wilt not thou, O God",0,20],["H2186","which hadst cast us off",22,45],["H0430","and thou, O God",47,62],["H3318","which didst not go out",64,86],["H6635","with our armies",87,102]]},"60:11":{"text":"Give us help from trouble: for vain is the help of man.","words":[["H3051","Give",0,4],["H5833","us help",5,12],["H6862","from trouble",13,25],["H7723","for vain",27,35],["H8668","is the help",36,47],["H0120","of man",48,54]]},"60:12":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies.","words":[["H0430","Through God",0,11],["H6213","we shall do",12,23],["H2428","valiantly",24,33],["H0947","for he it is that shall tread down",35,69],["H6862","our enemies",70,81]]},"61:1":{"text":"To the chief Musician upon Neginah, A Psalm of David. Hear my cry, O God; attend unto my prayer.","words":[["H5329","To the chief Musician",0,21],["H5058","upon Neginah",22,34],["H1732","A Psalm of David",36,52],["H8085","Hear",54,58],["H7440","my cry",59,65],["H0430","O God",67,72],["H7181","attend",74,80],["H8605","unto my prayer",81,95]]},"61:2":{"text":"From the end of the earth will I cry unto thee, when my heart is overwhelmed: lead me to the rock that is higher than I.","words":[["H7097","From the end",0,12],["H0776","of the earth",13,25],["H7121","will I cry",26,36],["H3820","unto thee, when my heart",37,61],["H5848","is overwhelmed",62,76],["H5148","lead",78,82],["H6697","me to the rock",83,97],["H7311","that is higher",98,112]]},"61:3":{"text":"For thou hast been a shelter for me, and a strong tower from the enemy.","words":[["H4268","For thou hast been a shelter",0,28],["H5797","for me, and a strong",29,49],["H4026","tower",50,55],["H6440","from",56,60],["H0341","the enemy",61,70]]},"61:4":{"text":"I will abide in thy tabernacle for ever: I will trust in the covert of thy wings. Selah.","words":[["H1481","I will abide",0,12],["H0168","in thy tabernacle",13,30],["H5769","for ever",31,39],["H2620","I will trust",41,53],["H5643","in the covert",54,67],["H3671","of thy wings",68,80],["H5542","Selah",82,87]]},"61:5":{"text":"For thou, O God, hast heard my vows: thou hast given me the heritage of those that fear thy name.","words":[["H0430","For thou, O God",0,15],["H8085","hast heard",17,27],["H5088","my vows",28,35],["H5414","thou hast given",37,52],["H3425","me the heritage",53,68],["H3373","of those that fear",69,87],["H8034","thy name",88,96]]},"61:6":{"text":"Thou wilt prolong the king's life: and his years as many generations.","words":[["H3254","Thou wilt prolong",0,17],["H4428","the king's",18,28],["H3117","life",29,33],["H3117","life",29,33],["H8141","and his years",35,48],["H1755","as many",49,56],["H1755","generations",57,68]]},"61:7":{"text":"He shall abide before God for ever: O prepare mercy and truth, which may preserve him.","words":[["H3427","He shall abide",0,14],["H6440","before",15,21],["H0430","God",22,25],["H5769","for ever",26,34],["H4487","O prepare",36,45],["H2617","mercy",46,51],["H0571","and truth",52,61],["H5341","which may preserve",63,81]]},"61:8":{"text":"So will I sing praise unto thy name for ever, that I may daily perform my vows.","words":[["H2167","So will I sing",0,14],["H8034","praise unto thy name",15,35],["H5703","for ever",36,44],["H3117","that I may daily",46,62],["H3117","that I may daily",46,62],["H7999","perform",63,70],["H5088","my vows",71,78]]},"62:1":{"text":"To the chief Musician, to Jeduthun, A Psalm of David. Truly my soul waiteth upon God: from him cometh my salvation.","words":[["H5329","To the chief Musician",0,21],["H3038","to Jeduthun",23,34],["H4210","A Psalm",36,43],["H1732","of David",44,52],["H5315","Truly my soul",54,67],["H1747","waiteth",68,75],["H0430","upon God",76,84],["H3444","from him cometh my salvation",86,114]]},"62:2":{"text":"He only is my rock and my salvation; he is my defence; I shall not be greatly moved.","words":[["H6697","He only is my rock",0,18],["H3444","and my salvation",19,35],["H4869","he is my defence",37,53],["H7227","I shall not be greatly",55,77],["H4131","moved",78,83]]},"62:3":{"text":"How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence.","words":[["H2050","How long will ye imagine mischief",0,33],["H0376","against a man",34,47],["H7523","ye shall be slain",49,66],["H5186","all of you: as a bowing",67,90],["H7023","wall",91,95],["H1760","shall ye be, and as a tottering",96,127],["H1447","fence",128,133]]},"62:4":{"text":"They only consult to cast him down from his excellency: they delight in lies: they bless with their mouth, but they curse inwardly. Selah.","words":[["H3289","They only consult",0,17],["H5080","to cast him down",18,34],["H7613","from his excellency",35,54],["H7521","they delight",56,68],["H3577","in lies",69,76],["H1288","they bless",78,88],["H6310","with their mouth",89,105],["H7043","but they curse",107,121],["H7130","inwardly",122,130],["H5542","Selah",132,137]]},"62:5":{"text":"My soul, wait thou only upon God; for my expectation is from him.","words":[["H5315","My soul",0,7],["H1826","wait",9,13],["H0430","thou only upon God",14,32],["H8615","for my expectation",34,52]]},"62:6":{"text":"He only is my rock and my salvation: he is my defence; I shall not be moved.","words":[["H6697","He only is my rock",0,18],["H3444","and my salvation",19,35],["H4869","he is my defence",37,53],["H4131","I shall not be moved",55,75]]},"62:7":{"text":"In God is my salvation and my glory: the rock of my strength, and my refuge, is in God.","words":[["H0430","In God",0,6],["H3468","is my salvation",7,22],["H3519","and my glory",23,35],["H6697","the rock",37,45],["H5797","of my strength",46,60],["H4268","and my refuge",62,75],["H0430","is in God",77,86]]},"62:8":{"text":"Trust in him at all times; ye people, pour out your heart before him: God is a refuge for us. Selah.","words":[["H0982","Trust",0,5],["H6256","in him at all times",6,25],["H5971","ye people",27,36],["H8210","pour out",38,46],["H3824","your heart",47,57],["H6440","before",58,64],["H0430","him: God",65,73],["H4268","is a refuge",74,85],["H5542","for us. Selah",86,99]]},"62:9":{"text":"Surely men of low degree are vanity, and men of high degree are a lie: to be laid in the balance, they are altogether lighter than vanity.","words":[["H0120","Surely men",0,10],["H1121","Surely men",0,10],["H1892","of low degree are vanity",11,35],["H0376","and men",37,44],["H3577","of high degree are a lie",45,69],["H5927","to be laid",71,81],["H3976","in the balance",82,96],["H3162","they are altogether",98,117],["H1892","lighter than vanity",118,137]]},"62:10":{"text":"Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them.","words":[["H0982","Trust",0,5],["H6233","not in oppression",6,23],["H1891","and become not vain",25,44],["H1498","in robbery",45,55],["H2428","if riches",57,66],["H5107","increase",67,75],["H7896","set",77,80],["H3820","not your heart",81,95]]},"62:11":{"text":"God hath spoken once; twice have I heard this; that power belongeth unto God.","words":[["H0430","God",0,3],["H1696","hath spoken",4,15],["H0259","once",16,20],["H8147","twice",22,27],["H8085","have I heard",28,40],["H2098","this",41,45],["H5797","that power",47,57],["H0430","belongeth unto God",58,76]]},"62:12":{"text":"Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work.","words":[["H0136","Also unto thee, O Lord",0,22],["H2617","belongeth mercy",24,39],["H7999","for thou renderest",41,59],["H0376","to every man",60,72],["H4639","according to his work",73,94]]},"63:1":{"text":"A Psalm of David, when he was in the wilderness of Judah. O God, thou art my God; early will I seek thee: my soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land, where no water is;","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H4057","when he was in the wilderness",18,47],["H3063","of Judah",48,56],["H0430","O God",58,63],["H0410","thou art my God",65,80],["H7836","early will I seek",82,99],["H5315","thee: my soul",100,113],["H6770","thirsteth",114,123],["H1320","for thee, my flesh",124,142],["H3642","longeth",143,150],["H6723","for thee in a dry",151,168],["H5889","and thirsty",169,180],["H0776","land",181,185],["H1097","where no",187,195],["H4325","water",196,201]]},"63:2":{"text":"To see thy power and thy glory, so as I have seen thee in the sanctuary.","words":[["H7200","To see",0,6],["H5797","thy power",7,16],["H3519","and thy glory",17,30],["H2372","so as I have seen",32,49],["H6944","thee in the sanctuary",50,71]]},"63:3":{"text":"Because thy lovingkindness is better than life, my lips shall praise thee.","words":[["H2617","Because thy lovingkindness",0,26],["H2896","is better",27,36],["H2416","than life",37,46],["H8193","my lips",48,55],["H7623","shall praise",56,68]]},"63:4":{"text":"Thus will I bless thee while I live: I will lift up my hands in thy name.","words":[["H1288","Thus will I bless",0,17],["H2416","thee while I live",18,35],["H5375","I will lift up",37,51],["H3709","my hands",52,60],["H8034","in thy name",61,72]]},"63:5":{"text":"My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips:","words":[["H5315","My soul",0,7],["H7646","shall be satisfied",8,26],["H2459","as with marrow",27,41],["H1880","and fatness",42,53],["H6310","and my mouth",55,67],["H1984","shall praise",68,80],["H7445","thee with joyful",81,97],["H8193","lips",98,102]]},"63:6":{"text":"When I remember thee upon my bed, and meditate on thee in the night watches.","words":[["H2142","When I remember",0,15],["H3326","thee upon my bed",16,32],["H1897","and meditate",34,46],["H0821","on thee in the night watches",47,75]]},"63:7":{"text":"Because thou hast been my help, therefore in the shadow of thy wings will I rejoice.","words":[["H5833","Because thou hast been my help",0,30],["H6738","therefore in the shadow",32,55],["H3671","of thy wings",56,68],["H7442","will I rejoice",69,83]]},"63:8":{"text":"My soul followeth hard after thee: thy right hand upholdeth me.","words":[["H5315","My soul",0,7],["H1692","followeth hard",8,22],["H0310","after",23,28],["H3225","thee: thy right hand",29,49],["H8551","upholdeth",50,59]]},"63:9":{"text":"But those that seek my soul, to destroy it, shall go into the lower parts of the earth.","words":[["H1245","But those that seek",0,19],["H5315","my soul",20,27],["H7722","to destroy",29,39],["H0935","it, shall go",40,52],["H8482","into the lower parts",53,73],["H0776","of the earth",74,86]]},"63:10":{"text":"They shall fall by the sword: they shall be a portion for foxes.","words":[["H5064","They shall fall",0,15],["H3027","by the sword",16,28],["H2719","by the sword",16,28],["H4521","they shall be a portion",30,53],["H7776","for foxes",54,63]]},"63:11":{"text":"But the king shall rejoice in God; every one that sweareth by him shall glory: but the mouth of them that speak lies shall be stopped.","words":[["H4428","But the king",0,12],["H8055","shall rejoice",13,26],["H0430","in God",27,33],["H7650","every one that sweareth",35,58],["H1984","by him shall glory",59,77],["H6310","but the mouth",79,92],["H1696","of them that speak",93,111],["H8267","lies",112,116],["H5534","shall be stopped",117,133]]},"64:1":{"text":"To the chief Musician, A Psalm of David. Hear my voice, O God, in my prayer: preserve my life from fear of the enemy.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H8085","Hear",41,45],["H6963","my voice",46,54],["H0430","O God",56,61],["H7879","in my prayer",63,75],["H5341","preserve",77,85],["H2416","my life",86,93],["H6343","from fear",94,103],["H0341","of the enemy",104,116]]},"64:2":{"text":"Hide me from the secret counsel of the wicked; from the insurrection of the workers of iniquity:","words":[["H5641","Hide",0,4],["H5475","me from the secret counsel",5,31],["H7489","of the wicked",32,45],["H7285","from the insurrection",47,68],["H6466","of the workers",69,83],["H0205","of iniquity",84,95]]},"64:3":{"text":"Who whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words:","words":[["H8150","Who whet",0,8],["H3956","their tongue",9,21],["H2719","like a sword",22,34],["H1869","and bend",36,44],["H2671","their bows to shoot their arrows",45,77],["H4751","even bitter",79,90],["H1697","words",91,96]]},"64:4":{"text":"That they may shoot in secret at the perfect: suddenly do they shoot at him, and fear not.","words":[["H3384","That they may shoot",0,19],["H4565","in secret",20,29],["H8535","at the perfect",30,44],["H6597","suddenly",46,54],["H3384","do they shoot",55,68],["H3372","at him, and fear",69,85]]},"64:5":{"text":"They encourage themselves in an evil matter: they commune of laying snares privily; they say, Who shall see them?","words":[["H2388","They encourage",0,14],["H7451","themselves in an evil",15,36],["H1697","matter",37,43],["H5608","they commune",45,57],["H2934","of laying",58,67],["H4170","snares",68,74],["H2934","privily",75,82],["H0559","they say",84,92],["H7200","Who shall see",94,107]]},"64:6":{"text":"They search out iniquities; they accomplish a diligent search: both the inward thought of every one of them, and the heart, is deep.","words":[["H2664","They search out",0,15],["H5766","iniquities",16,26],["H8552","they accomplish",28,43],["H2664","a diligent",44,54],["H2665","search",55,61],["H7130","both the inward",63,78],["H0376","thought of every one",79,99],["H3820","of them, and the heart",100,122],["H6013","is deep",124,131]]},"64:7":{"text":"But God shall shoot at them with an arrow; suddenly shall they be wounded.","words":[["H0430","But God",0,7],["H3384","shall shoot",8,19],["H2671","at them with an arrow",20,41],["H6597","suddenly",43,51],["H4347","shall they be wounded",52,73]]},"64:8":{"text":"So they shall make their own tongue to fall upon themselves: all that see them shall flee away.","words":[["H3956","So they shall make their own tongue",0,35],["H3782","to fall",36,43],["H7200","upon themselves: all that see",44,73],["H5074","them shall flee away",74,94]]},"64:9":{"text":"And all men shall fear, and shall declare the work of God; for they shall wisely consider of his doing.","words":[["H0120","And all men",0,11],["H3372","shall fear",12,22],["H5046","and shall declare",24,41],["H6467","the work",42,50],["H0430","of God",51,57],["H7919","for they shall wisely consider",59,89],["H4639","of his doing",90,102]]},"64:10":{"text":"The righteous shall be glad in the LORD, and shall trust in him; and all the upright in heart shall glory.","words":[["H6662","The righteous",0,13],["H8055","shall be glad",14,27],["H3068","in the LORD",28,39],["H2620","and shall trust",41,56],["H3477","in him; and all the upright",57,84],["H3820","in heart",85,93],["H1984","shall glory",94,105]]},"65:1":{"text":"To the chief Musician, A Psalm and Song of David. Praise waiteth for thee, O God, in Sion: and unto thee shall the vow be performed.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H7892","and Song",31,39],["H1732","of David",40,48],["H8416","Praise",50,56],["H1747","waiteth",57,64],["H0430","for thee, O God",65,80],["H6726","in Sion",82,89],["H5088","and unto thee shall the vow",91,118],["H7999","be performed",119,131]]},"65:2":{"text":"O thou that hearest prayer, unto thee shall all flesh come.","words":[["H8085","O thou that hearest",0,19],["H8605","prayer",20,26],["H1320","unto thee shall all flesh",28,53],["H0935","come",54,58]]},"65:3":{"text":"Iniquities prevail against me: as for our transgressions, thou shalt purge them away.","words":[["H1697","Iniquities",0,10],["H5771","Iniquities",0,10],["H1396","prevail",11,18],["H6588","against me: as for our transgressions",19,56],["H3722","thou shalt purge them away",58,84]]},"65:4":{"text":"Blessed is the man whom thou choosest, and causest to approach unto thee, that he may dwell in thy courts: we shall be satisfied with the goodness of thy house, even of thy holy temple.","words":[["H0835","Blessed",0,7],["H0977","is the man whom thou choosest",8,37],["H7126","and causest to approach",39,62],["H7931","unto thee, that he may dwell",63,91],["H2691","in thy courts",92,105],["H7646","we shall be satisfied",107,128],["H2898","with the goodness",129,146],["H1004","of thy house",147,159],["H6918","even of thy holy",161,177],["H1964","temple",178,184]]},"65:5":{"text":"By terrible things in righteousness wilt thou answer us, O God of our salvation; who art the confidence of all the ends of the earth, and of them that are afar off upon the sea:","words":[["H3372","By terrible things",0,18],["H6664","in righteousness",19,35],["H6030","wilt thou answer",36,52],["H0430","us, O God",53,62],["H3468","of our salvation",63,79],["H4009","who art the confidence",81,103],["H7099","of all the ends",104,119],["H0776","of the earth",120,132],["H7350","and of them that are afar off",134,163],["H3220","upon the sea",164,176]]},"65:6":{"text":"Which by his strength setteth fast the mountains; being girded with power:","words":[["H3581","Which by his strength",0,21],["H3559","setteth fast",22,34],["H2022","the mountains",35,48],["H0247","being girded",50,62],["H1369","with power",63,73]]},"65:7":{"text":"Which stilleth the noise of the seas, the noise of their waves, and the tumult of the people.","words":[["H7623","Which stilleth",0,14],["H7588","the noise",15,24],["H3220","of the seas",25,36],["H7588","the noise",38,47],["H1530","of their waves",48,62],["H1995","and the tumult",64,78],["H3816","of the people",79,92]]},"65:8":{"text":"They also that dwell in the uttermost parts are afraid at thy tokens: thou makest the outgoings of the morning and evening to rejoice.","words":[["H3427","They also that dwell",0,20],["H7099","in the uttermost parts",21,43],["H3372","are afraid",44,54],["H0226","at thy tokens",55,68],["H4161","thou makest the outgoings",70,95],["H1242","of the morning",96,110],["H6153","and evening",111,122],["H7442","to rejoice",123,133]]},"65:9":{"text":"Thou visitest the earth, and waterest it: thou greatly enrichest it with the river of God, which is full of water: thou preparest them corn, when thou hast so provided for it.","words":[["H6485","Thou visitest",0,13],["H0776","the earth",14,23],["H7783","and waterest",25,37],["H7227","it: thou greatly",38,54],["H6238","enrichest",55,64],["H6388","it with the river",65,82],["H0430","of God",83,89],["H4390","which is full",91,104],["H4325","of water",105,113],["H3559","thou preparest",115,129],["H1715","them corn",130,139],["H3559","when thou hast so provided",141,167]]},"65:10":{"text":"Thou waterest the ridges thereof abundantly: thou settlest the furrows thereof: thou makest it soft with showers: thou blessest the springing thereof.","words":[["H7301","Thou waterest",0,13],["H8525","the ridges",14,24],["H7301","thereof abundantly",25,43],["H5181","thou settlest",45,58],["H1417","the furrows",59,70],["H1418","the furrows",59,70],["H4127","thereof: thou makest it soft",71,99],["H7241","with showers",100,112],["H1288","thou blessest",114,127],["H6780","the springing",128,141]]},"65:11":{"text":"Thou crownest the year with thy goodness; and thy paths drop fatness.","words":[["H5849","Thou crownest",0,13],["H8141","the year",14,22],["H2896","with thy goodness",23,40],["H4570","and thy paths",42,55],["H7491","drop",56,60],["H1880","fatness",61,68]]},"65:12":{"text":"They drop upon the pastures of the wilderness: and the little hills rejoice on every side.","words":[["H7491","They drop",0,9],["H4999","upon the pastures",10,27],["H4057","of the wilderness",28,45],["H1389","and the little hills",47,67],["H1524","rejoice",68,75],["H2296","on every side",76,89]]},"65:13":{"text":"The pastures are clothed with flocks; the valleys also are covered over with corn; they shout for joy, they also sing.","words":[["H3733","The pastures",0,12],["H3847","are clothed",13,24],["H6629","with flocks",25,36],["H6010","the valleys",38,49],["H5848","also are covered over",50,71],["H1250","with corn",72,81],["H7321","they shout for joy",83,101],["H7891","they also sing",103,117]]},"66:1":{"text":"To the chief Musician, A Song or Psalm. Make a joyful noise unto God, all ye lands:","words":[["H5329","To the chief Musician",0,21],["H7892","A Song",23,29],["H4210","or Psalm",30,38],["H7321","Make a joyful noise",40,59],["H0430","unto God",60,68],["H0776","all ye lands",70,82]]},"66:2":{"text":"Sing forth the honour of his name: make his praise glorious.","words":[["H2167","Sing forth",0,10],["H3519","the honour",11,21],["H8034","of his name",22,33],["H7760","make",35,39],["H8416","his praise",40,50],["H3519","glorious",51,59]]},"66:3":{"text":"Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee.","words":[["H0559","Say",0,3],["H0430","unto God",4,12],["H3372","How terrible",14,26],["H4639","art thou in thy works",27,48],["H7230","through the greatness",50,71],["H5797","of thy power",72,84],["H0341","shall thine enemies",85,104],["H3584","submit",105,111]]},"66:4":{"text":"All the earth shall worship thee, and shall sing unto thee; they shall sing to thy name. Selah.","words":[["H0776","All the earth",0,13],["H7812","shall worship",14,27],["H2167","thee, and shall sing",28,48],["H2167","unto thee; they shall sing",49,75],["H8034","to thy name",76,87],["H5542","Selah",89,94]]},"66:5":{"text":"Come and see the works of God: he is terrible in his doing toward the children of men.","words":[["H3212","Come",0,4],["H7200","and see",5,12],["H4659","the works",13,22],["H0430","of God",23,29],["H3372","he is terrible",31,45],["H5949","in his doing",46,58],["H1121","toward the children",59,78],["H0120","of men",79,85]]},"66:6":{"text":"He turned the sea into dry land: they went through the flood on foot: there did we rejoice in him.","words":[["H2015","He turned",0,9],["H3220","the sea",10,17],["H3004","into dry",18,26],["H5674","land: they went",27,42],["H5104","through the flood",43,60],["H7272","on foot",61,68],["H8055","there did we rejoice",70,90]]},"66:7":{"text":"He ruleth by his power for ever; his eyes behold the nations: let not the rebellious exalt themselves. Selah.","words":[["H4910","He ruleth",0,9],["H1369","by his power",10,22],["H5769","for ever",23,31],["H5869","his eyes",33,41],["H6822","behold",42,48],["H1471","the nations",49,60],["H5637","let not the rebellious",62,84],["H7311","exalt",85,90],["H7311","exalt",85,90],["H5542","themselves. Selah",91,108]]},"66:8":{"text":"O bless our God, ye people, and make the voice of his praise to be heard:","words":[["H1288","O bless",0,7],["H0430","our God",8,15],["H5971","ye people",17,26],["H6963","and make the voice",28,46],["H8416","of his praise",47,60],["H8085","to be heard",61,72]]},"66:9":{"text":"Which holdeth our soul in life, and suffereth not our feet to be moved.","words":[["H7760","Which holdeth",0,13],["H5315","our soul",14,22],["H2416","in life",23,30],["H5414","and suffereth",32,45],["H7272","not our feet",46,58],["H4132","to be moved",59,70]]},"66:10":{"text":"For thou, O God, hast proved us: thou hast tried us, as silver is tried.","words":[["H0430","For thou, O God",0,15],["H0974","hast proved",17,28],["H6884","us: thou hast tried",29,48],["H3701","us, as silver",49,62],["H6884","is tried",63,71]]},"66:11":{"text":"Thou broughtest us into the net; thou laidst affliction upon our loins.","words":[["H0935","Thou broughtest",0,15],["H4686","us into the net",16,31],["H7760","thou laidst",33,44],["H4157","affliction",45,55],["H4975","upon our loins",56,70]]},"66:12":{"text":"Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place.","words":[["H0582","Thou hast caused men",0,20],["H7392","to ride",21,28],["H7218","over our heads",29,43],["H0935","we went",45,52],["H0784","through fire",53,65],["H4325","and through water",66,83],["H3318","but thou broughtest us out",85,111],["H7310","into a wealthy",112,126]]},"66:13":{"text":"I will go into thy house with burnt offerings: I will pay thee my vows,","words":[["H0935","I will go",0,9],["H1004","into thy house",10,24],["H5930","with burnt offerings",25,45],["H7999","I will pay",47,57],["H5088","thee my vows",58,70]]},"66:14":{"text":"Which my lips have uttered, and my mouth hath spoken, when I was in trouble.","words":[["H8193","Which my lips",0,13],["H6475","have uttered",14,26],["H6310","and my mouth",28,40],["H1696","hath spoken",41,52],["H6862","when I was in trouble",54,75]]},"66:15":{"text":"I will offer unto thee burnt sacrifices of fatlings, with the incense of rams; I will offer bullocks with goats. Selah.","words":[["H5927","I will offer",0,12],["H5930","unto thee burnt sacrifices",13,39],["H4220","of fatlings",40,51],["H7004","with the incense",53,69],["H0352","of rams",70,77],["H6213","I will offer",79,91],["H1241","bullocks",92,100],["H6260","with goats",101,111],["H5542","Selah",113,118]]},"66:16":{"text":"Come and hear, all ye that fear God, and I will declare what he hath done for my soul.","words":[["H3212","Come",0,4],["H8085","and hear",5,13],["H3373","all ye that fear",15,31],["H0430","God",32,35],["H5608","and I will declare",37,55],["H6213","what he hath done",56,73],["H5315","for my soul",74,85]]},"66:17":{"text":"I cried unto him with my mouth, and he was extolled with my tongue.","words":[["H7121","I cried",0,7],["H6310","unto him with my mouth",8,30],["H7311","and he was extolled",32,51],["H7318","and he was extolled",32,51],["H8478","with",52,56],["H3956","my tongue",57,66]]},"66:18":{"text":"If I regard iniquity in my heart, the Lord will not hear me:","words":[["H7200","If I regard",0,11],["H0205","iniquity",12,20],["H3820","in my heart",21,32],["H0136","the Lord",34,42],["H8085","will not hear",43,56]]},"66:19":{"text":"But verily God hath heard me; he hath attended to the voice of my prayer.","words":[["H0403","But verily",0,10],["H0430","God",11,14],["H8085","hath heard",15,25],["H7181","me; he hath attended",26,46],["H6963","to the voice",47,59],["H8605","of my prayer",60,72]]},"66:20":{"text":"Blessed be God, which hath not turned away my prayer, nor his mercy from me.","words":[["H1288","Blessed",0,7],["H0430","be God",8,14],["H5493","which hath not turned away",16,42],["H8605","my prayer",43,52],["H2617","nor his mercy",54,67]]},"67:1":{"text":"To the chief Musician on Neginoth, A Psalm or Song. God be merciful unto us, and bless us; and cause his face to shine upon us; Selah.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H4210","A Psalm",35,42],["H7892","or Song",43,50],["H0430","God",52,55],["H2603","be merciful",56,67],["H1288","unto us, and bless",68,86],["H6440","us; and cause his face",87,109],["H0215","to shine",110,118],["H5542","upon us; Selah",119,133]]},"67:2":{"text":"That thy way may be known upon earth, thy saving health among all nations.","words":[["H1870","That thy way",0,12],["H3045","may be known",13,25],["H0776","upon earth",26,36],["H3444","thy saving health",38,55],["H1471","among all nations",56,73]]},"67:3":{"text":"Let the people praise thee, O God; let all the people praise thee.","words":[["H5971","Let the people",0,14],["H3034","praise",15,21],["H0430","thee, O God",22,33],["H5971","let all the people",35,53],["H3034","praise",54,60]]},"67:4":{"text":"O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth. Selah.","words":[["H3816","O let the nations",0,17],["H8055","be glad",18,25],["H7442","and sing for joy",26,42],["H8199","for thou shalt judge",44,64],["H5971","the people",65,75],["H4334","righteously",76,87],["H5148","and govern",89,99],["H3816","the nations",100,111],["H0776","upon earth",112,122],["H5542","Selah",124,129]]},"67:5":{"text":"Let the people praise thee, O God; let all the people praise thee.","words":[["H5971","Let the people",0,14],["H3034","praise",15,21],["H0430","thee, O God",22,33],["H5971","let all the people",35,53],["H3034","praise",54,60]]},"67:6":{"text":"Then shall the earth yield her increase; and God, even our own God, shall bless us.","words":[["H0776","Then shall the earth",0,20],["H5414","yield",21,26],["H2981","her increase",27,39],["H0430","and God",41,48],["H0430","even our own God",50,66],["H1288","shall bless",68,79]]},"67:7":{"text":"God shall bless us; and all the ends of the earth shall fear him.","words":[["H0430","God",0,3],["H1288","shall bless",4,15],["H0657","us; and all the ends",16,36],["H0776","of the earth",37,49],["H3372","shall fear",50,60]]},"68:1":{"text":"To the chief Musician, A Psalm or Song of David. Let God arise, let his enemies be scattered: let them also that hate him flee before him.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H7892","or Song",31,38],["H1732","of David",39,47],["H0430","Let God",49,56],["H6965","arise",57,62],["H0341","let his enemies",64,79],["H6327","be scattered",80,92],["H8130","let them also that hate",94,117],["H5127","him flee",118,126],["H6440","before",127,133]]},"68:2":{"text":"As smoke is driven away, so drive them away: as wax melteth before the fire, so let the wicked perish at the presence of God.","words":[["H6227","As smoke",0,8],["H5086","is driven away",9,23],["H5086","so drive them away",25,43],["H1749","as wax",45,51],["H4549","melteth",52,59],["H6440","before",60,66],["H0784","the fire",67,75],["H7563","so let the wicked",77,94],["H0006","perish",95,101],["H6440","at the presence",102,117],["H0430","of God",118,124]]},"68:3":{"text":"But let the righteous be glad; let them rejoice before God: yea, let them exceedingly rejoice.","words":[["H6662","But let the righteous",0,21],["H8055","be glad",22,29],["H5970","let them rejoice",31,47],["H6440","before",48,54],["H0430","God",55,58],["H8057","yea, let them exceedingly",60,85],["H7797","rejoice",86,93]]},"68:4":{"text":"Sing unto God, sing praises to his name: extol him that rideth upon the heavens by his name JAH, and rejoice before him.","words":[["H7891","Sing",0,4],["H0430","unto God",5,13],["H2167","sing praises",15,27],["H8034","to his name",28,39],["H5549","extol",41,46],["H7392","him that rideth",47,62],["H6160","upon the heavens",63,79],["H8034","by his name",80,91],["H3050","JAH",92,95],["H5937","and rejoice",97,108],["H6440","before",109,115]]},"68:5":{"text":"A father of the fatherless, and a judge of the widows, is God in his holy habitation.","words":[["H0001","A father",0,8],["H3490","of the fatherless",9,26],["H1781","and a judge",28,39],["H0490","of the widows",40,53],["H0430","is God",55,61],["H6944","in his holy",62,73],["H4583","habitation",74,84]]},"68:6":{"text":"God setteth the solitary in families: he bringeth out those which are bound with chains: but the rebellious dwell in a dry land.","words":[["H0430","God",0,3],["H3427","setteth",4,11],["H3173","the solitary",12,24],["H1004","in families",25,36],["H3318","he bringeth out",38,53],["H0615","those which are bound",54,75],["H3574","with chains",76,87],["H5637","but the rebellious",89,107],["H7931","dwell",108,113],["H6707","in a dry",114,122]]},"68:7":{"text":"O God, when thou wentest forth before thy people, when thou didst march through the wilderness; Selah:","words":[["H0430","O God",0,5],["H3318","when thou wentest forth",7,30],["H6440","before",31,37],["H5971","thy people",38,48],["H6805","when thou didst march",50,71],["H3452","through the wilderness",72,94],["H5542","Selah",96,101]]},"68:8":{"text":"The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God, the God of Israel.","words":[["H0776","The earth",0,9],["H7493","shook",10,15],["H8064","the heavens",17,28],["H5197","also dropped",29,41],["H6440","at the presence",42,57],["H0430","of God",58,64],["H5514","even Sinai",66,76],["H2088","itself",77,83],["H6440","was moved at the presence",84,109],["H0430","of God",110,116],["H0430","the God",118,125],["H3478","of Israel",126,135]]},"68:9":{"text":"Thou, O God, didst send a plentiful rain, whereby thou didst confirm thine inheritance, when it was weary.","words":[["H0430","Thou, O God",0,11],["H5130","didst send",13,23],["H5071","a plentiful",24,35],["H1653","rain",36,40],["H3559","whereby thou didst confirm",42,68],["H5159","thine inheritance",69,86],["H3811","when it was weary",88,105]]},"68:10":{"text":"Thy congregation hath dwelt therein: thou, O God, hast prepared of thy goodness for the poor.","words":[["H2416","Thy congregation",0,16],["H3427","hath dwelt",17,27],["H0430","therein: thou, O God",28,48],["H3559","hast prepared",50,63],["H2896","of thy goodness",64,79],["H6041","for the poor",80,92]]},"68:11":{"text":"The Lord gave the word: great was the company of those that published it.","words":[["H0136","The Lord",0,8],["H5414","gave",9,13],["H0562","the word",14,22],["H7227","great",24,29],["H6635","was the company",30,45],["H1319","of those that published",46,69]]},"68:12":{"text":"Kings of armies did flee apace: and she that tarried at home divided the spoil.","words":[["H4428","Kings",0,5],["H6635","of armies",6,15],["H5074","did flee",16,24],["H5074","apace",25,30],["H5116","and she that tarried",32,52],["H1004","at home",53,60],["H2505","divided",61,68],["H7998","the spoil",69,78]]},"68:13":{"text":"Though ye have lien among the pots, yet shall ye be as the wings of a dove covered with silver, and her feathers with yellow gold.","words":[["H7901","Though ye have lien",0,19],["H8240","among the pots",20,34],["H3671","yet shall ye be as the wings",36,64],["H3123","of a dove",65,74],["H2645","covered",75,82],["H3701","with silver",83,94],["H0084","and her feathers",96,112],["H3422","with yellow",113,124],["H2742","gold",125,129]]},"68:14":{"text":"When the Almighty scattered kings in it, it was white as snow in Salmon.","words":[["H7706","When the Almighty",0,17],["H6566","scattered",18,27],["H4428","kings",28,33],["H7949","in it, it was white as snow",34,61],["H6756","in Salmon",62,71]]},"68:15":{"text":"The hill of God is as the hill of Bashan; an high hill as the hill of Bashan.","words":[["H2022","The hill",0,8],["H0430","of God",9,15],["H2022","is as the hill",16,30],["H1316","of Bashan",31,40],["H1386","an high",42,49],["H2022","hill",50,54],["H2022","as the hill",55,66],["H1316","of Bashan",67,76]]},"68:16":{"text":"Why leap ye, ye high hills? this is the hill which God desireth to dwell in; yea, the LORD will dwell in it for ever.","words":[["H7520","Why leap",0,8],["H1386","ye, ye high",9,20],["H2022","hills",21,26],["H2022","this is the hill",28,44],["H0430","which God",45,54],["H2530","desireth",55,63],["H3427","to dwell in",64,75],["H3068","yea, the LORD",77,90],["H7931","will dwell",91,101],["H5331","in it for ever",102,116]]},"68:17":{"text":"The chariots of God are twenty thousand, even thousands of angels: the Lord is among them, as in Sinai, in the holy place.","words":[["H7393","The chariots",0,12],["H0430","of God",13,19],["H7239","are twenty thousand",20,39],["H0505","even thousands",41,55],["H8136","of angels",56,65],["H0136","the Lord",67,75],["H5514","is among them, as in Sinai",76,102],["H6944","in the holy",104,115]]},"68:18":{"text":"Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men; yea, for the rebellious also, that the LORD God might dwell among them.","words":[["H5927","Thou hast ascended",0,18],["H4791","on high",19,26],["H7628","thou hast led captivity",28,51],["H7617","captive",52,59],["H3947","thou hast received",61,79],["H4979","gifts",80,85],["H0120","for men",86,93],["H5637","yea, for the rebellious",95,118],["H3050","also, that the LORD",119,138],["H0430","God",139,142],["H7931","might dwell",143,154]]},"68:19":{"text":"Blessed be the Lord, who daily loadeth us with benefits, even the God of our salvation. Selah.","words":[["H1288","Blessed",0,7],["H0136","be the Lord",8,19],["H3117","who daily",21,30],["H3117","who daily",21,30],["H6006","loadeth",31,38],["H0410","us with benefits, even the God",39,69],["H3444","of our salvation",70,86],["H5542","Selah",88,93]]},"68:20":{"text":"He that is our God is the God of salvation; and unto GOD the Lord belong the issues from death.","words":[["H0410","He that is our God",0,18],["H0410","is the God",19,29],["H4190","of salvation",30,42],["H3069","and unto GOD",44,56],["H0136","the Lord",57,65],["H8444","belong the issues",66,83],["H4194","from death",84,94]]},"68:21":{"text":"But God shall wound the head of his enemies, and the hairy scalp of such an one as goeth on still in his trespasses.","words":[["H0430","But God",0,7],["H4272","shall wound",8,19],["H7218","the head",20,28],["H0341","of his enemies",29,43],["H8181","and the hairy",45,58],["H6936","scalp",59,64],["H1980","of such an one as goeth on still",65,97],["H0817","in his trespasses",98,115]]},"68:22":{"text":"The Lord said, I will bring again from Bashan, I will bring my people again from the depths of the sea:","words":[["H0136","The Lord",0,8],["H0559","said",9,13],["H7725","I will bring again",15,33],["H1316","from Bashan",34,45],["H7725","I will bring my people again",47,75],["H4688","from the depths",76,91],["H3220","of the sea",92,102]]},"68:23":{"text":"That thy foot may be dipped in the blood of thine enemies, and the tongue of thy dogs in the same.","words":[["H7272","That thy foot",0,13],["H4272","may be dipped",14,27],["H1818","in the blood",28,40],["H0341","of thine enemies",41,57],["H3956","and the tongue",59,73],["H3611","of thy dogs",74,85]]},"68:24":{"text":"They have seen thy goings, O God; even the goings of my God, my King, in the sanctuary.","words":[["H7200","They have seen",0,14],["H1979","thy goings",15,25],["H0430","O God",27,32],["H1979","even the goings",34,49],["H0410","of my God",50,59],["H4428","my King",61,68],["H6944","in the sanctuary",70,86]]},"68:25":{"text":"The singers went before, the players on instruments followed after; among them were the damsels playing with timbrels.","words":[["H7891","The singers",0,11],["H6923","went before",12,23],["H5059","the players on instruments",25,51],["H0310","followed after",52,66],["H8432","among",68,73],["H5959","them were the damsels",74,95],["H8608","playing with timbrels",96,117]]},"68:26":{"text":"Bless ye God in the congregations, even the Lord, from the fountain of Israel.","words":[["H1288","Bless",0,5],["H0430","ye God",6,12],["H4721","in the congregations",13,33],["H0136","even the Lord",35,48],["H4726","from the fountain",50,67],["H3478","of Israel",68,77]]},"68:27":{"text":"There is little Benjamin with their ruler, the princes of Judah and their council, the princes of Zebulun, and the princes of Naphtali.","words":[["H6810","There is little",0,15],["H1144","Benjamin",16,24],["H7287","with their ruler",25,41],["H8269","the princes",43,54],["H3063","of Judah",55,63],["H7277","and their council",64,81],["H8269","the princes",83,94],["H2074","of Zebulun",95,105],["H8269","and the princes",107,122],["H5321","of Naphtali",123,134]]},"68:28":{"text":"Thy God hath commanded thy strength: strengthen, O God, that which thou hast wrought for us.","words":[["H0430","Thy God",0,7],["H6680","hath commanded",8,22],["H5797","thy strength",23,35],["H5810","strengthen",37,47],["H0430","O God",49,54],["H2098","that which",56,66],["H6466","thou hast wrought",67,84]]},"68:29":{"text":"Because of thy temple at Jerusalem shall kings bring presents unto thee.","words":[["H1964","Because of thy temple",0,21],["H3389","at Jerusalem",22,34],["H4428","shall kings",35,46],["H2986","bring",47,52],["H7862","presents",53,61]]},"68:30":{"text":"Rebuke the company of spearmen, the multitude of the bulls, with the calves of the people, till every one submit himself with pieces of silver: scatter thou the people that delight in war.","words":[["H1605","Rebuke",0,6],["H2416","the company",7,18],["H7070","of spearmen",19,30],["H5712","the multitude",32,45],["H0047","of the bulls",46,58],["H5695","with the calves",60,75],["H5971","of the people",76,89],["H7511","till every one submit",91,112],["H7518","himself with pieces",113,132],["H3701","of silver",133,142],["H0967","scatter",144,151],["H5971","thou the people",152,167],["H2654","that delight",168,180],["H7128","in war",181,187]]},"68:31":{"text":"Princes shall come out of Egypt; Ethiopia shall soon stretch out her hands unto God.","words":[["H2831","Princes",0,7],["H0857","shall come out",8,22],["H4714","of Egypt",23,31],["H3568","Ethiopia",33,41],["H7323","shall soon stretch out",42,64],["H3027","her hands",65,74],["H0430","unto God",75,83]]},"68:32":{"text":"Sing unto God, ye kingdoms of the earth; O sing praises unto the Lord; Selah:","words":[["H7891","Sing",0,4],["H0430","unto God",5,13],["H4467","ye kingdoms",15,26],["H0776","of the earth",27,39],["H2167","O sing praises",41,55],["H0136","unto the Lord",56,69],["H5542","Selah",71,76]]},"68:33":{"text":"To him that rideth upon the heavens of heavens, which were of old; lo, he doth send out his voice, and that a mighty voice.","words":[["H7392","To him that rideth",0,18],["H8064","upon the heavens",19,35],["H8064","of heavens",36,46],["H6924","which were of old",48,65],["H5414","lo, he doth send out",67,87],["H6963","his voice",88,97],["H5797","and that a mighty",99,116],["H6963","voice",117,122]]},"68:34":{"text":"Ascribe ye strength unto God: his excellency is over Israel, and his strength is in the clouds.","words":[["H5414","Ascribe",0,7],["H5797","ye strength",8,19],["H0430","unto God",20,28],["H1346","his excellency",30,44],["H3478","is over Israel",45,59],["H5797","and his strength",61,77],["H7834","is in the clouds",78,94]]},"68:35":{"text":"O God, thou art terrible out of thy holy places: the God of Israel is he that giveth strength and power unto his people. Blessed be God.","words":[["H0430","O God",0,5],["H3372","thou art terrible",7,24],["H4720","out of thy holy places",25,47],["H0410","the God",49,56],["H3478","of Israel",57,66],["H5414","is he that giveth",67,84],["H5797","strength",85,93],["H8592","and power",94,103],["H5971","unto his people",104,119],["H1288","Blessed",121,128],["H0430","be God",129,135]]},"69:1":{"text":"To the chief Musician upon Shoshannim, A Psalm of David. Save me, O God; for the waters are come in unto my soul.","words":[["H5329","To the chief Musician",0,21],["H7799","upon Shoshannim",22,37],["H1732","A Psalm of David",39,55],["H3467","Save",57,61],["H0430","me, O God",62,71],["H4325","for the waters",73,87],["H0935","are come",88,96],["H5315","in unto my soul",97,112]]},"69:2":{"text":"I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me.","words":[["H2883","I sink",0,6],["H4688","in deep",7,14],["H3121","mire",15,19],["H4613","where there is no standing",21,47],["H0935","I am come",49,58],["H4615","into deep",59,68],["H4325","waters",69,75],["H7641","where the floods",77,93],["H7857","overflow",94,102]]},"69:3":{"text":"I am weary of my crying: my throat is dried: mine eyes fail while I wait for my God.","words":[["H3021","I am weary",0,10],["H7121","of my crying",11,23],["H1627","my throat",25,34],["H2787","is dried",35,43],["H5869","mine eyes",45,54],["H3615","fail",55,59],["H3176","while I wait",60,72],["H0430","for my God",73,83]]},"69:4":{"text":"They that hate me without a cause are more than the hairs of mine head: they that would destroy me, being mine enemies wrongfully, are mighty: then I restored that which I took not away.","words":[["H8130","They that hate",0,14],["H2600","me without a cause",15,33],["H7231","are more",34,42],["H8185","than the hairs",43,57],["H7218","of mine head",58,70],["H6789","they that would destroy",72,95],["H0341","me, being mine enemies",96,118],["H8267","wrongfully",119,129],["H6105","are mighty",131,141],["H7725","then I restored",143,158],["H1497","that which I took not away",159,185]]},"69:5":{"text":"O God, thou knowest my foolishness; and my sins are not hid from thee.","words":[["H0430","O God",0,5],["H3045","thou knowest",7,19],["H0200","my foolishness",20,34],["H0819","and my sins",36,47],["H3582","are not hid",48,59]]},"69:6":{"text":"Let not them that wait on thee, O Lord GOD of hosts, be ashamed for my sake: let not those that seek thee be confounded for my sake, O God of Israel.","words":[["H6960","Let not them that wait",0,22],["H0136","on thee, O Lord",23,38],["H3069","GOD",39,42],["H6635","of hosts",43,51],["H0954","be ashamed",53,63],["H1245","for my sake: let not those that seek",64,100],["H3637","thee be confounded",101,119],["H0430","for my sake, O God",120,138],["H3478","of Israel",139,148]]},"69:7":{"text":"Because for thy sake I have borne reproach; shame hath covered my face.","words":[["H5375","Because for thy sake I have borne",0,33],["H2781","reproach",34,42],["H3639","shame",44,49],["H3680","hath covered",50,62],["H6440","my face",63,70]]},"69:8":{"text":"I am become a stranger unto my brethren, and an alien unto my mother's children.","words":[["H2114","I am become a stranger",0,22],["H0251","unto my brethren",23,39],["H5237","and an alien",41,53],["H0517","unto my mother's",54,70],["H1121","children",71,79]]},"69:9":{"text":"For the zeal of thine house hath eaten me up; and the reproaches of them that reproached thee are fallen upon me.","words":[["H7068","For the zeal",0,12],["H1004","of thine house",13,27],["H0398","hath eaten me up",28,44],["H2781","and the reproaches",46,64],["H2778","of them that reproached",65,88],["H5307","thee are fallen",89,104]]},"69:10":{"text":"When I wept, and chastened my soul with fasting, that was to my reproach.","words":[["H1058","When I wept",0,11],["H5315","and chastened my soul",13,34],["H6685","with fasting",35,47],["H2781","that was to my reproach",49,72]]},"69:11":{"text":"I made sackcloth also my garment; and I became a proverb to them.","words":[["H5414","I made",0,6],["H8242","sackcloth",7,16],["H3830","also my garment",17,32],["H4912","and I became a proverb",34,56]]},"69:12":{"text":"They that sit in the gate speak against me; and I was the song of the drunkards.","words":[["H3427","They that sit in",0,16],["H8179","the gate",17,25],["H7878","speak",26,31],["H5058","against me; and I was the song",32,62],["H8354","of the drunkards",63,79],["H7941","of the drunkards",63,79]]},"69:13":{"text":"But as for me, my prayer is unto thee, O LORD, in an acceptable time: O God, in the multitude of thy mercy hear me, in the truth of thy salvation.","words":[["H8605","But as for me, my prayer",0,24],["H3068","is unto thee, O LORD",25,45],["H7522","in an acceptable",47,63],["H6256","time",64,68],["H0430","O God",70,75],["H7230","in the multitude",77,93],["H2617","of thy mercy",94,106],["H6030","hear",107,111],["H0571","me, in the truth",112,128],["H3468","of thy salvation",129,145]]},"69:14":{"text":"Deliver me out of the mire, and let me not sink: let me be delivered from them that hate me, and out of the deep waters.","words":[["H5337","Deliver",0,7],["H2916","me out of the mire",8,26],["H2883","and let me not sink",28,47],["H5337","let me be delivered",49,68],["H8130","from them that hate",69,88],["H4615","me, and out of the deep",89,112],["H4325","waters",113,119]]},"69:15":{"text":"Let not the waterflood overflow me, neither let the deep swallow me up, and let not the pit shut her mouth upon me.","words":[["H4325","Let not the waterflood",0,22],["H7641","Let not the waterflood",0,22],["H7857","overflow",23,31],["H4688","me, neither let the deep",32,56],["H1104","swallow me up",57,70],["H0875","and let not the pit",72,91],["H0332","shut",92,96],["H6310","her mouth",97,106]]},"69:16":{"text":"Hear me, O LORD; for thy lovingkindness is good: turn unto me according to the multitude of thy tender mercies.","words":[["H6030","Hear",0,4],["H3068","me, O LORD",5,15],["H2617","for thy lovingkindness",17,39],["H2896","is good",40,47],["H6437","turn",49,53],["H7230","unto me according to the multitude",54,88],["H7356","of thy tender mercies",89,110]]},"69:17":{"text":"And hide not thy face from thy servant; for I am in trouble: hear me speedily.","words":[["H5641","And hide",0,8],["H6440","not thy face",9,21],["H5650","from thy servant",22,38],["H6887","for I am in trouble",40,59],["H6030","hear",61,65],["H4118","me speedily",66,77]]},"69:18":{"text":"Draw nigh unto my soul, and redeem it: deliver me because of mine enemies.","words":[["H7126","Draw nigh",0,9],["H5315","unto my soul",10,22],["H1350","and redeem",24,34],["H6299","it: deliver",35,46],["H0341","me because of mine enemies",47,73]]},"69:19":{"text":"Thou hast known my reproach, and my shame, and my dishonour: mine adversaries are all before thee.","words":[["H3045","Thou hast known",0,15],["H2781","my reproach",16,27],["H1322","and my shame",29,41],["H3639","and my dishonour",43,59],["H6887","mine adversaries",61,77]]},"69:20":{"text":"Reproach hath broken my heart; and I am full of heaviness: and I looked for some to take pity, but there was none; and for comforters, but I found none.","words":[["H2781","Reproach",0,8],["H7665","hath broken",9,20],["H3820","my heart",21,29],["H5136","and I am full of heaviness",31,57],["H6960","and I looked",59,71],["H5110","for some to take pity",72,93],["H5162","but there was none; and for comforters",95,133],["H4672","but I found",135,146]]},"69:21":{"text":"They gave me also gall for my meat; and in my thirst they gave me vinegar to drink.","words":[["H5414","They gave",0,9],["H7219","me also gall",10,22],["H1267","for my meat",23,34],["H6772","and in my thirst",36,52],["H2558","they gave me vinegar",53,73],["H8248","to drink",74,82]]},"69:22":{"text":"Let their table become a snare before them: and that which should have been for their welfare, let it become a trap.","words":[["H7979","Let their table",0,15],["H6341","become a snare",16,30],["H6440","before",31,37],["H7965","them: and that which should have been for their welfare",38,93],["H4170","let it become a trap",95,115]]},"69:23":{"text":"Let their eyes be darkened, that they see not; and make their loins continually to shake.","words":[["H5869","Let their eyes",0,14],["H2821","be darkened",15,26],["H7200","that they see",28,41],["H4975","not; and make their loins",42,67],["H8548","continually",68,79],["H4571","to shake",80,88]]},"69:24":{"text":"Pour out thine indignation upon them, and let thy wrathful anger take hold of them.","words":[["H8210","Pour out",0,8],["H2195","thine indignation",9,26],["H2740","upon them, and let thy wrathful",27,58],["H0639","anger",59,64],["H5381","take hold",65,74]]},"69:25":{"text":"Let their habitation be desolate; and let none dwell in their tents.","words":[["H2918","Let their habitation",0,20],["H8074","be desolate",21,32],["H3427","and let none dwell",34,52],["H0168","in their tents",53,67]]},"69:26":{"text":"For they persecute him whom thou hast smitten; and they talk to the grief of those whom thou hast wounded.","words":[["H7291","For they persecute",0,18],["H5221","him whom thou hast smitten",19,45],["H5608","and they talk",47,60],["H4341","to the grief",61,73],["H2491","of those whom thou hast wounded",74,105]]},"69:27":{"text":"Add iniquity unto their iniquity: and let them not come into thy righteousness.","words":[["H5414","Add",0,3],["H5771","iniquity",4,12],["H5771","unto their iniquity",13,32],["H0935","and let them not come",34,55],["H6666","into thy righteousness",56,78]]},"69:28":{"text":"Let them be blotted out of the book of the living, and not be written with the righteous.","words":[["H4229","Let them be blotted",0,19],["H5612","out of the book",20,35],["H2416","of the living",36,49],["H3789","and not be written",51,69],["H6662","with the righteous",70,88]]},"69:29":{"text":"But I am poor and sorrowful: let thy salvation, O God, set me up on high.","words":[["H6041","But I am poor",0,13],["H3510","and sorrowful",14,27],["H3444","let thy salvation",29,46],["H0430","O God",48,53],["H7682","set me up on high",55,72]]},"69:30":{"text":"I will praise the name of God with a song, and will magnify him with thanksgiving.","words":[["H1984","I will praise",0,13],["H8034","the name",14,22],["H0430","of God",23,29],["H7892","with a song",30,41],["H1431","and will magnify",43,59],["H8426","him with thanksgiving",60,81]]},"69:31":{"text":"This also shall please the LORD better than an ox or bullock that hath horns and hoofs.","words":[["H3190","This also shall please",0,22],["H3068","the LORD",23,31],["H3190","better",32,38],["H7794","than an ox",39,49],["H6499","or bullock",50,60],["H7160","that hath horns",61,76],["H6536","and hoofs",77,86]]},"69:32":{"text":"The humble shall see this, and be glad: and your heart shall live that seek God.","words":[["H6035","The humble",0,10],["H7200","shall see",11,20],["H8055","this, and be glad",21,38],["H3824","and your heart",40,54],["H2421","shall live",55,65],["H1875","that seek",66,75],["H0430","God",76,79]]},"69:33":{"text":"For the LORD heareth the poor, and despiseth not his prisoners.","words":[["H3068","For the LORD",0,12],["H8085","heareth",13,20],["H0034","the poor",21,29],["H0959","and despiseth",31,44],["H0615","not his prisoners",45,62]]},"69:34":{"text":"Let the heaven and earth praise him, the seas, and every thing that moveth therein.","words":[["H8064","Let the heaven",0,14],["H0776","and earth",15,24],["H1984","praise",25,31],["H3220","him, the seas",32,45],["H7430","and every thing that moveth",47,74]]},"69:35":{"text":"For God will save Zion, and will build the cities of Judah: that they may dwell there, and have it in possession.","words":[["H0430","For God",0,7],["H3467","will save",8,17],["H6726","Zion",18,22],["H1129","and will build",24,38],["H5892","the cities",39,49],["H3063","of Judah",50,58],["H3427","that they may dwell",60,79],["H3423","there, and have it in possession",80,112]]},"69:36":{"text":"The seed also of his servants shall inherit it: and they that love his name shall dwell therein.","words":[["H2233","The seed",0,8],["H5650","also of his servants",9,29],["H5157","shall inherit",30,43],["H0157","it: and they that love",44,66],["H8034","his name",67,75],["H7931","shall dwell",76,87]]},"70:1":{"text":"To the chief Musician, A Psalm of David, to bring to remembrance. Make haste, O God, to deliver me; make haste to help me, O LORD.","words":[["H5329","To the chief Musician",0,21],["H1732","A Psalm of David",23,39],["H2142","to bring to remembrance",41,64],["H0430","Make haste, O God",66,83],["H5337","to deliver",85,95],["H2363","me; make haste",96,110],["H5833","to help",111,118],["H3068","me, O LORD",119,129]]},"70:2":{"text":"Let them be ashamed and confounded that seek after my soul: let them be turned backward, and put to confusion, that desire my hurt.","words":[["H0954","Let them be ashamed",0,19],["H2659","and confounded",20,34],["H1245","that seek",35,44],["H5315","after my soul",45,58],["H5472","let them be turned",60,78],["H0268","backward",79,87],["H3637","and put to confusion",89,109],["H2655","that desire",111,122],["H7451","my hurt",123,130]]},"70:3":{"text":"Let them be turned back for a reward of their shame that say, Aha, aha.","words":[["H7725","Let them be turned back",0,23],["H6118","for a reward",24,36],["H1322","of their shame",37,51],["H0559","that say",52,60],["H1889","Aha",62,65],["H1889","aha",67,70]]},"70:4":{"text":"Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified.","words":[["H1245","Let all those that seek",0,23],["H7797","thee rejoice",24,36],["H8055","and be glad",37,48],["H0157","in thee: and let such as love",49,78],["H3444","thy salvation",79,92],["H0559","say",93,96],["H8548","continually",97,108],["H0430","Let God",110,117],["H1431","be magnified",118,130]]},"70:5":{"text":"But I am poor and needy: make haste unto me, O God: thou art my help and my deliverer; O LORD, make no tarrying.","words":[["H6041","But I am poor",0,13],["H0034","and needy",14,23],["H2363","make haste",25,35],["H0430","unto me, O God",36,50],["H5828","thou art my help",52,68],["H6403","and my deliverer",69,85],["H3068","O LORD",87,93],["H0309","make no tarrying",95,111]]},"71:1":{"text":"In thee, O LORD, do I put my trust: let me never be put to confusion.","words":[["H3068","In thee, O LORD",0,15],["H2620","do I put my trust",17,34],["H0408","let me never",36,48],["H5769","let me never",36,48],["H0954","be put to confusion",49,68]]},"71:2":{"text":"Deliver me in thy righteousness, and cause me to escape: incline thine ear unto me, and save me.","words":[["H5337","Deliver",0,7],["H6666","me in thy righteousness",8,31],["H6403","and cause me to escape",33,55],["H5186","incline",57,64],["H0241","thine ear",65,74],["H3467","unto me, and save",75,92]]},"71:3":{"text":"Be thou my strong habitation, whereunto I may continually resort: thou hast given commandment to save me; for thou art my rock and my fortress.","words":[["H6697","Be thou my strong",0,17],["H4583","habitation",18,28],["H8548","whereunto I may continually",30,57],["H0935","resort",58,64],["H6680","thou hast given commandment",66,93],["H3467","to save",94,101],["H5553","me; for thou art my rock",102,126],["H4686","and my fortress",127,142]]},"71:4":{"text":"Deliver me, O my God, out of the hand of the wicked, out of the hand of the unrighteous and cruel man.","words":[["H6403","Deliver",0,7],["H0430","me, O my God",8,20],["H3027","out of the hand",22,37],["H7563","of the wicked",38,51],["H3709","out of the hand",53,68],["H5765","of the unrighteous",69,87],["H2556","and cruel man",88,101]]},"71:5":{"text":"For thou art my hope, O Lord GOD: thou art my trust from my youth.","words":[["H8615","For thou art my hope",0,20],["H0136","O Lord",22,28],["H3069","GOD",29,32],["H4009","thou art my trust",34,51],["H5271","from my youth",52,65]]},"71:6":{"text":"By thee have I been holden up from the womb: thou art he that took me out of my mother's bowels: my praise shall be continually of thee.","words":[["H5564","By thee have I been holden up",0,29],["H0990","from the womb",30,43],["H1491","thou art he that took",45,66],["H0517","me out of my mother's",67,88],["H4578","bowels",89,95],["H8416","my praise",97,106],["H8548","shall be continually",107,127]]},"71:7":{"text":"I am as a wonder unto many; but thou art my strong refuge.","words":[["H4159","I am as a wonder",0,16],["H7227","unto many",17,26],["H5797","but thou art my strong",28,50],["H4268","refuge",51,57]]},"71:8":{"text":"Let my mouth be filled with thy praise and with thy honour all the day.","words":[["H6310","Let my mouth",0,12],["H4390","be filled",13,22],["H8416","with thy praise",23,38],["H8597","and with thy honour",39,58],["H3117","all the day",59,70]]},"71:9":{"text":"Cast me not off in the time of old age; forsake me not when my strength faileth.","words":[["H7993","Cast me not off",0,15],["H6256","in the time",16,27],["H2209","of old age",28,38],["H5800","forsake",40,47],["H3581","me not when my strength",48,71],["H3615","faileth",72,79]]},"71:10":{"text":"For mine enemies speak against me; and they that lay wait for my soul take counsel together,","words":[["H0341","For mine enemies",0,16],["H0559","speak",17,22],["H8104","against me; and they that lay wait",23,57],["H5315","for my soul",58,69],["H3289","take counsel",70,82],["H3162","together",83,91]]},"71:11":{"text":"Saying, God hath forsaken him: persecute and take him; for there is none to deliver him.","words":[["H0559","Saying",0,6],["H0430","God",8,11],["H5800","hath forsaken",12,25],["H7291","him: persecute",26,40],["H8610","and take",41,49],["H5337","him; for there is none to deliver",50,83]]},"71:12":{"text":"O God, be not far from me: O my God, make haste for my help.","words":[["H0430","O God",0,5],["H7368","be not far",7,17],["H0430","from me: O my God",18,35],["H2363","make haste",37,47],["H2439","make haste",37,47],["H5833","for my help",48,59]]},"71:13":{"text":"Let them be confounded and consumed that are adversaries to my soul; let them be covered with reproach and dishonour that seek my hurt.","words":[["H0954","Let them be confounded",0,22],["H3615","and consumed",23,35],["H7853","that are adversaries",36,56],["H5315","to my soul",57,67],["H5844","let them be covered",69,88],["H2781","with reproach",89,102],["H3639","and dishonour",103,116],["H1245","that seek",117,126],["H7451","my hurt",127,134]]},"71:14":{"text":"But I will hope continually, and will yet praise thee more and more.","words":[["H3176","But I will hope",0,15],["H8548","continually",16,27],["H8416","and will yet praise",29,48],["H3254","thee more",49,58],["H3254","and more",59,67]]},"71:15":{"text":"My mouth shall shew forth thy righteousness and thy salvation all the day; for I know not the numbers thereof.","words":[["H6310","My mouth",0,8],["H5608","shall shew forth",9,25],["H6666","thy righteousness",26,43],["H8668","and thy salvation",44,61],["H3117","all the day",62,73],["H3045","for I know",75,85],["H5615","not the numbers",86,101]]},"71:16":{"text":"I will go in the strength of the Lord GOD: I will make mention of thy righteousness, even of thine only.","words":[["H0935","I will go in",0,12],["H1369","the strength",13,25],["H0136","of the Lord",26,37],["H3069","GOD",38,41],["H2142","I will make mention",43,62],["H6666","of thy righteousness",63,83]]},"71:17":{"text":"O God, thou hast taught me from my youth: and hitherto have I declared thy wondrous works.","words":[["H0430","O God",0,5],["H3925","thou hast taught",7,23],["H5271","me from my youth",24,40],["H5046","and hitherto have I declared",42,70],["H6381","thy wondrous works",71,89]]},"71:18":{"text":"Now also when I am old and grayheaded, O God, forsake me not; until I have shewed thy strength unto this generation, and thy power to every one that is to come.","words":[["H5704","Now also when",0,13],["H2209","I am old",14,22],["H7872","and grayheaded",23,37],["H0430","O God",39,44],["H5800","forsake",46,53],["H5046","me not; until I have shewed",54,81],["H2220","thy strength",82,94],["H1755","unto this generation",95,115],["H1369","and thy power",117,130],["H0935","to every one that is to come",131,159]]},"71:19":{"text":"Thy righteousness also, O God, is very high, who hast done great things: O God, who is like unto thee!","words":[["H6666","Thy righteousness",0,17],["H0430","also, O God",18,29],["H4791","is very high",31,43],["H6213","who hast done",45,58],["H1419","great things",59,71],["H0430","O God",73,78]]},"71:20":{"text":"Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth.","words":[["H7200","Thou, which hast shewed",0,23],["H7227","me great",24,32],["H7451","and sore",33,41],["H6869","troubles",42,50],["H2421","shalt quicken",52,65],["H7725","me again",66,74],["H5927","and shalt bring me up",76,97],["H7725","again",98,103],["H8415","from the depths",104,119],["H0776","of the earth",120,132]]},"71:21":{"text":"Thou shalt increase my greatness, and comfort me on every side.","words":[["H7235","Thou shalt increase",0,19],["H1420","my greatness",20,32],["H5162","and comfort",34,45],["H5437","me on every side",46,62]]},"71:22":{"text":"I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp, O thou Holy One of Israel.","words":[["H3034","I will also praise",0,18],["H3627","thee with the psaltery",19,41],["H5035","thee with the psaltery",19,41],["H0571","even thy truth",43,57],["H0430","O my God",59,67],["H2167","unto thee will I sing",69,90],["H3658","with the harp",91,104],["H6918","O thou Holy One",106,121],["H3478","of Israel",122,131]]},"71:23":{"text":"My lips shall greatly rejoice when I sing unto thee; and my soul, which thou hast redeemed.","words":[["H8193","My lips",0,7],["H7442","shall greatly rejoice",8,29],["H2167","when I sing",30,41],["H5315","unto thee; and my soul",42,64],["H6299","which thou hast redeemed",66,90]]},"71:24":{"text":"My tongue also shall talk of thy righteousness all the day long: for they are confounded, for they are brought unto shame, that seek my hurt.","words":[["H3956","My tongue",0,9],["H1897","also shall talk",10,25],["H6666","of thy righteousness",26,46],["H3117","all the day",47,58],["H0954","long: for they are confounded",59,88],["H2659","for they are brought unto shame",90,121],["H1245","that seek",123,132],["H7451","my hurt",133,140]]},"72:1":{"text":"A Psalm for Solomon. Give the king thy judgments, O God, and thy righteousness unto the king's son.","words":[["H8010","A Psalm for Solomon",0,19],["H5414","Give",21,25],["H4428","the king",26,34],["H4941","thy judgments",35,48],["H0430","O God",50,55],["H6666","and thy righteousness",57,78],["H4428","unto the king's",79,94],["H1121","son",95,98]]},"72:2":{"text":"He shall judge thy people with righteousness, and thy poor with judgment.","words":[["H1777","He shall judge",0,14],["H5971","thy people",15,25],["H6664","with righteousness",26,44],["H6041","and thy poor",46,58],["H4941","with judgment",59,72]]},"72:3":{"text":"The mountains shall bring peace to the people, and the little hills, by righteousness.","words":[["H2022","The mountains",0,13],["H5375","shall bring",14,25],["H7965","peace",26,31],["H5971","to the people",32,45],["H1389","and the little hills",47,67],["H6666","by righteousness",69,85]]},"72:4":{"text":"He shall judge the poor of the people, he shall save the children of the needy, and shall break in pieces the oppressor.","words":[["H8199","He shall judge",0,14],["H6041","the poor",15,23],["H5971","of the people",24,37],["H3467","he shall save",39,52],["H1121","the children",53,65],["H0034","of the needy",66,78],["H1792","and shall break in pieces",80,105],["H6231","the oppressor",106,119]]},"72:5":{"text":"They shall fear thee as long as the sun and moon endure, throughout all generations.","words":[["H3372","They shall fear",0,15],["H5973","thee as long as",16,31],["H8121","the sun",32,39],["H3394","and moon",40,48],["H6440","endure",49,55],["H1755","throughout all",57,71],["H1755","generations",72,83]]},"72:6":{"text":"He shall come down like rain upon the mown grass: as showers that water the earth.","words":[["H3381","He shall come down",0,18],["H4306","like rain",19,28],["H1488","upon the mown",29,42],["H7241","grass: as showers",43,60],["H2222","that water",61,71],["H0776","the earth",72,81]]},"72:7":{"text":"In his days shall the righteous flourish; and abundance of peace so long as the moon endureth.","words":[["H3117","In his days",0,11],["H6662","shall the righteous",12,31],["H6524","flourish",32,40],["H7230","and abundance",42,55],["H7965","of peace",56,64],["H3394","so long as the moon",65,84]]},"72:8":{"text":"He shall have dominion also from sea to sea, and from the river unto the ends of the earth.","words":[["H7287","He shall have dominion",0,22],["H3220","also from sea",23,36],["H3220","to sea",37,43],["H5104","and from the river",45,63],["H0657","unto the ends",64,77],["H0776","of the earth",78,90]]},"72:9":{"text":"They that dwell in the wilderness shall bow before him; and his enemies shall lick the dust.","words":[["H6728","They that dwell in the wilderness",0,33],["H3766","shall bow",34,43],["H6440","before",44,50],["H0341","him; and his enemies",51,71],["H3897","shall lick",72,82],["H6083","the dust",83,91]]},"72:10":{"text":"The kings of Tarshish and of the isles shall bring presents: the kings of Sheba and Seba shall offer gifts.","words":[["H4428","The kings",0,9],["H8659","of Tarshish",10,21],["H0339","and of the isles",22,38],["H7725","shall bring",39,50],["H4503","presents",51,59],["H4428","the kings",61,70],["H7614","of Sheba",71,79],["H5434","and Seba",80,88],["H7126","shall offer",89,100],["H0814","gifts",101,106]]},"72:11":{"text":"Yea, all kings shall fall down before him: all nations shall serve him.","words":[["H4428","Yea, all kings",0,14],["H7812","shall fall down",15,30],["H1471","before him: all nations",31,54],["H5647","shall serve",55,66]]},"72:12":{"text":"For he shall deliver the needy when he crieth; the poor also, and him that hath no helper.","words":[["H5337","For he shall deliver",0,20],["H0034","the needy",21,30],["H7768","when he crieth",31,45],["H6041","the poor",47,55],["H5826","also, and him that hath no helper",56,89]]},"72:13":{"text":"He shall spare the poor and needy, and shall save the souls of the needy.","words":[["H2347","He shall spare",0,14],["H1800","the poor",15,23],["H0034","and needy",24,33],["H3467","and shall save",35,49],["H5315","the souls",50,59],["H0034","of the needy",60,72]]},"72:14":{"text":"He shall redeem their soul from deceit and violence: and precious shall their blood be in his sight.","words":[["H1350","He shall redeem",0,15],["H5315","their soul",16,26],["H8496","from deceit",27,38],["H2555","and violence",39,51],["H3365","and precious",53,65],["H1818","shall their blood",66,83],["H5869","be in his sight",84,99]]},"72:15":{"text":"And he shall live, and to him shall be given of the gold of Sheba: prayer also shall be made for him continually; and daily shall he be praised.","words":[["H2421","And he shall live",0,17],["H5414","and to him shall be given",19,44],["H2091","of the gold",45,56],["H7614","of Sheba",57,65],["H6419","prayer also shall be made",67,92],["H8548","for him continually",93,112],["H3117","and daily",114,123],["H1288","shall he be praised",124,143]]},"72:16":{"text":"There shall be an handful of corn in the earth upon the top of the mountains; the fruit thereof shall shake like Lebanon: and they of the city shall flourish like grass of the earth.","words":[["H6451","There shall be an handful",0,25],["H1250","of corn",26,33],["H0776","in the earth",34,46],["H7218","upon the top",47,59],["H2022","of the mountains",60,76],["H6529","the fruit",78,87],["H7493","thereof shall shake",88,107],["H3844","like Lebanon",108,120],["H5892","and they of the city",122,142],["H6692","shall flourish",143,157],["H6212","like grass",158,168],["H0776","of the earth",169,181]]},"72:17":{"text":"His name shall endure for ever: his name shall be continued as long as the sun: and men shall be blessed in him: all nations shall call him blessed.","words":[["H8034","His name",0,8],["H5769","shall endure for ever",9,30],["H8034","his name",32,40],["H5125","shall be continued",41,59],["H5125","shall be continued",41,59],["H6440","as long as",60,70],["H8121","the sun",71,78],["H1288","and men shall be blessed",80,104],["H1471","in him: all nations",105,124],["H0833","shall call him blessed",125,147]]},"72:18":{"text":"Blessed be the LORD God, the God of Israel, who only doeth wondrous things.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H0430","God",20,23],["H0430","the God",25,32],["H3478","of Israel",33,42],["H6213","who only doeth",44,58],["H6381","wondrous things",59,74]]},"72:19":{"text":"And blessed be his glorious name for ever: and let the whole earth be filled with his glory; Amen, and Amen.","words":[["H1288","And blessed",0,11],["H3519","be his glorious",12,27],["H8034","name",28,32],["H5769","for ever",33,41],["H0776","and let the whole earth",43,66],["H4390","be filled",67,76],["H3519","with his glory",77,91],["H0543","Amen",93,97],["H0543","and Amen",99,107]]},"72:20":{"text":"The prayers of David the son of Jesse are ended.","words":[["H8605","The prayers",0,11],["H1732","of David",12,20],["H1121","the son",21,28],["H3448","of Jesse",29,37],["H3615","are ended",38,47]]},"73:1":{"text":"A Psalm of Asaph. Truly God is good to Israel, even to such as are of a clean heart.","words":[["H4210","A Psalm",0,7],["H0623","of Asaph",8,16],["H0430","Truly God",18,27],["H2896","is good",28,35],["H3478","to Israel",36,45],["H1249","even to such as are of a clean",47,77],["H3824","heart",78,83]]},"73:2":{"text":"But as for me, my feet were almost gone; my steps had well nigh slipped.","words":[["H7272","But as for me, my feet",0,22],["H4592","were almost",23,34],["H5186","gone",35,39],["H5186","gone",35,39],["H0838","my steps",41,49],["H0369","had well nigh",50,63],["H8210","slipped",64,71]]},"73:3":{"text":"For I was envious at the foolish, when I saw the prosperity of the wicked.","words":[["H7065","For I was envious",0,17],["H1984","at the foolish",18,32],["H7200","when I saw",34,44],["H7965","the prosperity",45,59],["H7563","of the wicked",60,73]]},"73:4":{"text":"For there are no bands in their death: but their strength is firm.","words":[["H2784","For there are no bands",0,22],["H4194","in their death",23,37],["H0193","but their strength",39,57],["H1277","is firm",58,65]]},"73:5":{"text":"They are not in trouble as other men; neither are they plagued like other men.","words":[["H5999","They are not in trouble",0,23],["H0582","as other men",24,36],["H5060","neither are they plagued",38,62],["H5973","like",63,67],["H0120","other men",68,77]]},"73:6":{"text":"Therefore pride compasseth them about as a chain; violence covereth them as a garment.","words":[["H1346","Therefore pride",0,15],["H6059","compasseth them about as a chain",16,48],["H2555","violence",50,58],["H5848","covereth",59,67],["H7897","them as a garment",68,85]]},"73:7":{"text":"Their eyes stand out with fatness: they have more than heart could wish.","words":[["H5869","Their eyes",0,10],["H3318","stand out",11,20],["H2459","with fatness",21,33],["H5674","they have more",35,49],["H3824","than heart",50,60],["H4906","could wish",61,71]]},"73:8":{"text":"They are corrupt, and speak wickedly concerning oppression: they speak loftily.","words":[["H4167","They are corrupt",0,16],["H1696","and speak",18,27],["H7451","wickedly",28,36],["H6233","concerning oppression",37,58],["H1696","they speak",60,70],["H4791","loftily",71,78]]},"73:9":{"text":"They set their mouth against the heavens, and their tongue walketh through the earth.","words":[["H8371","They set",0,8],["H6310","their mouth",9,20],["H8064","against the heavens",21,40],["H3956","and their tongue",42,58],["H1980","walketh",59,66],["H0776","through the earth",67,84]]},"73:10":{"text":"Therefore his people return hither: and waters of a full cup are wrung out to them.","words":[["H5971","Therefore his people",0,20],["H7725","return",21,27],["H7725","return",21,27],["H1988","hither",28,34],["H4325","and waters",36,46],["H4392","of a full",47,56],["H4680","cup are wrung out",57,74]]},"73:11":{"text":"And they say, How doth God know? and is there knowledge in the most High?","words":[["H0559","And they say",0,12],["H0410","How doth God",14,26],["H3045","know",27,31],["H3426","and is there",33,45],["H1844","knowledge",46,55],["H5945","in the most High",56,72]]},"73:12":{"text":"Behold, these are the ungodly, who prosper in the world; they increase in riches.","words":[["H7563","Behold, these are the ungodly",0,29],["H7961","who prosper",31,42],["H5769","in the world",43,55],["H7685","they increase",57,70],["H2428","in riches",71,80]]},"73:13":{"text":"Verily I have cleansed my heart in vain, and washed my hands in innocency.","words":[["H2135","Verily I have cleansed",0,22],["H3824","my heart",23,31],["H7385","in vain",32,39],["H7364","and washed",41,51],["H3709","my hands",52,60],["H5356","in innocency",61,73]]},"73:14":{"text":"For all the day long have I been plagued, and chastened every morning.","words":[["H3117","For all the day",0,15],["H5060","long have I been plagued",16,40],["H8433","and chastened",42,55],["H1242","every morning",56,69]]},"73:15":{"text":"If I say, I will speak thus; behold, I should offend against the generation of thy children.","words":[["H0559","If I say",0,8],["H5608","I will speak",10,22],["H3644","thus",23,27],["H0898","behold, I should offend",29,52],["H1755","against the generation",53,75],["H1121","of thy children",76,91]]},"73:16":{"text":"When I thought to know this, it was too painful for me;","words":[["H2803","When I thought",0,14],["H3045","to know",15,22],["H5999","this, it was too painful",23,47],["H5869","for me",48,54]]},"73:17":{"text":"Until I went into the sanctuary of God; then understood I their end.","words":[["H0935","Until I went",0,12],["H4720","into the sanctuary",13,31],["H0410","of God",32,38],["H0995","then understood",40,55],["H0319","I their end",56,67]]},"73:18":{"text":"Surely thou didst set them in slippery places: thou castedst them down into destruction.","words":[["H7896","Surely thou didst set",0,21],["H2513","them in slippery places",22,45],["H5307","thou castedst them down",47,70],["H4876","into destruction",71,87]]},"73:19":{"text":"How are they brought into desolation, as in a moment! they are utterly consumed with terrors.","words":[["H8047","How are they brought into desolation",0,36],["H7281","as in a moment",38,52],["H5486","they are utterly",54,70],["H8552","consumed",71,79],["H1091","with terrors",80,92]]},"73:20":{"text":"As a dream when one awaketh; so, O Lord, when thou awakest, thou shalt despise their image.","words":[["H2472","As a dream",0,10],["H6974","when one awaketh",11,27],["H0136","so, O Lord",29,39],["H5782","when thou awakest",41,58],["H0959","thou shalt despise",60,78],["H6754","their image",79,90]]},"73:21":{"text":"Thus my heart was grieved, and I was pricked in my reins.","words":[["H3824","Thus my heart",0,13],["H2556","was grieved",14,25],["H8150","and I was pricked",27,44],["H3629","in my reins",45,56]]},"73:22":{"text":"So foolish was I, and ignorant: I was as a beast before thee.","words":[["H1198","So foolish",0,10],["H3045","was I, and ignorant",11,30],["H0929","I was as a beast",32,48]]},"73:23":{"text":"Nevertheless I am continually with thee: thou hast holden me by my right hand.","words":[["H8548","Nevertheless I am continually",0,29],["H0270","with thee: thou hast holden",30,57],["H3225","me by my right",58,72],["H3027","hand",73,77]]},"73:24":{"text":"Thou shalt guide me with thy counsel, and afterward receive me to glory.","words":[["H5148","Thou shalt guide",0,16],["H6098","me with thy counsel",17,36],["H0310","and afterward",38,51],["H3947","receive",52,59],["H3519","me to glory",60,71]]},"73:25":{"text":"Whom have I in heaven but thee? and there is none upon earth that I desire beside thee.","words":[["H8064","Whom have I in heaven",0,21],["H0776","but thee? and there is none upon earth",22,60],["H2654","that I desire",61,74]]},"73:26":{"text":"My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.","words":[["H7607","My flesh",0,8],["H3824","and my heart",9,21],["H3615","faileth",22,29],["H0430","but God",31,38],["H6697","is the strength",39,54],["H3824","of my heart",55,66],["H2506","and my portion",68,82],["H5769","for ever",83,91]]},"73:27":{"text":"For, lo, they that are far from thee shall perish: thou hast destroyed all them that go a whoring from thee.","words":[["H7369","For, lo, they that are far",0,26],["H0006","from thee shall perish",27,49],["H6789","thou hast destroyed",51,70],["H2181","all them that go a whoring",71,97]]},"73:28":{"text":"But it is good for me to draw near to God: I have put my trust in the Lord GOD, that I may declare all thy works.","words":[["H0589","But",0,3],["H2896","it is good",4,14],["H7132","for me to draw near",15,34],["H0430","to God",35,41],["H7896","I have put",43,53],["H4268","my trust",54,62],["H0136","in the Lord",63,74],["H3069","GOD",75,78],["H5608","that I may declare",80,98],["H4399","all thy works",99,112]]},"74:1":{"text":"Maschil of Asaph. O God, why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?","words":[["H4905","Maschil",0,7],["H0623","of Asaph",8,16],["H0430","O God",18,23],["H2186","why hast thou cast us off",25,50],["H5331","for ever",51,59],["H0639","why doth thine anger",61,81],["H6225","smoke",82,87],["H6629","against the sheep",88,105],["H4830","of thy pasture",106,120]]},"74:2":{"text":"Remember thy congregation, which thou hast purchased of old; the rod of thine inheritance, which thou hast redeemed; this mount Zion, wherein thou hast dwelt.","words":[["H2142","Remember",0,8],["H5712","thy congregation",9,25],["H7069","which thou hast purchased",27,52],["H6924","of old",53,59],["H7626","the rod",61,68],["H5159","of thine inheritance",69,89],["H1350","which thou hast redeemed",91,115],["H2022","this mount",117,127],["H6726","Zion",128,132],["H7931","wherein thou hast dwelt",134,157]]},"74:3":{"text":"Lift up thy feet unto the perpetual desolations; even all that the enemy hath done wickedly in the sanctuary.","words":[["H7311","Lift up",0,7],["H6471","thy feet",8,16],["H5331","unto the perpetual",17,35],["H4876","desolations",36,47],["H0341","even all that the enemy",49,72],["H7489","hath done wickedly",73,91],["H6944","in the sanctuary",92,108]]},"74:4":{"text":"Thine enemies roar in the midst of thy congregations; they set up their ensigns for signs.","words":[["H6887","Thine enemies",0,13],["H7580","roar",14,18],["H7130","in the midst",19,31],["H4150","of thy congregations",32,52],["H7760","they set up",54,65],["H0226","their ensigns",66,79],["H0226","for signs",80,89]]},"74:5":{"text":"A man was famous according as he had lifted up axes upon the thick trees.","words":[["H3045","A man was famous",0,16],["H0935","according as he had lifted up",17,46],["H4605","according as he had lifted up",17,46],["H7134","axes",47,51],["H5442","upon the thick",52,66],["H6086","trees",67,72]]},"74:6":{"text":"But now they break down the carved work thereof at once with axes and hammers.","words":[["H1986","But now they break down",0,23],["H6603","the carved work",24,39],["H3162","thereof at once",40,55],["H3781","with axes",56,65],["H3597","and hammers",66,77]]},"74:7":{"text":"They have cast fire into thy sanctuary, they have defiled by casting down the dwelling place of thy name to the ground.","words":[["H7971","They have cast",0,14],["H0784","fire",15,19],["H4720","into thy sanctuary",20,38],["H2490","they have defiled",40,57],["H4908","by casting down the dwelling place",58,92],["H8034","of thy name",93,104],["H0776","to the ground",105,118]]},"74:8":{"text":"They said in their hearts, Let us destroy them together: they have burned up all the synagogues of God in the land.","words":[["H0559","They said",0,9],["H3820","in their hearts",10,25],["H3238","Let us destroy",27,41],["H3162","them together",42,55],["H8313","they have burned up",57,76],["H4150","all the synagogues",77,95],["H0410","of God",96,102],["H0776","in the land",103,114]]},"74:9":{"text":"We see not our signs: there is no more any prophet: neither is there among us any that knoweth how long.","words":[["H7200","We see",0,6],["H0226","not our signs",7,20],["H5030","there is no more any prophet",22,50],["H3045","neither is there among us any that knoweth",52,94],["H5704","how long",95,103]]},"74:10":{"text":"O God, how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?","words":[["H0430","O God",0,5],["H6862","how long shall the adversary",7,35],["H2778","reproach",36,44],["H0341","shall the enemy",46,61],["H5006","blaspheme",62,71],["H8034","thy name",72,80],["H5331","for ever",81,89]]},"74:11":{"text":"Why withdrawest thou thy hand, even thy right hand? pluck it out of thy bosom.","words":[["H7725","Why withdrawest",0,15],["H3027","thou thy hand",16,29],["H3225","even thy right hand",31,50],["H3615","pluck",52,57],["H7130","it out of",58,67],["H2436","thy bosom",68,77],["H2436","thy bosom",68,77]]},"74:12":{"text":"For God is my King of old, working salvation in the midst of the earth.","words":[["H0430","For God",0,7],["H4428","is my King",8,18],["H6924","of old",19,25],["H6466","working",27,34],["H3444","salvation",35,44],["H7130","in the midst",45,57],["H0776","of the earth",58,70]]},"74:13":{"text":"Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters.","words":[["H6565","Thou didst divide",0,17],["H3220","the sea",18,25],["H5797","by thy strength",26,41],["H7665","thou brakest",43,55],["H7218","the heads",56,65],["H8577","of the dragons",66,80],["H4325","in the waters",81,94]]},"74:14":{"text":"Thou brakest the heads of leviathan in pieces, and gavest him to be meat to the people inhabiting the wilderness.","words":[["H7533","Thou brakest",0,12],["H7218","the heads",13,22],["H3882","of leviathan",23,35],["H5414","in pieces, and gavest",36,57],["H3978","him to be meat",58,72],["H5971","to the people",73,86],["H6728","inhabiting the wilderness",87,112]]},"74:15":{"text":"Thou didst cleave the fountain and the flood: thou driedst up mighty rivers.","words":[["H1234","Thou didst cleave",0,17],["H4599","the fountain",18,30],["H5158","and the flood",31,44],["H3001","thou driedst up",46,61],["H0386","mighty",62,68],["H5104","rivers",69,75]]},"74:16":{"text":"The day is thine, the night also is thine: thou hast prepared the light and the sun.","words":[["H3117","The day",0,7],["H3915","is thine, the night",8,27],["H3559","also is thine: thou hast prepared",28,61],["H3974","the light",62,71],["H8121","and the sun",72,83]]},"74:17":{"text":"Thou hast set all the borders of the earth: thou hast made summer and winter.","words":[["H5324","Thou hast set",0,13],["H1367","all the borders",14,29],["H0776","of the earth",30,42],["H3335","thou hast made",44,58],["H7019","summer",59,65],["H2779","and winter",66,76]]},"74:18":{"text":"Remember this, that the enemy hath reproached, O LORD, and that the foolish people have blasphemed thy name.","words":[["H2142","Remember",0,8],["H0341","this, that the enemy",9,29],["H2778","hath reproached",30,45],["H3068","O LORD",47,53],["H5036","and that the foolish",55,75],["H5971","people",76,82],["H5006","have blasphemed",83,98],["H8034","thy name",99,107]]},"74:19":{"text":"O deliver not the soul of thy turtledove unto the multitude of the wicked: forget not the congregation of thy poor for ever.","words":[["H5414","O deliver",0,9],["H5315","not the soul",10,22],["H8449","of thy turtledove",23,40],["H2416","unto the multitude",41,59],["H7911","of the wicked: forget",60,81],["H2416","not the congregation",82,102],["H6041","of thy poor",103,114],["H5331","for ever",115,123]]},"74:20":{"text":"Have respect unto the covenant: for the dark places of the earth are full of the habitations of cruelty.","words":[["H5027","Have respect",0,12],["H1285","unto the covenant",13,30],["H4285","for the dark",32,44],["H0776","places of the earth",45,64],["H4390","are full",65,73],["H4999","of the habitations",74,92],["H2555","of cruelty",93,103]]},"74:21":{"text":"O let not the oppressed return ashamed: let the poor and needy praise thy name.","words":[["H1790","O let not the oppressed",0,23],["H7725","return",24,30],["H3637","ashamed",31,38],["H6041","let the poor",40,52],["H0034","and needy",53,62],["H1984","praise",63,69],["H8034","thy name",70,78]]},"74:22":{"text":"Arise, O God, plead thine own cause: remember how the foolish man reproacheth thee daily.","words":[["H6965","Arise",0,5],["H0430","O God",7,12],["H7378","plead",14,19],["H7379","thine own cause",20,35],["H2142","remember",37,45],["H5036","how the foolish man",46,65],["H2781","reproacheth",66,77],["H3117","thee daily",78,88]]},"74:23":{"text":"Forget not the voice of thine enemies: the tumult of those that rise up against thee increaseth continually.","words":[["H7911","Forget",0,6],["H6963","not the voice",7,20],["H6887","of thine enemies",21,37],["H7588","the tumult",39,49],["H6965","of those that rise up",50,71],["H5927","against thee increaseth",72,95],["H8548","continually",96,107]]},"75:1":{"text":"To the chief Musician, Altaschith, A Psalm or Song of Asaph. Unto thee, O God, do we give thanks, unto thee do we give thanks: for that thy name is near thy wondrous works declare.","words":[["H5329","To the chief Musician",0,21],["H0516","Altaschith",23,33],["H4210","A Psalm",35,42],["H7892","or Song",43,50],["H0623","of Asaph",51,59],["H0430","Unto thee, O God",61,77],["H3034","do we give thanks",79,96],["H3034","unto thee do we give thanks",98,125],["H8034","for that thy name",127,144],["H7138","is near",145,152],["H6381","thy wondrous works",153,171],["H5608","declare",172,179]]},"75:2":{"text":"When I shall receive the congregation I will judge uprightly.","words":[["H3947","When I shall receive",0,20],["H4150","the congregation",21,37],["H8199","I will judge",38,50],["H4339","uprightly",51,60]]},"75:3":{"text":"The earth and all the inhabitants thereof are dissolved: I bear up the pillars of it. Selah.","words":[["H0776","The earth",0,9],["H3427","and all the inhabitants",10,33],["H4127","thereof are dissolved",34,55],["H8505","I bear up",57,66],["H5982","the pillars",67,78],["H5542","of it. Selah",79,91]]},"75:4":{"text":"I said unto the fools, Deal not foolishly: and to the wicked, Lift not up the horn:","words":[["H0559","I said",0,6],["H1984","unto the fools",7,21],["H1984","Deal not foolishly",23,41],["H7563","and to the wicked",43,60],["H7311","Lift not up",62,73],["H7161","the horn",74,82]]},"75:5":{"text":"Lift not up your horn on high: speak not with a stiff neck.","words":[["H7311","Lift not up",0,11],["H7161","your horn",12,21],["H4791","on high",22,29],["H1696","speak",31,36],["H6277","not with a stiff",37,53],["H6677","neck",54,58]]},"75:6":{"text":"For promotion cometh neither from the east, nor from the west, nor from the south.","words":[["H7311","For promotion",0,13],["H2022","For promotion",0,13],["H4161","cometh neither from the east",14,42],["H4628","nor from the west",44,61],["H4057","nor from the south",63,81]]},"75:7":{"text":"But God is the judge: he putteth down one, and setteth up another.","words":[["H0430","But God",0,7],["H8199","is the judge",8,20],["H8213","he putteth down",22,37],["H7311","one, and setteth up",38,57]]},"75:8":{"text":"For in the hand of the LORD there is a cup, and the wine is red; it is full of mixture; and he poureth out of the same: but the dregs thereof, all the wicked of the earth shall wring them out, and drink them.","words":[["H3027","For in the hand",0,15],["H3068","of the LORD",16,27],["H3563","there is a cup",28,42],["H3196","and the wine",44,56],["H2560","is red",57,63],["H4392","it is full",65,75],["H4538","of mixture",76,86],["H5064","and he poureth out",88,106],["H2088","of the same",107,118],["H8105","but the dregs",120,133],["H7563","thereof, all the wicked",134,157],["H0776","of the earth",158,170],["H4680","shall wring them out",171,191],["H8354","and drink",193,202]]},"75:9":{"text":"But I will declare for ever; I will sing praises to the God of Jacob.","words":[["H5046","But I will declare",0,18],["H5769","for ever",19,27],["H2167","I will sing praises",29,48],["H0430","to the God",49,59],["H3290","of Jacob",60,68]]},"75:10":{"text":"All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted.","words":[["H7161","All the horns",0,13],["H7563","of the wicked",14,27],["H1438","also will I cut off",28,47],["H7161","but the horns",49,62],["H6662","of the righteous",63,79],["H7311","shall be exalted",80,96]]},"76:1":{"text":"To the chief Musician on Neginoth, A Psalm or Song of Asaph. In Judah is God known: his name is great in Israel.","words":[["H5329","To the chief Musician",0,21],["H5058","on Neginoth",22,33],["H4210","A Psalm",35,42],["H7892","or Song",43,50],["H0623","of Asaph",51,59],["H3063","In Judah",61,69],["H0430","is God",70,76],["H3045","known",77,82],["H8034","his name",84,92],["H1419","is great",93,101],["H3478","in Israel",102,111]]},"76:2":{"text":"In Salem also is his tabernacle, and his dwelling place in Zion.","words":[["H8004","In Salem",0,8],["H5520","also is his tabernacle",9,31],["H4585","and his dwelling place",33,55],["H6726","in Zion",56,63]]},"76:3":{"text":"There brake he the arrows of the bow, the shield, and the sword, and the battle. Selah.","words":[["H7665","There brake",0,11],["H7565","he the arrows",12,25],["H7198","of the bow",26,36],["H4043","the shield",38,48],["H2719","and the sword",50,63],["H4421","and the battle",65,79],["H5542","Selah",81,86]]},"76:4":{"text":"Thou art more glorious and excellent than the mountains of prey.","words":[["H0215","Thou art more glorious",0,22],["H0117","and excellent",23,36],["H2042","than the mountains",37,55],["H2964","of prey",56,63]]},"76:5":{"text":"The stouthearted are spoiled, they have slept their sleep: and none of the men of might have found their hands.","words":[["H0047","The stouthearted",0,16],["H3820","The stouthearted",0,16],["H7997","are spoiled",17,28],["H5123","they have slept",30,45],["H8142","their sleep",46,57],["H0582","and none of the men",59,78],["H2428","of might",79,87],["H4672","have found",88,98],["H3027","their hands",99,110]]},"76:6":{"text":"At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep.","words":[["H1606","At thy rebuke",0,13],["H0430","O God",15,20],["H3290","of Jacob",21,29],["H7393","both the chariot",31,47],["H5483","and horse",48,57],["H7290","are cast into a dead sleep",58,84]]},"76:7":{"text":"Thou, even thou, art to be feared: and who may stand in thy sight when once thou art angry?","words":[["H3372","Thou, even thou, art to be feared",0,33],["H5975","and who may stand",35,52],["H6440","in thy sight",53,65],["H0227","when",66,70],["H0639","once thou art angry",71,90]]},"76:8":{"text":"Thou didst cause judgment to be heard from heaven; the earth feared, and was still,","words":[["H1779","Thou didst cause judgment",0,25],["H8085","to be heard",26,37],["H8064","from heaven",38,49],["H0776","the earth",51,60],["H3372","feared",61,67],["H8252","and was still",69,82]]},"76:9":{"text":"When God arose to judgment, to save all the meek of the earth. Selah.","words":[["H0430","When God",0,8],["H6965","arose",9,14],["H4941","to judgment",15,26],["H3467","to save",28,35],["H6035","all the meek",36,48],["H0776","of the earth",49,61],["H5542","Selah",63,68]]},"76:10":{"text":"Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain.","words":[["H2534","Surely the wrath",0,16],["H0120","of man",17,23],["H3034","shall praise",24,36],["H7611","thee: the remainder",37,56],["H2534","of wrath",57,65],["H2296","shalt thou restrain",66,85]]},"76:11":{"text":"Vow, and pay unto the LORD your God: let all that be round about him bring presents unto him that ought to be feared.","words":[["H5087","Vow",0,3],["H7999","and pay",5,12],["H3068","unto the LORD",13,26],["H0430","your God",27,35],["H5439","let all that be round about",37,64],["H2986","him bring",65,74],["H7862","presents",75,83],["H4172","unto him that ought to be feared",84,116]]},"76:12":{"text":"He shall cut off the spirit of princes: he is terrible to the kings of the earth.","words":[["H1219","He shall cut off",0,16],["H7307","the spirit",17,27],["H5057","of princes",28,38],["H3372","he is terrible",40,54],["H4428","to the kings",55,67],["H0776","of the earth",68,80]]},"77:1":{"text":"To the chief Musician, to Jeduthun, A Psalm of Asaph. I cried unto God with my voice, even unto God with my voice; and he gave ear unto me.","words":[["H5329","To the chief Musician",0,21],["H3038","to Jeduthun",23,34],["H4210","A Psalm",36,43],["H0623","of Asaph",44,52],["H6817","I cried",54,61],["H0430","unto God",62,70],["H6963","with my voice",71,84],["H0430","even unto God",86,99],["H6963","with my voice",100,113],["H0238","and he gave ear",115,130]]},"77:2":{"text":"In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not: my soul refused to be comforted.","words":[["H3117","In the day",0,10],["H6869","of my trouble",11,24],["H1875","I sought",25,33],["H0136","the Lord",34,42],["H3027","my sore",44,51],["H5064","ran",52,55],["H3915","in the night",56,68],["H6313","and ceased",70,80],["H5315","not: my soul",81,93],["H3985","refused",94,101],["H5162","to be comforted",102,117]]},"77:3":{"text":"I remembered God, and was troubled: I complained, and my spirit was overwhelmed. Selah.","words":[["H2142","I remembered",0,12],["H0430","God",13,16],["H1993","and was troubled",18,34],["H7878","I complained",36,48],["H7307","and my spirit",50,63],["H5848","was overwhelmed",64,79],["H5542","Selah",81,86]]},"77:4":{"text":"Thou holdest mine eyes waking: I am so troubled that I cannot speak.","words":[["H0270","Thou holdest",0,12],["H5869","mine eyes",13,22],["H8109","waking",23,29],["H6470","I am so troubled",31,47],["H1696","that I cannot speak",48,67]]},"77:5":{"text":"I have considered the days of old, the years of ancient times.","words":[["H2803","I have considered",0,17],["H3117","the days",18,26],["H6924","of old",27,33],["H8141","the years",35,44],["H5769","of ancient times",45,61]]},"77:6":{"text":"I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search.","words":[["H2142","I call to remembrance",0,21],["H5058","my song",22,29],["H3915","in the night",30,42],["H7878","I commune",44,53],["H3824","with mine own heart",54,73],["H7307","and my spirit",75,88],["H2664","made diligent search",89,109]]},"77:7":{"text":"Will the Lord cast off for ever? and will he be favourable no more?","words":[["H0136","Will the Lord",0,13],["H2186","cast off",14,22],["H5769","for ever",23,31],["H3254","and will",33,41],["H7521","he be favourable",42,58]]},"77:8":{"text":"Is his mercy clean gone for ever? doth his promise fail for evermore?","words":[["H2617","Is his mercy",0,12],["H0656","clean gone",13,23],["H5331","for ever",24,32],["H0562","doth his promise",34,50],["H1584","fail",51,55],["H1755","for evermore",56,68],["H1755","for evermore",56,68]]},"77:9":{"text":"Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah.","words":[["H0410","Hath God",0,8],["H7911","forgotten",9,18],["H2589","to be gracious",19,33],["H0639","hath he in anger",35,51],["H7092","shut up",52,59],["H7356","his tender mercies",60,78],["H5542","Selah",80,85]]},"77:10":{"text":"And I said, This is my infirmity: but I will remember the years of the right hand of the most High.","words":[["H0559","And I said",0,10],["H2470","This is my infirmity",12,32],["H8141","but I will remember the years",34,63],["H3225","of the right hand",64,81],["H5945","of the most High",82,98]]},"77:11":{"text":"I will remember the works of the LORD: surely I will remember thy wonders of old.","words":[["H2142","I will remember",0,15],["H2142","I will remember",0,15],["H4611","the works",16,25],["H3050","of the LORD",26,37],["H2142","surely I will remember",39,61],["H6382","thy wonders",62,73],["H6924","of old",74,80]]},"77:12":{"text":"I will meditate also of all thy work, and talk of thy doings.","words":[["H1897","I will meditate",0,15],["H6467","also of all thy work",16,36],["H7878","and talk",38,46],["H5949","of thy doings",47,60]]},"77:13":{"text":"Thy way, O God, is in the sanctuary: who is so great a God as our God?","words":[["H1870","Thy way",0,7],["H0430","O God",9,14],["H6944","is in the sanctuary",16,35],["H1419","who is so great",37,52],["H0410","a God",53,58],["H0430","as our God",59,69]]},"77:14":{"text":"Thou art the God that doest wonders: thou hast declared thy strength among the people.","words":[["H0410","Thou art the God",0,16],["H6213","that doest",17,27],["H6382","wonders",28,35],["H3045","thou hast declared",37,55],["H5797","thy strength",56,68],["H5971","among the people",69,85]]},"77:15":{"text":"Thou hast with thine arm redeemed thy people, the sons of Jacob and Joseph. Selah.","words":[["H2220","Thou hast with thine arm",0,24],["H1350","redeemed",25,33],["H5971","thy people",34,44],["H1121","the sons",46,54],["H3290","of Jacob",55,63],["H3130","and Joseph",64,74],["H5542","Selah",76,81]]},"77:16":{"text":"The waters saw thee, O God, the waters saw thee; they were afraid: the depths also were troubled.","words":[["H4325","The waters",0,10],["H7200","saw",11,14],["H0430","thee, O God",15,26],["H4325","the waters",28,38],["H7200","saw",39,42],["H2342","thee; they were afraid",43,65],["H8415","the depths",67,77],["H7264","also were troubled",78,96]]},"77:17":{"text":"The clouds poured out water: the skies sent out a sound: thine arrows also went abroad.","words":[["H5645","The clouds",0,10],["H2229","poured out",11,21],["H4325","water",22,27],["H7834","the skies",29,38],["H5414","sent out",39,47],["H6963","a sound",48,55],["H2687","thine arrows",57,69],["H1980","also went abroad",70,86]]},"77:18":{"text":"The voice of thy thunder was in the heaven: the lightnings lightened the world: the earth trembled and shook.","words":[["H6963","The voice",0,9],["H7482","of thy thunder",10,24],["H1534","was in the heaven",25,42],["H1300","the lightnings",44,58],["H0215","lightened",59,68],["H8398","the world",69,78],["H0776","the earth",80,89],["H7264","trembled",90,98],["H7493","and shook",99,108]]},"77:19":{"text":"Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known.","words":[["H1870","Thy way",0,7],["H3220","is in the sea",8,21],["H7635","and thy path",23,35],["H7227","in the great",36,48],["H4325","waters",49,55],["H6119","and thy footsteps",57,74],["H3045","are not known",75,88]]},"77:20":{"text":"Thou leddest thy people like a flock by the hand of Moses and Aaron.","words":[["H5148","Thou leddest",0,12],["H5971","thy people",13,23],["H6629","like a flock",24,36],["H3027","by the hand",37,48],["H4872","of Moses",49,57],["H0175","and Aaron",58,67]]},"78:1":{"text":"Maschil of Asaph. Give ear, O my people, to my law: incline your ears to the words of my mouth.","words":[["H4905","Maschil",0,7],["H0623","of Asaph",8,16],["H0238","Give ear",18,26],["H5971","O my people",28,39],["H8451","to my law",41,50],["H5186","incline",52,59],["H0241","your ears",60,69],["H0561","to the words",70,82],["H6310","of my mouth",83,94]]},"78:2":{"text":"I will open my mouth in a parable: I will utter dark sayings of old:","words":[["H6605","I will open",0,11],["H6310","my mouth",12,20],["H4912","in a parable",21,33],["H5042","I will utter",35,47],["H2420","dark sayings",48,60],["H6924","of old",61,67]]},"78:3":{"text":"Which we have heard and known, and our fathers have told us.","words":[["H8085","Which we have heard",0,19],["H3045","and known",20,29],["H0001","and our fathers",31,46],["H5608","have told",47,56]]},"78:4":{"text":"We will not hide them from their children, shewing to the generation to come the praises of the LORD, and his strength, and his wonderful works that he hath done.","words":[["H3582","We will not hide",0,16],["H1121","them from their children",17,41],["H5608","shewing",43,50],["H1755","to the generation",51,68],["H0314","to come",69,76],["H8416","the praises",77,88],["H3068","of the LORD",89,100],["H5807","and his strength",102,118],["H6381","and his wonderful works",120,143],["H6213","that he hath done",144,161]]},"78:5":{"text":"For he established a testimony in Jacob, and appointed a law in Israel, which he commanded our fathers, that they should make them known to their children:","words":[["H6965","For he established",0,18],["H5715","a testimony",19,30],["H3290","in Jacob",31,39],["H7760","and appointed",41,54],["H8451","a law",55,60],["H3478","in Israel",61,70],["H6680","which he commanded",72,90],["H0001","our fathers",91,102],["H3045","that they should make them known",104,136],["H1121","to their children",137,154]]},"78:6":{"text":"That the generation to come might know them, even the children which should be born; who should arise and declare them to their children:","words":[["H1755","That the generation",0,19],["H0314","to come",20,27],["H3045","might know",28,38],["H1121","them, even the children",39,62],["H3205","which should be born",63,83],["H6965","who should arise",85,101],["H5608","and declare",102,113],["H1121","them to their children",114,136]]},"78:7":{"text":"That they might set their hope in God, and not forget the works of God, but keep his commandments:","words":[["H7760","That they might set",0,19],["H3689","their hope",20,30],["H0430","in God",31,37],["H7911","and not forget",39,53],["H4611","the works",54,63],["H0410","of God",64,70],["H5341","but keep",72,80],["H4687","his commandments",81,97]]},"78:8":{"text":"And might not be as their fathers, a stubborn and rebellious generation; a generation that set not their heart aright, and whose spirit was not stedfast with God.","words":[["H0001","And might not be as their fathers",0,33],["H5637","a stubborn",35,45],["H4784","and rebellious",46,60],["H1755","generation",61,71],["H1755","a generation",73,85],["H3559","that set",86,94],["H3820","not their heart",95,110],["H3559","aright",111,117],["H7307","and whose spirit",119,135],["H0539","was not stedfast",136,152],["H0410","with God",153,161]]},"78:9":{"text":"The children of Ephraim, being armed, and carrying bows, turned back in the day of battle.","words":[["H1121","The children",0,12],["H0669","of Ephraim",13,23],["H5401","being armed",25,36],["H7411","and carrying",38,50],["H7198","bows",51,55],["H2015","turned back",57,68],["H3117","in the day",69,79],["H7128","of battle",80,89]]},"78:10":{"text":"They kept not the covenant of God, and refused to walk in his law;","words":[["H8104","They kept",0,9],["H1285","not the covenant",10,26],["H0430","of God",27,33],["H3985","and refused",35,46],["H3212","to walk",47,54],["H8451","in his law",55,65]]},"78:11":{"text":"And forgat his works, and his wonders that he had shewed them.","words":[["H7911","And forgat",0,10],["H5949","his works",11,20],["H6381","and his wonders",22,37],["H7200","that he had shewed",38,56]]},"78:12":{"text":"Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan.","words":[["H6382","Marvellous things",0,17],["H6213","did",18,21],["H5048","he in the sight",22,37],["H0001","of their fathers",38,54],["H0776","in the land",56,67],["H4714","of Egypt",68,76],["H7704","in the field",78,90],["H6814","of Zoan",91,98]]},"78:13":{"text":"He divided the sea, and caused them to pass through; and he made the waters to stand as an heap.","words":[["H1234","He divided",0,10],["H3220","the sea",11,18],["H5674","and caused them to pass through",20,51],["H4325","and he made the waters",53,75],["H5324","to stand",76,84],["H5067","as an heap",85,95]]},"78:14":{"text":"In the daytime also he led them with a cloud, and all the night with a light of fire.","words":[["H3119","In the daytime",0,14],["H5148","also he led",15,26],["H6051","them with a cloud",27,44],["H3915","and all the night",46,63],["H0216","with a light",64,76],["H0784","of fire",77,84]]},"78:15":{"text":"He clave the rocks in the wilderness, and gave them drink as out of the great depths.","words":[["H1234","He clave",0,8],["H6697","the rocks",9,18],["H4057","in the wilderness",19,36],["H8248","and gave them drink",38,57],["H7227","as out of the great",58,77],["H8415","depths",78,84]]},"78:16":{"text":"He brought streams also out of the rock, and caused waters to run down like rivers.","words":[["H3318","He brought",0,10],["H5140","streams",11,18],["H5553","also out of the rock",19,39],["H4325","and caused waters",41,58],["H3381","to run down",59,70],["H5104","like rivers",71,82]]},"78:17":{"text":"And they sinned yet more against him by provoking the most High in the wilderness.","words":[["H2398","And they sinned",0,15],["H3254","yet more",16,24],["H4784","against him by provoking",25,49],["H5945","the most High",50,63],["H6723","in the wilderness",64,81]]},"78:18":{"text":"And they tempted God in their heart by asking meat for their lust.","words":[["H5254","And they tempted",0,16],["H0410","God",17,20],["H3824","in their heart",21,35],["H7592","by asking",36,45],["H0400","meat",46,50],["H5315","for their lust",51,65]]},"78:19":{"text":"Yea, they spake against God; they said, Can God furnish a table in the wilderness?","words":[["H1696","Yea, they spake",0,15],["H0430","against God",16,27],["H0559","they said",29,38],["H3201","Can",40,43],["H0410","God",44,47],["H6186","furnish",48,55],["H7979","a table",56,63],["H4057","in the wilderness",64,81]]},"78:20":{"text":"Behold, he smote the rock, that the waters gushed out, and the streams overflowed; can he give bread also? can he provide flesh for his people?","words":[["H5221","Behold, he smote",0,16],["H6697","the rock",17,25],["H4325","that the waters",27,42],["H2100","gushed out",43,53],["H5158","and the streams",55,70],["H7857","overflowed",71,81],["H3201","can",83,86],["H5414","he give",87,94],["H3899","bread",95,100],["H3201","also? can",101,110],["H3559","he provide",111,121],["H7607","flesh",122,127],["H5971","for his people",128,142]]},"78:21":{"text":"Therefore the LORD heard this, and was wroth: so a fire was kindled against Jacob, and anger also came up against Israel;","words":[["H3068","Therefore the LORD",0,18],["H8085","heard",19,24],["H5674","this, and was wroth",25,44],["H0784","so a fire",46,55],["H5400","was kindled",56,67],["H3290","against Jacob",68,81],["H0639","and anger",83,92],["H5927","also came up",93,105],["H3478","against Israel",106,120]]},"78:22":{"text":"Because they believed not in God, and trusted not in his salvation:","words":[["H0539","Because they believed",0,21],["H0430","not in God",22,32],["H0982","and trusted",34,45],["H3444","not in his salvation",46,66]]},"78:23":{"text":"Though he had commanded the clouds from above, and opened the doors of heaven,","words":[["H6680","Though he had commanded",0,23],["H7834","the clouds",24,34],["H4605","from above",35,45],["H6605","and opened",47,57],["H1817","the doors",58,67],["H8064","of heaven",68,77]]},"78:24":{"text":"And had rained down manna upon them to eat, and had given them of the corn of heaven.","words":[["H4305","And had rained down",0,19],["H4478","manna",20,25],["H0398","upon them to eat",26,42],["H5414","and had given",44,57],["H1715","them of the corn",58,74],["H8064","of heaven",75,84]]},"78:25":{"text":"Man did eat angels' food: he sent them meat to the full.","words":[["H0376","Man",0,3],["H0398","did eat",4,11],["H0047","angels'",12,19],["H3899","food",20,24],["H7971","he sent",26,33],["H6720","them meat",34,43],["H7648","to the full",44,55]]},"78:26":{"text":"He caused an east wind to blow in the heaven: and by his power he brought in the south wind.","words":[["H6921","He caused an east wind",0,22],["H5265","to blow",23,30],["H8064","in the heaven",31,44],["H5797","and by his power",46,62],["H5090","he brought in",63,76],["H8486","the south wind",77,91]]},"78:27":{"text":"He rained flesh also upon them as dust, and feathered fowls like as the sand of the sea:","words":[["H4305","He rained",0,9],["H7607","flesh",10,15],["H6083","also upon them as dust",16,38],["H3671","and feathered",40,53],["H5775","fowls",54,59],["H2344","like as the sand",60,76],["H3220","of the sea",77,87]]},"78:28":{"text":"And he let it fall in the midst of their camp, round about their habitations.","words":[["H5307","And he let it fall",0,18],["H7130","in the midst",19,31],["H4264","of their camp",32,45],["H5439","round about",47,58],["H4908","their habitations",59,76]]},"78:29":{"text":"So they did eat, and were well filled: for he gave them their own desire;","words":[["H0398","So they did eat",0,15],["H3966","and were well",17,30],["H7646","filled",31,37],["H0935","for he gave",39,50],["H8378","them their own desire",51,72]]},"78:30":{"text":"They were not estranged from their lust. But while their meat was yet in their mouths,","words":[["H2114","They were not estranged",0,23],["H8378","from their lust",24,39],["H0400","But while their meat",41,61],["H6310","was yet in their mouths",62,85]]},"78:31":{"text":"The wrath of God came upon them, and slew the fattest of them, and smote down the chosen men of Israel.","words":[["H0639","The wrath",0,9],["H0430","of God",10,16],["H5927","came",17,21],["H2026","upon them, and slew",22,41],["H4924","the fattest",42,53],["H3766","of them, and smote down",54,77],["H0970","the chosen",78,88],["H3478","men of Israel",89,102]]},"78:32":{"text":"For all this they sinned still, and believed not for his wondrous works.","words":[["H2398","For all this they sinned",0,24],["H0539","still, and believed",25,44],["H6381","not for his wondrous works",45,71]]},"78:33":{"text":"Therefore their days did he consume in vanity, and their years in trouble.","words":[["H3117","Therefore their days",0,20],["H3615","did he consume",21,35],["H1892","in vanity",36,45],["H8141","and their years",47,62],["H0928","in trouble",63,73]]},"78:34":{"text":"When he slew them, then they sought him: and they returned and enquired early after God.","words":[["H2026","When he slew",0,12],["H1875","them, then they sought",13,35],["H7725","him: and they returned",36,58],["H7836","and enquired early",59,77],["H0410","after God",78,87]]},"78:35":{"text":"And they remembered that God was their rock, and the high God their redeemer.","words":[["H2142","And they remembered",0,19],["H0430","that God",20,28],["H6697","was their rock",29,43],["H5945","and the high",45,57],["H0410","God",58,61],["H1350","their redeemer",62,76]]},"78:36":{"text":"Nevertheless they did flatter him with their mouth, and they lied unto him with their tongues.","words":[["H6601","Nevertheless they did flatter",0,29],["H6310","him with their mouth",30,50],["H3576","and they lied",52,65],["H3956","unto him with their tongues",66,93]]},"78:37":{"text":"For their heart was not right with him, neither were they stedfast in his covenant.","words":[["H3820","For their heart",0,15],["H3559","was not right",16,29],["H0539","with him, neither were they stedfast",30,66],["H1285","in his covenant",67,82]]},"78:38":{"text":"But he, being full of compassion, forgave their iniquity, and destroyed them not: yea, many a time turned he his anger away, and did not stir up all his wrath.","words":[["H7349","But he, being full of compassion",0,32],["H3722","forgave",34,41],["H5771","their iniquity",42,56],["H7843","and destroyed",58,71],["H7235","them not: yea, many a time",72,98],["H7725","turned",99,105],["H0639","he his anger",106,118],["H7725","away",119,123],["H5782","and did not stir up",125,144],["H2534","all his wrath",145,158]]},"78:39":{"text":"For he remembered that they were but flesh; a wind that passeth away, and cometh not again.","words":[["H2142","For he remembered",0,17],["H1320","that they were but flesh",18,42],["H7307","a wind",44,50],["H1980","that passeth away",51,68],["H7725","and cometh not again",70,90]]},"78:40":{"text":"How oft did they provoke him in the wilderness, and grieve him in the desert!","words":[["H4100","How",0,3],["H4784","oft did they provoke",4,24],["H4057","him in the wilderness",25,46],["H6087","and grieve",48,58],["H3452","him in the desert",59,76]]},"78:41":{"text":"Yea, they turned back and tempted God, and limited the Holy One of Israel.","words":[["H7725","Yea, they turned back",0,21],["H5254","and tempted",22,33],["H0410","God",34,37],["H8428","and limited",39,50],["H6918","the Holy One",51,63],["H3478","of Israel",64,73]]},"78:42":{"text":"They remembered not his hand, nor the day when he delivered them from the enemy.","words":[["H2142","They remembered",0,15],["H3027","not his hand",16,28],["H3117","nor the day",30,41],["H6299","when he delivered",42,59],["H6862","them from the enemy",60,79]]},"78:43":{"text":"How he had wrought his signs in Egypt, and his wonders in the field of Zoan:","words":[["H7760","How he had wrought",0,18],["H0226","his signs",19,28],["H4714","in Egypt",29,37],["H4159","and his wonders",39,54],["H7704","in the field",55,67],["H6814","of Zoan",68,75]]},"78:44":{"text":"And had turned their rivers into blood; and their floods, that they could not drink.","words":[["H2015","And had turned",0,14],["H2975","their rivers",15,27],["H1818","into blood",28,38],["H5140","and their floods",40,56],["H8354","that they could not drink",58,83]]},"78:45":{"text":"He sent divers sorts of flies among them, which devoured them; and frogs, which destroyed them.","words":[["H7971","He sent",0,7],["H6157","divers sorts of flies",8,29],["H0398","among them, which devoured",30,56],["H6854","them; and frogs",57,72],["H7843","which destroyed",74,89]]},"78:46":{"text":"He gave also their increase unto the caterpiller, and their labour unto the locust.","words":[["H5414","He gave",0,7],["H2981","also their increase",8,27],["H2625","unto the caterpiller",28,48],["H3018","and their labour",50,66],["H0697","unto the locust",67,82]]},"78:47":{"text":"He destroyed their vines with hail, and their sycomore trees with frost.","words":[["H2026","He destroyed",0,12],["H1612","their vines",13,24],["H1259","with hail",25,34],["H8256","and their sycomore trees",36,60],["H2602","with frost",61,71]]},"78:48":{"text":"He gave up their cattle also to the hail, and their flocks to hot thunderbolts.","words":[["H5462","He gave up",0,10],["H1165","their cattle",11,23],["H1259","also to the hail",24,40],["H4735","and their flocks",42,58],["H7565","to hot thunderbolts",59,78]]},"78:49":{"text":"He cast upon them the fierceness of his anger, wrath, and indignation, and trouble, by sending evil angels among them.","words":[["H7971","He cast",0,7],["H2740","upon them the fierceness",8,32],["H0639","of his anger",33,45],["H5678","wrath",47,52],["H2195","and indignation",54,69],["H6869","and trouble",71,82],["H4917","by sending",84,94],["H7451","evil",95,99],["H4397","angels",100,106]]},"78:50":{"text":"He made a way to his anger; he spared not their soul from death, but gave their life over to the pestilence;","words":[["H6424","He made",0,7],["H5410","a way",8,13],["H0639","to his anger",14,26],["H2820","he spared",28,37],["H5315","not their soul",38,52],["H4194","from death",53,63],["H5462","but gave",65,73],["H2416","their life",74,84],["H5462","over",85,89],["H1698","to the pestilence",90,107]]},"78:51":{"text":"And smote all the firstborn in Egypt; the chief of their strength in the tabernacles of Ham:","words":[["H5221","And smote",0,9],["H1060","all the firstborn",10,27],["H4714","in Egypt",28,36],["H7225","the chief",38,47],["H0202","of their strength",48,65],["H0168","in the tabernacles",66,84],["H2526","of Ham",85,91]]},"78:52":{"text":"But made his own people to go forth like sheep, and guided them in the wilderness like a flock.","words":[["H5971","But made his own people",0,23],["H5265","to go forth",24,35],["H6629","like sheep",36,46],["H5090","and guided",48,58],["H4057","them in the wilderness",59,81],["H5739","like a flock",82,94]]},"78:53":{"text":"And he led them on safely, so that they feared not: but the sea overwhelmed their enemies.","words":[["H5148","And he led",0,10],["H0983","them on safely",11,25],["H6342","so that they feared",27,46],["H3220","not: but the sea",47,63],["H3680","overwhelmed",64,75],["H0341","their enemies",76,89]]},"78:54":{"text":"And he brought them to the border of his sanctuary, even to this mountain, which his right hand had purchased.","words":[["H0935","And he brought",0,14],["H1366","them to the border",15,33],["H6944","of his sanctuary",34,50],["H2022","even to this mountain",52,73],["H3225","which his right hand",75,95],["H7069","had purchased",96,109]]},"78:55":{"text":"He cast out the heathen also before them, and divided them an inheritance by line, and made the tribes of Israel to dwell in their tents.","words":[["H1644","He cast out",0,11],["H1471","the heathen",12,23],["H6440","also before",24,35],["H5307","them, and divided",36,53],["H5159","them an inheritance",54,73],["H2256","by line",74,81],["H7626","and made the tribes",83,102],["H3478","of Israel",103,112],["H7931","to dwell",113,121],["H0168","in their tents",122,136]]},"78:56":{"text":"Yet they tempted and provoked the most high God, and kept not his testimonies:","words":[["H5254","Yet they tempted",0,16],["H4784","and provoked",17,29],["H5945","the most high",30,43],["H0430","God",44,47],["H8104","and kept",49,57],["H5713","not his testimonies",58,77]]},"78:57":{"text":"But turned back, and dealt unfaithfully like their fathers: they were turned aside like a deceitful bow.","words":[["H5472","But turned back",0,15],["H0898","and dealt unfaithfully",17,39],["H0001","like their fathers",40,58],["H2015","they were turned aside",60,82],["H7423","like a deceitful",83,99],["H7198","bow",100,103]]},"78:58":{"text":"For they provoked him to anger with their high places, and moved him to jealousy with their graven images.","words":[["H3707","For they provoked him to anger",0,30],["H1116","with their high places",31,53],["H7065","and moved him to jealousy",55,80],["H6456","with their graven images",81,105]]},"78:59":{"text":"When God heard this, he was wroth, and greatly abhorred Israel:","words":[["H0430","When God",0,8],["H8085","heard",9,14],["H5674","this, he was wroth",15,33],["H3966","and greatly",35,46],["H3988","abhorred",47,55],["H3478","Israel",56,62]]},"78:60":{"text":"So that he forsook the tabernacle of Shiloh, the tent which he placed among men;","words":[["H5203","So that he forsook",0,18],["H4908","the tabernacle",19,33],["H7887","of Shiloh",34,43],["H0168","the tent",45,53],["H7931","which he placed",54,69],["H0120","among men",70,79]]},"78:61":{"text":"And delivered his strength into captivity, and his glory into the enemy's hand.","words":[["H5414","And delivered",0,13],["H5797","his strength",14,26],["H7628","into captivity",27,41],["H8597","and his glory",43,56],["H6862","into the enemy's",57,73],["H3027","hand",74,78]]},"78:62":{"text":"He gave his people over also unto the sword; and was wroth with his inheritance.","words":[["H5462","He gave",0,7],["H5971","his people",8,18],["H5462","over",19,23],["H2719","also unto the sword",24,43],["H5674","and was wroth",45,58],["H5159","with his inheritance",59,79]]},"78:63":{"text":"The fire consumed their young men; and their maidens were not given to marriage.","words":[["H0784","The fire",0,8],["H0398","consumed",9,17],["H0970","their young men",18,33],["H1330","and their maidens",35,52],["H1984","were not given to marriage",53,79]]},"78:64":{"text":"Their priests fell by the sword; and their widows made no lamentation.","words":[["H3548","Their priests",0,13],["H5307","fell",14,18],["H2719","by the sword",19,31],["H0490","and their widows",33,49],["H1058","made no lamentation",50,69]]},"78:65":{"text":"Then the Lord awaked as one out of sleep, and like a mighty man that shouteth by reason of wine.","words":[["H0136","Then the Lord",0,13],["H3364","awaked",14,20],["H3463","as one out of sleep",21,40],["H1368","and like a mighty man",42,63],["H7442","that shouteth",64,77],["H3196","by reason of wine",78,95]]},"78:66":{"text":"And he smote his enemies in the hinder parts: he put them to a perpetual reproach.","words":[["H5221","And he smote",0,12],["H6862","his enemies",13,24],["H0268","in the hinder parts",25,44],["H5414","he put",46,52],["H5769","them to a perpetual",53,72],["H2781","reproach",73,81]]},"78:67":{"text":"Moreover he refused the tabernacle of Joseph, and chose not the tribe of Ephraim:","words":[["H3988","Moreover he refused",0,19],["H0168","the tabernacle",20,34],["H3130","of Joseph",35,44],["H0977","and chose",46,55],["H7626","not the tribe",56,69],["H0669","of Ephraim",70,80]]},"78:68":{"text":"But chose the tribe of Judah, the mount Zion which he loved.","words":[["H0977","But chose",0,9],["H7626","the tribe",10,19],["H3063","of Judah",20,28],["H2022","the mount",30,39],["H6726","Zion",40,44],["H0157","which he loved",45,59]]},"78:69":{"text":"And he built his sanctuary like high palaces, like the earth which he hath established for ever.","words":[["H1129","And he built",0,12],["H4720","his sanctuary",13,26],["H7311","like high",27,36],["H0776","palaces, like the earth",37,60],["H3245","which he hath established",61,86],["H5769","for ever",87,95]]},"78:70":{"text":"He chose David also his servant, and took him from the sheepfolds:","words":[["H0977","He chose",0,8],["H1732","David",9,14],["H5650","also his servant",15,31],["H3947","and took",33,41],["H4356","him from the sheepfolds",42,65],["H6629","him from the sheepfolds",42,65]]},"78:71":{"text":"From following the ewes great with young he brought him to feed Jacob his people, and Israel his inheritance.","words":[["H0310","From following",0,14],["H5763","the ewes great with young",15,40],["H0935","he brought",41,51],["H7462","him to feed",52,63],["H3290","Jacob",64,69],["H5971","his people",70,80],["H3478","and Israel",82,92],["H5159","his inheritance",93,108]]},"78:72":{"text":"So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands.","words":[["H7462","So he fed",0,9],["H8537","them according to the integrity",10,41],["H3824","of his heart",42,54],["H5148","and guided",56,66],["H8394","them by the skilfulness",67,90],["H3709","of his hands",91,103]]},"79:1":{"text":"A Psalm of Asaph. O God, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps.","words":[["H4210","A Psalm",0,7],["H0623","of Asaph",8,16],["H0430","O God",18,23],["H1471","the heathen",25,36],["H0935","are come",37,45],["H5159","into thine inheritance",46,68],["H6944","thy holy",70,78],["H1964","temple",79,85],["H2930","have they defiled",86,103],["H7760","they have laid",105,119],["H3389","Jerusalem",120,129],["H5856","on heaps",130,138]]},"79:2":{"text":"The dead bodies of thy servants have they given to be meat unto the fowls of the heaven, the flesh of thy saints unto the beasts of the earth.","words":[["H5038","The dead bodies",0,15],["H5650","of thy servants",16,31],["H5414","have they given",32,47],["H3978","to be meat",48,58],["H5775","unto the fowls",59,73],["H8064","of the heaven",74,87],["H1320","the flesh",89,98],["H2623","of thy saints",99,112],["H2416","unto the beasts",113,128],["H0776","of the earth",129,141]]},"79:3":{"text":"Their blood have they shed like water round about Jerusalem; and there was none to bury them.","words":[["H1818","Their blood",0,11],["H8210","have they shed",12,26],["H4325","like water",27,37],["H5439","round about",38,49],["H3389","Jerusalem",50,59],["H6912","and there was none to bury",61,87]]},"79:4":{"text":"We are become a reproach to our neighbours, a scorn and derision to them that are round about us.","words":[["H2781","We are become a reproach",0,24],["H7934","to our neighbours",25,42],["H3933","a scorn",44,51],["H7047","and derision",52,64],["H5439","to them that are round about",65,93]]},"79:5":{"text":"How long, LORD? wilt thou be angry for ever? shall thy jealousy burn like fire?","words":[["H3068","How long, LORD",0,14],["H0599","wilt thou be angry",16,34],["H5331","for ever",35,43],["H7068","shall thy jealousy",45,63],["H1197","burn",64,68],["H0784","like fire",69,78]]},"79:6":{"text":"Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name.","words":[["H8210","Pour out",0,8],["H2534","thy wrath",9,18],["H1471","upon the heathen",19,35],["H3045","that have not known",36,55],["H4467","thee, and upon the kingdoms",56,83],["H7121","that have not called",84,104],["H8034","upon thy name",105,118]]},"79:7":{"text":"For they have devoured Jacob, and laid waste his dwelling place.","words":[["H0398","For they have devoured",0,22],["H3290","Jacob",23,28],["H8074","and laid waste",30,44],["H5116","his dwelling place",45,63]]},"79:8":{"text":"O remember not against us former iniquities: let thy tender mercies speedily prevent us: for we are brought very low.","words":[["H2142","O remember",0,10],["H7223","not against us former",11,32],["H5771","iniquities",33,43],["H7356","let thy tender mercies",45,67],["H4118","speedily",68,76],["H6923","prevent",77,84],["H1809","us: for we are brought",85,107],["H3966","very",108,112],["H1809","low",113,116]]},"79:9":{"text":"Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name's sake.","words":[["H5826","Help",0,4],["H0430","us, O God",5,14],["H3468","of our salvation",15,31],["H1697","for",33,36],["H3519","the glory",37,46],["H8034","of thy name",47,58],["H5337","and deliver",60,71],["H3722","us, and purge away",72,90],["H2403","our sins",91,99],["H8034","for thy name's",101,115]]},"79:10":{"text":"Wherefore should the heathen say, Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed.","words":[["H1471","Wherefore should the heathen",0,28],["H0559","say",29,32],["H0430","Where is their God",34,52],["H3045","let him be known",54,70],["H1471","among the heathen",71,88],["H5869","in our sight",89,101],["H5360","by the revenging",102,118],["H1818","of the blood",119,131],["H5650","of thy servants",132,147],["H8210","which is shed",148,161]]},"79:11":{"text":"Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die;","words":[["H0603","Let the sighing",0,15],["H0615","of the prisoner",16,31],["H0935","come",32,36],["H6440","before",37,43],["H1433","thee; according to the greatness",44,76],["H2220","of thy power",77,89],["H3498","preserve",90,98],["H1121","thou those that are appointed",99,128],["H8546","to die",129,135]]},"79:12":{"text":"And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord.","words":[["H7725","And render",0,10],["H7934","unto our neighbours",11,30],["H7659","sevenfold",31,40],["H2436","into their bosom",41,57],["H2781","their reproach",58,72],["H2778","wherewith they have reproached",74,104],["H0136","thee, O Lord",105,117]]},"79:13":{"text":"So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations.","words":[["H5971","So we thy people",0,16],["H6629","and sheep",17,26],["H4830","of thy pasture",27,41],["H3034","will give thee thanks",42,63],["H5769","for ever",64,72],["H5608","we will shew forth",74,92],["H8416","thy praise",93,103],["H1755","to all",104,110],["H1755","generations",111,122]]},"80:1":{"text":"To the chief Musician upon Shoshannimeduth, A Psalm of Asaph. Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock; thou that dwellest between the cherubims, shine forth.","words":[["H5329","To the chief Musician",0,21],["H7802","upon Shoshannimeduth",22,42],["H4210","A Psalm",44,51],["H0623","of Asaph",52,60],["H0238","Give ear",62,70],["H7462","O Shepherd",72,82],["H3478","of Israel",83,92],["H5090","thou that leadest",94,111],["H3130","Joseph",112,118],["H6629","like a flock",119,131],["H3427","thou that dwellest",133,151],["H3742","between the cherubims",152,173],["H3313","shine forth",175,186]]},"80:2":{"text":"Before Ephraim and Benjamin and Manasseh stir up thy strength, and come and save us.","words":[["H6440","Before",0,6],["H0669","Ephraim",7,14],["H1144","and Benjamin",15,27],["H4519","and Manasseh",28,40],["H5782","stir up",41,48],["H1369","thy strength",49,61],["H3212","and come",63,71],["H3444","and save",72,80]]},"80:3":{"text":"Turn us again, O God, and cause thy face to shine; and we shall be saved.","words":[["H7725","Turn us again",0,13],["H0430","O God",15,20],["H6440","and cause thy face",22,40],["H0215","to shine",41,49],["H3467","and we shall be saved",51,72]]},"80:4":{"text":"O LORD God of hosts, how long wilt thou be angry against the prayer of thy people?","words":[["H3068","O LORD",0,6],["H0430","God",7,10],["H6635","of hosts",11,19],["H6225","how long wilt thou be angry",21,48],["H8605","against the prayer",49,67],["H5971","of thy people",68,81]]},"80:5":{"text":"Thou feedest them with the bread of tears; and givest them tears to drink in great measure.","words":[["H0398","Thou feedest",0,12],["H3899","them with the bread",13,32],["H1832","of tears",33,41],["H1832","and givest them tears",43,64],["H8248","to drink",65,73],["H7991","in great measure",74,90]]},"80:6":{"text":"Thou makest us a strife unto our neighbours: and our enemies laugh among themselves.","words":[["H7760","Thou makest",0,11],["H4066","us a strife",12,23],["H7934","unto our neighbours",24,43],["H0341","and our enemies",45,60],["H3932","laugh",61,66]]},"80:7":{"text":"Turn us again, O God of hosts, and cause thy face to shine; and we shall be saved.","words":[["H7725","Turn us again",0,13],["H0430","O God",15,20],["H6635","of hosts",21,29],["H6440","and cause thy face",31,49],["H0215","to shine",50,58],["H3467","and we shall be saved",60,81]]},"80:8":{"text":"Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it.","words":[["H5265","Thou hast brought",0,17],["H1612","a vine",18,24],["H4714","out of Egypt",25,37],["H1644","thou hast cast out",39,57],["H1471","the heathen",58,69],["H5193","and planted",71,82]]},"80:9":{"text":"Thou preparedst room before it, and didst cause it to take deep root, and it filled the land.","words":[["H6437","Thou preparedst",0,15],["H6440","room before",16,27],["H8328","it, and didst cause it to take deep",28,63],["H8327","root",64,68],["H4390","and it filled",70,83],["H0776","the land",84,92]]},"80:10":{"text":"The hills were covered with the shadow of it, and the boughs thereof were like the goodly cedars.","words":[["H2022","The hills",0,9],["H3680","were covered",10,22],["H6738","with the shadow",23,38],["H6057","of it, and the boughs",39,60],["H0410","thereof were like the goodly",61,89],["H0730","cedars",90,96]]},"80:11":{"text":"She sent out her boughs unto the sea, and her branches unto the river.","words":[["H7971","She sent out",0,12],["H7105","her boughs",13,23],["H3220","unto the sea",24,36],["H3127","and her branches",38,54],["H5104","unto the river",55,69]]},"80:12":{"text":"Why hast thou then broken down her hedges, so that all they which pass by the way do pluck her?","words":[["H6555","Why hast thou then broken down",0,30],["H1447","her hedges",31,41],["H5674","so that all they which pass",43,70],["H1870","by the way",71,81],["H0717","do pluck",82,90]]},"80:13":{"text":"The boar out of the wood doth waste it, and the wild beast of the field doth devour it.","words":[["H2386","The boar",0,8],["H3293","out of the wood",9,24],["H3765","doth waste",25,35],["H2123","it, and the wild beast",36,58],["H7704","of the field",59,71],["H7462","doth devour",72,83]]},"80:14":{"text":"Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine;","words":[["H7725","Return",0,6],["H0430","we beseech thee, O God",8,30],["H6635","of hosts",31,39],["H5027","look down",41,50],["H8064","from heaven",51,62],["H7200","and behold",64,74],["H6485","and visit",76,85],["H1612","this vine",86,95]]},"80:15":{"text":"And the vineyard which thy right hand hath planted, and the branch that thou madest strong for thyself.","words":[["H3657","And the vineyard",0,16],["H3661","And the vineyard",0,16],["H3225","which thy right hand",17,37],["H5193","hath planted",38,50],["H1121","and the branch",52,66],["H0553","that thou madest strong",67,90]]},"80:16":{"text":"It is burned with fire, it is cut down: they perish at the rebuke of thy countenance.","words":[["H8313","It is burned",0,12],["H0784","with fire",13,22],["H3683","it is cut down",24,38],["H0006","they perish",40,51],["H1606","at the rebuke",52,65],["H6440","of thy countenance",66,84]]},"80:17":{"text":"Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself.","words":[["H3027","Let thy hand",0,12],["H0376","be upon the man",13,28],["H3225","of thy right hand",29,46],["H1121","upon the son",48,60],["H0120","of man",61,67],["H0553","whom thou madest strong",68,91]]},"80:18":{"text":"So will not we go back from thee: quicken us, and we will call upon thy name.","words":[["H5472","So will not we go back",0,22],["H2421","from thee: quicken",23,41],["H7121","us, and we will call",42,62],["H8034","upon thy name",63,76]]},"80:19":{"text":"Turn us again, O LORD God of hosts, cause thy face to shine; and we shall be saved.","words":[["H7725","Turn us again",0,13],["H3068","O LORD",15,21],["H0430","God",22,25],["H6635","of hosts",26,34],["H6440","cause thy face",36,50],["H0215","to shine",51,59],["H3467","and we shall be saved",61,82]]},"81:1":{"text":"To the chief Musician upon Gittith, A Psalm of Asaph. Sing aloud unto God our strength: make a joyful noise unto the God of Jacob.","words":[["H5329","To the chief Musician",0,21],["H1665","upon Gittith",22,34],["H0623","A Psalm of Asaph",36,52],["H7442","Sing aloud",54,64],["H0430","unto God",65,73],["H5797","our strength",74,86],["H7321","make a joyful noise",88,107],["H0430","unto the God",108,120],["H3290","of Jacob",121,129]]},"81:2":{"text":"Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery.","words":[["H5375","Take",0,4],["H2172","a psalm",5,12],["H5414","and bring",14,23],["H8596","hither the timbrel",24,42],["H5273","the pleasant",44,56],["H3658","harp",57,61],["H5035","with the psaltery",62,79]]},"81:3":{"text":"Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day.","words":[["H8628","Blow up",0,7],["H7782","the trumpet",8,19],["H2320","in the new moon",20,35],["H3677","in the time appointed",37,58],["H2282","on our solemn feast",60,79],["H3117","day",80,83]]},"81:4":{"text":"For this was a statute for Israel, and a law of the God of Jacob.","words":[["H2706","For this was a statute",0,22],["H3478","for Israel",23,33],["H4941","and a law",35,44],["H0430","of the God",45,55],["H3290","of Jacob",56,64]]},"81:5":{"text":"This he ordained in Joseph for a testimony, when he went out through the land of Egypt: where I heard a language that I understood not.","words":[["H7760","This he ordained",0,16],["H3084","in Joseph",17,26],["H5715","for a testimony",27,42],["H3318","when he went out",44,60],["H0776","through the land",61,77],["H4714","of Egypt",78,86],["H8085","where I heard",88,101],["H8193","a language",102,112],["H3045","that I understood",113,130]]},"81:6":{"text":"I removed his shoulder from the burden: his hands were delivered from the pots.","words":[["H5493","I removed",0,9],["H7926","his shoulder",10,22],["H5447","from the burden",23,38],["H3709","his hands",40,49],["H5674","were delivered",50,64],["H1731","from the pots",65,78]]},"81:7":{"text":"Thou calledst in trouble, and I delivered thee; I answered thee in the secret place of thunder: I proved thee at the waters of Meribah. Selah.","words":[["H7121","Thou calledst",0,13],["H6869","in trouble",14,24],["H2502","and I delivered",26,41],["H6030","thee; I answered",42,58],["H5643","thee in the secret place",59,83],["H7482","of thunder",84,94],["H0974","I proved",96,104],["H4325","thee at the waters",105,123],["H4809","of Meribah",124,134],["H5542","Selah",136,141]]},"81:8":{"text":"Hear, O my people, and I will testify unto thee: O Israel, if thou wilt hearken unto me;","words":[["H8085","Hear",0,4],["H5971","O my people",6,17],["H5749","and I will testify",19,37],["H3478","unto thee: O Israel",38,57],["H8085","if thou wilt hearken",59,79]]},"81:9":{"text":"There shall no strange god be in thee; neither shalt thou worship any strange god.","words":[["H2114","There shall no strange",0,22],["H0410","god",23,26],["H7812","be in thee; neither shalt thou worship",27,65],["H5236","any strange",66,77],["H0410","god",78,81]]},"81:10":{"text":"I am the LORD thy God, which brought thee out of the land of Egypt: open thy mouth wide, and I will fill it.","words":[["H3068","I am the LORD",0,13],["H0430","thy God",14,21],["H5927","which brought",23,36],["H0776","thee out of the land",37,57],["H4714","of Egypt",58,66],["H6310","open thy mouth",68,82],["H7337","wide",83,87],["H4390","and I will fill",89,104]]},"81:11":{"text":"But my people would not hearken to my voice; and Israel would none of me.","words":[["H5971","But my people",0,13],["H8085","would not hearken",14,31],["H6963","to my voice",32,43],["H3478","and Israel",45,55],["H0014","would",56,61]]},"81:12":{"text":"So I gave them up unto their own hearts' lust: and they walked in their own counsels.","words":[["H7971","So I gave them up",0,17],["H3820","unto their own hearts'",18,40],["H8307","lust",41,45],["H3212","and they walked",47,62],["H4156","in their own counsels",63,84]]},"81:13":{"text":"Oh that my people had hearkened unto me, and Israel had walked in my ways!","words":[["H3863","Oh",0,2],["H5971","that my people",3,17],["H8085","had hearkened",18,31],["H3478","unto me, and Israel",32,51],["H1980","had walked",52,62],["H1870","in my ways",63,73]]},"81:14":{"text":"I should soon have subdued their enemies, and turned my hand against their adversaries.","words":[["H4592","I should soon",0,13],["H3665","have subdued",14,26],["H0341","their enemies",27,40],["H7725","and turned",42,52],["H3027","my hand",53,60],["H6862","against their adversaries",61,86]]},"81:15":{"text":"The haters of the LORD should have submitted themselves unto him: but their time should have endured for ever.","words":[["H8130","The haters",0,10],["H3068","of the LORD",11,22],["H3584","should have submitted",23,44],["H6256","themselves unto him: but their time",45,80],["H5769","should have endured for ever",81,109]]},"81:16":{"text":"He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee.","words":[["H0398","He should have fed",0,18],["H2459","them also with the finest",19,44],["H2406","of the wheat",45,57],["H1706","and with honey",59,73],["H6697","out of the rock",74,89],["H7646","should I have satisfied",90,113]]},"82:1":{"text":"A Psalm of Asaph. God standeth in the congregation of the mighty; he judgeth among the gods.","words":[["H4210","A Psalm",0,7],["H0623","of Asaph",8,16],["H0430","God",18,21],["H5324","standeth",22,30],["H5712","in the congregation",31,50],["H0410","of the mighty",51,64],["H8199","he judgeth",66,76],["H7130","among",77,82],["H0430","the gods",83,91]]},"82:2":{"text":"How long will ye judge unjustly, and accept the persons of the wicked? Selah.","words":[["H8199","How long will ye judge",0,22],["H5766","unjustly",23,31],["H5375","and accept",33,43],["H6440","the persons",44,55],["H7563","of the wicked",56,69],["H5542","Selah",71,76]]},"82:3":{"text":"Defend the poor and fatherless: do justice to the afflicted and needy.","words":[["H8199","Defend",0,6],["H1800","the poor",7,15],["H3490","and fatherless",16,30],["H6663","do justice",32,42],["H6041","to the afflicted",43,59],["H7326","and needy",60,69]]},"82:4":{"text":"Deliver the poor and needy: rid them out of the hand of the wicked.","words":[["H6403","Deliver",0,7],["H1800","the poor",8,16],["H0034","and needy",17,26],["H5337","rid",28,31],["H3027","them out of the hand",32,52],["H7563","of the wicked",53,66]]},"82:5":{"text":"They know not, neither will they understand; they walk on in darkness: all the foundations of the earth are out of course.","words":[["H3045","They know",0,9],["H0995","not, neither will they understand",10,43],["H1980","they walk",45,54],["H2825","on in darkness",55,69],["H4144","all the foundations",71,90],["H0776","of the earth",91,103],["H4131","are out of course",104,121]]},"82:6":{"text":"I have said, Ye are gods; and all of you are children of the most High.","words":[["H0559","I have said",0,11],["H0430","Ye are gods",13,24],["H1121","and all of you are children",26,53],["H5945","of the most High",54,70]]},"82:7":{"text":"But ye shall die like men, and fall like one of the princes.","words":[["H0403","But",0,3],["H4191","ye shall die",4,16],["H0120","like men",17,25],["H5307","and fall",27,35],["H0259","like one",36,44],["H8269","of the princes",45,59]]},"82:8":{"text":"Arise, O God, judge the earth: for thou shalt inherit all nations.","words":[["H6965","Arise",0,5],["H0430","O God",7,12],["H8199","judge",14,19],["H0776","the earth",20,29],["H5157","for thou shalt inherit",31,53],["H1471","all nations",54,65]]},"83:1":{"text":"A Song or Psalm of Asaph. Keep not thou silence, O God: hold not thy peace, and be not still, O God.","words":[["H7892","A Song",0,6],["H4210","or Psalm",7,15],["H0623","of Asaph",16,24],["H1824","Keep not thou silence",26,47],["H0430","O God",49,54],["H2790","hold not thy peace",56,74],["H8252","and be not still",76,92],["H0410","O God",94,99]]},"83:2":{"text":"For, lo, thine enemies make a tumult: and they that hate thee have lifted up the head.","words":[["H0341","For, lo, thine enemies",0,22],["H1993","make a tumult",23,36],["H8130","and they that hate",38,56],["H5375","thee have lifted up",57,76],["H7218","the head",77,85]]},"83:3":{"text":"They have taken crafty counsel against thy people, and consulted against thy hidden ones.","words":[["H6191","They have taken crafty",0,22],["H5475","counsel",23,30],["H5971","against thy people",31,49],["H3289","and consulted",51,64],["H6845","against thy hidden ones",65,88]]},"83:4":{"text":"They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance.","words":[["H0559","They have said",0,14],["H3212","Come",16,20],["H3582","and let us cut them off",22,45],["H1471","from being a nation",46,65],["H8034","that the name",67,80],["H3478","of Israel",81,90],["H2142","may be no more in remembrance",91,120]]},"83:5":{"text":"For they have consulted together with one consent: they are confederate against thee:","words":[["H3289","For they have consulted",0,23],["H3162","together",24,32],["H3820","with one consent",33,49],["H3772","they are",51,59],["H1285","confederate",60,71]]},"83:6":{"text":"The tabernacles of Edom, and the Ishmaelites; of Moab, and the Hagarenes;","words":[["H0168","The tabernacles",0,15],["H0123","of Edom",16,23],["H3459","and the Ishmaelites",25,44],["H4124","of Moab",46,53],["H1905","and the Hagarenes",55,72]]},"83:7":{"text":"Gebal, and Ammon, and Amalek; the Philistines with the inhabitants of Tyre;","words":[["H1381","Gebal",0,5],["H5983","and Ammon",7,16],["H6002","and Amalek",18,28],["H6429","the Philistines",30,45],["H3427","with the inhabitants",46,66],["H6865","of Tyre",67,74]]},"83:8":{"text":"Assur also is joined with them: they have holpen the children of Lot. Selah.","words":[["H0804","Assur",0,5],["H3867","also is joined",6,20],["H2220","with them: they have holpen",21,48],["H1121","the children",49,61],["H3876","of Lot",62,68],["H5542","Selah",70,75]]},"83:9":{"text":"Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison:","words":[["H6213","Do",0,2],["H4080","unto them as unto the Midianites",3,35],["H5516","as to Sisera",37,49],["H2985","as to Jabin",51,62],["H5158","at the brook",64,76],["H7028","of Kison",77,85]]},"83:10":{"text":"Which perished at Endor: they became as dung for the earth.","words":[["H8045","Which perished",0,14],["H5874","at Endor",15,23],["H1828","they became as dung",25,44],["H0127","for the earth",45,58]]},"83:11":{"text":"Make their nobles like Oreb, and like Zeeb: yea, all their princes as Zebah, and as Zalmunna:","words":[["H7896","Make",0,4],["H5081","their nobles",5,17],["H6159","like Oreb",18,27],["H2062","and like Zeeb",29,42],["H5257","yea, all their princes",44,66],["H2078","as Zebah",67,75],["H6759","and as Zalmunna",77,92]]},"83:12":{"text":"Who said, Let us take to ourselves the houses of God in possession.","words":[["H0559","Who said",0,8],["H4999","Let us take to ourselves the houses",10,45],["H0430","of God",46,52],["H3423","in possession",53,66]]},"83:13":{"text":"O my God, make them like a wheel; as the stubble before the wind.","words":[["H0430","O my God",0,8],["H7896","make",10,14],["H1534","them like a wheel",15,32],["H7179","as the stubble",34,48],["H6440","before",49,55],["H7307","the wind",56,64]]},"83:14":{"text":"As the fire burneth a wood, and as the flame setteth the mountains on fire;","words":[["H0784","As the fire",0,11],["H1197","burneth",12,19],["H3293","a wood",20,26],["H3852","and as the flame",28,44],["H3857","setteth",45,52],["H2022","the mountains",53,66],["H3857","on fire",67,74]]},"83:15":{"text":"So persecute them with thy tempest, and make them afraid with thy storm.","words":[["H7291","So persecute",0,12],["H5591","them with thy tempest",13,34],["H0926","and make them afraid",36,56],["H5492","with thy storm",57,71]]},"83:16":{"text":"Fill their faces with shame; that they may seek thy name, O LORD.","words":[["H4390","Fill",0,4],["H6440","their faces",5,16],["H7036","with shame",17,27],["H1245","that they may seek",29,47],["H8034","thy name",48,56],["H3068","O LORD",58,64]]},"83:17":{"text":"Let them be confounded and troubled for ever; yea, let them be put to shame, and perish:","words":[["H0954","Let them be confounded",0,22],["H0926","and troubled",23,35],["H5703","for ever",36,44],["H2659","yea, let them be put to shame",46,75],["H0006","and perish",77,87]]},"83:18":{"text":"That men may know that thou, whose name alone is JEHOVAH, art the most high over all the earth.","words":[["H3045","That men may know",0,17],["H8034","that thou, whose name",18,39],["H3068","alone is JEHOVAH",40,56],["H5945","art the most high",58,75],["H0776","over all the earth",76,94]]},"84:1":{"text":"To the chief Musician upon Gittith, A Psalm for the sons of Korah. How amiable are thy tabernacles, O LORD of hosts!","words":[["H5329","To the chief Musician",0,21],["H1665","upon Gittith",22,34],["H4210","A Psalm",36,43],["H1121","for the sons",44,56],["H7141","of Korah",57,65],["H3039","How amiable",67,78],["H4908","are thy tabernacles",79,98],["H3068","O LORD",100,106],["H6635","of hosts",107,115]]},"84:2":{"text":"My soul longeth, yea, even fainteth for the courts of the LORD: my heart and my flesh crieth out for the living God.","words":[["H5315","My soul",0,7],["H3700","longeth",8,15],["H3615","yea, even fainteth",17,35],["H2691","for the courts",36,50],["H3068","of the LORD",51,62],["H3820","my heart",64,72],["H1320","and my flesh",73,85],["H7442","crieth out",86,96],["H2416","for the living",97,111],["H0410","God",112,115]]},"84:3":{"text":"Yea, the sparrow hath found an house, and the swallow a nest for herself, where she may lay her young, even thine altars, O LORD of hosts, my King, and my God.","words":[["H6833","Yea, the sparrow",0,16],["H4672","hath found",17,27],["H1004","an house",28,36],["H1866","and the swallow",38,53],["H7064","a nest",54,60],["H7896","for herself, where she may lay",61,91],["H0667","her young",92,101],["H4196","even thine altars",103,120],["H3068","O LORD",122,128],["H6635","of hosts",129,137],["H4428","my King",139,146],["H0430","and my God",148,158]]},"84:4":{"text":"Blessed are they that dwell in thy house: they will be still praising thee. Selah.","words":[["H0835","Blessed",0,7],["H3427","are they that dwell",8,27],["H1004","in thy house",28,40],["H1984","they will be still praising",42,69],["H5542","thee. Selah",70,81]]},"84:5":{"text":"Blessed is the man whose strength is in thee; in whose heart are the ways of them.","words":[["H0835","Blessed",0,7],["H0120","is the man",8,18],["H5797","whose strength",19,33],["H3824","is in thee; in whose heart",34,60],["H4546","are the ways",61,73]]},"84:6":{"text":"Who passing through the valley of Baca make it a well; the rain also filleth the pools.","words":[["H5674","Who passing",0,11],["H6010","through the valley",12,30],["H1056","of Baca",31,38],["H1057","of Baca",31,38],["H7896","make",39,43],["H4599","it a well",44,53],["H4175","the rain",55,63],["H5844","also filleth",64,76],["H1293","the pools",77,86]]},"84:7":{"text":"They go from strength to strength, every one of them in Zion appeareth before God.","words":[["H3212","They go",0,7],["H2428","from strength",8,21],["H2428","to strength",22,33],["H6726","every one of them in Zion",35,60],["H7200","appeareth",61,70],["H0430","before God",71,81]]},"84:8":{"text":"O LORD God of hosts, hear my prayer: give ear, O God of Jacob. Selah.","words":[["H3068","O LORD",0,6],["H0430","God",7,10],["H6635","of hosts",11,19],["H8085","hear",21,25],["H8605","my prayer",26,35],["H0238","give ear",37,45],["H0430","O God",47,52],["H3290","of Jacob",53,61],["H5542","Selah",63,68]]},"84:9":{"text":"Behold, O God our shield, and look upon the face of thine anointed.","words":[["H7200","Behold",0,6],["H0430","O God",8,13],["H4043","our shield",14,24],["H5027","and look",26,34],["H6440","upon the face",35,48],["H4899","of thine anointed",49,66]]},"84:10":{"text":"For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness.","words":[["H3117","For a day",0,9],["H2691","in thy courts",10,23],["H2896","is better",24,33],["H0505","than a thousand",34,49],["H0977","I had rather",51,63],["H5605","be a doorkeeper",64,79],["H1004","in the house",80,92],["H0430","of my God",93,102],["H1752","than to dwell",104,117],["H0168","in the tents",118,130],["H7562","of wickedness",131,144]]},"84:11":{"text":"For the LORD God is a sun and shield: the LORD will give grace and glory: no good thing will he withhold from them that walk uprightly.","words":[["H3068","For the LORD",0,12],["H0430","God",13,16],["H8121","is a sun",17,25],["H4043","and shield",26,36],["H3068","the LORD",38,46],["H5414","will give",47,56],["H2580","grace",57,62],["H3519","and glory",63,72],["H2896","no good",74,81],["H4513","thing will he withhold",82,104],["H1980","from them that walk",105,124],["H8549","uprightly",125,134]]},"84:12":{"text":"O LORD of hosts, blessed is the man that trusteth in thee.","words":[["H3068","O LORD",0,6],["H6635","of hosts",7,15],["H0835","blessed",17,24],["H0120","is the man",25,35],["H0982","that trusteth",36,49]]},"85:1":{"text":"To the chief Musician, A Psalm for the sons of Korah. LORD, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1121","for the sons",31,43],["H7141","of Korah",44,52],["H3068","LORD",54,58],["H7521","thou hast been favourable",60,85],["H0776","unto thy land",86,99],["H7725","thou hast brought back",101,123],["H7622","the captivity",124,137],["H7622","the captivity",124,137],["H3290","of Jacob",138,146]]},"85:2":{"text":"Thou hast forgiven the iniquity of thy people, thou hast covered all their sin. Selah.","words":[["H5375","Thou hast forgiven",0,18],["H5771","the iniquity",19,31],["H5971","of thy people",32,45],["H3680","thou hast covered",47,64],["H2403","all their sin",65,78],["H5542","Selah",80,85]]},"85:3":{"text":"Thou hast taken away all thy wrath: thou hast turned thyself from the fierceness of thine anger.","words":[["H0622","Thou hast taken away",0,20],["H5678","all thy wrath",21,34],["H7725","thou hast turned",36,52],["H2740","thyself from the fierceness",53,80],["H0639","of thine anger",81,95]]},"85:4":{"text":"Turn us, O God of our salvation, and cause thine anger toward us to cease.","words":[["H7725","Turn",0,4],["H0430","us, O God",5,14],["H3468","of our salvation",15,31],["H3708","and cause thine anger",33,54],["H6565","toward us to cease",55,73]]},"85:5":{"text":"Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?","words":[["H0599","Wilt thou be angry",0,18],["H5769","with us for ever",19,35],["H4900","wilt thou draw out",37,55],["H0639","thine anger",56,67],["H1755","to all",68,74],["H1755","generations",75,86]]},"85:6":{"text":"Wilt thou not revive us again: that thy people may rejoice in thee?","words":[["H2421","Wilt thou not revive",0,20],["H7725","us again",21,29],["H5971","that thy people",31,46],["H8055","may rejoice",47,58]]},"85:7":{"text":"Shew us thy mercy, O LORD, and grant us thy salvation.","words":[["H7200","Shew",0,4],["H2617","us thy mercy",5,17],["H3068","O LORD",19,25],["H5414","and grant",27,36],["H3468","us thy salvation",37,53]]},"85:8":{"text":"I will hear what God the LORD will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly.","words":[["H8085","I will hear",0,11],["H0410","what God",12,20],["H3068","the LORD",21,29],["H1696","will speak",30,40],["H1696","for he will speak",42,59],["H7965","peace",60,65],["H5971","unto his people",66,81],["H2623","and to his saints",83,100],["H7725","but let them not turn again",102,129],["H3690","to folly",130,138]]},"85:9":{"text":"Surely his salvation is nigh them that fear him; that glory may dwell in our land.","words":[["H3468","Surely his salvation",0,20],["H7138","is nigh",21,28],["H3373","them that fear",29,43],["H3519","him; that glory",44,59],["H7931","may dwell",60,69],["H0776","in our land",70,81]]},"85:10":{"text":"Mercy and truth are met together; righteousness and peace have kissed each other.","words":[["H2617","Mercy",0,5],["H0571","and truth",6,15],["H6298","are met together",16,32],["H6664","righteousness",34,47],["H7965","and peace",48,57],["H5401","have kissed",58,69]]},"85:11":{"text":"Truth shall spring out of the earth; and righteousness shall look down from heaven.","words":[["H0571","Truth",0,5],["H6779","shall spring out",6,22],["H0776","of the earth",23,35],["H6664","and righteousness",37,54],["H8259","shall look down",55,70],["H8064","from heaven",71,82]]},"85:12":{"text":"Yea, the LORD shall give that which is good; and our land shall yield her increase.","words":[["H3068","Yea, the LORD",0,13],["H5414","shall give",14,24],["H2896","that which is good",25,43],["H0776","and our land",45,57],["H5414","shall yield",58,69],["H2981","her increase",70,82]]},"85:13":{"text":"Righteousness shall go before him; and shall set us in the way of his steps.","words":[["H6664","Righteousness",0,13],["H1980","shall go",14,22],["H6440","before",23,29],["H7760","him; and shall set",30,48],["H1870","us in the way",49,62],["H6471","of his steps",63,75]]},"86:1":{"text":"A Prayer of David. Bow down thine ear, O LORD, hear me: for I am poor and needy.","words":[["H8605","A Prayer",0,8],["H1732","of David",9,17],["H5186","Bow down",19,27],["H0241","thine ear",28,37],["H3068","O LORD",39,45],["H6030","hear",47,51],["H6041","me: for I am poor",52,69],["H0034","and needy",70,79]]},"86:2":{"text":"Preserve my soul; for I am holy: O thou my God, save thy servant that trusteth in thee.","words":[["H8104","Preserve",0,8],["H5315","my soul",9,16],["H2623","for I am holy",18,31],["H0430","O thou my God",33,46],["H3467","save",48,52],["H5650","thy servant",53,64],["H0982","that trusteth",65,78]]},"86:3":{"text":"Be merciful unto me, O Lord: for I cry unto thee daily.","words":[["H2603","Be merciful",0,11],["H0136","unto me, O Lord",12,27],["H7121","for I cry",29,38],["H3117","unto thee daily",39,54]]},"86:4":{"text":"Rejoice the soul of thy servant: for unto thee, O Lord, do I lift up my soul.","words":[["H8055","Rejoice",0,7],["H5315","the soul",8,16],["H5650","of thy servant",17,31],["H0136","for unto thee, O Lord",33,54],["H5375","do I lift up",56,68],["H5315","my soul",69,76]]},"86:5":{"text":"For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee.","words":[["H0136","For thou, Lord",0,14],["H2896","art good",16,24],["H5546","and ready to forgive",26,46],["H7227","and plenteous",48,61],["H2617","in mercy",62,70],["H7121","unto all them that call",71,94]]},"86:6":{"text":"Give ear, O LORD, unto my prayer; and attend to the voice of my supplications.","words":[["H0238","Give ear",0,8],["H3068","O LORD",10,16],["H8605","unto my prayer",18,32],["H7181","and attend",34,44],["H6963","to the voice",45,57],["H8469","of my supplications",58,77]]},"86:7":{"text":"In the day of my trouble I will call upon thee: for thou wilt answer me.","words":[["H3117","In the day",0,10],["H6869","of my trouble",11,24],["H7121","I will call",25,36],["H6030","upon thee: for thou wilt answer",37,68]]},"86:8":{"text":"Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works.","words":[["H0430","Among the gods",0,14],["H0136","there is none like unto thee, O Lord",15,51],["H4639","neither are there any works like unto thy works",53,100]]},"86:9":{"text":"All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name.","words":[["H1471","All nations",0,11],["H6213","whom thou hast made",12,31],["H0935","shall come",32,42],["H7812","and worship",43,54],["H6440","before",55,61],["H0136","thee, O Lord",62,74],["H3513","and shall glorify",76,93],["H8034","thy name",94,102]]},"86:10":{"text":"For thou art great, and doest wondrous things: thou art God alone.","words":[["H1419","For thou art great",0,18],["H6213","and doest",20,29],["H6381","wondrous things",30,45],["H0430","thou art God",47,59]]},"86:11":{"text":"Teach me thy way, O LORD; I will walk in thy truth: unite my heart to fear thy name.","words":[["H3384","Teach",0,5],["H1870","me thy way",6,16],["H3068","O LORD",18,24],["H1980","I will walk",26,37],["H0571","in thy truth",38,50],["H3161","unite",52,57],["H3824","my heart",58,66],["H3372","to fear",67,74],["H8034","thy name",75,83]]},"86:12":{"text":"I will praise thee, O Lord my God, with all my heart: and I will glorify thy name for evermore.","words":[["H3034","I will praise",0,13],["H0136","thee, O Lord",14,26],["H0430","my God",27,33],["H3824","with all my heart",35,52],["H3513","and I will glorify",54,72],["H8034","thy name",73,81],["H5769","for evermore",82,94]]},"86:13":{"text":"For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell.","words":[["H1419","For great",0,9],["H2617","is thy mercy",10,22],["H5337","toward me: and thou hast delivered",23,57],["H5315","my soul",58,65],["H8482","from the lowest",66,81],["H7585","hell",82,86]]},"86:14":{"text":"O God, the proud are risen against me, and the assemblies of violent men have sought after my soul; and have not set thee before them.","words":[["H0430","O God",0,5],["H2086","the proud",7,16],["H6965","are risen",17,26],["H5712","against me, and the assemblies",27,57],["H6184","of violent",58,68],["H1245","men have sought",69,84],["H5315","after my soul",85,98],["H7760","and have not set",100,116]]},"86:15":{"text":"But thou, O Lord, art a God full of compassion, and gracious, longsuffering, and plenteous in mercy and truth.","words":[["H0136","But thou, O Lord",0,16],["H0410","art a God",18,27],["H7349","full of compassion",28,46],["H2587","and gracious",48,60],["H0750","longsuffering",62,75],["H0639","longsuffering",62,75],["H7227","and plenteous",77,90],["H2617","in mercy",91,99],["H0571","and truth",100,109]]},"86:16":{"text":"O turn unto me, and have mercy upon me; give thy strength unto thy servant, and save the son of thine handmaid.","words":[["H6437","O turn",0,6],["H2603","unto me, and have mercy",7,30],["H5414","upon me; give",31,44],["H5797","thy strength",45,57],["H5650","unto thy servant",58,74],["H3467","and save",76,84],["H1121","the son",85,92],["H0519","of thine handmaid",93,110]]},"86:17":{"text":"Shew me a token for good; that they which hate me may see it, and be ashamed: because thou, LORD, hast holpen me, and comforted me.","words":[["H6213","Shew",0,4],["H0226","me a token",5,15],["H2896","for good",16,24],["H8130","that they which hate",26,46],["H7200","me may see",47,57],["H0954","it, and be ashamed",58,76],["H3068","because thou, LORD",78,96],["H5826","hast holpen",98,109],["H5162","me, and comforted",110,127]]},"87:1":{"text":"A Psalm or Song for the sons of Korah. His foundation is in the holy mountains.","words":[["H4210","A Psalm",0,7],["H7892","or Song",8,15],["H1121","for the sons",16,28],["H7141","of Korah",29,37],["H3248","His foundation",39,53],["H6944","is in the holy",54,68],["H2042","mountains",69,78]]},"87:2":{"text":"The LORD loveth the gates of Zion more than all the dwellings of Jacob.","words":[["H3068","The LORD",0,8],["H0157","loveth",9,15],["H8179","the gates",16,25],["H6726","of Zion",26,33],["H4908","more than all the dwellings",34,61],["H3290","of Jacob",62,70]]},"87:3":{"text":"Glorious things are spoken of thee, O city of God. Selah.","words":[["H3513","Glorious things",0,15],["H1696","are spoken",16,26],["H5892","of thee, O city",27,42],["H0430","of God",43,49],["H5542","Selah",51,56]]},"87:4":{"text":"I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there.","words":[["H2142","I will make mention",0,19],["H7294","of Rahab",20,28],["H0894","and Babylon",29,40],["H3045","to them that know",41,58],["H6429","me: behold Philistia",59,79],["H6865","and Tyre",81,89],["H3568","with Ethiopia",91,104],["H3205","this man was born",106,123]]},"87:5":{"text":"And of Zion it shall be said, This and that man was born in her: and the highest himself shall establish her.","words":[["H6726","And of Zion",0,11],["H0559","it shall be said",12,28],["H0376","This and that man",30,47],["H3205","was born",48,56],["H5945","in her: and the highest",57,80],["H3559","himself shall establish",81,104]]},"87:6":{"text":"The LORD shall count, when he writeth up the people, that this man was born there. Selah.","words":[["H3068","The LORD",0,8],["H5608","shall count",9,20],["H3789","when he writeth up",22,40],["H5971","the people",41,51],["H3205","that this man was born",53,75],["H5542","there. Selah",76,88]]},"87:7":{"text":"As well the singers as the players on instruments shall be there: all my springs are in thee.","words":[["H7891","As well the singers",0,19],["H2490","as the players",20,34],["H4599","on instruments shall be there: all my springs",35,80]]},"88:1":{"text":"A Song or Psalm for the sons of Korah, to the chief Musician upon Mahalath Leannoth, Maschil of Heman the Ezrahite. O LORD God of my salvation, I have cried day and night before thee:","words":[["H7892","A Song",0,6],["H4210","or Psalm",7,15],["H1121","for the sons",16,28],["H7141","of Korah",29,37],["H5329","to the chief Musician",39,60],["H4257","upon Mahalath",61,74],["H6031","Leannoth",75,83],["H4905","Maschil",85,92],["H1968","of Heman",93,101],["H0250","the Ezrahite",102,114],["H3068","O LORD",116,122],["H0430","God",123,126],["H3444","of my salvation",127,142],["H6817","I have cried",144,156],["H3117","day",157,160],["H3915","and night",161,170]]},"88:2":{"text":"Let my prayer come before thee: incline thine ear unto my cry;","words":[["H8605","Let my prayer",0,13],["H0935","come",14,18],["H6440","before",19,25],["H5186","thee: incline",26,39],["H0241","thine ear",40,49],["H7440","unto my cry",50,61]]},"88:3":{"text":"For my soul is full of troubles: and my life draweth nigh unto the grave.","words":[["H5315","For my soul",0,11],["H7646","is full",12,19],["H7451","of troubles",20,31],["H2416","and my life",33,44],["H5060","draweth nigh",45,57],["H7585","unto the grave",58,72]]},"88:4":{"text":"I am counted with them that go down into the pit: I am as a man that hath no strength:","words":[["H2803","I am counted",0,12],["H3381","with them that go down",13,35],["H0953","into the pit",36,48],["H1397","I am as a man",50,63],["H0353","that hath no strength",64,85]]},"88:5":{"text":"Free among the dead, like the slain that lie in the grave, whom thou rememberest no more: and they are cut off from thy hand.","words":[["H2670","Free",0,4],["H4191","among the dead",5,19],["H2491","like the slain",21,35],["H7901","that lie",36,44],["H6913","in the grave",45,57],["H2142","whom thou rememberest",59,80],["H1504","no more: and they are cut off",81,110],["H3027","from thy hand",111,124]]},"88:6":{"text":"Thou hast laid me in the lowest pit, in darkness, in the deeps.","words":[["H7896","Thou hast laid",0,14],["H8482","me in the lowest",15,31],["H0953","pit",32,35],["H4285","in darkness",37,48],["H4688","in the deeps",50,62]]},"88:7":{"text":"Thy wrath lieth hard upon me, and thou hast afflicted me with all thy waves. Selah.","words":[["H2534","Thy wrath",0,9],["H5564","lieth hard",10,20],["H6031","upon me, and thou hast afflicted",21,53],["H4867","me with all thy waves",54,75],["H5542","Selah",77,82]]},"88:8":{"text":"Thou hast put away mine acquaintance far from me; thou hast made me an abomination unto them: I am shut up, and I cannot come forth.","words":[["H7368","Thou hast put away",0,18],["H3045","mine acquaintance",19,36],["H7368","far",37,40],["H7896","from me; thou hast made",41,64],["H8441","me an abomination",65,82],["H3607","unto them: I am shut up",83,106],["H3318","and I cannot come forth",108,131]]},"88:9":{"text":"Mine eye mourneth by reason of affliction: LORD, I have called daily upon thee, I have stretched out my hands unto thee.","words":[["H5869","Mine eye",0,8],["H1669","mourneth",9,17],["H6040","by reason of affliction",18,41],["H3068","LORD",43,47],["H7121","I have called",49,62],["H3117","daily",63,68],["H7849","upon thee, I have stretched out",69,100],["H3709","my hands",101,109]]},"88:10":{"text":"Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah.","words":[["H6213","Wilt thou shew",0,14],["H6382","wonders",15,22],["H4191","to the dead",23,34],["H7496","shall the dead",36,50],["H6965","arise",51,56],["H3034","and praise",57,67],["H5542","thee? Selah",68,79]]},"88:11":{"text":"Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?","words":[["H2617","Shall thy lovingkindness",0,24],["H5608","be declared",25,36],["H6913","in the grave",37,49],["H0530","or thy faithfulness",51,70],["H0011","in destruction",71,85]]},"88:12":{"text":"Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?","words":[["H6382","Shall thy wonders",0,17],["H3045","be known",18,26],["H2822","in the dark",27,38],["H6666","and thy righteousness",40,61],["H0776","in the land",62,73],["H5388","of forgetfulness",74,90]]},"88:13":{"text":"But unto thee have I cried, O LORD; and in the morning shall my prayer prevent thee.","words":[["H7768","But unto thee have I cried",0,26],["H3068","O LORD",28,34],["H1242","and in the morning",36,54],["H8605","shall my prayer",55,70],["H6923","prevent",71,78]]},"88:14":{"text":"LORD, why castest thou off my soul? why hidest thou thy face from me?","words":[["H3068","LORD",0,4],["H2186","why castest thou off",6,26],["H5315","my soul",27,34],["H5641","why hidest",36,46],["H6440","thou thy face",47,60]]},"88:15":{"text":"I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted.","words":[["H6041","I am afflicted",0,14],["H1478","and ready to die",15,31],["H5290","from my youth",32,45],["H5375","up: while I suffer",46,64],["H0367","thy terrors",65,76],["H6323","I am distracted",77,92]]},"88:16":{"text":"Thy fierce wrath goeth over me; thy terrors have cut me off.","words":[["H2740","Thy fierce wrath",0,16],["H5674","goeth over",17,27],["H1161","me; thy terrors",28,43],["H6789","have cut me off",44,59]]},"88:17":{"text":"They came round about me daily like water; they compassed me about together.","words":[["H5437","They came round about",0,21],["H3117","me daily",22,30],["H4325","like water",31,41],["H5362","they compassed",43,57],["H3162","me about together",58,75]]},"88:18":{"text":"Lover and friend hast thou put far from me, and mine acquaintance into darkness.","words":[["H0157","Lover",0,5],["H7453","and friend",6,16],["H7368","hast thou put far",17,34],["H3045","from me, and mine acquaintance",35,65],["H4285","into darkness",66,79]]},"89:1":{"text":"Maschil of Ethan the Ezrahite. I will sing of the mercies of the LORD for ever: with my mouth will I make known thy faithfulness to all generations.","words":[["H4905","Maschil",0,7],["H0387","of Ethan",8,16],["H0250","the Ezrahite",17,29],["H7891","I will sing",31,42],["H2617","of the mercies",43,57],["H3068","of the LORD",58,69],["H5769","for ever",70,78],["H6310","with my mouth",80,93],["H3045","will I make known",94,111],["H0530","thy faithfulness",112,128],["H1755","to all",129,135],["H1755","generations",136,147]]},"89:2":{"text":"For I have said, Mercy shall be built up for ever: thy faithfulness shalt thou establish in the very heavens.","words":[["H0559","For I have said",0,15],["H2617","Mercy",17,22],["H1129","shall be built up",23,40],["H5769","for ever",41,49],["H0530","thy faithfulness",51,67],["H3559","shalt thou establish",68,88],["H8064","in the very heavens",89,108]]},"89:3":{"text":"I have made a covenant with my chosen, I have sworn unto David my servant,","words":[["H3772","I have made",0,11],["H1285","a covenant",12,22],["H0972","with my chosen",23,37],["H7650","I have sworn",39,51],["H1732","unto David",52,62],["H5650","my servant",63,73]]},"89:4":{"text":"Thy seed will I establish for ever, and build up thy throne to all generations. Selah.","words":[["H2233","Thy seed",0,8],["H3559","will I establish",9,25],["H5704","for",26,29],["H5769","ever",30,34],["H1129","and build up",36,48],["H3678","thy throne",49,59],["H1755","to all",60,66],["H1755","generations",67,78],["H5542","Selah",80,85]]},"89:5":{"text":"And the heavens shall praise thy wonders, O LORD: thy faithfulness also in the congregation of the saints.","words":[["H8064","And the heavens",0,15],["H3034","shall praise",16,28],["H6382","thy wonders",29,40],["H3068","O LORD",42,48],["H0530","thy faithfulness",50,66],["H6951","also in the congregation",67,91],["H6918","of the saints",92,105]]},"89:6":{"text":"For who in the heaven can be compared unto the LORD? who among the sons of the mighty can be likened unto the LORD?","words":[["H7834","For who in the heaven",0,21],["H6186","can be compared",22,37],["H3068","unto the LORD",38,51],["H1121","who among the sons",53,71],["H0410","of the mighty",72,85],["H1819","can be likened",86,100],["H3068","unto the LORD",101,114]]},"89:7":{"text":"God is greatly to be feared in the assembly of the saints, and to be had in reverence of all them that are about him.","words":[["H0410","God",0,3],["H7227","is greatly",4,14],["H6206","to be feared",15,27],["H5475","in the assembly",28,43],["H6918","of the saints",44,57],["H3372","and to be had in reverence",59,85],["H5439","of all them that are about",86,112]]},"89:8":{"text":"O LORD God of hosts, who is a strong LORD like unto thee? or to thy faithfulness round about thee?","words":[["H3068","O LORD",0,6],["H0430","God",7,10],["H6635","of hosts",11,19],["H2626","who is a strong",21,36],["H3050","LORD",37,41],["H0530","like unto thee? or to thy faithfulness",42,80],["H5439","round about",81,92]]},"89:9":{"text":"Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them.","words":[["H4910","Thou rulest",0,11],["H1348","the raging",12,22],["H3220","of the sea",23,33],["H1530","when the waves",35,49],["H7721","thereof arise",50,63],["H7623","thou stillest",65,78]]},"89:10":{"text":"Thou hast broken Rahab in pieces, as one that is slain; thou hast scattered thine enemies with thy strong arm.","words":[["H1792","Thou hast broken",0,16],["H7294","Rahab",17,22],["H1792","in pieces",23,32],["H2491","as one that is slain",34,54],["H6340","thou hast scattered",56,75],["H0341","thine enemies",76,89],["H5797","with thy strong",90,105],["H2220","arm",106,109]]},"89:11":{"text":"The heavens are thine, the earth also is thine: as for the world and the fulness thereof, thou hast founded them.","words":[["H8064","The heavens",0,11],["H0776","are thine, the earth",12,32],["H8398","also is thine: as for the world",33,64],["H4393","and the fulness",65,80],["H3245","thereof, thou hast founded",81,107]]},"89:12":{"text":"The north and the south thou hast created them: Tabor and Hermon shall rejoice in thy name.","words":[["H6828","The north",0,9],["H3225","and the south",10,23],["H1254","thou hast created",24,41],["H8396","them: Tabor",42,53],["H2768","and Hermon",54,64],["H7442","shall rejoice",65,78],["H8034","in thy name",79,90]]},"89:13":{"text":"Thou hast a mighty arm: strong is thy hand, and high is thy right hand.","words":[["H1369","Thou hast a mighty",0,18],["H2220","arm",19,22],["H5810","strong",24,30],["H3027","is thy hand",31,42],["H7311","and high",44,52],["H3225","is thy right hand",53,70]]},"89:14":{"text":"Justice and judgment are the habitation of thy throne: mercy and truth shall go before thy face.","words":[["H6664","Justice",0,7],["H4941","and judgment",8,20],["H4349","are the habitation",21,39],["H3678","of thy throne",40,53],["H2617","mercy",55,60],["H0571","and truth",61,70],["H6923","shall go",71,79],["H6440","before thy face",80,95]]},"89:15":{"text":"Blessed is the people that know the joyful sound: they shall walk, O LORD, in the light of thy countenance.","words":[["H0835","Blessed",0,7],["H5971","is the people",8,21],["H3045","that know",22,31],["H8643","the joyful sound",32,48],["H1980","they shall walk",50,65],["H3068","O LORD",67,73],["H0216","in the light",75,87],["H6440","of thy countenance",88,106]]},"89:16":{"text":"In thy name shall they rejoice all the day: and in thy righteousness shall they be exalted.","words":[["H8034","In thy name",0,11],["H1523","shall they rejoice",12,30],["H3117","all the day",31,42],["H6666","and in thy righteousness",44,68],["H7311","shall they be exalted",69,90]]},"89:17":{"text":"For thou art the glory of their strength: and in thy favour our horn shall be exalted.","words":[["H8597","For thou art the glory",0,22],["H5797","of their strength",23,40],["H7522","and in thy favour",42,59],["H7161","our horn",60,68],["H7311","shall be exalted",69,85],["H7311","shall be exalted",69,85]]},"89:18":{"text":"For the LORD is our defence; and the Holy One of Israel is our king.","words":[["H3068","For the LORD",0,12],["H4043","is our defence",13,27],["H6918","and the Holy One",29,45],["H3478","of Israel",46,55],["H4428","is our king",56,67]]},"89:19":{"text":"Then thou spakest in vision to thy holy one, and saidst, I have laid help upon one that is mighty; I have exalted one chosen out of the people.","words":[["H1696","Then thou spakest",0,17],["H2377","in vision",18,27],["H2623","to thy holy one",28,43],["H0559","and saidst",45,55],["H7737","I have laid",57,68],["H5828","help",69,73],["H1368","upon one that is mighty",74,97],["H7311","I have exalted",99,113],["H0977","one chosen",114,124],["H5971","out of the people",125,142]]},"89:20":{"text":"I have found David my servant; with my holy oil have I anointed him:","words":[["H4672","I have found",0,12],["H1732","David",13,18],["H5650","my servant",19,29],["H6944","with my holy",31,43],["H8081","oil",44,47],["H4886","have I anointed",48,63]]},"89:21":{"text":"With whom my hand shall be established: mine arm also shall strengthen him.","words":[["H3027","With whom my hand",0,17],["H3559","shall be established",18,38],["H2220","mine arm",40,48],["H0553","also shall strengthen",49,70]]},"89:22":{"text":"The enemy shall not exact upon him; nor the son of wickedness afflict him.","words":[["H0341","The enemy",0,9],["H5378","shall not exact",10,25],["H1121","upon him; nor the son",26,47],["H5766","of wickedness",48,61],["H6031","afflict",62,69]]},"89:23":{"text":"And I will beat down his foes before his face, and plague them that hate him.","words":[["H3807","And I will beat down",0,20],["H6862","his foes",21,29],["H6440","before his face",30,45],["H5062","and plague",47,57],["H8130","them that hate",58,72]]},"89:24":{"text":"But my faithfulness and my mercy shall be with him: and in my name shall his horn be exalted.","words":[["H0530","But my faithfulness",0,19],["H2617","and my mercy",20,32],["H8034","shall be with him: and in my name",33,66],["H7161","shall his horn",67,81],["H7311","be exalted",82,92]]},"89:25":{"text":"I will set his hand also in the sea, and his right hand in the rivers.","words":[["H7760","I will set",0,10],["H3027","his hand",11,19],["H3220","also in the sea",20,35],["H3225","and his right hand",37,55],["H5104","in the rivers",56,69]]},"89:26":{"text":"He shall cry unto me, Thou art my father, my God, and the rock of my salvation.","words":[["H7121","He shall cry",0,12],["H0001","unto me, Thou art my father",13,40],["H0410","my God",42,48],["H6697","and the rock",50,62],["H3444","of my salvation",63,78]]},"89:27":{"text":"Also I will make him my firstborn, higher than the kings of the earth.","words":[["H5414","Also I will make",0,16],["H1060","him my firstborn",17,33],["H5945","higher",35,41],["H4428","than the kings",42,56],["H0776","of the earth",57,69]]},"89:28":{"text":"My mercy will I keep for him for evermore, and my covenant shall stand fast with him.","words":[["H2617","My mercy",0,8],["H8104","will I keep",9,20],["H5769","for him for evermore",21,41],["H1285","and my covenant",43,58],["H0539","shall stand fast",59,75]]},"89:29":{"text":"His seed also will I make to endure for ever, and his throne as the days of heaven.","words":[["H2233","His seed",0,8],["H7760","also will I make",9,25],["H5703","to endure for ever",26,44],["H3678","and his throne",46,60],["H3117","as the days",61,72],["H8064","of heaven",73,82]]},"89:30":{"text":"If his children forsake my law, and walk not in my judgments;","words":[["H1121","If his children",0,15],["H5800","forsake",16,23],["H8451","my law",24,30],["H3212","and walk",32,40],["H4941","not in my judgments",41,60]]},"89:31":{"text":"If they break my statutes, and keep not my commandments;","words":[["H2490","If they break",0,13],["H2708","my statutes",14,25],["H8104","and keep",27,35],["H4687","not my commandments",36,55]]},"89:32":{"text":"Then will I visit their transgression with the rod, and their iniquity with stripes.","words":[["H6485","Then will I visit",0,17],["H6588","their transgression",18,37],["H7626","with the rod",38,50],["H5771","and their iniquity",52,70],["H5061","with stripes",71,83]]},"89:33":{"text":"Nevertheless my lovingkindness will I not utterly take from him, nor suffer my faithfulness to fail.","words":[["H2617","Nevertheless my lovingkindness",0,30],["H6331","will I not utterly take",31,54],["H0530","from him, nor suffer my faithfulness",55,91],["H8266","to fail",92,99]]},"89:34":{"text":"My covenant will I not break, nor alter the thing that is gone out of my lips.","words":[["H1285","My covenant",0,11],["H2490","will I not break",12,28],["H8138","nor alter",30,39],["H4161","the thing that is gone out",40,66],["H8193","of my lips",67,77]]},"89:35":{"text":"Once have I sworn by my holiness that I will not lie unto David.","words":[["H0259","Once",0,4],["H7650","have I sworn",5,17],["H6944","by my holiness",18,32],["H3576","that I will not lie",33,52],["H1732","unto David",53,63]]},"89:36":{"text":"His seed shall endure for ever, and his throne as the sun before me.","words":[["H2233","His seed",0,8],["H5769","shall endure for ever",9,30],["H3678","and his throne",32,46],["H8121","as the sun",47,57]]},"89:37":{"text":"It shall be established for ever as the moon, and as a faithful witness in heaven. Selah.","words":[["H3559","It shall be established",0,23],["H5769","for ever",24,32],["H3394","as the moon",33,44],["H0539","and as a faithful",46,63],["H5707","witness",64,71],["H7834","in heaven",72,81],["H5542","Selah",83,88]]},"89:38":{"text":"But thou hast cast off and abhorred, thou hast been wroth with thine anointed.","words":[["H2186","But thou hast cast off",0,22],["H3988","and abhorred",23,35],["H5674","thou hast been wroth",37,57],["H4899","with thine anointed",58,77]]},"89:39":{"text":"Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground.","words":[["H5010","Thou hast made void",0,19],["H1285","the covenant",20,32],["H5650","of thy servant",33,47],["H2490","thou hast profaned",49,67],["H5145","his crown",68,77],["H0776","by casting it to the ground",78,105]]},"89:40":{"text":"Thou hast broken down all his hedges; thou hast brought his strong holds to ruin.","words":[["H6555","Thou hast broken down",0,21],["H1448","all his hedges",22,36],["H7760","thou hast brought",38,55],["H4013","his strong holds",56,72],["H4288","to ruin",73,80]]},"89:41":{"text":"All that pass by the way spoil him: he is a reproach to his neighbours.","words":[["H5674","All that pass by",0,16],["H1870","the way",17,24],["H8155","spoil",25,30],["H2781","him: he is a reproach",31,52],["H7934","to his neighbours",53,70]]},"89:42":{"text":"Thou hast set up the right hand of his adversaries; thou hast made all his enemies to rejoice.","words":[["H7311","Thou hast set up",0,16],["H3225","the right hand",17,31],["H6862","of his adversaries",32,50],["H0341","thou hast made all his enemies",52,82],["H8055","to rejoice",83,93]]},"89:43":{"text":"Thou hast also turned the edge of his sword, and hast not made him to stand in the battle.","words":[["H7725","Thou hast also turned",0,21],["H6697","the edge",22,30],["H2719","of his sword",31,43],["H6965","and hast not made him to stand",45,75],["H4421","in the battle",76,89]]},"89:44":{"text":"Thou hast made his glory to cease, and cast his throne down to the ground.","words":[["H2892","Thou hast made his glory",0,24],["H7673","to cease",25,33],["H4048","and cast",35,43],["H3678","his throne",44,54],["H4048","down",55,59],["H0776","to the ground",60,73]]},"89:45":{"text":"The days of his youth hast thou shortened: thou hast covered him with shame. Selah.","words":[["H3117","The days",0,8],["H5934","of his youth",9,21],["H7114","hast thou shortened",22,41],["H5844","thou hast covered",43,60],["H0955","him with shame",61,75],["H5542","Selah",77,82]]},"89:46":{"text":"How long, LORD? wilt thou hide thyself for ever? shall thy wrath burn like fire?","words":[["H3068","How long, LORD",0,14],["H5641","wilt thou hide",16,30],["H5331","thyself for ever",31,47],["H2534","shall thy wrath",49,64],["H1197","burn",65,69],["H0784","like fire",70,79]]},"89:47":{"text":"Remember how short my time is: wherefore hast thou made all men in vain?","words":[["H2142","Remember",0,8],["H2465","how short",9,18],["H1254","my time is: wherefore hast thou made",19,55],["H1121","all men",56,63],["H0120","all men",56,63],["H7723","in vain",64,71]]},"89:48":{"text":"What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah.","words":[["H1397","What man",0,8],["H2421","is he that liveth",9,26],["H7200","and shall not see",28,45],["H4194","death",46,51],["H4422","shall he deliver",53,69],["H5315","his soul",70,78],["H3027","from the hand",79,92],["H7585","of the grave",93,105],["H5542","Selah",107,112]]},"89:49":{"text":"Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?","words":[["H0136","Lord",0,4],["H7223","where are thy former",6,26],["H2617","lovingkindnesses",27,43],["H7650","which thou swarest",45,63],["H1732","unto David",64,74],["H0530","in thy truth",75,87]]},"89:50":{"text":"Remember, Lord, the reproach of thy servants; how I do bear in my bosom the reproach of all the mighty people;","words":[["H2142","Remember",0,8],["H0136","Lord",10,14],["H2781","the reproach",16,28],["H5650","of thy servants",29,44],["H5375","how I do bear",46,59],["H2436","in my bosom",60,71],["H7227","the reproach of all the mighty",72,102],["H5971","people",103,109]]},"89:51":{"text":"Wherewith thine enemies have reproached, O LORD; wherewith they have reproached the footsteps of thine anointed.","words":[["H0341","Wherewith thine enemies",0,23],["H2778","have reproached",24,39],["H3068","O LORD",41,47],["H2778","wherewith they have reproached",49,79],["H6119","the footsteps",80,93],["H4899","of thine anointed",94,111]]},"89:52":{"text":"Blessed be the LORD for evermore. Amen, and Amen.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H5769","for evermore",20,32],["H0543","Amen",34,38],["H0543","and Amen",40,48]]},"90:1":{"text":"A Prayer of Moses the man of God. Lord, thou hast been our dwelling place in all generations.","words":[["H8605","A Prayer",0,8],["H4872","of Moses",9,17],["H0376","the man",18,25],["H0430","of God",26,32],["H0136","Lord",34,38],["H4583","thou hast been our dwelling place",40,73],["H1755","in all",74,80],["H1755","generations",81,92]]},"90:2":{"text":"Before the mountains were brought forth, or ever thou hadst formed the earth and the world, even from everlasting to everlasting, thou art God.","words":[["H2022","Before the mountains",0,20],["H3205","were brought forth",21,39],["H2342","or ever thou hadst formed",41,66],["H0776","the earth",67,76],["H8398","and the world",77,90],["H5769","even from everlasting",92,113],["H5704","to",114,116],["H5769","everlasting",117,128],["H0410","thou art God",130,142]]},"90:3":{"text":"Thou turnest man to destruction; and sayest, Return, ye children of men.","words":[["H7725","Thou turnest",0,12],["H0582","man",13,16],["H1793","to destruction",17,31],["H0559","and sayest",33,43],["H7725","Return",45,51],["H1121","ye children",53,64],["H0120","of men",65,71]]},"90:4":{"text":"For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night.","words":[["H0505","For a thousand",0,14],["H8141","years",15,20],["H5869","in thy sight",21,33],["H3117","are but as",34,44],["H0865","yesterday",45,54],["H5674","when it is past",55,70],["H0821","and as a watch",72,86],["H3915","in the night",87,99]]},"90:5":{"text":"Thou carriest them away as with a flood; they are as a sleep: in the morning they are like grass which groweth up.","words":[["H2229","Thou carriest them away as with a flood",0,39],["H8142","they are as a sleep",41,60],["H1242","in the morning",62,76],["H2682","they are like grass",77,96],["H2498","which groweth up",97,113]]},"90:6":{"text":"In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth.","words":[["H1242","In the morning",0,14],["H6692","it flourisheth",15,29],["H2498","and groweth up",31,45],["H6153","in the evening",47,61],["H4135","it is cut down",62,76],["H3001","and withereth",78,91]]},"90:7":{"text":"For we are consumed by thine anger, and by thy wrath are we troubled.","words":[["H3615","For we are consumed",0,19],["H0639","by thine anger",20,34],["H2534","and by thy wrath",36,52],["H0926","are we troubled",53,68]]},"90:8":{"text":"Thou hast set our iniquities before thee, our secret sins in the light of thy countenance.","words":[["H7896","Thou hast set",0,13],["H5771","our iniquities",14,28],["H5956","before thee, our secret",29,52],["H3974","sins in the light",53,70],["H6440","of thy countenance",71,89]]},"90:9":{"text":"For all our days are passed away in thy wrath: we spend our years as a tale that is told.","words":[["H3117","For all our days",0,16],["H6437","are passed away",17,32],["H5678","in thy wrath",33,45],["H3615","we spend",47,55],["H8141","our years",56,65],["H1899","as a tale",66,75]]},"90:10":{"text":"The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away.","words":[["H3117","The days",0,8],["H8141","of our years",9,21],["H7657","are threescore",22,36],["H8141","years",37,42],["H7657","and ten",43,50],["H1369","and if by reason of strength",52,80],["H8084","they be fourscore",81,98],["H8141","years",99,104],["H7296","yet is their strength",106,127],["H5999","labour",128,134],["H0205","and sorrow",135,145],["H2440","for it is soon",147,161],["H1468","cut off",162,169],["H5774","and we fly away",171,186]]},"90:11":{"text":"Who knoweth the power of thine anger? even according to thy fear, so is thy wrath.","words":[["H3045","Who knoweth",0,11],["H5797","the power",12,21],["H0639","of thine anger",22,36],["H3374","even according to thy fear",38,64],["H5678","so is thy wrath",66,81]]},"90:12":{"text":"So teach us to number our days, that we may apply our hearts unto wisdom.","words":[["H3045","So teach",0,8],["H4487","us to number",9,21],["H3117","our days",22,30],["H0935","that we may apply",32,49],["H3824","our hearts",50,60],["H2451","unto wisdom",61,72]]},"90:13":{"text":"Return, O LORD, how long? and let it repent thee concerning thy servants.","words":[["H7725","Return",0,6],["H3068","O LORD",8,14],["H5162","how long? and let it repent",16,43],["H5650","thee concerning thy servants",44,72]]},"90:14":{"text":"O satisfy us early with thy mercy; that we may rejoice and be glad all our days.","words":[["H7646","O satisfy",0,9],["H1242","us early",10,18],["H2617","with thy mercy",19,33],["H7442","that we may rejoice",35,54],["H8055","and be glad",55,66],["H3117","all our days",67,79]]},"90:15":{"text":"Make us glad according to the days wherein thou hast afflicted us, and the years wherein we have seen evil.","words":[["H8055","Make us glad",0,12],["H3117","according to the days",13,34],["H6031","wherein thou hast afflicted",35,62],["H8141","us, and the years",63,80],["H7200","wherein we have seen",81,101],["H7451","evil",102,106]]},"90:16":{"text":"Let thy work appear unto thy servants, and thy glory unto their children.","words":[["H6467","Let thy work",0,12],["H7200","appear",13,19],["H5650","unto thy servants",20,37],["H1926","and thy glory",39,52],["H1121","unto their children",53,72]]},"90:17":{"text":"And let the beauty of the LORD our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it.","words":[["H5278","And let the beauty",0,18],["H3068","of the LORD",19,30],["H0430","our God",31,38],["H3559","be upon us: and establish",39,64],["H4639","thou the work",65,78],["H3027","of our hands",79,91],["H4639","upon us; yea, the work",92,114],["H3027","of our hands",115,127],["H3559","establish",128,137]]},"91:1":{"text":"He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty.","words":[["H3427","He that dwelleth",0,16],["H5643","in the secret",17,30],["H5945","place of the most High",31,53],["H3885","shall abide",54,65],["H6738","under the shadow",66,82],["H7706","of the Almighty",83,98]]},"91:2":{"text":"I will say of the LORD, He is my refuge and my fortress: my God; in him will I trust.","words":[["H0559","I will say",0,10],["H3068","of the LORD",11,22],["H4268","He is my refuge",24,39],["H4686","and my fortress",40,55],["H0430","my God",57,63],["H0982","in him will I trust",65,84]]},"91:3":{"text":"Surely he shall deliver thee from the snare of the fowler, and from the noisome pestilence.","words":[["H5337","Surely he shall deliver",0,23],["H6341","thee from the snare",24,43],["H3353","of the fowler",44,57],["H1942","and from the noisome",59,79],["H1698","pestilence",80,90]]},"91:4":{"text":"He shall cover thee with his feathers, and under his wings shalt thou trust: his truth shall be thy shield and buckler.","words":[["H5526","He shall cover",0,14],["H0084","thee with his feathers",15,37],["H3671","and under his wings",39,58],["H2620","shalt thou trust",59,75],["H0571","his truth",77,86],["H6793","shall be thy shield",87,106],["H5507","and buckler",107,118]]},"91:5":{"text":"Thou shalt not be afraid for the terror by night; nor for the arrow that flieth by day;","words":[["H3372","Thou shalt not be afraid",0,24],["H6343","for the terror",25,39],["H3915","by night",40,48],["H2671","nor for the arrow",50,67],["H5774","that flieth",68,79],["H3119","by day",80,86]]},"91:6":{"text":"Nor for the pestilence that walketh in darkness; nor for the destruction that wasteth at noonday.","words":[["H1698","Nor for the pestilence",0,22],["H1980","that walketh",23,35],["H0652","in darkness",36,47],["H6986","nor for the destruction",49,72],["H7736","that wasteth",73,85],["H6672","at noonday",86,96]]},"91:7":{"text":"A thousand shall fall at thy side, and ten thousand at thy right hand; but it shall not come nigh thee.","words":[["H0505","A thousand",0,10],["H5307","shall fall",11,21],["H6654","at thy side",22,33],["H7233","and ten thousand",35,51],["H3225","at thy right hand",52,69],["H5066","but it shall not come nigh",71,97]]},"91:8":{"text":"Only with thine eyes shalt thou behold and see the reward of the wicked.","words":[["H5869","Only with thine eyes",0,20],["H5027","shalt thou behold",21,38],["H7200","and see",39,46],["H8011","the reward",47,57],["H7563","of the wicked",58,71]]},"91:9":{"text":"Because thou hast made the LORD, which is my refuge, even the most High, thy habitation;","words":[["H7760","Because thou hast made",0,22],["H3068","the LORD",23,31],["H4268","which is my refuge",33,51],["H5945","even the most High",53,71],["H4583","thy habitation",73,87]]},"91:10":{"text":"There shall no evil befall thee, neither shall any plague come nigh thy dwelling.","words":[["H7451","There shall no evil",0,19],["H0579","befall",20,26],["H5061","thee, neither shall any plague",27,57],["H7126","come nigh",58,67],["H0168","thy dwelling",68,80]]},"91:11":{"text":"For he shall give his angels charge over thee, to keep thee in all thy ways.","words":[["H4397","For he shall give his angels",0,28],["H6680","charge",29,35],["H8104","over thee, to keep",36,54],["H1870","thee in all thy ways",55,75]]},"91:12":{"text":"They shall bear thee up in their hands, lest thou dash thy foot against a stone.","words":[["H5375","They shall bear thee up",0,23],["H3709","in their hands",24,38],["H5062","lest thou dash",40,54],["H7272","thy foot",55,63],["H0068","against a stone",64,79]]},"91:13":{"text":"Thou shalt tread upon the lion and adder: the young lion and the dragon shalt thou trample under feet.","words":[["H1869","Thou shalt tread",0,16],["H7826","upon the lion",17,30],["H6620","and adder",31,40],["H3715","the young lion",42,56],["H8577","and the dragon",57,71],["H7429","shalt thou trample under feet",72,101]]},"91:14":{"text":"Because he hath set his love upon me, therefore will I deliver him: I will set him on high, because he hath known my name.","words":[["H2836","Because he hath set his love",0,28],["H6403","upon me, therefore will I deliver",29,62],["H7682","him: I will set him on high",63,90],["H3045","because he hath known",92,113],["H8034","my name",114,121]]},"91:15":{"text":"He shall call upon me, and I will answer him: I will be with him in trouble; I will deliver him, and honour him.","words":[["H7121","He shall call",0,13],["H6030","upon me, and I will answer",14,40],["H6869","him: I will be with him in trouble",41,75],["H2502","I will deliver",77,91],["H3513","him, and honour",92,107]]},"91:16":{"text":"With long life will I satisfy him, and shew him my salvation.","words":[["H0753","With long",0,9],["H3117","life",10,14],["H7646","will I satisfy",15,29],["H7200","him, and shew",30,43],["H3444","him my salvation",44,60]]},"92:1":{"text":"A Psalm or Song for the sabbath day. It is a good thing to give thanks unto the LORD, and to sing praises unto thy name, O most High:","words":[["H4210","A Psalm",0,7],["H7892","or Song",8,15],["H7676","for the sabbath",16,31],["H3117","day",32,35],["H2896","It is a good",37,49],["H3034","thing to give thanks",50,70],["H3068","unto the LORD",71,84],["H2167","and to sing praises",86,105],["H8034","unto thy name",106,119],["H5945","O most High",121,132]]},"92:2":{"text":"To shew forth thy lovingkindness in the morning, and thy faithfulness every night,","words":[["H5046","To shew forth",0,13],["H2617","thy lovingkindness",14,32],["H1242","in the morning",33,47],["H0530","and thy faithfulness",49,69],["H3915","every night",70,81]]},"92:3":{"text":"Upon an instrument of ten strings, and upon the psaltery; upon the harp with a solemn sound.","words":[["H6218","Upon an instrument of ten strings",0,33],["H5035","and upon the psaltery",35,56],["H3658","upon the harp",58,71],["H1902","with a solemn sound",72,91]]},"92:4":{"text":"For thou, LORD, hast made me glad through thy work: I will triumph in the works of thy hands.","words":[["H3068","For thou, LORD",0,14],["H8055","hast made me glad",16,33],["H6467","through thy work",34,50],["H7442","I will triumph",52,66],["H4639","in the works",67,79],["H3027","of thy hands",80,92]]},"92:5":{"text":"O LORD, how great are thy works! and thy thoughts are very deep.","words":[["H3068","O LORD",0,6],["H1431","how great",8,17],["H4639","are thy works",18,31],["H4284","and thy thoughts",33,49],["H3966","are very",50,58],["H6009","deep",59,63]]},"92:6":{"text":"A brutish man knoweth not; neither doth a fool understand this.","words":[["H1198","A brutish",0,9],["H0376","man",10,13],["H3045","knoweth",14,21],["H3684","not; neither doth a fool",22,46],["H0995","understand",47,57]]},"92:7":{"text":"When the wicked spring as the grass, and when all the workers of iniquity do flourish; it is that they shall be destroyed for ever:","words":[["H7563","When the wicked",0,15],["H6524","spring",16,22],["H6212","as the grass",23,35],["H6466","and when all the workers",37,61],["H0205","of iniquity",62,73],["H6692","do flourish",74,85],["H8045","it is that they shall be destroyed",87,121],["H5703","for ever",122,130]]},"92:8":{"text":"But thou, LORD, art most high for evermore.","words":[["H3068","But thou, LORD",0,14],["H4791","art most high",16,29],["H5769","for evermore",30,42]]},"92:9":{"text":"For, lo, thine enemies, O LORD, for, lo, thine enemies shall perish; all the workers of iniquity shall be scattered.","words":[["H0341","For, lo, thine enemies",0,22],["H3068","O LORD",24,30],["H0341","for, lo, thine enemies",32,54],["H0006","shall perish",55,67],["H6466","all the workers",69,84],["H0205","of iniquity",85,96],["H6504","shall be scattered",97,115]]},"92:10":{"text":"But my horn shalt thou exalt like the horn of an unicorn: I shall be anointed with fresh oil.","words":[["H7161","But my horn",0,11],["H7311","shalt thou exalt",12,28],["H7214","like the horn of an unicorn",29,56],["H1101","I shall be anointed",58,77],["H7488","with fresh",78,88],["H8081","oil",89,92]]},"92:11":{"text":"Mine eye also shall see my desire on mine enemies, and mine ears shall hear my desire of the wicked that rise up against me.","words":[["H5869","Mine eye",0,8],["H5027","also shall see",9,23],["H7790","my desire on mine enemies",24,49],["H0241","and mine ears",51,64],["H8085","shall hear",65,75],["H7489","my desire of the wicked",76,99],["H6965","that rise up",100,112]]},"92:12":{"text":"The righteous shall flourish like the palm tree: he shall grow like a cedar in Lebanon.","words":[["H6662","The righteous",0,13],["H6524","shall flourish",14,28],["H8558","like the palm tree",29,47],["H7685","he shall grow",49,62],["H0730","like a cedar",63,75],["H3844","in Lebanon",76,86]]},"92:13":{"text":"Those that be planted in the house of the LORD shall flourish in the courts of our God.","words":[["H8362","Those that be planted",0,21],["H1004","in the house",22,34],["H3068","of the LORD",35,46],["H6524","shall flourish",47,61],["H2691","in the courts",62,75],["H0430","of our God",76,86]]},"92:14":{"text":"They shall still bring forth fruit in old age; they shall be fat and flourishing;","words":[["H5107","They shall still bring forth fruit",0,34],["H7872","in old age",35,45],["H1879","they shall be fat",47,64],["H7488","and flourishing",65,80]]},"92:15":{"text":"To shew that the LORD is upright: he is my rock, and there is no unrighteousness in him.","words":[["H5046","To shew",0,7],["H3068","that the LORD",8,21],["H3477","is upright",22,32],["H6697","he is my rock",34,47],["H5766","and there is no unrighteousness",49,80],["H5766","and there is no unrighteousness",49,80]]},"93:1":{"text":"The LORD reigneth, he is clothed with majesty; the LORD is clothed with strength, wherewith he hath girded himself: the world also is stablished, that it cannot be moved.","words":[["H3068","The LORD",0,8],["H4427","reigneth",9,17],["H3847","he is clothed",19,32],["H1348","with majesty",33,45],["H3068","the LORD",47,55],["H3847","is clothed",56,66],["H5797","with strength",67,80],["H0247","wherewith he hath girded",82,106],["H8398","himself: the world",107,125],["H3559","also is stablished",126,144],["H4131","that it cannot be moved",146,169]]},"93:2":{"text":"Thy throne is established of old: thou art from everlasting.","words":[["H3678","Thy throne",0,10],["H3559","is established",11,25],["H0227","of old",26,32],["H5769","thou art from everlasting",34,59]]},"93:3":{"text":"The floods have lifted up, O LORD, the floods have lifted up their voice; the floods lift up their waves.","words":[["H5104","The floods",0,10],["H5375","have lifted up",11,25],["H3068","O LORD",27,33],["H5104","the floods",35,45],["H5375","have lifted up",46,60],["H6963","their voice",61,72],["H5104","the floods",74,84],["H5375","lift up",85,92],["H1796","their waves",93,104]]},"93:4":{"text":"The LORD on high is mightier than the noise of many waters, yea, than the mighty waves of the sea.","words":[["H3068","The LORD",0,8],["H4791","on high",9,16],["H0117","is mightier",17,28],["H6963","than the noise",29,43],["H7227","of many",44,51],["H4325","waters",52,58],["H0117","yea, than the mighty",60,80],["H4867","waves",81,86],["H3220","of the sea",87,97]]},"93:5":{"text":"Thy testimonies are very sure: holiness becometh thine house, O LORD, for ever.","words":[["H5713","Thy testimonies",0,15],["H3966","are very",16,24],["H0539","sure",25,29],["H6944","holiness",31,39],["H4998","becometh",40,48],["H1004","thine house",49,60],["H3068","O LORD",62,68],["H0753","for ever",70,78],["H3117","for ever",70,78]]},"94:1":{"text":"O LORD God, to whom vengeance belongeth; O God, to whom vengeance belongeth, shew thyself.","words":[["H3068","O LORD",0,6],["H0410","God",7,10],["H5360","to whom vengeance",12,29],["H0410","belongeth; O God",30,46],["H5360","to whom vengeance",48,65],["H3313","belongeth, shew",66,81]]},"94:2":{"text":"Lift up thyself, thou judge of the earth: render a reward to the proud.","words":[["H5375","Lift up",0,7],["H8199","thyself, thou judge",8,27],["H0776","of the earth",28,40],["H7725","render",42,48],["H1576","a reward",49,57],["H1343","to the proud",58,70]]},"94:3":{"text":"LORD, how long shall the wicked, how long shall the wicked triumph?","words":[["H3068","LORD",0,4],["H7563","how long shall the wicked",6,31],["H7563","how long shall the wicked",33,58],["H5937","triumph",59,66]]},"94:4":{"text":"How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?","words":[["H5042","How long shall they utter",0,25],["H1696","and speak",26,35],["H6277","hard things",36,47],["H6466","and all the workers",49,68],["H0205","of iniquity",69,80],["H0559","boast",81,86]]},"94:5":{"text":"They break in pieces thy people, O LORD, and afflict thine heritage.","words":[["H1792","They break in pieces",0,20],["H5971","thy people",21,31],["H3068","O LORD",33,39],["H6031","and afflict",41,52],["H5159","thine heritage",53,67]]},"94:6":{"text":"They slay the widow and the stranger, and murder the fatherless.","words":[["H2026","They slay",0,9],["H0490","the widow",10,19],["H1616","and the stranger",20,36],["H7523","and murder",38,48],["H3490","the fatherless",49,63]]},"94:7":{"text":"Yet they say, The LORD shall not see, neither shall the God of Jacob regard it.","words":[["H0559","Yet they say",0,12],["H3050","The LORD",14,22],["H7200","shall not see",23,36],["H0430","neither shall the God",38,59],["H3290","of Jacob",60,68],["H0995","regard",69,75]]},"94:8":{"text":"Understand, ye brutish among the people: and ye fools, when will ye be wise?","words":[["H0995","Understand",0,10],["H1197","ye brutish",12,22],["H5971","among the people",23,39],["H3684","and ye fools",41,53],["H7919","when will ye be wise",55,75]]},"94:9":{"text":"He that planted the ear, shall he not hear? he that formed the eye, shall he not see?","words":[["H5193","He that planted",0,15],["H0241","the ear",16,23],["H8085","shall he not hear",25,42],["H3335","he that formed",44,58],["H5869","the eye",59,66],["H5027","shall he not see",68,84]]},"94:10":{"text":"He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge, shall not he know?","words":[["H3256","He that chastiseth",0,18],["H1471","the heathen",19,30],["H3198","shall not he correct",32,52],["H3925","he that teacheth",54,70],["H0120","man",71,74],["H1847","knowledge",75,84]]},"94:11":{"text":"The LORD knoweth the thoughts of man, that they are vanity.","words":[["H3068","The LORD",0,8],["H3045","knoweth",9,16],["H4284","the thoughts",17,29],["H0120","of man",30,36],["H1892","that they are vanity",38,58]]},"94:12":{"text":"Blessed is the man whom thou chastenest, O LORD, and teachest him out of thy law;","words":[["H0835","Blessed",0,7],["H1397","is the man",8,18],["H3256","whom thou chastenest",19,39],["H3050","O LORD",41,47],["H3925","and teachest",49,61],["H8451","him out of thy law",62,80]]},"94:13":{"text":"That thou mayest give him rest from the days of adversity, until the pit be digged for the wicked.","words":[["H8252","That thou mayest give him rest",0,30],["H3117","from the days",31,44],["H7451","of adversity",45,57],["H7845","until the pit",59,72],["H3738","be digged",73,82],["H7563","for the wicked",83,97]]},"94:14":{"text":"For the LORD will not cast off his people, neither will he forsake his inheritance.","words":[["H3068","For the LORD",0,12],["H5203","will not cast off",13,30],["H5971","his people",31,41],["H5800","neither will he forsake",43,66],["H5159","his inheritance",67,82]]},"94:15":{"text":"But judgment shall return unto righteousness: and all the upright in heart shall follow it.","words":[["H4941","But judgment",0,12],["H7725","shall return",13,25],["H6664","unto righteousness",26,44],["H3477","and all the upright",46,65],["H3820","in heart",66,74],["H0310","shall follow",75,87]]},"94:16":{"text":"Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?","words":[["H6965","Who will rise up",0,16],["H7489","for me against the evildoers",17,45],["H3320","or who will stand up",47,67],["H6466","for me against the workers",68,94],["H0205","of iniquity",95,106]]},"94:17":{"text":"Unless the LORD had been my help, my soul had almost dwelt in silence.","words":[["H3884","Unless",0,6],["H3068","the LORD",7,15],["H5833","had been my help",16,32],["H5315","my soul",34,41],["H4592","had almost",42,52],["H7931","dwelt",53,58],["H1745","in silence",59,69]]},"94:18":{"text":"When I said, My foot slippeth; thy mercy, O LORD, held me up.","words":[["H0559","When I said",0,11],["H7272","My foot",13,20],["H4131","slippeth",21,29],["H2617","thy mercy",31,40],["H3068","O LORD",42,48],["H5582","held me up",50,60]]},"94:19":{"text":"In the multitude of my thoughts within me thy comforts delight my soul.","words":[["H7230","In the multitude",0,16],["H8312","of my thoughts",17,31],["H7130","within",32,38],["H8575","me thy comforts",39,54],["H8173","delight",55,62],["H5315","my soul",63,70]]},"94:20":{"text":"Shall the throne of iniquity have fellowship with thee, which frameth mischief by a law?","words":[["H3678","Shall the throne",0,16],["H1942","of iniquity",17,28],["H2266","have fellowship",29,44],["H3335","with thee, which frameth",45,69],["H5999","mischief",70,78],["H2706","by a law",79,87]]},"94:21":{"text":"They gather themselves together against the soul of the righteous, and condemn the innocent blood.","words":[["H1413","They gather themselves together",0,31],["H5315","against the soul",32,48],["H6662","of the righteous",49,65],["H7561","and condemn",67,78],["H5355","the innocent",79,91],["H1818","blood",92,97]]},"94:22":{"text":"But the LORD is my defence; and my God is the rock of my refuge.","words":[["H3068","But the LORD",0,12],["H4869","is my defence",13,26],["H0430","and my God",28,38],["H6697","is the rock",39,50],["H4268","of my refuge",51,63]]},"94:23":{"text":"And he shall bring upon them their own iniquity, and shall cut them off in their own wickedness; yea, the LORD our God shall cut them off.","words":[["H7725","And he shall bring",0,18],["H0205","upon them their own iniquity",19,47],["H6789","and shall cut them off",49,71],["H7451","in their own wickedness",72,95],["H3068","yea, the LORD",97,110],["H0430","our God",111,118],["H6789","shall cut them off",119,137]]},"95:1":{"text":"O come, let us sing unto the LORD: let us make a joyful noise to the rock of our salvation.","words":[["H3212","O come",0,6],["H7442","let us sing",8,19],["H3068","unto the LORD",20,33],["H7321","let us make a joyful noise",35,61],["H6697","to the rock",62,73],["H3468","of our salvation",74,90]]},"95:2":{"text":"Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms.","words":[["H6923","Let us come",0,11],["H6440","before his presence",12,31],["H8426","with thanksgiving",32,49],["H7321","and make a joyful noise",51,74],["H2158","unto him with psalms",75,95]]},"95:3":{"text":"For the LORD is a great God, and a great King above all gods.","words":[["H3068","For the LORD",0,12],["H1419","is a great",13,23],["H0410","God",24,27],["H1419","and a great",29,40],["H4428","King",41,45],["H0430","above all gods",46,60]]},"95:4":{"text":"In his hand are the deep places of the earth: the strength of the hills is his also.","words":[["H3027","In his hand",0,11],["H4278","are the deep places",12,31],["H0776","of the earth",32,44],["H8443","the strength",46,58],["H2022","of the hills",59,71]]},"95:5":{"text":"The sea is his, and he made it: and his hands formed the dry land.","words":[["H3220","The sea",0,7],["H6213","is his, and he made",8,27],["H3027","it: and his hands",28,45],["H3335","formed",46,52],["H3006","the dry",53,60]]},"95:6":{"text":"O come, let us worship and bow down: let us kneel before the LORD our maker.","words":[["H0935","O come",0,6],["H7812","let us worship",8,22],["H3766","and bow down",23,35],["H1288","let us kneel",37,49],["H6440","before",50,56],["H3068","the LORD",57,65],["H6213","our maker",66,75]]},"95:7":{"text":"For he is our God; and we are the people of his pasture, and the sheep of his hand. To day if ye will hear his voice,","words":[["H0430","For he is our God",0,17],["H5971","and we are the people",19,40],["H4830","of his pasture",41,55],["H6629","and the sheep",57,70],["H3027","of his hand",71,82],["H3117","To day",84,90],["H8085","if ye will hear",91,106],["H6963","his voice",107,116]]},"95:8":{"text":"Harden not your heart, as in the provocation, and as in the day of temptation in the wilderness:","words":[["H7185","Harden",0,6],["H3824","not your heart",7,21],["H4808","as in the provocation",23,44],["H3117","and as in the day",46,63],["H4531","of temptation",64,77],["H4057","in the wilderness",78,95]]},"95:9":{"text":"When your fathers tempted me, proved me, and saw my work.","words":[["H0001","When your fathers",0,17],["H5254","tempted",18,25],["H0974","me, proved",26,36],["H7200","me, and saw",37,48],["H6467","my work",49,56]]},"95:10":{"text":"Forty years long was I grieved with this generation, and said, It is a people that do err in their heart, and they have not known my ways:","words":[["H0705","Forty",0,5],["H8141","years",6,11],["H6962","long was I grieved",12,30],["H1755","with this generation",31,51],["H0559","and said",53,61],["H5971","It is a people",63,77],["H8582","that do err",78,89],["H3824","in their heart",90,104],["H3045","and they have not known",106,129],["H1870","my ways",130,137]]},"95:11":{"text":"Unto whom I sware in my wrath that they should not enter into my rest.","words":[["H7650","Unto whom I sware",0,17],["H0639","in my wrath",18,29],["H0935","that they should not enter",30,56],["H4496","into my rest",57,69]]},"96:1":{"text":"O sing unto the LORD a new song: sing unto the LORD, all the earth.","words":[["H7891","O sing",0,6],["H3068","unto the LORD",7,20],["H2319","a new",21,26],["H7892","song",27,31],["H7891","sing",33,37],["H3068","unto the LORD",38,51],["H0776","all the earth",53,66]]},"96:2":{"text":"Sing unto the LORD, bless his name; shew forth his salvation from day to day.","words":[["H7891","Sing",0,4],["H3068","unto the LORD",5,18],["H1288","bless",20,25],["H8034","his name",26,34],["H1319","shew forth",36,46],["H3444","his salvation",47,60],["H3117","from day",61,69],["H3117","to day",70,76]]},"96:3":{"text":"Declare his glory among the heathen, his wonders among all people.","words":[["H5608","Declare",0,7],["H3519","his glory",8,17],["H1471","among the heathen",18,35],["H6381","his wonders",37,48],["H5971","among all people",49,65]]},"96:4":{"text":"For the LORD is great, and greatly to be praised: he is to be feared above all gods.","words":[["H3068","For the LORD",0,12],["H1419","is great",13,21],["H3966","and greatly",23,34],["H1984","to be praised",35,48],["H3372","he is to be feared",50,68],["H0430","above all gods",69,83]]},"96:5":{"text":"For all the gods of the nations are idols: but the LORD made the heavens.","words":[["H0430","For all the gods",0,16],["H5971","of the nations",17,31],["H0457","are idols",32,41],["H3068","but the LORD",43,55],["H6213","made",56,60],["H8064","the heavens",61,72]]},"96:6":{"text":"Honour and majesty are before him: strength and beauty are in his sanctuary.","words":[["H1935","Honour",0,6],["H1926","and majesty",7,18],["H6440","are before",19,29],["H5797","him: strength",30,43],["H8597","and beauty",44,54],["H4720","are in his sanctuary",55,75]]},"96:7":{"text":"Give unto the LORD, O ye kindreds of the people, give unto the LORD glory and strength.","words":[["H3051","Give",0,4],["H3068","unto the LORD",5,18],["H4940","O ye kindreds",20,33],["H5971","of the people",34,47],["H3051","give",49,53],["H3068","unto the LORD",54,67],["H3519","glory",68,73],["H5797","and strength",74,86]]},"96:8":{"text":"Give unto the LORD the glory due unto his name: bring an offering, and come into his courts.","words":[["H3051","Give",0,4],["H3068","unto the LORD",5,18],["H3519","the glory",19,28],["H8034","due unto his name",29,46],["H5375","bring",48,53],["H4503","an offering",54,65],["H0935","and come",67,75],["H2691","into his courts",76,91]]},"96:9":{"text":"O worship the LORD in the beauty of holiness: fear before him, all the earth.","words":[["H7812","O worship",0,9],["H3068","the LORD",10,18],["H1927","in the beauty",19,32],["H6944","of holiness",33,44],["H2342","fear",46,50],["H6440","before",51,57],["H0776","him, all the earth",58,76]]},"96:10":{"text":"Say among the heathen that the LORD reigneth: the world also shall be established that it shall not be moved: he shall judge the people righteously.","words":[["H0559","Say",0,3],["H1471","among the heathen",4,21],["H3068","that the LORD",22,35],["H4427","reigneth",36,44],["H8398","the world",46,55],["H3559","also shall be established",56,81],["H4131","that it shall not be moved",82,108],["H1777","he shall judge",110,124],["H5971","the people",125,135],["H4339","righteously",136,147]]},"96:11":{"text":"Let the heavens rejoice, and let the earth be glad; let the sea roar, and the fulness thereof.","words":[["H8064","Let the heavens",0,15],["H8055","rejoice",16,23],["H0776","and let the earth",25,42],["H1523","be glad",43,50],["H3220","let the sea",52,63],["H7481","roar",64,68],["H4393","and the fulness",70,85]]},"96:12":{"text":"Let the field be joyful, and all that is therein: then shall all the trees of the wood rejoice","words":[["H7704","Let the field",0,13],["H5937","be joyful",14,23],["H6086","and all that is therein: then shall all the trees",25,74],["H3293","of the wood",75,86],["H7442","rejoice",87,94]]},"96:13":{"text":"Before the LORD: for he cometh, for he cometh to judge the earth: he shall judge the world with righteousness, and the people with his truth.","words":[["H6440","Before",0,6],["H3068","the LORD",7,15],["H0935","for he cometh",17,30],["H0935","for he cometh",32,45],["H8199","to judge",46,54],["H0776","the earth",55,64],["H8199","he shall judge",66,80],["H8398","the world",81,90],["H6664","with righteousness",91,109],["H5971","and the people",111,125],["H0530","with his truth",126,140]]},"97:1":{"text":"The LORD reigneth; let the earth rejoice; let the multitude of isles be glad thereof.","words":[["H3068","The LORD",0,8],["H4427","reigneth",9,17],["H0776","let the earth",19,32],["H1523","rejoice",33,40],["H7227","let the multitude",42,59],["H0339","of isles",60,68],["H8055","be glad",69,76]]},"97:2":{"text":"Clouds and darkness are round about him: righteousness and judgment are the habitation of his throne.","words":[["H6051","Clouds",0,6],["H6205","and darkness",7,19],["H5439","are round about",20,35],["H6664","him: righteousness",36,54],["H4941","and judgment",55,67],["H4349","are the habitation",68,86],["H3678","of his throne",87,100]]},"97:3":{"text":"A fire goeth before him, and burneth up his enemies round about.","words":[["H0784","A fire",0,6],["H3212","goeth",7,12],["H6440","before",13,19],["H3857","him, and burneth up",20,39],["H6862","his enemies",40,51],["H5439","round about",52,63]]},"97:4":{"text":"His lightnings enlightened the world: the earth saw, and trembled.","words":[["H1300","His lightnings",0,14],["H0215","enlightened",15,26],["H8398","the world",27,36],["H0776","the earth",38,47],["H7200","saw",48,51],["H2342","and trembled",53,65]]},"97:5":{"text":"The hills melted like wax at the presence of the LORD, at the presence of the Lord of the whole earth.","words":[["H2022","The hills",0,9],["H4549","melted",10,16],["H1749","like wax",17,25],["H6440","at the presence",26,41],["H3068","of the LORD",42,53],["H6440","at the presence",55,70],["H0113","of the Lord",71,82],["H0776","of the whole earth",83,101]]},"97:6":{"text":"The heavens declare his righteousness, and all the people see his glory.","words":[["H8064","The heavens",0,11],["H5046","declare",12,19],["H6664","his righteousness",20,37],["H5971","and all the people",39,57],["H7200","see",58,61],["H3519","his glory",62,71]]},"97:7":{"text":"Confounded be all they that serve graven images, that boast themselves of idols: worship him, all ye gods.","words":[["H0954","Confounded",0,10],["H5647","be all they that serve",11,33],["H6459","graven images",34,47],["H1984","that boast",49,59],["H0457","themselves of idols",60,79],["H7812","worship",81,88],["H0430","him, all ye gods",89,105]]},"97:8":{"text":"Zion heard, and was glad; and the daughters of Judah rejoiced because of thy judgments, O LORD.","words":[["H6726","Zion",0,4],["H8085","heard",5,10],["H8055","and was glad",12,24],["H1323","and the daughters",26,43],["H3063","of Judah",44,52],["H1523","rejoiced",53,61],["H4941","because of thy judgments",62,86],["H3068","O LORD",88,94]]},"97:9":{"text":"For thou, LORD, art high above all the earth: thou art exalted far above all gods.","words":[["H3068","For thou, LORD",0,14],["H5945","art high above",16,30],["H0776","all the earth",31,44],["H5927","thou art exalted",46,62],["H3966","far above",63,72],["H0430","all gods",73,81]]},"97:10":{"text":"Ye that love the LORD, hate evil: he preserveth the souls of his saints; he delivereth them out of the hand of the wicked.","words":[["H0157","Ye that love",0,12],["H3068","the LORD",13,21],["H8130","hate",23,27],["H7451","evil",28,32],["H8104","he preserveth",34,47],["H5315","the souls",48,57],["H2623","of his saints",58,71],["H5337","he delivereth",73,86],["H3027","them out of the hand",87,107],["H7563","of the wicked",108,121]]},"97:11":{"text":"Light is sown for the righteous, and gladness for the upright in heart.","words":[["H0216","Light",0,5],["H2232","is sown",6,13],["H6662","for the righteous",14,31],["H8057","and gladness",33,45],["H3477","for the upright",46,61],["H3820","in heart",62,70]]},"97:12":{"text":"Rejoice in the LORD, ye righteous; and give thanks at the remembrance of his holiness.","words":[["H8055","Rejoice",0,7],["H3068","in the LORD",8,19],["H6662","ye righteous",21,33],["H3034","and give thanks",35,50],["H2143","at the remembrance",51,69],["H6944","of his holiness",70,85]]},"98:1":{"text":"A Psalm. O sing unto the LORD a new song; for he hath done marvellous things: his right hand, and his holy arm, hath gotten him the victory.","words":[["H4210","A Psalm",0,7],["H7891","O sing",9,15],["H3068","unto the LORD",16,29],["H2319","a new",30,35],["H7892","song",36,40],["H6213","for he hath done",42,58],["H6381","marvellous things",59,76],["H3225","his right hand",78,92],["H6944","and his holy",94,106],["H2220","arm",107,110],["H3467","hath gotten him the victory",112,139]]},"98:2":{"text":"The LORD hath made known his salvation: his righteousness hath he openly shewed in the sight of the heathen.","words":[["H3068","The LORD",0,8],["H3045","hath made known",9,24],["H3444","his salvation",25,38],["H6666","his righteousness",40,57],["H1540","hath he openly shewed",58,79],["H5869","in the sight",80,92],["H1471","of the heathen",93,107]]},"98:3":{"text":"He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God.","words":[["H2142","He hath remembered",0,18],["H2617","his mercy",19,28],["H0530","and his truth",29,42],["H1004","toward the house",43,59],["H3478","of Israel",60,69],["H0657","all the ends",71,83],["H0776","of the earth",84,96],["H7200","have seen",97,106],["H3444","the salvation",107,120],["H0430","of our God",121,131]]},"98:4":{"text":"Make a joyful noise unto the LORD, all the earth: make a loud noise, and rejoice, and sing praise.","words":[["H7321","Make a joyful noise",0,19],["H3068","unto the LORD",20,33],["H0776","all the earth",35,48],["H6476","make a loud noise",50,67],["H7442","and rejoice",69,80],["H2167","and sing",82,90]]},"98:5":{"text":"Sing unto the LORD with the harp; with the harp, and the voice of a psalm.","words":[["H2167","Sing",0,4],["H3068","unto the LORD",5,18],["H3658","with the harp",19,32],["H3658","with the harp",34,47],["H6963","and the voice",49,62],["H2172","of a psalm",63,73]]},"98:6":{"text":"With trumpets and sound of cornet make a joyful noise before the LORD, the King.","words":[["H2689","With trumpets",0,13],["H6963","and sound",14,23],["H7782","of cornet",24,33],["H7321","make a joyful noise",34,53],["H6440","before",54,60],["H3068","the LORD",61,69],["H4428","the King",71,79]]},"98:7":{"text":"Let the sea roar, and the fulness thereof; the world, and they that dwell therein.","words":[["H3220","Let the sea",0,11],["H7481","roar",12,16],["H4393","and the fulness",18,33],["H8398","thereof; the world",34,52],["H3427","and they that dwell",54,73]]},"98:8":{"text":"Let the floods clap their hands: let the hills be joyful together","words":[["H5104","Let the floods",0,14],["H4222","clap",15,19],["H3709","their hands",20,31],["H2022","let the hills",33,46],["H7442","be joyful",47,56],["H3162","together",57,65]]},"98:9":{"text":"Before the LORD; for he cometh to judge the earth: with righteousness shall he judge the world, and the people with equity.","words":[["H6440","Before",0,6],["H3068","the LORD",7,15],["H0935","for he cometh",17,30],["H8199","to judge",31,39],["H0776","the earth",40,49],["H6664","with righteousness",51,69],["H8199","shall he judge",70,84],["H8398","the world",85,94],["H5971","and the people",96,110],["H4339","with equity",111,122]]},"99:1":{"text":"The LORD reigneth; let the people tremble: he sitteth between the cherubims; let the earth be moved.","words":[["H3068","The LORD",0,8],["H4427","reigneth",9,17],["H5971","let the people",19,33],["H7264","tremble",34,41],["H3427","he sitteth",43,53],["H3742","between the cherubims",54,75],["H0776","let the earth",77,90],["H5120","be moved",91,99]]},"99:2":{"text":"The LORD is great in Zion; and he is high above all the people.","words":[["H3068","The LORD",0,8],["H1419","is great",9,17],["H6726","in Zion",18,25],["H7311","and he is high",27,41],["H5971","above all the people",42,62]]},"99:3":{"text":"Let them praise thy great and terrible name; for it is holy.","words":[["H3034","Let them praise",0,15],["H1419","thy great",16,25],["H3372","and terrible",26,38],["H8034","name",39,43],["H6918","for it is holy",45,59]]},"99:4":{"text":"The king's strength also loveth judgment; thou dost establish equity, thou executest judgment and righteousness in Jacob.","words":[["H4428","The king's",0,10],["H5797","strength",11,19],["H0157","also loveth",20,31],["H4941","judgment",32,40],["H3559","thou dost establish",42,61],["H4339","equity",62,68],["H6213","thou executest",70,84],["H4941","judgment",85,93],["H6666","and righteousness",94,111],["H3290","in Jacob",112,120]]},"99:5":{"text":"Exalt ye the LORD our God, and worship at his footstool; for he is holy.","words":[["H7311","Exalt",0,5],["H3068","ye the LORD",6,17],["H0430","our God",18,25],["H7812","and worship",27,38],["H7272","at his footstool",39,55],["H1916","at his footstool",39,55],["H6918","for he is holy",57,71]]},"99:6":{"text":"Moses and Aaron among his priests, and Samuel among them that call upon his name; they called upon the LORD, and he answered them.","words":[["H4872","Moses",0,5],["H0175","and Aaron",6,15],["H3548","among his priests",16,33],["H8050","and Samuel",35,45],["H7121","among them that call",46,66],["H8034","upon his name",67,80],["H7121","they called",82,93],["H3068","upon the LORD",94,107],["H6030","and he answered",109,124]]},"99:7":{"text":"He spake unto them in the cloudy pillar: they kept his testimonies, and the ordinance that he gave them.","words":[["H1696","He spake",0,8],["H6051","unto them in the cloudy",9,32],["H5982","pillar",33,39],["H8104","they kept",41,50],["H5713","his testimonies",51,66],["H2706","and the ordinance",68,85],["H5414","that he gave",86,98]]},"99:8":{"text":"Thou answeredst them, O LORD our God: thou wast a God that forgavest them, though thou tookest vengeance of their inventions.","words":[["H6030","Thou answeredst",0,15],["H3068","them, O LORD",16,28],["H0430","our God",29,36],["H0410","thou wast a God",38,53],["H5375","that forgavest",54,68],["H5358","them, though thou tookest vengeance",69,104],["H5949","of their inventions",105,124]]},"99:9":{"text":"Exalt the LORD our God, and worship at his holy hill; for the LORD our God is holy.","words":[["H7311","Exalt",0,5],["H3068","the LORD",6,14],["H0430","our God",15,22],["H7812","and worship",24,35],["H6944","at his holy",36,47],["H2022","hill",48,52],["H3068","for the LORD",54,66],["H0430","our God",67,74],["H6918","is holy",75,82]]},"100:1":{"text":"A Psalm of praise. Make a joyful noise unto the LORD, all ye lands.","words":[["H4210","A Psalm",0,7],["H8426","of praise",8,17],["H7321","Make a joyful noise",19,38],["H3068","unto the LORD",39,52],["H0776","all ye lands",54,66]]},"100:2":{"text":"Serve the LORD with gladness: come before his presence with singing.","words":[["H5647","Serve",0,5],["H3068","the LORD",6,14],["H8057","with gladness",15,28],["H0935","come",30,34],["H6440","before his presence",35,54],["H7445","with singing",55,67]]},"100:3":{"text":"Know ye that the LORD he is God: it is he that hath made us, and not we ourselves; we are his people, and the sheep of his pasture.","words":[["H3045","Know",0,4],["H3068","ye that the LORD",5,21],["H0430","he is God",22,31],["H6213","it is he that hath made",33,56],["H5971","us, and not we ourselves; we are his people",57,100],["H6629","and the sheep",102,115],["H4830","of his pasture",116,130]]},"100:4":{"text":"Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name.","words":[["H0935","Enter",0,5],["H8179","into his gates",6,20],["H8426","with thanksgiving",21,38],["H2691","and into his courts",40,59],["H8416","with praise",60,71],["H3034","be thankful",73,84],["H1288","unto him, and bless",85,104],["H8034","his name",105,113]]},"100:5":{"text":"For the LORD is good; his mercy is everlasting; and his truth endureth to all generations.","words":[["H3068","For the LORD",0,12],["H2896","is good",13,20],["H2617","his mercy",22,31],["H5769","is everlasting",32,46],["H0530","and his truth",48,61],["H1755","endureth to all",62,77],["H1755","generations",78,89]]},"101:1":{"text":"A Psalm of David. I will sing of mercy and judgment: unto thee, O LORD, will I sing.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H7891","I will sing",18,29],["H2617","of mercy",30,38],["H4941","and judgment",39,51],["H3068","unto thee, O LORD",53,70],["H2167","will I sing",72,83]]},"101:2":{"text":"I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart.","words":[["H7919","I will behave myself wisely",0,27],["H8549","in a perfect",28,40],["H1870","way",41,44],["H0935","O when wilt thou come",46,67],["H1980","unto me? I will walk",68,88],["H7130","within",89,95],["H1004","my house",96,104],["H8537","with a perfect",105,119],["H3824","heart",120,125]]},"101:3":{"text":"I will set no wicked thing before mine eyes: I hate the work of them that turn aside; it shall not cleave to me.","words":[["H7896","I will set",0,10],["H1100","no wicked",11,20],["H1697","thing",21,26],["H5869","before mine eyes",27,43],["H8130","I hate",45,51],["H6213","the work",52,60],["H7750","of them that turn aside",61,84],["H1692","it shall not cleave",86,105]]},"101:4":{"text":"A froward heart shall depart from me: I will not know a wicked person.","words":[["H6141","A froward",0,9],["H3824","heart",10,15],["H5493","shall depart",16,28],["H3045","from me: I will not know",29,53],["H7451","a wicked",54,62]]},"101:5":{"text":"Whoso privily slandereth his neighbour, him will I cut off: him that hath an high look and a proud heart will not I suffer.","words":[["H5643","Whoso privily",0,13],["H3960","slandereth",14,24],["H3960","slandereth",14,24],["H7453","his neighbour",25,38],["H6789","him will I cut off",40,58],["H1362","him that hath an high",60,81],["H5869","look",82,86],["H7342","and a proud",87,98],["H3824","heart",99,104],["H3201","will not I suffer",105,122]]},"101:6":{"text":"Mine eyes shall be upon the faithful of the land, that they may dwell with me: he that walketh in a perfect way, he shall serve me.","words":[["H5869","Mine eyes",0,9],["H0539","shall be upon the faithful",10,36],["H0776","of the land",37,48],["H3427","that they may dwell",50,69],["H1980","with me: he that walketh",70,94],["H8549","in a perfect",95,107],["H1870","way",108,111],["H8334","he shall serve",113,127]]},"101:7":{"text":"He that worketh deceit shall not dwell within my house: he that telleth lies shall not tarry in my sight.","words":[["H6213","He that worketh",0,15],["H7423","deceit",16,22],["H3427","shall not dwell",23,38],["H7130","within",39,45],["H1004","my house",46,54],["H1696","he that telleth",56,71],["H8267","lies",72,76],["H3559","shall not tarry",77,92],["H5869","in my sight",93,104]]},"101:8":{"text":"I will early destroy all the wicked of the land; that I may cut off all wicked doers from the city of the LORD.","words":[["H1242","I will early",0,12],["H6789","destroy",13,20],["H7563","all the wicked",21,35],["H0776","of the land",36,47],["H3772","that I may cut off",49,67],["H0205","all wicked",68,78],["H6466","doers",79,84],["H5892","from the city",85,98],["H3068","of the LORD",99,110]]},"102:1":{"text":"A Prayer of the afflicted, when he is overwhelmed, and poureth out his complaint before the LORD. Hear my prayer, O LORD, and let my cry come unto thee.","words":[["H8605","A Prayer",0,8],["H6041","of the afflicted",9,25],["H5848","when he is overwhelmed",27,49],["H8210","and poureth out",51,66],["H7879","his complaint",67,80],["H6440","before",81,87],["H3068","the LORD",88,96],["H8085","Hear",98,102],["H8605","my prayer",103,112],["H3068","O LORD",114,120],["H7775","and let my cry",122,136],["H0935","come",137,141]]},"102:2":{"text":"Hide not thy face from me in the day when I am in trouble; incline thine ear unto me: in the day when I call answer me speedily.","words":[["H5641","Hide",0,4],["H6440","not thy face",5,17],["H3117","from me in the day",18,36],["H6862","when I am in trouble",37,57],["H5186","incline",59,66],["H0241","thine ear",67,76],["H3117","unto me: in the day",77,96],["H7121","when I call",97,108],["H6030","answer",109,115],["H4118","me speedily",116,127]]},"102:3":{"text":"For my days are consumed like smoke, and my bones are burned as an hearth.","words":[["H3117","For my days",0,11],["H3615","are consumed",12,24],["H6227","like smoke",25,35],["H6106","and my bones",37,49],["H2787","are burned",50,60],["H4168","as an hearth",61,73]]},"102:4":{"text":"My heart is smitten, and withered like grass; so that I forget to eat my bread.","words":[["H3820","My heart",0,8],["H5221","is smitten",9,19],["H3001","and withered",21,33],["H6212","like grass",34,44],["H7911","so that I forget",46,62],["H0398","to eat",63,69],["H3899","my bread",70,78]]},"102:5":{"text":"By reason of the voice of my groaning my bones cleave to my skin.","words":[["H6963","By reason of the voice",0,22],["H0585","of my groaning",23,37],["H6106","my bones",38,46],["H1692","cleave",47,53],["H1320","to my skin",54,64]]},"102:6":{"text":"I am like a pelican of the wilderness: I am like an owl of the desert.","words":[["H1819","I am like",0,9],["H6893","a pelican",10,19],["H4057","of the wilderness",20,37],["H3563","I am like an owl",39,55],["H2723","of the desert",56,69]]},"102:7":{"text":"I watch, and am as a sparrow alone upon the house top.","words":[["H8245","I watch",0,7],["H6833","and am as a sparrow",9,28],["H0909","alone",29,34],["H1406","upon the house top",35,53]]},"102:8":{"text":"Mine enemies reproach me all the day; and they that are mad against me are sworn against me.","words":[["H0341","Mine enemies",0,12],["H2778","reproach",13,21],["H3117","me all the day",22,36],["H1984","and they that are mad",38,59],["H7650","against me are sworn",60,80]]},"102:9":{"text":"For I have eaten ashes like bread, and mingled my drink with weeping,","words":[["H0398","For I have eaten",0,16],["H0665","ashes",17,22],["H3899","like bread",23,33],["H4537","and mingled",35,46],["H8249","my drink",47,55],["H1065","with weeping",56,68]]},"102:10":{"text":"Because of thine indignation and thy wrath: for thou hast lifted me up, and cast me down.","words":[["H6440","Because",0,7],["H2195","of thine indignation",8,28],["H7110","and thy wrath",29,42],["H5375","for thou hast lifted me up",44,70],["H7993","and cast me down",72,88]]},"102:11":{"text":"My days are like a shadow that declineth; and I am withered like grass.","words":[["H3117","My days",0,7],["H6738","are like a shadow",8,25],["H5186","that declineth",26,40],["H3001","and I am withered",42,59],["H6212","like grass",60,70]]},"102:12":{"text":"But thou, O LORD, shalt endure for ever; and thy remembrance unto all generations.","words":[["H3068","But thou, O LORD",0,16],["H3427","shalt endure",18,30],["H5769","for ever",31,39],["H2143","and thy remembrance",41,60],["H1755","unto all",61,69],["H1755","generations",70,81]]},"102:13":{"text":"Thou shalt arise, and have mercy upon Zion: for the time to favour her, yea, the set time, is come.","words":[["H6965","Thou shalt arise",0,16],["H7355","and have mercy",18,32],["H6726","upon Zion",33,42],["H6256","for the time",44,56],["H2603","to favour",57,66],["H4150","her, yea, the set time",67,89],["H0935","is come",91,98]]},"102:14":{"text":"For thy servants take pleasure in her stones, and favour the dust thereof.","words":[["H5650","For thy servants",0,16],["H7521","take pleasure",17,30],["H0068","in her stones",31,44],["H2603","and favour",46,56],["H6083","the dust",57,65]]},"102:15":{"text":"So the heathen shall fear the name of the LORD, and all the kings of the earth thy glory.","words":[["H1471","So the heathen",0,14],["H3372","shall fear",15,25],["H8034","the name",26,34],["H3068","of the LORD",35,46],["H4428","and all the kings",48,65],["H0776","of the earth",66,78],["H3519","thy glory",79,88]]},"102:16":{"text":"When the LORD shall build up Zion, he shall appear in his glory.","words":[["H3068","When the LORD",0,13],["H1129","shall build up",14,28],["H6726","Zion",29,33],["H7200","he shall appear",35,50],["H3519","in his glory",51,63]]},"102:17":{"text":"He will regard the prayer of the destitute, and not despise their prayer.","words":[["H6437","He will regard",0,14],["H8605","the prayer",15,25],["H6199","of the destitute",26,42],["H0959","and not despise",44,59],["H8605","their prayer",60,72]]},"102:18":{"text":"This shall be written for the generation to come: and the people which shall be created shall praise the LORD.","words":[["H3789","This shall be written",0,21],["H1755","for the generation",22,40],["H0314","to come",41,48],["H5971","and the people",50,64],["H1254","which shall be created",65,87],["H1984","shall praise",88,100],["H3050","the LORD",101,109]]},"102:19":{"text":"For he hath looked down from the height of his sanctuary; from heaven did the LORD behold the earth;","words":[["H8259","For he hath looked down",0,23],["H4791","from the height",24,39],["H6944","of his sanctuary",40,56],["H8064","from heaven",58,69],["H3068","did the LORD",70,82],["H5027","behold",83,89],["H0776","the earth",90,99]]},"102:20":{"text":"To hear the groaning of the prisoner; to loose those that are appointed to death;","words":[["H8085","To hear",0,7],["H0603","the groaning",8,20],["H0615","of the prisoner",21,36],["H6605","to loose",38,46],["H1121","those that are appointed",47,71],["H8546","to death",72,80]]},"102:21":{"text":"To declare the name of the LORD in Zion, and his praise in Jerusalem;","words":[["H5608","To declare",0,10],["H8034","the name",11,19],["H3068","of the LORD",20,31],["H6726","in Zion",32,39],["H8416","and his praise",41,55],["H3389","in Jerusalem",56,68]]},"102:22":{"text":"When the people are gathered together, and the kingdoms, to serve the LORD.","words":[["H5971","When the people",0,15],["H6908","are gathered",16,28],["H3162","together",29,37],["H4467","and the kingdoms",39,55],["H5647","to serve",57,65],["H3068","the LORD",66,74]]},"102:23":{"text":"He weakened my strength in the way; he shortened my days.","words":[["H6031","He weakened",0,11],["H3581","my strength",12,23],["H1870","in the way",24,34],["H7114","he shortened",36,48],["H3117","my days",49,56]]},"102:24":{"text":"I said, O my God, take me not away in the midst of my days: thy years are throughout all generations.","words":[["H0559","I said",0,6],["H0410","O my God",8,16],["H5927","take me not away",18,34],["H2677","in the midst",35,47],["H3117","of my days",48,58],["H8141","thy years",60,69],["H1755","are throughout all",70,88],["H1755","generations",89,100]]},"102:25":{"text":"Of old hast thou laid the foundation of the earth: and the heavens are the work of thy hands.","words":[["H6440","Of old",0,6],["H3245","hast thou laid the foundation",7,36],["H0776","of the earth",37,49],["H8064","and the heavens",51,66],["H4639","are the work",67,79],["H3027","of thy hands",80,92]]},"102:26":{"text":"They shall perish, but thou shalt endure: yea, all of them shall wax old like a garment; as a vesture shalt thou change them, and they shall be changed:","words":[["H0006","They shall perish",0,17],["H5975","but thou shalt endure",19,40],["H1086","yea, all of them shall wax old",42,72],["H0899","like a garment",73,87],["H3830","as a vesture",89,101],["H2498","shalt thou change",102,119],["H2498","them, and they shall be changed",120,151]]},"102:27":{"text":"But thou art the same, and thy years shall have no end.","words":[["H8141","But thou art the same, and thy years",0,36],["H8552","shall have no end",37,54]]},"102:28":{"text":"The children of thy servants shall continue, and their seed shall be established before thee.","words":[["H1121","The children",0,12],["H5650","of thy servants",13,28],["H7931","shall continue",29,43],["H2233","and their seed",45,59],["H3559","shall be established",60,80],["H6440","before",81,87]]},"103:1":{"text":"A Psalm of David. Bless the LORD, O my soul: and all that is within me, bless his holy name.","words":[["H1732","A Psalm of David",0,16],["H1288","Bless",18,23],["H3068","the LORD",24,32],["H5315","O my soul",34,43],["H7130","and all that is within",45,67],["H6944","me, bless his holy",68,86],["H8034","name",87,91]]},"103:2":{"text":"Bless the LORD, O my soul, and forget not all his benefits:","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H5315","O my soul",16,25],["H7911","and forget",27,37],["H1576","not all his benefits",38,58]]},"103:3":{"text":"Who forgiveth all thine iniquities; who healeth all thy diseases;","words":[["H5545","Who forgiveth",0,13],["H5771","all thine iniquities",14,34],["H7495","who healeth",36,47],["H8463","all thy diseases",48,64]]},"103:4":{"text":"Who redeemeth thy life from destruction; who crowneth thee with lovingkindness and tender mercies;","words":[["H1350","Who redeemeth",0,13],["H2416","thy life",14,22],["H7845","from destruction",23,39],["H5849","who crowneth",41,53],["H2617","thee with lovingkindness",54,78],["H7356","and tender mercies",79,97]]},"103:5":{"text":"Who satisfieth thy mouth with good things; so that thy youth is renewed like the eagle's.","words":[["H7646","Who satisfieth",0,14],["H5716","thy mouth",15,24],["H2896","with good",25,34],["H5271","things; so that thy youth",35,60],["H2318","is renewed",61,71],["H5404","like the eagle's",72,88]]},"103:6":{"text":"The LORD executeth righteousness and judgment for all that are oppressed.","words":[["H3068","The LORD",0,8],["H6213","executeth",9,18],["H6666","righteousness",19,32],["H4941","and judgment",33,45],["H6231","for all that are oppressed",46,72]]},"103:7":{"text":"He made known his ways unto Moses, his acts unto the children of Israel.","words":[["H3045","He made known",0,13],["H1870","his ways",14,22],["H4872","unto Moses",23,33],["H5949","his acts",35,43],["H1121","unto the children",44,61],["H3478","of Israel",62,71]]},"103:8":{"text":"The LORD is merciful and gracious, slow to anger, and plenteous in mercy.","words":[["H3068","The LORD",0,8],["H7349","is merciful",9,20],["H2587","and gracious",21,33],["H0750","slow",35,39],["H0639","to anger",40,48],["H7227","and plenteous",50,63],["H2617","in mercy",64,72]]},"103:9":{"text":"He will not always chide: neither will he keep his anger for ever.","words":[["H5331","He will not always",0,18],["H7378","chide",19,24],["H5201","neither will he keep",26,46],["H5769","his anger for ever",47,65]]},"103:10":{"text":"He hath not dealt with us after our sins; nor rewarded us according to our iniquities.","words":[["H6213","He hath not dealt",0,17],["H2399","with us after our sins",18,40],["H1580","nor rewarded",42,54],["H5771","us according to our iniquities",55,85]]},"103:11":{"text":"For as the heaven is high above the earth, so great is his mercy toward them that fear him.","words":[["H8064","For as the heaven",0,17],["H1361","is high above",18,31],["H0776","the earth",32,41],["H1396","so great",43,51],["H2617","is his mercy",52,64],["H3373","toward them that fear",65,86]]},"103:12":{"text":"As far as the east is from the west, so far hath he removed our transgressions from us.","words":[["H7368","As far as",0,9],["H4217","the east",10,18],["H4628","is from the west",19,35],["H7368","so far hath he removed",37,59],["H6588","our transgressions",60,78]]},"103:13":{"text":"Like as a father pitieth his children, so the LORD pitieth them that fear him.","words":[["H0001","Like as a father",0,16],["H7355","pitieth",17,24],["H1121","his children",25,37],["H3068","so the LORD",39,50],["H7355","pitieth",51,58],["H3373","them that fear",59,73]]},"103:14":{"text":"For he knoweth our frame; he remembereth that we are dust.","words":[["H3045","For he knoweth",0,14],["H3336","our frame",15,24],["H2142","he remembereth",26,40],["H6083","that we are dust",41,57]]},"103:15":{"text":"As for man, his days are as grass: as a flower of the field, so he flourisheth.","words":[["H0582","As for man",0,10],["H3117","his days",12,20],["H2682","are as grass",21,33],["H6731","as a flower",35,46],["H7704","of the field",47,59],["H6692","so he flourisheth",61,78]]},"103:16":{"text":"For the wind passeth over it, and it is gone; and the place thereof shall know it no more.","words":[["H7307","For the wind",0,12],["H5674","passeth over",13,25],["H4725","it, and it is gone; and the place",26,59],["H5234","thereof shall know",60,78]]},"103:17":{"text":"But the mercy of the LORD is from everlasting to everlasting upon them that fear him, and his righteousness unto children's children;","words":[["H2617","But the mercy",0,13],["H3068","of the LORD",14,25],["H5769","is from everlasting",26,45],["H5704","to",46,48],["H5769","everlasting",49,60],["H3373","upon them that fear",61,80],["H6666","him, and his righteousness",81,107],["H1121","unto children's",108,123],["H1121","children",124,132]]},"103:18":{"text":"To such as keep his covenant, and to those that remember his commandments to do them.","words":[["H8104","To such as keep",0,15],["H1285","his covenant",16,28],["H2142","and to those that remember",30,56],["H6490","his commandments",57,73],["H6213","to do",74,79]]},"103:19":{"text":"The LORD hath prepared his throne in the heavens; and his kingdom ruleth over all.","words":[["H3068","The LORD",0,8],["H3559","hath prepared",9,22],["H3678","his throne",23,33],["H8064","in the heavens",34,48],["H4438","and his kingdom",50,65],["H4910","ruleth",66,72]]},"103:20":{"text":"Bless the LORD, ye his angels, that excel in strength, that do his commandments, hearkening unto the voice of his word.","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H4397","ye his angels",16,29],["H1368","that excel",31,41],["H3581","in strength",42,53],["H6213","that do",55,62],["H1697","his commandments",63,79],["H8085","hearkening",81,91],["H6963","unto the voice",92,106],["H1697","of his word",107,118]]},"103:21":{"text":"Bless ye the LORD, all ye his hosts; ye ministers of his, that do his pleasure.","words":[["H1288","Bless",0,5],["H3068","ye the LORD",6,17],["H6635","all ye his hosts",19,35],["H8334","ye ministers",37,49],["H6213","of his, that do",50,65],["H7522","his pleasure",66,78]]},"103:22":{"text":"Bless the LORD, all his works in all places of his dominion: bless the LORD, O my soul.","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H4639","all his works",16,29],["H4725","in all places",30,43],["H4475","of his dominion",44,59],["H1288","bless",61,66],["H3068","the LORD",67,75],["H5315","O my soul",77,86]]},"104:1":{"text":"Bless the LORD, O my soul. O LORD my God, thou art very great; thou art clothed with honour and majesty.","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H5315","O my soul",16,25],["H3068","O LORD",27,33],["H0430","my God",34,40],["H3966","thou art very",42,55],["H1431","great",56,61],["H3847","thou art clothed",63,79],["H1935","with honour",80,91],["H1926","and majesty",92,103]]},"104:2":{"text":"Who coverest thyself with light as with a garment: who stretchest out the heavens like a curtain:","words":[["H5844","Who coverest",0,12],["H0216","thyself with light",13,31],["H8008","as with a garment",32,49],["H5186","who stretchest out",51,69],["H8064","the heavens",70,81],["H3407","like a curtain",82,96]]},"104:3":{"text":"Who layeth the beams of his chambers in the waters: who maketh the clouds his chariot: who walketh upon the wings of the wind:","words":[["H7136","Who layeth the beams",0,20],["H5944","of his chambers",21,36],["H4325","in the waters",37,50],["H7760","who maketh",52,62],["H5645","the clouds",63,73],["H7398","his chariot",74,85],["H1980","who walketh",87,98],["H3671","upon the wings",99,113],["H7307","of the wind",114,125]]},"104:4":{"text":"Who maketh his angels spirits; his ministers a flaming fire:","words":[["H6213","Who maketh",0,10],["H4397","his angels",11,21],["H7307","spirits",22,29],["H8334","his ministers",31,44],["H3857","a flaming",45,54],["H0784","fire",55,59]]},"104:5":{"text":"Who laid the foundations of the earth, that it should not be removed for ever.","words":[["H3245","Who laid",0,8],["H4349","the foundations",9,24],["H0776","of the earth",25,37],["H4131","that it should not be removed",39,68],["H5769","for ever",69,77],["H5703","for ever",69,77]]},"104:6":{"text":"Thou coveredst it with the deep as with a garment: the waters stood above the mountains.","words":[["H3680","Thou coveredst",0,14],["H8415","it with the deep",15,31],["H3830","as with a garment",32,49],["H4325","the waters",51,61],["H5975","stood",62,67],["H2022","above the mountains",68,87]]},"104:7":{"text":"At thy rebuke they fled; at the voice of thy thunder they hasted away.","words":[["H4480","At",0,2],["H1606","thy rebuke",3,13],["H5127","they fled",14,23],["H6963","at the voice",25,37],["H7482","of thy thunder",38,52],["H2648","they hasted",53,64]]},"104:8":{"text":"They go up by the mountains; they go down by the valleys unto the place which thou hast founded for them.","words":[["H5927","They go up",0,10],["H2022","by the mountains",11,27],["H3381","they go down",29,41],["H1237","by the valleys",42,56],["H4725","unto the place",57,71],["H2088","which",72,77],["H3245","thou hast founded",78,95]]},"104:9":{"text":"Thou hast set a bound that they may not pass over; that they turn not again to cover the earth.","words":[["H7760","Thou hast set",0,13],["H1366","a bound",14,21],["H5674","that they may not pass over",22,49],["H7725","that they turn not again",51,75],["H3680","to cover",76,84],["H0776","the earth",85,94]]},"104:10":{"text":"He sendeth the springs into the valleys, which run among the hills.","words":[["H7971","He sendeth",0,10],["H4599","the springs",11,22],["H5158","into the valleys",23,39],["H1980","which run",41,50],["H2022","among the hills",51,66]]},"104:11":{"text":"They give drink to every beast of the field: the wild asses quench their thirst.","words":[["H8248","They give drink",0,15],["H2416","to every beast",16,30],["H7704","of the field",31,43],["H6501","the wild asses",45,59],["H7665","quench",60,66],["H6772","their thirst",67,79]]},"104:12":{"text":"By them shall the fowls of the heaven have their habitation, which sing among the branches.","words":[["H5775","By them shall the fowls",0,23],["H8064","of the heaven",24,37],["H7931","have their habitation",38,59],["H5414","which sing",61,71],["H6963","which sing",61,71],["H0996","among",72,77],["H6073","the branches",78,90]]},"104:13":{"text":"He watereth the hills from his chambers: the earth is satisfied with the fruit of thy works.","words":[["H8248","He watereth",0,11],["H2022","the hills",12,21],["H5944","from his chambers",22,39],["H0776","the earth",41,50],["H7646","is satisfied",51,63],["H6529","with the fruit",64,78],["H4639","of thy works",79,91]]},"104:14":{"text":"He causeth the grass to grow for the cattle, and herb for the service of man: that he may bring forth food out of the earth;","words":[["H2682","He causeth the grass",0,20],["H6779","to grow",21,28],["H0929","for the cattle",29,43],["H6212","and herb",45,53],["H5656","for the service",54,69],["H0120","of man",70,76],["H3318","that he may bring forth",78,101],["H3899","food",102,106],["H0776","out of the earth",107,123]]},"104:15":{"text":"And wine that maketh glad the heart of man, and oil to make his face to shine, and bread which strengtheneth man's heart.","words":[["H3196","And wine",0,8],["H8055","that maketh glad",9,25],["H3824","the heart",26,35],["H0582","of man",36,42],["H8081","and oil",44,51],["H6440","to make his face",52,68],["H6670","to shine",69,77],["H3899","and bread",79,88],["H5582","which strengtheneth",89,108],["H0582","man's",109,114],["H3824","heart",115,120]]},"104:16":{"text":"The trees of the LORD are full of sap; the cedars of Lebanon, which he hath planted;","words":[["H6086","The trees",0,9],["H3068","of the LORD",10,21],["H7646","are full",22,30],["H0730","of sap; the cedars",31,49],["H3844","of Lebanon",50,60],["H5193","which he hath planted",62,83]]},"104:17":{"text":"Where the birds make their nests: as for the stork, the fir trees are her house.","words":[["H6833","Where the birds",0,15],["H7077","make their nests",16,32],["H2624","as for the stork",34,50],["H1265","the fir trees",52,65],["H1004","are her house",66,79]]},"104:18":{"text":"The high hills are a refuge for the wild goats; and the rocks for the conies.","words":[["H1364","The high",0,8],["H2022","hills",9,14],["H4268","are a refuge",15,27],["H3277","for the wild goats",28,46],["H5553","and the rocks",48,61],["H8227","for the conies",62,76]]},"104:19":{"text":"He appointed the moon for seasons: the sun knoweth his going down.","words":[["H6213","He appointed",0,12],["H3394","the moon",13,21],["H4150","for seasons",22,33],["H8121","the sun",35,42],["H3045","knoweth",43,50],["H3996","his going down",51,65]]},"104:20":{"text":"Thou makest darkness, and it is night: wherein all the beasts of the forest do creep forth.","words":[["H7896","Thou makest",0,11],["H2822","darkness",12,20],["H3915","and it is night",22,37],["H2416","wherein all the beasts",39,61],["H3293","of the forest",62,75],["H7430","do creep",76,84]]},"104:21":{"text":"The young lions roar after their prey, and seek their meat from God.","words":[["H3715","The young lions",0,15],["H7580","roar",16,20],["H2964","after their prey",21,37],["H1245","and seek",39,47],["H0400","their meat",48,58],["H0410","from God",59,67]]},"104:22":{"text":"The sun ariseth, they gather themselves together, and lay them down in their dens.","words":[["H8121","The sun",0,7],["H2224","ariseth",8,15],["H0622","they gather themselves together",17,48],["H7257","and lay them down",50,67],["H4585","in their dens",68,81]]},"104:23":{"text":"Man goeth forth unto his work and to his labour until the evening.","words":[["H0120","Man",0,3],["H3318","goeth forth",4,15],["H6467","unto his work",16,29],["H5656","and to his labour",30,47],["H6153","until the evening",48,65]]},"104:24":{"text":"O LORD, how manifold are thy works! in wisdom hast thou made them all: the earth is full of thy riches.","words":[["H3068","O LORD",0,6],["H7231","how manifold",8,20],["H4639","are thy works",21,34],["H2451","in wisdom",36,45],["H6213","hast thou made",46,60],["H0776","them all: the earth",61,80],["H4390","is full",81,88],["H7075","of thy riches",89,102]]},"104:25":{"text":"So is this great and wide sea, wherein are things creeping innumerable, both small and great beasts.","words":[["H1419","So is this great",0,16],["H7342","and wide",17,25],["H3027","and wide",17,25],["H3220","sea",26,29],["H7431","wherein are things creeping",31,58],["H4557","innumerable",59,70],["H6996","both small",72,82],["H1419","and great",83,92],["H2416","beasts",93,99]]},"104:26":{"text":"There go the ships: there is that leviathan, whom thou hast made to play therein.","words":[["H1980","There go",0,8],["H0591","the ships",9,18],["H3882","there is that leviathan",20,43],["H3335","whom thou hast made",45,64],["H7832","to play",65,72]]},"104:27":{"text":"These wait all upon thee; that thou mayest give them their meat in due season.","words":[["H7663","These wait",0,10],["H5414","all upon thee; that thou mayest give",11,47],["H0400","them their meat",48,63],["H6256","in due season",64,77]]},"104:28":{"text":"That thou givest them they gather: thou openest thine hand, they are filled with good.","words":[["H5414","That thou givest",0,16],["H3950","them they gather",17,33],["H6605","thou openest",35,47],["H3027","thine hand",48,58],["H7646","they are filled",60,75],["H2896","with good",76,85]]},"104:29":{"text":"Thou hidest thy face, they are troubled: thou takest away their breath, they die, and return to their dust.","words":[["H5641","Thou hidest",0,11],["H6440","thy face",12,20],["H0926","they are troubled",22,39],["H0622","thou takest away",41,57],["H7307","their breath",58,70],["H1478","they die",72,80],["H7725","and return",82,92],["H6083","to their dust",93,106]]},"104:30":{"text":"Thou sendest forth thy spirit, they are created: and thou renewest the face of the earth.","words":[["H7971","Thou sendest",0,12],["H7307","forth thy spirit",13,29],["H1254","they are created",31,47],["H2318","and thou renewest",49,66],["H6440","the face",67,75],["H0127","of the earth",76,88]]},"104:31":{"text":"The glory of the LORD shall endure for ever: the LORD shall rejoice in his works.","words":[["H3519","The glory",0,9],["H3068","of the LORD",10,21],["H5769","shall endure for ever",22,43],["H3068","the LORD",45,53],["H8055","shall rejoice",54,67],["H4639","in his works",68,80]]},"104:32":{"text":"He looketh on the earth, and it trembleth: he toucheth the hills, and they smoke.","words":[["H5027","He looketh",0,10],["H0776","on the earth",11,23],["H7460","and it trembleth",25,41],["H5060","he toucheth",43,54],["H2022","the hills",55,64],["H6225","and they smoke",66,80]]},"104:33":{"text":"I will sing unto the LORD as long as I live: I will sing praise to my God while I have my being.","words":[["H7891","I will sing",0,11],["H3068","unto the LORD",12,25],["H2416","as long as I live",26,43],["H2167","I will sing",45,56],["H0430","praise to my God",57,73],["H5750","while I have my being",74,95]]},"104:34":{"text":"My meditation of him shall be sweet: I will be glad in the LORD.","words":[["H7879","My meditation",0,13],["H6149","of him shall be sweet",14,35],["H8055","I will be glad",37,51],["H3068","in the LORD",52,63]]},"104:35":{"text":"Let the sinners be consumed out of the earth, and let the wicked be no more. Bless thou the LORD, O my soul. Praise ye the LORD.","words":[["H2400","Let the sinners",0,15],["H8552","be consumed",16,27],["H0776","out of the earth",28,44],["H7563","and let the wicked",46,64],["H1288","be no more. Bless",65,82],["H3068","thou the LORD",83,96],["H5315","O my soul",98,107],["H1984","Praise",109,115],["H3050","ye the LORD",116,127]]},"105:1":{"text":"O give thanks unto the LORD; call upon his name: make known his deeds among the people.","words":[["H3034","O give thanks",0,13],["H3068","unto the LORD",14,27],["H7121","call",29,33],["H8034","upon his name",34,47],["H3045","make known",49,59],["H5949","his deeds",60,69],["H5971","among the people",70,86]]},"105:2":{"text":"Sing unto him, sing psalms unto him: talk ye of all his wondrous works.","words":[["H7891","Sing",0,4],["H2167","unto him, sing psalms",5,26],["H7878","unto him: talk",27,41],["H6381","ye of all his wondrous works",42,70]]},"105:3":{"text":"Glory ye in his holy name: let the heart of them rejoice that seek the LORD.","words":[["H1984","Glory",0,5],["H6944","ye in his holy",6,20],["H8034","name",21,25],["H3820","let the heart",27,40],["H8055","of them rejoice",41,56],["H1245","that seek",57,66],["H3068","the LORD",67,75]]},"105:4":{"text":"Seek the LORD, and his strength: seek his face evermore.","words":[["H1875","Seek",0,4],["H3068","the LORD",5,13],["H5797","and his strength",15,31],["H1245","seek",33,37],["H6440","his face",38,46],["H8548","evermore",47,55]]},"105:5":{"text":"Remember his marvellous works that he hath done; his wonders, and the judgments of his mouth;","words":[["H2142","Remember",0,8],["H6381","his marvellous works",9,29],["H6213","that he hath done",30,47],["H4159","his wonders",49,60],["H4941","and the judgments",62,79],["H6310","of his mouth",80,92]]},"105:6":{"text":"O ye seed of Abraham his servant, ye children of Jacob his chosen.","words":[["H2233","O ye seed",0,9],["H0085","of Abraham",10,20],["H5650","his servant",21,32],["H1121","ye children",34,45],["H3290","of Jacob",46,54],["H0972","his chosen",55,65]]},"105:7":{"text":"He is the LORD our God: his judgments are in all the earth.","words":[["H3068","He is the LORD",0,14],["H0430","our God",15,22],["H4941","his judgments",24,37],["H0776","are in all the earth",38,58]]},"105:8":{"text":"He hath remembered his covenant for ever, the word which he commanded to a thousand generations.","words":[["H2142","He hath remembered",0,18],["H1285","his covenant",19,31],["H5769","for ever",32,40],["H1697","the word",42,50],["H6680","which he commanded",51,69],["H0505","to a thousand",70,83],["H1755","generations",84,95]]},"105:9":{"text":"Which covenant he made with Abraham, and his oath unto Isaac;","words":[["H3772","Which covenant he made",0,22],["H0085","with Abraham",23,35],["H7621","and his oath",37,49],["H3446","unto Isaac",50,60]]},"105:10":{"text":"And confirmed the same unto Jacob for a law, and to Israel for an everlasting covenant:","words":[["H5975","And confirmed",0,13],["H3290","the same unto Jacob",14,33],["H2706","for a law",34,43],["H3478","and to Israel",45,58],["H5769","for an everlasting",59,77],["H1285","covenant",78,86]]},"105:11":{"text":"Saying, Unto thee will I give the land of Canaan, the lot of your inheritance:","words":[["H0559","Saying",0,6],["H5414","Unto thee will I give",8,29],["H0776","the land",30,38],["H3667","of Canaan",39,48],["H2256","the lot",50,57],["H5159","of your inheritance",58,77]]},"105:12":{"text":"When they were but a few men in number; yea, very few, and strangers in it.","words":[["H4962","When they were but a few men",0,28],["H4557","in number",29,38],["H4592","yea, very few",40,53],["H1481","and strangers",55,68]]},"105:13":{"text":"When they went from one nation to another, from one kingdom to another people;","words":[["H1980","When they went",0,14],["H1471","from one nation",15,30],["H4467","to another, from one kingdom",31,59],["H0312","to another",60,70],["H5971","people",71,77]]},"105:14":{"text":"He suffered no man to do them wrong: yea, he reproved kings for their sakes;","words":[["H3240","He suffered",0,11],["H0120","no man",12,18],["H6231","to do them wrong",19,35],["H3198","yea, he reproved",37,53],["H4428","kings",54,59]]},"105:15":{"text":"Saying, Touch not mine anointed, and do my prophets no harm.","words":[["H5060","Saying, Touch",0,13],["H4899","not mine anointed",14,31],["H5030","and do my prophets",33,51],["H7489","no harm",52,59]]},"105:16":{"text":"Moreover he called for a famine upon the land: he brake the whole staff of bread.","words":[["H7121","Moreover he called",0,18],["H7458","for a famine",19,31],["H0776","upon the land",32,45],["H7665","he brake",47,55],["H4294","the whole staff",56,71],["H3899","of bread",72,80]]},"105:17":{"text":"He sent a man before them, even Joseph, who was sold for a servant:","words":[["H7971","He sent",0,7],["H0376","a man",8,13],["H6440","before",14,20],["H3130","them, even Joseph",21,38],["H4376","who was sold",40,52],["H5650","for a servant",53,66]]},"105:18":{"text":"Whose feet they hurt with fetters: he was laid in iron:","words":[["H7272","Whose feet",0,10],["H6031","they hurt",11,20],["H3525","with fetters",21,33],["H5315","he",35,37],["H0935","was laid",38,46],["H1270","in iron",47,54]]},"105:19":{"text":"Until the time that his word came: the word of the LORD tried him.","words":[["H6256","Until the time",0,14],["H1697","that his word",15,28],["H0935","came",29,33],["H0565","the word",35,43],["H3068","of the LORD",44,55],["H6884","tried",56,61]]},"105:20":{"text":"The king sent and loosed him; even the ruler of the people, and let him go free.","words":[["H4428","The king",0,8],["H7971","sent",9,13],["H5425","and loosed",14,24],["H4910","him; even the ruler",25,44],["H5971","of the people",45,58],["H6605","and let him go free",60,79]]},"105:21":{"text":"He made him lord of his house, and ruler of all his substance:","words":[["H7760","He made",0,7],["H0113","him lord",8,16],["H1004","of his house",17,29],["H4910","and ruler",31,40],["H7075","of all his substance",41,61]]},"105:22":{"text":"To bind his princes at his pleasure; and teach his senators wisdom.","words":[["H0631","To bind",0,7],["H8269","his princes",8,19],["H5315","at his pleasure",20,35],["H2205","and teach his senators",37,59],["H2449","wisdom",60,66]]},"105:23":{"text":"Israel also came into Egypt; and Jacob sojourned in the land of Ham.","words":[["H3478","Israel",0,6],["H0935","also came",7,16],["H4714","into Egypt",17,27],["H3290","and Jacob",29,38],["H1481","sojourned",39,48],["H0776","in the land",49,60],["H2526","of Ham",61,67]]},"105:24":{"text":"And he increased his people greatly; and made them stronger than their enemies.","words":[["H6509","And he increased",0,16],["H5971","his people",17,27],["H3966","greatly",28,35],["H6105","and made them stronger",37,59],["H6862","than their enemies",60,78]]},"105:25":{"text":"He turned their heart to hate his people, to deal subtilly with his servants.","words":[["H2015","He turned",0,9],["H3820","their heart",10,21],["H8130","to hate",22,29],["H5971","his people",30,40],["H5230","to deal subtilly",42,58],["H5650","with his servants",59,76]]},"105:26":{"text":"He sent Moses his servant; and Aaron whom he had chosen.","words":[["H7971","He sent",0,7],["H4872","Moses",8,13],["H5650","his servant",14,25],["H0175","and Aaron",27,36],["H0977","whom he had chosen",37,55]]},"105:27":{"text":"They shewed his signs among them, and wonders in the land of Ham.","words":[["H7760","They shewed",0,11],["H0226","his signs",12,21],["H1697","his signs",12,21],["H4159","among them, and wonders",22,45],["H0776","in the land",46,57],["H2526","of Ham",58,64]]},"105:28":{"text":"He sent darkness, and made it dark; and they rebelled not against his word.","words":[["H7971","He sent",0,7],["H2822","darkness",8,16],["H2821","and made it dark",18,34],["H4784","and they rebelled",36,53],["H1697","not against his word",54,74]]},"105:29":{"text":"He turned their waters into blood, and slew their fish.","words":[["H2015","He turned",0,9],["H4325","their waters",10,22],["H1818","into blood",23,33],["H4191","and slew",35,43],["H1710","their fish",44,54]]},"105:30":{"text":"Their land brought forth frogs in abundance, in the chambers of their kings.","words":[["H0776","Their land",0,10],["H8317","brought forth",11,24],["H6854","frogs",25,30],["H8317","in abundance",31,43],["H2315","in the chambers",45,60],["H4428","of their kings",61,75]]},"105:31":{"text":"He spake, and there came divers sorts of flies, and lice in all their coasts.","words":[["H0559","He spake",0,8],["H0935","and there came",10,24],["H6157","divers sorts of flies",25,46],["H3654","and lice",48,56],["H1366","in all their coasts",57,76]]},"105:32":{"text":"He gave them hail for rain, and flaming fire in their land.","words":[["H5414","He gave",0,7],["H1259","them hail",8,17],["H1653","for rain",18,26],["H3852","and flaming",28,39],["H0784","fire",40,44],["H0776","in their land",45,58]]},"105:33":{"text":"He smote their vines also and their fig trees; and brake the trees of their coasts.","words":[["H5221","He smote",0,8],["H1612","their vines",9,20],["H8384","also and their fig trees",21,45],["H7665","and brake",47,56],["H6086","the trees",57,66],["H1366","of their coasts",67,82]]},"105:34":{"text":"He spake, and the locusts came, and caterpillers, and that without number,","words":[["H0559","He spake",0,8],["H0697","and the locusts",10,25],["H0935","came",26,30],["H3218","and caterpillers",32,48],["H4557","and that without number",50,73]]},"105:35":{"text":"And did eat up all the herbs in their land, and devoured the fruit of their ground.","words":[["H0398","And did eat up",0,14],["H6212","all the herbs",15,28],["H0776","in their land",29,42],["H0398","and devoured",44,56],["H6529","the fruit",57,66],["H0127","of their ground",67,82]]},"105:36":{"text":"He smote also all the firstborn in their land, the chief of all their strength.","words":[["H5221","He smote",0,8],["H1060","also all the firstborn",9,31],["H0776","in their land",32,45],["H7225","the chief",47,56],["H0202","of all their strength",57,78]]},"105:37":{"text":"He brought them forth also with silver and gold: and there was not one feeble person among their tribes.","words":[["H3318","He brought them forth",0,21],["H3701","also with silver",22,38],["H2091","and gold",39,47],["H3782","and there was not one feeble",49,77],["H7626","person among their tribes",78,103]]},"105:38":{"text":"Egypt was glad when they departed: for the fear of them fell upon them.","words":[["H4714","Egypt",0,5],["H8055","was glad",6,14],["H3318","when they departed",15,33],["H6343","for the fear",35,47],["H5307","of them fell",48,60]]},"105:39":{"text":"He spread a cloud for a covering; and fire to give light in the night.","words":[["H6566","He spread",0,9],["H6051","a cloud",10,17],["H4539","for a covering",18,32],["H0784","and fire",34,42],["H0215","to give light",43,56],["H3915","in the night",57,69]]},"105:40":{"text":"The people asked, and he brought quails, and satisfied them with the bread of heaven.","words":[["H7592","The people asked",0,16],["H0935","and he brought",18,32],["H7958","quails",33,39],["H7646","and satisfied",41,54],["H3899","them with the bread",55,74],["H8064","of heaven",75,84]]},"105:41":{"text":"He opened the rock, and the waters gushed out; they ran in the dry places like a river.","words":[["H6605","He opened",0,9],["H6697","the rock",10,18],["H4325","and the waters",20,34],["H2100","gushed out",35,45],["H1980","they ran",47,55],["H6723","in the dry places",56,73],["H5104","like a river",74,86]]},"105:42":{"text":"For he remembered his holy promise, and Abraham his servant.","words":[["H2142","For he remembered",0,17],["H6944","his holy",18,26],["H1697","promise",27,34],["H0085","and Abraham",36,47],["H5650","his servant",48,59]]},"105:43":{"text":"And he brought forth his people with joy, and his chosen with gladness:","words":[["H3318","And he brought forth",0,20],["H5971","his people",21,31],["H8342","with joy",32,40],["H0972","and his chosen",42,56],["H7440","with gladness",57,70]]},"105:44":{"text":"And gave them the lands of the heathen: and they inherited the labour of the people;","words":[["H5414","And gave",0,8],["H0776","them the lands",9,23],["H1471","of the heathen",24,38],["H3423","and they inherited",40,58],["H5999","the labour",59,69],["H3816","of the people",70,83]]},"105:45":{"text":"That they might observe his statutes, and keep his laws. Praise ye the LORD.","words":[["H8104","That they might observe",0,23],["H2706","his statutes",24,36],["H5341","and keep",38,46],["H8451","his laws",47,55],["H1984","Praise",57,63],["H3050","ye the LORD",64,75]]},"106:1":{"text":"Praise ye the LORD. O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H3034","O give thanks",20,33],["H3068","unto the LORD",34,47],["H2896","for he is good",49,63],["H2617","for his mercy",65,78],["H5769","endureth for ever",79,96]]},"106:2":{"text":"Who can utter the mighty acts of the LORD? who can shew forth all his praise?","words":[["H4448","Who can utter",0,13],["H1369","the mighty acts",14,29],["H3068","of the LORD",30,41],["H8085","who can shew forth",43,61],["H8416","all his praise",62,76]]},"106:3":{"text":"Blessed are they that keep judgment, and he that doeth righteousness at all times.","words":[["H0835","Blessed",0,7],["H8104","are they that keep",8,26],["H4941","judgment",27,35],["H6213","and he that doeth",37,54],["H6666","righteousness",55,68],["H6256","at all times",69,81]]},"106:4":{"text":"Remember me, O LORD, with the favour that thou bearest unto thy people: O visit me with thy salvation;","words":[["H2142","Remember",0,8],["H3068","me, O LORD",9,19],["H7522","with the favour",21,36],["H5971","that thou bearest unto thy people",37,70],["H6485","O visit",72,79],["H3444","me with thy salvation",80,101]]},"106:5":{"text":"That I may see the good of thy chosen, that I may rejoice in the gladness of thy nation, that I may glory with thine inheritance.","words":[["H7200","That I may see",0,14],["H2896","the good",15,23],["H0972","of thy chosen",24,37],["H8055","that I may rejoice",39,57],["H8057","in the gladness",58,73],["H1471","of thy nation",74,87],["H1984","that I may glory",89,105],["H5159","with thine inheritance",106,128]]},"106:6":{"text":"We have sinned with our fathers, we have committed iniquity, we have done wickedly.","words":[["H2398","We have sinned",0,14],["H0001","with our fathers",15,31],["H5753","we have committed iniquity",33,59],["H7561","we have done wickedly",61,82]]},"106:7":{"text":"Our fathers understood not thy wonders in Egypt; they remembered not the multitude of thy mercies; but provoked him at the sea, even at the Red sea.","words":[["H0001","Our fathers",0,11],["H7919","understood",12,22],["H6381","not thy wonders",23,38],["H4714","in Egypt",39,47],["H2142","they remembered",49,64],["H7230","not the multitude",65,82],["H2617","of thy mercies",83,97],["H4784","but provoked",99,111],["H3220","him at the sea",112,126],["H5488","even at the Red",128,143],["H3220","sea",144,147]]},"106:8":{"text":"Nevertheless he saved them for his name's sake, that he might make his mighty power to be known.","words":[["H3467","Nevertheless he saved",0,21],["H8034","them for his name's",22,41],["H1369","sake, that he might make his mighty power",42,83],["H3045","to be known",84,95]]},"106:9":{"text":"He rebuked the Red sea also, and it was dried up: so he led them through the depths, as through the wilderness.","words":[["H1605","He rebuked",0,10],["H5488","the Red",11,18],["H3220","sea",19,22],["H2717","also, and it was dried up",23,48],["H3212","so he led",50,59],["H8415","them through the depths",60,83],["H4057","as through the wilderness",85,110]]},"106:10":{"text":"And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy.","words":[["H3467","And he saved",0,12],["H3027","them from the hand",13,31],["H8130","of him that hated",32,49],["H1350","them, and redeemed",50,68],["H3027","them from the hand",69,87],["H0341","of the enemy",88,100]]},"106:11":{"text":"And the waters covered their enemies: there was not one of them left.","words":[["H4325","And the waters",0,14],["H3680","covered",15,22],["H6862","their enemies",23,36],["H0259","there was not one",38,55],["H3498","of them left",56,68]]},"106:12":{"text":"Then believed they his words; they sang his praise.","words":[["H0539","Then believed",0,13],["H1697","they his words",14,28],["H7891","they sang",30,39],["H8416","his praise",40,50]]},"106:13":{"text":"They soon forgat his works; they waited not for his counsel:","words":[["H4116","They soon",0,9],["H7911","forgat",10,16],["H4639","his works",17,26],["H2442","they waited",28,39],["H6098","not for his counsel",40,59]]},"106:14":{"text":"But lusted exceedingly in the wilderness, and tempted God in the desert.","words":[["H0183","But lusted",0,10],["H8378","exceedingly",11,22],["H4057","in the wilderness",23,40],["H5254","and tempted",42,53],["H0410","God",54,57],["H3452","in the desert",58,71]]},"106:15":{"text":"And he gave them their request; but sent leanness into their soul.","words":[["H5414","And he gave",0,11],["H7596","them their request",12,30],["H7971","but sent",32,40],["H7332","leanness",41,49],["H5315","into their soul",50,65]]},"106:16":{"text":"They envied Moses also in the camp, and Aaron the saint of the LORD.","words":[["H7065","They envied",0,11],["H4872","Moses",12,17],["H4264","also in the camp",18,34],["H0175","and Aaron",36,45],["H6918","the saint",46,55],["H3068","of the LORD",56,67]]},"106:17":{"text":"The earth opened and swallowed up Dathan, and covered the company of Abiram.","words":[["H0776","The earth",0,9],["H6605","opened",10,16],["H1104","and swallowed up",17,33],["H1885","Dathan",34,40],["H3680","and covered",42,53],["H5712","the company",54,65],["H0048","of Abiram",66,75]]},"106:18":{"text":"And a fire was kindled in their company; the flame burned up the wicked.","words":[["H0784","And a fire",0,10],["H1197","was kindled",11,22],["H5712","in their company",23,39],["H3852","the flame",41,50],["H3857","burned up",51,60],["H7563","the wicked",61,71]]},"106:19":{"text":"They made a calf in Horeb, and worshipped the molten image.","words":[["H6213","They made",0,9],["H5695","a calf",10,16],["H2722","in Horeb",17,25],["H7812","and worshipped",27,41],["H4541","the molten image",42,58]]},"106:20":{"text":"Thus they changed their glory into the similitude of an ox that eateth grass.","words":[["H4171","Thus they changed",0,17],["H3519","their glory",18,29],["H8403","into the similitude",30,49],["H7794","of an ox",50,58],["H0398","that eateth",59,70],["H6212","grass",71,76]]},"106:21":{"text":"They forgat God their saviour, which had done great things in Egypt;","words":[["H7911","They forgat",0,11],["H0410","God",12,15],["H3467","their saviour",16,29],["H6213","which had done",31,45],["H1419","great things",46,58],["H4714","in Egypt",59,67]]},"106:22":{"text":"Wondrous works in the land of Ham, and terrible things by the Red sea.","words":[["H6381","Wondrous works",0,14],["H0776","in the land",15,26],["H2526","of Ham",27,33],["H3372","and terrible things",35,54],["H5488","by the Red",55,65],["H3220","sea",66,69]]},"106:23":{"text":"Therefore he said that he would destroy them, had not Moses his chosen stood before him in the breach, to turn away his wrath, lest he should destroy them.","words":[["H0559","Therefore he said",0,17],["H8045","that he would destroy",18,39],["H3884","them, had not",40,53],["H4872","Moses",54,59],["H0972","his chosen",60,70],["H5975","stood",71,76],["H6440","before",77,83],["H6556","him in the breach",84,101],["H7725","to turn away",103,115],["H2534","his wrath",116,125],["H7843","lest he should destroy",127,149]]},"106:24":{"text":"Yea, they despised the pleasant land, they believed not his word:","words":[["H3988","Yea, they despised",0,18],["H2532","the pleasant",19,31],["H0776","land",32,36],["H0539","they believed",38,51],["H1697","not his word",52,64]]},"106:25":{"text":"But murmured in their tents, and hearkened not unto the voice of the LORD.","words":[["H7279","But murmured",0,12],["H0168","in their tents",13,27],["H8085","and hearkened",29,42],["H6963","not unto the voice",43,61],["H3068","of the LORD",62,73]]},"106:26":{"text":"Therefore he lifted up his hand against them, to overthrow them in the wilderness:","words":[["H5375","Therefore he lifted up",0,22],["H3027","his hand",23,31],["H5307","against them, to overthrow",32,58],["H4057","them in the wilderness",59,81]]},"106:27":{"text":"To overthrow their seed also among the nations, and to scatter them in the lands.","words":[["H5307","To overthrow",0,12],["H2233","their seed",13,23],["H1471","also among the nations",24,46],["H2219","and to scatter",48,62],["H0776","them in the lands",63,80]]},"106:28":{"text":"They joined themselves also unto Baalpeor, and ate the sacrifices of the dead.","words":[["H6775","They joined",0,11],["H1187","themselves also unto Baalpeor",12,41],["H0398","and ate",43,50],["H2077","the sacrifices",51,65],["H4191","of the dead",66,77]]},"106:29":{"text":"Thus they provoked him to anger with their inventions: and the plague brake in upon them.","words":[["H3707","Thus they provoked him to anger",0,31],["H4611","with their inventions",32,53],["H4046","and the plague",55,69],["H6555","brake in",70,78]]},"106:30":{"text":"Then stood up Phinehas, and executed judgment: and so the plague was stayed.","words":[["H5975","Then stood up",0,13],["H6372","Phinehas",14,22],["H6419","and executed judgment",24,45],["H4046","and so the plague",47,64],["H6113","was stayed",65,75]]},"106:31":{"text":"And that was counted unto him for righteousness unto all generations for evermore.","words":[["H2803","And that was counted",0,20],["H6666","unto him for righteousness",21,47],["H1755","unto all",48,56],["H1755","generations",57,68],["H5704","for",69,72],["H5769","evermore",73,81]]},"106:32":{"text":"They angered him also at the waters of strife, so that it went ill with Moses for their sakes:","words":[["H7107","They angered",0,12],["H4325","him also at the waters",13,35],["H4808","of strife",36,45],["H4809","of strife",36,45],["H3415","so that it went ill",47,66],["H4872","with Moses",67,77]]},"106:33":{"text":"Because they provoked his spirit, so that he spake unadvisedly with his lips.","words":[["H4784","Because they provoked",0,21],["H7307","his spirit",22,32],["H0981","so that he spake unadvisedly",34,62],["H8193","with his lips",63,76]]},"106:34":{"text":"They did not destroy the nations, concerning whom the LORD commanded them:","words":[["H8045","They did not destroy",0,20],["H5971","the nations",21,32],["H3068","concerning whom the LORD",34,58],["H0559","commanded",59,68]]},"106:35":{"text":"But were mingled among the heathen, and learned their works.","words":[["H6148","But were mingled",0,16],["H1471","among the heathen",17,34],["H3925","and learned",36,47],["H4639","their works",48,59]]},"106:36":{"text":"And they served their idols: which were a snare unto them.","words":[["H5647","And they served",0,15],["H6091","their idols",16,27],["H4170","which were a snare",29,47]]},"106:37":{"text":"Yea, they sacrificed their sons and their daughters unto devils,","words":[["H2076","Yea, they sacrificed",0,20],["H1121","their sons",21,31],["H1323","and their daughters",32,51],["H7700","unto devils",52,63]]},"106:38":{"text":"And shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed unto the idols of Canaan: and the land was polluted with blood.","words":[["H8210","And shed",0,8],["H5355","innocent",9,17],["H1818","blood",18,23],["H1818","even the blood",25,39],["H1121","of their sons",40,53],["H1323","and of their daughters",54,76],["H2076","whom they sacrificed",78,98],["H6091","unto the idols",99,113],["H3667","of Canaan",114,123],["H0776","and the land",125,137],["H2610","was polluted",138,150],["H1818","with blood",151,161]]},"106:39":{"text":"Thus were they defiled with their own works, and went a whoring with their own inventions.","words":[["H2930","Thus were they defiled",0,22],["H4639","with their own works",23,43],["H2181","and went a whoring",45,63],["H4611","with their own inventions",64,89]]},"106:40":{"text":"Therefore was the wrath of the LORD kindled against his people, insomuch that he abhorred his own inheritance.","words":[["H0639","Therefore was the wrath",0,23],["H3068","of the LORD",24,35],["H2734","kindled",36,43],["H5971","against his people",44,62],["H8581","insomuch that he abhorred",64,89],["H5159","his own inheritance",90,109]]},"106:41":{"text":"And he gave them into the hand of the heathen; and they that hated them ruled over them.","words":[["H5414","And he gave",0,11],["H3027","them into the hand",12,30],["H1471","of the heathen",31,45],["H8130","and they that hated",47,66],["H4910","them ruled",67,77]]},"106:42":{"text":"Their enemies also oppressed them, and they were brought into subjection under their hand.","words":[["H0341","Their enemies",0,13],["H3905","also oppressed",14,28],["H3665","them, and they were brought into subjection",29,72],["H3027","under their hand",73,89]]},"106:43":{"text":"Many times did he deliver them; but they provoked him with their counsel, and were brought low for their iniquity.","words":[["H7227","Many",0,4],["H6471","times",5,10],["H5337","did he deliver",11,25],["H4784","them; but they provoked",26,49],["H6098","him with their counsel",50,72],["H4355","and were brought low",74,94],["H5771","for their iniquity",95,113]]},"106:44":{"text":"Nevertheless he regarded their affliction, when he heard their cry:","words":[["H7200","Nevertheless he regarded",0,24],["H6862","their affliction",25,41],["H8085","when he heard",43,56],["H7440","their cry",57,66]]},"106:45":{"text":"And he remembered for them his covenant, and repented according to the multitude of his mercies.","words":[["H2142","And he remembered",0,17],["H1285","for them his covenant",18,39],["H5162","and repented",41,53],["H7230","according to the multitude",54,80],["H2617","of his mercies",81,95]]},"106:46":{"text":"He made them also to be pitied of all those that carried them captives.","words":[["H5414","He made",0,7],["H7356","them also to be pitied",8,30],["H6440","of",31,33],["H7617","all those that carried them captives",34,70]]},"106:47":{"text":"Save us, O LORD our God, and gather us from among the heathen, to give thanks unto thy holy name, and to triumph in thy praise.","words":[["H3467","Save",0,4],["H3068","us, O LORD",5,15],["H0430","our God",16,23],["H6908","and gather",25,35],["H1471","us from among the heathen",36,61],["H3034","to give thanks",63,77],["H6944","unto thy holy",78,91],["H8034","name",92,96],["H7623","and to triumph",98,112],["H8416","in thy praise",113,126]]},"106:48":{"text":"Blessed be the LORD God of Israel from everlasting to everlasting: and let all the people say, Amen. Praise ye the LORD.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H0430","God",20,23],["H3478","of Israel",24,33],["H5769","from everlasting",34,50],["H5769","to everlasting",51,65],["H5971","and let all the people",67,89],["H0559","say",90,93],["H0543","Amen",95,99],["H1984","Praise",101,107],["H3050","ye the LORD",108,119]]},"107:1":{"text":"O give thanks unto the LORD, for he is good: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H3068","unto the LORD",14,27],["H2896","for he is good",29,43],["H2617","for his mercy",45,58],["H5769","endureth for ever",59,76]]},"107:2":{"text":"Let the redeemed of the LORD say so, whom he hath redeemed from the hand of the enemy;","words":[["H1350","Let the redeemed",0,16],["H3068","of the LORD",17,28],["H0559","say",29,32],["H1350","so, whom he hath redeemed",33,58],["H3027","from the hand",59,72],["H6862","of the enemy",73,85]]},"107:3":{"text":"And gathered them out of the lands, from the east, and from the west, from the north, and from the south.","words":[["H6908","And gathered",0,12],["H0776","them out of the lands",13,34],["H4217","from the east",36,49],["H4628","and from the west",51,68],["H6828","from the north",70,84],["H3220","and from the south",86,104]]},"107:4":{"text":"They wandered in the wilderness in a solitary way; they found no city to dwell in.","words":[["H8582","They wandered",0,13],["H4057","in the wilderness",14,31],["H3452","in a solitary",32,45],["H1870","way",46,49],["H4672","they found",51,61],["H5892","no city",62,69],["H4186","to dwell",70,78]]},"107:5":{"text":"Hungry and thirsty, their soul fainted in them.","words":[["H7457","Hungry",0,6],["H6771","and thirsty",7,18],["H5315","their soul",20,30],["H5848","fainted",31,38]]},"107:6":{"text":"Then they cried unto the LORD in their trouble, and he delivered them out of their distresses.","words":[["H6817","Then they cried",0,15],["H3068","unto the LORD",16,29],["H6862","in their trouble",30,46],["H5337","and he delivered",48,64],["H4691","them out of their distresses",65,93]]},"107:7":{"text":"And he led them forth by the right way, that they might go to a city of habitation.","words":[["H1869","And he led them forth",0,21],["H3477","by the right",22,34],["H1870","way",35,38],["H3212","that they might go",40,58],["H5892","to a city",59,68],["H4186","of habitation",69,82]]},"107:8":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","words":[["H3034","Oh that men would praise",0,24],["H3068","the LORD",25,33],["H2617","for his goodness",34,50],["H6381","and for his wonderful works",52,79],["H1121","to the children",80,95],["H0120","of men",96,102]]},"107:9":{"text":"For he satisfieth the longing soul, and filleth the hungry soul with goodness.","words":[["H7646","For he satisfieth",0,17],["H8264","the longing",18,29],["H5315","soul",30,34],["H4390","and filleth",36,47],["H7457","the hungry",48,58],["H5315","soul",59,63],["H2896","with goodness",64,77]]},"107:10":{"text":"Such as sit in darkness and in the shadow of death, being bound in affliction and iron;","words":[["H3427","Such as sit",0,11],["H2822","in darkness",12,23],["H6757","and in the shadow of death",24,50],["H0615","being bound",52,63],["H6040","in affliction",64,77],["H1270","and iron",78,86]]},"107:11":{"text":"Because they rebelled against the words of God, and contemned the counsel of the most High:","words":[["H4784","Because they rebelled",0,21],["H0561","against the words",22,39],["H0410","of God",40,46],["H5006","and contemned",48,61],["H6098","the counsel",62,73],["H5945","of the most High",74,90]]},"107:12":{"text":"Therefore he brought down their heart with labour; they fell down, and there was none to help.","words":[["H3665","Therefore he brought down",0,25],["H3820","their heart",26,37],["H5999","with labour",38,49],["H3782","they fell down",51,65],["H5826","and there was none to help",67,93]]},"107:13":{"text":"Then they cried unto the LORD in their trouble, and he saved them out of their distresses.","words":[["H2199","Then they cried",0,15],["H3068","unto the LORD",16,29],["H6862","in their trouble",30,46],["H3467","and he saved",48,60],["H4691","them out of their distresses",61,89]]},"107:14":{"text":"He brought them out of darkness and the shadow of death, and brake their bands in sunder.","words":[["H3318","He brought them out",0,19],["H2822","of darkness",20,31],["H6757","and the shadow of death",32,55],["H5423","and brake",57,66],["H4147","their bands",67,78],["H5423","in sunder",79,88]]},"107:15":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","words":[["H3034","Oh that men would praise",0,24],["H3068","the LORD",25,33],["H2617","for his goodness",34,50],["H6381","and for his wonderful works",52,79],["H1121","to the children",80,95],["H0120","of men",96,102]]},"107:16":{"text":"For he hath broken the gates of brass, and cut the bars of iron in sunder.","words":[["H7665","For he hath broken",0,18],["H1817","the gates",19,28],["H5178","of brass",29,37],["H1438","and cut",39,46],["H1280","the bars",47,55],["H1270","of iron",56,63],["H1438","in sunder",64,73]]},"107:17":{"text":"Fools because of their transgression, and because of their iniquities, are afflicted.","words":[["H0191","Fools",0,5],["H1870","because",6,13],["H6588","of their transgression",14,36],["H5771","and because of their iniquities",38,69],["H6031","are afflicted",71,84]]},"107:18":{"text":"Their soul abhorreth all manner of meat; and they draw near unto the gates of death.","words":[["H5315","Their soul",0,10],["H8581","abhorreth",11,20],["H0400","all manner of meat",21,39],["H5060","and they draw near",41,59],["H8179","unto the gates",60,74],["H4194","of death",75,83]]},"107:19":{"text":"Then they cry unto the LORD in their trouble, and he saveth them out of their distresses.","words":[["H2199","Then they cry",0,13],["H3068","unto the LORD",14,27],["H6862","in their trouble",28,44],["H3467","and he saveth",46,59],["H4691","them out of their distresses",60,88]]},"107:20":{"text":"He sent his word, and healed them, and delivered them from their destructions.","words":[["H7971","He sent",0,7],["H1697","his word",8,16],["H7495","and healed",18,28],["H4422","them, and delivered",29,48],["H7825","them from their destructions",49,77]]},"107:21":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","words":[["H3034","Oh that men would praise",0,24],["H3068","the LORD",25,33],["H2617","for his goodness",34,50],["H6381","and for his wonderful works",52,79],["H1121","to the children",80,95],["H0120","of men",96,102]]},"107:22":{"text":"And let them sacrifice the sacrifices of thanksgiving, and declare his works with rejoicing.","words":[["H2076","And let them sacrifice",0,22],["H2077","the sacrifices",23,37],["H8426","of thanksgiving",38,53],["H5608","and declare",55,66],["H4639","his works",67,76],["H7440","with rejoicing",77,91]]},"107:23":{"text":"They that go down to the sea in ships, that do business in great waters;","words":[["H3381","They that go down",0,17],["H3220","to the sea",18,28],["H0591","in ships",29,37],["H6213","that do",39,46],["H4399","business",47,55],["H7227","in great",56,64],["H4325","waters",65,71]]},"107:24":{"text":"These see the works of the LORD, and his wonders in the deep.","words":[["H7200","These see",0,9],["H4639","the works",10,19],["H3068","of the LORD",20,31],["H6381","and his wonders",33,48],["H4688","in the deep",49,60]]},"107:25":{"text":"For he commandeth, and raiseth the stormy wind, which lifteth up the waves thereof.","words":[["H0559","For he commandeth",0,17],["H5975","and raiseth",19,30],["H5591","the stormy",31,41],["H7307","wind",42,46],["H7311","which lifteth up",48,64],["H1530","the waves",65,74]]},"107:26":{"text":"They mount up to the heaven, they go down again to the depths: their soul is melted because of trouble.","words":[["H5927","They mount up",0,13],["H8064","to the heaven",14,27],["H3381","they go down",29,41],["H8415","again to the depths",42,61],["H5315","their soul",63,73],["H4127","is melted",74,83],["H7451","because of trouble",84,102]]},"107:27":{"text":"They reel to and fro, and stagger like a drunken man, and are at their wits' end.","words":[["H2287","They reel to and fro",0,20],["H5128","and stagger",22,33],["H7910","like a drunken man",34,52],["H2451","and are at their wits'",54,76],["H1104","end",77,80]]},"107:28":{"text":"Then they cry unto the LORD in their trouble, and he bringeth them out of their distresses.","words":[["H6817","Then they cry",0,13],["H3068","unto the LORD",14,27],["H6862","in their trouble",28,44],["H3318","and he bringeth them out",46,70],["H4691","of their distresses",71,90]]},"107:29":{"text":"He maketh the storm a calm, so that the waves thereof are still.","words":[["H6965","He maketh",0,9],["H5591","the storm",10,19],["H1827","a calm",20,26],["H1530","so that the waves",28,45],["H2814","thereof are still",46,63]]},"107:30":{"text":"Then are they glad because they be quiet; so he bringeth them unto their desired haven.","words":[["H8055","Then are they glad",0,18],["H8367","because they be quiet",19,40],["H5148","so he bringeth",42,56],["H2656","them unto their desired",57,80],["H4231","haven",81,86]]},"107:31":{"text":"Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!","words":[["H3034","Oh that men would praise",0,24],["H3068","the LORD",25,33],["H2617","for his goodness",34,50],["H6381","and for his wonderful works",52,79],["H1121","to the children",80,95],["H0120","of men",96,102]]},"107:32":{"text":"Let them exalt him also in the congregation of the people, and praise him in the assembly of the elders.","words":[["H7311","Let them exalt",0,14],["H6951","him also in the congregation",15,43],["H5971","of the people",44,57],["H1984","and praise",59,69],["H4186","him in the assembly",70,89],["H2205","of the elders",90,103]]},"107:33":{"text":"He turneth rivers into a wilderness, and the watersprings into dry ground;","words":[["H7760","He turneth",0,10],["H5104","rivers",11,17],["H4057","into a wilderness",18,35],["H4325","and the watersprings",37,57],["H4161","and the watersprings",37,57],["H6774","into dry ground",58,73]]},"107:34":{"text":"A fruitful land into barrenness, for the wickedness of them that dwell therein.","words":[["H6529","A fruitful",0,10],["H0776","land",11,15],["H4420","into barrenness",16,31],["H7451","for the wickedness",33,51],["H3427","of them that dwell",52,70]]},"107:35":{"text":"He turneth the wilderness into a standing water, and dry ground into watersprings.","words":[["H7760","He turneth",0,10],["H4057","the wilderness",11,25],["H0098","into a standing",26,41],["H4325","water",42,47],["H6723","and dry",49,56],["H0776","ground",57,63],["H4325","into watersprings",64,81],["H4161","into watersprings",64,81]]},"107:36":{"text":"And there he maketh the hungry to dwell, that they may prepare a city for habitation;","words":[["H7457","And there he maketh the hungry",0,30],["H3427","to dwell",31,39],["H3559","that they may prepare",41,62],["H5892","a city",63,69],["H4186","for habitation",70,84]]},"107:37":{"text":"And sow the fields, and plant vineyards, which may yield fruits of increase.","words":[["H2232","And sow",0,7],["H7704","the fields",8,18],["H5193","and plant",20,29],["H3754","vineyards",30,39],["H6213","which may yield",41,56],["H6529","fruits",57,63],["H8393","of increase",64,75]]},"107:38":{"text":"He blesseth them also, so that they are multiplied greatly; and suffereth not their cattle to decrease.","words":[["H1288","He blesseth",0,11],["H7235","them also, so that they are multiplied",12,50],["H3966","greatly",51,58],["H4591","and suffereth",60,73],["H0929","not their cattle",74,90],["H4591","to decrease",91,102]]},"107:39":{"text":"Again, they are minished and brought low through oppression, affliction, and sorrow.","words":[["H4591","Again, they are minished",0,24],["H7817","and brought low",25,40],["H6115","through oppression",41,59],["H7451","affliction",61,71],["H3015","and sorrow",73,83]]},"107:40":{"text":"He poureth contempt upon princes, and causeth them to wander in the wilderness, where there is no way.","words":[["H8210","He poureth",0,10],["H0937","contempt",11,19],["H5081","upon princes",20,32],["H8582","and causeth them to wander",34,60],["H8414","in the wilderness",61,78],["H1870","where there is no way",80,101]]},"107:41":{"text":"Yet setteth he the poor on high from affliction, and maketh him families like a flock.","words":[["H0034","Yet setteth he the poor",0,23],["H7682","on high",24,31],["H6040","from affliction",32,47],["H7760","and maketh",49,59],["H4940","him families",60,72],["H6629","like a flock",73,85]]},"107:42":{"text":"The righteous shall see it, and rejoice: and all iniquity shall stop her mouth.","words":[["H3477","The righteous",0,13],["H7200","shall see",14,23],["H8055","it, and rejoice",24,39],["H5766","and all iniquity",41,57],["H7092","shall stop",58,68],["H6310","her mouth",69,78]]},"107:43":{"text":"Whoso is wise, and will observe these things, even they shall understand the lovingkindness of the LORD.","words":[["H2450","Whoso is wise",0,13],["H8104","and will observe",15,31],["H0995","these things, even they shall understand",32,72],["H2617","the lovingkindness",73,91],["H3068","of the LORD",92,103]]},"108:1":{"text":"A Song or Psalm of David. O God, my heart is fixed; I will sing and give praise, even with my glory.","words":[["H7892","A Song",0,6],["H4210","or Psalm",7,15],["H1732","of David",16,24],["H0430","O God",26,31],["H3820","my heart",33,41],["H3559","is fixed",42,50],["H7891","I will sing",52,63],["H2167","and give praise",64,79],["H3519","even with my glory",81,99]]},"108:2":{"text":"Awake, psaltery and harp: I myself will awake early.","words":[["H5782","Awake",0,5],["H5035","psaltery",7,15],["H3658","and harp",16,24],["H5782","I myself will awake",26,45],["H7837","early",46,51]]},"108:3":{"text":"I will praise thee, O LORD, among the people: and I will sing praises unto thee among the nations.","words":[["H3034","I will praise",0,13],["H3068","thee, O LORD",14,26],["H5971","among the people",28,44],["H2167","and I will sing praises",46,69],["H3816","unto thee among the nations",70,97]]},"108:4":{"text":"For thy mercy is great above the heavens: and thy truth reacheth unto the clouds.","words":[["H2617","For thy mercy",0,13],["H1419","is great",14,22],["H8064","above the heavens",23,40],["H0571","and thy truth",42,55],["H7834","reacheth unto the clouds",56,80]]},"108:5":{"text":"Be thou exalted, O God, above the heavens: and thy glory above all the earth;","words":[["H7311","Be thou exalted",0,15],["H0430","O God",17,22],["H8064","above the heavens",24,41],["H3519","and thy glory",43,56],["H0776","above all the earth",57,76]]},"108:6":{"text":"That thy beloved may be delivered: save with thy right hand, and answer me.","words":[["H3039","That thy beloved",0,16],["H2502","may be delivered",17,33],["H3467","save",35,39],["H3225","with thy right hand",40,59],["H6030","and answer",61,71]]},"108:7":{"text":"God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth.","words":[["H0430","God",0,3],["H1696","hath spoken",4,15],["H6944","in his holiness",16,31],["H5937","I will rejoice",33,47],["H2505","I will divide",49,62],["H7927","Shechem",63,70],["H4058","and mete out",72,84],["H6010","the valley",85,95],["H5523","of Succoth",96,106]]},"108:8":{"text":"Gilead is mine; Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;","words":[["H1568","Gilead",0,6],["H4519","is mine; Manasseh",7,24],["H0669","is mine; Ephraim",25,41],["H4581","also is the strength",42,62],["H7218","of mine head",63,75],["H3063","Judah",77,82],["H2710","is my lawgiver",83,97]]},"108:9":{"text":"Moab is my washpot; over Edom will I cast out my shoe; over Philistia will I triumph.","words":[["H4124","Moab",0,4],["H7366","is my washpot",5,18],["H5518","is my washpot",5,18],["H0123","over Edom",20,29],["H7993","will I cast out",30,45],["H5275","my shoe",46,53],["H6429","over Philistia",55,69],["H7321","will I triumph",70,84]]},"108:10":{"text":"Who will bring me into the strong city? who will lead me into Edom?","words":[["H2986","Who will bring",0,14],["H4013","me into the strong",15,33],["H5892","city",34,38],["H5148","who will lead",40,53],["H0123","me into Edom",54,66]]},"108:11":{"text":"Wilt not thou, O God, who hast cast us off? and wilt not thou, O God, go forth with our hosts?","words":[["H0430","Wilt not thou, O God",0,20],["H2186","who hast cast us off",22,42],["H0430","and wilt not thou, O God",44,68],["H3318","go forth",70,78],["H6635","with our hosts",79,93]]},"108:12":{"text":"Give us help from trouble: for vain is the help of man.","words":[["H3051","Give",0,4],["H5833","us help",5,12],["H6862","from trouble",13,25],["H7723","for vain",27,35],["H8668","is the help",36,47],["H0120","of man",48,54]]},"108:13":{"text":"Through God we shall do valiantly: for he it is that shall tread down our enemies.","words":[["H0430","Through God",0,11],["H6213","we shall do",12,23],["H2428","valiantly",24,33],["H0947","for he it is that shall tread down",35,69],["H6862","our enemies",70,81]]},"109:1":{"text":"To the chief Musician, A Psalm of David. Hold not thy peace, O God of my praise;","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H2790","Hold not thy peace",41,59],["H0430","O God",61,66],["H8416","of my praise",67,79]]},"109:2":{"text":"For the mouth of the wicked and the mouth of the deceitful are opened against me: they have spoken against me with a lying tongue.","words":[["H6310","For the mouth",0,13],["H7563","of the wicked",14,27],["H6310","and the mouth",28,41],["H4820","of the deceitful",42,58],["H6605","are opened",59,69],["H1696","against me: they have spoken",70,98],["H8267","against me with a lying",99,122],["H3956","tongue",123,129]]},"109:3":{"text":"They compassed me about also with words of hatred; and fought against me without a cause.","words":[["H5437","They compassed",0,14],["H1697","me about also with words",15,39],["H8135","of hatred",40,49],["H3898","and fought",51,61],["H2600","against me without a cause",62,88]]},"109:4":{"text":"For my love they are my adversaries: but I give myself unto prayer.","words":[["H0160","For my love",0,11],["H7853","they are my adversaries",12,35],["H8605","but I give myself unto prayer",37,66]]},"109:5":{"text":"And they have rewarded me evil for good, and hatred for my love.","words":[["H7760","And they have rewarded",0,22],["H7451","me evil",23,30],["H2896","for good",31,39],["H8135","and hatred",41,51],["H0160","for my love",52,63]]},"109:6":{"text":"Set thou a wicked man over him: and let Satan stand at his right hand.","words":[["H6485","Set",0,3],["H7563","thou a wicked man",4,21],["H7854","over him: and let Satan",22,45],["H5975","stand",46,51],["H3225","at his right hand",52,69]]},"109:7":{"text":"When he shall be judged, let him be condemned: and let his prayer become sin.","words":[["H8199","When he shall be judged",0,23],["H3318","let him be",25,35],["H7563","condemned",36,45],["H8605","and let his prayer",47,65],["H2401","become sin",66,76]]},"109:8":{"text":"Let his days be few; and let another take his office.","words":[["H3117","Let his days",0,12],["H4592","be few",13,19],["H0312","and let another",21,36],["H3947","take",37,41],["H6486","his office",42,52]]},"109:9":{"text":"Let his children be fatherless, and his wife a widow.","words":[["H1121","Let his children",0,16],["H3490","be fatherless",17,30],["H0802","and his wife",32,44],["H0490","a widow",45,52]]},"109:10":{"text":"Let his children be continually vagabonds, and beg: let them seek their bread also out of their desolate places.","words":[["H1121","Let his children",0,16],["H5128","be continually",17,31],["H5128","vagabonds",32,41],["H7592","and beg",43,50],["H1875","let them seek",52,65],["H2723","their bread also out of their desolate places",66,111]]},"109:11":{"text":"Let the extortioner catch all that he hath; and let the strangers spoil his labour.","words":[["H5383","Let the extortioner",0,19],["H5367","catch",20,25],["H2114","all that he hath; and let the strangers",26,65],["H0962","spoil",66,71],["H3018","his labour",72,82]]},"109:12":{"text":"Let there be none to extend mercy unto him: neither let there be any to favour his fatherless children.","words":[["H4900","Let there be none to extend",0,27],["H2617","mercy",28,33],["H2603","unto him: neither let there be any to favour",34,78],["H3490","his fatherless children",79,102]]},"109:13":{"text":"Let his posterity be cut off; and in the generation following let their name be blotted out.","words":[["H0319","Let his posterity",0,17],["H3772","be cut off",18,28],["H1755","and in the generation",30,51],["H0312","following",52,61],["H8034","let their name",62,76],["H4229","be blotted out",77,91]]},"109:14":{"text":"Let the iniquity of his fathers be remembered with the LORD; and let not the sin of his mother be blotted out.","words":[["H5771","Let the iniquity",0,16],["H0001","of his fathers",17,31],["H2142","be remembered",32,45],["H3068","with the LORD",46,59],["H2403","and let not the sin",61,80],["H0517","of his mother",81,94],["H4229","be blotted out",95,109]]},"109:15":{"text":"Let them be before the LORD continually, that he may cut off the memory of them from the earth.","words":[["H3068","Let them be before the LORD",0,27],["H8548","continually",28,39],["H3772","that he may cut off",41,60],["H2143","the memory",61,71],["H0776","of them from the earth",72,94]]},"109:16":{"text":"Because that he remembered not to shew mercy, but persecuted the poor and needy man, that he might even slay the broken in heart.","words":[["H2142","Because that he remembered",0,26],["H6213","not to shew",27,38],["H2617","mercy",39,44],["H7291","but persecuted",46,60],["H6041","the poor",61,69],["H0034","and needy",70,79],["H0376","man",80,83],["H4191","that he might even slay",85,108],["H3512","the broken",109,119],["H3824","in heart",120,128]]},"109:17":{"text":"As he loved cursing, so let it come unto him: as he delighted not in blessing, so let it be far from him.","words":[["H0157","As he loved",0,11],["H7045","cursing",12,19],["H0935","so let it come",21,35],["H2654","unto him: as he delighted",36,61],["H1293","not in blessing",62,77],["H7368","so let it be far",79,95]]},"109:18":{"text":"As he clothed himself with cursing like as with his garment, so let it come into his bowels like water, and like oil into his bones.","words":[["H3847","As he clothed",0,13],["H7045","himself with cursing",14,34],["H4055","like as with his garment",35,59],["H0935","so let it come",61,75],["H7130","into his bowels",76,91],["H4325","like water",92,102],["H8081","and like oil",104,116],["H6106","into his bones",117,131]]},"109:19":{"text":"Let it be unto him as the garment which covereth him, and for a girdle wherewith he is girded continually.","words":[["H0899","Let it be unto him as the garment",0,33],["H5844","which covereth",34,48],["H4206","him, and for a girdle",49,70],["H2296","wherewith he is girded",71,93],["H8548","continually",94,105]]},"109:20":{"text":"Let this be the reward of mine adversaries from the LORD, and of them that speak evil against my soul.","words":[["H6468","Let this be the reward",0,22],["H7853","of mine adversaries",23,42],["H3068","from the LORD",43,56],["H1696","and of them that speak",58,80],["H7451","evil",81,85],["H5315","against my soul",86,101]]},"109:21":{"text":"But do thou for me, O GOD the Lord, for thy name's sake: because thy mercy is good, deliver thou me.","words":[["H6213","But do",0,6],["H3069","thou for me, O GOD",7,25],["H0136","the Lord",26,34],["H8034","for thy name's",36,50],["H2617","sake: because thy mercy",51,74],["H2896","is good",75,82],["H5337","deliver",84,91]]},"109:22":{"text":"For I am poor and needy, and my heart is wounded within me.","words":[["H6041","For I am poor",0,13],["H0034","and needy",14,23],["H3820","and my heart",25,37],["H2490","is wounded",38,48],["H7130","within",49,55]]},"109:23":{"text":"I am gone like the shadow when it declineth: I am tossed up and down as the locust.","words":[["H1980","I am gone",0,9],["H6738","like the shadow",10,25],["H5186","when it declineth",26,43],["H5287","I am tossed up and down",45,68],["H0697","as the locust",69,82]]},"109:24":{"text":"My knees are weak through fasting; and my flesh faileth of fatness.","words":[["H1290","My knees",0,8],["H3782","are weak",9,17],["H6685","through fasting",18,33],["H1320","and my flesh",35,47],["H3584","faileth",48,55],["H8081","of fatness",56,66]]},"109:25":{"text":"I became also a reproach unto them: when they looked upon me they shaked their heads.","words":[["H2781","I became also a reproach",0,24],["H7200","unto them: when they looked",25,52],["H5128","upon me they shaked",53,72],["H7218","their heads",73,84]]},"109:26":{"text":"Help me, O LORD my God: O save me according to thy mercy:","words":[["H5826","Help",0,4],["H3068","me, O LORD",5,15],["H0430","my God",16,22],["H3467","O save",24,30],["H2617","me according to thy mercy",31,56]]},"109:27":{"text":"That they may know that this is thy hand; that thou, LORD, hast done it.","words":[["H3045","That they may know",0,18],["H3027","that this is thy hand",19,40],["H3068","that thou, LORD",42,57],["H6213","hast done",59,68]]},"109:28":{"text":"Let them curse, but bless thou: when they arise, let them be ashamed; but let thy servant rejoice.","words":[["H7043","Let them curse",0,14],["H1288","but bless",16,25],["H6965","thou: when they arise",26,47],["H0954","let them be ashamed",49,68],["H5650","but let thy servant",70,89],["H8055","rejoice",90,97]]},"109:29":{"text":"Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion, as with a mantle.","words":[["H7853","Let mine adversaries",0,20],["H3847","be clothed",21,31],["H3639","with shame",32,42],["H5844","and let them cover",44,62],["H1322","themselves with their own confusion",63,98],["H4598","as with a mantle",100,116]]},"109:30":{"text":"I will greatly praise the LORD with my mouth; yea, I will praise him among the multitude.","words":[["H3966","I will greatly",0,14],["H3034","praise",15,21],["H3068","the LORD",22,30],["H6310","with my mouth",31,44],["H1984","yea, I will praise",46,64],["H8432","him among",65,74],["H7227","the multitude",75,88]]},"109:31":{"text":"For he shall stand at the right hand of the poor, to save him from those that condemn his soul.","words":[["H5975","For he shall stand",0,18],["H3225","at the right hand",19,36],["H0034","of the poor",37,48],["H3467","to save",50,57],["H8199","him from those that condemn",58,85],["H5315","his soul",86,94]]},"110:1":{"text":"A Psalm of David. The LORD said unto my Lord, Sit thou at my right hand, until I make thine enemies thy footstool.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H3068","The LORD",18,26],["H5002","said",27,31],["H0113","unto my Lord",32,44],["H3427","Sit",46,49],["H3225","thou at my right hand",50,71],["H7896","until I make",73,85],["H0341","thine enemies",86,99],["H1916","thy footstool",100,113],["H7272","thy footstool",100,113]]},"110:2":{"text":"The LORD shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies.","words":[["H3068","The LORD",0,8],["H7971","shall send",9,19],["H4294","the rod",20,27],["H5797","of thy strength",28,43],["H6726","out of Zion",44,55],["H7287","rule",57,61],["H7130","thou in the midst",62,79],["H0341","of thine enemies",80,96]]},"110:3":{"text":"Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning: thou hast the dew of thy youth.","words":[["H5971","Thy people",0,10],["H5071","shall be willing",11,27],["H3117","in the day",28,38],["H2428","of thy power",39,51],["H1926","in the beauties",53,68],["H6944","of holiness",69,80],["H7358","from the womb",81,94],["H4891","of the morning",95,109],["H2919","thou hast the dew",111,128],["H3208","of thy youth",129,141]]},"110:4":{"text":"The LORD hath sworn, and will not repent, Thou art a priest for ever after the order of Melchizedek.","words":[["H3068","The LORD",0,8],["H7650","hath sworn",9,19],["H5162","and will not repent",21,40],["H3548","Thou art a priest",42,59],["H5769","for ever",60,68],["H1700","after the order",69,84],["H4442","of Melchizedek",85,99]]},"110:5":{"text":"The Lord at thy right hand shall strike through kings in the day of his wrath.","words":[["H0136","The Lord",0,8],["H3225","at thy right hand",9,26],["H4272","shall strike",27,39],["H4428","through kings",40,53],["H3117","in the day",54,64],["H0639","of his wrath",65,77]]},"110:6":{"text":"He shall judge among the heathen, he shall fill the places with the dead bodies; he shall wound the heads over many countries.","words":[["H1777","He shall judge",0,14],["H1471","among the heathen",15,32],["H4390","he shall fill",34,47],["H1472","the places with the dead bodies",48,79],["H4272","he shall wound",81,95],["H7218","the heads",96,105],["H7227","over many",106,115],["H0776","countries",116,125]]},"110:7":{"text":"He shall drink of the brook in the way: therefore shall he lift up the head.","words":[["H8354","He shall drink",0,14],["H5158","of the brook",15,27],["H1870","in the way",28,38],["H7311","therefore shall he lift up",40,66],["H7218","the head",67,75]]},"111:1":{"text":"Praise ye the LORD. I will praise the LORD with my whole heart, in the assembly of the upright, and in the congregation.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H3034","I will praise",20,33],["H3068","the LORD",34,42],["H3824","with my whole heart",43,62],["H5475","in the assembly",64,79],["H3477","of the upright",80,94],["H5712","and in the congregation",96,119]]},"111:2":{"text":"The works of the LORD are great, sought out of all them that have pleasure therein.","words":[["H4639","The works",0,9],["H3068","of the LORD",10,21],["H1419","are great",22,31],["H1875","sought out",33,43],["H2656","of all them that have pleasure",44,74]]},"111:3":{"text":"His work is honourable and glorious: and his righteousness endureth for ever.","words":[["H6467","His work",0,8],["H1935","is honourable",9,22],["H1926","and glorious",23,35],["H6666","and his righteousness",37,58],["H5975","endureth",59,67],["H5703","for ever",68,76]]},"111:4":{"text":"He hath made his wonderful works to be remembered: the LORD is gracious and full of compassion.","words":[["H6213","He hath made",0,12],["H6381","his wonderful works",13,32],["H2143","to be remembered",33,49],["H3068","the LORD",51,59],["H2587","is gracious",60,71],["H7349","and full of compassion",72,94]]},"111:5":{"text":"He hath given meat unto them that fear him: he will ever be mindful of his covenant.","words":[["H5414","He hath given",0,13],["H2964","meat",14,18],["H3373","unto them that fear",19,38],["H5769","him: he will ever",39,56],["H2142","be mindful",57,67],["H1285","of his covenant",68,83]]},"111:6":{"text":"He hath shewed his people the power of his works, that he may give them the heritage of the heathen.","words":[["H5046","He hath shewed",0,14],["H5971","his people",15,25],["H3581","the power",26,35],["H4639","of his works",36,48],["H5414","that he may give",50,66],["H5159","them the heritage",67,84],["H1471","of the heathen",85,99]]},"111:7":{"text":"The works of his hands are verity and judgment; all his commandments are sure.","words":[["H4639","The works",0,9],["H3027","of his hands",10,22],["H0571","are verity",23,33],["H4941","and judgment",34,46],["H6490","all his commandments",48,68],["H0539","are sure",69,77]]},"111:8":{"text":"They stand fast for ever and ever, and are done in truth and uprightness.","words":[["H5564","They stand fast",0,15],["H5703","for ever",16,24],["H5769","and ever",25,33],["H6213","and are done",35,47],["H0571","in truth",48,56],["H3477","and uprightness",57,72]]},"111:9":{"text":"He sent redemption unto his people: he hath commanded his covenant for ever: holy and reverend is his name.","words":[["H7971","He sent",0,7],["H6304","redemption",8,18],["H5971","unto his people",19,34],["H6680","he hath commanded",36,53],["H1285","his covenant",54,66],["H5769","for ever",67,75],["H6918","holy",77,81],["H3372","and reverend",82,94],["H8034","is his name",95,106]]},"111:10":{"text":"The fear of the LORD is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever.","words":[["H3374","The fear",0,8],["H3068","of the LORD",9,20],["H7225","is the beginning",21,37],["H2451","of wisdom",38,47],["H2896","a good",49,55],["H7922","understanding",56,69],["H6213","have all they that do",70,91],["H8416","his commandments: his praise",92,120],["H5975","endureth",121,129],["H5703","for ever",130,138]]},"112:1":{"text":"Praise ye the LORD. Blessed is the man that feareth the LORD, that delighteth greatly in his commandments.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H0835","Blessed",20,27],["H0376","is the man",28,38],["H3372","that feareth",39,51],["H3068","the LORD",52,60],["H2654","that delighteth",62,77],["H3966","greatly",78,85],["H4687","in his commandments",86,105]]},"112:2":{"text":"His seed shall be mighty upon earth: the generation of the upright shall be blessed.","words":[["H2233","His seed",0,8],["H1368","shall be mighty",9,24],["H0776","upon earth",25,35],["H1755","the generation",37,51],["H3477","of the upright",52,66],["H1288","shall be blessed",67,83]]},"112:3":{"text":"Wealth and riches shall be in his house: and his righteousness endureth for ever.","words":[["H1952","Wealth",0,6],["H6239","and riches",7,17],["H1004","shall be in his house",18,39],["H6666","and his righteousness",41,62],["H5975","endureth",63,71],["H5703","for ever",72,80]]},"112:4":{"text":"Unto the upright there ariseth light in the darkness: he is gracious, and full of compassion, and righteous.","words":[["H3477","Unto the upright",0,16],["H2224","there ariseth",17,30],["H0216","light",31,36],["H2822","in the darkness",37,52],["H2587","he is gracious",54,68],["H7349","and full of compassion",70,92],["H6662","and righteous",94,107]]},"112:5":{"text":"A good man sheweth favour, and lendeth: he will guide his affairs with discretion.","words":[["H2896","A good",0,6],["H0376","man",7,10],["H2603","sheweth favour",11,25],["H3867","and lendeth",27,38],["H3557","he will guide",40,53],["H1697","his affairs",54,65],["H4941","with discretion",66,81]]},"112:6":{"text":"Surely he shall not be moved for ever: the righteous shall be in everlasting remembrance.","words":[["H4131","Surely he shall not be moved",0,28],["H5769","for ever",29,37],["H6662","the righteous",39,52],["H5769","shall be in everlasting",53,76],["H2143","remembrance",77,88]]},"112:7":{"text":"He shall not be afraid of evil tidings: his heart is fixed, trusting in the LORD.","words":[["H3372","He shall not be afraid",0,22],["H7451","of evil",23,30],["H8052","tidings",31,38],["H3820","his heart",40,49],["H3559","is fixed",50,58],["H0982","trusting",60,68],["H3068","in the LORD",69,80]]},"112:8":{"text":"His heart is established, he shall not be afraid, until he see his desire upon his enemies.","words":[["H3820","His heart",0,9],["H5564","is established",10,24],["H3372","he shall not be afraid",26,48],["H7200","until he see",50,62],["H6862","his desire upon his enemies",63,90]]},"112:9":{"text":"He hath dispersed, he hath given to the poor; his righteousness endureth for ever; his horn shall be exalted with honour.","words":[["H6340","He hath dispersed",0,17],["H5414","he hath given",19,32],["H0034","to the poor",33,44],["H6666","his righteousness",46,63],["H5975","endureth",64,72],["H5703","for ever",73,81],["H7161","his horn",83,91],["H7311","shall be exalted",92,108],["H3519","with honour",109,120]]},"112:10":{"text":"The wicked shall see it, and be grieved; he shall gnash with his teeth, and melt away: the desire of the wicked shall perish.","words":[["H7563","The wicked",0,10],["H7200","shall see",11,20],["H3707","it, and be grieved",21,39],["H2786","he shall gnash",41,55],["H8127","with his teeth",56,70],["H4549","and melt away",72,85],["H8378","the desire",87,97],["H7563","of the wicked",98,111],["H0006","shall perish",112,124]]},"113:1":{"text":"Praise ye the LORD. Praise, O ye servants of the LORD, praise the name of the LORD.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H1984","Praise",20,26],["H5650","O ye servants",28,41],["H3068","of the LORD",42,53],["H1984","praise",55,61],["H8034","the name",62,70],["H3068","of the LORD",71,82]]},"113:2":{"text":"Blessed be the name of the LORD from this time forth and for evermore.","words":[["H1288","Blessed",0,7],["H8034","be the name",8,19],["H3068","of the LORD",20,31],["H6258","from this time forth",32,52],["H5704","and for",53,60],["H5769","evermore",61,69]]},"113:3":{"text":"From the rising of the sun unto the going down of the same the LORD'S name is to be praised.","words":[["H4217","From the rising",0,15],["H8121","of the sun",16,26],["H3996","unto the going down",27,46],["H3068","of the same the LORD'S",47,69],["H8034","name",70,74],["H1984","is to be praised",75,91]]},"113:4":{"text":"The LORD is high above all nations, and his glory above the heavens.","words":[["H3068","The LORD",0,8],["H7311","is high",9,16],["H1471","above all nations",17,34],["H3519","and his glory",36,49],["H8064","above the heavens",50,67]]},"113:5":{"text":"Who is like unto the LORD our God, who dwelleth on high,","words":[["H3068","Who is like unto the LORD",0,25],["H0430","our God",26,33],["H3427","who dwelleth",35,47],["H1361","on high",48,55]]},"113:6":{"text":"Who humbleth himself to behold the things that are in heaven, and in the earth!","words":[["H8213","Who humbleth",0,12],["H7200","himself to behold",13,30],["H8064","the things that are in heaven",31,60],["H0776","and in the earth",62,78]]},"113:7":{"text":"He raiseth up the poor out of the dust, and lifteth the needy out of the dunghill;","words":[["H6965","He raiseth up",0,13],["H1800","the poor",14,22],["H6083","out of the dust",23,38],["H7311","and lifteth",40,51],["H0034","the needy",52,61],["H0830","out of the dunghill",62,81]]},"113:8":{"text":"That he may set him with princes, even with the princes of his people.","words":[["H3427","That he may set",0,15],["H5081","him with princes",16,32],["H5081","even with the princes",34,55],["H5971","of his people",56,69]]},"113:9":{"text":"He maketh the barren woman to keep house, and to be a joyful mother of children. Praise ye the LORD.","words":[["H6135","He maketh the barren woman",0,26],["H3427","to keep",27,34],["H1004","house",35,40],["H8056","and to be a joyful",42,60],["H0517","mother",61,67],["H1121","of children",68,79],["H1984","Praise",81,87],["H3050","ye the LORD",88,99]]},"114:1":{"text":"When Israel went out of Egypt, the house of Jacob from a people of strange language;","words":[["H3478","When Israel",0,11],["H3318","went out",12,20],["H4714","of Egypt",21,29],["H1004","the house",31,40],["H3290","of Jacob",41,49],["H5971","from a people",50,63],["H3937","of strange language",64,83]]},"114:2":{"text":"Judah was his sanctuary, and Israel his dominion.","words":[["H3063","Judah",0,5],["H6944","was his sanctuary",6,23],["H3478","and Israel",25,35],["H4475","his dominion",36,48]]},"114:3":{"text":"The sea saw it, and fled: Jordan was driven back.","words":[["H3220","The sea",0,7],["H7200","saw",8,11],["H5127","it, and fled",12,24],["H3383","Jordan",26,32],["H5437","was driven",33,43],["H0268","back",44,48]]},"114:4":{"text":"The mountains skipped like rams, and the little hills like lambs.","words":[["H2022","The mountains",0,13],["H7540","skipped",14,21],["H0352","like rams",22,31],["H1389","and the little hills",33,53],["H1121","like lambs",54,64],["H6629","like lambs",54,64]]},"114:5":{"text":"What ailed thee, O thou sea, that thou fleddest? thou Jordan, that thou wast driven back?","words":[["H3220","What ailed thee, O thou sea",0,27],["H5127","that thou fleddest",29,47],["H3383","thou Jordan",49,60],["H5437","that thou wast driven",62,83],["H0268","back",84,88]]},"114:6":{"text":"Ye mountains, that ye skipped like rams; and ye little hills, like lambs?","words":[["H2022","Ye mountains",0,12],["H7540","that ye skipped",14,29],["H0352","like rams",30,39],["H1389","and ye little hills",41,60],["H1121","like lambs",62,72],["H6629","like lambs",62,72]]},"114:7":{"text":"Tremble, thou earth, at the presence of the Lord, at the presence of the God of Jacob;","words":[["H2342","Tremble",0,7],["H0776","thou earth",9,19],["H6440","at the presence",21,36],["H0113","of the Lord",37,48],["H6440","at the presence",50,65],["H0433","of the God",66,76],["H3290","of Jacob",77,85]]},"114:8":{"text":"Which turned the rock into a standing water, the flint into a fountain of waters.","words":[["H2015","Which turned",0,12],["H6697","the rock",13,21],["H0098","into a standing",22,37],["H4325","water",38,43],["H2496","the flint",45,54],["H4599","into a fountain",55,70],["H4325","of waters",71,80]]},"115:1":{"text":"Not unto us, O LORD, not unto us, but unto thy name give glory, for thy mercy, and for thy truth's sake.","words":[["H3068","Not unto us, O LORD",0,19],["H8034","not unto us, but unto thy name",21,51],["H5414","give",52,56],["H3519","glory",57,62],["H2617","for thy mercy",64,77],["H0571","and for thy truth's",79,98]]},"115:2":{"text":"Wherefore should the heathen say, Where is now their God?","words":[["H1471","Wherefore should the heathen",0,28],["H0559","say",29,32],["H0430","Where is now their God",34,56]]},"115:3":{"text":"But our God is in the heavens: he hath done whatsoever he hath pleased.","words":[["H0430","But our God",0,11],["H8064","is in the heavens",12,29],["H6213","he hath done",31,43],["H2654","whatsoever he hath pleased",44,70]]},"115:4":{"text":"Their idols are silver and gold, the work of men's hands.","words":[["H6091","Their idols",0,11],["H3701","are silver",12,22],["H2091","and gold",23,31],["H4639","the work",33,41],["H0120","of men's",42,50],["H3027","hands",51,56]]},"115:5":{"text":"They have mouths, but they speak not: eyes have they, but they see not:","words":[["H6310","They have mouths",0,16],["H1696","but they speak",18,32],["H5869","not: eyes",33,42],["H7200","have they, but they see",43,66]]},"115:6":{"text":"They have ears, but they hear not: noses have they, but they smell not:","words":[["H0241","They have ears",0,14],["H8085","but they hear",16,29],["H0639","not: noses",30,40],["H7306","have they, but they smell",41,66]]},"115:7":{"text":"They have hands, but they handle not: feet have they, but they walk not: neither speak they through their throat.","words":[["H3027","They have hands",0,15],["H4184","but they handle",17,32],["H7272","not: feet",33,42],["H1980","have they, but they walk",43,67],["H1897","not: neither speak",68,86],["H1627","they through their throat",87,112]]},"115:8":{"text":"They that make them are like unto them; so is every one that trusteth in them.","words":[["H6213","They that make",0,14],["H0982","them are like unto them; so is every one that trusteth",15,69]]},"115:9":{"text":"O Israel, trust thou in the LORD: he is their help and their shield.","words":[["H3478","O Israel",0,8],["H0982","trust",10,15],["H3068","thou in the LORD",16,32],["H5828","he is their help",34,50],["H4043","and their shield",51,67]]},"115:10":{"text":"O house of Aaron, trust in the LORD: he is their help and their shield.","words":[["H1004","O house",0,7],["H0175","of Aaron",8,16],["H0982","trust",18,23],["H3068","in the LORD",24,35],["H5828","he is their help",37,53],["H4043","and their shield",54,70]]},"115:11":{"text":"Ye that fear the LORD, trust in the LORD: he is their help and their shield.","words":[["H3373","Ye that fear",0,12],["H3068","the LORD",13,21],["H0982","trust",23,28],["H3068","in the LORD",29,40],["H5828","he is their help",42,58],["H4043","and their shield",59,75]]},"115:12":{"text":"The LORD hath been mindful of us: he will bless us; he will bless the house of Israel; he will bless the house of Aaron.","words":[["H3068","The LORD",0,8],["H2142","hath been mindful",9,26],["H1288","of us: he will bless",27,47],["H1288","us; he will bless",48,65],["H1004","the house",66,75],["H3478","of Israel",76,85],["H1288","he will bless",87,100],["H1004","the house",101,110],["H0175","of Aaron",111,119]]},"115:13":{"text":"He will bless them that fear the LORD, both small and great.","words":[["H1288","He will bless",0,13],["H3373","them that fear",14,28],["H3068","the LORD",29,37],["H6996","both small",39,49],["H1419","and great",50,59]]},"115:14":{"text":"The LORD shall increase you more and more, you and your children.","words":[["H3068","The LORD",0,8],["H3254","shall increase",9,23],["H1121","you more and more, you and your children",24,64]]},"115:15":{"text":"Ye are blessed of the LORD which made heaven and earth.","words":[["H1288","Ye are blessed",0,14],["H3068","of the LORD",15,26],["H6213","which made",27,37],["H8064","heaven",38,44],["H0776","and earth",45,54]]},"115:16":{"text":"The heaven, even the heavens, are the LORD'S: but the earth hath he given to the children of men.","words":[["H8064","The heaven",0,10],["H8064","even the heavens",12,28],["H3068","are the LORD'S",30,44],["H0776","but the earth",46,59],["H5414","hath he given",60,73],["H1121","to the children",74,89],["H0120","of men",90,96]]},"115:17":{"text":"The dead praise not the LORD, neither any that go down into silence.","words":[["H4191","The dead",0,8],["H1984","praise",9,15],["H3050","not the LORD",16,28],["H3381","neither any that go down",30,54],["H1745","into silence",55,67]]},"115:18":{"text":"But we will bless the LORD from this time forth and for evermore. Praise the LORD.","words":[["H1288","But we will bless",0,17],["H3050","the LORD",18,26],["H5704","from this time forth and for",27,55],["H5769","evermore",56,64],["H1984","Praise",66,72],["H3050","the LORD",73,81]]},"116:1":{"text":"I love the LORD, because he hath heard my voice and my supplications.","words":[["H0157","I love",0,6],["H3068","the LORD",7,15],["H8085","because he hath heard",17,38],["H6963","my voice",39,47],["H8469","and my supplications",48,68]]},"116:2":{"text":"Because he hath inclined his ear unto me, therefore will I call upon him as long as I live.","words":[["H5186","Because he hath inclined",0,24],["H0241","his ear",25,32],["H7121","unto me, therefore will I call",33,63],["H3117","upon him as long as I live",64,90]]},"116:3":{"text":"The sorrows of death compassed me, and the pains of hell gat hold upon me: I found trouble and sorrow.","words":[["H2256","The sorrows",0,11],["H4194","of death",12,20],["H0661","compassed",21,30],["H4712","me, and the pains",31,48],["H7585","of hell",49,56],["H4672","gat hold",57,65],["H4672","upon me: I found",66,82],["H6869","trouble",83,90],["H3015","and sorrow",91,101]]},"116:4":{"text":"Then called I upon the name of the LORD; O LORD, I beseech thee, deliver my soul.","words":[["H7121","Then called",0,11],["H8034","I upon the name",12,27],["H3068","of the LORD",28,39],["H3068","O LORD",41,47],["H0577","I beseech",49,58],["H4422","thee, deliver",59,72],["H5315","my soul",73,80]]},"116:5":{"text":"Gracious is the LORD, and righteous; yea, our God is merciful.","words":[["H2587","Gracious",0,8],["H3068","is the LORD",9,20],["H6662","and righteous",22,35],["H0430","yea, our God",37,49],["H7355","is merciful",50,61]]},"116:6":{"text":"The LORD preserveth the simple: I was brought low, and he helped me.","words":[["H3068","The LORD",0,8],["H8104","preserveth",9,19],["H6612","the simple",20,30],["H1809","I was brought low",32,49],["H3467","and he helped",51,64]]},"116:7":{"text":"Return unto thy rest, O my soul; for the LORD hath dealt bountifully with thee.","words":[["H7725","Return",0,6],["H4494","unto thy rest",7,20],["H5315","O my soul",22,31],["H3068","for the LORD",33,45],["H1580","hath dealt bountifully",46,68]]},"116:8":{"text":"For thou hast delivered my soul from death, mine eyes from tears, and my feet from falling.","words":[["H2502","For thou hast delivered",0,23],["H5315","my soul",24,31],["H4194","from death",32,42],["H5869","mine eyes",44,53],["H1832","from tears",54,64],["H7272","and my feet",66,77],["H1762","from falling",78,90]]},"116:9":{"text":"I will walk before the LORD in the land of the living.","words":[["H1980","I will walk",0,11],["H6440","before",12,18],["H3068","the LORD",19,27],["H0776","in the land",28,39],["H2416","of the living",40,53]]},"116:10":{"text":"I believed, therefore have I spoken: I was greatly afflicted:","words":[["H0539","I believed",0,10],["H1696","therefore have I spoken",12,35],["H3966","I was greatly",37,50],["H6031","afflicted",51,60]]},"116:11":{"text":"I said in my haste, All men are liars.","words":[["H0559","I said",0,6],["H2648","in my haste",7,18],["H0120","All men",20,27],["H3576","are liars",28,37]]},"116:12":{"text":"What shall I render unto the LORD for all his benefits toward me?","words":[["H7725","What shall I render",0,19],["H3068","unto the LORD",20,33],["H8408","for all his benefits",34,54]]},"116:13":{"text":"I will take the cup of salvation, and call upon the name of the LORD.","words":[["H5375","I will take",0,11],["H3563","the cup",12,19],["H3444","of salvation",20,32],["H7121","and call",34,42],["H8034","upon the name",43,56],["H3068","of the LORD",57,68]]},"116:14":{"text":"I will pay my vows unto the LORD now in the presence of all his people.","words":[["H7999","I will pay",0,10],["H5088","my vows",11,18],["H3068","unto the LORD",19,32],["H5971","now in the presence of all his people",33,70]]},"116:15":{"text":"Precious in the sight of the LORD is the death of his saints.","words":[["H3368","Precious",0,8],["H5869","in the sight",9,21],["H3068","of the LORD",22,33],["H4194","is the death",34,46],["H2623","of his saints",47,60]]},"116:16":{"text":"O LORD, truly I am thy servant; I am thy servant, and the son of thine handmaid: thou hast loosed my bonds.","words":[["H3068","O LORD",0,6],["H0577","truly",8,13],["H5650","I am thy servant",14,30],["H5650","I am thy servant",32,48],["H1121","and the son",50,61],["H0519","of thine handmaid",62,79],["H6605","thou hast loosed",81,97],["H4147","my bonds",98,106]]},"116:17":{"text":"I will offer to thee the sacrifice of thanksgiving, and will call upon the name of the LORD.","words":[["H2076","I will offer",0,12],["H2077","to thee the sacrifice",13,34],["H8426","of thanksgiving",35,50],["H7121","and will call",52,65],["H8034","upon the name",66,79],["H3068","of the LORD",80,91]]},"116:18":{"text":"I will pay my vows unto the LORD now in the presence of all his people,","words":[["H7999","I will pay",0,10],["H5088","my vows",11,18],["H3068","unto the LORD",19,32],["H5971","now in the presence of all his people",33,70]]},"116:19":{"text":"In the courts of the LORD'S house, in the midst of thee, O Jerusalem. Praise ye the LORD.","words":[["H2691","In the courts",0,13],["H3068","of the LORD'S",14,27],["H1004","house",28,33],["H8432","in the midst",35,47],["H3389","of thee, O Jerusalem",48,68],["H1984","Praise",70,76],["H3050","ye the LORD",77,88]]},"117:1":{"text":"O praise the LORD, all ye nations: praise him, all ye people.","words":[["H1984","O praise",0,8],["H3068","the LORD",9,17],["H1471","all ye nations",19,33],["H7623","praise",35,41],["H0523","him, all ye people",42,60]]},"117:2":{"text":"For his merciful kindness is great toward us: and the truth of the LORD endureth for ever. Praise ye the LORD.","words":[["H2617","For his merciful",0,16],["H2617","kindness",17,25],["H1396","is great",26,34],["H0571","toward us: and the truth",35,59],["H3068","of the LORD",60,71],["H5769","endureth for ever",72,89],["H1984","Praise",91,97],["H3050","ye the LORD",98,109]]},"118:1":{"text":"O give thanks unto the LORD; for he is good: because his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H3068","unto the LORD",14,27],["H2896","for he is good",29,43],["H2617","because his mercy",45,62],["H5769","endureth for ever",63,80]]},"118:2":{"text":"Let Israel now say, that his mercy endureth for ever.","words":[["H3478","Let Israel",0,10],["H0559","now say",11,18],["H2617","that his mercy",20,34],["H5769","endureth for ever",35,52]]},"118:3":{"text":"Let the house of Aaron now say, that his mercy endureth for ever.","words":[["H1004","Let the house",0,13],["H0175","of Aaron",14,22],["H0559","now say",23,30],["H2617","that his mercy",32,46],["H5769","endureth for ever",47,64]]},"118:4":{"text":"Let them now that fear the LORD say, that his mercy endureth for ever.","words":[["H3373","Let them now that fear",0,22],["H3068","the LORD",23,31],["H0559","say",32,35],["H2617","that his mercy",37,51],["H5769","endureth for ever",52,69]]},"118:5":{"text":"I called upon the LORD in distress: the LORD answered me, and set me in a large place.","words":[["H7121","I called",0,8],["H3050","upon the LORD",9,22],["H4712","in distress",23,34],["H3050","the LORD",36,44],["H6030","answered",45,53],["H4800","me, and set me in a large place",54,85]]},"118:6":{"text":"The LORD is on my side; I will not fear: what can man do unto me?","words":[["H3068","The LORD",0,8],["H3372","is on my side; I will not fear",9,39],["H6213","what can",41,49],["H0120","man",50,53],["H6213","do",54,56]]},"118:7":{"text":"The LORD taketh my part with them that help me: therefore shall I see my desire upon them that hate me.","words":[["H3068","The LORD",0,8],["H5826","taketh my part with them that help",9,43],["H7200","me: therefore shall I see",44,69],["H8130","my desire upon them that hate",70,99]]},"118:8":{"text":"It is better to trust in the LORD than to put confidence in man.","words":[["H2896","It is better",0,12],["H2620","to trust",13,21],["H3068","in the LORD",22,33],["H0982","than to put confidence",34,56],["H0120","in man",57,63]]},"118:9":{"text":"It is better to trust in the LORD than to put confidence in princes.","words":[["H2896","It is better",0,12],["H2620","to trust",13,21],["H3068","in the LORD",22,33],["H0982","than to put confidence",34,56],["H5081","in princes",57,67]]},"118:10":{"text":"All nations compassed me about: but in the name of the LORD will I destroy them.","words":[["H1471","All nations",0,11],["H5437","compassed me about",12,30],["H8034","but in the name",32,47],["H3068","of the LORD",48,59],["H4135","will I destroy",60,74]]},"118:11":{"text":"They compassed me about; yea, they compassed me about: but in the name of the LORD I will destroy them.","words":[["H5437","They compassed me about",0,23],["H5437","yea, they compassed me about",25,53],["H8034","but in the name",55,70],["H3068","of the LORD",71,82],["H4135","I will destroy",83,97]]},"118:12":{"text":"They compassed me about like bees; they are quenched as the fire of thorns: for in the name of the LORD I will destroy them.","words":[["H5437","They compassed me about",0,23],["H1682","like bees",24,33],["H1846","they are quenched",35,52],["H0784","as the fire",53,64],["H6975","of thorns",65,74],["H8034","for in the name",76,91],["H3068","of the LORD",92,103],["H4135","I will destroy",104,118]]},"118:13":{"text":"Thou hast thrust sore at me that I might fall: but the LORD helped me.","words":[["H1760","Thou hast thrust",0,16],["H1760","sore",17,21],["H5307","at me that I might fall",22,45],["H3068","but the LORD",47,59],["H5826","helped",60,66]]},"118:14":{"text":"The LORD is my strength and song, and is become my salvation.","words":[["H3050","The LORD",0,8],["H5797","is my strength",9,23],["H2176","and song",24,32],["H3444","and is become my salvation",34,60]]},"118:15":{"text":"The voice of rejoicing and salvation is in the tabernacles of the righteous: the right hand of the LORD doeth valiantly.","words":[["H6963","The voice",0,9],["H7440","of rejoicing",10,22],["H3444","and salvation",23,36],["H0168","is in the tabernacles",37,58],["H6662","of the righteous",59,75],["H3225","the right hand",77,91],["H3068","of the LORD",92,103],["H6213","doeth",104,109],["H2428","valiantly",110,119]]},"118:16":{"text":"The right hand of the LORD is exalted: the right hand of the LORD doeth valiantly.","words":[["H3225","The right hand",0,14],["H3068","of the LORD",15,26],["H7426","is exalted",27,37],["H3225","the right hand",39,53],["H3068","of the LORD",54,65],["H6213","doeth",66,71],["H2428","valiantly",72,81]]},"118:17":{"text":"I shall not die, but live, and declare the works of the LORD.","words":[["H4191","I shall not die",0,15],["H2421","but live",17,25],["H5608","and declare",27,38],["H4639","the works",39,48],["H3050","of the LORD",49,60]]},"118:18":{"text":"The LORD hath chastened me sore: but he hath not given me over unto death.","words":[["H3050","The LORD",0,8],["H3256","hath chastened",9,23],["H3256","me sore",24,31],["H5414","but he hath not given me over",33,62],["H4194","unto death",63,73]]},"118:19":{"text":"Open to me the gates of righteousness: I will go into them, and I will praise the LORD:","words":[["H6605","Open",0,4],["H8179","to me the gates",5,20],["H6664","of righteousness",21,37],["H0935","I will go",39,48],["H3034","into them, and I will praise",49,77],["H3050","the LORD",78,86]]},"118:20":{"text":"This gate of the LORD, into which the righteous shall enter.","words":[["H8179","This gate",0,9],["H3068","of the LORD",10,21],["H6662","into which the righteous",23,47],["H0935","shall enter",48,59]]},"118:21":{"text":"I will praise thee: for thou hast heard me, and art become my salvation.","words":[["H3034","I will praise",0,13],["H6030","thee: for thou hast heard",14,39],["H3444","me, and art become my salvation",40,71]]},"118:22":{"text":"The stone which the builders refused is become the head stone of the corner.","words":[["H0068","The stone",0,9],["H1129","which the builders",10,28],["H3988","refused",29,36],["H7218","is become the head",37,55],["H6438","stone of the corner",56,75]]},"118:23":{"text":"This is the LORD'S doing; it is marvellous in our eyes.","words":[["H3068","This is the LORD'S",0,18],["H6381","doing; it is marvellous",19,42],["H5869","in our eyes",43,54]]},"118:24":{"text":"This is the day which the LORD hath made; we will rejoice and be glad in it.","words":[["H3117","This is the day",0,15],["H3068","which the LORD",16,30],["H6213","hath made",31,40],["H1523","we will rejoice",42,57],["H8055","and be glad",58,69]]},"118:25":{"text":"Save now, I beseech thee, O LORD: O LORD, I beseech thee, send now prosperity.","words":[["H3467","Save",0,4],["H0577","now, I beseech",5,19],["H3068","thee, O LORD",20,32],["H3068","O LORD",34,40],["H0577","I beseech",42,51],["H6743","thee, send now prosperity",52,77]]},"118:26":{"text":"Blessed be he that cometh in the name of the LORD: we have blessed you out of the house of the LORD.","words":[["H1288","Blessed",0,7],["H0935","be he that cometh",8,25],["H8034","in the name",26,37],["H3068","of the LORD",38,49],["H1288","we have blessed",51,66],["H1004","you out of the house",67,87],["H3068","of the LORD",88,99]]},"118:27":{"text":"God is the LORD, which hath shewed us light: bind the sacrifice with cords, even unto the horns of the altar.","words":[["H0410","God",0,3],["H3068","is the LORD",4,15],["H0215","which hath shewed us light",17,43],["H0631","bind",45,49],["H2282","the sacrifice",50,63],["H5688","with cords",64,74],["H7161","even unto the horns",76,95],["H4196","of the altar",96,108]]},"118:28":{"text":"Thou art my God, and I will praise thee: thou art my God, I will exalt thee.","words":[["H0410","Thou art my God",0,15],["H3034","and I will praise",17,34],["H0430","thee: thou art my God",35,56],["H7311","I will exalt",58,70]]},"118:29":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H3068","unto the LORD",14,27],["H2896","for he is good",29,43],["H2617","for his mercy",45,58],["H5769","endureth for ever",59,76]]},"119:1":{"text":"ALEPH. Blessed are the undefiled in the way, who walk in the law of the LORD.","words":[["H0835","ALEPH. Blessed",0,14],["H8549","are the undefiled",15,32],["H1870","in the way",33,43],["H1980","who walk",45,53],["H8451","in the law",54,64],["H3068","of the LORD",65,76]]},"119:2":{"text":"Blessed are they that keep his testimonies, and that seek him with the whole heart.","words":[["H0835","Blessed",0,7],["H5341","are they that keep",8,26],["H5713","his testimonies",27,42],["H1875","and that seek",44,57],["H3820","him with the whole heart",58,82]]},"119:3":{"text":"They also do no iniquity: they walk in his ways.","words":[["H6466","They also do",0,12],["H5766","no iniquity",13,24],["H1980","they walk",26,35],["H1870","in his ways",36,47]]},"119:4":{"text":"Thou hast commanded us to keep thy precepts diligently.","words":[["H6680","Thou hast commanded",0,19],["H8104","us to keep",20,30],["H6490","thy precepts",31,43],["H3966","diligently",44,54]]},"119:5":{"text":"O that my ways were directed to keep thy statutes!","words":[["H0305","O that",0,6],["H1870","my ways",7,14],["H3559","were directed",15,28],["H8104","to keep",29,36],["H2706","thy statutes",37,49]]},"119:6":{"text":"Then shall I not be ashamed, when I have respect unto all thy commandments.","words":[["H0954","Then shall I not be ashamed",0,27],["H5027","when I have respect",29,48],["H4687","unto all thy commandments",49,74]]},"119:7":{"text":"I will praise thee with uprightness of heart, when I shall have learned thy righteous judgments.","words":[["H3034","I will praise",0,13],["H3476","thee with uprightness",14,35],["H3824","of heart",36,44],["H3925","when I shall have learned",46,71],["H6664","thy righteous",72,85],["H4941","judgments",86,95]]},"119:8":{"text":"I will keep thy statutes: O forsake me not utterly.","words":[["H8104","I will keep",0,11],["H2706","thy statutes",12,24],["H5800","O forsake",26,35],["H3966","me not utterly",36,50]]},"119:9":{"text":"BETH. Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word.","words":[["H5288","BETH. Wherewithal shall a young man",0,35],["H2135","cleanse",36,43],["H0734","his way",44,51],["H8104","by taking heed",53,67],["H1697","thereto according to thy word",68,97]]},"119:10":{"text":"With my whole heart have I sought thee: O let me not wander from thy commandments.","words":[["H3820","With my whole heart",0,19],["H1875","have I sought",20,33],["H7686","thee: O let me not wander",34,59],["H4687","from thy commandments",60,81]]},"119:11":{"text":"Thy word have I hid in mine heart, that I might not sin against thee.","words":[["H0565","Thy word",0,8],["H6845","have I hid",9,19],["H3820","in mine heart",20,33],["H2398","that I might not sin",35,55]]},"119:12":{"text":"Blessed art thou, O LORD: teach me thy statutes.","words":[["H1288","Blessed",0,7],["H3068","art thou, O LORD",8,24],["H3925","teach",26,31],["H2706","me thy statutes",32,47]]},"119:13":{"text":"With my lips have I declared all the judgments of thy mouth.","words":[["H8193","With my lips",0,12],["H5608","have I declared",13,28],["H4941","all the judgments",29,46],["H6310","of thy mouth",47,59]]},"119:14":{"text":"I have rejoiced in the way of thy testimonies, as much as in all riches.","words":[["H7797","I have rejoiced",0,15],["H1870","in the way",16,26],["H5715","of thy testimonies",27,45],["H5921","as much as in",47,60],["H1952","all riches",61,71]]},"119:15":{"text":"I will meditate in thy precepts, and have respect unto thy ways.","words":[["H7878","I will meditate",0,15],["H6490","in thy precepts",16,31],["H5027","and have respect",33,49],["H0734","unto thy ways",50,63]]},"119:16":{"text":"I will delight myself in thy statutes: I will not forget thy word.","words":[["H8173","I will delight",0,14],["H2708","myself in thy statutes",15,37],["H7911","I will not forget",39,56],["H1697","thy word",57,65]]},"119:17":{"text":"GIMEL. Deal bountifully with thy servant, that I may live, and keep thy word.","words":[["H1580","GIMEL. Deal bountifully",0,23],["H5650","with thy servant",24,40],["H2421","that I may live",42,57],["H8104","and keep",59,67],["H1697","thy word",68,76]]},"119:18":{"text":"Open thou mine eyes, that I may behold wondrous things out of thy law.","words":[["H1540","Open",0,4],["H5869","thou mine eyes",5,19],["H5027","that I may behold",21,38],["H6381","wondrous things",39,54],["H8451","out of thy law",55,69]]},"119:19":{"text":"I am a stranger in the earth: hide not thy commandments from me.","words":[["H1616","I am a stranger",0,15],["H0776","in the earth",16,28],["H5641","hide",30,34],["H4687","not thy commandments",35,55]]},"119:20":{"text":"My soul breaketh for the longing that it hath unto thy judgments at all times.","words":[["H5315","My soul",0,7],["H1638","breaketh",8,16],["H8375","for the longing",17,32],["H4941","that it hath unto thy judgments",33,64],["H6256","at all times",65,77]]},"119:21":{"text":"Thou hast rebuked the proud that are cursed, which do err from thy commandments.","words":[["H1605","Thou hast rebuked",0,17],["H2086","the proud",18,27],["H0779","that are cursed",28,43],["H7686","which do err",45,57],["H4687","from thy commandments",58,79]]},"119:22":{"text":"Remove from me reproach and contempt; for I have kept thy testimonies.","words":[["H1556","Remove",0,6],["H2781","from me reproach",7,23],["H0937","and contempt",24,36],["H5341","for I have kept",38,53],["H5713","thy testimonies",54,69]]},"119:23":{"text":"Princes also did sit and speak against me: but thy servant did meditate in thy statutes.","words":[["H8269","Princes",0,7],["H3427","also did sit",8,20],["H1696","and speak",21,30],["H5650","against me: but thy servant",31,58],["H7878","did meditate",59,71],["H2706","in thy statutes",72,87]]},"119:24":{"text":"Thy testimonies also are my delight and my counsellors.","words":[["H5713","Thy testimonies",0,15],["H8191","also are my delight",16,35],["H0582","and my counsellors",36,54],["H6098","and my counsellors",36,54]]},"119:25":{"text":"DALETH. My soul cleaveth unto the dust: quicken thou me according to thy word.","words":[["H5315","DALETH. My soul",0,15],["H1692","cleaveth",16,24],["H6083","unto the dust",25,38],["H2421","quicken",40,47],["H1697","thou me according to thy word",48,77]]},"119:26":{"text":"I have declared my ways, and thou heardest me: teach me thy statutes.","words":[["H5608","I have declared",0,15],["H1870","my ways",16,23],["H6030","and thou heardest",25,42],["H3925","me: teach",43,52],["H2706","me thy statutes",53,68]]},"119:27":{"text":"Make me to understand the way of thy precepts: so shall I talk of thy wondrous works.","words":[["H0995","Make me to understand",0,21],["H1870","the way",22,29],["H6490","of thy precepts",30,45],["H7878","so shall I talk",47,62],["H6381","of thy wondrous works",63,84]]},"119:28":{"text":"My soul melteth for heaviness: strengthen thou me according unto thy word.","words":[["H5315","My soul",0,7],["H1811","melteth",8,15],["H8424","for heaviness",16,29],["H6965","strengthen",31,41],["H1697","thou me according unto thy word",42,73]]},"119:29":{"text":"Remove from me the way of lying: and grant me thy law graciously.","words":[["H5493","Remove",0,6],["H1870","from me the way",7,22],["H8267","of lying",23,31],["H8451","and grant me thy law",33,53],["H2603","graciously",54,64]]},"119:30":{"text":"I have chosen the way of truth: thy judgments have I laid before me.","words":[["H0977","I have chosen",0,13],["H1870","the way",14,21],["H0530","of truth",22,30],["H4941","thy judgments",32,45],["H7737","have I laid",46,57]]},"119:31":{"text":"I have stuck unto thy testimonies: O LORD, put me not to shame.","words":[["H1692","I have stuck",0,12],["H5715","unto thy testimonies",13,33],["H3068","O LORD",35,41],["H0954","put me not to shame",43,62]]},"119:32":{"text":"I will run the way of thy commandments, when thou shalt enlarge my heart.","words":[["H7323","I will run",0,10],["H1870","the way",11,18],["H4687","of thy commandments",19,38],["H7337","when thou shalt enlarge",40,63],["H3820","my heart",64,72]]},"119:33":{"text":"HE. Teach me, O LORD, the way of thy statutes; and I shall keep it unto the end.","words":[["H3384","HE. Teach",0,9],["H3068","me, O LORD",10,20],["H1870","the way",22,29],["H2706","of thy statutes",30,45],["H5341","and I shall keep",47,63],["H6118","it unto the end",64,79]]},"119:34":{"text":"Give me understanding, and I shall keep thy law; yea, I shall observe it with my whole heart.","words":[["H0995","Give me understanding",0,21],["H5341","and I shall keep",23,39],["H8451","thy law",40,47],["H8104","yea, I shall observe",49,69],["H3820","it with my whole heart",70,92]]},"119:35":{"text":"Make me to go in the path of thy commandments; for therein do I delight.","words":[["H1869","Make me to go",0,13],["H5410","in the path",14,25],["H4687","of thy commandments",26,45],["H2654","for therein do I delight",47,71]]},"119:36":{"text":"Incline my heart unto thy testimonies, and not to covetousness.","words":[["H5186","Incline",0,7],["H3820","my heart",8,16],["H5715","unto thy testimonies",17,37],["H1215","and not to covetousness",39,62]]},"119:37":{"text":"Turn away mine eyes from beholding vanity; and quicken thou me in thy way.","words":[["H5674","Turn away",0,9],["H5869","mine eyes",10,19],["H7200","from beholding",20,34],["H7723","vanity",35,41],["H2421","and quicken",43,54],["H1870","thou me in thy way",55,73]]},"119:38":{"text":"Stablish thy word unto thy servant, who is devoted to thy fear.","words":[["H6965","Stablish",0,8],["H0565","thy word",9,17],["H5650","unto thy servant",18,34],["H3374","who is devoted to thy fear",36,62]]},"119:39":{"text":"Turn away my reproach which I fear: for thy judgments are good.","words":[["H5674","Turn away",0,9],["H2781","my reproach",10,21],["H3025","which I fear",22,34],["H4941","for thy judgments",36,53],["H2896","are good",54,62]]},"119:40":{"text":"Behold, I have longed after thy precepts: quicken me in thy righteousness.","words":[["H8373","Behold, I have longed",0,21],["H6490","after thy precepts",22,40],["H2421","quicken",42,49],["H6666","me in thy righteousness",50,73]]},"119:41":{"text":"VAU. Let thy mercies come also unto me, O LORD, even thy salvation, according to thy word.","words":[["H2617","VAU. Let thy mercies",0,20],["H0935","come",21,25],["H3068","also unto me, O LORD",26,46],["H8668","even thy salvation",48,66],["H0565","according to thy word",68,89]]},"119:42":{"text":"So shall I have wherewith to answer him that reproacheth me: for I trust in thy word.","words":[["H1697","So shall I have wherewith",0,25],["H6030","to answer",26,35],["H2778","him that reproacheth",36,56],["H0982","me: for I trust",57,72],["H1697","in thy word",73,84]]},"119:43":{"text":"And take not the word of truth utterly out of my mouth; for I have hoped in thy judgments.","words":[["H5337","And take",0,8],["H1697","not the word",9,21],["H0571","of truth",22,30],["H3966","utterly",31,38],["H6310","out of my mouth",39,54],["H3176","for I have hoped",56,72],["H4941","in thy judgments",73,89]]},"119:44":{"text":"So shall I keep thy law continually for ever and ever.","words":[["H8104","So shall I keep",0,15],["H8451","thy law",16,23],["H8548","continually",24,35],["H5769","for ever",36,44],["H5703","and ever",45,53]]},"119:45":{"text":"And I will walk at liberty: for I seek thy precepts.","words":[["H1980","And I will walk",0,15],["H7342","at liberty",16,26],["H1875","for I seek",28,38],["H6490","thy precepts",39,51]]},"119:46":{"text":"I will speak of thy testimonies also before kings, and will not be ashamed.","words":[["H1696","I will speak",0,12],["H5713","of thy testimonies",13,31],["H4428","also before kings",32,49],["H0954","and will not be ashamed",51,74]]},"119:47":{"text":"And I will delight myself in thy commandments, which I have loved.","words":[["H8173","And I will delight",0,18],["H4687","myself in thy commandments",19,45],["H0157","which I have loved",47,65]]},"119:48":{"text":"My hands also will I lift up unto thy commandments, which I have loved; and I will meditate in thy statutes.","words":[["H3709","My hands",0,8],["H5375","also will I lift up",9,28],["H4687","unto thy commandments",29,50],["H0157","which I have loved",52,70],["H7878","and I will meditate",72,91],["H2706","in thy statutes",92,107]]},"119:49":{"text":"ZAIN. Remember the word unto thy servant, upon which thou hast caused me to hope.","words":[["H2142","ZAIN. Remember",0,14],["H1697","the word",15,23],["H5650","unto thy servant",24,40],["H3176","upon which thou hast caused me to hope",42,80]]},"119:50":{"text":"This is my comfort in my affliction: for thy word hath quickened me.","words":[["H5165","This is my comfort",0,18],["H6040","in my affliction",19,35],["H0565","for thy word",37,49],["H2421","hath quickened",50,64]]},"119:51":{"text":"The proud have had me greatly in derision: yet have I not declined from thy law.","words":[["H2086","The proud",0,9],["H3966","have had me greatly",10,29],["H3887","in derision",30,41],["H5186","yet have I not declined",43,66],["H8451","from thy law",67,79]]},"119:52":{"text":"I remembered thy judgments of old, O LORD; and have comforted myself.","words":[["H2142","I remembered",0,12],["H4941","thy judgments",13,26],["H5769","of old",27,33],["H3068","O LORD",35,41],["H5162","and have comforted",43,61]]},"119:53":{"text":"Horror hath taken hold upon me because of the wicked that forsake thy law.","words":[["H2152","Horror",0,6],["H0270","hath taken hold",7,22],["H7563","upon me because of the wicked",23,52],["H5800","that forsake",53,65],["H8451","thy law",66,73]]},"119:54":{"text":"Thy statutes have been my songs in the house of my pilgrimage.","words":[["H2706","Thy statutes",0,12],["H2158","have been my songs",13,31],["H1004","in the house",32,44],["H4033","of my pilgrimage",45,61]]},"119:55":{"text":"I have remembered thy name, O LORD, in the night, and have kept thy law.","words":[["H2142","I have remembered",0,17],["H8034","thy name",18,26],["H3068","O LORD",28,34],["H3915","in the night",36,48],["H8104","and have kept",50,63],["H8451","thy law",64,71]]},"119:56":{"text":"This I had, because I kept thy precepts.","words":[["H5341","This I had, because I kept",0,26],["H6490","thy precepts",27,39]]},"119:57":{"text":"CHETH. Thou art my portion, O LORD: I have said that I would keep thy words.","words":[["H2506","CHETH. Thou art my portion",0,26],["H3068","O LORD",28,34],["H0559","I have said",36,47],["H8104","that I would keep",48,65],["H1697","thy words",66,75]]},"119:58":{"text":"I intreated thy favour with my whole heart: be merciful unto me according to thy word.","words":[["H2470","I intreated",0,11],["H6440","thy favour",12,22],["H3820","with my whole heart",23,42],["H2603","be merciful",44,55],["H0565","unto me according to thy word",56,85]]},"119:59":{"text":"I thought on my ways, and turned my feet unto thy testimonies.","words":[["H2803","I thought",0,9],["H1870","on my ways",10,20],["H7725","and turned",22,32],["H7272","my feet",33,40],["H5713","unto thy testimonies",41,61]]},"119:60":{"text":"I made haste, and delayed not to keep thy commandments.","words":[["H2363","I made haste",0,12],["H4102","and delayed",14,25],["H8104","not to keep",26,37],["H4687","thy commandments",38,54]]},"119:61":{"text":"The bands of the wicked have robbed me: but I have not forgotten thy law.","words":[["H2256","The bands",0,9],["H7563","of the wicked",10,23],["H5749","have robbed",24,35],["H7911","me: but I have not forgotten",36,64],["H8451","thy law",65,72]]},"119:62":{"text":"At midnight I will rise to give thanks unto thee because of thy righteous judgments.","words":[["H2676","At midnight",0,11],["H3915","At midnight",0,11],["H6965","I will rise",12,23],["H3034","to give thanks",24,38],["H6664","unto thee because of thy righteous",39,73],["H4941","judgments",74,83]]},"119:63":{"text":"I am a companion of all them that fear thee, and of them that keep thy precepts.","words":[["H2270","I am a companion",0,16],["H3372","of all them that fear",17,38],["H8104","thee, and of them that keep",39,66],["H6490","thy precepts",67,79]]},"119:64":{"text":"The earth, O LORD, is full of thy mercy: teach me thy statutes.","words":[["H0776","The earth",0,9],["H3068","O LORD",11,17],["H4390","is full",19,26],["H2617","of thy mercy",27,39],["H3925","teach",41,46],["H2706","me thy statutes",47,62]]},"119:65":{"text":"TETH. Thou hast dealt well with thy servant, O LORD, according unto thy word.","words":[["H6213","TETH. Thou hast dealt",0,21],["H2896","well",22,26],["H5650","with thy servant",27,43],["H3068","O LORD",45,51],["H1697","according unto thy word",53,76]]},"119:66":{"text":"Teach me good judgment and knowledge: for I have believed thy commandments.","words":[["H3925","Teach",0,5],["H2898","me good",6,13],["H2940","judgment",14,22],["H1847","and knowledge",23,36],["H0539","for I have believed",38,57],["H4687","thy commandments",58,74]]},"119:67":{"text":"Before I was afflicted I went astray: but now have I kept thy word.","words":[["H6031","Before I was afflicted",0,22],["H7683","I went astray",23,36],["H8104","but now have I kept",38,57],["H0565","thy word",58,66]]},"119:68":{"text":"Thou art good, and doest good; teach me thy statutes.","words":[["H2896","Thou art good",0,13],["H2895","and doest good",15,29],["H3925","teach",31,36],["H2706","me thy statutes",37,52]]},"119:69":{"text":"The proud have forged a lie against me: but I will keep thy precepts with my whole heart.","words":[["H2086","The proud",0,9],["H2950","have forged",10,21],["H8267","a lie",22,27],["H5341","against me: but I will keep",28,55],["H6490","thy precepts",56,68],["H3820","with my whole heart",69,88]]},"119:70":{"text":"Their heart is as fat as grease; but I delight in thy law.","words":[["H3820","Their heart",0,11],["H2954","is as fat",12,21],["H2459","as grease",22,31],["H8173","but I delight",33,46],["H8451","in thy law",47,57]]},"119:71":{"text":"It is good for me that I have been afflicted; that I might learn thy statutes.","words":[["H2896","It is good",0,10],["H6031","for me that I have been afflicted",11,44],["H3925","that I might learn",46,64],["H2706","thy statutes",65,77]]},"119:72":{"text":"The law of thy mouth is better unto me than thousands of gold and silver.","words":[["H8451","The law",0,7],["H6310","of thy mouth",8,20],["H2896","is better",21,30],["H0505","unto me than thousands",31,53],["H2091","of gold",54,61],["H3701","and silver",62,72]]},"119:73":{"text":"JOD. Thy hands have made me and fashioned me: give me understanding, that I may learn thy commandments.","words":[["H3027","JOD. Thy hands",0,14],["H6213","have made",15,24],["H3559","me and fashioned",25,41],["H0995","me: give me understanding",42,67],["H3925","that I may learn",69,85],["H4687","thy commandments",86,102]]},"119:74":{"text":"They that fear thee will be glad when they see me; because I have hoped in thy word.","words":[["H3373","They that fear",0,14],["H8055","thee will be glad",15,32],["H7200","when they see",33,46],["H3176","me; because I have hoped",47,71],["H1697","in thy word",72,83]]},"119:75":{"text":"I know, O LORD, that thy judgments are right, and that thou in faithfulness hast afflicted me.","words":[["H3045","I know",0,6],["H3068","O LORD",8,14],["H4941","that thy judgments",16,34],["H6664","are right",35,44],["H0530","and that thou in faithfulness",46,75],["H6031","hast afflicted",76,90]]},"119:76":{"text":"Let, I pray thee, thy merciful kindness be for my comfort, according to thy word unto thy servant.","words":[["H2617","Let, I pray thee, thy merciful kindness",0,39],["H5162","be for my comfort",40,57],["H0565","according to thy word",59,80],["H5650","unto thy servant",81,97]]},"119:77":{"text":"Let thy tender mercies come unto me, that I may live: for thy law is my delight.","words":[["H7356","Let thy tender mercies",0,22],["H0935","come",23,27],["H2421","unto me, that I may live",28,52],["H8451","for thy law",54,65],["H8191","is my delight",66,79]]},"119:78":{"text":"Let the proud be ashamed; for they dealt perversely with me without a cause: but I will meditate in thy precepts.","words":[["H2086","Let the proud",0,13],["H0954","be ashamed",14,24],["H5791","for they dealt perversely",26,51],["H8267","with me without a cause",52,75],["H7878","but I will meditate",77,96],["H6490","in thy precepts",97,112]]},"119:79":{"text":"Let those that fear thee turn unto me, and those that have known thy testimonies.","words":[["H3373","Let those that fear",0,19],["H7725","thee turn",20,29],["H3045","unto me, and those that have known",30,64],["H3045","unto me, and those that have known",30,64],["H5713","thy testimonies",65,80]]},"119:80":{"text":"Let my heart be sound in thy statutes; that I be not ashamed.","words":[["H3820","Let my heart",0,12],["H8549","be sound",13,21],["H2706","in thy statutes",22,37],["H0954","that I be not ashamed",39,60]]},"119:81":{"text":"CAPH. My soul fainteth for thy salvation: but I hope in thy word.","words":[["H5315","CAPH. My soul",0,13],["H3615","fainteth",14,22],["H8668","for thy salvation",23,40],["H3176","but I hope",42,52],["H1697","in thy word",53,64]]},"119:82":{"text":"Mine eyes fail for thy word, saying, When wilt thou comfort me?","words":[["H5869","Mine eyes",0,9],["H3615","fail",10,14],["H0565","for thy word",15,27],["H0559","saying",29,35],["H5162","When wilt thou comfort",37,59]]},"119:83":{"text":"For I am become like a bottle in the smoke; yet do I not forget thy statutes.","words":[["H4997","For I am become like a bottle",0,29],["H7008","in the smoke",30,42],["H7911","yet do I not forget",44,63],["H2706","thy statutes",64,76]]},"119:84":{"text":"How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?","words":[["H3117","How many are the days",0,21],["H5650","of thy servant",22,36],["H6213","when wilt thou execute",38,60],["H4941","judgment",61,69],["H7291","on them that persecute",70,92]]},"119:85":{"text":"The proud have digged pits for me, which are not after thy law.","words":[["H2086","The proud",0,9],["H3738","have digged",10,21],["H7882","pits",22,26],["H8451","for me, which are not after thy law",27,62]]},"119:86":{"text":"All thy commandments are faithful: they persecute me wrongfully; help thou me.","words":[["H4687","All thy commandments",0,20],["H0530","are faithful",21,33],["H7291","they persecute",35,49],["H8267","me wrongfully",50,63],["H5826","help",65,69]]},"119:87":{"text":"They had almost consumed me upon earth; but I forsook not thy precepts.","words":[["H4592","They had almost",0,15],["H3615","consumed",16,24],["H0776","me upon earth",25,38],["H5800","but I forsook",40,53],["H6490","not thy precepts",54,70]]},"119:88":{"text":"Quicken me after thy lovingkindness; so shall I keep the testimony of thy mouth.","words":[["H2421","Quicken",0,7],["H2617","me after thy lovingkindness",8,35],["H8104","so shall I keep",37,52],["H5715","the testimony",53,66],["H6310","of thy mouth",67,79]]},"119:89":{"text":"LAMED. For ever, O LORD, thy word is settled in heaven.","words":[["H5769","LAMED. For ever",0,15],["H3068","O LORD",17,23],["H1697","thy word",25,33],["H5324","is settled",34,44],["H8064","in heaven",45,54]]},"119:90":{"text":"Thy faithfulness is unto all generations: thou hast established the earth, and it abideth.","words":[["H0530","Thy faithfulness",0,16],["H1755","is unto all",17,28],["H1755","generations",29,40],["H3559","thou hast established",42,63],["H0776","the earth",64,73],["H5975","and it abideth",75,89]]},"119:91":{"text":"They continue this day according to thine ordinances: for all are thy servants.","words":[["H5975","They continue",0,13],["H3117","this day",14,22],["H4941","according to thine ordinances",23,52],["H5650","for all are thy servants",54,78]]},"119:92":{"text":"Unless thy law had been my delights, I should then have perished in mine affliction.","words":[["H3884","Unless",0,6],["H8451","thy law",7,14],["H8191","had been my delights",15,35],["H0006","I should then have perished",37,64],["H6040","in mine affliction",65,83]]},"119:93":{"text":"I will never forget thy precepts: for with them thou hast quickened me.","words":[["H5769","I will never",0,12],["H7911","forget",13,19],["H6490","thy precepts",20,32],["H2421","for with them thou hast quickened",34,67]]},"119:94":{"text":"I am thine, save me; for I have sought thy precepts.","words":[["H3467","I am thine, save",0,16],["H1875","me; for I have sought",17,38],["H6490","thy precepts",39,51]]},"119:95":{"text":"The wicked have waited for me to destroy me: but I will consider thy testimonies.","words":[["H7563","The wicked",0,10],["H6960","have waited",11,22],["H0006","for me to destroy",23,40],["H0995","me: but I will consider",41,64],["H5713","thy testimonies",65,80]]},"119:96":{"text":"I have seen an end of all perfection: but thy commandment is exceeding broad.","words":[["H7200","I have seen",0,11],["H7093","an end",12,18],["H8502","of all perfection",19,36],["H4687","but thy commandment",38,57],["H3966","is exceeding",58,70],["H7342","broad",71,76]]},"119:97":{"text":"MEM. O how love I thy law! it is my meditation all the day.","words":[["H0157","MEM. O how love I",0,17],["H8451","thy law",18,25],["H7881","it is my meditation",27,46],["H3117","all the day",47,58]]},"119:98":{"text":"Thou through thy commandments hast made me wiser than mine enemies: for they are ever with me.","words":[["H4687","Thou through thy commandments",0,29],["H2449","hast made me wiser",30,48],["H0341","than mine enemies",49,66],["H5769","for they are ever",68,85]]},"119:99":{"text":"I have more understanding than all my teachers: for thy testimonies are my meditation.","words":[["H7919","I have more understanding",0,25],["H3925","than all my teachers",26,46],["H5715","for thy testimonies",48,67],["H7881","are my meditation",68,85]]},"119:100":{"text":"I understand more than the ancients, because I keep thy precepts.","words":[["H0995","I understand",0,12],["H2205","more than the ancients",13,35],["H5341","because I keep",37,51],["H6490","thy precepts",52,64]]},"119:101":{"text":"I have refrained my feet from every evil way, that I might keep thy word.","words":[["H3607","I have refrained",0,16],["H7272","my feet",17,24],["H7451","from every evil",25,40],["H0734","way",41,44],["H8104","that I might keep",46,63],["H1697","thy word",64,72]]},"119:102":{"text":"I have not departed from thy judgments: for thou hast taught me.","words":[["H5493","I have not departed",0,19],["H4941","from thy judgments",20,38],["H3384","for thou hast taught",40,60]]},"119:103":{"text":"How sweet are thy words unto my taste! yea, sweeter than honey to my mouth!","words":[["H4452","How sweet",0,9],["H0565","are thy words",10,23],["H2441","unto my taste",24,37],["H1706","yea, sweeter than honey",39,62],["H6310","to my mouth",63,74]]},"119:104":{"text":"Through thy precepts I get understanding: therefore I hate every false way.","words":[["H6490","Through thy precepts",0,20],["H0995","I get understanding",21,40],["H8130","therefore I hate",42,58],["H8267","every false",59,70],["H0734","way",71,74]]},"119:105":{"text":"NUN. Thy word is a lamp unto my feet, and a light unto my path.","words":[["H1697","NUN. Thy word",0,13],["H5216","is a lamp",14,23],["H7272","unto my feet",24,36],["H0216","and a light",38,49],["H5410","unto my path",50,62]]},"119:106":{"text":"I have sworn, and I will perform it, that I will keep thy righteous judgments.","words":[["H7650","I have sworn",0,12],["H6965","and I will perform",14,32],["H8104","it, that I will keep",33,53],["H6664","thy righteous",54,67],["H4941","judgments",68,77]]},"119:107":{"text":"I am afflicted very much: quicken me, O LORD, according unto thy word.","words":[["H6031","I am afflicted",0,14],["H3966","very much",15,24],["H2421","quicken",26,33],["H3068","me, O LORD",34,44],["H1697","according unto thy word",46,69]]},"119:108":{"text":"Accept, I beseech thee, the freewill offerings of my mouth, O LORD, and teach me thy judgments.","words":[["H7521","Accept",0,6],["H5071","I beseech thee, the freewill offerings",8,46],["H6310","of my mouth",47,58],["H3068","O LORD",60,66],["H3925","and teach",68,77],["H4941","me thy judgments",78,94]]},"119:109":{"text":"My soul is continually in my hand: yet do I not forget thy law.","words":[["H5315","My soul",0,7],["H8548","is continually",8,22],["H3709","in my hand",23,33],["H7911","yet do I not forget",35,54],["H8451","thy law",55,62]]},"119:110":{"text":"The wicked have laid a snare for me: yet I erred not from thy precepts.","words":[["H7563","The wicked",0,10],["H5414","have laid",11,20],["H6341","a snare",21,28],["H8582","for me: yet I erred",29,48],["H6490","not from thy precepts",49,70]]},"119:111":{"text":"Thy testimonies have I taken as an heritage for ever: for they are the rejoicing of my heart.","words":[["H5715","Thy testimonies",0,15],["H5157","have I taken as an heritage",16,43],["H5769","for ever",44,52],["H8342","for they are the rejoicing",54,80],["H3820","of my heart",81,92]]},"119:112":{"text":"I have inclined mine heart to perform thy statutes alway, even unto the end.","words":[["H5186","I have inclined",0,15],["H3820","mine heart",16,26],["H6213","to perform",27,37],["H2706","thy statutes",38,50],["H5769","alway",51,56],["H6118","even unto the end",58,75]]},"119:113":{"text":"SAMECH. I hate vain thoughts: but thy law do I love.","words":[["H8130","SAMECH. I hate",0,14],["H5588","vain thoughts",15,28],["H8451","but thy law",30,41],["H0157","do I love",42,51]]},"119:114":{"text":"Thou art my hiding place and my shield: I hope in thy word.","words":[["H5643","Thou art my hiding place",0,24],["H4043","and my shield",25,38],["H3176","I hope",40,46],["H1697","in thy word",47,58]]},"119:115":{"text":"Depart from me, ye evildoers: for I will keep the commandments of my God.","words":[["H5493","Depart",0,6],["H7489","from me, ye evildoers",7,28],["H5341","for I will keep",30,45],["H4687","the commandments",46,62],["H0430","of my God",63,72]]},"119:116":{"text":"Uphold me according unto thy word, that I may live: and let me not be ashamed of my hope.","words":[["H5564","Uphold",0,6],["H0565","me according unto thy word",7,33],["H2421","that I may live",35,50],["H0954","and let me not be ashamed",52,77],["H7664","of my hope",78,88]]},"119:117":{"text":"Hold thou me up, and I shall be safe: and I will have respect unto thy statutes continually.","words":[["H5582","Hold thou me up",0,15],["H3467","and I shall be safe",17,36],["H8159","and I will have respect",38,61],["H2706","unto thy statutes",62,79],["H8548","continually",80,91]]},"119:118":{"text":"Thou hast trodden down all them that err from thy statutes: for their deceit is falsehood.","words":[["H5541","Thou hast trodden down",0,22],["H7686","all them that err",23,40],["H2706","from thy statutes",41,58],["H8649","for their deceit",60,76],["H8267","is falsehood",77,89]]},"119:119":{"text":"Thou puttest away all the wicked of the earth like dross: therefore I love thy testimonies.","words":[["H7673","Thou puttest away",0,17],["H7563","all the wicked",18,32],["H0776","of the earth",33,45],["H5509","like dross",46,56],["H0157","therefore I love",58,74],["H5713","thy testimonies",75,90]]},"119:120":{"text":"My flesh trembleth for fear of thee; and I am afraid of thy judgments.","words":[["H1320","My flesh",0,8],["H5568","trembleth",9,18],["H6343","for fear",19,27],["H3372","of thee; and I am afraid",28,52],["H4941","of thy judgments",53,69]]},"119:121":{"text":"AIN. I have done judgment and justice: leave me not to mine oppressors.","words":[["H6213","AIN. I have done",0,16],["H4941","judgment",17,25],["H6664","and justice",26,37],["H3240","leave",39,44],["H6231","me not to mine oppressors",45,70]]},"119:122":{"text":"Be surety for thy servant for good: let not the proud oppress me.","words":[["H6148","Be surety",0,9],["H5650","for thy servant",10,25],["H2896","for good",26,34],["H2086","let not the proud",36,53],["H6231","oppress",54,61]]},"119:123":{"text":"Mine eyes fail for thy salvation, and for the word of thy righteousness.","words":[["H5869","Mine eyes",0,9],["H3615","fail",10,14],["H3444","for thy salvation",15,32],["H0565","and for the word",34,50],["H6664","of thy righteousness",51,71]]},"119:124":{"text":"Deal with thy servant according unto thy mercy, and teach me thy statutes.","words":[["H6213","Deal",0,4],["H5650","with thy servant",5,21],["H2617","according unto thy mercy",22,46],["H3925","and teach",48,57],["H2706","me thy statutes",58,73]]},"119:125":{"text":"I am thy servant; give me understanding, that I may know thy testimonies.","words":[["H5650","I am thy servant",0,16],["H0995","give me understanding",18,39],["H3045","that I may know",41,56],["H5713","thy testimonies",57,72]]},"119:126":{"text":"It is time for thee, LORD, to work: for they have made void thy law.","words":[["H6256","It is time",0,10],["H3068","for thee, LORD",11,25],["H6213","to work",27,34],["H6565","for they have made void",36,59],["H8451","thy law",60,67]]},"119:127":{"text":"Therefore I love thy commandments above gold; yea, above fine gold.","words":[["H0157","Therefore I love",0,16],["H4687","thy commandments",17,33],["H2091","above gold",34,44],["H6337","yea, above fine gold",46,66]]},"119:128":{"text":"Therefore I esteem all thy precepts concerning all things to be right; and I hate every false way.","words":[["H6490","Therefore I esteem all thy precepts",0,35],["H3474","concerning all things to be right",36,69],["H8130","and I hate",71,81],["H8267","every false",82,93],["H0734","way",94,97]]},"119:129":{"text":"PE. Thy testimonies are wonderful: therefore doth my soul keep them.","words":[["H5715","PE. Thy testimonies",0,19],["H6382","are wonderful",20,33],["H5315","therefore doth my soul",35,57],["H5341","keep",58,62]]},"119:130":{"text":"The entrance of thy words giveth light; it giveth understanding unto the simple.","words":[["H6608","The entrance",0,12],["H1697","of thy words",13,25],["H0215","giveth light",26,38],["H0995","it giveth understanding",40,63],["H6612","unto the simple",64,79]]},"119:131":{"text":"I opened my mouth, and panted: for I longed for thy commandments.","words":[["H6473","I opened",0,8],["H6310","my mouth",9,17],["H7602","and panted",19,29],["H2968","for I longed",31,43],["H4687","for thy commandments",44,64]]},"119:132":{"text":"Look thou upon me, and be merciful unto me, as thou usest to do unto those that love thy name.","words":[["H6437","Look",0,4],["H2603","thou upon me, and be merciful",5,34],["H4941","unto me, as thou usest",35,57],["H0157","to do unto those that love",58,84],["H8034","thy name",85,93]]},"119:133":{"text":"Order my steps in thy word: and let not any iniquity have dominion over me.","words":[["H3559","Order",0,5],["H6471","my steps",6,14],["H0565","in thy word",15,26],["H0205","and let not any iniquity",28,52],["H7980","have dominion",53,66]]},"119:134":{"text":"Deliver me from the oppression of man: so will I keep thy precepts.","words":[["H6299","Deliver",0,7],["H6233","me from the oppression",8,30],["H0120","of man",31,37],["H8104","so will I keep",39,53],["H6490","thy precepts",54,66]]},"119:135":{"text":"Make thy face to shine upon thy servant; and teach me thy statutes.","words":[["H6440","Make thy face",0,13],["H0215","to shine",14,22],["H5650","upon thy servant",23,39],["H3925","and teach",41,50],["H2706","me thy statutes",51,66]]},"119:136":{"text":"Rivers of waters run down mine eyes, because they keep not thy law.","words":[["H6388","Rivers",0,6],["H4325","of waters",7,16],["H3381","run down",17,25],["H5869","mine eyes",26,35],["H8104","because they keep",37,54],["H8451","not thy law",55,66]]},"119:137":{"text":"TZADDI. Righteous art thou, O LORD, and upright are thy judgments.","words":[["H6662","TZADDI. Righteous",0,17],["H3068","art thou, O LORD",18,34],["H3477","and upright",36,47],["H4941","are thy judgments",48,65]]},"119:138":{"text":"Thy testimonies that thou hast commanded are righteous and very faithful.","words":[["H5713","Thy testimonies",0,15],["H6680","that thou hast commanded",16,40],["H6664","are righteous",41,54],["H3966","and very",55,63],["H0530","faithful",64,72]]},"119:139":{"text":"My zeal hath consumed me, because mine enemies have forgotten thy words.","words":[["H7068","My zeal",0,7],["H6789","hath consumed",8,21],["H6862","me, because mine enemies",22,46],["H7911","have forgotten",47,61],["H1697","thy words",62,71]]},"119:140":{"text":"Thy word is very pure: therefore thy servant loveth it.","words":[["H0565","Thy word",0,8],["H3966","is very",9,16],["H6884","pure",17,21],["H5650","therefore thy servant",23,44],["H0157","loveth",45,51]]},"119:141":{"text":"I am small and despised: yet do not I forget thy precepts.","words":[["H6810","I am small",0,10],["H0959","and despised",11,23],["H7911","yet do not I forget",25,44],["H6490","thy precepts",45,57]]},"119:142":{"text":"Thy righteousness is an everlasting righteousness, and thy law is the truth.","words":[["H6666","Thy righteousness",0,17],["H5769","is an everlasting",18,35],["H6664","righteousness",36,49],["H8451","and thy law",51,62],["H0571","is the truth",63,75]]},"119:143":{"text":"Trouble and anguish have taken hold on me: yet thy commandments are my delights.","words":[["H6862","Trouble",0,7],["H4689","and anguish",8,19],["H4672","have taken hold",20,35],["H4687","on me: yet thy commandments",36,63],["H8191","are my delights",64,79]]},"119:144":{"text":"The righteousness of thy testimonies is everlasting: give me understanding, and I shall live.","words":[["H6664","The righteousness",0,17],["H5715","of thy testimonies",18,36],["H5769","is everlasting",37,51],["H0995","give me understanding",53,74],["H2421","and I shall live",76,92]]},"119:145":{"text":"KOPH. I cried with my whole heart; hear me, O LORD: I will keep thy statutes.","words":[["H7121","KOPH. I cried",0,13],["H3820","with my whole heart",14,33],["H6030","hear",35,39],["H3068","me, O LORD",40,50],["H5341","I will keep",52,63],["H2706","thy statutes",64,76]]},"119:146":{"text":"I cried unto thee; save me, and I shall keep thy testimonies.","words":[["H7121","I cried",0,7],["H3467","unto thee; save",8,23],["H8104","me, and I shall keep",24,44],["H5713","thy testimonies",45,60]]},"119:147":{"text":"I prevented the dawning of the morning, and cried: I hoped in thy word.","words":[["H6923","I prevented",0,11],["H5399","the dawning of the morning",12,38],["H7768","and cried",40,49],["H3176","I hoped",51,58],["H1697","in thy word",59,70]]},"119:148":{"text":"Mine eyes prevent the night watches, that I might meditate in thy word.","words":[["H5869","Mine eyes",0,9],["H6923","prevent",10,17],["H0821","the night watches",18,35],["H7878","that I might meditate",37,58],["H0565","in thy word",59,70]]},"119:149":{"text":"Hear my voice according unto thy lovingkindness: O LORD, quicken me according to thy judgment.","words":[["H8085","Hear",0,4],["H6963","my voice",5,13],["H2617","according unto thy lovingkindness",14,47],["H3068","O LORD",49,55],["H2421","quicken",57,64],["H4941","me according to thy judgment",65,93]]},"119:150":{"text":"They draw nigh that follow after mischief: they are far from thy law.","words":[["H7126","They draw nigh",0,14],["H7291","that follow",15,26],["H2154","after mischief",27,41],["H7368","they are far",43,55],["H8451","from thy law",56,68]]},"119:151":{"text":"Thou art near, O LORD; and all thy commandments are truth.","words":[["H7138","Thou art near",0,13],["H3068","O LORD",15,21],["H4687","and all thy commandments",23,47],["H0571","are truth",48,57]]},"119:152":{"text":"Concerning thy testimonies, I have known of old that thou hast founded them for ever.","words":[["H5713","Concerning thy testimonies",0,26],["H3045","I have known",28,40],["H6924","of old",41,47],["H3245","that thou hast founded",48,70],["H5769","them for ever",71,84]]},"119:153":{"text":"RESH. Consider mine affliction, and deliver me: for I do not forget thy law.","words":[["H7200","RESH. Consider",0,14],["H6040","mine affliction",15,30],["H2502","and deliver",32,43],["H7911","me: for I do not forget",44,67],["H8451","thy law",68,75]]},"119:154":{"text":"Plead my cause, and deliver me: quicken me according to thy word.","words":[["H7378","Plead",0,5],["H7379","my cause",6,14],["H1350","and deliver",16,27],["H2421","me: quicken",28,39],["H0565","me according to thy word",40,64]]},"119:155":{"text":"Salvation is far from the wicked: for they seek not thy statutes.","words":[["H3444","Salvation",0,9],["H7350","is far",10,16],["H7563","from the wicked",17,32],["H1875","for they seek",34,47],["H2706","not thy statutes",48,64]]},"119:156":{"text":"Great are thy tender mercies, O LORD: quicken me according to thy judgments.","words":[["H7227","Great",0,5],["H7356","are thy tender mercies",6,28],["H3068","O LORD",30,36],["H2421","quicken",38,45],["H4941","me according to thy judgments",46,75]]},"119:157":{"text":"Many are my persecutors and mine enemies; yet do I not decline from thy testimonies.","words":[["H7227","Many",0,4],["H7291","are my persecutors",5,23],["H6862","and mine enemies",24,40],["H5186","yet do I not decline",42,62],["H5715","from thy testimonies",63,83]]},"119:158":{"text":"I beheld the transgressors, and was grieved; because they kept not thy word.","words":[["H7200","I beheld",0,8],["H0898","the transgressors",9,26],["H6962","and was grieved",28,43],["H8104","because they kept",45,62],["H0565","not thy word",63,75]]},"119:159":{"text":"Consider how I love thy precepts: quicken me, O LORD, according to thy lovingkindness.","words":[["H7200","Consider",0,8],["H0157","how I love",9,19],["H6490","thy precepts",20,32],["H2421","quicken",34,41],["H3068","me, O LORD",42,52],["H2617","according to thy lovingkindness",54,85]]},"119:160":{"text":"Thy word is true from the beginning: and every one of thy righteous judgments endureth for ever.","words":[["H1697","Thy word",0,8],["H0571","is true",9,16],["H7218","from the beginning",17,35],["H6664","and every one of thy righteous",37,67],["H4941","judgments",68,77],["H5769","endureth for ever",78,95]]},"119:161":{"text":"SCHIN. Princes have persecuted me without a cause: but my heart standeth in awe of thy word.","words":[["H8269","SCHIN. Princes",0,14],["H7291","have persecuted",15,30],["H2600","me without a cause",31,49],["H3820","but my heart",51,63],["H6342","standeth in awe",64,79],["H1697","of thy word",80,91]]},"119:162":{"text":"I rejoice at thy word, as one that findeth great spoil.","words":[["H7797","I rejoice",0,9],["H0565","at thy word",10,21],["H4672","as one that findeth",23,42],["H7227","great",43,48],["H7998","spoil",49,54]]},"119:163":{"text":"I hate and abhor lying: but thy law do I love.","words":[["H8130","I hate",0,6],["H8581","and abhor",7,16],["H8267","lying",17,22],["H8451","but thy law",24,35],["H0157","do I love",36,45]]},"119:164":{"text":"Seven times a day do I praise thee because of thy righteous judgments.","words":[["H7651","Seven times",0,11],["H3117","a day",12,17],["H1984","do I praise",18,29],["H6664","thee because of thy righteous",30,59],["H4941","judgments",60,69]]},"119:165":{"text":"Great peace have they which love thy law: and nothing shall offend them.","words":[["H7227","Great",0,5],["H7965","peace",6,11],["H0157","have they which love",12,32],["H8451","thy law",33,40],["H4383","and nothing shall offend",42,66]]},"119:166":{"text":"LORD, I have hoped for thy salvation, and done thy commandments.","words":[["H3068","LORD",0,4],["H7663","I have hoped",6,18],["H3444","for thy salvation",19,36],["H6213","and done",38,46],["H4687","thy commandments",47,63]]},"119:167":{"text":"My soul hath kept thy testimonies; and I love them exceedingly.","words":[["H5315","My soul",0,7],["H8104","hath kept",8,17],["H5713","thy testimonies",18,33],["H0157","and I love",35,45],["H3966","them exceedingly",46,62]]},"119:168":{"text":"I have kept thy precepts and thy testimonies: for all my ways are before thee.","words":[["H8104","I have kept",0,11],["H6490","thy precepts",12,24],["H5713","and thy testimonies",25,44],["H1870","for all my ways",46,61]]},"119:169":{"text":"TAU. Let my cry come near before thee, O LORD: give me understanding according to thy word.","words":[["H7440","TAU. Let my cry",0,15],["H7126","come near",16,25],["H6440","before",26,32],["H3068","thee, O LORD",33,45],["H0995","give me understanding",47,68],["H1697","according to thy word",69,90]]},"119:170":{"text":"Let my supplication come before thee: deliver me according to thy word.","words":[["H8467","Let my supplication",0,19],["H0935","come",20,24],["H6440","before",25,31],["H5337","thee: deliver",32,45],["H0565","me according to thy word",46,70]]},"119:171":{"text":"My lips shall utter praise, when thou hast taught me thy statutes.","words":[["H8193","My lips",0,7],["H5042","shall utter",8,19],["H8416","praise",20,26],["H3925","when thou hast taught",28,49],["H2706","me thy statutes",50,65]]},"119:172":{"text":"My tongue shall speak of thy word: for all thy commandments are righteousness.","words":[["H3956","My tongue",0,9],["H6030","shall speak",10,21],["H0565","of thy word",22,33],["H4687","for all thy commandments",35,59],["H6664","are righteousness",60,77]]},"119:173":{"text":"Let thine hand help me; for I have chosen thy precepts.","words":[["H3027","Let thine hand",0,14],["H5826","help",15,19],["H0977","me; for I have chosen",20,41],["H6490","thy precepts",42,54]]},"119:174":{"text":"I have longed for thy salvation, O LORD; and thy law is my delight.","words":[["H8373","I have longed",0,13],["H3444","for thy salvation",14,31],["H3068","O LORD",33,39],["H8451","and thy law",41,52],["H8191","is my delight",53,66]]},"119:175":{"text":"Let my soul live, and it shall praise thee; and let thy judgments help me.","words":[["H5315","Let my soul",0,11],["H2421","live",12,16],["H1984","and it shall praise",18,37],["H4941","thee; and let thy judgments",38,65],["H5826","help",66,70]]},"119:176":{"text":"I have gone astray like a lost sheep; seek thy servant; for I do not forget thy commandments.","words":[["H8582","I have gone astray",0,18],["H0006","like a lost",19,30],["H7716","sheep",31,36],["H1245","seek",38,42],["H5650","thy servant",43,54],["H7911","for I do not forget",56,75],["H4687","thy commandments",76,92]]},"120:1":{"text":"A Song of degrees. In my distress I cried unto the LORD, and he heard me.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H6869","In my distress",19,33],["H7121","I cried",34,41],["H3068","unto the LORD",42,55],["H6030","and he heard",57,69]]},"120:2":{"text":"Deliver my soul, O LORD, from lying lips, and from a deceitful tongue.","words":[["H5337","Deliver",0,7],["H5315","my soul",8,15],["H3068","O LORD",17,23],["H8267","from lying",25,35],["H8193","lips",36,40],["H7423","and from a deceitful",42,62],["H3956","tongue",63,69]]},"120:3":{"text":"What shall be given unto thee? or what shall be done unto thee, thou false tongue?","words":[["H5414","What shall be given",0,19],["H3254","unto thee? or what shall be done",20,52],["H7423","unto thee, thou false",53,74],["H3956","tongue",75,81]]},"120:4":{"text":"Sharp arrows of the mighty, with coals of juniper.","words":[["H8150","Sharp",0,5],["H2671","arrows",6,12],["H1368","of the mighty",13,26],["H1513","with coals",28,38],["H7574","of juniper",39,49]]},"120:5":{"text":"Woe is me, that I sojourn in Mesech, that I dwell in the tents of Kedar!","words":[["H0190","Woe",0,3],["H1481","is me, that I sojourn",4,25],["H4902","in Mesech",26,35],["H7931","that I dwell",37,49],["H0168","in the tents",50,62],["H6938","of Kedar",63,71]]},"120:6":{"text":"My soul hath long dwelt with him that hateth peace.","words":[["H5315","My soul",0,7],["H7227","hath long",8,17],["H7931","dwelt",18,23],["H8130","with him that hateth",24,44],["H7965","peace",45,50]]},"120:7":{"text":"I am for peace: but when I speak, they are for war.","words":[["H7965","I am for peace",0,14],["H1696","but when I speak",16,32],["H4421","they are for war",34,50]]},"121:1":{"text":"A Song of degrees. I will lift up mine eyes unto the hills, from whence cometh my help.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H5375","I will lift up",19,33],["H5869","mine eyes",34,43],["H2022","unto the hills",44,58],["H0370","from whence",60,71],["H0935","cometh",72,78],["H5828","my help",79,86]]},"121:2":{"text":"My help cometh from the LORD, which made heaven and earth.","words":[["H5828","My help",0,7],["H3068","cometh from the LORD",8,28],["H6213","which made",30,40],["H8064","heaven",41,47],["H0776","and earth",48,57]]},"121:3":{"text":"He will not suffer thy foot to be moved: he that keepeth thee will not slumber.","words":[["H5414","He will not suffer",0,18],["H7272","thy foot",19,27],["H4132","to be moved",28,39],["H8104","he that keepeth",41,56],["H5123","thee will not slumber",57,78]]},"121:4":{"text":"Behold, he that keepeth Israel shall neither slumber nor sleep.","words":[["H8104","Behold, he that keepeth",0,23],["H3478","Israel",24,30],["H5123","shall neither slumber",31,52],["H3462","nor sleep",53,62]]},"121:5":{"text":"The LORD is thy keeper: the LORD is thy shade upon thy right hand.","words":[["H3068","The LORD",0,8],["H8104","is thy keeper",9,22],["H3068","the LORD",24,32],["H6738","is thy shade",33,45],["H3225","upon thy right",46,60],["H3027","hand",61,65]]},"121:6":{"text":"The sun shall not smite thee by day, nor the moon by night.","words":[["H8121","The sun",0,7],["H5221","shall not smite",8,23],["H3119","thee by day",24,35],["H3394","nor the moon",37,49],["H3915","by night",50,58]]},"121:7":{"text":"The LORD shall preserve thee from all evil: he shall preserve thy soul.","words":[["H3068","The LORD",0,8],["H8104","shall preserve",9,23],["H7451","thee from all evil",24,42],["H8104","he shall preserve",44,61],["H5315","thy soul",62,70]]},"121:8":{"text":"The LORD shall preserve thy going out and thy coming in from this time forth, and even for evermore.","words":[["H3068","The LORD",0,8],["H8104","shall preserve",9,23],["H3318","thy going out",24,37],["H0935","and thy coming in",38,55],["H5704","from this time forth, and even for",56,90],["H5769","evermore",91,99]]},"122:1":{"text":"A Song of degrees of David. I was glad when they said unto me, Let us go into the house of the LORD.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H1732","of David",18,26],["H8055","I was glad",28,38],["H0559","when they said",39,53],["H3212","unto me, Let us go",54,72],["H1004","into the house",73,87],["H3068","of the LORD",88,99]]},"122:2":{"text":"Our feet shall stand within thy gates, O Jerusalem.","words":[["H7272","Our feet",0,8],["H5975","shall stand",9,20],["H8179","within thy gates",21,37],["H3389","O Jerusalem",39,50]]},"122:3":{"text":"Jerusalem is builded as a city that is compact together:","words":[["H3389","Jerusalem",0,9],["H1129","is builded",10,20],["H5892","as a city",21,30],["H2266","that is compact",31,46],["H3162","together",47,55]]},"122:4":{"text":"Whither the tribes go up, the tribes of the LORD, unto the testimony of Israel, to give thanks unto the name of the LORD.","words":[["H8033","Whither",0,7],["H7626","the tribes",8,18],["H5927","go up",19,24],["H7626","the tribes",26,36],["H3050","of the LORD",37,48],["H5715","unto the testimony",50,68],["H3478","of Israel",69,78],["H3034","to give thanks",80,94],["H8034","unto the name",95,108],["H3068","of the LORD",109,120]]},"122:5":{"text":"For there are set thrones of judgment, the thrones of the house of David.","words":[["H3427","For there are set",0,17],["H3678","thrones",18,25],["H4941","of judgment",26,37],["H3678","the thrones",39,50],["H1004","of the house",51,63],["H1732","of David",64,72]]},"122:6":{"text":"Pray for the peace of Jerusalem: they shall prosper that love thee.","words":[["H7592","Pray",0,4],["H7965","for the peace",5,18],["H3389","of Jerusalem",19,31],["H7951","they shall prosper",33,51],["H0157","that love",52,61]]},"122:7":{"text":"Peace be within thy walls, and prosperity within thy palaces.","words":[["H7965","Peace",0,5],["H2426","be within thy walls",6,25],["H7962","and prosperity",27,41],["H0759","within thy palaces",42,60]]},"122:8":{"text":"For my brethren and companions' sakes, I will now say, Peace be within thee.","words":[["H0251","For my brethren",0,15],["H7453","and companions'",16,31],["H1696","sakes, I will now say",32,53],["H7965","Peace",55,60]]},"122:9":{"text":"Because of the house of the LORD our God I will seek thy good.","words":[["H1004","Because of the house",0,20],["H3068","of the LORD",21,32],["H0430","our God",33,40],["H1245","I will seek",41,52],["H2896","thy good",53,61]]},"123:1":{"text":"A Song of degrees. Unto thee lift I up mine eyes, O thou that dwellest in the heavens.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H5375","Unto thee lift I up",19,38],["H5869","mine eyes",39,48],["H3427","O thou that dwellest",50,70],["H8064","in the heavens",71,85]]},"123:2":{"text":"Behold, as the eyes of servants look unto the hand of their masters, and as the eyes of a maiden unto the hand of her mistress; so our eyes wait upon the LORD our God, until that he have mercy upon us.","words":[["H5869","Behold, as the eyes",0,19],["H5650","of servants",20,31],["H3027","look unto the hand",32,50],["H0113","of their masters",51,67],["H5869","and as the eyes",69,84],["H8198","of a maiden",85,96],["H3027","unto the hand",97,110],["H1404","of her mistress",111,126],["H5869","so our eyes",128,139],["H3068","wait upon the LORD",140,158],["H0430","our God",159,166],["H2603","until that he have mercy",168,192]]},"123:3":{"text":"Have mercy upon us, O LORD, have mercy upon us: for we are exceedingly filled with contempt.","words":[["H2603","Have mercy",0,10],["H3068","upon us, O LORD",11,26],["H2603","have mercy",28,38],["H7227","upon us: for we are exceedingly",39,70],["H7646","filled",71,77],["H0937","with contempt",78,91]]},"123:4":{"text":"Our soul is exceedingly filled with the scorning of those that are at ease, and with the contempt of the proud.","words":[["H5315","Our soul",0,8],["H7227","is exceedingly",9,23],["H7646","filled",24,30],["H3933","with the scorning",31,48],["H7600","of those that are at ease",49,74],["H0937","and with the contempt",76,97],["H3238","of the proud",98,110],["H1343","of the proud",98,110],["H1349","of the proud",98,110]]},"124:1":{"text":"A Song of degrees of David. If it had not been the LORD who was on our side, now may Israel say;","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H1732","of David",18,26],["H3884","If",28,30],["H3068","it had not been the LORD",31,55],["H3478","who was on our side, now may Israel",56,91],["H0559","say",92,95]]},"124:2":{"text":"If it had not been the LORD who was on our side, when men rose up against us:","words":[["H3884","If",0,2],["H3068","it had not been the LORD",3,27],["H0120","who was on our side, when men",28,57],["H6965","rose up",58,65]]},"124:3":{"text":"Then they had swallowed us up quick, when their wrath was kindled against us:","words":[["H0233","Then",0,4],["H1104","they had swallowed us up",5,29],["H2416","quick",30,35],["H0639","when their wrath",37,53],["H2734","was kindled",54,65]]},"124:4":{"text":"Then the waters had overwhelmed us, the stream had gone over our soul:","words":[["H0233","Then",0,4],["H4325","the waters",5,15],["H7857","had overwhelmed",16,31],["H5158","us, the stream",32,46],["H5674","had gone over",47,60],["H5315","our soul",61,69]]},"124:5":{"text":"Then the proud waters had gone over our soul.","words":[["H0233","Then",0,4],["H2121","the proud",5,14],["H4325","waters",15,21],["H5674","had gone over",22,35],["H5315","our soul",36,44]]},"124:6":{"text":"Blessed be the LORD, who hath not given us as a prey to their teeth.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H5414","who hath not given",21,39],["H2964","us as a prey",40,52],["H8127","to their teeth",53,67]]},"124:7":{"text":"Our soul is escaped as a bird out of the snare of the fowlers: the snare is broken, and we are escaped.","words":[["H5315","Our soul",0,8],["H4422","is escaped",9,19],["H6833","as a bird",20,29],["H6341","out of the snare",30,46],["H3369","of the fowlers",47,61],["H6341","the snare",63,72],["H7665","is broken",73,82],["H4422","and we are escaped",84,102]]},"124:8":{"text":"Our help is in the name of the LORD, who made heaven and earth.","words":[["H5828","Our help",0,8],["H8034","is in the name",9,23],["H3068","of the LORD",24,35],["H6213","who made",37,45],["H8064","heaven",46,52],["H0776","and earth",53,62]]},"125:1":{"text":"A Song of degrees. They that trust in the LORD shall be as mount Zion, which cannot be removed, but abideth for ever.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H0982","They that trust",19,34],["H3068","in the LORD",35,46],["H2022","shall be as mount",47,64],["H6726","Zion",65,69],["H4131","which cannot be removed",71,94],["H3427","but abideth",96,107],["H5769","for ever",108,116]]},"125:2":{"text":"As the mountains are round about Jerusalem, so the LORD is round about his people from henceforth even for ever.","words":[["H2022","As the mountains",0,16],["H5439","are round about",17,32],["H3389","Jerusalem",33,42],["H3068","so the LORD",44,55],["H5439","is round about",56,70],["H5971","his people",71,81],["H5704","from henceforth even for",82,106],["H5769","ever",107,111]]},"125:3":{"text":"For the rod of the wicked shall not rest upon the lot of the righteous; lest the righteous put forth their hands unto iniquity.","words":[["H7626","For the rod",0,11],["H7562","of the wicked",12,25],["H5117","shall not rest",26,40],["H1486","upon the lot",41,53],["H6662","of the righteous",54,70],["H4616","lest",72,76],["H6662","the righteous",77,90],["H7971","put forth",91,100],["H3027","their hands",101,112],["H5766","unto iniquity",113,126]]},"125:4":{"text":"Do good, O LORD, unto those that be good, and to them that are upright in their hearts.","words":[["H2895","Do good",0,7],["H3068","O LORD",9,15],["H2896","unto those that be good",17,40],["H3477","and to them that are upright",42,70],["H3826","in their hearts",71,86]]},"125:5":{"text":"As for such as turn aside unto their crooked ways, the LORD shall lead them forth with the workers of iniquity: but peace shall be upon Israel.","words":[["H5186","As for such as turn aside",0,25],["H6128","unto their crooked ways",26,49],["H3068","the LORD",51,59],["H3212","shall lead them forth",60,81],["H6466","with the workers",82,98],["H0205","of iniquity",99,110],["H7965","but peace",112,121],["H3478","shall be upon Israel",122,142]]},"126:1":{"text":"A Song of degrees. When the LORD turned again the captivity of Zion, we were like them that dream.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H3068","When the LORD",19,32],["H7725","turned again",33,45],["H7870","the captivity",46,59],["H6726","of Zion",60,67],["H2492","we were like them that dream",69,97]]},"126:2":{"text":"Then was our mouth filled with laughter, and our tongue with singing: then said they among the heathen, The LORD hath done great things for them.","words":[["H6310","Then was our mouth",0,18],["H4390","filled",19,25],["H7814","with laughter",26,39],["H3956","and our tongue",41,55],["H7440","with singing",56,68],["H0559","then said",70,79],["H1471","they among the heathen",80,102],["H3068","The LORD",104,112],["H6213","hath done",113,122],["H1431","great things",123,135]]},"126:3":{"text":"The LORD hath done great things for us; whereof we are glad.","words":[["H3068","The LORD",0,8],["H6213","hath done",9,18],["H1431","great things",19,31],["H8056","for us; whereof we are glad",32,59]]},"126:4":{"text":"Turn again our captivity, O LORD, as the streams in the south.","words":[["H7725","Turn again",0,10],["H7622","our captivity",11,24],["H7622","our captivity",11,24],["H3068","O LORD",26,32],["H0650","as the streams",34,48],["H5045","in the south",49,61]]},"126:5":{"text":"They that sow in tears shall reap in joy.","words":[["H2232","They that sow",0,13],["H1832","in tears",14,22],["H7114","shall reap",23,33],["H7440","in joy",34,40]]},"126:6":{"text":"He that goeth forth and weepeth, bearing precious seed, shall doubtless come again with rejoicing, bringing his sheaves with him.","words":[["H3212","He that goeth",0,13],["H1980","forth",14,19],["H1058","and weepeth",20,31],["H5375","bearing",33,40],["H4901","precious",41,49],["H2233","seed",50,54],["H0935","shall doubtless",56,71],["H0935","come",72,76],["H7440","again with rejoicing",77,97],["H5375","bringing",99,107],["H0485","his sheaves",108,119]]},"127:1":{"text":"A Song of degrees for Solomon. Except the LORD build the house, they labour in vain that build it: except the LORD keep the city, the watchman waketh but in vain.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H8010","for Solomon",18,29],["H3068","Except the LORD",31,46],["H1129","build",47,52],["H1004","the house",53,62],["H5998","they labour",64,75],["H7723","in vain",76,83],["H1129","that build",84,94],["H3068","it: except the LORD",95,114],["H8104","keep",115,119],["H5892","the city",120,128],["H8104","the watchman",130,142],["H8245","waketh",143,149],["H7723","but in vain",150,161]]},"127:2":{"text":"It is vain for you to rise up early, to sit up late, to eat the bread of sorrows: for so he giveth his beloved sleep.","words":[["H7723","It is vain",0,10],["H6965","for you to rise up",11,29],["H7925","early",30,35],["H3427","to sit up",37,46],["H0309","late",47,51],["H0398","to eat",53,59],["H3899","the bread",60,69],["H6089","of sorrows",70,80],["H5414","for so he giveth",82,98],["H3039","his beloved",99,110],["H8142","sleep",111,116]]},"127:3":{"text":"Lo, children are an heritage of the LORD: and the fruit of the womb is his reward.","words":[["H1121","Lo, children",0,12],["H5159","are an heritage",13,28],["H3068","of the LORD",29,40],["H6529","and the fruit",42,55],["H0990","of the womb",56,67],["H7939","is his reward",68,81]]},"127:4":{"text":"As arrows are in the hand of a mighty man; so are children of the youth.","words":[["H2671","As arrows",0,9],["H3027","are in the hand",10,25],["H1368","of a mighty man",26,41],["H1121","so are children",43,58],["H5271","of the youth",59,71]]},"127:5":{"text":"Happy is the man that hath his quiver full of them: they shall not be ashamed, but they shall speak with the enemies in the gate.","words":[["H0835","Happy",0,5],["H1397","is the man",6,16],["H0827","that hath his quiver",17,37],["H4390","full",38,42],["H0954","of them: they shall not be ashamed",43,77],["H1696","but they shall speak",79,99],["H0341","with the enemies",100,116],["H8179","in the gate",117,128]]},"128:1":{"text":"A Song of degrees. Blessed is every one that feareth the LORD; that walketh in his ways.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H0835","Blessed",19,26],["H3373","is every one that feareth",27,52],["H3068","the LORD",53,61],["H1980","that walketh",63,75],["H1870","in his ways",76,87]]},"128:2":{"text":"For thou shalt eat the labour of thine hands: happy shalt thou be, and it shall be well with thee.","words":[["H0398","For thou shalt eat",0,18],["H3018","the labour",19,29],["H3709","of thine hands",30,44],["H0835","happy",46,51],["H2896","shalt thou be, and it shall be well",52,87]]},"128:3":{"text":"Thy wife shall be as a fruitful vine by the sides of thine house: thy children like olive plants round about thy table.","words":[["H0802","Thy wife",0,8],["H6509","shall be as a fruitful",9,31],["H1612","vine",32,36],["H3411","by the sides",37,49],["H1004","of thine house",50,64],["H1121","thy children",66,78],["H2132","like olive",79,89],["H8363","plants",90,96],["H5439","round about",97,108],["H7979","thy table",109,118]]},"128:4":{"text":"Behold, that thus shall the man be blessed that feareth the LORD.","words":[["H1397","Behold, that thus shall the man",0,31],["H1288","be blessed",32,42],["H3373","that feareth",43,55],["H3068","the LORD",56,64]]},"128:5":{"text":"The LORD shall bless thee out of Zion: and thou shalt see the good of Jerusalem all the days of thy life.","words":[["H3068","The LORD",0,8],["H1288","shall bless",9,20],["H6726","thee out of Zion",21,37],["H7200","and thou shalt see",39,57],["H2898","the good",58,66],["H3389","of Jerusalem",67,79],["H3117","all the days",80,92],["H2416","of thy life",93,104]]},"128:6":{"text":"Yea, thou shalt see thy children's children, and peace upon Israel.","words":[["H7200","Yea, thou shalt see",0,19],["H1121","thy children's",20,34],["H1121","children",35,43],["H7965","and peace",45,54],["H3478","upon Israel",55,66]]},"129:1":{"text":"A Song of degrees. Many a time have they afflicted me from my youth, may Israel now say:","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H7227","Many a time",19,30],["H6887","have they afflicted",31,50],["H5271","me from my youth",51,67],["H3478","may Israel",69,79],["H0559","now say",80,87]]},"129:2":{"text":"Many a time have they afflicted me from my youth: yet they have not prevailed against me.","words":[["H7227","Many a time",0,11],["H6887","have they afflicted",12,31],["H5271","me from my youth",32,48],["H3201","yet they have not prevailed",50,77]]},"129:3":{"text":"The plowers plowed upon my back: they made long their furrows.","words":[["H2790","The plowers",0,11],["H2790","plowed",12,18],["H1354","upon my back",19,31],["H0748","they made long",33,47],["H4618","their furrows",48,61],["H4618","their furrows",48,61]]},"129:4":{"text":"The LORD is righteous: he hath cut asunder the cords of the wicked.","words":[["H3068","The LORD",0,8],["H6662","is righteous",9,21],["H7112","he hath cut asunder",23,42],["H5688","the cords",43,52],["H7563","of the wicked",53,66]]},"129:5":{"text":"Let them all be confounded and turned back that hate Zion.","words":[["H0954","Let them all be confounded",0,26],["H5472","and turned",27,37],["H0268","back",38,42],["H8130","that hate",43,52],["H6726","Zion",53,57]]},"129:6":{"text":"Let them be as the grass upon the housetops, which withereth afore it groweth up:","words":[["H2682","Let them be as the grass",0,24],["H1406","upon the housetops",25,43],["H3001","which withereth",45,60],["H6927","afore",61,66],["H8025","it groweth up",67,80]]},"129:7":{"text":"Wherewith the mower filleth not his hand; nor he that bindeth sheaves his bosom.","words":[["H7114","Wherewith the mower",0,19],["H4390","filleth",20,27],["H3709","not his hand",28,40],["H6014","nor he that bindeth sheaves",42,69],["H2683","his bosom",70,79]]},"129:8":{"text":"Neither do they which go by say, The blessing of the LORD be upon you: we bless you in the name of the LORD.","words":[["H5674","Neither do they which go by",0,27],["H0559","say",28,31],["H1293","The blessing",33,45],["H3068","of the LORD",46,57],["H1288","be upon you: we bless",58,79],["H8034","you in the name",80,95],["H3068","of the LORD",96,107]]},"130:1":{"text":"A Song of degrees. Out of the depths have I cried unto thee, O LORD.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H4615","Out of the depths",19,36],["H7121","have I cried",37,49],["H3068","unto thee, O LORD",50,67]]},"130:2":{"text":"Lord, hear my voice: let thine ears be attentive to the voice of my supplications.","words":[["H0136","Lord",0,4],["H8085","hear",6,10],["H6963","my voice",11,19],["H0241","let thine ears",21,35],["H7183","be attentive",36,48],["H6963","to the voice",49,61],["H8469","of my supplications",62,81]]},"130:3":{"text":"If thou, LORD, shouldest mark iniquities, O Lord, who shall stand?","words":[["H3050","If thou, LORD",0,13],["H8104","shouldest mark",15,29],["H5771","iniquities",30,40],["H0136","O Lord",42,48],["H5975","who shall stand",50,65]]},"130:4":{"text":"But there is forgiveness with thee, that thou mayest be feared.","words":[["H5547","But there is forgiveness",0,24],["H3372","with thee, that thou mayest be feared",25,62]]},"130:5":{"text":"I wait for the LORD, my soul doth wait, and in his word do I hope.","words":[["H6960","I wait",0,6],["H3068","for the LORD",7,19],["H5315","my soul",21,28],["H6960","doth wait",29,38],["H1697","and in his word",40,55],["H3176","do I hope",56,65]]},"130:6":{"text":"My soul waiteth for the Lord more than they that watch for the morning: I say, more than they that watch for the morning.","words":[["H5315","My soul",0,7],["H0136","waiteth for the Lord",8,28],["H8104","more than they that watch",29,54],["H1242","for the morning",55,70],["H8104","I say, more than they that watch",72,104],["H1242","for the morning",105,120]]},"130:7":{"text":"Let Israel hope in the LORD: for with the LORD there is mercy, and with him is plenteous redemption.","words":[["H3478","Let Israel",0,10],["H3176","hope",11,15],["H3068","in the LORD",16,27],["H3068","for with the LORD",29,46],["H2617","there is mercy",47,61],["H7235","and with him is plenteous",63,88],["H6304","redemption",89,99]]},"130:8":{"text":"And he shall redeem Israel from all his iniquities.","words":[["H6299","And he shall redeem",0,19],["H3478","Israel",20,26],["H5771","from all his iniquities",27,50]]},"131:1":{"text":"A Song of degrees of David. LORD, my heart is not haughty, nor mine eyes lofty: neither do I exercise myself in great matters, or in things too high for me.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H1732","of David",18,26],["H3068","LORD",28,32],["H3820","my heart",34,42],["H1361","is not haughty",43,57],["H5869","nor mine eyes",59,72],["H7311","lofty",73,78],["H1980","neither do I exercise",80,101],["H1419","myself in great matters",102,125],["H6381","or in things too high",127,148]]},"131:2":{"text":"Surely I have behaved and quieted myself, as a child that is weaned of his mother: my soul is even as a weaned child.","words":[["H7737","Surely I have behaved",0,21],["H1826","and quieted",22,33],["H5315","myself",34,40],["H1580","as a child that is weaned",42,67],["H0517","of his mother",68,81],["H5315","my soul",83,90],["H1580","is even as a weaned child",91,116]]},"131:3":{"text":"Let Israel hope in the LORD from henceforth and for ever.","words":[["H3478","Let Israel",0,10],["H3176","hope",11,15],["H3068","in the LORD",16,27],["H5704","from henceforth and for",28,51],["H5769","ever",52,56]]},"132:1":{"text":"A Song of degrees. LORD, remember David, and all his afflictions:","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H3068","LORD",19,23],["H2142","remember",25,33],["H1732","David",34,39],["H6031","and all his afflictions",41,64]]},"132:2":{"text":"How he sware unto the LORD, and vowed unto the mighty God of Jacob;","words":[["H7650","How he sware",0,12],["H3068","unto the LORD",13,26],["H5087","and vowed",28,37],["H0046","unto the mighty",38,53],["H3290","God of Jacob",54,66]]},"132:3":{"text":"Surely I will not come into the tabernacle of my house, nor go up into my bed;","words":[["H0935","Surely I will not come",0,22],["H0168","into the tabernacle",23,42],["H1004","of my house",43,54],["H5927","nor go up",56,65],["H6210","into my bed",66,77],["H3326","into my bed",66,77]]},"132:4":{"text":"I will not give sleep to mine eyes, or slumber to mine eyelids,","words":[["H5414","I will not give",0,15],["H8153","sleep",16,21],["H5869","to mine eyes",22,34],["H8572","or slumber",36,46],["H6079","to mine eyelids",47,62]]},"132:5":{"text":"Until I find out a place for the LORD, an habitation for the mighty God of Jacob.","words":[["H4672","Until I find out",0,16],["H4725","a place",17,24],["H3068","for the LORD",25,37],["H4908","an habitation",39,52],["H0046","for the mighty",53,67],["H3290","God of Jacob",68,80]]},"132:6":{"text":"Lo, we heard of it at Ephratah: we found it in the fields of the wood.","words":[["H8085","Lo, we heard",0,12],["H0672","of it at Ephratah",13,30],["H4672","we found",32,40],["H7704","it in the fields",41,57],["H3293","of the wood",58,69]]},"132:7":{"text":"We will go into his tabernacles: we will worship at his footstool.","words":[["H0935","We will go",0,10],["H4908","into his tabernacles",11,31],["H7812","we will worship",33,48],["H1916","at his footstool",49,65],["H7272","at his footstool",49,65]]},"132:8":{"text":"Arise, O LORD, into thy rest; thou, and the ark of thy strength.","words":[["H6965","Arise",0,5],["H3068","O LORD",7,13],["H4496","into thy rest",15,28],["H0727","thou, and the ark",30,47],["H5797","of thy strength",48,63]]},"132:9":{"text":"Let thy priests be clothed with righteousness; and let thy saints shout for joy.","words":[["H3548","Let thy priests",0,15],["H3847","be clothed",16,26],["H6664","with righteousness",27,45],["H2623","and let thy saints",47,65],["H7442","shout for joy",66,79]]},"132:10":{"text":"For thy servant David's sake turn not away the face of thine anointed.","words":[["H5650","For thy servant",0,15],["H1732","David's",16,23],["H7725","sake turn not away",24,42],["H6440","the face",43,51],["H4899","of thine anointed",52,69]]},"132:11":{"text":"The LORD hath sworn in truth unto David; he will not turn from it; Of the fruit of thy body will I set upon thy throne.","words":[["H3068","The LORD",0,8],["H7650","hath sworn",9,19],["H0571","in truth",20,28],["H1732","unto David",29,39],["H7725","he will not turn",41,57],["H6529","from it; Of the fruit",58,79],["H0990","of thy body",80,91],["H7896","will I set",92,102],["H3678","upon thy throne",103,118]]},"132:12":{"text":"If thy children will keep my covenant and my testimony that I shall teach them, their children shall also sit upon thy throne for evermore.","words":[["H1121","If thy children",0,15],["H8104","will keep",16,25],["H1285","my covenant",26,37],["H5713","and my testimony",38,54],["H2090","that",55,59],["H2097","that",55,59],["H3925","I shall teach",60,73],["H1121","them, their children",74,94],["H3427","shall also sit",95,109],["H3678","upon thy throne",110,125],["H5703","for evermore",126,138]]},"132:13":{"text":"For the LORD hath chosen Zion; he hath desired it for his habitation.","words":[["H3068","For the LORD",0,12],["H0977","hath chosen",13,24],["H6726","Zion",25,29],["H0183","he hath desired",31,46],["H4186","it for his habitation",47,68]]},"132:14":{"text":"This is my rest for ever: here will I dwell; for I have desired it.","words":[["H4496","This is my rest",0,15],["H5703","for ever",16,24],["H3427","here will I dwell",26,43],["H0183","for I have desired",45,63]]},"132:15":{"text":"I will abundantly bless her provision: I will satisfy her poor with bread.","words":[["H1288","I will abundantly",0,17],["H1288","bless",18,23],["H6718","her provision",24,37],["H7646","I will satisfy",39,53],["H0034","her poor",54,62],["H3899","with bread",63,73]]},"132:16":{"text":"I will also clothe her priests with salvation: and her saints shall shout aloud for joy.","words":[["H3847","I will also clothe",0,18],["H3548","her priests",19,30],["H3468","with salvation",31,45],["H2623","and her saints",47,61],["H7442","shall shout aloud",62,79],["H7444","for joy",80,87]]},"132:17":{"text":"There will I make the horn of David to bud: I have ordained a lamp for mine anointed.","words":[["H6779","There will I make",0,17],["H7161","the horn",18,26],["H1732","of David",27,35],["H6779","to bud",36,42],["H6186","I have ordained",44,59],["H5216","a lamp",60,66],["H4899","for mine anointed",67,84]]},"132:18":{"text":"His enemies will I clothe with shame: but upon himself shall his crown flourish.","words":[["H0341","His enemies",0,11],["H3847","will I clothe",12,25],["H1322","with shame",26,36],["H5145","but upon himself shall his crown",38,70],["H6692","flourish",71,79]]},"133:1":{"text":"A Song of degrees of David. Behold, how good and how pleasant it is for brethren to dwell together in unity!","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H1732","of David",18,26],["H2896","Behold, how good",28,44],["H5273","and how pleasant",45,61],["H0251","it is for brethren",62,80],["H3427","to dwell",81,89],["H3162","together",90,98],["H3162","in unity",99,107]]},"133:2":{"text":"It is like the precious ointment upon the head, that ran down upon the beard, even Aaron's beard: that went down to the skirts of his garments;","words":[["H2896","It is like the precious",0,23],["H8081","ointment",24,32],["H7218","upon the head",33,46],["H3381","that ran down",48,61],["H2206","upon the beard",62,76],["H0175","even Aaron's",78,90],["H2206","beard",91,96],["H3381","that went down",98,112],["H6310","to the skirts",113,126],["H4060","of his garments",127,142]]},"133:3":{"text":"As the dew of Hermon, and as the dew that descended upon the mountains of Zion: for there the LORD commanded the blessing, even life for evermore.","words":[["H2919","As the dew",0,10],["H2768","of Hermon",11,20],["H3381","and as the dew that descended",22,51],["H2042","upon the mountains",52,70],["H6726","of Zion",71,78],["H3068","for there the LORD",80,98],["H6680","commanded",99,108],["H1293","the blessing",109,121],["H2416","even life",123,132],["H5769","for evermore",133,145]]},"134:1":{"text":"A Song of degrees. Behold, bless ye the LORD, all ye servants of the LORD, which by night stand in the house of the LORD.","words":[["H7892","A Song",0,6],["H4609","of degrees",7,17],["H1288","Behold, bless",19,32],["H3068","ye the LORD",33,44],["H5650","all ye servants",46,61],["H3068","of the LORD",62,73],["H3915","which by night",75,89],["H5975","stand",90,95],["H1004","in the house",96,108],["H3068","of the LORD",109,120]]},"134:2":{"text":"Lift up your hands in the sanctuary, and bless the LORD.","words":[["H5375","Lift up",0,7],["H3027","your hands",8,18],["H6944","in the sanctuary",19,35],["H1288","and bless",37,46],["H3068","the LORD",47,55]]},"134:3":{"text":"The LORD that made heaven and earth bless thee out of Zion.","words":[["H3068","The LORD",0,8],["H6213","that made",9,18],["H8064","heaven",19,25],["H0776","and earth",26,35],["H1288","bless",36,41],["H6726","thee out of Zion",42,58]]},"135:1":{"text":"Praise ye the LORD. Praise ye the name of the LORD; praise him, O ye servants of the LORD.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H1984","Praise",20,26],["H8034","ye the name",27,38],["H3068","of the LORD",39,50],["H1984","praise",52,58],["H5650","him, O ye servants",59,77],["H3068","of the LORD",78,89]]},"135:2":{"text":"Ye that stand in the house of the LORD, in the courts of the house of our God,","words":[["H5975","Ye that stand",0,13],["H1004","in the house",14,26],["H3068","of the LORD",27,38],["H2691","in the courts",40,53],["H1004","of the house",54,66],["H0430","of our God",67,77]]},"135:3":{"text":"Praise the LORD; for the LORD is good: sing praises unto his name; for it is pleasant.","words":[["H1984","Praise",0,6],["H3050","the LORD",7,15],["H3068","for the LORD",17,29],["H2896","is good",30,37],["H2167","sing praises",39,51],["H8034","unto his name",52,65],["H5273","for it is pleasant",67,85]]},"135:4":{"text":"For the LORD hath chosen Jacob unto himself, and Israel for his peculiar treasure.","words":[["H3050","For the LORD",0,12],["H0977","hath chosen",13,24],["H3290","Jacob",25,30],["H3478","unto himself, and Israel",31,55],["H5459","for his peculiar treasure",56,81]]},"135:5":{"text":"For I know that the LORD is great, and that our Lord is above all gods.","words":[["H3045","For I know",0,10],["H3068","that the LORD",11,24],["H1419","is great",25,33],["H0113","and that our Lord",35,52],["H0430","is above all gods",53,70]]},"135:6":{"text":"Whatsoever the LORD pleased, that did he in heaven, and in earth, in the seas, and all deep places.","words":[["H3068","Whatsoever the LORD",0,19],["H2654","pleased",20,27],["H6213","that did",29,37],["H8064","he in heaven",38,50],["H0776","and in earth",52,64],["H3220","in the seas",66,77],["H8415","and all deep places",79,98]]},"135:7":{"text":"He causeth the vapours to ascend from the ends of the earth; he maketh lightnings for the rain; he bringeth the wind out of his treasuries.","words":[["H5387","He causeth the vapours",0,22],["H5927","to ascend",23,32],["H7097","from the ends",33,46],["H0776","of the earth",47,59],["H6213","he maketh",61,70],["H1300","lightnings",71,81],["H4306","for the rain",82,94],["H3318","he bringeth",96,107],["H7307","the wind",108,116],["H0214","out of his treasuries",117,138]]},"135:8":{"text":"Who smote the firstborn of Egypt, both of man and beast.","words":[["H5221","Who smote",0,9],["H1060","the firstborn",10,23],["H4714","of Egypt",24,32],["H0120","both of man",34,45],["H0929","and beast",46,55]]},"135:9":{"text":"Who sent tokens and wonders into the midst of thee, O Egypt, upon Pharaoh, and upon all his servants.","words":[["H7971","Who sent",0,8],["H0226","tokens",9,15],["H4159","and wonders",16,27],["H8432","into the midst",28,42],["H4714","of thee, O Egypt",43,59],["H6547","upon Pharaoh",61,73],["H5650","and upon all his servants",75,100]]},"135:10":{"text":"Who smote great nations, and slew mighty kings;","words":[["H5221","Who smote",0,9],["H7227","great",10,15],["H1471","nations",16,23],["H2026","and slew",25,33],["H6099","mighty",34,40],["H4428","kings",41,46]]},"135:11":{"text":"Sihon king of the Amorites, and Og king of Bashan, and all the kingdoms of Canaan:","words":[["H5511","Sihon",0,5],["H4428","king",6,10],["H0567","of the Amorites",11,26],["H5747","and Og",28,34],["H4428","king",35,39],["H1316","of Bashan",40,49],["H4467","and all the kingdoms",51,71],["H3667","of Canaan",72,81]]},"135:12":{"text":"And gave their land for an heritage, an heritage unto Israel his people.","words":[["H5414","And gave",0,8],["H0776","their land",9,19],["H5159","for an heritage",20,35],["H5159","an heritage",37,48],["H3478","unto Israel",49,60],["H5971","his people",61,71]]},"135:13":{"text":"Thy name, O LORD, endureth for ever; and thy memorial, O LORD, throughout all generations.","words":[["H8034","Thy name",0,8],["H3068","O LORD",10,16],["H5769","endureth for ever",18,35],["H2143","and thy memorial",37,53],["H3068","O LORD",55,61],["H1755","throughout all",63,77],["H1755","generations",78,89]]},"135:14":{"text":"For the LORD will judge his people, and he will repent himself concerning his servants.","words":[["H3068","For the LORD",0,12],["H1777","will judge",13,23],["H5971","his people",24,34],["H5162","and he will repent",36,54],["H5650","himself concerning his servants",55,86]]},"135:15":{"text":"The idols of the heathen are silver and gold, the work of men's hands.","words":[["H6091","The idols",0,9],["H1471","of the heathen",10,24],["H3701","are silver",25,35],["H2091","and gold",36,44],["H4639","the work",46,54],["H0120","of men's",55,63],["H3027","hands",64,69]]},"135:16":{"text":"They have mouths, but they speak not; eyes have they, but they see not;","words":[["H6310","They have mouths",0,16],["H1696","but they speak",18,32],["H5869","not; eyes",33,42],["H7200","have they, but they see",43,66]]},"135:17":{"text":"They have ears, but they hear not; neither is there any breath in their mouths.","words":[["H0241","They have ears",0,14],["H0238","but they hear",16,29],["H3426","not; neither is there",30,51],["H7307","any breath",52,62],["H6310","in their mouths",63,78]]},"135:18":{"text":"They that make them are like unto them: so is every one that trusteth in them.","words":[["H6213","They that make",0,14],["H0982","them are like unto them: so is every one that trusteth",15,69]]},"135:19":{"text":"Bless the LORD, O house of Israel: bless the LORD, O house of Aaron:","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H1004","O house",16,23],["H3478","of Israel",24,33],["H1288","bless",35,40],["H3068","the LORD",41,49],["H1004","O house",51,58],["H0175","of Aaron",59,67]]},"135:20":{"text":"Bless the LORD, O house of Levi: ye that fear the LORD, bless the LORD.","words":[["H1288","Bless",0,5],["H3068","the LORD",6,14],["H1004","O house",16,23],["H3878","of Levi",24,31],["H3373","ye that fear",33,45],["H3068","the LORD",46,54],["H1288","bless",56,61],["H3068","the LORD",62,70]]},"135:21":{"text":"Blessed be the LORD out of Zion, which dwelleth at Jerusalem. Praise ye the LORD.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H6726","out of Zion",20,31],["H7931","which dwelleth",33,47],["H3389","at Jerusalem",48,60],["H1984","Praise",62,68],["H3050","ye the LORD",69,80]]},"136:1":{"text":"O give thanks unto the LORD; for he is good: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H3068","unto the LORD",14,27],["H2896","for he is good",29,43],["H2617","for his mercy",45,58],["H5769","endureth for ever",59,76]]},"136:2":{"text":"O give thanks unto the God of gods: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H0430","unto the God",14,26],["H0430","of gods",27,34],["H2617","for his mercy",36,49],["H5769","endureth for ever",50,67]]},"136:3":{"text":"O give thanks to the Lord of lords: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H0113","to the Lord",14,25],["H0113","of lords",26,34],["H2617","for his mercy",36,49],["H5769","endureth for ever",50,67]]},"136:4":{"text":"To him who alone doeth great wonders: for his mercy endureth for ever.","words":[["H6213","To him who alone doeth",0,22],["H1419","great",23,28],["H6381","wonders",29,36],["H2617","for his mercy",38,51],["H5769","endureth for ever",52,69]]},"136:5":{"text":"To him that by wisdom made the heavens: for his mercy endureth for ever.","words":[["H8394","To him that by wisdom",0,21],["H6213","made",22,26],["H8064","the heavens",27,38],["H2617","for his mercy",40,53],["H5769","endureth for ever",54,71]]},"136:6":{"text":"To him that stretched out the earth above the waters: for his mercy endureth for ever.","words":[["H7554","To him that stretched out",0,25],["H0776","the earth",26,35],["H4325","above the waters",36,52],["H2617","for his mercy",54,67],["H5769","endureth for ever",68,85]]},"136:7":{"text":"To him that made great lights: for his mercy endureth for ever:","words":[["H6213","To him that made",0,16],["H1419","great",17,22],["H0216","lights",23,29],["H2617","for his mercy",31,44],["H5769","endureth for ever",45,62]]},"136:8":{"text":"The sun to rule by day: for his mercy endureth for ever:","words":[["H8121","The sun",0,7],["H4475","to rule",8,15],["H3117","by day",16,22],["H2617","for his mercy",24,37],["H5769","endureth for ever",38,55]]},"136:9":{"text":"The moon and stars to rule by night: for his mercy endureth for ever.","words":[["H3394","The moon",0,8],["H3556","and stars",9,18],["H4475","to rule",19,26],["H3915","by night",27,35],["H2617","for his mercy",37,50],["H5769","endureth for ever",51,68]]},"136:10":{"text":"To him that smote Egypt in their firstborn: for his mercy endureth for ever:","words":[["H5221","To him that smote",0,17],["H4714","Egypt",18,23],["H1060","in their firstborn",24,42],["H2617","for his mercy",44,57],["H5769","endureth for ever",58,75]]},"136:11":{"text":"And brought out Israel from among them: for his mercy endureth for ever:","words":[["H3318","And brought out",0,15],["H3478","Israel",16,22],["H8432","from among",23,33],["H2617","them: for his mercy",34,53],["H5769","endureth for ever",54,71]]},"136:12":{"text":"With a strong hand, and with a stretched out arm: for his mercy endureth for ever.","words":[["H2389","With a strong",0,13],["H3027","hand",14,18],["H5186","and with a stretched out",20,44],["H2220","arm",45,48],["H2617","for his mercy",50,63],["H5769","endureth for ever",64,81]]},"136:13":{"text":"To him which divided the Red sea into parts: for his mercy endureth for ever:","words":[["H1504","To him which divided",0,20],["H5488","the Red",21,28],["H3220","sea",29,32],["H1506","into parts",33,43],["H2617","for his mercy",45,58],["H5769","endureth for ever",59,76]]},"136:14":{"text":"And made Israel to pass through the midst of it: for his mercy endureth for ever:","words":[["H3478","And made Israel",0,15],["H5674","to pass through",16,31],["H8432","the midst",32,41],["H2617","of it: for his mercy",42,62],["H5769","endureth for ever",63,80]]},"136:15":{"text":"But overthrew Pharaoh and his host in the Red sea: for his mercy endureth for ever.","words":[["H5287","But overthrew",0,13],["H6547","Pharaoh",14,21],["H2428","and his host",22,34],["H5488","in the Red",35,45],["H3220","sea",46,49],["H2617","for his mercy",51,64],["H5769","endureth for ever",65,82]]},"136:16":{"text":"To him which led his people through the wilderness: for his mercy endureth for ever.","words":[["H3212","To him which led",0,16],["H5971","his people",17,27],["H4057","through the wilderness",28,50],["H2617","for his mercy",52,65],["H5769","endureth for ever",66,83]]},"136:17":{"text":"To him which smote great kings: for his mercy endureth for ever:","words":[["H5221","To him which smote",0,18],["H1419","great",19,24],["H4428","kings",25,30],["H2617","for his mercy",32,45],["H5769","endureth for ever",46,63]]},"136:18":{"text":"And slew famous kings: for his mercy endureth for ever:","words":[["H2026","And slew",0,8],["H0117","famous",9,15],["H4428","kings",16,21],["H2617","for his mercy",23,36],["H5769","endureth for ever",37,54]]},"136:19":{"text":"Sihon king of the Amorites: for his mercy endureth for ever:","words":[["H5511","Sihon",0,5],["H4428","king",6,10],["H0567","of the Amorites",11,26],["H2617","for his mercy",28,41],["H5769","endureth for ever",42,59]]},"136:20":{"text":"And Og the king of Bashan: for his mercy endureth for ever:","words":[["H5747","And Og",0,6],["H4428","the king",7,15],["H1316","of Bashan",16,25],["H2617","for his mercy",27,40],["H5769","endureth for ever",41,58]]},"136:21":{"text":"And gave their land for an heritage: for his mercy endureth for ever:","words":[["H5414","And gave",0,8],["H0776","their land",9,19],["H5159","for an heritage",20,35],["H2617","for his mercy",37,50],["H5769","endureth for ever",51,68]]},"136:22":{"text":"Even an heritage unto Israel his servant: for his mercy endureth for ever.","words":[["H5159","Even an heritage",0,16],["H3478","unto Israel",17,28],["H5650","his servant",29,40],["H2617","for his mercy",42,55],["H5769","endureth for ever",56,73]]},"136:23":{"text":"Who remembered us in our low estate: for his mercy endureth for ever:","words":[["H2142","Who remembered",0,14],["H8216","us in our low estate",15,35],["H2617","for his mercy",37,50],["H5769","endureth for ever",51,68]]},"136:24":{"text":"And hath redeemed us from our enemies: for his mercy endureth for ever.","words":[["H6561","And hath redeemed",0,17],["H6862","us from our enemies",18,37],["H2617","for his mercy",39,52],["H5769","endureth for ever",53,70]]},"136:25":{"text":"Who giveth food to all flesh: for his mercy endureth for ever.","words":[["H5414","Who giveth",0,10],["H3899","food",11,15],["H1320","to all flesh",16,28],["H2617","for his mercy",30,43],["H5769","endureth for ever",44,61]]},"136:26":{"text":"O give thanks unto the God of heaven: for his mercy endureth for ever.","words":[["H3034","O give thanks",0,13],["H0410","unto the God",14,26],["H8064","of heaven",27,36],["H2617","for his mercy",38,51],["H5769","endureth for ever",52,69]]},"137:1":{"text":"By the rivers of Babylon, there we sat down, yea, we wept, when we remembered Zion.","words":[["H5104","By the rivers",0,13],["H0894","of Babylon",14,24],["H3427","there we sat down",26,43],["H1058","yea, we wept",45,57],["H2142","when we remembered",59,77],["H6726","Zion",78,82]]},"137:2":{"text":"We hanged our harps upon the willows in the midst thereof.","words":[["H8518","We hanged",0,9],["H3658","our harps",10,19],["H6155","upon the willows",20,36],["H8432","in the midst",37,49]]},"137:3":{"text":"For there they that carried us away captive required of us a song; and they that wasted us required of us mirth, saying, Sing us one of the songs of Zion.","words":[["H7617","For there they that carried us away captive",0,43],["H7592","required",44,52],["H1697","of us a song",53,65],["H7892","of us a song",53,65],["H8437","and they that wasted",67,87],["H8057","us required of us mirth",88,111],["H7891","saying, Sing",113,125],["H7892","us one of the songs",126,145],["H6726","of Zion",146,153]]},"137:4":{"text":"How shall we sing the LORD'S song in a strange land?","words":[["H7891","How shall we sing",0,17],["H3068","the LORD'S",18,28],["H7892","song",29,33],["H5236","in a strange",34,46],["H0127","land",47,51]]},"137:5":{"text":"If I forget thee, O Jerusalem, let my right hand forget her cunning.","words":[["H7911","If I forget",0,11],["H3389","thee, O Jerusalem",12,29],["H3225","let my right hand",31,48],["H7911","forget",49,55]]},"137:6":{"text":"If I do not remember thee, let my tongue cleave to the roof of my mouth; if I prefer not Jerusalem above my chief joy.","words":[["H2142","If I do not remember",0,20],["H3956","thee, let my tongue",21,40],["H1692","cleave",41,47],["H2441","to the roof of my mouth",48,71],["H5927","if I prefer",73,84],["H3389","not Jerusalem",85,98],["H7218","above my chief",99,113],["H8057","joy",114,117]]},"137:7":{"text":"Remember, O LORD, the children of Edom in the day of Jerusalem; who said, Rase it, rase it, even to the foundation thereof.","words":[["H2142","Remember",0,8],["H3068","O LORD",10,16],["H1121","the children",18,30],["H0123","of Edom",31,38],["H3117","in the day",39,49],["H3389","of Jerusalem",50,62],["H0559","who said",64,72],["H6168","Rase",74,78],["H6168","it, rase",79,87],["H3247","it, even to the foundation",88,114]]},"137:8":{"text":"O daughter of Babylon, who art to be destroyed; happy shall he be, that rewardeth thee as thou hast served us.","words":[["H1323","O daughter",0,10],["H0894","of Babylon",11,21],["H7703","who art to be destroyed",23,46],["H0835","happy",48,53],["H7999","shall he be, that rewardeth",54,81],["H1580","thee as thou hast served",82,106],["H1576","thee as thou hast served",82,106]]},"137:9":{"text":"Happy shall he be, that taketh and dasheth thy little ones against the stones.","words":[["H0835","Happy",0,5],["H0270","shall he be, that taketh",6,30],["H5310","and dasheth",31,42],["H5768","thy little ones",43,58],["H5553","against the stones",59,77]]},"138:1":{"text":"A Psalm of David. I will praise thee with my whole heart: before the gods will I sing praise unto thee.","words":[["H1732","A Psalm of David",0,16],["H3034","I will praise",18,31],["H3820","thee with my whole heart",32,56],["H0430","before the gods",58,73],["H2167","will I sing praise",74,92]]},"138:2":{"text":"I will worship toward thy holy temple, and praise thy name for thy lovingkindness and for thy truth: for thou hast magnified thy word above all thy name.","words":[["H7812","I will worship",0,14],["H6944","toward thy holy",15,30],["H1964","temple",31,37],["H3034","and praise",39,49],["H8034","thy name",50,58],["H2617","for thy lovingkindness",59,81],["H0571","and for thy truth",82,99],["H1431","for thou hast magnified",101,124],["H0565","thy word",125,133],["H8034","above all thy name",134,152]]},"138:3":{"text":"In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul.","words":[["H3117","In the day",0,10],["H7121","when I cried",11,23],["H6030","thou answeredst",24,39],["H7292","me, and strengthenedst",40,62],["H5797","me with strength",63,79],["H5315","in my soul",80,90]]},"138:4":{"text":"All the kings of the earth shall praise thee, O LORD, when they hear the words of thy mouth.","words":[["H4428","All the kings",0,13],["H0776","of the earth",14,26],["H3034","shall praise",27,39],["H3068","thee, O LORD",40,52],["H8085","when they hear",54,68],["H0561","the words",69,78],["H6310","of thy mouth",79,91]]},"138:5":{"text":"Yea, they shall sing in the ways of the LORD: for great is the glory of the LORD.","words":[["H7891","Yea, they shall sing",0,20],["H1870","in the ways",21,32],["H3068","of the LORD",33,44],["H1419","for great",46,55],["H3519","is the glory",56,68],["H3068","of the LORD",69,80]]},"138:6":{"text":"Though the LORD be high, yet hath he respect unto the lowly: but the proud he knoweth afar off.","words":[["H3068","Though the LORD",0,15],["H7311","be high",16,23],["H7200","yet hath he respect",25,44],["H8217","unto the lowly",45,59],["H1364","but the proud",61,74],["H3045","he knoweth",75,85],["H4801","afar off",86,94]]},"138:7":{"text":"Though I walk in the midst of trouble, thou wilt revive me: thou shalt stretch forth thine hand against the wrath of mine enemies, and thy right hand shall save me.","words":[["H3212","Though I walk",0,13],["H7130","in the midst",14,26],["H6869","of trouble",27,37],["H2421","thou wilt revive",39,55],["H7971","me: thou shalt stretch forth",56,84],["H3027","thine hand",85,95],["H0639","against the wrath",96,113],["H0341","of mine enemies",114,129],["H3225","and thy right hand",131,149],["H3467","shall save",150,160]]},"138:8":{"text":"The LORD will perfect that which concerneth me: thy mercy, O LORD, endureth for ever: forsake not the works of thine own hands.","words":[["H3068","The LORD",0,8],["H1584","will perfect",9,21],["H2617","that which concerneth me: thy mercy",22,57],["H3068","O LORD",59,65],["H5769","endureth for ever",67,84],["H7503","forsake",86,93],["H4639","not the works",94,107],["H3027","of thine own hands",108,126]]},"139:1":{"text":"To the chief Musician, A Psalm of David. O LORD, thou hast searched me, and known me.","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H3068","O LORD",41,47],["H2713","thou hast searched",49,67],["H3045","me, and known",68,81]]},"139:2":{"text":"Thou knowest my downsitting and mine uprising, thou understandest my thought afar off.","words":[["H3045","Thou knowest",0,12],["H3427","my downsitting",13,27],["H6965","and mine uprising",28,45],["H0995","thou understandest",47,65],["H7454","my thought",66,76],["H7350","afar off",77,85]]},"139:3":{"text":"Thou compassest my path and my lying down, and art acquainted with all my ways.","words":[["H2219","Thou compassest",0,15],["H0734","my path",16,23],["H7252","and my lying down",24,41],["H5532","and art acquainted",43,61],["H1870","with all my ways",62,78]]},"139:4":{"text":"For there is not a word in my tongue, but, lo, O LORD, thou knowest it altogether.","words":[["H4405","For there is not a word",0,23],["H3956","in my tongue",24,36],["H3068","but, lo, O LORD",38,53],["H3045","thou knowest",55,67]]},"139:5":{"text":"Thou hast beset me behind and before, and laid thine hand upon me.","words":[["H6696","Thou hast beset",0,15],["H0268","me behind",16,25],["H6924","and before",26,36],["H7896","and laid",38,46],["H3709","thine hand",47,57]]},"139:6":{"text":"Such knowledge is too wonderful for me; it is high, I cannot attain unto it.","words":[["H1847","Such knowledge",0,14],["H6383","is too wonderful",15,31],["H6383","is too wonderful",15,31],["H7682","for me; it is high",32,50],["H3201","I cannot",52,60]]},"139:7":{"text":"Whither shall I go from thy spirit? or whither shall I flee from thy presence?","words":[["H3212","Whither shall I go",0,18],["H7307","from thy spirit",19,34],["H1272","or whither shall I flee",36,59],["H6440","from thy presence",60,77]]},"139:8":{"text":"If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there.","words":[["H5266","If I ascend up",0,14],["H8064","into heaven",15,26],["H3331","thou art there: if I make my bed",28,60],["H7585","in hell",61,68]]},"139:9":{"text":"If I take the wings of the morning, and dwell in the uttermost parts of the sea;","words":[["H5375","If I take",0,9],["H3671","the wings",10,19],["H7837","of the morning",20,34],["H7931","and dwell",36,45],["H0319","in the uttermost parts",46,68],["H3220","of the sea",69,79]]},"139:10":{"text":"Even there shall thy hand lead me, and thy right hand shall hold me.","words":[["H3027","Even there shall thy hand",0,25],["H5148","lead",26,30],["H3225","me, and thy right hand",31,53],["H0270","shall hold",54,64]]},"139:11":{"text":"If I say, Surely the darkness shall cover me; even the night shall be light about me.","words":[["H0559","If I say",0,8],["H2822","Surely the darkness",10,29],["H7779","shall cover",30,41],["H3915","me; even the night",42,60],["H0216","shall be light",61,75],["H1157","about me",76,84]]},"139:12":{"text":"Yea, the darkness hideth not from thee; but the night shineth as the day: the darkness and the light are both alike to thee.","words":[["H2822","Yea, the darkness",0,17],["H2821","hideth",18,24],["H3915","not from thee; but the night",25,53],["H0215","shineth",54,61],["H3117","as the day",62,72],["H2825","the darkness",74,86],["H0219","and the light",87,100]]},"139:13":{"text":"For thou hast possessed my reins: thou hast covered me in my mother's womb.","words":[["H7069","For thou hast possessed",0,23],["H3629","my reins",24,32],["H5526","thou hast covered",34,51],["H0517","me in my mother's",52,69],["H0990","womb",70,74]]},"139:14":{"text":"I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well.","words":[["H3034","I will praise",0,13],["H3372","thee; for I am fearfully",14,38],["H6395","and wonderfully made",39,59],["H6381","marvellous",61,71],["H4639","are thy works",72,85],["H5315","and that my soul",87,103],["H3045","knoweth",104,111],["H3966","right well",112,122]]},"139:15":{"text":"My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth.","words":[["H6108","My substance",0,12],["H3582","was not hid",13,24],["H6213","from thee, when I was made",25,51],["H5643","in secret",52,61],["H7551","and curiously wrought",63,84],["H8482","in the lowest parts",85,104],["H0776","of the earth",105,117]]},"139:16":{"text":"Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them.","words":[["H5869","Thine eyes",0,10],["H7200","did see",11,18],["H1564","my substance, yet being unperfect",19,52],["H5612","and in thy book",54,69],["H3789","all my members were written",70,97],["H3117","which in continuance",99,119],["H3335","were fashioned",120,134],["H0259","when as yet there was none",136,162]]},"139:17":{"text":"How precious also are thy thoughts unto me, O God! how great is the sum of them!","words":[["H3365","How precious",0,12],["H7454","also are thy thoughts",13,34],["H0410","unto me, O God",35,49],["H6105","how great",51,60],["H7218","is the sum",61,71]]},"139:18":{"text":"If I should count them, they are more in number than the sand: when I awake, I am still with thee.","words":[["H5608","If I should count",0,17],["H7235","them, they are more in number",18,47],["H2344","than the sand",48,61],["H6974","when I awake",63,75],["H5750","I am still",77,87]]},"139:19":{"text":"Surely thou wilt slay the wicked, O God: depart from me therefore, ye bloody men.","words":[["H6991","Surely thou wilt slay",0,21],["H7563","the wicked",22,32],["H0433","O God",34,39],["H5493","depart",41,47],["H1818","from me therefore, ye bloody",48,76],["H0582","men",77,80]]},"139:20":{"text":"For they speak against thee wickedly, and thine enemies take thy name in vain.","words":[["H0559","For they speak",0,14],["H4209","against thee wickedly",15,36],["H6145","and thine enemies",38,55],["H5375","take",56,60],["H7723","thy name in vain",61,77]]},"139:21":{"text":"Do not I hate them, O LORD, that hate thee? and am not I grieved with those that rise up against thee?","words":[["H8130","Do not I hate",0,13],["H3068","them, O LORD",14,26],["H8130","that hate",28,37],["H6962","thee? and am not I grieved",38,64],["H8618","with those that rise up",65,88]]},"139:22":{"text":"I hate them with perfect hatred: I count them mine enemies.","words":[["H8130","I hate",0,6],["H8503","them with perfect",7,24],["H8135","hatred",25,31],["H0341","I count them mine enemies",33,58]]},"139:23":{"text":"Search me, O God, and know my heart: try me, and know my thoughts:","words":[["H2713","Search",0,6],["H0410","me, O God",7,16],["H3045","and know",18,26],["H3824","my heart",27,35],["H0974","try",37,40],["H3045","me, and know",41,53],["H8312","my thoughts",54,65]]},"139:24":{"text":"And see if there be any wicked way in me, and lead me in the way everlasting.","words":[["H7200","And see",0,7],["H6090","if there be any wicked",8,30],["H1870","way",31,34],["H5148","in me, and lead",35,50],["H1870","me in the way",51,64],["H5769","everlasting",65,76]]},"140:1":{"text":"To the chief Musician, A Psalm of David. Deliver me, O LORD, from the evil man: preserve me from the violent man;","words":[["H5329","To the chief Musician",0,21],["H4210","A Psalm",23,30],["H1732","of David",31,39],["H2502","Deliver",41,48],["H3068","me, O LORD",49,59],["H7451","from the evil",61,74],["H0120","man",75,78],["H5341","preserve",80,88],["H2555","me from the violent",89,108],["H0376","man",109,112]]},"140:2":{"text":"Which imagine mischiefs in their heart; continually are they gathered together for war.","words":[["H2803","Which imagine",0,13],["H7451","mischiefs",14,23],["H3820","in their heart",24,38],["H3117","continually",40,51],["H1481","are they gathered together",52,78],["H4421","for war",79,86]]},"140:3":{"text":"They have sharpened their tongues like a serpent; adders' poison is under their lips. Selah.","words":[["H8150","They have sharpened",0,19],["H3956","their tongues",20,33],["H5175","like a serpent",34,48],["H5919","adders'",50,57],["H2534","poison",58,64],["H8193","is under their lips",65,84],["H5542","Selah",86,91]]},"140:4":{"text":"Keep me, O LORD, from the hands of the wicked; preserve me from the violent man; who have purposed to overthrow my goings.","words":[["H8104","Keep",0,4],["H3068","me, O LORD",5,15],["H3027","from the hands",17,31],["H7563","of the wicked",32,45],["H5341","preserve",47,55],["H2555","me from the violent",56,75],["H0376","man",76,79],["H2803","who have purposed",81,98],["H1760","to overthrow",99,111],["H6471","my goings",112,121]]},"140:5":{"text":"The proud have hid a snare for me, and cords; they have spread a net by the wayside; they have set gins for me. Selah.","words":[["H1343","The proud",0,9],["H2934","have hid",10,18],["H6341","a snare",19,26],["H2256","for me, and cords",27,44],["H6566","they have spread",46,62],["H7568","a net",63,68],["H3027","by the wayside",69,83],["H4570","by the wayside",69,83],["H7896","they have set",85,98],["H4170","gins",99,103],["H5542","for me. Selah",104,117]]},"140:6":{"text":"I said unto the LORD, Thou art my God: hear the voice of my supplications, O LORD.","words":[["H0559","I said",0,6],["H3068","unto the LORD",7,20],["H0410","Thou art my God",22,37],["H0238","hear",39,43],["H6963","the voice",44,53],["H8469","of my supplications",54,73],["H3068","O LORD",75,81]]},"140:7":{"text":"O GOD the Lord, the strength of my salvation, thou hast covered my head in the day of battle.","words":[["H3069","O GOD",0,5],["H0136","the Lord",6,14],["H5797","the strength",16,28],["H3444","of my salvation",29,44],["H5526","thou hast covered",46,63],["H7218","my head",64,71],["H3117","in the day",72,82],["H5402","of battle",83,92]]},"140:8":{"text":"Grant not, O LORD, the desires of the wicked: further not his wicked device; lest they exalt themselves. Selah.","words":[["H5414","Grant",0,5],["H3068","not, O LORD",6,17],["H3970","the desires",19,30],["H7563","of the wicked",31,44],["H6329","further",46,53],["H2162","not his wicked device",54,75],["H7311","lest they exalt",77,92],["H5542","themselves. Selah",93,110]]},"140:9":{"text":"As for the head of those that compass me about, let the mischief of their own lips cover them.","words":[["H7218","As for the head",0,15],["H4524","of those that compass me about",16,46],["H5999","let the mischief",48,64],["H8193","of their own lips",65,82],["H3680","cover",83,88]]},"140:10":{"text":"Let burning coals fall upon them: let them be cast into the fire; into deep pits, that they rise not up again.","words":[["H1513","Let burning coals",0,17],["H4131","fall",18,22],["H4131","fall",18,22],["H5307","upon them: let them be cast",23,50],["H0784","into the fire",51,64],["H4113","into deep pits",66,80],["H6965","that they rise not up again",82,109]]},"140:11":{"text":"Let not an evil speaker be established in the earth: evil shall hunt the violent man to overthrow him.","words":[["H0376","Let not an evil speaker",0,23],["H3956","Let not an evil speaker",0,23],["H3559","be established",24,38],["H0776","in the earth",39,51],["H7451","evil",53,57],["H6679","shall hunt",58,68],["H2555","the violent",69,80],["H0376","man",81,84],["H4073","to overthrow",85,97]]},"140:12":{"text":"I know that the LORD will maintain the cause of the afflicted, and the right of the poor.","words":[["H3045","I know",0,6],["H3068","that the LORD",7,20],["H6213","will maintain",21,34],["H1779","the cause",35,44],["H6041","of the afflicted",45,61],["H4941","and the right",63,76],["H0034","of the poor",77,88]]},"140:13":{"text":"Surely the righteous shall give thanks unto thy name: the upright shall dwell in thy presence.","words":[["H6662","Surely the righteous",0,20],["H3034","shall give thanks",21,38],["H8034","unto thy name",39,52],["H3477","the upright",54,65],["H3427","shall dwell",66,77],["H6440","in thy presence",78,93]]},"141:1":{"text":"A Psalm of David. LORD, I cry unto thee: make haste unto me; give ear unto my voice, when I cry unto thee.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H3068","LORD",18,22],["H7121","I cry",24,29],["H2363","unto thee: make haste",30,51],["H0238","unto me; give ear",52,69],["H6963","unto my voice",70,83],["H7121","when I cry",85,95]]},"141:2":{"text":"Let my prayer be set forth before thee as incense; and the lifting up of my hands as the evening sacrifice.","words":[["H8605","Let my prayer",0,13],["H3559","be set forth",14,26],["H6440","before",27,33],["H7004","thee as incense",34,49],["H4864","and the lifting up",51,69],["H3709","of my hands",70,81],["H6153","as the evening",82,96],["H4503","sacrifice",97,106]]},"141:3":{"text":"Set a watch, O LORD, before my mouth; keep the door of my lips.","words":[["H7896","Set",0,3],["H8108","a watch",4,11],["H3068","O LORD",13,19],["H6310","before my mouth",21,36],["H5341","keep",38,42],["H1817","the door",43,51],["H8193","of my lips",52,62]]},"141:4":{"text":"Incline not my heart to any evil thing, to practise wicked works with men that work iniquity: and let me not eat of their dainties.","words":[["H5186","Incline",0,7],["H3820","not my heart",8,20],["H7451","to any evil",21,32],["H1697","thing",33,38],["H5953","to practise",40,51],["H7562","wicked",52,58],["H5949","works",59,64],["H0376","with men",65,73],["H6466","that work",74,83],["H0205","iniquity",84,92],["H3898","and let me not eat",94,112],["H4516","of their dainties",113,130]]},"141:5":{"text":"Let the righteous smite me; it shall be a kindness: and let him reprove me; it shall be an excellent oil, which shall not break my head: for yet my prayer also shall be in their calamities.","words":[["H6662","Let the righteous",0,17],["H1986","smite",18,23],["H2617","me; it shall be a kindness",24,50],["H3198","and let him reprove",52,71],["H7218","me; it shall be an excellent",72,100],["H8081","oil",101,104],["H5106","which shall not break",106,127],["H7218","my head",128,135],["H8605","for yet my prayer",137,154],["H7451","also shall be in their calamities",155,188]]},"141:6":{"text":"When their judges are overthrown in stony places, they shall hear my words; for they are sweet.","words":[["H8199","When their judges",0,17],["H8058","are overthrown",18,32],["H5553","in stony",33,41],["H3027","places",42,48],["H8085","they shall hear",50,65],["H0561","my words",66,74],["H5276","for they are sweet",76,94]]},"141:7":{"text":"Our bones are scattered at the grave's mouth, as when one cutteth and cleaveth wood upon the earth.","words":[["H6106","Our bones",0,9],["H6340","are scattered",10,23],["H7585","at the grave's",24,38],["H6310","mouth",39,44],["H6398","as when one cutteth",46,65],["H1234","and cleaveth",66,78],["H0776","wood upon the earth",79,98]]},"141:8":{"text":"But mine eyes are unto thee, O GOD the Lord: in thee is my trust; leave not my soul destitute.","words":[["H5869","But mine eyes",0,13],["H3069","are unto thee, O GOD",14,34],["H0136","the Lord",35,43],["H2620","in thee is my trust",45,64],["H6168","leave",66,71],["H5315","not my soul",72,83],["H6168","destitute",84,93]]},"141:9":{"text":"Keep me from the snares which they have laid for me, and the gins of the workers of iniquity.","words":[["H8104","Keep",0,4],["H3027","me from the snares",5,23],["H6341","me from the snares",5,23],["H3369","which they have laid",24,44],["H4170","for me, and the gins",45,65],["H6466","of the workers",66,80],["H0205","of iniquity",81,92]]},"141:10":{"text":"Let the wicked fall into their own nets, whilst that I withal escape.","words":[["H7563","Let the wicked",0,14],["H5307","fall",15,19],["H4364","into their own nets",20,39],["H3162","whilst that I withal",41,61],["H5674","escape",62,68]]},"142:1":{"text":"Maschil of David; A Prayer when he was in the cave. I cried unto the LORD with my voice; with my voice unto the LORD did I make my supplication.","words":[["H4905","Maschil",0,7],["H1732","of David",8,16],["H8605","A Prayer",18,26],["H4631","when he was in the cave",27,50],["H2199","I cried",52,59],["H3068","unto the LORD",60,73],["H6963","with my voice",74,87],["H6963","with my voice",89,102],["H3068","unto the LORD",103,116],["H2603","did I make my supplication",117,143]]},"142:2":{"text":"I poured out my complaint before him; I shewed before him my trouble.","words":[["H8210","I poured out",0,12],["H7879","my complaint",13,25],["H6440","before",26,32],["H5046","him; I shewed",33,46],["H6440","before",47,53],["H6869","him my trouble",54,68]]},"142:3":{"text":"When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me.","words":[["H7307","When my spirit",0,14],["H5848","was overwhelmed",15,30],["H3045","within me, then thou knewest",31,59],["H5410","my path",60,67],["H0734","In the way",69,79],["H2098","wherein",80,87],["H1980","I walked",88,96],["H2934","have they privily laid",97,119],["H6341","a snare",120,127]]},"142:4":{"text":"I looked on my right hand, and beheld, but there was no man that would know me: refuge failed me; no man cared for my soul.","words":[["H5027","I looked",0,8],["H3225","on my right hand",9,25],["H7200","and beheld",27,37],["H5234","but there was no man that would know",39,75],["H4498","me: refuge",76,86],["H0006","failed",87,93],["H1875","me; no man cared",94,110],["H5315","for my soul",111,122]]},"142:5":{"text":"I cried unto thee, O LORD: I said, Thou art my refuge and my portion in the land of the living.","words":[["H2199","I cried",0,7],["H3068","unto thee, O LORD",8,25],["H0559","I said",27,33],["H4268","Thou art my refuge",35,53],["H2506","and my portion",54,68],["H0776","in the land",69,80],["H2416","of the living",81,94]]},"142:6":{"text":"Attend unto my cry; for I am brought very low: deliver me from my persecutors; for they are stronger than I.","words":[["H7181","Attend",0,6],["H7440","unto my cry",7,18],["H1809","for I am brought",20,36],["H3966","very",37,41],["H1809","low",42,45],["H5337","deliver",47,54],["H7291","me from my persecutors",55,77],["H0553","for they are stronger",79,100]]},"142:7":{"text":"Bring my soul out of prison, that I may praise thy name: the righteous shall compass me about; for thou shalt deal bountifully with me.","words":[["H3318","Bring",0,5],["H5315","my soul",6,13],["H4525","out of prison",14,27],["H3034","that I may praise",29,46],["H8034","thy name",47,55],["H6662","the righteous",57,70],["H3803","shall compass me about",71,93],["H1580","for thou shalt deal bountifully",95,126]]},"143:1":{"text":"A Psalm of David. Hear my prayer, O LORD, give ear to my supplications: in thy faithfulness answer me, and in thy righteousness.","words":[["H4210","A Psalm",0,7],["H1732","of David",8,16],["H8085","Hear",18,22],["H8605","my prayer",23,32],["H3068","O LORD",34,40],["H0238","give ear",42,50],["H8469","to my supplications",51,70],["H0530","in thy faithfulness",72,91],["H6030","answer",92,98],["H6666","me, and in thy righteousness",99,127]]},"143:2":{"text":"And enter not into judgment with thy servant: for in thy sight shall no man living be justified.","words":[["H0935","And enter",0,9],["H4941","not into judgment",10,27],["H5650","with thy servant",28,44],["H6440","for in thy sight",46,62],["H2416","shall no man living",63,82],["H6663","be justified",83,95]]},"143:3":{"text":"For the enemy hath persecuted my soul; he hath smitten my life down to the ground; he hath made me to dwell in darkness, as those that have been long dead.","words":[["H0341","For the enemy",0,13],["H7291","hath persecuted",14,29],["H5315","my soul",30,37],["H1792","he hath smitten",39,54],["H2416","my life",55,62],["H1792","down",63,67],["H0776","to the ground",68,81],["H3427","he hath made me to dwell",83,107],["H4285","in darkness",108,119],["H5769","as those that have been long",121,149],["H4191","dead",150,154]]},"143:4":{"text":"Therefore is my spirit overwhelmed within me; my heart within me is desolate.","words":[["H7307","Therefore is my spirit",0,22],["H5848","overwhelmed",23,34],["H3820","within me; my heart",35,54],["H8432","within",55,61],["H8074","me is desolate",62,76]]},"143:5":{"text":"I remember the days of old; I meditate on all thy works; I muse on the work of thy hands.","words":[["H2142","I remember",0,10],["H3117","the days",11,19],["H6924","of old",20,26],["H1897","I meditate",28,38],["H6467","on all thy works",39,55],["H7878","I muse",57,63],["H4639","on the work",64,75],["H3027","of thy hands",76,88]]},"143:6":{"text":"I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah.","words":[["H6566","I stretch forth",0,15],["H3027","my hands",16,24],["H5315","unto thee: my soul",25,43],["H5889","thirsteth after thee, as a thirsty",44,78],["H0776","land",79,83],["H5542","Selah",85,90]]},"143:7":{"text":"Hear me speedily, O LORD: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit.","words":[["H6030","Hear",0,4],["H4118","me speedily",5,16],["H3068","O LORD",18,24],["H7307","my spirit",26,35],["H3615","faileth",36,43],["H5641","hide",45,49],["H6440","not thy face",50,62],["H4911","from me, lest I be like",63,86],["H3381","unto them that go down",87,109],["H0953","into the pit",110,122]]},"143:8":{"text":"Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee.","words":[["H8085","Cause me to hear",0,16],["H2617","thy lovingkindness",17,35],["H1242","in the morning",36,50],["H0982","for in thee do I trust",52,74],["H3045","cause me to know",76,92],["H1870","the way",93,100],["H2098","wherein",101,108],["H3212","I should walk",109,122],["H5375","for I lift up",124,137],["H5315","my soul",138,145]]},"143:9":{"text":"Deliver me, O LORD, from mine enemies: I flee unto thee to hide me.","words":[["H5337","Deliver",0,7],["H3068","me, O LORD",8,18],["H0341","from mine enemies",20,37],["H3680","I flee unto thee to hide",39,63]]},"143:10":{"text":"Teach me to do thy will; for thou art my God: thy spirit is good; lead me into the land of uprightness.","words":[["H3925","Teach",0,5],["H6213","me to do",6,14],["H7522","thy will",15,23],["H0430","for thou art my God",25,44],["H7307","thy spirit",46,56],["H2896","is good",57,64],["H5148","lead",66,70],["H0776","me into the land",71,87],["H4334","of uprightness",88,102]]},"143:11":{"text":"Quicken me, O LORD, for thy name's sake: for thy righteousness' sake bring my soul out of trouble.","words":[["H2421","Quicken",0,7],["H3068","me, O LORD",8,18],["H8034","for thy name's",20,34],["H6666","sake: for thy righteousness'",35,63],["H3318","sake bring",64,74],["H5315","my soul",75,82],["H6869","out of trouble",83,97]]},"143:12":{"text":"And of thy mercy cut off mine enemies, and destroy all them that afflict my soul: for I am thy servant.","words":[["H2617","And of thy mercy",0,16],["H6789","cut off",17,24],["H0341","mine enemies",25,37],["H0006","and destroy",39,50],["H6887","all them that afflict",51,72],["H5315","my soul",73,80],["H5650","for I am thy servant",82,102]]},"144:1":{"text":"A Psalm of David. Blessed be the LORD my strength, which teacheth my hands to war, and my fingers to fight:","words":[["H1732","A Psalm of David",0,16],["H1288","Blessed",18,25],["H3068","be the LORD",26,37],["H6697","my strength",38,49],["H3925","which teacheth",51,65],["H3027","my hands",66,74],["H7128","to war",75,81],["H0676","and my fingers",83,97],["H4421","to fight",98,106]]},"144:2":{"text":"My goodness, and my fortress; my high tower, and my deliverer; my shield, and he in whom I trust; who subdueth my people under me.","words":[["H2617","My goodness",0,11],["H4686","and my fortress",13,28],["H4869","my high tower",30,43],["H6403","and my deliverer",45,61],["H4043","my shield",63,72],["H2620","and he in whom I trust",74,96],["H7286","who subdueth",98,110],["H5971","my people",111,120]]},"144:3":{"text":"LORD, what is man, that thou takest knowledge of him! or the son of man, that thou makest account of him!","words":[["H3068","LORD",0,4],["H0120","what is man",6,17],["H3045","that thou takest knowledge",19,45],["H1121","of him! or the son",46,64],["H0582","of man",65,71],["H2803","that thou makest account",73,97]]},"144:4":{"text":"Man is like to vanity: his days are as a shadow that passeth away.","words":[["H0120","Man",0,3],["H1819","is like",4,11],["H1892","to vanity",12,21],["H3117","his days",23,31],["H6738","are as a shadow",32,47],["H5674","that passeth away",48,65]]},"144:5":{"text":"Bow thy heavens, O LORD, and come down: touch the mountains, and they shall smoke.","words":[["H5186","Bow",0,3],["H8064","thy heavens",4,15],["H3068","O LORD",17,23],["H3381","and come down",25,38],["H5060","touch",40,45],["H2022","the mountains",46,59],["H6225","and they shall smoke",61,81]]},"144:6":{"text":"Cast forth lightning, and scatter them: shoot out thine arrows, and destroy them.","words":[["H1299","Cast forth",0,10],["H1300","lightning",11,20],["H6327","and scatter",22,33],["H7971","them: shoot out",34,49],["H2671","thine arrows",50,62],["H2000","and destroy",64,75]]},"144:7":{"text":"Send thine hand from above; rid me, and deliver me out of great waters, from the hand of strange children;","words":[["H7971","Send",0,4],["H3027","thine hand",5,15],["H4791","from above",16,26],["H6475","rid",28,31],["H5337","me, and deliver",32,47],["H7227","me out of great",48,63],["H4325","waters",64,70],["H3027","from the hand",72,85],["H5236","of strange",86,96],["H1121","children",97,105]]},"144:8":{"text":"Whose mouth speaketh vanity, and their right hand is a right hand of falsehood.","words":[["H6310","Whose mouth",0,11],["H1696","speaketh",12,20],["H7723","vanity",21,27],["H3225","and their right hand",29,49],["H3225","is a right hand",50,65],["H8267","of falsehood",66,78]]},"144:9":{"text":"I will sing a new song unto thee, O God: upon a psaltery and an instrument of ten strings will I sing praises unto thee.","words":[["H7891","I will sing",0,11],["H2319","a new",12,17],["H7892","song",18,22],["H0430","unto thee, O God",23,39],["H5035","upon a psaltery",41,56],["H6218","and an instrument of ten strings",57,89],["H2167","will I sing praises",90,109]]},"144:10":{"text":"It is he that giveth salvation unto kings: who delivereth David his servant from the hurtful sword.","words":[["H5414","It is he that giveth",0,20],["H8668","salvation",21,30],["H4428","unto kings",31,41],["H6475","who delivereth",43,57],["H1732","David",58,63],["H5650","his servant",64,75],["H7451","from the hurtful",76,92],["H2719","sword",93,98]]},"144:11":{"text":"Rid me, and deliver me from the hand of strange children, whose mouth speaketh vanity, and their right hand is a right hand of falsehood:","words":[["H6475","Rid",0,3],["H5337","me, and deliver",4,19],["H3027","me from the hand",20,36],["H5236","of strange",37,47],["H1121","children",48,56],["H6310","whose mouth",58,69],["H1696","speaketh",70,78],["H7723","vanity",79,85],["H3225","and their right hand",87,107],["H3225","is a right hand",108,123],["H8267","of falsehood",124,136]]},"144:12":{"text":"That our sons may be as plants grown up in their youth; that our daughters may be as corner stones, polished after the similitude of a palace:","words":[["H1121","That our sons",0,13],["H5195","may be as plants",14,30],["H1431","grown up",31,39],["H5271","in their youth",40,54],["H1323","that our daughters",56,74],["H2106","may be as corner stones",75,98],["H2404","polished",100,108],["H8403","after the similitude",109,129],["H1964","of a palace",130,141]]},"144:13":{"text":"That our garners may be full, affording all manner of store: that our sheep may bring forth thousands and ten thousands in our streets:","words":[["H4200","That our garners",0,16],["H4392","may be full",17,28],["H6329","affording",30,39],["H2177","all manner of store",40,59],["H2177","all manner of store",40,59],["H6629","that our sheep",61,75],["H0503","may bring forth thousands",76,101],["H7231","and ten thousands",102,119],["H2351","in our streets",120,134]]},"144:14":{"text":"That our oxen may be strong to labour; that there be no breaking in, nor going out; that there be no complaining in our streets.","words":[["H0441","That our oxen",0,13],["H5445","may be strong to labour",14,37],["H6556","that there be no breaking in",39,67],["H3318","nor going out",69,82],["H6682","that there be no complaining",84,112],["H7339","in our streets",113,127]]},"144:15":{"text":"Happy is that people, that is in such a case: yea, happy is that people, whose God is the LORD.","words":[["H0835","Happy",0,5],["H5971","is that people",6,20],["H3602","that is in such a case",22,44],["H0835","yea, happy",46,56],["H5971","is that people",57,71],["H0430","whose God",73,82],["H3068","is the LORD",83,94]]},"145:1":{"text":"David's Psalm of praise. I will extol thee, my God, O king; and I will bless thy name for ever and ever.","words":[["H1732","David's",0,7],["H8416","Psalm of praise",8,23],["H7311","I will extol",25,37],["H0430","thee, my God",38,50],["H4428","O king",52,58],["H1288","and I will bless",60,76],["H8034","thy name",77,85],["H5769","for ever",86,94],["H5703","and ever",95,103]]},"145:2":{"text":"Every day will I bless thee; and I will praise thy name for ever and ever.","words":[["H3117","Every day",0,9],["H1288","will I bless",10,22],["H1984","thee; and I will praise",23,46],["H8034","thy name",47,55],["H5769","for ever",56,64],["H5703","and ever",65,73]]},"145:3":{"text":"Great is the LORD, and greatly to be praised; and his greatness is unsearchable.","words":[["H1419","Great",0,5],["H3068","is the LORD",6,17],["H3966","and greatly",19,30],["H1984","to be praised",31,44],["H1420","and his greatness",46,63],["H2714","is unsearchable",64,79]]},"145:4":{"text":"One generation shall praise thy works to another, and shall declare thy mighty acts.","words":[["H1755","One",0,3],["H1755","generation",4,14],["H7623","shall praise",15,27],["H4639","thy works",28,37],["H5046","to another, and shall declare",38,67],["H1369","thy mighty acts",68,83]]},"145:5":{"text":"I will speak of the glorious honour of thy majesty, and of thy wondrous works.","words":[["H7878","I will speak",0,12],["H3519","of the glorious",13,28],["H1926","honour",29,35],["H1935","of thy majesty",36,50],["H6381","and of thy wondrous",52,71],["H1697","works",72,77]]},"145:6":{"text":"And men shall speak of the might of thy terrible acts: and I will declare thy greatness.","words":[["H0559","And men shall speak",0,19],["H5807","of the might",20,32],["H3372","of thy terrible acts",33,53],["H5608","and I will declare",55,73],["H1420","thy greatness",74,87]]},"145:7":{"text":"They shall abundantly utter the memory of thy great goodness, and shall sing of thy righteousness.","words":[["H5042","They shall abundantly utter",0,27],["H2143","the memory",28,38],["H7227","of thy great",39,51],["H2898","goodness",52,60],["H7442","and shall sing",62,76],["H6666","of thy righteousness",77,97]]},"145:8":{"text":"The LORD is gracious, and full of compassion; slow to anger, and of great mercy.","words":[["H3068","The LORD",0,8],["H2587","is gracious",9,20],["H7349","and full of compassion",22,44],["H0750","slow",46,50],["H0639","to anger",51,59],["H1419","and of great",61,73],["H2617","mercy",74,79]]},"145:9":{"text":"The LORD is good to all: and his tender mercies are over all his works.","words":[["H3068","The LORD",0,8],["H2896","is good",9,16],["H7356","to all: and his tender mercies",17,47],["H4639","are over all his works",48,70]]},"145:10":{"text":"All thy works shall praise thee, O LORD; and thy saints shall bless thee.","words":[["H4639","All thy works",0,13],["H3034","shall praise",14,26],["H3068","thee, O LORD",27,39],["H2623","and thy saints",41,55],["H1288","shall bless",56,67]]},"145:11":{"text":"They shall speak of the glory of thy kingdom, and talk of thy power;","words":[["H0559","They shall speak",0,16],["H3519","of the glory",17,29],["H4438","of thy kingdom",30,44],["H1696","and talk",46,54],["H1369","of thy power",55,67]]},"145:12":{"text":"To make known to the sons of men his mighty acts, and the glorious majesty of his kingdom.","words":[["H3045","To make known",0,13],["H1121","to the sons",14,25],["H0120","of men",26,32],["H1369","his mighty acts",33,48],["H3519","and the glorious",50,66],["H1926","majesty",67,74],["H4438","of his kingdom",75,89]]},"145:13":{"text":"Thy kingdom is an everlasting kingdom, and thy dominion endureth throughout all generations.","words":[["H4438","Thy kingdom",0,11],["H5769","is an everlasting",12,29],["H4438","kingdom",30,37],["H4475","and thy dominion",39,55],["H1755","endureth throughout all",56,79],["H1755","generations",80,91]]},"145:14":{"text":"The LORD upholdeth all that fall, and raiseth up all those that be bowed down.","words":[["H3068","The LORD",0,8],["H5564","upholdeth",9,18],["H5307","all that fall",19,32],["H2210","and raiseth up",34,48],["H3721","all those that be bowed down",49,77]]},"145:15":{"text":"The eyes of all wait upon thee; and thou givest them their meat in due season.","words":[["H5869","The eyes",0,8],["H7663","of all wait",9,20],["H5414","upon thee; and thou givest",21,47],["H0400","them their meat",48,63],["H6256","in due season",64,77]]},"145:16":{"text":"Thou openest thine hand, and satisfiest the desire of every living thing.","words":[["H6605","Thou openest",0,12],["H3027","thine hand",13,23],["H7646","and satisfiest",25,39],["H7522","the desire",40,50],["H2416","of every living thing",51,72]]},"145:17":{"text":"The LORD is righteous in all his ways, and holy in all his works.","words":[["H3068","The LORD",0,8],["H6662","is righteous",9,21],["H1870","in all his ways",22,37],["H2623","and holy",39,47],["H4639","in all his works",48,64]]},"145:18":{"text":"The LORD is nigh unto all them that call upon him, to all that call upon him in truth.","words":[["H3068","The LORD",0,8],["H7138","is nigh",9,16],["H7121","unto all them that call",17,40],["H7121","upon him, to all that call",41,67],["H0571","upon him in truth",68,85]]},"145:19":{"text":"He will fulfil the desire of them that fear him: he also will hear their cry, and will save them.","words":[["H6213","He will fulfil",0,14],["H7522","the desire",15,25],["H3373","of them that fear",26,43],["H8085","him: he also will hear",44,66],["H7775","their cry",67,76],["H3467","and will save",78,91]]},"145:20":{"text":"The LORD preserveth all them that love him: but all the wicked will he destroy.","words":[["H3068","The LORD",0,8],["H8104","preserveth",9,19],["H0157","all them that love",20,38],["H7563","him: but all the wicked",39,62],["H8045","will he destroy",63,78]]},"145:21":{"text":"My mouth shall speak the praise of the LORD: and let all flesh bless his holy name for ever and ever.","words":[["H6310","My mouth",0,8],["H1696","shall speak",9,20],["H8416","the praise",21,31],["H3068","of the LORD",32,43],["H1320","and let all flesh",45,62],["H1288","bless",63,68],["H6944","his holy",69,77],["H8034","name",78,82],["H5769","for ever",83,91],["H5703","and ever",92,100]]},"146:1":{"text":"Praise ye the LORD. Praise the LORD, O my soul.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H1984","Praise",20,26],["H3068","the LORD",27,35],["H5315","O my soul",37,46]]},"146:2":{"text":"While I live will I praise the LORD: I will sing praises unto my God while I have any being.","words":[["H2416","While I live",0,12],["H1984","will I praise",13,26],["H3068","the LORD",27,35],["H2167","I will sing praises",37,56],["H0430","unto my God",57,68]]},"146:3":{"text":"Put not your trust in princes, nor in the son of man, in whom there is no help.","words":[["H0982","Put not your trust",0,18],["H5081","in princes",19,29],["H1121","nor in the son",31,45],["H0120","of man",46,52],["H8668","in whom there is no help",54,78]]},"146:4":{"text":"His breath goeth forth, he returneth to his earth; in that very day his thoughts perish.","words":[["H7307","His breath",0,10],["H3318","goeth forth",11,22],["H7725","he returneth",24,36],["H0127","to his earth",37,49],["H3117","in that very day",51,67],["H6250","his thoughts",68,80],["H0006","perish",81,87]]},"146:5":{"text":"Happy is he that hath the God of Jacob for his help, whose hope is in the LORD his God:","words":[["H0835","Happy",0,5],["H0410","is he that hath the God",6,29],["H3290","of Jacob",30,38],["H5828","for his help",39,51],["H7664","whose hope",53,63],["H3068","is in the LORD",64,78],["H0430","his God",79,86]]},"146:6":{"text":"Which made heaven, and earth, the sea, and all that therein is: which keepeth truth for ever:","words":[["H6213","Which made",0,10],["H8064","heaven",11,17],["H0776","and earth",19,28],["H3220","the sea",30,37],["H8104","and all that therein is: which keepeth",39,77],["H0571","truth",78,83],["H5769","for ever",84,92]]},"146:7":{"text":"Which executeth judgment for the oppressed: which giveth food to the hungry. The LORD looseth the prisoners:","words":[["H6213","Which executeth",0,15],["H4941","judgment",16,24],["H6231","for the oppressed",25,42],["H5414","which giveth",44,56],["H3899","food",57,61],["H7457","to the hungry",62,75],["H3068","The LORD",77,85],["H5425","looseth",86,93],["H0631","the prisoners",94,107]]},"146:8":{"text":"The LORD openeth the eyes of the blind: the LORD raiseth them that are bowed down: the LORD loveth the righteous:","words":[["H3068","The LORD",0,8],["H6491","openeth",9,16],["H5787","the eyes of the blind",17,38],["H3068","the LORD",40,48],["H2210","raiseth",49,56],["H3721","them that are bowed down",57,81],["H3068","the LORD",83,91],["H0157","loveth",92,98],["H6662","the righteous",99,112]]},"146:9":{"text":"The LORD preserveth the strangers; he relieveth the fatherless and widow: but the way of the wicked he turneth upside down.","words":[["H3068","The LORD",0,8],["H8104","preserveth",9,19],["H1616","the strangers",20,33],["H5749","he relieveth",35,47],["H3490","the fatherless",48,62],["H0490","and widow",63,72],["H1870","but the way",74,85],["H7563","of the wicked",86,99],["H5791","he turneth upside down",100,122]]},"146:10":{"text":"The LORD shall reign for ever, even thy God, O Zion, unto all generations. Praise ye the LORD.","words":[["H3068","The LORD",0,8],["H4427","shall reign",9,20],["H5769","for ever",21,29],["H0430","even thy God",31,43],["H6726","O Zion",45,51],["H1755","unto all",53,61],["H1755","generations",62,73],["H1984","Praise",75,81],["H3050","ye the LORD",82,93]]},"147:1":{"text":"Praise ye the LORD: for it is good to sing praises unto our God; for it is pleasant; and praise is comely.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H2896","for it is good",20,34],["H2167","to sing praises",35,50],["H0430","unto our God",51,63],["H5273","for it is pleasant",65,83],["H8416","and praise",85,95],["H5000","is comely",96,105]]},"147:2":{"text":"The LORD doth build up Jerusalem: he gathereth together the outcasts of Israel.","words":[["H3068","The LORD",0,8],["H1129","doth build up",9,22],["H3389","Jerusalem",23,32],["H3664","he gathereth together",34,55],["H1760","the outcasts",56,68],["H3478","of Israel",69,78]]},"147:3":{"text":"He healeth the broken in heart, and bindeth up their wounds.","words":[["H7495","He healeth",0,10],["H7665","the broken",11,21],["H3820","in heart",22,30],["H2280","and bindeth up",32,46],["H6094","their wounds",47,59]]},"147:4":{"text":"He telleth the number of the stars; he calleth them all by their names.","words":[["H4487","He telleth",0,10],["H4557","the number",11,21],["H3556","of the stars",22,34],["H7121","he calleth",36,46],["H8034","them all by their names",47,70]]},"147:5":{"text":"Great is our Lord, and of great power: his understanding is infinite.","words":[["H1419","Great",0,5],["H0113","is our Lord",6,17],["H7227","and of great",19,31],["H3581","power",32,37],["H8394","his understanding",39,56],["H4557","is infinite",57,68]]},"147:6":{"text":"The LORD lifteth up the meek: he casteth the wicked down to the ground.","words":[["H3068","The LORD",0,8],["H5749","lifteth up",9,19],["H6035","the meek",20,28],["H8213","he casteth",30,40],["H7563","the wicked",41,51],["H8213","down",52,56],["H0776","to the ground",57,70]]},"147:7":{"text":"Sing unto the LORD with thanksgiving; sing praise upon the harp unto our God:","words":[["H6030","Sing",0,4],["H3068","unto the LORD",5,18],["H8426","with thanksgiving",19,36],["H2167","sing praise",38,49],["H3658","upon the harp",50,63],["H0430","unto our God",64,76]]},"147:8":{"text":"Who covereth the heaven with clouds, who prepareth rain for the earth, who maketh grass to grow upon the mountains.","words":[["H3680","Who covereth",0,12],["H8064","the heaven",13,23],["H5645","with clouds",24,35],["H3559","who prepareth",37,50],["H4306","rain",51,55],["H0776","for the earth",56,69],["H2682","who maketh grass",71,87],["H6779","to grow",88,95],["H2022","upon the mountains",96,114]]},"147:9":{"text":"He giveth to the beast his food, and to the young ravens which cry.","words":[["H5414","He giveth",0,9],["H0929","to the beast",10,22],["H3899","his food",23,31],["H1121","and to the young",33,49],["H6158","ravens",50,56],["H7121","which cry",57,66]]},"147:10":{"text":"He delighteth not in the strength of the horse: he taketh not pleasure in the legs of a man.","words":[["H2654","He delighteth",0,13],["H1369","not in the strength",14,33],["H5483","of the horse",34,46],["H7521","he taketh not pleasure",48,70],["H7785","in the legs",71,82],["H0376","of a man",83,91]]},"147:11":{"text":"The LORD taketh pleasure in them that fear him, in those that hope in his mercy.","words":[["H3068","The LORD",0,8],["H7521","taketh pleasure",9,24],["H3373","in them that fear",25,42],["H3176","him, in those that hope",43,66],["H2617","in his mercy",67,79]]},"147:12":{"text":"Praise the LORD, O Jerusalem; praise thy God, O Zion.","words":[["H7623","Praise",0,6],["H3068","the LORD",7,15],["H3389","O Jerusalem",17,28],["H1984","praise",30,36],["H0430","thy God",37,44],["H6726","O Zion",46,52]]},"147:13":{"text":"For he hath strengthened the bars of thy gates; he hath blessed thy children within thee.","words":[["H2388","For he hath strengthened",0,24],["H1280","the bars",25,33],["H8179","of thy gates",34,46],["H1288","he hath blessed",48,63],["H1121","thy children",64,76],["H7130","within",77,83]]},"147:14":{"text":"He maketh peace in thy borders, and filleth thee with the finest of the wheat.","words":[["H7760","He maketh",0,9],["H7965","peace",10,15],["H1366","in thy borders",16,30],["H7646","and filleth",32,43],["H2459","thee with the finest",44,64],["H2406","of the wheat",65,77]]},"147:15":{"text":"He sendeth forth his commandment upon earth: his word runneth very swiftly.","words":[["H7971","He sendeth forth",0,16],["H0565","his commandment",17,32],["H0776","upon earth",33,43],["H1697","his word",45,53],["H7323","runneth",54,61],["H4120","very swiftly",62,74]]},"147:16":{"text":"He giveth snow like wool: he scattereth the hoarfrost like ashes.","words":[["H5414","He giveth",0,9],["H7950","snow",10,14],["H6785","like wool",15,24],["H6340","he scattereth",26,39],["H3713","the hoarfrost",40,53],["H0665","like ashes",54,64]]},"147:17":{"text":"He casteth forth his ice like morsels: who can stand before his cold?","words":[["H7993","He casteth forth",0,16],["H7140","his ice",17,24],["H6595","like morsels",25,37],["H5975","who can stand",39,52],["H6440","before",53,59],["H7135","his cold",60,68]]},"147:18":{"text":"He sendeth out his word, and melteth them: he causeth his wind to blow, and the waters flow.","words":[["H7971","He sendeth out",0,14],["H1697","his word",15,23],["H4529","and melteth",25,36],["H7307","them: he causeth his wind",37,62],["H5380","to blow",63,70],["H4325","and the waters",72,86],["H5140","flow",87,91]]},"147:19":{"text":"He sheweth his word unto Jacob, his statutes and his judgments unto Israel.","words":[["H5046","He sheweth",0,10],["H1697","his word",11,19],["H1697","his word",11,19],["H3290","unto Jacob",20,30],["H2706","his statutes",32,44],["H4941","and his judgments",45,62],["H3478","unto Israel",63,74]]},"147:20":{"text":"He hath not dealt so with any nation: and as for his judgments, they have not known them. Praise ye the LORD.","words":[["H6213","He hath not dealt",0,17],["H1471","so with any nation",18,36],["H4941","and as for his judgments",38,62],["H3045","they have not known",64,83],["H1984","them. Praise",84,96],["H3050","ye the LORD",97,108]]},"148:1":{"text":"Praise ye the LORD. Praise ye the LORD from the heavens: praise him in the heights.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H1984","Praise",20,26],["H3068","ye the LORD",27,38],["H8064","from the heavens",39,55],["H1984","praise",57,63],["H4791","him in the heights",64,82]]},"148:2":{"text":"Praise ye him, all his angels: praise ye him, all his hosts.","words":[["H1984","Praise",0,6],["H4397","ye him, all his angels",7,29],["H1984","praise",31,37],["H6635","ye him, all his hosts",38,59]]},"148:3":{"text":"Praise ye him, sun and moon: praise him, all ye stars of light.","words":[["H1984","Praise",0,6],["H8121","ye him, sun",7,18],["H3394","and moon",19,27],["H1984","praise",29,35],["H3556","him, all ye stars",36,53],["H0216","of light",54,62]]},"148:4":{"text":"Praise him, ye heavens of heavens, and ye waters that be above the heavens.","words":[["H1984","Praise",0,6],["H8064","him, ye heavens",7,22],["H8064","of heavens",23,33],["H4325","and ye waters",35,48],["H8064","that be above the heavens",49,74]]},"148:5":{"text":"Let them praise the name of the LORD: for he commanded, and they were created.","words":[["H1984","Let them praise",0,15],["H8034","the name",16,24],["H3068","of the LORD",25,36],["H6680","for he commanded",38,54],["H1254","and they were created",56,77]]},"148:6":{"text":"He hath also stablished them for ever and ever: he hath made a decree which shall not pass.","words":[["H5975","He hath also stablished",0,23],["H5703","them for ever",24,37],["H5769","and ever",38,46],["H5414","he hath made",48,60],["H2706","a decree",61,69],["H5674","which shall not pass",70,90]]},"148:7":{"text":"Praise the LORD from the earth, ye dragons, and all deeps:","words":[["H1984","Praise",0,6],["H3068","the LORD",7,15],["H0776","from the earth",16,30],["H8577","ye dragons",32,42],["H8415","and all deeps",44,57]]},"148:8":{"text":"Fire, and hail; snow, and vapour; stormy wind fulfilling his word:","words":[["H0784","Fire",0,4],["H1259","and hail",6,14],["H7950","snow",16,20],["H7008","and vapour",22,32],["H5591","stormy",34,40],["H7307","wind",41,45],["H6213","fulfilling",46,56],["H1697","his word",57,65]]},"148:9":{"text":"Mountains, and all hills; fruitful trees, and all cedars:","words":[["H2022","Mountains",0,9],["H1389","and all hills",11,24],["H6529","fruitful",26,34],["H6086","trees",35,40],["H0730","and all cedars",42,56]]},"148:10":{"text":"Beasts, and all cattle; creeping things, and flying fowl:","words":[["H2416","Beasts",0,6],["H0929","and all cattle",8,22],["H7431","creeping things",24,39],["H3671","and flying",41,51],["H6833","fowl",52,56]]},"148:11":{"text":"Kings of the earth, and all people; princes, and all judges of the earth:","words":[["H4428","Kings",0,5],["H0776","of the earth",6,18],["H3816","and all people",20,34],["H8269","princes",36,43],["H8199","and all judges",45,59],["H0776","of the earth",60,72]]},"148:12":{"text":"Both young men, and maidens; old men, and children:","words":[["H0970","Both young men",0,14],["H1330","and maidens",16,27],["H2205","old men",29,36],["H5288","and children",38,50]]},"148:13":{"text":"Let them praise the name of the LORD: for his name alone is excellent; his glory is above the earth and heaven.","words":[["H1984","Let them praise",0,15],["H8034","the name",16,24],["H3068","of the LORD",25,36],["H8034","for his name",38,50],["H7682","alone is excellent",51,69],["H1935","his glory",71,80],["H0776","is above the earth",81,99],["H8064","and heaven",100,110]]},"148:14":{"text":"He also exalteth the horn of his people, the praise of all his saints; even of the children of Israel, a people near unto him. Praise ye the LORD.","words":[["H7311","He also exalteth",0,16],["H7161","the horn",17,25],["H5971","of his people",26,39],["H8416","the praise",41,51],["H2623","of all his saints",52,69],["H1121","even of the children",71,91],["H3478","of Israel",92,101],["H5971","a people",103,111],["H7138","near",112,116],["H1984","unto him. Praise",117,133],["H3050","ye the LORD",134,145]]},"149:1":{"text":"Praise ye the LORD. Sing unto the LORD a new song, and his praise in the congregation of saints.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H7891","Sing",20,24],["H3068","unto the LORD",25,38],["H2319","a new",39,44],["H7892","song",45,49],["H8416","and his praise",51,65],["H6951","in the congregation",66,85],["H2623","of saints",86,95]]},"149:2":{"text":"Let Israel rejoice in him that made him: let the children of Zion be joyful in their King.","words":[["H3478","Let Israel",0,10],["H8055","rejoice",11,18],["H6213","in him that made",19,35],["H1121","him: let the children",36,57],["H6726","of Zion",58,65],["H1523","be joyful",66,75],["H4428","in their King",76,89]]},"149:3":{"text":"Let them praise his name in the dance: let them sing praises unto him with the timbrel and harp.","words":[["H1984","Let them praise",0,15],["H8034","his name",16,24],["H4234","in the dance",25,37],["H2167","let them sing praises",39,60],["H8596","unto him with the timbrel",61,86],["H3658","and harp",87,95]]},"149:4":{"text":"For the LORD taketh pleasure in his people: he will beautify the meek with salvation.","words":[["H3068","For the LORD",0,12],["H7521","taketh pleasure",13,28],["H5971","in his people",29,42],["H6286","he will beautify",44,60],["H6035","the meek",61,69],["H3444","with salvation",70,84]]},"149:5":{"text":"Let the saints be joyful in glory: let them sing aloud upon their beds.","words":[["H2623","Let the saints",0,14],["H5937","be joyful",15,24],["H3519","in glory",25,33],["H7442","let them sing aloud",35,54],["H4904","upon their beds",55,70]]},"149:6":{"text":"Let the high praises of God be in their mouth, and a twoedged sword in their hand;","words":[["H7319","Let the high",0,12],["H0410","praises of God",13,27],["H1627","be in their mouth",28,45],["H6374","and a twoedged",47,61],["H2719","sword",62,67],["H3027","in their hand",68,81]]},"149:7":{"text":"To execute vengeance upon the heathen, and punishments upon the people;","words":[["H6213","To execute",0,10],["H5360","vengeance",11,20],["H1471","upon the heathen",21,37],["H8433","and punishments",39,54],["H3816","upon the people",55,70]]},"149:8":{"text":"To bind their kings with chains, and their nobles with fetters of iron;","words":[["H0631","To bind",0,7],["H4428","their kings",8,19],["H2131","with chains",20,31],["H3513","and their nobles",33,49],["H3525","with fetters",50,62],["H1270","of iron",63,70]]},"149:9":{"text":"To execute upon them the judgment written: this honour have all his saints. Praise ye the LORD.","words":[["H6213","To execute",0,10],["H4941","upon them the judgment",11,33],["H3789","written",34,41],["H1926","this honour",43,54],["H2623","have all his saints",55,74],["H1984","Praise",76,82],["H3050","ye the LORD",83,94]]},"150:1":{"text":"Praise ye the LORD. Praise God in his sanctuary: praise him in the firmament of his power.","words":[["H1984","Praise",0,6],["H3050","ye the LORD",7,18],["H1984","Praise",20,26],["H0410","God",27,30],["H6944","in his sanctuary",31,47],["H1984","praise",49,55],["H7549","him in the firmament",56,76],["H5797","of his power",77,89]]},"150:2":{"text":"Praise him for his mighty acts: praise him according to his excellent greatness.","words":[["H1984","Praise",0,6],["H1369","him for his mighty acts",7,30],["H1984","praise",32,38],["H7230","him according to his excellent",39,69],["H1433","greatness",70,79]]},"150:3":{"text":"Praise him with the sound of the trumpet: praise him with the psaltery and harp.","words":[["H1984","Praise",0,6],["H8629","him with the sound",7,25],["H7782","of the trumpet",26,40],["H1984","praise",42,48],["H5035","him with the psaltery",49,70],["H3658","and harp",71,79]]},"150:4":{"text":"Praise him with the timbrel and dance: praise him with stringed instruments and organs.","words":[["H1984","Praise",0,6],["H8596","him with the timbrel",7,27],["H4234","and dance",28,37],["H1984","praise",39,45],["H4482","him with stringed instruments",46,75],["H5748","and organs",76,86]]},"150:5":{"text":"Praise him upon the loud cymbals: praise him upon the high sounding cymbals.","words":[["H1984","Praise",0,6],["H8088","him upon the loud",7,24],["H6767","cymbals",25,32],["H1984","praise",34,40],["H8643","him upon the high sounding",41,67],["H6767","cymbals",68,75]]},"150:6":{"text":"Let every thing that hath breath praise the LORD. Praise ye the LORD.","words":[["H5397","Let every thing that hath breath",0,32],["H1984","praise",33,39],["H3050","the LORD",40,48],["H1984","Praise",50,56],["H3050","ye the LORD",57,68]]}}};
